DROP PROCEDURE BBC_LAY_NV;

CREATE OR REPLACE PROCEDURE BBC_LAY_NV
 (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_phong varchar2)
as
    b_i1 number;b_i2 number;
begin
--BCNam: Lay nghiep vu duoc xem, bo sung NV moi
    delete temp_bc_nv;
    insert into temp_bc_nv(nv) select nv from ht_ma_nsd_nv
        where ma_dvi=b_ma_dvi and ma=b_nsd and (instr(tc,'X')>0 or instr(tc,'N')>0) and md='BH';
    select count(*) into b_i1 from temp_bc_nv where nv ='XE';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('XEL');
        insert into temp_bc_nv(nv) values('XG');

    end if;
    select count(*) into b_i1 from temp_bc_nv where nv ='2B';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('2BL');
        insert into temp_bc_nv(nv) values('XG');
    end if;
    select count(*) into b_i1 from temp_bc_nv where nv ='TAU';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('TAUL');
        insert into temp_bc_nv(nv) values('TT');
        insert into temp_bc_nv(nv) values('TC');
        insert into temp_bc_nv(nv) values('CN.6');
        insert into temp_bc_nv(nv) values('HK');
        insert into temp_bc_nv(nv) values('NL');
    end if;

    select count(*) into b_i1 from temp_bc_nv where nv ='NG';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('CN');
        insert into temp_bc_nv(nv) values('SK');
        insert into temp_bc_nv(nv) values('SKL');
    end if;

    select count(*) into b_i1 from temp_bc_nv where nv ='PHH';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('TS');
        insert into temp_bc_nv(nv) values('HP');
    end if;

    select count(*) into b_i1 from temp_bc_nv where nv ='PKT';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('KT');
    end if;
    select count(*) into b_i1 from temp_bc_nv where nv ='PTN';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('TN');
    end if;
    select count(*) into b_i1 from temp_bc_nv where nv ='HOP';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('HOP');
    end if;

    select count(*) into b_i1 from temp_bc_nv where nv ='HANG';
    if b_i1>0 then
        insert into temp_bc_nv(nv) values('HH');
    end if;
    commit;
end;
/

DROP PROCEDURE BBH_BH_BC_BH_NGHIEPVU_XECG;

CREATE OR REPLACE PROCEDURE BBH_BH_BC_BH_NGHIEPVU_XECG
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_NV VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_I1 NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE TEMP_4;DELETE TEMP_5;DELETE KET_QUA; COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
-- IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;

    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_4(C1,N10,N12,N30) SELECT MA_DVI,SO_ID,SUM(PHI),1
        FROM TEMP_BC_BH_DTBH_MM WHERE (B_PHONG IS NULL OR PHONG=B_PHONG)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND NV IN ('XE','XEL','2B','2BL') GROUP BY MA_DVI,SO_ID;
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MM';
    BC_BH_LAY_BC_BH_DTTT_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_4(C1,N10,N11) SELECT MA_DVI,SO_ID,SUM(PHI)
        FROM TEMP_BC_BH_DTTT_MM WHERE (B_PHONG IS NULL OR PHONG=B_PHONG)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND NV IN ('XE','XEL','2B','2BL') GROUP BY MA_DVI,SO_ID;

    --uoc
    BC_BH_THBT_MD_CD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,'','','',B_NGAYD,B_NGAYC,B_LOI,'B');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    INSERT INTO TEMP_5 (C29,C1,C18,N7,N8,N13,N10) SELECT C29,C1,C18,N7,N8,N13,N10 FROM TEMP_1 where c1 in ('XE','XEL','2B','2BL'); --instr(c30,'B')>0 and
--    UPDATE TEMP_5 SET N8=(SELECT SO_ID_DT FROM BH_BT_HS_NV WHERE MA_DVI=TEMP_5.C29 AND SO_ID=TEMP_5.N10 AND ROWNUM=1);
    
    BC_BH_THBT_MD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,'','','',B_NGAYD,B_NGAYC,B_LOI,'B');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

    
    INSERT INTO TEMP_3(C1,N10,N11,N12) SELECT C1,N10,SUM(NVL(N11,0)),SUM(NVL(N12,0)) FROM TEMP_4 WHERE N10>0 GROUP BY C1,N10;
    
    INSERT INTO TEMP_2(C1,C2,C3,C4,N3,N4,N10,N11,N12,N30)
        SELECT A.MA_DVI,GCN,'' MA_BH,BIEN_XE,SUM(B.PHI),SUM(B.PHI),A.SO_ID,N11,N12,1
        FROM BH_XE_DS A,BH_XE_DK B,TEMP_3
        WHERE A.MA_DVI=C1 AND A.SO_ID=N10
        AND B.MA_DVI=C1 AND B.SO_ID=N10 AND B.SO_ID_DT=A.SO_ID_DT
        GROUP BY  A.MA_DVI,GCN,BIEN_XE,A.SO_ID,N11,N12;

--    UPDATE TEMP_2 SET N13=(SELECT SUM(PHI_DT) FROM BH_XEGCN_DK WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N10) WHERE N30=1;
    
