--    UPDATE TEMP_2 SET N13=(SELECT SUM(PHI_DT) FROM BH_XELGCN_DK WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N10) WHERE N30=2;
    
    INSERT INTO TEMP_2(C1,C2,C3,C4,N3,N4,N10,N11,N12,N30)
