    update temp_2 set N13=n12;
--    UPDATE TEMP_2 SET N13=(SELECT SUM(PHI_DT) FROM BH_2B_GCN_DK WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N10) WHERE N30=3;

    
