--        SELECT A.MA_DVI,SO_HD,'' MA_BH,BIEN_XE,SUM(B.PHI_DT),SUM(B.PHI_DT),A.SO_ID,N11,N12,4
--        FROM BH_2BLGCN A,BH_2BLGCN_DK B,TEMP_3
--        WHERE A.MA_DVI=C1 AND A.SO_ID=N10
--        AND B.MA_DVI=C1 AND B.SO_ID=N10
--         GROUP BY  A.MA_DVI,SO_HD,BIEN_XE,A.SO_ID,N11,N12;
--    UPDATE TEMP_2 SET N13=(SELECT SUM(PHI_DT) FROM BH_2BLGCN_DK WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N10) WHERE N30=4;

--     UPDATE TEMP_2 SET N3=N12/N13*N3 WHERE NVL(N13,0)<>0 OR NVL(N3,0)<>0;
--     UPDATE TEMP_2 SET N4=N11/N13*N4 WHERE NVL(N13,0)<>0 OR NVL(N4,0)<>0;

    UPDATE TEMP_1 SET C30=BC_HOI_LOAIXE(C29,C1,N13,N8,C18);
    UPDATE TEMP_5 SET C30=BC_HOI_LOAIXE(C29,C1,N13,N8,C18);
    
    INSERT INTO TEMP_2(C1,C2,C3,C4,N6)
        SELECT A.MA_DVI,GCN,'' MA_BH,BIEN_XE,N7        
        FROM bh_xe_ds A,TEMP_1 WHERE A.MA_DVI=C29 AND A.SO_ID=N13 AND A.SO_ID_DT=N8 and instr(c30,'T')>0 and c1 in ('XE','XEL','2B','2BL'); 

    INSERT INTO TEMP_2(C1,C2,C3,C4,N7)
        SELECT A.MA_DVI,GCN,'' MA_BH,BIEN_XE,N7  
        FROM BH_XE_ds A,TEMP_5 WHERE A.MA_DVI=C29 AND A.SO_ID=N13 AND A.SO_ID_DT=N8 and instr(c30,'B')>0 and c1 in ('XE','XEL','2B','2BL');

    
--    INSERT INTO TEMP_2(C1,C2,C3,C4,N6,N7,N8,N9)
--        SELECT A.MA_DVI,SO_HD,'' MA_BH,BIEN_XE,DECODE(C30,'TL',N7,0),DECODE(C30,'TH',N7,0),DECODE(C30,'TV',N7,0),
--        DECODE(SUBSTR(C30,2,1),'N',N7,0)+DECODE(SUBSTR(C30,2,1),'T',N7,0)+DECODE(SUBSTR(C30,2,1),'K',N7,0)
--        FROM BH_XELGCN A,TEMP_1 WHERE A.MA_DVI=C29 AND A.SO_ID=N13 ;
--
--    INSERT INTO TEMP_2(C1,C2,C3,C4,N6,N7,N8,N9)
--        SELECT A.MA_DVI,SO_HD,'' MA_BH,BIEN_XE,DECODE(C30,'TL',N7,0),DECODE(C30,'TH',N7,0),DECODE(C30,'TV',N7,0),
--        DECODE(SUBSTR(C30,2,1),'N',N7,0)+DECODE(SUBSTR(C30,2,1),'T',N7,0)+DECODE(SUBSTR(C30,2,1),'K',N7,0)
--        FROM BH_XELGCN A,TEMP_5 WHERE A.MA_DVI=C29 AND A.SO_ID=N13;


    
    INSERT INTO TEMP_2(C1,C2,C3,C4,N8)
        SELECT A.MA_DVI,GCN,'' MA_BH,BIEN_XE,n7
        FROM BH_2B_ds A,TEMP_1 WHERE A.MA_DVI=C29 AND A.SO_ID=N13 AND A.SO_ID_DT=N8 and instr(c30,'T')>0 and c1 in ('XE','XEL','2B','2BL');


    INSERT INTO TEMP_2(C1,C2,C3,C4,N9)
        SELECT A.MA_DVI,GCN,'' MA_BH,BIEN_XE,n7
        FROM BH_2B_DS A,TEMP_5 WHERE A.MA_DVI=C29 AND A.SO_ID=N13 AND A.SO_ID_DT=N8 and instr(c30,'B')>0 and c1 in ('XE','XEL','2B','2BL');

    
