INSERT INTO KET_QUA(C1,C2,C3,C4,C5,N2,N3,N4,N5,N6,N7,N8,N10)
    SELECT C1,C2,C3,C4,C5,SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),SUM(NVL(N5,0)),SUM(NVL(N6,0)),
    SUM(NVL(N7,0)),SUM(NVL(N8,0)),N10
