        ROUND(SUM(NVL(N3,0)),0) DTBH,ROUND(SUM(NVL(N4,0)),0) DTTT,
         ROUND(SUM(NVL(N6,0)),0) VCX_OTO_DGQ,
        ROUND(SUM(NVL(N7,0)),0) VCX_OTO_CGQ,ROUND(SUM(NVL(N8,0)),0) VCX_2B_DGQ,ROUND(SUM(NVL(N9,0)),0) VCX_2B_CGQ
        FROM KET_QUA GROUP BY C1,C11,C3,C14 ORDER BY C3;
