DROP PROCEDURE BBH_BH_BC_BH_THBT_MD;
-- author: chuclh  update bt.so_id_dt
CREATE OR REPLACE PROCEDURE BBH_BH_BC_BH_THBT_MD
    (B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_N_DUYET VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2,B_BT VARCHAR2:='')
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';

DELETE TEMP_1;COMMIT;

IF B_BT='B' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,
    C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7,C20) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),
        PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        ''MA_NN,'' MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_QD,SO_ID_HD,TIEN_BH,
        PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR),'T'
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
        AND BT.MA_DVI=BT.MA_DVI_QL AND (B_MA_DVI IS NULL OR BT.MA_DVI_QL=B_MA_DVI) 
        AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC) AND BT.NGAY_QD<'30000101'
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%'); 
    
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,
    C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7,C20) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),
        PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        ''MA_NN,'' MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_QD,SO_ID_HD,TIEN_BH,
        PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR),'K'
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
        AND BT.MA_DVI=BT.MA_DVI_XL AND BT.MA_DVI<> BT.MA_DVI_QL
        AND (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI)
        AND BT.MA_DVI IN (SELECT MA_DVI FROM BH_BT_HS_PB WHERE SO_ID=BT.SO_ID)
        AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC) AND BT.NGAY_QD<'30000101'
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,
    C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7,C20) 
    SELECT PB.MA_DVI,NV,SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),
        PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        ''MA_NN,'' MA_MD,''QUY_LOI,'',NV.MA_NT,NV.LH_NV,BT.SO_ID,BT.NGAY_QD,BT.SO_ID_HD,TIEN_BH,
        PT_BT,T_THAT,'' K_TRU,PB.TIEN,PB.TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR),'C'
    FROM BH_BT_HS_PB PB,BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE PB.MA_DVI<>PB.DVI_XL 
        AND PB.DVI_XL=BT.MA_DVI_XL AND PB.SO_ID=BT.SO_ID AND PB.SO_ID=NV.SO_ID AND PB.DVI_XL =NV.MA_DVI
        AND (B_MA_DVI IS NULL OR PB.MA_DVI=B_MA_DVI)
        AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC) AND BT.NGAY_QD<'30000101'
        AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%');
        
UPDATE TEMP_1 SET N7=ROUND(N7*(100- NVL((SELECT PT FROM BH_HD_DO_TL WHERE MA_DVI=C29 AND SO_ID=N13 AND PTHUC='D' AND ROWNUM=1),0))/100) WHERE C20='T';
UPDATE TEMP_1 SET N7=ROUND(N7*NVL((SELECT PT/100 FROM BH_HD_DO_TL WHERE NHA_BH=C29 AND SO_ID=N13  AND PTHUC='D' AND ROWNUM=1),1)) WHERE C20='K';
  
ELSIF  B_BT='B1' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7) 
    SELECT BT.MA_DVI_XL,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    ''MA_NN,'' MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_QD,SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR)
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    AND (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI) 

    AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC)
    AND BT.NGAY_QD<'30000101'

    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
ELSIF  B_BT='H1' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    ''MA_NN,'' MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_QD,SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR)
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>MA_DVI_XL
    AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) 

    AND BT.NGAY_QD<'30000101'
    AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC)    

    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
ELSIF  B_BT='H2' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7) 
    SELECT BT.MA_DVI_XL,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    ''MA_NN,'' MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_QD,SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR)
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>MA_DVI_XL
    AND (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI) 

        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET)
    AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC)    
    AND BT.NGAY_QD<'30000101'

    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
ELSE
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,D7) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    ''MA_NN,'' MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_QD,SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,PKH_SO_DATE(NGAY_XR)
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) 

        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET)
    AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC)    
    AND BT.NGAY_QD<'30000101'

    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
END IF;

DELETE TEMP_1 WHERE N7=0;
UPDATE TEMP_1 SET (C6,C4,C5,N11,C21)=(SELECT PHONG,SO_HD,MA_KH,NGAY_HT,KIEU_HD FROM BH_HD_GOC
    WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N13);
DELETE TEMP_1 WHERE NVL(C21,'G')='V';
IF B_PHONG IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;

UPDATE
       (SELECT TEMP_1.C16 TEMP_1_C16, BH_HD_MA_KH.LOAI BH_HD_MA_KH_LOAI
              FROM TEMP_1, BH_HD_MA_KH
             WHERE TEMP_1.C29 = BH_HD_MA_KH.MA_DVI AND TEMP_1.C5 = BH_HD_MA_KH.MA)
       SET TEMP_1_C16 = BH_HD_MA_KH_LOAI;

IF B_MA_KH IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C5<>B_MA_KH;
END IF;
IF B_LOAI_KH IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C16<>B_LOAI_KH;
END IF;
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/

DROP PROCEDURE BBH_BH_BC_BH_NHANH_DTMOI_LKH;

CREATE OR REPLACE PROCEDURE BBH_BH_BC_BH_NHANH_DTMOI_LKH
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_loai varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_lkh varchar2,b_ma_kh varchar2,b_ma_cb varchar2,b_nguon varchar2, b_ma_dt varchar2, b_ma_dl varchar2,b_kieu_kt varchar2,b_tc varchar2,
    b_ngayd number,b_ngayc number,b_ngayd_hd number,b_ngayc_hd number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number;b_ngayd1 number;b_ma_vp varchar2(10);b_i1 number;b_kieu varchar2(1);b_i2 number;

Begin
--Bao cao nhanh doanh thu bao hiem sua gom nhom loai
--b_loai='0' bao cao group theo nghiep vu
--b_loai='1' Bao cao group theo khach hang
--b_loai='2' Bao cao group theo phong
--b_loai='3' Bao cao group theo don vi
--b_loai='4' Bao cao chi tiet
--tinh chat la C de in cac ma bao cao theo nghiep vu, tinh chat K in cac bao cao gom theo phong, theo don vi,khach hang vv...

--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;

if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi';
    raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
b_ngayd1:=b_ngayd-1;

EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE ket_qua';
--delete temp_1;
--delete temp_2;
--delete ket_qua;
commit;

PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
--c6 loai khach hang
--Doanh thu phat sinh trong ky
--lay nghiep vu
PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
--lay bang tham so truyen vao view
--EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bc_ts';
delete temp_bc_ts;

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
BC_BH_LAY_BC_BH_DTPS_MM(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2 (c29,c1,c2,c3,c4,c5,c7,n2,n3,n14,c28)
    select ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,sum(phi),sum(thue),so_id,ma_dvig
    from TEMP_BC_BH_DTPS_MM
    where (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
    and (b_ma_nv is null or lh_nv like b_ma_nv||'%') and (b_ma_cb is null or cb_ql=b_ma_cb)
    and (b_ma_dl is null or ma_kt=b_ma_dl) and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
    and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--    and FBH_HD_LKH(ma_dvig,so_id)=b_lkh
    group by ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,so_id,ma_dvig;

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);

insert into temp_2 (c29,c1,c2,c3,c4,c5,c7,n6,n7,n14,c28)
    select ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,sum(phi),sum(thue),so_id,ma_dvig
    from TEMP_BC_BH_DTBH_MM
    where (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
    and (b_ma_nv is null or lh_nv like b_ma_nv||'%') and (b_ma_cb is null or cb_ql=b_ma_cb)
    and (b_ma_dl is null or ma_kt=b_ma_dl) and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
    and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--     and  FBH_HD_LKH(ma_dvig,so_id)=b_lkh
    group by ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,so_id,ma_dvig;

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngayd,b_ngayc);

insert into temp_1(c29,c28,c1,c2,c3,c4,c5,c7,n10,n1,n11,n12,n14)
        select ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,sum(phi),sum(thue),ngay,ngay_htnv,so_id
            from TEMP_BC_BH_DTTT_MA_DT where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
                and ngay_htbs between b_ngayd and b_ngayc
                and (b_phong is null or phong=b_phong) and (b_ma_cb is null or cb_ql=b_ma_cb)
                and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
                and (b_ma_dl is null or ma_kt=b_ma_dl)
                and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--                and  FBH_HD_LKH(ma_dvig,so_id)=b_lkh
            group by ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,ngay,ngay_htnv,so_id;


insert into temp_2 (c29,c1,c2,c3,c4,c5,c7,n10,n11)
    select c29,c1,c2,c3,c4,c5,c7,n10,n1 from temp_1; --where n20 between b_ngayd and b_ngayc;
        commit;

if b_ngayd<>b_ngaydn then

    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
    BC_BH_LAY_BC_BH_DTPS_MM(b_ma_dvi,b_ngaydn,b_ngayd1);
    insert into temp_2 (c29,c1,c2,c3,c4,c5,c7,n4,n5,c28)
        select ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,sum(phi),sum(thue),ma_dvig
        from TEMP_BC_BH_DTPS_MM
        where (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%') and (b_ma_cb is null or cb_ql=b_ma_cb)
        and (b_ma_dl is null or ma_kt=b_ma_dl) and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--        and  FBH_HD_LKH(ma_dvig,so_id)=b_lkh
        group by ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,ma_dvig;

   EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngaydn,b_ngayd1);
    insert into temp_2 (c29,c1,c2,c3,c4,c5,c7,n8,n9,c28)
        select ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,sum(phi),sum(thue),ma_dvig
        from TEMP_BC_BH_DTBH_MM
        where (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%') and (b_ma_cb is null or cb_ql=b_ma_cb)
        and (b_ma_dl is null or ma_kt=b_ma_dl) and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--        and  FBH_HD_LKH(ma_dvig,so_id)=b_lkh
        group by ma_dvi,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,ma_dvig;

    EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_1';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
    BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngaydn,b_ngayd1);
    insert into temp_1(c29,c28,c1,c2,c3,c4,c5,c7,n10,n1,n11,n12,n14)
        select ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,sum(phi),sum(thue),ngay,ngay_htnv,so_id
            from TEMP_BC_BH_DTTT_MA_DT where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
                and ngay_htbs between b_ngaydn and b_ngayd1
                and (b_phong is null or phong=b_phong)
                and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
                and (b_ma_dl is null or ma_kt=b_ma_dl) and (b_ma_cb is null or cb_ql=b_ma_cb)
                and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--                and  FBH_HD_LKH(ma_dvig,so_id)=b_lkh
            group by ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,ngay,ngay_htnv,so_id;
    insert into temp_2 (c29,c1,c2,c3,c4,c5,c7,n12,n13)
        select c29,c1,c2,c3,c4,c5,c7,n10,n1 from temp_1;
end if;
--Xoa cac nghiep vu khong quan ly
if b_ma_dvi is null then
    delete temp_2 where substr(c7,0,2) not in (Select nv from temp_bc_nv);
    commit;
end if;
--ke_hoach

if b_ma_dvi is null then
    select count(*) into b_i1 from bh_ma_lhnv_kh where
        ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4)  and kieu='C' and kh<>0;
--so chi nhanh
    if b_i1<>0 then
        insert into temp_2 (c29,c7,n1) select dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0;
            commit;
    else
        insert into temp_2 (c29,c7,n1) select ma_dvi,ma,kh from bh_ma_lhnv_kh where
            (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0;
            commit;
    end if;
-- so van phong
    select ma into b_ma_vp from ht_ma_dvi where vp='C' and rownum=1;
    insert into temp_2 (c29,c4,c7,n1) select ma_dvi,dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_ma_vp and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0;
else

        select count(*) into b_i1 from bh_ma_lhnv_kh where
            ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0;

        if b_i1=0 then b_kieu:='C'; else b_kieu:='P'; end if;

        insert into temp_2 (c29,c7,c4,n1) select ma_dvi,ma,dvi,kh from bh_ma_lhnv_kh where
            ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%') and (b_phong is null or dvi=b_phong)
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu=b_kieu;
            commit;
end if;

--loai khach hang
if b_loai_kh is not null then
    update temp_2 set c6=(select loai from bh_hd_ma_kh where ma_dvi=temp_2.c29 and ma=temp_2.c2);
    --commit;
    delete temp_2 where  c6  not like b_loai_kh||'%' or c6 is null;
    commit;
end if;

insert into ket_qua(c20,c29,c1,c2,c3,c4,c5,c6,c7,n1,n2,n3,n4,n5,n6,n7,n8,n9,n10,n11,n12,n13)
select 'C',c29,c1,c2,c3,c4,c5,c6,c7,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0)),sum(nvl(n11,0)),
sum(nvl(n12,0)),sum(nvl(n13,0)) from temp_2 group by c29,c1,c2,c3,c4,c5,c6,c7;
commit;

update ket_qua set c30=(select ten from ht_ma_dvi where ma=ket_qua.c29);
update ket_qua set (c12,c6)=(select ten,loai from bh_hd_ma_kh where ma_dvi=ket_qua.c29 and ma=ket_qua.c2);
commit;
update ket_qua set c13=(select ten from ht_ma_cb where ma_dvi=ket_qua.c29 and ma=ket_qua.c3);
commit;
update ket_qua set c14=(select ten from ht_ma_phong where ma_dvi=ket_qua.c29 and ma=ket_qua.c4);
commit;
update ket_qua set c15=(select ten from bh_dl_ma_kh where ma_dvi=ket_qua.c29 and ma=ket_qua.c5);
commit;
update ket_qua set c16=(select ten from kh_ma_loai_dn where ma_dvi=ket_qua.c29 and ma=ket_qua.c6);
delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n4,0)=0 and nvl(n5,0)=0
    and nvl(n6,0)=0 and nvl(n7,0)=0 and nvl(n8,0)=0 and nvl(n9,0)=0 and nvl(n10,0)=0
    and nvl(n11,0)=0 and  nvl(n12,0)=0 and nvl(n13,0)=0  and nvl(n1,0)=0;
select count(*) into b_i1 from temp_bc_dvi;
commit;
open cs_kq for select c20 tc,c29 ma_dvi,c30 ten_dvi,c1 so_hd,c2 ma_kh, c12 ten_kh,c3 cb_ql, c13 ten_cbql,c4 phong,c14 ten_phong,
c5 ma_dl, c15 ten_dl,c6 loai_kh,c16 ten_loai,c7 lh_nv,c17 ten_lhnv,n1 ke_hoach,
n2 phi_ps,n3 thue_ps,(n4+n2) phi_ps_lk,(n5+n3) thue_s_lk,n6 phi_bh,n7 thue_bh,(n8+n6) phi_bh_lk,
(n9+n7) thue_bh_lk,n10 phi_tt,n11 thue_tt,(n12+n10) phi_tt_lk,(n13+n11) thue_tt_lk
from ket_qua order by n30,c7;

exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BBH_BH_BC_BH_NHANH_NGHIEPVU;

CREATE OR REPLACE PROCEDURE BBH_BH_BC_BH_NHANH_NGHIEPVU
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_NV VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,CS_KQ1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_I1 NUMBER;B_NV VARCHAR2(10);
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF FHT_MA_NSD_PHONG(B_MA_DVI,B_NSD)='TBH' THEN
    B_LOI:='loi:ban khong co quyen xem bao cao:loi';
    RAISE PROGRAM_ERROR;
END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_3';
EXECUTE IMMEDIATE 'TRUNCATE TABLE ket_qua';
COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
--DBMS_OUTPUT.PUT_LINE('1');
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
    BC_BH_LAY_BC_BH_DTPS_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_2 (C1,C3,C4,C5,C7,N1,N2,N3,N4) SELECT MA_DVI,
        FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHONG,LH_NV,SO_ID,PHI,0,0
        FROM TEMP_BC_BH_DTPS_MM WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND LH_NV LIKE B_MA_NV||'%';
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_2 (C1,C3,C4,C5,C7,N1,N2,N3,N4) SELECT MA_DVI,
        FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHONG,LH_NV,SO_ID,0,PHI,0
        FROM TEMP_BC_BH_DTBH_MM WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND LH_NV LIKE B_MA_NV||'%';
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MM';
    BC_BH_LAY_BC_BH_DTTT_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_2 (C1,C3,C4,C5,C7,N1,N2,N3,N4) SELECT MA_DVI,
        FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHONG,LH_NV,SO_ID,0,0,PHI
        FROM TEMP_BC_BH_DTTT_MM WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND LH_NV LIKE B_MA_NV||'%';
ELSE
--    DBMS_OUTPUT.PUT_LINE('2');
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
    BC_BH_LAY_BC_BH_DTPS_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_2 (C1,C3,C4,C5,C7,N1,N2,N3,N4) SELECT MA_DVI,
        FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHONG,LH_NV,SO_ID,PHI,0,0
        FROM TEMP_BC_BH_DTPS_MM,TEMP_BC_DVI WHERE MA_DVI=DVI
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND LH_NV LIKE B_MA_NV||'%';
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_2 (C1,C3,C4,C5,C7,N1,N2,N3,N4) SELECT  MA_DVI,
        FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHONG,LH_NV,SO_ID,0,PHI,0
        FROM TEMP_BC_BH_DTBH_MM,TEMP_BC_DVI WHERE MA_DVI=DVI
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND LH_NV LIKE B_MA_NV||'%';
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MM';
    BC_BH_LAY_BC_BH_DTTT_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
    INSERT INTO TEMP_2 (C1,C3,C4,C5,C7,N1,N2,N3,N4) SELECT  MA_DVI,
        FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHONG,LH_NV,SO_ID,0,0,PHI
        FROM TEMP_BC_BH_DTTT_MM,TEMP_BC_DVI WHERE MA_DVI=DVI
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND LH_NV LIKE B_MA_NV||'%';
END IF;

UPDATE
    (SELECT TEMP_2.C4 TEMP_2_C4, BH_MA_LHNV.TEN BH_MA_LHNV_TEN
        FROM TEMP_2, BH_MA_LHNV
             WHERE TEMP_2.C1 = BH_MA_LHNV.MA_DVI AND TEMP_2.C7 = BH_MA_LHNV.MA)
        SET TEMP_2_C4 = BH_MA_LHNV_TEN;
update TEMP_2 set c4 = (select max(ten) from bh_ma_lhnv where c7=ma) where c4 is null;

INSERT INTO KET_QUA(C1,c7,C4,C5,N2,N3,N4,N10)
    SELECT C1,c7,C4,C5,SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),N10
    FROM TEMP_2 GROUP BY C1,c7,C4,C5,N10;
--UPDATE
--       (SELECT KET_QUA.C6 KET_QUA_C6, HT_MA_PHONG.TEN HT_MA_PHONG_TEN
--              FROM KET_QUA, HT_MA_PHONG
--             WHERE KET_QUA.C1 = HT_MA_PHONG.MA_DVI AND KET_QUA.C5 = HT_MA_PHONG.MA)
--       SET KET_QUA_C6 = HT_MA_PHONG_TEN;
merge into KET_QUA using HT_MA_PHONG a on (a.ma=c5 and a.ma_dvi=c1) when matched then update set c6 =a.ten;
UPDATE KET_QUA SET C2=(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C1);
COMMIT;
OPEN CS_KQ FOR SELECT C1 MA_DVI,C2 TEN_DVI,c7 MA_NV, C4 TEN_NV,C5 PHONG,C6 TEN_PHONG,N2 DTPS,N3 DTBH,N4 DTTT
    FROM KET_QUA ORDER BY C1,C5,N10;
OPEN CS_KQ1 FOR SELECT c7 MA_NV, C4 TEN_NV,SUM(N2) DTPS,SUM(N3) DTBH,SUM(N4) DTTT
    FROM KET_QUA GROUP BY c7,C4,N10 ORDER BY N10,c7;
--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

