DROP FUNCTION BCNam_loai_xe_ten;
CREATE OR REPLACE FUNCTION BCNam_loai_xe_ten
(
    b_ma_dvi nvarchar2, b_ma nvarchar2
)return nvarchar2
AS
    b_giatri_ra nvarchar2(250);
BEGIN
    b_giatri_ra:='';
    select min(ten) into b_giatri_ra from bh_xe_loai where ma_dvi=b_ma_dvi and ma=b_ma;
    return b_giatri_ra;
END;
/

DROP FUNCTION BCNAM_MA_GD_TEN;

CREATE OR REPLACE FUNCTION BCNAM_MA_GD_TEN
(
    b_ma_dvi nvarchar2,b_ma nvarchar2
)return nvarchar2
AS
    b_giatri_ra nvarchar2(300);
BEGIN
    b_giatri_ra:='';

    select min(ten) into b_giatri_ra from bh_gdinh_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma;

    return b_giatri_ra;
END;
/

DROP FUNCTION BCNAM_NG_TO_SO;

CREATE OR REPLACE FUNCTION BCNAM_NG_TO_SO(b_ngay date) return number
AS
begin
return to_number(to_char(b_ngay,'yyyymmdd'));
end;
