    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_so_hd varchar2,b_gcn varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
as
    b_loi varchar2(100);b_ngaydn number;b_i1 number;--b_phong varchar2(30);
begin
    b_loi:=fht_ma_nsd_ktra(b_madvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise program_error; end if;
   -- PBC_QUYEN_XEM_BC(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong_x,'XE',b_phong);
