DROP PROCEDURE BC_BH_BKE_HUY;

CREATE OR REPLACE PROCEDURE BC_BH_BKE_HUY
	(B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
	B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TIEN_D NUMBER,B_TIEN_C NUMBER,B_NHOM  VARCHAR2,
	B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
	B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,
	B_TEN_PHONG OUT VARCHAR2,B_TEN_KHACH OUT VARCHAR2)
AS
	B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; 
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN
	SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
	SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
	SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE	B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN 
	SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_KH IS NOT NULL THEN
	SELECT TEN INTO B_TEN_KHACH FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TEN_KHACH:=' ';
END IF;
IF B_TIEN_C=0 AND B_TIEN_D<>0 THEN B_N1:=B_TIEN_D; B_N2:=1.E18;
ELSIF B_TIEN_C=0 AND B_TIEN_D=0 THEN B_N1:=-1.E18; B_N2:=1.E18;
ELSIF B_TIEN_D=0 THEN B_N1:=-1.E18; B_N2:=B_TIEN_C;
ELSE B_N1:=B_TIEN_D; B_N2:=B_TIEN_C;
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;


DELETE TEMP_6;
INSERT INTO TEMP_6 (N1,N2,N30) SELECT A.SO_ID,A.NGAY_HT,1 FROM BH_HD_GOC A,BH_HD_GOC_HUPS B
	WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND (B_MA_DVI IS NULL OR A.MA_DVI = B_MA_DVI)
	AND NO=0 AND TRA=0;

INSERT INTO TEMP_1(C29,C10,C1,C2,C3,N10,N1,N2,C20) 
	SELECT GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,GOC.NGAY_HT,SUM(nv.phi),SUM(nv.THUE),'CPSDT-NAMPSHD'
	FROM BH_HD_GOC GOC,BH_HD_GOC_PT NV,(SELECT DISTINCT N1 FROM TEMP_6) C
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID AND GOC.SO_ID=C.N1 AND GOC.KIEU_HD NOT IN ('V','U','K')
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	GROUP BY GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,GOC.NGAY_HT;


INSERT INTO TEMP_1(C29,C10,C1,C2,C3,N10,N1,N2,C20) 
	SELECT GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,NV.NGAY_TT,-SUM(nv.phi),-SUM(nv.THUE),'DPSDT-NAMPSHD'
	FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID
	AND KIEU_HD NOT IN ('V','U','K') AND PT<>'N' AND nv.PHI<0 AND SO_ID_TT=NV.SO_ID
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	GROUP BY GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,NV.NGAY_TT;



DELETE TEMP_6;
INSERT INTO TEMP_6 (N1,N2,N30) SELECT SO_ID,NGAY_HT,1 FROM BH_HD_GOC_HUPS WHERE 	
	(B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
	AND NO=0 AND TRA=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);

INSERT INTO TEMP_1(C29,C10,C1,C2,C3,N10,N1,N2,C20) 
	SELECT GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,GOC.NGAY_HT,SUM(nv.phi),SUM(nv.THUE),'CPSDT-NAMTC'
	FROM BH_HD_GOC GOC,BH_HD_GOC_PT NV,(SELECT DISTINCT N1 FROM TEMP_6) C
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID AND GOC.SO_ID=C.N1 AND GOC.KIEU_HD NOT IN ('V','U','K')
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	GROUP BY GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,GOC.NGAY_HT;


INSERT INTO TEMP_1(C29,C10,C1,C2,C3,N10,N1,N2,C20) 
	SELECT GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,NV.NGAY_TT,-SUM(nv.phi),-SUM(nv.THUE),'DPSDT-NAMTC'
	FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID
	AND KIEU_HD NOT IN ('V','U','K') AND PT<>'N' AND nv.PHI<0 AND SO_ID_TT=NV.SO_ID
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (NV.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	GROUP BY GOC.MA_DVI,MA_NT,SO_HD,MA_KH,CB_QL,NV.NGAY_TT;

UPDATE TEMP_1 SET N21=(SELECT A.TY_GIA FROM TT_TGTT A WHERE A.MA_DVI=TEMP_1.C29 AND
	A.NGAY=(SELECT MAX(B.NGAY) FROM TT_TGTT B WHERE B.MA_DVI=TEMP_1.C29 AND
	B.NGAY <=TO_DATE(TEMP_1.N10,'YYYYMMDD') AND B.MA=A.MA AND A.MA=TEMP_1.C10));

UPDATE TEMP_1 SET N1=N1*NVL(N21,1),N2=N2*NVL(N21,1);

INSERT INTO KET_QUA (C29,C1,C2,C3,N1,N2,C20)  SELECT C29,C1,C2,C3,SUM(NVL(N1,0)),SUM(NVL(N2,0)),C20  FROM TEMP_1 
	GROUP BY C29,C1,C2,C3,C20;

UPDATE KET_QUA SET C4 =(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=B_MA_DVI AND MA=KET_QUA.C3);			
UPDATE KET_QUA SET C5 =(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=KET_QUA.C2);

OPEN CS_KQ FOR SELECT C3 CB_QL,C4 TEN_CB,C2 MA_KH,C5 TEN,C1 SO_HD, 
	NVL(N1,0) DT_TT, NVL(N2,0) THUE,C20 NHOM
	FROM KET_QUA  ORDER BY C1,C2,C5;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_BOITHUONG_HH;

CREATE OR REPLACE PROCEDURE BC_BH_BOITHUONG_HH
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_TTRANG VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;--B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; --COMMIT;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;

BC_BH_THBT_MD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,'',B_NGAYD,B_NGAYC,B_LOI,'B');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO TEMP_2 (C1,C20,C24,C22,C2,C3,C5,C6,N1,N3,N6) 
        SELECT C29,C5,C6,C18,C19,C2,so_id,'',N10,N4,N6 FROM TEMP_1 A, BH_HD_GOC B --FBC_TEN_HANG(N13),FBC_PT_VC(N13)
        WHERE A.C29=B.MA_DVI AND A.N13=B.SO_ID AND C1='HANG' AND (B_TTRANG1 IS NULL OR B.TTRANG=B_TTRANG1); --C22 like HH%
ELSE
    INSERT INTO TEMP_2 (C1,C20,C24,C22,C2,C3,C5,C6,N1,N3,N6) 
        SELECT C29,C5,C6,C18,C19,C2,so_id,'',N10,N4,N6 FROM TEMP_1,TEMP_BC_DVI, BH_HD_GOC --FBC_TEN_HANG(N13),FBC_PT_VC(N13)
        WHERE C29=DVI AND C29=MA_DVI AND N13=SO_ID AND C1='HANG' AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1 );  
END IF;

UPDATE TEMP_2 SET N7=(SELECT SUM(TTOAN_QD) FROM BH_BT_GD_HS WHERE MA_DVI=TEMP_2.C1 AND SO_HS=TEMP_2.C3);

UPDATE TEMP_2 SET N8=(SELECT SUM(TTOAN_QD) FROM BH_CP WHERE MA_DVI=TEMP_2.C1 AND SO_HS=TEMP_2.C3);
UPDATE TEMP_2 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA=TEMP_2.C22); --MA_DVI=TEMP_2.C1 AND 
UPDATE TEMP_2 SET C21=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C20);
UPDATE TEMP_2 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA=TEMP_2.C24); --MA_DVI=TEMP_2.C1 AND 
UPDATE TEMP_2 SET C26=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_2.C1);

merge into temp_2 a using (select so_id,listagg(ten_pt,', ')ten_ptvc from bh_hang_ptvc group by so_id) b
on (a.c5=b.so_id) when matched then update set c7=ten_ptvc;
merge into temp_2 a using (select so_id,listagg(ten_hang,', ')ten_hang from bh_hang_ds group by so_id) b
on (a.c5=b.so_id) when matched then update set c8=ten_hang;

COMMIT;
OPEN CS_KQ FOR SELECT  C1 MA_DVI,C26 TEN_DVI,C20 MA_KH,C21 TEN_KH,'' CB_QL,'' TEN_CB_QL,C24 PHONG, C25 TEN_PHONG,C22 LH_NV,C23 TEN_LHNV,
    C2 NGAY_NHS,C3 SO_HSBT,c8 TEN_HANG,C7 PTVC,NVL(N3,0) STTT_KN,NVL(N4,0) GIAMD_KN,NVL(N5,0) CPK_KN,
    NVL(N6,0) STTT_BT,NVL(N7,0) GIAMD_BT,NVL(N8,0) CPK_BT FROM TEMP_2;
--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_BOITHUONG_TKE_HH;

create or replace PROCEDURE BC_BH_BOITHUONG_TKE_HH
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_SO_HD VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_TTRANG VARCHAR2,B_TIEND NUMBER,B_TIENC NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOAI VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');

IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='LOI:NHAP NGAY BAO CAO:LOI'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='LOI:MA CHUA DANG KY:LOI';
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);
IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
IF B_LOAI='TD' THEN B_TTRANG1:='T'; END IF;
INSERT INTO TEMP_2(C1,C2,C3,C4,C5,C6,C8,C9,N1,N2,N4,N5,N9,C30,c31)
    SELECT MA_DVI,NV,PHONG,SO_HS,PKH_SO_CNG(NGAY_XR),MA_NT,SO_HD,MA_KH,
            SO_ID,SO_ID_HD,TIEN,TIEN_QD,SO_ID_DT,'GQ',TTRANG
    FROM V_BC_BH_BT_GQ WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND (B_SO_HD IS NULL OR SO_HD=B_SO_HD)
            AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH) AND NV='HANG' AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1);

INSERT INTO TEMP_2(C1,C2,C3,C4,C5,C6,C8,C9,N1,N2,N4,N5,N9,C30,C31)
    SELECT MA_DVI,NV,PHONG,SO_HS,PKH_SO_CNG(NGAY_XR),MA_NT,SO_HD,MA_KH,
            SO_ID,SO_ID_HD,TIEN,TIEN_QD,SO_ID_DT,'TD',TTRANG
    FROM V_BC_BH_BT_GQ WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND (B_SO_HD IS NULL OR SO_HD=B_SO_HD)
            AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH) AND NV='HANG' AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1);

UPDATE TEMP_2 SET (C20,N8)=(SELECT MA_NT,SUM(TTOAN) FROM BH_BT_GD_HS WHERE MA_DVI=TEMP_2.C1 AND SO_HS_BT=TEMP_2.C4 and TTRANG = 'D' GROUP BY MA_NT);
UPDATE TEMP_2 SET (C20,N8)=(SELECT MA_NT,SUM(TTOAN) FROM BH_BT_GD_HS WHERE MA_DVI=TEMP_2.C1 AND SO_HS_BT=TEMP_2.C4 and TTRANG = 'T' and TEMP_2.C30 = 'TD' GROUP BY MA_NT);

UPDATE TEMP_2 SET (C25,N12)=(SELECT MA_NT,SUM(TIEN) FROM BH_BT_TU WHERE MA_DVI=TEMP_2.C1 AND SO_ID_HS=TEMP_2.N1 GROUP BY MA_NT);

UPDATE TEMP_2 SET (N3)=(SELECT SUM(TIEN) FROM BH_HANG_DK WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N2 );

UPDATE TEMP_2 SET C12=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C7);
UPDATE TEMP_2 SET C13=(SELECT TEN FROM bh_bt_hs WHERE MA_DVI=TEMP_2.C1 AND so_hs=TEMP_2.C4);
UPDATE TEMP_2 SET C14=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C3);
UPDATE TEMP_2 SET C15=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_2.C1);

UPDATE TEMP_2 SET C16=(SELECT PKH_SO_CNG(NGAY_HL) FROM BH_HANG WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N2 AND ROWNUM=1);
UPDATE TEMP_2 SET C26=(SELECT PKH_SO_CNG(NGAY_GUI) FROM BH_BT_HS WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N1);
-- UPDATE TEMP_2 SET C18=(SELECT ND FROM BH_KH_TTT_CT WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N1 AND PS='BT' AND
--                         NV='HANG' AND MA='NOIXAYRA');
-- UPDATE TEMP_2 SET C19=(SELECT ND FROM BH_KH_TTT_CT WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N1 AND PS='BT' AND
--                         NV='HANG' AND MA='NGUYENNHAN');
--UPDATE TEMP_2 SET (C10)=(SELECT TEN_HANG FROM BH_HANG_DS WHERE MA_DVI=C1 AND SO_ID=N1 AND SO_ID_DT=N9);
UPDATE TEMP_2 SET C11 = (SELECT MAX(TEN_PT) FROM BH_HANG_PTVC WHERE MA_DVI=C1 AND SO_ID=N1);-- AND SO_ID_DT=N9);
UPDATE TEMP_2 SET (N11)=(SELECT PT FROM BH_HD_DO_TL WHERE MA_DVI=C1 AND SO_ID=N1 AND SO_ID_DT IN (0,N9));
UPDATE TEMP_2 SET (C17)=(SELECT NT_TIEN FROM bh_bt_hs WHERE MA_DVI=C1 AND so_hs = C4);
UPDATE TEMP_2 SET (C18)=(SELECT FBH_HANG_NNTT_TENl(ma_nn) FROM BH_BT_HANG WHERE MA_DVI=C1 AND SO_HS=C4);
UPDATE TEMP_2 SET (C19)=(SELECT FBH_HANG_NNTT_TENl(ma_nn) FROM BH_BT_HANG WHERE MA_DVI=C1 AND SO_HS=C4);

IF B_LOAI='GQ' THEN
    DELETE TEMP_2 WHERE C30='TD' OR N4=0;
ELSIF B_LOAI='TD' THEN
    DELETE TEMP_2 WHERE C30='GQ';
END IF;
COMMIT;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    IF B_MA_DVI IS NULL OR B_MA_DVI ='' THEN
    OPEN CS_KQ FOR SELECT  C1 MA_DVI,C15 TEN_DVI,C8 SO_HD,C11 PTVC,C13 TEN_KH,'' TEN_HANG,C16 NGAY_KH,C17 MA_NT_HD,C20 NT_GD,
                    SUM(NVL(N3,0)) TIEN,C4 SO_HSBT,C5 NGAY_XR,C18 NOIXAYRA,C19 NGUYENNHAN,C6 MA_NT_BT,SUM(NVL(N4,0)) TIEN_GQ,
                    SUM(NVL(N8,0)) GD_GQ,SUM(NVL(N6,0)) TIEN_TD,SUM(NVL(N8,0)) GD_TD,C25 NT_TU,SUM(NVL(N12,0)) TU_TD,
                    C18 NN_DD_TT,N11 PT_DO,C21 GHI_CHU,C26 NGAY_TB,C31 TTRANG
                    FROM TEMP_2 GROUP BY C1,N1,N2,C15,C8,C11,C13,C10,C16,C17,C4,C5,C18,C19,C6,C20,N11,C21,C25,C26,C31 ORDER BY C1;
    ELSE
    OPEN CS_KQ FOR SELECT C14 TEN_DVI,C8 SO_HD,C11 PTVC,C13 TEN_KH,'' TEN_HANG,C16 NGAY_KH,C17 MA_NT_HD,C20 NT_GD,
                    SUM(NVL(N3,0)) TIEN,C4 SO_HSBT,C5 NGAY_XR,C18 NOIXAYRA,C19 NGUYENNHAN,C6 MA_NT_BT,SUM(NVL(N4,0)) TIEN_GQ,
                    SUM(NVL(N8,0)) GD_GQ,SUM(NVL(N6,0)) TIEN_TD,SUM(NVL(N8,0)) GD_TD,C25 NT_TU,SUM(NVL(N12,0)) TU_TD,
                    C18 NN_DD_TT,N11 PT_DO,C21 GHI_CHU,C26 NGAY_TB,C31 TTRANG
                    FROM TEMP_2 WHERE C1=B_MA_DVI GROUP BY C3,N1,N2,C14,C8,C11,C13,C10,C16,C17,C4,C5,C18,C19,C6,C20,N11,C21,C25,C26,C31 ORDER BY C3;
    END IF;
ELSE
OPEN CS_KQ FOR SELECT  C1 MA_DVI,C14 TEN_DVI,C8 SO_HD,C11 PTVC,C13 TEN_KH,'' TEN_HANG,C16 NGAY_KH,C17 MA_NT_HD,C20 NT_GD,
                    SUM(NVL(N3,0)) TIEN,C4 SO_HSBT,C5 NGAY_XR,C18 NOIXAYRA,C19 NGUYENNHAN,C6 MA_NT_BT,SUM(NVL(N4,0)) TIEN_GQ,
                    SUM(NVL(N8,0)) GD_GQ,SUM(NVL(N6,0)) TIEN_TD,SUM(NVL(N8,0)) GD_TD,C25 NT_TU,SUM(NVL(N12,0)) TU_TD,
                    C18 NN_DD_TT,N11 PT_DO,C21 GHI_CHU,C26 NGAY_TB,C31 TTRANG
                    FROM TEMP_2,TEMP_BC_DVI WHERE C1=DVI GROUP BY C3,N1,N2,C1,C14,C8,C11,C13,C10,C16,C17,C4,C5,C18,C19,C6,C20,N11,C21,C25,C26,C31 ORDER BY C3;
END IF;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_BTHS_MD;
CREATE OR REPLACE PROCEDURE BC_BH_BTHS_MD
    (B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_N_DUYET VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Loi ho so boi thuong:loi';
DELETE TEMP_1;COMMIT;
if b_ma_dvi is not null then
    INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,D7) 
        SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,TO_CHAR(NGAY_GUI,'dd/mm/yyyy'),TO_CHAR(NGAY_XR,'dd/mm/yyyy'),'' KVUC,N_TRINH,N_DUYET,TO_CHAR(NGAY_QD,'dd/mm/yyyy'),
        ''MA_NN,''MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_HT,SO_ID_HD,TIEN_BH,PT_BT,T_THAT,''K_TRU,TIEN,to_date(NGAY_XR,'yyyyMMdd')
        FROM BH_BT_HS BT,BH_BT_HS_NV NV
        WHERE 
        BT.MA_DVI = B_MA_DVI and (BT.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)    
        and BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI=BT.MA_DVI_QL
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
else
    INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,D7) 
        SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,TO_CHAR(NGAY_GUI,'dd/mm/yyyy'),TO_CHAR(NGAY_XR,'dd/mm/yyyy'),'' KVUC,N_TRINH,N_DUYET,TO_CHAR(NGAY_QD,'dd/mm/yyyy'),
        ''MA_NN,''MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,BT.NGAY_HT,SO_ID_HD,TIEN_BH,PT_BT,T_THAT,''K_TRU,TIEN,to_date(NGAY_XR,'yyyyMMdd')
        FROM BH_BT_HS BT,BH_BT_HS_NV NV
        WHERE 
        --(B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) AND 
        (BT.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)    
        and BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI=BT.MA_DVI_QL
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
end if;    
UPDATE TEMP_1 SET (C4,C5,N11) =(SELECT SO_HD,MA_KH,NGAY_HT FROM BH_HD_GOC WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N13);
UPDATE TEMP_1 SET C6=(SELECT PHONG FROM BH_HD_GOC WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N13);
IF B_PHONG IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;
UPDATE TEMP_1 SET C16 =(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C29 AND MA=TEMP_1.C5);
IF B_MA_KH IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C5<>B_MA_KH;
END IF;
DELETE TEMP_1 WHERE (B_LOAI_KH IS NOT NULL AND C16  NOT LIKE B_LOAI_KH||'%');
B_LOI:='';
END;
/
DROP PROCEDURE BC_BH_BT_TSTD;

CREATE OR REPLACE PROCEDURE BC_BH_BT_TSTD
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_TC VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_NV VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN
--nam
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;
--PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
--IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;
BC_BH_THBT_MD_CD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,'',B_NGAYD,B_NGAYC,B_LOI,'B');
--DELETE TEMP_1 WHERE C1 NOT IN (SELECT NV FROM TEMP_BC_NV);
IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
   INSERT INTO TEMP_2(C30,C29,C6,C1,C4,C5,C2,C7,C17,C19,N3,N4,N5,N12,N6,N13,N10,N11,C22,N15,N14)
      SELECT C1,C29,C6,C18,C4,C5,C2,C7,C17,C19,N3,N4,N5,N12,N7,N13,N10,N6,C22,N15,N14 FROM TEMP_1 a,BH_BT_HS b
       WHERE a.C1=B_NV AND a.C29=b.MA_DVI AND a.N13=b.SO_ID AND (B_TTRANG1 IS NULL OR b.TTRANG=B_TTRANG1);
ELSE
   INSERT INTO TEMP_2(C30,C29,C6,C1,C4,C5,C2,C7,C17,C19,N12,N6,N13,N10,N11,C22,N15)
   SELECT C1,C29,C6,C18,C4,C5,C2,C7,C17,C19,N12,N7,N13,N10,N6,C22,N15 FROM TEMP_1 a,TEMP_BC_DVI b,BH_BT_HS c
    WHERE a.C29=b.DVI AND a.C1=B_NV AND a.C29=c.MA_DVI AND a.N13=c.SO_ID AND (B_TTRANG1 IS NULL OR c.TTRANG=B_TTRANG1);
END IF;

BC_BH_THGD_MD_CD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,B_NGAYD,B_NGAYC,B_LOI,'B');
UPDATE TEMP_2 SET N7=(SELECT SUM(N7) FROM TEMP_1 WHERE C29=TEMP_2.C29 AND N30=TEMP_2.N10 AND C18=TEMP_2.C1);
UPDATE TEMP_2 SET C28=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_2.C29);
UPDATE TEMP_2 SET C26=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_2.C29 AND MA=TEMP_2.C6);
UPDATE TEMP_2 SET C21=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_2.C29 AND MA=TEMP_2.C1);
UPDATE TEMP_2 SET (C25,C26)=(SELECT TEN,LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_2.C29 AND MA=TEMP_2.C5);

UPDATE TEMP_2 SET N29=(SELECT NVL(MAX(NGAY_TT),30000101) FROM BH_HD_GOC_TTPT WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND PT<>'C');

UPDATE TEMP_2 SET C27 ='1',C30='A' WHERE C26 LIKE '1.1%';
UPDATE TEMP_2 SET C27 ='2',C30='B' WHERE C26 NOT LIKE '1.1%';

UPDATE TEMP_2 SET N8=(SELECT SO_ID_DT FROM BH_BT_HS_NV WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N13 AND ROWNUM=1);
--Ty le dong BH
UPDATE TEMP_2 SET N23=(SELECT SUM(PT)/100 FROM BH_HD_DO_TL WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 and so_id_dt in (0,TEMP_2.N8) and pthuc='C');

UPDATE TEMP_2 SET (C20,N14)=(SELECT MIN(MA_NT),SUM(TIEN) FROM BH_BT_TU WHERE MA_DVI=TEMP_2.C29 AND SO_ID_HS=TEMP_2.N10);

IF B_NV='PHH' THEN
  UPDATE TEMP_2 SET (C11,C12)=(SELECT PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT) FROM BH_PHH_DVI WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND SO_ID_DT=TEMP_2.N8);
  UPDATE TEMP_2 SET (C13)=(SELECT DVI FROM BH_PHH_DVI WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND SO_ID_DT=TEMP_2.N8);
  UPDATE TEMP_2 SET (N20)=(SELECT SUM(TIEN) FROM BH_PHH_DK WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND SO_ID_DT=TEMP_2.N8 and lh_nv<>' ');
  UPDATE TEMP_2 SET C21=(SELECT sp.TEN FROM bh_phh p,bh_phh_sp sp WHERE p.MA_DVI=TEMP_2.C29 AND p.SO_ID=TEMP_2.N12 and p.ma_sp = sp.ma);
  UPDATE TEMP_2 SET C16=(SELECT t.TEN FROM bh_bt_phh p,bh_phh_nntt t WHERE p.MA_DVI=TEMP_2.C29 AND p.SO_ID=TEMP_2.N13 and p.ma_nn=t.ma);
elsIF B_NV='PKT' THEN
  UPDATE TEMP_2 SET (C11,C12)=(SELECT PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT) FROM BH_PKT_DVI WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND SO_ID_DT=TEMP_2.N8);
  UPDATE TEMP_2 SET (C13)=(SELECT DVI FROM BH_PKT_DVI WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND SO_ID_DT=TEMP_2.N8);
  UPDATE TEMP_2 SET (N20)=(SELECT SUM(TIEN) FROM BH_PKT_DK WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 AND SO_ID_DT=TEMP_2.N8 and lh_nv<>' ');
  UPDATE TEMP_2 SET C21=(SELECT sp.TEN FROM BH_PKT p,BH_PKT_sp sp WHERE p.MA_DVI=TEMP_2.C29 AND p.SO_ID=TEMP_2.N12 and p.ma_sp = sp.ma);
  UPDATE TEMP_2 SET C16=(SELECT t.TEN FROM bh_bt_pkt p,bh_pkt_nntt t WHERE p.MA_DVI=TEMP_2.C29 AND p.SO_ID=TEMP_2.N13 and p.ma_nn=t.ma);
elsIF B_NV='PTN' THEN
  UPDATE TEMP_2 SET (C11,C12,C14)=(SELECT PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),PKH_SO_CNG(NGAY_CAP) FROM BH_PTN WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12);
  UPDATE TEMP_2 SET (C13)=(SELECT DCHI FROM BH_PTN WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12);
  UPDATE TEMP_2 SET (N20)=(SELECT SUM(TIEN) FROM BH_PTN_DK WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 and lh_nv<>' ');
  UPDATE TEMP_2 SET C21=FBH_HD_TXT('PTN',C29,N12,'ma_sp');
  UPDATE TEMP_2 SET C16=(SELECT t.TEN FROM bh_bt_ptn p,bh_ptn_nntt t WHERE p.MA_DVI=TEMP_2.C29 AND p.SO_ID=TEMP_2.N13 and p.ma_nn=t.ma);
elsIF B_NV='HOP' THEN
  UPDATE TEMP_2 SET (C11,C12,C14)=(SELECT PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),PKH_SO_CNG(NGAY_CAP) FROM BH_HOP WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12);
  UPDATE TEMP_2 SET (C13)=(SELECT DCHI FROM BH_HOP WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12);
  UPDATE TEMP_2 SET (N20)=(SELECT SUM(TIEN) FROM BH_HOP_DK WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N12 and lh_nv<>' ');
  UPDATE TEMP_2 SET C21=FBH_HD_TXT('HOP',C29,N12,'ma_sp');
  UPDATE TEMP_2 SET C16=(SELECT t.TEN FROM BH_BT_HOP p,BH_HOP_NNTT t WHERE p.MA_DVI=TEMP_2.C29 AND p.SO_ID=TEMP_2.N13 and p.ma_nn=t.ma);
END IF;
COMMIT;

OPEN CS_KQ FOR SELECT C30 STT,C29 MA_DVI, C6 MA_PHONG, C26 TEN_PHONG,C27 MA_LKH,
    TO_NUMBER(SUBSTR(C7,7,4)) NAM,
    C1 MA_NV, C21 TEN_NV, C25 TEN_KH, C4 SO_GCN,
    DECODE(N29,30000101,'Chua nop phi',N29) NGAY_TT, C2 SO_HS,
    C7 NGAY_XR, C19 NGAY_GUI, N12 NGAY_HS, NVL(N28,0) NGAY_TD, NVL(N6,0) TIEN_U ,NVL(N7,0) TIEN_GDU,
    C11 NGAY_HL,C12 NGAY_KT,C13 DDIEM,C14 NGAY_CAP,NVL(N9,0) TIENBH,C16 TEN_NN,C36 GHI_CHU, 
    N20 TIEN_BH,C22 NT_TIEN,C17 NT_BT,N5 TIEN_UBT,N3 TU_TD,C17 NT_TU,N23 PT_DO,N4 TIEN_CON
    FROM TEMP_2 ORDER BY C29,C6,C1,C5;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE bc_bh_chigd;

CREATE OR REPLACE PROCEDURE bc_bh_chigd
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_dvi varchar2,
    b_ma_phong varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_maphong out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number;b_i1 number;
Begin
-- BCNamm Bao cao chi giam dinh
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi';raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
if b_ma_phong is not null then
    select ten into b_maphong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_ma_phong;
else b_maphong:=' ';
end if;
delete temp_1;delete temp_2;delete ket_qua;commit;
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
--lay So tien chi giam dinh
insert into temp_2(c29,c1,n1,c3,c5,n2) select ma_dvi,so_hs,so_id,phong,PKH_SO_CNG(ngay_ht),sum(tien_qd)
    from bh_bt_gd_hs where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and ngay_ht between b_ngayd and b_ngayc
    group by ma_dvi,so_hs,so_id,phong,ngay_ht;
--tam ung giam dinh
--LAM SACH
-- insert into temp_2(c29,n1,c5,n3) select ma_dvi,so_id_hs,PKH_SO_CNG(ngay_ht),sum(tien_qd)
--     from bh_bt_gd_tu where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
--     and ngay_ht between b_ngayd and b_ngayc
--     group by ma_dvi,so_id_hs,ngay_ht;
--thanh toan giam dinh
-- LAM SACH
-- insert into temp_2(c29,n1,c5,n3) select a.ma_dvi,so_id,PKH_SO_CNG(ngay_ht),sum(tien_qd)
--     from bh_bt_gd_tt a, bh_bt_gd_tt_ps b where a.ma_dvi=b.ma_dvi and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
--     and a.so_id_tt=b.so_id_tt and ngay_ht between b_ngayd and b_ngayc
--     group by a.ma_dvi,so_id,ngay_ht;

insert into temp_1(c29,n1,n2,n3) select c29,n1,sum(n2),sum(n3) from temp_2   group by c29,n1;
--BCNam: sua lai
update temp_1 set (n2)=(select sum(tien_qd) from bh_bt_gd_hs where ma_dvi=c29 and so_id=n1) where n2=0 or n2 is null;
update temp_1 set (c1,c2,c3,c14)=(select so_hs,PKH_SO_CNG(ngay_ht),phong,ma_gd from bh_bt_gd_hs where ma_dvi=temp_1.c29 and so_id=temp_1.n1);
--LAM SACH
-- update temp_1 set (c5)=(select PKH_SO_CNG(ngay_ht) from   bh_bt_gd_tu
--         where ma_dvi=temp_1.c29 and so_id_hs=temp_1.n1 and rownum=1);

--LAM SACH
-- update temp_1 set (c5)=(select PKH_SO_CNG(a.ngay_ht) from   bh_bt_gd_tt a, bh_bt_gd_tt_ps b
--         where a.ma_dvi=b.ma_dvi and  a.so_id_tt=b.so_id_tt and a.ma_dvi=temp_1.c29 and b.so_id=temp_1.n1 and rownum=1) where c5 is null;
-- END LAM SACH
update temp_1 set n4=nvl(n2,0)-nvl(n3,0);
select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    insert into ket_qua(n1,c29,c1,c2,c5,n2,n3,n4,c14) select n1,c29,c1,c2,c5,sum(n2),sum(n3),sum(n4),c14
        from temp_1 group by n1,c29,c1,c2,c5,c14;
else
    insert into ket_qua(n1,c29,c1,c2,c5,n2,n3,n4,c14) select n1,c29,c1,c2,c5,sum(n2),sum(n3),sum(n4),c14
        from temp_1,temp_bc_dvi where c29=dvi group by n1,c29,c1,c2,c5,c14;
end if;
--delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0;
--DQD RAO
----update ket_qua set (n5,n6,n8)=(select so_id_bt,so_id_hd,ngay_ht from bh_bt_gd_hs where so_id=n1 and ma_dvi=c29);
--update ket_qua set (n7,c4)=(select so_id_dt,lh_nv from bh_bt_gd_hs_pt where so_id=n1 and ma_dvi=c29 and rownum=1);

--update ket_qua set n9=(select nvl(sum(pt),0) from bh_hd_do_tl where so_id=n1 and (so_id_dt=0 or so_id_dt=n7) and (lh_nv='*' or lh_nv=c4)
--                        and kieu='D' and pthuc='C');
--update ket_qua set n11=(select nvl(sum(pt),0) from bh_hd_do_tl where so_id=n1 and (so_id_dt=0 or so_id_dt=n7) and (lh_nv='*' or lh_nv=c4)
--                        and kieu='V' and pthuc='C');

--update ket_qua set n13=(select nvl(sum(pt),0) FROM tbh_ghep_pbo where ma_dvi_hd=c29 and (so_id_hd=n6)
--        and (so_id_dt=0 or so_id_dt=n7) and lh_nv like c4||'%'
--        and so_id in (select so_id from tbh_ghep where ng_tai <= n8) group by so_id_hd,so_id_dt,lh_nv);
--update ket_qua set n14=(select DISTINCT nvl(sum(pt),0) FROM tbh_tm_pbo where ma_dvi_hd=c29 and (so_id_hd=n6)
--        and (so_id_dt=0 or so_id_dt=n7) and lh_nv like c4||'%'
--        and so_id in (select so_id from tbh_tm where ng_tai <= n8) group by so_id_hd,so_id_dt,lh_nv);

update ket_qua set c30=(select ten from ht_ma_dvi where ma=ket_qua.c29);

open cs_kq for select c29 ma_dvi ,c30 ten_dvi,c1 as so_hs,c14 ma_gd, BCNAM_MA_GD_TEN(c29,c14) ten, c2 as ngay_hs,round(nvl(n2,0)) as tien,
    c5 as ngay_thu,round(nvl(n3,0)) as tien_thu, n4 as no from ket_qua
    where (b_ma_phong is null or c3=b_ma_phong) order by c1;
--exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_BH_CHI_HHHT;

CREATE OR REPLACE PROCEDURE BC_BH_CHI_HHHT
	(B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
	B_MA_NV VARCHAR2,B_DLY VARCHAR2,B_PHONG VARCHAR2,
	B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
	B_TENNV OUT VARCHAR2,B_TEN_DLY OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
	B_LOI VARCHAR2(100);B_NGAYDN NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_NV IS NOT NULL THEN
	SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_DLY IS NOT NULL THEN
	SELECT TEN INTO B_TEN_DLY FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_DLY;
ELSE B_TEN_DLY:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
	SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
DELETE TEMP_2;DELETE KET_QUA;COMMIT;

INSERT INTO TEMP_2(C1,N2) SELECT LH_NV,HHONG_QD 
	FROM BH_HD_GOC G,BH_HD_GOC_HH_PT P WHERE G.MA_DVI=B_MA_DVI AND P.MA_DVI=B_MA_DVI
	AND G.SO_ID=P.SO_ID AND SO_ID_HH IN(SELECT SO_ID_HH FROM BH_HD_GOC_HH WHERE  MA_DVI=B_MA_DVI AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG)
	AND (B_DLY IS NULL OR MA_KT=B_DLY)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');

INSERT INTO TEMP_2(C1,N3) SELECT LH_NV,HHONG_QD 
	FROM BH_HD_GOC G,BH_HD_GOC_HH_PT P WHERE G.MA_DVI=B_MA_DVI AND P.MA_DVI=B_MA_DVI
	AND G.SO_ID=P.SO_ID  AND SO_ID_HH IN(SELECT SO_ID_HH FROM BH_HD_GOC_HH WHERE  MA_DVI=B_MA_DVI AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG)
	AND (B_DLY IS NULL OR MA_KT=B_DLY)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
INSERT INTO KET_QUA(C1,N2,N3)
		SELECT C1,SUM(N2),SUM(N3) FROM TEMP_2 GROUP BY C1;
DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N3,0)=0;
UPDATE KET_QUA SET C2=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI
	AND MA=KET_QUA.C1);
OPEN CS_KQ FOR SELECT C1 MA,C2 TEN,NVL(N2,0) TIEN,NVL(N3,0) AS LUY_KE
	FROM KET_QUA;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

drop PROCEDURE BC_BH_CHI_PHI_QLY_HDONG_DBH;

CREATE OR REPLACE PROCEDURE BC_BH_CHI_PHI_QLY_HDONG_DBH
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_MA_DVI_CT VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_MA_DVI_M VARCHAR2(20);B_TEN_DVI VARCHAR2(100);
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'KT','KT','NX');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_MA_DVI_CT='00' THEN B_MA_DVI_M:='0'; ELSE B_MA_DVI_M:=B_MA_DVI_CT; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;
B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN SELECT TEN INTO B_TEN_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA;COMMIT;
INSERT INTO TEMP_1(C3,N1) SELECT LH_NV,SUM(TIEN_QD) FROM BH_HD_DO_PT WHERE NV='T' AND LOAI='CH_LE_HH'
        AND (MA_DVI LIKE B_MA_DVI_M||'%')
        AND SO_ID_TT IN (SELECT SO_ID_TT FROM BH_HD_DO_TT
                            WHERE (MA_DVI LIKE B_MA_DVI_M||'%')
                            AND SO_ID_KT IN (SELECT SO_ID FROM KT_3 WHERE (MA_DVI LIKE B_MA_DVI_M||'%')
                            AND (NGAY_HT BETWEEN B_NGAYDN AND B_NGAYD-1)))
        GROUP BY LH_NV;
INSERT INTO TEMP_1(C3,N2) SELECT LH_NV,SUM(TIEN_QD) FROM BH_HD_DO_PT WHERE NV='T' AND LOAI='CH_LE_HH'
    AND (MA_DVI LIKE B_MA_DVI_M||'%')
    AND SO_ID_TT IN (SELECT SO_ID_TT FROM BH_HD_DO_TT
                            WHERE (MA_DVI LIKE B_MA_DVI_M||'%')
                            AND SO_ID_KT IN (SELECT SO_ID FROM KT_3
                                             WHERE (MA_DVI LIKE B_MA_DVI_M||'%')
                                             AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)))
        GROUP BY LH_NV;
INSERT INTO TEMP_1(C3,N3) SELECT LH_NV,SUM(TIEN_QD) FROM BH_HD_DO_PT WHERE NV='T' AND LOAI='CH_LE_HH'
    AND (MA_DVI LIKE B_MA_DVI_M||'%')
    AND SO_ID_TT IN (SELECT SO_ID_TT FROM BH_HD_DO_TT
                            WHERE (MA_DVI LIKE B_MA_DVI_M||'%')
                            AND SO_ID_KT IN (SELECT SO_ID FROM KT_3
                                             WHERE (MA_DVI LIKE B_MA_DVI_M||'%')
                                             AND (NGAY_HT BETWEEN B_NGAYDN AND B_NGAYC)))
        GROUP BY LH_NV;

INSERT INTO KET_QUA(C3,N1,N2,N3) SELECT C3,SUM(N1),SUM(N2),SUM(N3) FROM TEMP_1 GROUP BY C3;

INSERT INTO TEMP_2(C3,N1,N2,N3) SELECT SUBSTR(C3,1,2),SUM(N1),SUM(N2),SUM(N3) FROM KET_QUA GROUP BY SUBSTR(C3,1,2);

INSERT INTO TEMP_3(N5,N6,N7) SELECT SUM(N1),SUM(N2),SUM(N3) FROM KET_QUA;

INSERT INTO KET_QUA(C3,N1,N2,N3,N9) SELECT C3,N1,N2,N3,2 FROM TEMP_2;

UPDATE KET_QUA SET (N5,N6,N7)=(SELECT N5,N6,N7 FROM TEMP_3);
UPDATE KET_QUA SET C4=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=C3);

UPDATE KET_QUA SET N30=1 WHERE C1 LIKE 'XG%';
UPDATE KET_QUA SET N30=2 WHERE C1 LIKE 'CN%';
UPDATE KET_QUA SET N30=3 WHERE C1 LIKE 'HH%';
UPDATE KET_QUA SET N30=4 WHERE C1 LIKE 'TT%';
UPDATE KET_QUA SET N30=5 WHERE C1 LIKE 'HH%';
UPDATE KET_QUA SET N30=6 WHERE C1 LIKE 'TS%';
UPDATE KET_QUA SET N30=7 WHERE C1 LIKE 'HP%';
UPDATE KET_QUA SET N30=8 WHERE C1 LIKE 'TN%';

OPEN CS_KQ FOR SELECT ' ' MA_TK,' ' TEN_TK,NVL(C3,' ') MA_TKE,NVL(C4,' ') TEN_TKE,NVL(N1,0) DK,
     NVL(N2,0) PS,NVL(N3,0) LK_PS,NVL(N4,0) CK,NVL(N5,0) TDK, NVL(N6,0) TPS,NVL(N7,0) TLK_PS,NVL(N8,0) TCK,NVL(N9,1) NHOM
    FROM KET_QUA ORDER BY N30,C3;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
