DROP PROCEDURE BC_BH_CNKH_BT_CT;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_BT_CT
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_kh varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);
Begin
-- Bao cao cong no boi thuong
b_loi:='loi:Ma chua dang ky:loi';
--delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
execute immediate 'truncate table temp_1';
execute immediate 'truncate table temp_2';
execute immediate 'truncate table temp_3';
execute immediate 'truncate table ket_qua';
--n2 ps no,n3 ps c,n6 du co dk,n15 dc cuoi ky,n5 dn dau ky,n14 n ck

b_loi:='loi:Lay so lieu phat sinh co:loi';
BC_BH_CNKH_BT_MD(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2(c20,n10,n2,n3,n5,n6,n14,n15) select c1,n10,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),sum(n15) from temp_1 group by c1,n10;
b_loi:='loi:Lay so lieu ma khach hang:loi';
--update temp_2 set (c1,n11,c21)=(select so_hs,so_id_hd,ma_dvi_ql from bh_bt_hs where ma_dvi=temp_2.c20 and so_id=temp_2.n10);
update
    (select temp_2.c1 t_c1, temp_2.n11 t_n11, temp_2.c21 t_c21, 
        bh_bt_hs.so_hs hd_so_hs, bh_bt_hs.so_id_hd hd_so_id, bh_bt_hs.ma_dvi_ql hd_ma_dvi_ql
        from temp_2, bh_bt_hs
        where  bh_bt_hs.ma_dvi=temp_2.c20 and bh_bt_hs.so_id=temp_2.n10)
        set t_c1 = hd_so_hs, t_n11 = hd_so_id, t_c21 = hd_ma_dvi_ql;

update temp_2 set (c4,c5)=(select /*+ parallel (bh_hd_goc,4) */ ma_kh,phong from bh_hd_goc where ma_dvi=temp_2.c21 and so_id=temp_2.n11);
delete temp_2 where c5='TBH' or c1 is null;
b_loi:='loi:Lay so lieu ket qua:loi';
insert into ket_qua(c1,c4,c21,n2,n3,n5,n6,n14,n15,c20)
    select c1,c4,c21,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),
    sum(n15),c20 from temp_2 where (b_ma_kh is null or c4=b_ma_kh) group by c4,c1,c21,c20;
--update ket_qua set c5=(select ten from bh_hd_ma_kh where ma_dvi=ket_qua.c21 and ma=ket_qua.c4);
update
    (select ket_qua.c5 t_c5, bh_hd_ma_kh.ten hd_ten
        from ket_qua, bh_hd_ma_kh
        where  bh_hd_ma_kh.ma_dvi=ket_qua.c21 and bh_hd_ma_kh.ma=ket_qua.c4)
        set t_c5 = hd_ten;

delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n5,0)=0
    and nvl(n6,0)=0 and nvl(n14,0)=0 and nvl(n15,0)=0;
delete ket_qua where c1 is null;
commit;
open cs_kq for select c20 ma_dvi,' ' ngay_hd,' ' so_hd,
    '33111' ma_tk,unistr('Ph\1EA3i tr\1EA3 v\1EC1 chi b\1ED3i th\01B0\1EDDng b\1EA3o hi\1EC3m g\1ED1c') ten_ma_tk,c1 ma_td,
    c1 ten_ma_td,c4 ma_cn,c5 ten_ma_cn,nvl(n5,0) as no_dk,
    nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck,
    nvl(n15,0) as co_ck from ket_qua order by c4;
--delete temp_1;delete temp_2;delete temp_3;commit;
exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_BH_CNKH_GD;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_GD
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_dvi varchar2,b_ma_kh varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);
Begin
-- Bao cao cong no giam dinh
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
BC_BH_CNKH_GD_MD(b_ma_dvi,b_ngayd,b_ngayc,b_loi);
b_loi:='loi:Lay ma khach hang:loi';
update temp_1 set (c3,c4,c10)=(select phong,ma_gd,k_ma_gd from bh_bt_gd_hs where ma_dvi=c1 and so_id=n10);
update temp_1 set (c7)=(select phong from bh_hd_goc where ma_dvi=temp_1.c1 and so_id=temp_1.n8);
delete temp_1 where c7='TBH' or c3 ='TBH';
b_loi:='loi:Lay ket qua bao cao:loi';
delete temp_1 where n10=2017101049885011;
insert into ket_qua(c20,c4,c10,n2,n3,n5,n6,n14,n15) select c1,c4,c10,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),
    sum(n15) from temp_1 where (b_ma_kh is null or c4=b_ma_kh) group by c1,c4,c10;
update ket_qua set c5=(select ten from bh_gdinh_ma_kh where ma_dvi=ket_qua.c20 and ma=ket_qua.c4) where c10='G';
update ket_qua set c5=(select ten from ht_ma_cb where ma_dvi=ket_qua.c20 and ma=ket_qua.c4) where c10='C';
update ket_qua set c5=(select ten from bh_dl_ma_kh where ma_dvi=ket_qua.c20 and ma=ket_qua.c4) where c10='D';
delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n14,0)=0 and nvl(n15,0)=0;
open cs_kq for select c1 ma_dvi,' ',' ','33113' ma_tk,'Chi giam dinh' ten_ma_tk,' ' ma_td,
    ' ' ten_ma_td,c4 ma_cn,c5 ten_ma_cn,nvl(n5,0) as no_dk, nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck,
    nvl(n15,0) as co_ck from ket_qua order by c4;

exception when others then if b_loi is null then raise PROGRAM_ERROR; else  raise_application_error(-20105,b_loi); end if;
end;
/

DROP PROCEDURE BC_BH_CNKH_GD_CT;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_GD_CT
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_kh varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);
Begin
-- Bao cao cong no giam dinh
b_loi:='loi:Ma chua dang ky:loi';
if b_ma_kh is not null then
    select ten into b_tenkh
        from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma_kh;
else b_tenkh:=' ';end if;
--delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
execute immediate 'truncate table temp_1';
execute immediate 'truncate table temp_2';
execute immediate 'truncate table temp_3';
execute immediate 'truncate table ket_qua';
BC_BH_CNKH_GD_MD(b_ma_dvi,b_ngayd,b_ngayc,b_loi);
b_loi:='loi:Lay ma khach hang:loi';

update temp_1 set (c2,c3,c4,c10)=(select so_hs,phong,ma_gd,k_ma_gd from bh_bt_gd_hs where ma_dvi=temp_1.c1 and so_id=temp_1.n10);
update temp_1 set (c7)=(select phong from bh_hd_goc where ma_dvi=temp_1.c1 and so_id=temp_1.n8);
delete temp_1 where c7='TBH' or c3 ='TBH';
b_loi:='loi:Lay ket qua bao cao:loi';
insert into ket_qua(c1,c2,c4,c10,n2,n3,n5,n6,n14,n15)
    select c1,c2,c4,c10,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),
    sum(n15) from temp_1 where (b_ma_kh is null or c4=b_ma_kh) group by c4,c1,c2,c10;

update ket_qua set c5=(select ten from bh_gdinh_ma_kh where
    ma_dvi=ket_qua.c1 and ma=ket_qua.c4) where c10='G';
update ket_qua set c5=(select ten from ht_ma_cb where
    ma_dvi=ket_qua.c1 and ma=ket_qua.c4) where c10='C';
update ket_qua set c5=(select ten from bh_dl_ma_kh where
    ma_dvi=ket_qua.c1 and ma=ket_qua.c4) where c10='D';

delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n5,0)=0
    and nvl(n6,0)=0 and nvl(n14,0)=0 and nvl(n15,0)=0;
commit;
open cs_kq for select c1 ma_dvi,' ' ngay_hd,' ' so_hd,
    '33113' ma_tk,'Chi boi thuong ve tra tien bao hiem goc' ten_ma_tk,c2 ma_td,--BCNam
    c2 ten_ma_td,c4 ma_cn,c5 ten_ma_cn,nvl(n5,0) as no_dk,
    nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck,
    nvl(n15,0) as co_ck from ket_qua order by c4;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_CNKH_GD_MD;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_GD_MD
    (b_ma_dvi varchar2,b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
Begin
--delete temp_1;commit;
execute immediate 'truncate table temp_1';
--if b_ma_dvi <> 'BCNam' then raise PROGRAM_ERROR; end if;
insert into temp_1(c1,n10,n2) select ma_dvi,so_id,sum(thu_qd)
    from bh_bt_gd_sc where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id;

insert into temp_1(c1,n10,n3) select ma_dvi,so_id,sum(chi_qd)
    from bh_bt_gd_sc where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id;

insert into temp_1(c1,n10,n6) select ma_dvi,so_id,sum(ton_qd)
    from bh_bt_gd_sc a where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and ngay_ht =(select max(b.ngay_ht) from bh_bt_gd_sc b
    where b.ma_dvi=a.ma_dvi and a.so_id=b.so_id and a.ma_nt=b.ma_nt and b.ngay_ht<b_ngayd)
    group by ma_dvi,so_id;
update temp_1 set n5=-n6,n6=0 where nvl(n6,0)<0;

insert into temp_1(c1,n10,n15) select ma_dvi,so_id,sum(ton_qd)
    from bh_bt_gd_sc a where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and ngay_ht =(select max(b.ngay_ht) from bh_bt_gd_sc b
    where b.ma_dvi=a.ma_dvi and a.so_id=b.so_id and a.ma_nt=b.ma_nt and b.ngay_ht<=b_ngayc)
    group by ma_dvi,so_id;
update temp_1 set n14=-n15,n15=0 where nvl(n15,0)<0;


--update temp_1 set (n9) =(select so_id_bt from bh_bt_gd_hs where  ma_dvi=temp_1.c1 and so_id=temp_1.n10);
--update temp_1 set (n8) =(select so_id_hd from bh_bt_hs where  ma_dvi=temp_1.c1 and so_id=temp_1.n9);
--update temp_1 set (c30) =(select kieu_hd from bh_hd_goc where ma_dvi=temp_1.c1 and so_id=temp_1.n8);

update
    (select temp_1.n9 t_n9, bh_bt_gd_hs.so_id_bt goc_so_id_bt
        from temp_1, bh_bt_gd_hs
        where bh_bt_gd_hs.ma_dvi=temp_1.c1 and bh_bt_gd_hs.so_id=temp_1.n10)
        set t_n9=goc_so_id_bt;
update
    (select temp_1.n8 t_n8, bh_bt_hs.so_id_hd goc_so_id_hd
        from temp_1, bh_bt_hs
        where bh_bt_hs.ma_dvi=temp_1.c1 and bh_bt_hs.so_id=temp_1.n9)
        set t_n8=goc_so_id_hd;
update
    (select temp_1.c30 t_c30, bh_hd_goc.kieu_hd goc_kieu_hd
        from temp_1, bh_hd_goc
        where bh_hd_goc.ma_dvi=temp_1.c1 and bh_hd_goc.so_id=temp_1.n8)
        set t_c30=goc_kieu_hd;

delete temp_1 where nvl(c30,'G')='V';
b_loi:='';
exception when others then null;
End;
/

DROP PROCEDURE BC_BH_CNKH_HH;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_HH
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_PHONG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOAI VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE,B_DVI OUT VARCHAR2,B_TENKH OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);
BEGIN

B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_KH IS NOT NULL AND B_MA_DVI IS NOT NULL THEN SELECT TEN INTO B_TENKH FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TENKH:=' ';END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA;COMMIT;
--LAM SACH
B_LOI:='loi:Lay so lieu phat sinh:loi';
-- IF B_LOAI='H' THEN
--     BC_BH_CNKH_HH_MD(B_MA_DVI,B_MA_KH,B_PHONG,B_NGAYD,B_NGAYC);
-- ELSE
--     BC_BH_CNKH_HHP_MD(B_MA_DVI,B_MA_KH,B_PHONG,B_NGAYD,B_NGAYC);
-- END IF;
insert into temp_2(c1,c4,n3,n2,c29) select c27,c28,n1,n2,c29 from temp_1;
if b_ngayd<20200101 then
--du co dau ky n6
insert into temp_2(c29,c1,c4,n6) select a.ma_dvi,'SD',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) --, bh_dl_ma_kh b
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi and b.ngay_ht<b_ngayd and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt) 
    group by a.ma_kh,a.ma_dvi;
--du co cuoi ky n15
insert into temp_2(c29,c1,c4,n15) select a.ma_dvi,'SD',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi  and b.ngay_ht<=b_ngayc and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt) 
    group by a.ma_kh,a.ma_dvi;
else
--du co dau ky n6
delete temp_3;
insert into temp_3(c29,c1,c4,n6) select a.ma_dvi,'SD',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) --, bh_dl_ma_kh b
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi and b.ngay_ht<b_ngayd and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt)
    group by a.ma_kh,a.ma_dvi;
--du co cuoi ky n15
insert into temp_3(c29,c1,c4,n15) select a.ma_dvi,'SD',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi  and b.ngay_ht<=b_ngayc and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt)
    group by a.ma_kh,a.ma_dvi;
--merge into temp_3 using (select * from bh_dl_ma_kh where loai_dly='K')a on (c29=a.ma_dvi and c4=a.ma) when matched then update set c10='X';
--delete temp_3 where c10='X';
insert into temp_2 select * from temp_3;
end if;

--no cuoi ky n14
update temp_2 set n14=-n15,n15=0 where n15<0;
--no dau ky
update temp_2 set n5=-n6,n6=0 where n6<0;
b_loi:='loi:Lay ket qua bao cao:loi';
insert into ket_qua(c1,c4,n2,n3,n5,n6,n14,n15,c29)
    select c1,c4,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),
    sum(n15),c29 from temp_2 where (b_ma_kh is null or c4=b_ma_kh) group by c1,c4,c29;

delete temp_5;
insert into temp_5(c4,n2,n3,n5,n6,n14,n15) select c29,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14), sum(n15) from ket_qua group by c29;
delete ket_qua;
insert into ket_qua select * from temp_5;

UPDATE KET_QUA SET C5=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=C20 AND MA=KET_QUA.C4);
DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N5,0)=0 AND NVL(N6,0)=0 AND NVL(N14,0)=0 AND NVL(N15,0)=0;
OPEN CS_KQ FOR SELECT C20 ma_dvi,C10 NGAY_HD,PBH_HD_GOC_DHD_SHD(C20,PBH_HD_GOC_DHD_SOID(C20,C11),B_NGAYC),
    '33114' MA_TK,'Phai tra ve hoa hong bao hiem goc' TEN_MA_TK,' ' MA_TD,' ' TEN_MA_TD,C4 MA_CN,C5 TEN_MA_CN,NVL(N5,0) AS NO_DK,
    NVL(N6,0) AS CO_DK,NVL(N3,0) AS NO_PS,NVL(N2,0) AS CO_PS,NVL(N14,0) AS NO_CK,
    NVL(N15,0) AS CO_CK FROM KET_QUA ORDER BY C1;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;

/

DROP PROCEDURE BC_BH_CNKH_HHP_MD;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_HHP_MD
    (B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_PHONG VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER)
AS
BEGIN
--DELETE TEMP_1; COMMIT;
execute immediate 'truncate table temp_1';
INSERT INTO TEMP_1(C29,C28,C27,N1,N2) SELECT MA_DVI,MA_KH,'CN: '||PKH_SO_CNG(NGAY_HT)||':'||SO_CT,TIEN_QD,0 
    FROM BH_DL_CN_TU TU
    WHERE NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND L_CT='C' /*AND LOAI='P'*/  -- LAM SACH
    AND (B_MA_DVI IS NULL OR B_MA_DVI=MA_DVI)
    AND (B_MA_KH IS NULL OR B_MA_KH=MA_KH) AND (B_PHONG IS NULL OR B_PHONG=PHONG);

INSERT INTO TEMP_1(C29,C28,C27,N1,N2) SELECT MA_DVI,MA_KH,'CN: '||PKH_SO_CNG(NGAY_HT)||':'||SO_CT,TIEN_QD,0 
    FROM BH_DL_CN_TU TU
    WHERE NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND L_CT='B' /*AND LOAI='PH'*/
    AND (B_MA_DVI IS NULL OR B_MA_DVI=MA_DVI) 
    AND (B_MA_KH IS NULL OR B_MA_KH=MA_KH) AND (B_PHONG IS NULL OR B_PHONG=PHONG);

INSERT INTO TEMP_1(C29,C28,C27,N1,N2) SELECT A.MA_DVI,FBH_NGGCN_BA_MA_DL(A.MA_DVI,B.MA_DL),'HT:'||PKH_SO_CNG(A.NGAY_HT)||':'||GCN,B.TTOAN_QD,0 
    FROM KT_1 A,BH_NGGCN_BA B,BH_DL_MA_KH C
    WHERE A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC 
    AND B.MA_DVI=A.MA_DVI AND B.SO_ID_KT=A.SO_ID AND B.KIEU_HD='G' 
    AND C.MA_DVI=B.MA_DVI AND C.MA=B.MA_DL
    AND (B_MA_KH IS NULL OR B_MA_KH=B.MA_DL);-- AND (B_PHONG IS NULL OR B_PHONG=C.PHONG);

INSERT INTO TEMP_1(C29,C28,C27,N1,N2) SELECT A.MA_DVI,FBH_NGGCN_BA_MA_DL(A.MA_DVI,B.MA_DL),'HT:'||PKH_SO_CNG(A.NGAY_HT)||':'||GCN,B.TTOAN_QD+B.CHENH_QD,0 
    FROM KT_1 A,BH_NGGCN_BA B,BH_DL_MA_KH C
    WHERE A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC 
    AND B.MA_DVI=A.MA_DVI AND B.SO_ID_KT=A.SO_ID AND B.KIEU_HD='B'
    AND C.MA_DVI=B.MA_DVI AND C.MA=B.MA_DL
    AND (B_MA_DVI IS NULL OR B_MA_DVI=A.MA_DVI) 
    AND (B_MA_KH IS NULL OR B_MA_KH=FBH_NGGCN_BA_MA_DL(A.MA_DVI,B.MA_DL));-- AND (B_PHONG IS NULL OR B_PHONG=C.PHONG);




INSERT INTO TEMP_1(C29,C28,C27,N1,N2) SELECT MA_DVI,MA_KH,'CN: '||PKH_SO_CNG(NGAY_HT)||':'||SO_CT,0,TIEN_QD 
    FROM BH_DL_CN_TU TU
    WHERE NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND L_CT='T'  /*AND LOAI='P'  */
    AND (B_MA_DVI IS NULL OR B_MA_DVI=MA_DVI)
    AND (B_MA_KH IS NULL OR B_MA_KH=MA_KH) AND (B_PHONG IS NULL OR B_PHONG=PHONG);  

INSERT INTO TEMP_1(C29,C28,C27,N1,N2) SELECT MA_DVI,MA_KH,'CN: '||PKH_SO_CNG(NGAY_HT)||':'||SO_CT,0,TIEN_QD 
    FROM BH_DL_CN_TU TU
    WHERE NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND L_CT='B'  /*AND LOAI='HP' */
    AND (B_MA_DVI IS NULL OR B_MA_DVI=MA_DVI) 
    AND (B_MA_KH IS NULL OR B_MA_KH=MA_KH) AND (B_PHONG IS NULL OR B_PHONG=PHONG);  
END;
/

DROP PROCEDURE BC_BH_CNKH_HH_CT;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_HH_CT
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_kh varchar2,b_phong varchar2,
    b_ngayd number,b_ngayc number,b_loai varchar2,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);b_ma_tkdl varchar2(10);b_ten_tk varchar2(100);
Begin
--BCNam: Bao cao cong no dai ly chi tiet, sua lai
b_loi:='loi:Ma chua dang ky:loi';
if b_ma_kh is not null then
    select ten into b_tenkh from bh_dl_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma_kh;
else b_tenkh:=' ';end if;
--delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
execute immediate 'truncate table temp_1';
execute immediate 'truncate table temp_2';
execute immediate 'truncate table temp_3';
execute immediate 'truncate table ket_qua';
b_loi:='loi:Lay so lieu phat sinh:loi';
if b_loai='H' then
    BC_BH_CNKH_HH_MD(b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc);
    b_ma_tkdl :='33114';
    b_ten_tk :='Phai tra ve hoa hong bao hiem goc';
else
    BC_BH_CNKH_HHP_MD(b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc);
    if b_ma_dvi is not null then
        select ma_tk into b_ma_tkdl from bh_kt_tk where ma_dvi=b_ma_dvi and loai='NPH';
        --LAM SACH
--         select ten into b_ten_tk  from kt_ma_tk where  ma_dvi=b_ma_dvi and ma=b_ma_tkdl;
    else
        select ma_tk into b_ma_tkdl from bh_kt_tk where ma_dvi=b_madvi and loai='NPH';
--         select ten into b_ten_tk  from kt_ma_tk where  ma_dvi=b_madvi and ma=b_ma_tkdl;
    end if;
end if;
--temp_1--n1: no-ps, n2 co_ps
--temp_2--n3: no-ps, n2 co_ps
insert into temp_2(c1,c4,n3,n2,c29) select c27,c28,n1,n2,c29 from temp_1;
if b_ngayd<20200101 then
--du co dau ky n6
insert into temp_2(c29,c1,c4,n6) select a.ma_dvi,'SD_1',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) --, bh_dl_ma_kh b
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi /*and b.loai=b_loai*/ and b.ngay_ht<b_ngayd and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt)  /*and a.loai=b_loai*/
    group by a.ma_kh,a.ma_dvi;
--du co cuoi ky n15
insert into temp_2(c29,c1,c4,n15) select a.ma_dvi,'SD',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi  /*and b.loai=b_loai*/   and b.ngay_ht<=b_ngayc and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt) /*and a.loai=b_loai*/
    group by a.ma_kh,a.ma_dvi;
else
--du co dau ky n6
--delete temp_3;
execute immediate 'truncate table temp_3';
insert into temp_3(c29,c1,c4,n6) select a.ma_dvi,'SD_2',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) --, bh_dl_ma_kh b
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi /*and b.loai=b_loai*/  and b.ngay_ht<b_ngayd and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt) /*and a.loai=b_loai*/
    group by a.ma_kh,a.ma_dvi;
--du co cuoi ky n15
insert into temp_3(c29,c1,c4,n15) select a.ma_dvi,'SD',a.ma_kh,sum(ton_qd)
    from bh_dl_cn_sc a where (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and a.ngay_ht =(select max(b.ngay_ht) from bh_dl_cn_sc b
    where b.ma_dvi=a.ma_dvi  /*and b.loai=b_loai*/   and b.ngay_ht<=b_ngayc and a.ma_kh=b.ma_kh and a.ma_nt=b.ma_nt)  /*and a.loai=b_loai*/
    group by a.ma_kh,a.ma_dvi;
--merge into temp_3 using (select ma_dvi,ma from bh_dl_ma_kh where loai_dly='K')a on (c29=a.ma_dvi and c4=a.ma) when matched then update set c10='X';
--delete temp_3 where c10='X';
--insert into temp_2 select * from temp_3;
end if;

--no cuoi ky n14
update temp_2 set n14=-n15,n15=0 where n15<0;
--no dau ky
update temp_2 set n5=-n6,n6=0 where n6<0;
b_loi:='loi:Lay ket qua bao cao:loi';
insert into ket_qua(c1,c4,n2,n3,n5,n6,n14,n15,c29)
    select c1,c4,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),
    sum(n15),c29 from temp_2 where (b_ma_kh is null or c4=b_ma_kh) group by c1,c4,c29;
update ket_qua set c5=(select ten from bh_dl_ma_kh where ma_dvi=b_madvi and ma=ket_qua.c4);
delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0
    and nvl(n14,0)=0 and nvl(n15,0)=0;

commit;
open cs_kq for select c29 ma_dvi,c10 ngay_hd,
    '' so_hd,b_ma_tkdl ma_tk,b_ten_tk ten_ma_tk,c1 ma_td,
    c1 ten_ma_td,c4 ma_cn,c5 ten_ma_cn,nvl(n5,0) as no_dk,
    nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck,
    nvl(n15,0) as co_ck from ket_qua order by c29,c1;
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_CNKH_HH_MD;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_HH_MD
    (b_ma_dvi varchar2,b_ma_kh varchar2,b_phong varchar2,b_ngayd number,b_ngayc number)
AS
Begin
