insert into temp_1(c29,c28,c27,n1,n2) select ma_dvi,ma_kh,'CN: '||PKH_SO_CNG(ngay_ht)||':'||so_ct,tien_qd,0 from bh_dl_cn_tu tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='C' 
    and (b_ma_dvi is null or b_ma_dvi=ma_dvi) and (b_ma_kh is null or b_ma_kh=ma_kh) and (b_phong is null or b_phong=phong);
--bu tru cong no
insert into temp_1(c29,c28,c27,n1,n2) select ma_dvi,ma_kh,'CN: '||PKH_SO_CNG(ngay_ht)||':'||so_ct,tien_qd,0 from bh_dl_cn_tu tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='B'
    and (b_ma_dvi is null or b_ma_dvi=ma_dvi) and (b_ma_kh is null or b_ma_kh=ma_kh);

if b_ngayd <20200101 then 
insert into temp_1(c29,c28,c27,n1,n2) select a.ma_dvi,a.ma_dl,'TT: '||PKH_SO_CNG(a.ngay_ht)||':'||so_ct,b.tien_qd,0 from bh_hd_goc_ttps a,bh_hd_goc_ttct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='D'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) and (b_ma_kh is null or b_ma_kh=a.ma_dl) and (b_phong is null or b_phong=a.phong);
else
--delete temp_3;
