insert into temp_3(c29,c28,c27,n1,n2,n3) select a.ma_dvi,a.ma_dl,'TT: '||PKH_SO_CNG(a.ngay_ht)||':'||so_ct,b.tien_qd,0,a.so_id_tt from bh_hd_goc_ttps a,bh_hd_goc_ttct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='D' and htoan<>'T'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) and (b_ma_kh is null or b_ma_kh=a.ma_dl) and (b_phong is null or b_phong=a.phong);
    
--merge into temp_3 
--using (select distinct max(nvl(so_id,0))so_id,max(ma_dvi)ma_dvi,max(so_id_tt)so_id_tt from bh_hd_goc_ttpt where ngay_ht>=b_ngayd group by ma_dvi,so_id,so_id_tt) a 
--on (c29=a.ma_dvi and n3=a.so_id_tt) 
--when matched then update set n4=a.so_id;
--update temp_3 set n4 = (select max(so_id) from bh_hd_goc_ttpt a where ngay_ht between b_ngayd and b_ngayc and c29=a.ma_dvi and n3=a.so_id_tt and rownum = 1);
/*delete temp_s_1;
insert into temp_s_1 (n1,c1,n2)
select max(so_id)so_id,ma_dvi,so_id_tt from bh_hd_goc_ttpt where ngay_ht >= b_ngayd  group by ma_dvi,so_id_tt;
merge into temp_3 b using temp_s_1 a on (a.c1=b.c29 and b.n3=a.n2) when matched then update set b.n4=a.n1;
merge into temp_3 using (select ma_dvi,so_id,ma_kt from bh_hd_goc where ngay_ht>=b_ngayd and kieu_kt='D') a on (c29=a.ma_dvi and n4=a.so_id) when matched then update set c25=a.ma_kt;
merge into temp_3 using (select ma_dvi,ma from bh_dl_ma_kh where loai_dly='K')a on (c29=a.ma_dvi and c25=a.ma) when matched then update set c10='X';
delete temp_3 where c10='X';
insert into temp_1 select * from temp_3;
*/
end if;
-- phat sinh co
insert into temp_1(c29,c28,c27,n1,n2) select ma_dvi,ma_kh,'CN: '||PKH_SO_CNG(ngay_ht)||':'||so_ct,0,tien_qd from bh_dl_cn_tu tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='T'
    and (b_ma_dvi is null or b_ma_dvi=ma_dvi)
    and (b_ma_kh is null or b_ma_kh=ma_kh) and (b_phong is null or b_phong=phong);
--merge into temp_1 using (select ma_dvi,ma from bh_dl_ma_kh where loai_dly='K') a on (c28=a.ma and c29 = a.ma_dvi) when matched then update set C40='X';
--delete temp_1 where c40='X';

/*    --phat sinh co truong hop dai ly thu ho
insert into temp_1(c29,c28,c27,n1,n2) select a.ma_dvi,a.ma_dl,'CN: '||PKH_SO_CNG(ngay_ht)||':'||so_ct,0,b.tien_qd from bh_hd_goc_hh_ct a,bh_hd_goc_ttct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='D'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi) and (b_ma_kh is null or b_ma_kh=a.ma_dl) and (b_phong is null or b_phong=phong);
    */
--bu tru cong no
insert into temp_1(c29,c28,c27,n1,n2) select ma_dvi,ma_kh,'CN: '||PKH_SO_CNG(ngay_ht)||':'||so_ct,0,tien_qd from bh_dl_cn_tu tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='B'
    and (b_ma_dvi is null or b_ma_dvi=ma_dvi)
    and (b_ma_kh is null or b_ma_kh=ma_kh) and (b_phong is null or b_phong=phong);
insert into temp_1(c29,c28,c27,n1,n2) select a.ma_dvi,a.ma_kh,'BT: '||PKH_SO_CNG(ngay_ht),0,b.tien_qd from bh_bt_tt a,bh_bt_tt_ct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='D'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or b_ma_kh=a.ma_kh) and (b_phong is null or b_phong=a.phong);
insert into temp_1(c29,c28,c27,n1,n2) select a.ma_dvi,a.ma_dl,'HH: '||PKH_SO_CNG(ngay_ht)||':'||a.so_id_hh,0,b.tien_qd
    from bh_hd_goc_hh a,bh_hd_goc_hh_tt b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_hh=a.so_id_hh and b.pt='C'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or b_ma_kh=a.ma_dl) and (b_phong is null or b_phong=a.phong);
insert into temp_1(c29,c28,c27,n1,n2) select a.ma_dvi,a.ma_dl,'HU: '||PKH_SO_CNG(ngay_ht),0,b.tien_qd
    from bh_hd_goc_hu a,bh_hd_goc_hutt b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id=a.so_id and b.pt='D'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or b_ma_kh=a.ma_dl) and (b_phong is null or b_phong=a.phong);
End;
