            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_phong is null or phong=b_phong)
            and ngay_ht<=b_ngayc
            group by ma_dvi,ma_kh,phong,ma_nt) ng
        where sc.ma_dvi=ng.ma_dvi and sc.ma_kh=ng.ma_kh and sc.phong=ng.phong and sc.ma_nt=ng.ma_nt
        and sc.ngay_ht=ng.ngay_ht and sc.ton_qd<>0
        group by sc.ma_dvi,sc.ma_kh;
update temp_2 set n21=1 where nvl(n21,0)<>2;
-- nvl(n5,0) as no_dk,nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck, nvl(n15,0) as co_ck
--select count(1) into b_dem from temp_2 where  c4 in ('064.07206') and n2=4740000 and n20=20200813; --c10='HUY1-:13/08/2020' and
--if b_dem <> 0 then -- fake data coo_ck theo yc ke toan Ms.Huyen
--insert into temp_2(c20,c4,n15) values ('064','064.07206',4740000);
----DBMS_output.put_line('?on v? ben k? toan h?ch toan g?p 2 don 2006400045320/EOTOTN.4   2006400045328/EOTOTN.4 ');
--end if;

b_loi:='loi:Lay ket qua bao cao:loi';
insert into ket_qua(c1,c4,c10,c11,c12,c13,n2,n3,n5,n6,n14,n15,n20,n21)
    select c20,c4,c10,c11,c12,c13,sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n14,0)),sum(nvl(n15,0)),nvl(n20,0),n21
    from temp_2 where c4<>'KH_TBH'
    group by c20,c4,c10,c11,c12,c13,n20,n21;

-- xu ly kenh - dai ly
--merge into ket_qua
--using (select ma_kt,so_hd,ma_dvi from bh_hd_goc where kieu_kt='D' and ngay_ht between b_ngayd and b_ngayc order by ma_dvi)a
--on (a.ma_dvi=c1 and a.so_hd=c10)
--when matched then update
--set c6 = a.ma_kt where c10 not in ('Du co cuoi ky','Du co dau ky');
--merge into ket_qua
--using (select ma_dvi,ma,loai_dly from bh_dl_ma_kh where loai_dly = 'K')a
--on (a.ma_dvi=c1 and a.ma=c6)
--when matched then update
--set c40 = a.loai_dly;
--delete ket_qua a where trim(c40) ='K'; -- loai bo dly moi gioi
-----

delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n14,0)=0 and nvl(n15,0)=0;
--update ket_qua set c5=(select ten from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=ket_qua.c4);

--update
--(select ket_qua.c5 ket_qua_c5, bh_hd_ma_kh.ten bh_hd_ma_kh_ten
--from ket_qua, bh_hd_ma_kh
--where b_ma_dvi = bh_hd_ma_kh.ma_dvi and ket_qua.c4 = bh_hd_ma_kh.ma)
--set ket_qua_c5 = bh_hd_ma_kh_ten;

merge into ket_qua
using bh_hd_ma_kh a
on (a.ma=c4)
when matched then update set c5=a.ten
where a.ma_dvi = b_ma_dvi;

--
--delete ket_qua where c4='KH_TBH';
commit;
open cs_kq for
    select  c1 ma_dvi,PKH_SO_CNG(n20) ngay_hd,c10 so_hd,
    '13111' ma_tk,U'Ph\1EA3i thu v\1EC1 ph\00ED b\1EA3o hi\1EC3m g\1ED1c' ten_ma_tk,c10 ma_td,
    c10 ten_ma_td,c4 ma_cn,c5 ten_ma_cn,nvl(n5,0) as no_dk,
    nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck,
    nvl(n15,0) as co_ck from ket_qua order by c4,n21,n20;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_CNKH_KT;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_KT
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_dvi varchar2,b_ma_tk varchar2,b_ma_kh varchar2,b_phong varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number;b_ngaydnd number;b_ngaydht number;
    cs_tam pht_type.cs_type;b_ma_tkdl varchar2(10);b_ten_tk varchar2(100);b_ma_dvivp varchar2(10);
Begin
-- Bao cao cong no khach hang
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;end if;
b_loi:='';delete temp_tgcn;commit;
if b_ma_dvi is not null then
    select ma_tk into b_ma_tkdl from bh_kt_tk where ma_dvi=b_ma_dvi and loai='NPH';
    select ten into b_ten_tk  from kt_ma_tk where  ma_dvi=b_madvi and ma=b_ma_tkdl;
else
    select ma into b_ma_dvivp from ht_ma_dvi where cap='2' and rownum=1;
    select ma_tk into b_ma_tkdl from bh_kt_tk where ma_dvi=b_ma_dvivp  and loai='NPH';
    select ten into b_ten_tk  from kt_ma_tk where  ma_dvi=b_ma_dvivp  and ma=b_ma_tkdl;
end if;
if b_ma_tk is not null then
    if b_ma_tk='13111' then
        BC_BH_CNKH_KH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);--return;
        if b_loi is not null then raise PROGRAM_ERROR; end if;
        insert into temp_tgcn(c40,c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c1,c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),c1,'13111',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    elsif b_ma_tk='13112' then
        BC_BH_CNKH_NBH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
        if b_loi is not null then raise PROGRAM_ERROR; end if;
        insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'13112','Ph?i thu v? phi b?o hi?m g?c - nha b?o hi?m',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    elsif b_ma_tk='33111' then
        BC_BH_CNKH_BT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
        if b_loi is not null then raise PROGRAM_ERROR; end if;
        insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33111','Ph?i tr? v? chi b?i thu?ng b?o hi?m g?c',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    -- cong no dai ly hoa hong
    /*elsif b_ma_tk='33112' then
        BC_BH_CNKH_HH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'H',cs_tam,b_dvi,b_tenkh);
        if b_loi is not null then raise PROGRAM_ERROR; end if;
        insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33112','Ph?i tr? v? hoa h?ng b?o hi?m g?c',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
        */
    --BCNam: sua theo tai khoan moi 33114
    /*elsif b_ma_tk='13118' then
        BC_BH_CNKH_HH_URBOX(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'H',cs_tam,b_dvi,b_tenkh);*/
--    elsif b_ma_tk = '13118' then
--        BC_BH_CNKH_KE(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_kq,b_dvi,b_tenkh);
--        if b_loi is not null then raise PROGRAM_ERROR; end if;
--        insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15)
--            select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'13118',
--            'Phai tra ve hoa hong bao hiem goc',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    elsif b_ma_tk='33114' then
        BC_BH_CNKH_HH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'H',cs_tam,b_dvi,b_tenkh);
        if b_loi is not null then raise PROGRAM_ERROR; end if;
        insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c4,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),c4,'33114','Phai tra ve hoa hong bao hiem goc',c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    -- cong no dai ly phi
    elsif b_ma_tk=b_ma_tkdl then
        BC_BH_CNKH_HH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'P',cs_tam,b_dvi,b_tenkh);
        if b_loi is not null then raise PROGRAM_ERROR; end if;
            insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15)
        select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),b_ma_tkdl,b_ten_tk,c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    elsif b_ma_tk='33113' then
        BC_BH_CNKH_GD(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
        if b_loi is not null then raise PROGRAM_ERROR; end if;
        insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33113','Ph?i tr? v? phi giam d?nh t?n th?t',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    end if;
else
    --'13111'
    BC_BH_CNKH_KH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'13111-KH','Ph?i thu v? phi b?o hi?m g?c - khach hang',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    --'13112'
    BC_BH_CNKH_NBH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'13111-NBH','Ph?i thu v? phi b?o hi?m g?c - nha b?o hi?m',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    --'33111'
    BC_BH_CNKH_BT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33111','Ph?i tr? v? chi b?i thu?ng b?o hi?m g?c',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    --'33112'
    BC_BH_CNKH_HH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'H',cs_tam,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    --insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33112','Ph?i tr? v? hoa h?ng b?o hi?m g?c',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    --BCNam: sua theo tai khoan moi 33114
    insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33114','Phai tra ve hoa hong bao hiem goc',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    --cong no dai ly phi 13119
    BC_BH_CNKH_HH(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'P',cs_tam,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,
    PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),b_ma_tkdl,b_ten_tk,c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
    --'33113'
    BC_BH_CNKH_GD(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_ngayd,b_ngayc,cs_tam,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    insert into temp_tgcn(c20,c10,c11,c1,c2,c4,c5,n5,n6,n3,n2,n14,n15) select c20,c10,PBH_HD_GOC_DHD_SHD(c20,PBH_HD_GOC_DHD_SOID(c20,c11),b_ngayc),'33113','Chi boi thuong va tra tien bao hiem goc',c4,c5,n5,n6,n3,n2,n14,n15 from ket_qua;
end if;
commit;
if b_ma_dvi is null then
    update temp_tgcn set c4=c20;
    update temp_tgcn set c5=(select ten from ht_ma_dvi where ma=c4);
    open cs_kq for select c10 ngay_hd,nvl(c11,' ') so_hd,nvl(c1,' ') ma_tk,nvl(c2,' ') ten_ma_tk,' ' ma_td,' ' ten_ma_td,c4 ma_cn,c5 ten_ma_cn,
        sum(nvl(n5,0)) no_dk,sum(nvl(n6,0)) co_dk,sum(nvl(n3,0)) no_ps,sum(nvl(n2,0)) co_ps,sum(nvl(n14,0)) no_ck,sum(nvl(n15,0)) co_ck
        from temp_tgcn group by c10,c11,c1,c2,c4,c5 order by c4;
else
    open cs_kq for select c10 ngay_hd,nvl(c11,' ') so_hd,nvl(c1,' ') ma_tk,nvl(c2,' ') ten_ma_tk,' ' ma_td,' ' ten_ma_td,c4 ma_cn,c5 ten_ma_cn,
        nvl(n5,0) no_dk,nvl(n6,0) co_dk,nvl(n3,0) no_ps,nvl(n2,0) co_ps,nvl(n14,0) no_ck,nvl(n15,0) co_ck
        from temp_tgcn order by c4;
end if;
--exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_BH_CNKH_KT_CT;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_KT_CT
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_tk varchar2,b_ma_kh varchar2,b_phong varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number;
    b_ngaydnd number;b_ngaydht number;b_ma_tkdl varchar2(10);b_ma_dvivp varchar2(10);
Begin
-- BCNam: D/c Bao cao cong no khach hang chi tiet theo TT 232, 200
if b_nsd='bctk' and b_pas='bctk' then b_loi:='';
else
    b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
if b_ma_tk is null then
    b_loi:='loi:Nhap ma tai khoan:loi'; raise PROGRAM_ERROR;
end if;
if b_ma_dvi is not null then
    select ma_tk into b_ma_tkdl from bh_kt_tk where ma_dvi=b_ma_dvi and loai='NPH';
else
    select ma into b_ma_dvivp from ht_ma_dvi where cap='2' and rownum=1;
    select ma_tk into b_ma_tkdl from bh_kt_tk where ma_dvi=b_ma_dvivp  and loai='NPH';
end if;
if b_ma_tk='13111' then
    BC_BH_CNKH_KH_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
--elsif b_ma_tk = '13118' then
--    BC_BH_CNKH_KE_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_kq,b_dvi,b_tenkh);
elsif b_ma_tk='13112' then
    BC_BH_CNKH_NBH_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
elsif b_ma_tk='33111' then
    BC_BH_CNKH_BT_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_ngayd,b_ngayc,cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
elsif b_ma_tk='33114' then
    BC_BH_CNKH_HH_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'H',cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
/*
elsif b_ma_tk='33112' then
    BC_BH_CNKH_HH_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'H',cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
*/
elsif b_ma_tk=b_ma_tkdl  then
    BC_BH_CNKH_HH_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc,'P',cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
elsif b_ma_tk='33113' then
    BC_BH_CNKH_GD_CT(b_madvi,b_nsd,b_pas,b_ma_dvi,b_ma_kh,b_ngayd,b_ngayc,cs_kq,b_dvi,b_tenkh);
    if b_loi is not null then raise PROGRAM_ERROR; end if;
end if;
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_CNKH_NBH;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_NBH
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_PHONG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_DVI OUT VARCHAR2,B_TENKH OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);
BEGIN


B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_KH IS NOT NULL AND B_MA_DVI IS NOT NULL THEN SELECT TEN INTO B_TENKH    FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TENKH:=' ';END IF;

DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA;COMMIT;


B_LOI:='loi:Lay so lieu phat sinh cong no nha bao hiem:loi';
BC_BH_CNKH_NBH_MD(B_MA_DVI,B_MA_KH,B_PHONG,B_NGAYD,B_NGAYC); 
INSERT INTO TEMP_2(C20,C4,N20,N3,N2) SELECT C1,C2,N3,N1,N2 FROM TEMP_1;

B_LOI:='loi:Lay so lieu so du dau ky cong no nha bao hiem:loi';

DELETE TEMP_1;
INSERT INTO TEMP_1(C1,C2,C3,C4,N1) SELECT MA_DVI,NHA_BH,'' PHONG,MA_NT,MAX(NGAY_HT) FROM BH_DO_BH_SC
    WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI)
    AND (B_MA_KH IS NULL OR NHA_BH=B_MA_KH) --AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND NGAY_HT<B_NGAYD
    GROUP BY MA_DVI,NHA_BH,MA_NT; --,PHONG
INSERT INTO TEMP_2(C20,C4,N6) SELECT MA_DVI,NHA_BH,SUM(TON_QD) FROM BH_DO_BH_SC A, TEMP_1 B
    WHERE A.MA_DVI=B.C1 AND A.NHA_BH=B.C2  AND A.MA_NT=B.C4 AND A.NGAY_HT=B.N1 --AND A.PHONG=B.C3
    GROUP BY MA_DVI,NHA_BH;

UPDATE TEMP_2 SET N5=-N6 WHERE N6<0;
UPDATE TEMP_2 SET N6=0 WHERE N6<0;

B_LOI:='loi:Lay so lieu so du cuoi ky cong no nha bao hiem:loi';
DELETE TEMP_1;
INSERT INTO TEMP_1(C1,C2,C3,C4,N1) SELECT MA_DVI,NHA_BH,''PHONG,MA_NT,MAX(NGAY_HT) FROM BH_DO_BH_SC
    WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI)
    AND (B_MA_KH IS NULL OR NHA_BH=B_MA_KH)-- AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND NGAY_HT<=B_NGAYC
    GROUP BY MA_DVI,NHA_BH,MA_NT; --,PHONG
INSERT INTO TEMP_2(C20,C4,N15) SELECT MA_DVI,NHA_BH,SUM(TON_QD) FROM BH_DO_BH_SC A, TEMP_1 B
    WHERE A.MA_DVI=B.C1 AND A.NHA_BH=B.C2  AND A.MA_NT=B.C4 AND A.NGAY_HT=B.N1 --AND A.PHONG=B.C3
    GROUP BY MA_DVI,NHA_BH;
UPDATE TEMP_2 SET N14=-N15 WHERE N15<0;
UPDATE TEMP_2 SET N15=0 WHERE N15<0;

B_LOI:='loi:Lay ket qua bao cao cong no nha bao hiem:loi';
INSERT INTO KET_QUA(C20,C4,N2,N3,N5,N6,N14,N15) SELECT C20,C4,SUM(N2),SUM(N3),SUM(N5),SUM(N6),SUM(N14), SUM(N15) FROM TEMP_2 GROUP BY C20,C4;
UPDATE KET_QUA SET C5=(SELECT TEN FROM TBH_MA_NBH WHERE MA_DVI=C20 AND MA=KET_QUA.C4);


DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N6,0)=0 AND NVL(N5,0)=0 AND NVL(N14,0)=0 AND NVL(N15,0)=0;
OPEN CS_KQ FOR SELECT C20 ma_dvi,C10 NGAY_HD,PBH_HD_GOC_DHD_SHD(C20,PBH_HD_GOC_DHD_SOID(C20,C11),B_NGAYC),'13111' MA_TK,'Ph?i thu v? ph? b?o hi?m g?c' TEN_MA_TK,
    ' ' MA_TD,' ' TEN_MA_TD,C4 MA_CN,C5 TEN_MA_CN,NVL(N5,0) AS NO_DK,NVL(N6,0) AS CO_DK,NVL(N3,0) AS NO_PS,NVL(N2,0) AS CO_PS,NVL(N14,0) AS NO_CK,
    NVL(N15,0) AS CO_CK FROM KET_QUA ORDER BY C4;

EXCEPTION WHEN OTHERS THEN IF B_LOI IS NULL THEN RAISE PROGRAM_ERROR; ELSE  RAISE_APPLICATION_ERROR(-20105,B_LOI); END IF;
END;
/

DROP PROCEDURE BC_BH_CNKH_NBH_CT;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_NBH_CT
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_kh varchar2,b_phong varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tenkh out varchar2)
AS
    b_loi varchar2(100);
Begin
-- Bao cao cong no 13111 - khach hang va nha bao hiem
-- BCNam: Dieu chinh theo MIC
b_loi:='loi:Ma chua dang ky:loi';
--BCNam: lay ma nha bh
if b_ma_kh is not null then
    select ten into b_tenkh from tbh_ma_nbh where ma_dvi=b_ma_dvi and ma=b_ma_kh;
else b_tenkh:=' ';end if;
--delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
execute immediate 'truncate table temp_1';
execute immediate 'truncate table temp_2';
execute immediate 'truncate table temp_3';
execute immediate 'truncate table ket_qua';
b_loi:='loi:Lay so lieu phat sinh:loi';
BC_BH_CNKH_NBH_MD(b_ma_dvi,b_ma_kh,b_phong,b_ngayd,b_ngayc); --temp_1:c1 ma_dvi, c2 ma_kh, c3 nd, n1 ps_no, n2 ps_co, n3 ngay_ht
insert into temp_2(c20,c4,c10,n20,n3,n2) select c1,c2,c3,n3,n1,n2 from temp_1;

b_loi:='loi:Lay so lieu so du dau ky cong no nha bao hiem:loi';
--du co n6
execute immediate 'truncate table temp_1';
insert into temp_1(c1,c2,c3,c4,n1) select ma_dvi,nha_bh,''phong,ma_nt,max(ngay_ht) from bh_do_bh_sc
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and (b_ma_kh is null or nha_bh=b_ma_kh) --and (b_phong is null or phong=b_phong)
    and ngay_ht<b_ngayd
    group by ma_dvi,nha_bh,ma_nt; --,phong

insert into temp_2(c20,c4,c10,n6) select ma_dvi,nha_bh,'Du co dau ky',sum(ton_qd) from bh_do_bh_sc a, temp_1 b
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and a.ma_dvi=b.c1 and a.nha_bh=b.c2  and a.ma_nt=b.c4 and a.ngay_ht=b.n1 --and a.phong=b.c3
    group by ma_dvi,nha_bh;

update temp_2 set n5=-n6,c10='Du no dau ky' where n6<0;
update temp_2 set n6=0 where n6<0;

b_loi:='loi:Lay so lieu so du cuoi ky cong no nha bao hiem:loi';
--delete temp_1;
execute immediate 'truncate table temp_1';
insert into temp_1(c1,c2,c3,c4,n1) select ma_dvi,nha_bh,''phong,ma_nt,max(ngay_ht) from bh_do_bh_sc
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and (b_ma_kh is null or nha_bh=b_ma_kh) --and (b_phong is null or phong=b_phong)
    and ngay_ht<=b_ngayc
    group by ma_dvi,nha_bh,ma_nt;--,phong

insert into temp_2(c20,c4,c10,n15) select ma_dvi,nha_bh,'Du co cuoi ky',sum(ton_qd) from bh_do_bh_sc a, temp_1 b
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and a.ma_dvi=b.c1 and a.nha_bh=b.c2  and a.ma_nt=b.c4 and a.ngay_ht=b.n1 --and a.phong=b.c3
    group by ma_dvi,nha_bh;

update temp_2 set n14=-n15,c10='Du no cuoi ky' where n15<0;
update temp_2 set n15=0 where n15<0;

b_loi:='loi:Lay ket qua bao cao:loi';
insert into ket_qua(c1,c4,c10,c11,c12,c13,n2,n3,n5,n6,n14,n15,n20,c20)
    select c1,c4,c10,c11,c12,c13,sum(n2),sum(n3),sum(n5),sum(n6),sum(n14),sum(n15),n20,c20 from temp_2
    group by c1,c4,c10,c11,c12,c13,n20,c20;
delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n14,0)=0 and nvl(n15,0)=0;
update ket_qua set c5=(select ten from tbh_ma_nbh where ma_dvi=ket_qua.c20 and ma=ket_qua.c4);

update ket_qua set n2=-n2 where n2<0;
update ket_qua set n3=-n3 where n3<0;
commit;
open cs_kq for
    select  c20 ma_dvi,PKH_SO_CNG(n20) ngay_hd,c10 so_hd,
    '13112' ma_tk,'Phai thu ve phi bao hiem goc' ten_ma_tk,c10 ma_td,
    c10 ten_ma_td,c4 ma_cn,c5 ten_ma_cn,nvl(n5,0) as no_dk,
    nvl(n6,0) as co_dk,nvl(n3,0) as no_ps,nvl(n2,0) as co_ps,nvl(n14,0) as no_ck,
    nvl(n15,0) as co_ck from ket_qua order by c20,c4;
exception when others then if b_loi is null then raise PROGRAM_ERROR; else  raise_application_error(-20105,b_loi); end if;
end;
/

DROP PROCEDURE BC_BH_CNKH_NBH_MD;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_NBH_MD
    (b_ma_dvi varchar2,b_ma_kh varchar2,b_phong varchar2,
    b_ngayd number,b_ngayc number)
AS
Begin
-- Bao cao cong no nha bao hiem - module chi tiet dong bao hiem
--delete temp_1;delete temp_2;commit;
execute immediate 'truncate table temp_1';
execute immediate 'truncate table temp_2';
insert into temp_2(c1,c2,n1) select distinct ma_dvi,kieu,so_id_tt from bh_hd_do_pt
    where ngay_ht between b_ngayd and b_ngayc and (b_ma_dvi is null or b_ma_dvi=ma_dvi);
/* phat sinh no */
insert into temp_1(c1,c2,c3,n3,n1) select ma_dvi,nha_bh,so_ct||'_1:'||PKH_SO_CNG(ngay_ht),ngay_ht,sum(tien_qd) from bh_do_bh_cn
    where ngay_ht between b_ngayd and b_ngayc and l_ct='C'
    and (b_ma_dvi is null or b_ma_dvi=ma_dvi)
    and (b_ma_kh is null or nha_bh=b_ma_kh) --and (b_phong is null or phong=b_phong)
    group by ma_dvi,nha_bh,so_ct,ngay_ht;
--tam rao sua loi lech logic 021 ma PTI_TN
insert into temp_1(c1,c2,c3,n3,n1)
select a.ma_dvi,a.ma_dl,so_ct||'2:'||PKH_SO_CNG(ngay_ht),a.ngay_ht,sum(b.tien_qd) from bh_hd_goc_ttps a, bh_hd_goc_ttct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='B'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or a.ma_dl=b_ma_kh) and (b_phong is null or a.phong=b_phong)
    and b.tien_qd>0
    group by a.ma_dvi,a.ma_dl,so_ct,a.ngay_ht;
--leader

insert into temp_1(c1,c2,c3,n3,n1) select a.ma_dvi,a.nha_bh,so_ct||'3:'||PKH_SO_CNG(a.ngay_ht),a.ngay_ht,sum(c.tien_qd)+sum(c.thue_qd)
    from bh_hd_do_tt a, bh_hd_do_pp b, bh_hd_do_pt c
    where a.ngay_ht between b_ngayd and b_ngayc
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='C'
    and c.ma_dvi=a.ma_dvi and c.so_id_tt=a.so_id_tt and c.kieu='D'
    and c.nv='T' --tam rao
    --and c.nv='C'
    and (b_ma_kh is null or a.nha_bh=b_ma_kh) --and (b_phong is null or a.phong=b_phong)
    group by a.ma_dvi,a.nha_bh,so_ct,a.ngay_ht;
/* phat sinh co */
insert into temp_1(c1,c2,c3,n3,n2) select ma_dvi,nha_bh,so_ct||'4:'||PKH_SO_CNG(ngay_ht),ngay_ht,sum(tien_qd) from bh_do_bh_cn
    where ngay_ht between b_ngayd and b_ngayc and l_ct='T'
    and (b_ma_dvi is null or b_ma_dvi=ma_dvi)
    and (b_ma_kh is null or nha_bh=b_ma_kh) --and (b_phong is null or phong=b_phong)
    group by ma_dvi,nha_bh,so_ct,ngay_ht; --,phong
--them vao ps co, sua loi logic 021 BAO MINH PTI_TN 061 
insert into temp_1(c1,c2,c3,n3,n2)
select a.ma_dvi,a.ma_dl,so_ct||'2:'||PKH_SO_CNG(ngay_ht),a.ngay_ht,sum(b.tien_qd) from bh_hd_goc_ttps a, bh_hd_goc_ttct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='B'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or a.ma_dl=b_ma_kh) --and (b_phong is null or a.phong=b_phong)
    and b.tien_qd<0
    group by a.ma_dvi,a.ma_dl,so_ct,a.ngay_ht;
--Follower

insert into temp_1(c1,c2,c3,n3,n2) select a.ma_dvi,a.nha_bh,so_ct||'5:'||PKH_SO_CNG(a.ngay_ht),a.ngay_ht,sum(b.tien_qd)
    from bh_hd_do_tt a, bh_hd_do_pp b, temp_2 c
    where c.c2='V'
    and a.ma_dvi=c.c1 and a.so_id_tt=c.n1 and a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='C' and b.tien_qd>0
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or a.nha_bh=b_ma_kh) --and (b_phong is null or a.phong=b_phong)
    group by a.ma_dvi,a.nha_bh,so_ct,a.ngay_ht;

--Leader
insert into temp_1(c1,c2,c3,n3,n2) select a.ma_dvi,a.nha_bh,so_ct||'6:'||PKH_SO_CNG(a.ngay_ht),a.ngay_ht,sum(c.tien_qd)+sum(c.thue_qd)
    from bh_hd_do_tt a, bh_hd_do_pp b, bh_hd_do_pt c
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='C'
    and c.ma_dvi=a.ma_dvi and c.so_id_tt=a.so_id_tt and c.kieu='D'
    and c.nv='C'--tam rao
    -- and c.nv='T'
    and (b_ma_dvi is null or b_ma_dvi=a.ma_dvi)
    and (b_ma_kh is null or a.nha_bh=b_ma_kh) --and (b_phong is null or a.phong=b_phong)
    group by a.ma_dvi,a.nha_bh,so_ct,a.ngay_ht;
End;
/
DROP PROCEDURE BC_BH_DOINTBA;

CREATE OR REPLACE PROCEDURE BC_BH_DOINTBA
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_phong varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_maphong out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number;b_ma_dvi varchar(10);
Begin
-- bao cao thu doi nguoi thu ba
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
if b_madvi='00' then b_ma_dvi:=''; else b_ma_dvi:=b_madvi;end if;

if b_ma_phong is not null then
    select ten into b_maphong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_ma_phong;
else b_maphong:=' ';
end if;
delete temp_1;delete temp_2;delete ket_qua;
--lay So tien can doi nguoi thu 3
insert into temp_2(c21,n10,c3,c20,n2,n3,n4) select ma_dvi,so_id,ten,ma_nt,sum(FTT_VND_QD(ma_dvi,ngay_ht,ma_nt,thu)),sum(FTT_VND_QD(ma_dvi,ngay_ht,ma_nt,chi)),0
    from  bh_bt_tba_sc where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht between b_ngayd and b_ngayc
    group by ma_dvi,so_id,ngay_ht,ten,ma_nt;

-- Lay ty gia hach toan,PKH_SO_CNG(ngay_ht)
update temp_2 set n5=(select a.ty_gia from tt_tgtt a where a.ma_dvi=c21 and
    a.ngay=(select max(b.ngay) from tt_tgtt b where b.ma_dvi=temp_2.c21 and
    b.ngay <=to_date(temp_2.n1,'YYYYMMDD') and b.ma=a.ma and a.ma=temp_2.c20));
update temp_2 set n2=n2*nvl(n5,1),n3=n3*nvl(n5,1),n4=n4*nvl(n5,1);

update temp_2 set (c1,c2)=(select so_hs,PKH_SO_CNG(ngay_ht) from bh_bt_hs where ma_dvi=temp_2.c21 and so_id=temp_2.n10);
insert into ket_qua(c1,c2,c3,c5,n1,n2,n3,n4,c10) select c1,c2,c3,c5,sum(n1),sum(n2),sum(n3),sum(n4),c10 from temp_2
     group by c1,c2,c3,c5,c10;
delete ket_qua where nvl(n3,0)=0 and nvl(n2,0)=0 and nvl(n4,0)=0;
open cs_kq for select c1 as so_hs,c2 as ngay_hs,c3 ten,nvl(n2,0) as tien,
    c4 as ngay_thu,nvl(n3,0) as tien_thu, n4 as no from ket_qua where (b_ma_phong is null or c5=b_ma_phong) order by c1,c10;
exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_BH_DTBH_DONGDV_MD;

CREATE OR REPLACE PROCEDURE BC_BH_DTBH_DONGDV_MD
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_KIEU_KT VARCHAR2,B_SO_ID NUMBER,
	B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Loi doanh thu ban hang:loi';
COMMIT;
INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,C19,N10,N11,N12,N2,N3,C30) 
	SELECT NV.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,NV.PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),
	MA_NT,LH_NV,'DT',GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_HT,
	phi_qd, 0,'G' FROM BH_HD_GOC GOC,BH_HD_GOC_TTPB NV,
	(SELECT DISTINCT  A.MA_DVI C1,A.SO_ID N1,A.SO_ID_TT N2 FROM BH_HD_GOC_TTPT A, BH_HD_DO_TL B 
	WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND A.PT<>'N' AND A.LH_NV=B.LH_NV AND B.PTHUC IN ('D','P')
	AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC))
	WHERE GOC.MA_DVI=NV.DVI_XL AND GOC.MA_DVI=C1
	AND GOC.SO_ID=NV.SO_ID AND NV.SO_ID=N1 AND NV.SO_ID_TT=N2 
	AND KIEU_HD <>'V' AND PTHUC IN ('D','P')
	AND (B_MA_DVI IS NULL OR NV.MA_DVI = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR NV.PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);
	
INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,C19,N10,N11,N12,N2,N3,C30) 
	SELECT GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_HL),
	MA_NT,LH_NV,'DG',GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_HT,
	-phi_qd, 0,'G' FROM BH_HD_GOC GOC,BH_HD_GOC_TTPB NV,
	(SELECT DISTINCT  A.MA_DVI C1,A.SO_ID N1,A.SO_ID_TT N2 FROM BH_HD_GOC_TTPT A, BH_HD_DO_TL B 
	WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND A.PT<>'N' AND A.LH_NV=B.LH_NV AND B.PTHUC IN ('D','P')
	AND (A.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC))
	WHERE GOC.MA_DVI=NV.DVI_XL 
	AND GOC.SO_ID=NV.SO_ID AND NV.SO_ID=N1 AND NV.SO_ID_TT=N2 
	AND KIEU_HD <>'V' AND PTHUC IN ('D','P')
	AND (B_MA_DVI IS NULL OR NV.DVI_XL = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR GOC.PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);
	
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_DTBH_NHTR;

CREATE OR REPLACE PROCEDURE BC_BH_DTBH_NHTR
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_nguon varchar2, b_ma_dt varchar2,b_kieu_kt varchar2,b_tien_d number,b_tien_c number,b_nhom  varchar2,
    b_ngayd number,b_ngayc number,b_ngayhl_d date,b_ngayhl_c date,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tennv out varchar2,b_tenloai out varchar2,
    b_ten_phong out varchar2,b_ten_khach out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_i1 number;
Begin
-- bao cao chi tiet doanh thu ban nhan truoc (giam doanh thu trong ky)

--iF b_nsd <> 'BCNam' then
--    b_loi:='loi:ban khong co quyen xem bao cao:loi';
--    raise PROGRAM_ERROR;
--end if;
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
if b_ma_dvi is not null then
    select ten into b_dvi from ht_ma_dvi where ma=b_ma_dvi;
else b_dvi:=' ';
end if;
if b_ma_nv is not null then
    select ten into b_tennv from bh_ma_lhnv where ma_dvi=b_ma_dvi and ma=b_ma_nv;
else b_tennv:=' ';
end if;
if b_loai is not null then
    select ten into b_tenloai from kh_ma_loai_dn where ma_dvi=b_ma_dvi and ma=b_loai;
else    b_tenloai:=' ';
end if;
if b_phong is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_phong;
else b_ten_phong:=' ';
end if;
if b_ma_kh is not null then
    select ten into b_ten_khach from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma_kh;
else b_ten_khach:=' ';
end if;
if b_tien_c=0 and b_tien_d<>0 then b_n1:=b_tien_d; b_n2:=1.e18;
elsif b_tien_c=0 and b_tien_d=0 then b_n1:=-1.e18; b_n2:=1.e18;
elsif b_tien_d=0 then b_n1:=-1.e18; b_n2:=b_tien_c;
else b_n1:=b_tien_d; b_n2:=b_tien_c;
end if;
delete temp_2;delete ket_qua; commit;
b_loi:='loi:here:loi';
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    insert into ket_qua (c29,c1,c2,c5,c6,c7,c11,n2,n3,c12,n1) 
        select ma_dvi,cb_ql,ma_kh,so_hd,'',lh_nv,ma_kt,-sum(phi),-sum(thue),kieu_kt,so_id
        from V_BC_BH_DTBH_NTM where (b_ma_dvi is null or ma_dvi = b_ma_dvi)
            and (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_cb is null or cb_ql=b_ma_cb) and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
        and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%') --and so_hd not in ('10238/18/HD-TS.1.1/19-KD02','10239/18/HD-TS.1.1/019-KD02')
        and (ngay_htnv between b_ngayd and b_ngayc) group by ma_dvi,cb_ql,ma_kh,so_hd,lh_nv,ma_kt,kieu_kt,so_id;
else
    insert into ket_qua (c29,c1,c2,c5,c6,c7,c11,n2,n3,c12,n1) 
        select ma_dvi,cb_ql,ma_kh,so_hd,'',lh_nv,ma_kt,-sum(phi),-sum(thue),kieu_kt,so_id
        from V_BC_BH_DTBH_NTM,temp_bc_dvi where ma_dvi=dvi and (b_ma_dvi is null or ma_dvi = b_ma_dvi)
            and (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_cb is null or cb_ql=b_ma_cb) and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
        and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%') --and so_hd not in ('10238/18/HD-TS.1.1/19-KD02','10239/18/HD-TS.1.1/019-KD02')
        and (ngay_htnv between b_ngayd and b_ngayc) group by ma_dvi,cb_ql,ma_kh,so_hd,lh_nv,ma_kt,kieu_kt,so_id;
end if;

delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0;
update ket_qua set c4 =(select ten from ht_ma_cb where ma_dvi=ket_qua.c29 and ma=ket_qua.c1);
--update (select ket_qua.c4 ket_qua_c4, ht_ma_cb.ten ht_ma_cb_ten from ket_qua,ht_ma_cb where ma_dvi=ket_qua.c29 and ma=ket_qua.c1 )set ket_qua_c4= ht_ma_cb_ten;

update ket_qua set (c3,c8) =(select loai,ten from bh_hd_ma_kh where ma_dvi=ket_qua.c29 and ma=ket_qua.c2);

--update (select ket_qua.c3 ket_qua_c3, bh_hd_ma_kh.loai bh_hd_ma_kh_loai, ket_qua.c8 ket_qua_c8,
--                    bh_hd_ma_kh.ten bh_hd_ma_kh_ten
--             from   ket_qua, bh_hd_ma_kh
--             where  ket_qua.c29 = bh_hd_ma_kh.ma_dvi
--                    and ket_qua.c2 = bh_hd_ma_kh.ma)
--    set ket_qua_c3 = bh_hd_ma_kh_loai, ket_qua_c8 = bh_hd_ma_kh_ten;
    
--update ket_qua set c33=(select nsd from bh_hd_goc where ma_dvi=ket_qua.c29 and so_id=ket_qua.n1 and rownum=1);
merge into ket_qua
using bh_hd_goc
on (ma_dvi=ket_qua.c29 and so_id=ket_qua.n1)
when matched then update
set c33=nsd,c13=PKH_SO_CNG(ngay_hl),c14=PKH_SO_CNG(ngay_kt); --them ngay hl ngay kt theo yc ktoan

update ket_qua set c9 =(select ten from bh_ma_lhnv where ma_dvi=ket_qua.c29 and ma=ket_qua.c7);
update ket_qua set c10 =(select ten from kh_ma_loai_dn where ma_dvi=ket_qua.c29 and ma=ket_qua.c3);
--dbms_output.put_line('1');
open cs_kq for select c1 cb_ql,c4 ten_cb,c2 ma_kh,c8 ten,c5 so_hd,c6 lh_bh,c7 lh_nv,c9 ten_lh_nv,c3 loai_kh,c10 ten_loai_kh,
    nvl(n2,0) dt_tt, nvl(n3,0) thue,c33 NSD,c12 kieu_kt,c11 ma_kt,c13 ngay_hl,c14 ngay_kt,c29 ma_dvi
    from ket_qua a where (b_loai is null or c3=b_loai) and (nvl(n2,0) between b_n1 and b_n2) order by c1,c11,c2,c5,c29;
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_DTBH_NHTR_KCTANG;

CREATE OR REPLACE PROCEDURE BC_BH_DTBH_NHTR_KCTANG
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_NGUON VARCHAR2, B_MA_DT VARCHAR2,B_KIEU_KT VARCHAR2,B_TIEN_D NUMBER,B_TIEN_C NUMBER,B_NHOM  VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_NGAYDL_D DATE,B_NGAYHL_C DATE,CS_KQ OUT PHT_TYPE.CS_TYPE,
    B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,
    B_TEN_PHONG OUT VARCHAR2,B_TEN_KHACH OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_I1 NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
    SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE    B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_KH IS NOT NULL THEN
    SELECT TEN INTO B_TEN_KHACH FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TEN_KHACH:=' ';
END IF;
IF B_TIEN_C=0 AND B_TIEN_D<>0 THEN B_N1:=B_TIEN_D; B_N2:=1.E18;
ELSIF B_TIEN_C=0 AND B_TIEN_D=0 THEN B_N1:=-1.E18; B_N2:=1.E18;
ELSIF B_TIEN_D=0 THEN B_N1:=-1.E18; B_N2:=B_TIEN_C;
ELSE B_N1:=B_TIEN_D; B_N2:=B_TIEN_C;
END IF;
DELETE TEMP_2;DELETE KET_QUA; COMMIT;
B_LOI:='loi:BCNam:loi';
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN

    INSERT INTO KET_QUA (C29,C1,C2,C5,C6,C7,N2,N3) SELECT MA_DVI,CB_QL,MA_KH,SO_HD,'',LH_NV,SUM(PHI),SUM(THUE)
        FROM V_BC_BH_DTBH_NTM WHERE (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
        AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
        AND (NGAY BETWEEN B_NGAYD AND B_NGAYC) AND TC=1 GROUP BY MA_DVI,CB_QL,MA_KH,SO_HD,LH_NV;

    INSERT INTO KET_QUA (C29,C1,C2,C5,C6,C7,N2,N3) SELECT MA_DVI,CB_QL,MA_KH,SO_HD,'',LH_NV,SUM(PHI),SUM(THUE)
        FROM V_BC_BH_DTBH_NTM WHERE (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
        AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
        AND (NGAY_HL BETWEEN B_NGAYD AND B_NGAYC) AND TC=2 GROUP BY MA_DVI,CB_QL,MA_KH,SO_HD,LH_NV;
ELSE

    INSERT INTO KET_QUA (C29,C1,C2,C5,C6,C7,N2,N3) SELECT MA_DVI,CB_QL,MA_KH,SO_HD,'',LH_NV,SUM(PHI),SUM(THUE)
        FROM V_BC_BH_DTBH_NTM,TEMP_BC_DVI WHERE MA_DVI=DVI AND (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
        AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
        AND (NGAY BETWEEN B_NGAYD AND B_NGAYC) AND TC =1 GROUP BY MA_DVI,CB_QL,MA_KH,SO_HD,LH_NV;

    INSERT INTO KET_QUA (C29,C1,C2,C5,C6,C7,N2,N3) SELECT MA_DVI,CB_QL,MA_KH,SO_HD,'',LH_NV,SUM(PHI),SUM(THUE)
        FROM V_BC_BH_DTBH_NTM,TEMP_BC_DVI WHERE MA_DVI=DVI AND (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
        AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
        AND (NGAY_HL BETWEEN B_NGAYD AND B_NGAYC) AND TC =2 GROUP BY MA_DVI,CB_QL,MA_KH,SO_HD,LH_NV;
END IF;
DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N3,0)=0;
UPDATE KET_QUA SET C4 =(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C1);

--UPDATE KET_QUA SET (C3,C8) =(SELECT LOAI,TEN FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C2);

update (select ket_qua.c3 ket_qua_c3, bh_hd_ma_kh.loai bh_hd_ma_kh_loai, ket_qua.c8 ket_qua_c8,
                    bh_hd_ma_kh.ten bh_hd_ma_kh_ten
             from   ket_qua, bh_hd_ma_kh
             where  ket_qua.c29 = bh_hd_ma_kh.ma_dvi
                    and ket_qua.c2 = bh_hd_ma_kh.ma)
    set ket_qua_c3 = bh_hd_ma_kh_loai, ket_qua_c8 = bh_hd_ma_kh_ten;


UPDATE KET_QUA SET C9 =(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C7);
UPDATE KET_QUA SET C10 =(SELECT TEN FROM KH_MA_LOAI_DN WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C3);
--update ket_qua set (c12,c13) = (select ngay_hl,ngay_kt from bh_hd_goc where MA_DVI=KET_QUA.C29 and so_hd=ket_qua.c5);
merge into ket_qua using bh_hd_goc on (MA_DVI=KET_QUA.C29 and so_hd=ket_qua.c5) when matched then update set c12=PKH_SO_CNG(ngay_hl),c13=PKH_SO_CNG(ngay_kt); 
OPEN CS_KQ FOR SELECT C1 CB_QL,C4 TEN_CB,C2 MA_KH,C8 TEN,C5 SO_HD,C6 LH_BH,C7 LH_NV,C9 TEN_LH_NV,C3 LOAI_KH,C10 TEN_LOAI_KH,
    NVL(N2,0) DT_TT, NVL(N3,0) THUE,c12 ngay_hl,c13 ngay_kt
    FROM KET_QUA A WHERE (B_LOAI IS NULL OR C3=B_LOAI) AND (NVL(N2,0) BETWEEN B_N1 AND B_N2) ORDER BY C1,C2,C5;
--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_DTHU_BHGOC;

CREATE OR REPLACE PROCEDURE BC_BH_DTHU_BHGOC
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_ngayd number,b_ngayc number,
     b_ma_dvi_x varchar2,b_phong varchar2,b_ten_phong out varchar2,cs_kq out pht_type.cs_type,
     b_lke_hd varchar2:='N')
AS
    b_loi varchar2(100);b_ngaydn number;b_ten_dvi varchar2(100);b_ma_dvi_m varchar2(10);b_ma_dvim varchar2(10):='000';
    b_ngay_dtnt number;b_i number; b_ten_proc varchar2(40); b_i1 number;
Begin
-- Bao cao doanh thu bao hiem goc co giam phi, hoan phi
-- BCNam: sua lai cac truong hop dac biet
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','KT','X');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;end if;

-- Lock: de single run
/*
select count(*) into b_i1 from cmc_lock_proc where ten_proc='BC_BH_DTHU_BHGOC';
if b_i1>0 then
    b_loi:='loi:loi chay timeout procedure:loi';
    select ten_proc into b_ten_proc from cmc_lock_proc where ten_proc='BC_BH_DTHU_BHGOC' for update;
end if;
*/
b_ngaydn:=round(b_ngayd,-4)+0101;b_ten_phong:=' ';
b_loi:='loi:Ma chua dang ky:loi';
if b_phong is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi_x and ma=b_phong;
end if;
--delete temp_1;delete temp_2;delete ket_qua;commit;
execute immediate 'truncate table temp_1';
execute immediate 'truncate table temp_2';
execute immediate 'truncate table ket_qua';
---------------------------------------------------------------------------------------------------------------------------
b_ngay_dtnt:=0;

select count(*) into b_i from ht_ma_dvi where ten_dbo like '%MIC%';
if b_i >0 then b_ngay_dtnt:=20091000; end if;
--PHAT SINH TRONG KY
--if b_ma_dvi_x='00' then b_ma_dvi_m:='0'; else b_ma_dvi_m:=b_ma_dvi_x; end if;
if b_ma_dvi_x='00' then b_ma_dvi_m:=''; else b_ma_dvi_m:=b_ma_dvi_x; end if;

delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi_m||'%',b_ngayd,b_ngayc);

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
--BC_BH_LAY_BC_BH_DTBH_MM_TEST(b_ma_dvi_m,b_ngayd,b_ngayc);
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi_m,b_ngayd,b_ngayc);

insert into temp_1(n20,c3,n1)
    select v.so_id, v.lh_nv,sum(v.phi) from TEMP_BC_BH_DTBH_MM v
    group by v.ma_dvi,v.so_id, v.lh_nv;
-- Sua doi bo sung Giam phi

insert into temp_1(n20,c3,n2) select   goc.so_id,lh_nv,-sum(phi_dt_qd)from bh_hd_goc goc,v_bh_hd_goc_ttpt_1 nv where nv.ma_dvig=goc.ma_dvi
    and nv.loai='HD' and goc.so_id=nv.so_id and kieu_hd not in ('V','N') and pt<>'H'
    and phi_dt_qd<0 and nv.so_id<>nv.so_id_tt
    group by nv.ma_dvi,goc.ma_dvi, goc.so_id,lh_nv;
--return;
/*
insert into temp_1(n20,c3,n2) select goc.so_id,lh_nv,-sum(phi_dt_qd) from bh_hd_goc goc,bh_hd_goc_ttpb nv
    where (b_ma_dvi_m is null or nv.ma_dvi LIKE b_ma_dvi_m||'%') and (b_ma_dvi_m is null or goc.ma_dvi LIKE b_ma_dvi_m||'%')
    and goc.so_id=nv.so_id and kieu_hd not in ('V','N') and pt<>'H'
    and phi_dt_qd<0 and nv.so_id<>nv.so_id_tt
    group by nv.ma_dvi, goc.so_id,lh_nv;
*/
insert into temp_1(n20,c3,n2) select   goc.so_id,lh_nv,sum(tien_qd) from bh_hd_goc goc,bh_hd_do_pt nv
    where nv.ma_dvi=goc.ma_dvi and goc.so_id=nv.so_id and (nv.ngay_ht between b_ngayd and b_ngayc)
    and (b_phong is null or goc.phong=b_phong)and (b_ma_dvi_m is null or goc.ma_dvi  like b_ma_dvi_m||'%') and nv.loai='DT_LE_TL'
    and (nv.ma_dvi,nv.so_id_tt) in (select ma_dvi,so_id_tt  from bh_hd_do_tt where so_id_kt>0 and ngay_ht between b_ngayd and b_ngayc)
    and goc.so_id not in(20140328032578)
