drop PROCEDURE BC_BH_DTHU_NHAN_TRUOC;

CREATE OR REPLACE PROCEDURE BC_BH_DTHU_NHAN_TRUOC
(B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,
     B_MA_DVI_M VARCHAR2,B_PHONG VARCHAR2,B_TEN_PHONG OUT VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_TEN_DVI VARCHAR2(100);
    B_NGAY_DTNT NUMBER;B_I NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'KT','KT','NX');
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);

IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+0101;B_TEN_PHONG:=' ';
B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN SELECT TEN INTO B_TEN_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;END IF;
IF B_PHONG IS NOT NULL THEN SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA;COMMIT;

B_LOI:='loi:Loi lay so lieu phat sinh trong ky:loi';

B_NGAY_DTNT:=20091000;

INSERT INTO TEMP_1(C3,N1) SELECT LH_NV,-SUM(PHI) FROM V_BC_BH_DTBH_NTM WHERE (B_MA_DVI_M IS NULL OR MA_DVI = B_MA_DVI_M) 
    AND KIEU_HD <>'V' AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND NGAY_HTNV BETWEEN B_NGAYD AND B_NGAYC  AND NGAY_HTNV>B_NGAY_DTNT
    AND (MA_DVI,SO_ID_TT) IN (SELECT MA_DVI,SO_ID_TT  FROM BH_HD_GOC_TTPS WHERE (B_MA_DVI_M IS NULL OR MA_DVI = B_MA_DVI_M) 
    AND SO_ID_KT>0 AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) GROUP BY LH_NV;

B_LOI:='loi:Loi lay so lieu luy ke:loi';
INSERT INTO TEMP_1(C3,N4) SELECT LH_NV,-SUM(PHI) FROM V_BC_BH_DTBH_NTM WHERE (B_MA_DVI_M IS NULL OR MA_DVI = B_MA_DVI_M) 
    AND KIEU_HD <>'V' AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND NGAY_HTNV BETWEEN B_NGAYD AND B_NGAYC  AND NGAY_HTNV>B_NGAY_DTNT
    AND (MA_DVI,SO_ID_TT) IN (SELECT MA_DVI,SO_ID_TT  FROM BH_HD_GOC_TTPS WHERE (B_MA_DVI_M IS NULL OR MA_DVI = B_MA_DVI_M) 
    AND SO_ID_KT>0 AND NGAY_HT BETWEEN B_NGAYDN AND B_NGAYC) GROUP BY LH_NV;

INSERT INTO KET_QUA(C3,N1,N2,N3,N4,N5,N6) SELECT C3,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),SUM(NVL(N5,0)),
    SUM(NVL(N6,0)) FROM TEMP_1 GROUP BY C3;
UPDATE KET_QUA SET C1=(SELECT MA FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=SUBSTR(C3,1,2) AND TC='T');
UPDATE KET_QUA SET C2=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=C1);
UPDATE KET_QUA SET C4=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=C3);

UPDATE KET_QUA SET N30=1 WHERE C1 LIKE 'XG%';
UPDATE KET_QUA SET N30=2 WHERE C1 LIKE 'CN%';
UPDATE KET_QUA SET N30=3 WHERE C1 LIKE 'HH%';
UPDATE KET_QUA SET N30=4 WHERE C1 LIKE 'TT%';
UPDATE KET_QUA SET N30=5 WHERE C1 LIKE 'HH%';
UPDATE KET_QUA SET N30=6 WHERE C1 LIKE 'TS%';
UPDATE KET_QUA SET N30=7 WHERE C1 LIKE 'HP%';
UPDATE KET_QUA SET N30=8 WHERE C1 LIKE 'TN%';

OPEN CS_KQ FOR SELECT NVL(C1,' ') MA_NV_QL,NVL(C2,' ') TEN_NV_QL,NVL(C3,' ') MA_NV,NVL(C4,' ') TEN_NV,NVL(N1,0) DTHU_PS, 
    NVL(N2,0) DTHU_GP_PS,NVL(N3,0) DTHU_HP_PS,NVL(N4,0) DTHU_LK,NVL(N5,0) DTHU_GP_LK, NVL(N6,0) DTHU_HP_LK 
    FROM KET_QUA ORDER BY N30,C3;

EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;

/
create or replace procedure BC_BH_DTHU_PHIBH(
    dk_ma_dviN varchar2,b_nsd varchar2,b_pas varchar2,b_oraIn clob,b_oraOut out clob)
AS
    b_lenh varchar2(1000); b_loi varchar2(100); b_i1 number; b_thang number :=FKH_JS_GTRIn(b_oraIn,'ngayd');
    b_thangD number; b_thangC number :=FKH_JS_GTRIn(b_oraIn,'ngayc'); b_thangNT number;
    b_ma_dvi varchar2(10) :=FKH_JS_GTRIs(b_oraIn,'ma_dvi'); b_tkvuc varchar2(500);
    b_ngay_bc varchar2(100);b_ten_dvi varchar2(500); b_ngayB date;
    dt_ct clob;dt_ts clob;dt_ds clob;
begin
b_ma_dvi:=nvl(trim(b_ma_dvi),dk_ma_dviN);
--ASCIISTR(N'T?n doanh nghi?p b?o hi?m')
b_ten_dvi := UNISTR(' - T\00ean doanh nghi\1ec7p b\1ea3o hi\1ec3m: ') || FHT_MA_DVI_TEN(b_ma_dvi);
b_ngay_bc := UNISTR(' - B\00e1o c\00e1o qu\00fd: T\1eeb ') || PKH_SO_CNG(b_thang) || UNISTR(' \0111\1ebfn ') || PKH_SO_CNG(b_thangC);
b_tkvuc := FHT_MA_DVI_TEN_KVUC(b_ma_dvi) || UNISTR(',\004E\0067\00E0\0079 ') || to_char(sysdate,'DD') || UNISTR(' \0074\0068\00E1\006E\0067 ') || to_char(sysdate,'MM') 
    || UNISTR(' \006E\0103\006D ') || to_char(sysdate,'YYYY');
b_thang := trunc(b_thang,-2)+01;
b_thangNT:=b_thang-10000;
delete temp_1;
if b_thang is null or b_thangC is null or b_thang > b_thangC then
      b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_ngayB:=PKH_SO_CDT(trunc(b_thang,-4)+101);
/*temp_1 n1-xep,c1-ma,c2-ten,c3-lvl,c4-ma_ct,c5-xep_ktu,
n3-tienCP,n4-ta_diTP,n5-ta_diNP,n6-ta_veTP,n7-ta_veNP,n8- ,n9=n3-n4-n5+n6+n7-n8,n10-
*/
insert into temp_1 (n1,c1,c2,c3,c4,n3,n4,n5,n6,n7,n8,n9,n10)
select row_number() over(order by ord) as stt, lpad(' ',(lvl-1)*2) || case when lvl <= 3 then ma else '-' || ma end, ten, lvl, ma_ct, 0,0,0,0,0,0,0,0
from ( select level lvl, ma, ten, rownum ord, ma_ct
    from bh_ma_lhnv_bo start with ma_ct = ' ' connect by prior ma = ma_ct order siblings by ma);

-- phi bh giu lai (1)
update temp_1 p set (n3,n4,n5,n6,n7)=(
    select sum(nvl(t.phiGP,0)), sum(nvl(t.ta_veTP,0)), sum(nvl(t.ta_veNP,0)), sum(nvl(t.ta_diTP,0)), sum(nvl(t.ta_diNP,0))
    from sli_dt_th_lh t where t.thang=b_thang and trim(upper(t.lh_bo)) = trim(upper(p.c1)));
update temp_1 set n9 = nvl(n3,0) + nvl(n4,0) + nvl(n5,0) - nvl(n6,0) - nvl(n7,0);
update temp_1 p set (n3,n4,n5,n6,n7,n8,n9,n10) = (
    select sum(nvl(c.n3,0)), sum(nvl(c.n4,0)), sum(nvl(c.n5,0)), sum(nvl(c.n6,0)), sum(nvl(c.n7,0)),
        sum(nvl(c.n8,0)), sum(nvl(c.n9,0)), sum(nvl(c.n10,0))
    from temp_1 c start with trim(upper(c.c4)) = trim(upper(p.c1)) connect by nocycle prior trim(upper(c.c1)) = trim(upper(c.c4)))
where exists ( select 1 from temp_1 c where trim(upper(c.c4)) = trim(upper(p.c1)));

insert into temp_1(n1,c5,c2,c3,c4,c1,n3,n4,n5,n6,n7,n8,n9,n10)
  select 0, ' ','', '0', ' ', 'I.', sum(nvl(c.n3,0)), sum(nvl(c.n4,0)), sum(nvl(c.n5,0)), sum(nvl(c.n6,0)), sum(nvl(c.n7,0)),
    sum(nvl(c.n8,0)), sum(nvl(c.n9,0)), sum(nvl(c.n10,0))
  from temp_1 c where c.c1 <> 'I.' and c.c3 = '1';
update temp_1 set c3 ='0' where c3 = '1';
--sort xep theo cap va ma
update temp_1 set c1 = ' ', c2 =(c1 || '.' || c2) where c3 = 3;
update temp_1 t set c1='', c2 = (select to_nchar(lpad('-', x.c3 - 3, '-') || ' ' || t.c1 || '.' || t.c2)
     from ( select n1, c3 from temp_1 where c3 >= 4) x
   where x.n1 = t.n1) where t.c3 >= 4;
select json_arrayagg(json_object('STT' value c1,'NVU' value c2,'N3' value FBH_CSO_TIEN(nvl(n3,0),' '),
    'N4' value FBH_CSO_TIEN(nvl(n4,0),' '),'N5' value FBH_CSO_TIEN(nvl(n5,0),' '),'N6' value FBH_CSO_TIEN(nvl(n6,0),' '),
    'N7' value FBH_CSO_TIEN(nvl(n7,0),' '),'N8' value FBH_CSO_TIEN(nvl(n8,0),' '),'N9' value FBH_CSO_TIEN(nvl(n9,0),' '),
    'N10' value FBH_CSO_TIEN(nvl(n10,0),' '), 'BAC' value c3 ) order by n1 returning clob) into dt_ds from temp_1 where nvl(c1,' ') <> 'I.';
select json_arrayagg(json_object('STT' value c1,'NVU' value c2,'N3' value FBH_CSO_TIEN(nvl(n3,0),' '),
    'N4' value FBH_CSO_TIEN(nvl(n4,0),' '),'N5' value FBH_CSO_TIEN(nvl(n5,0),' '),'N6' value FBH_CSO_TIEN(nvl(n6,0),' '),
    'N7' value FBH_CSO_TIEN(nvl(n7,0),' '),'N8' value FBH_CSO_TIEN(nvl(n8,0),' '),'N9' value FBH_CSO_TIEN(nvl(n9,0),' '),
    'N10' value FBH_CSO_TIEN(nvl(n10,0),' '), 'BAC' value c3 ) order by n1 returning clob) into dt_ts from temp_1 where nvl(c1,' ') = 'I.';
select json_object('ten_dvi' value b_ten_dvi, 'ngaybc' value b_ngay_bc, 'ngay_tbc' value b_tkvuc) into dt_ct from dual;
select json_object('dt_ct' value dt_ct,'dt_ds' value dt_ds,'dt_ts' value dt_ts returning clob) into b_oraOut from dual;

delete temp_1; commit;

exception when others then if b_loi is null then raise PROGRAM_ERROR; else  raise_application_error(-20105,b_loi); end if;
end;
/
DROP PROCEDURE BC_BH_DTPS_MD;

CREATE OR REPLACE PROCEDURE BC_BH_DTPS_MD
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_KIEU_KT VARCHAR2,B_SO_ID NUMBER,
	B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
    B_NOITE VARCHAR2(5);
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Loi doanh thu phat sinh:loi';
DELETE TEMP_1;COMMIT;
B_NOITE:=FTT_TRA_NOITE(B_MADVI);

INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
	SELECT GOC.MA_DVI,SO_HD,GOC.KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT,
	FTT_VND_QD(GOC.MA_DVI,GOC.NGAY_HT,MA_NT,NV.phi),FTT_VND_QD(GOC.MA_DVI,GOC.NGAY_HT,MA_NT,NV.THUE)
	FROM BH_HD_GOC GOC,BH_HD_GOC_CL NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID AND GOC.KIEU_HD ='G' AND MA_NT<>B_NOITE
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI) 
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) 	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)  AND (GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);

INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
	SELECT GOC.MA_DVI,SO_HD,GOC.KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT,NV.phi,NV.THUE
	FROM BH_HD_GOC GOC,BH_HD_GOC_CL NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID AND GOC.KIEU_HD ='G' AND MA_NT=B_NOITE
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) 	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)  AND (GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);

INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
	SELECT GOC.MA_DVI,SO_HD,GOC.KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT,
	FTT_VND_QD(GOC.MA_DVI,GOC.NGAY_HT,MA_NT,NV.phi),FTT_VND_QD(GOC.MA_DVI,GOC.NGAY_HT,MA_NT,NV.THUE)
	FROM BH_HD_GOC GOC,BH_HD_GOC_CL NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID_XL AND GOC.KIEU_HD ='B' AND MA_NT<>B_NOITE
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI) 
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) 	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)  AND (GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);

INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
	SELECT GOC.MA_DVI,SO_HD,GOC.KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT,NV.phi,NV.THUE
	FROM BH_HD_GOC GOC,BH_HD_GOC_CL NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID_XL AND GOC.KIEU_HD ='B' AND MA_NT=B_NOITE
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID) AND (GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
--LAM SACH
-- INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
-- 	SELECT GOC.MA_DVI,SO_HD,GOC.KIEU_HD,MA_KH,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
