COMMIT;

INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
	SELECT GOC.MA_DVI,SO_HD,GOC.KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),
	MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,NV.NGAY,
	-FTT_VND_QD(GOC.MA_DVI,NV.NGAY,MA_NT,NV.phi),-FTT_VND_QD(GOC.MA_DVI,NV.NGAY,MA_NT,NV.THUE)
	FROM BH_HD_GOC GOC,BH_HD_GOC_CL NV,(SELECT MA_DVI C1,SO_ID N1,NGAY_HT N2 FROM BH_HD_GOC_HUPS WHERE 	
	(B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)	AND TRA=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)) C
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.MA_DVI=C1 AND GOC.SO_ID=NV.SO_ID AND GOC.SO_ID=C.N1
	AND GOC.KIEU_HD NOT IN ('V','U','K')
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);


INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3) 
	SELECT GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),
	MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_HT,FTT_VND_QD(GOC.MA_DVI,NV.NGAY_TT,MA_NT,NV.phi),
	FTT_VND_QD(GOC.MA_DVI,NV.NGAY_TT,MA_NT,NV.THUE)
	FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV,(SELECT MA_DVI C1,SO_ID N1,NGAY_HT N2 FROM BH_HD_GOC_HUPS WHERE 	
	(B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)	AND TRA<>0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)) C
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.MA_DVI=C1 AND GOC.SO_ID=NV.SO_ID AND GOC.SO_ID=C.N1
	AND KIEU_HD NOT IN ('V','U','K') AND PT<>'N' AND NV.PHI<0 AND SO_ID_TT=NV.SO_ID
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (NV.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);

BC_BH_DTBH_DONGDV_MD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,
	B_MA_CB,B_MA_DL,B_KIEU_KT,B_SO_ID,B_NGAYD,B_NGAYC,B_LOI);
UPDATE TEMP_1 SET C16 =(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C29 AND MA=TEMP_1.C5);
IF B_LOAI_KH IS NOT NULL THEN DELETE TEMP_1 WHERE  C16  NOT LIKE B_LOAI_KH||'%' OR C16 IS NULL; END IF;
COMMIT;
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_DTTT_DONGDV_MD;

CREATE OR REPLACE PROCEDURE BC_BH_DTTT_DONGDV_MD
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_KIEU_KT VARCHAR2,B_SO_ID NUMBER,
	B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Loi doanh thu ban hang:loi';
COMMIT;
INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,C19,N10,N11,N12,N2,N3,C30) 
	SELECT NV.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,NV.PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),
	MA_NT,LH_NV,'DT',GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_HT,
	phi_qd, 0,'G' FROM BH_HD_GOC GOC,BH_HD_GOC_TTPB NV,
	(SELECT DISTINCT A.SO_ID N1,A.SO_ID_TT N2 FROM BH_HD_GOC_TTPT A, BH_HD_DO_TL B 
	WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND A.PT<>'C' AND A.LH_NV=B.LH_NV AND B.PTHUC IN ('D','P')
	AND (A.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC))
	WHERE GOC.MA_DVI=NV.DVI_XL
	AND GOC.SO_ID=NV.SO_ID AND NV.SO_ID=N1 AND NV.SO_ID_TT=N2 
	AND KIEU_HD <>'V' AND PTHUC IN ('D','P')
	AND (B_MA_DVI IS NULL OR NV.MA_DVI = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR NV.PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);
	
INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,C19,N10,N11,N12,N2,N3,C30) 
	SELECT GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_HL),
	MA_NT,LH_NV,'DG',GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_HT,
	-phi_qd, 0,'G' FROM BH_HD_GOC GOC,BH_HD_GOC_TTPB NV,
	(SELECT DISTINCT A.SO_ID N1,A.SO_ID_TT N2 FROM BH_HD_GOC_TTPT A, BH_HD_DO_TL B 
	WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND A.PT<>'C' AND A.LH_NV=B.LH_NV AND B.PTHUC IN ('D','P')
	AND (A.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC))
	WHERE GOC.MA_DVI=NV.DVI_XL 
	AND GOC.SO_ID=NV.SO_ID AND NV.SO_ID=N1 AND NV.SO_ID_TT=N2 
	AND KIEU_HD <>'V' AND PTHUC IN ('D','P')
	AND (B_MA_DVI IS NULL OR NV.DVI_XL = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR GOC.PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
