DROP PROCEDURE BC_BH_DTTT_MD;

CREATE OR REPLACE PROCEDURE BC_BH_DTTT_MD
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_KIEU_KT VARCHAR2,B_SO_ID NUMBER,
	B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Loi doanh thu thuc thu:loi';
DELETE TEMP_1;DELETE TEMP_6;COMMIT;
INSERT INTO TEMP_1(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3,N4,N5,C30) 
	SELECT GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_TT,
	phi_qd,THUE_QD,ROUND(PHI_QD*NV.HHONG_TL/100,0),ROUND(PHI_QD*NV.HTRO_TL/100,0),PT FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
	WHERE GOC.MA_DVI=NV.MA_DVI
	AND GOC.SO_ID=NV.SO_ID  AND KIEU_HD <>'V' AND PT<>'C' 
	AND (NV.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC)	
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);
INSERT INTO TEMP_6(C29,C2,C3,C5,C8,C9,C10,C11,C13,C15,C17,C18,N10,N11,N12,N2,N3,N4,N5,C30) 
	SELECT GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_HL),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_TT,
	-phi_qd,-THUE_QD,-NV.HHONG,-NV.HTRO,PT FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
	WHERE GOC.MA_DVI=NV.MA_DVI
	AND GOC.SO_ID=NV.SO_ID  AND KIEU_HD <>'V' AND PT<>'C' AND NV.PHI<0 AND NV.SO_ID=SO_ID_TT
	AND (NV.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC)
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (B_SO_ID=0 OR GOC.SO_ID = B_SO_ID)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT);
INSERT INTO TEMP_1 (C29,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N11,N12,N2,N3,N4,N5) 
	SELECT C29,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N11,N12,N2,N3,N4,N5
	FROM TEMP_6 A,BH_HD_GOC_HUPS B
	WHERE C29=B.MA_DVI AND N10=B.SO_ID AND C17=MA_NT AND NO<>0 AND TRA=0;
BC_BH_DTTT_DONG_MD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,
	B_MA_CB,B_MA_DL,B_KIEU_KT,B_SO_ID,B_NGAYD,B_NGAYC,B_LOI);
BC_BH_DTTT_DONGDV_MD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,
	B_MA_CB,B_MA_DL,B_KIEU_KT,B_SO_ID,B_NGAYD,B_NGAYC,B_LOI);
UPDATE TEMP_1 SET C16=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C29 AND MA=TEMP_1.C5);
IF B_LOAI_KH IS NOT NULL THEN DELETE TEMP_1 WHERE  C16  NOT LIKE B_LOAI_KH||'%' OR C16 IS NULL; END IF;
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_DT_DUPHONGCN_6T;

CREATE OR REPLACE PROCEDURE BC_BH_DT_DUPHONGCN_6T
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_loai varchar2,b_tc varchar2,
    b_phong varchar2,b_ngayc number, b_tra varchar2,cs_kq out pht_type.cs_type,
    b_tennv out varchar2,b_tenloai out varchar2,b_ten_phong out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number;b_nam number;b_ngaycn number;b_i1 number; b_ten_proc varchar2(40);
Begin
-- Bao cao doanh thu du phong cong no- Bao cao cong no da phat hanh hoa don
-- Kieu: C- lay bao cao theo tong nghiep vu,K- khong lay bao cao theo tong nghiep vu
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');

--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_loi:='loi:Ma chua dang ky '||b_loai||':loi';
if b_loai is not null  and b_ma_dvi is not null then
    select ten into b_tenloai from kh_ma_loai_dn where ma_dvi=b_ma_dvi and ma=b_loai;
else b_tenloai:=' ';
end if;


if b_phong is not null and b_ma_dvi is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_phong;
else b_ten_phong:=' ';
end if;
delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
/* c1 ma_dvi,c2 ten_dvi,c3 so_hd,c4 ma_kh,c5 ten_kh,c6 ma_nv,c7 ten_nv,c8 ngay_ky,n1 dtth,n2 dtdp */
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;

--lay cac don con no phi den ngayc
select count(*) into b_i1 from temp_bc_dvi;
/*
if b_i1=0 then
    insert into temp_1(c1,n1,c2,n2) select ma_dvi,so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_no
        where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht<=b_ngayc
        group by ma_dvi,so_id,ma_nt;
else
    insert into temp_1(c1,n1,c2,n2) select a.ma_dvi,a.so_id,a.ma_nt,max(a.ngay_ht)
        from bh_hd_goc_sc_no a, temp_bc_dvi b
        where a.ma_dvi=b.dvi and a.ngay_ht<=b_ngayc
        group by a.ma_dvi,a.so_id,a.ma_nt;
end if;
update temp_1 set n3=(select ton_qd from bh_hd_goc_sc_no where ma_dvi=c1 and so_id=n1 and ngay_ht=n2 and ma_nt=c2);
delete temp_1 where n3=0;
*/

-- b_loi:='loi:Nhap '||b_i1||' :loi'; raise PROGRAM_ERROR;
if b_i1=0 then
    insert into temp_1(c1,n1,c2,n2,n3)
        select   sc.ma_dvi,sc.so_id,sc.ma_nt,sc.ngay_ht,sc.ton_qd from bh_hd_goc_sc_no sc,
            (select a.ma_dvi,a.so_id,a.ma_nt,max(a.ngay_ht) ngay_ht
                from bh_hd_goc_sc_no a
                where a.ma_dvi=b_ma_dvi and a.ngay_ht<=b_ngayc
                group by a.ma_dvi,a.so_id,a.ma_nt) ng
             where sc.ma_dvi=ng.ma_dvi and sc.so_id=ng.so_id and sc.ma_nt=ng.ma_nt and sc.ngay_ht=ng.ngay_ht
--             and sc.ton_qd>0;
             and sc.ton_qd<>0;
else
    for b_lp in (select dvi from temp_bc_dvi) loop
        insert into temp_1(c1,n1,c2,n2,n3)
        select   sc.ma_dvi,sc.so_id,sc.ma_nt,sc.ngay_ht,sc.ton_qd from bh_hd_goc_sc_no sc,
            (select a.ma_dvi,a.so_id,a.ma_nt,max(a.ngay_ht) ngay_ht
                from bh_hd_goc_sc_no a
                where a.ma_dvi=b_lp.dvi and a.ngay_ht<=b_ngayc
                group by a.ma_dvi,a.so_id,a.ma_nt) ng
             where sc.ma_dvi=ng.ma_dvi and sc.so_id=ng.so_id and sc.ma_nt=ng.ma_nt and sc.ngay_ht=ng.ngay_ht
--             and sc.ton_qd>0;
             and sc.ton_qd<>0;
    end loop;
end if;

--DQD bo sung theo yc phong ktoan, tinh theo cong thuc bo tai chinh
--update temp_1 set n2=(select max(ngay_ht) from bh_hd_goc_ttpt where ngay_ht<=b_ngayc and ma_dvi=c1 and so_id=n1 and pt='C' and phi > 0);
merge into temp_1 using (select ma_dvi,so_id,max(ngay_ht)ngay_ht from bh_hd_goc_ttpt where ngay_ht<=b_ngayc and pt='C' and phi > 0 group by ma_dvi,so_id)a
on( ma_dvi=c1 and so_id=n1 ) when matched then update set n2=a.ngay_ht;
--if b_i1=0 then
--    insert into temp_1(c1,n1,c2,n2,n3)
--        select   sc.ma_dvi,sc.so_id,sc.ma_nt,sc.ngay_ht,sc.ton_qd from bh_hd_goc_sc_no sc,
--            (select a.ma_dvi,a.so_id,a.ma_nt,max(a.ngay_ht) ngay_ht
--                from bh_hd_goc_ttpt a
--                where a.ma_dvi=b_ma_dvi and a.ngay_ht<=b_ngayc and pt='C'
--                group by a.ma_dvi,a.so_id,a.ma_nt) ng
--             where sc.ma_dvi=ng.ma_dvi and sc.so_id=ng.so_id and sc.ma_nt=ng.ma_nt and sc.ngay_ht=ng.ngay_ht
--             and sc.ton_qd<>0;
--else
--    for b_lp in (select dvi from temp_bc_dvi) loop
--        insert into temp_1(c1,n1,c2,n2,n3)
--        select   sc.ma_dvi,sc.so_id,sc.ma_nt,sc.ngay_ht,sc.ton_qd from bh_hd_goc_sc_no sc,
--            (select a.ma_dvi,a.so_id,a.ma_nt,max(a.ngay_ht) ngay_ht
--                from bh_hd_goc_ttpt a
--                where a.ma_dvi=b_lp.dvi and a.ngay_ht<=b_ngayc and pt='C'
--                group by a.ma_dvi,a.so_id,a.ma_nt) ng
--             where sc.ma_dvi=ng.ma_dvi and sc.so_id=ng.so_id and sc.ma_nt=ng.ma_nt and sc.ngay_ht=ng.ngay_ht
--             and sc.ton_qd<>0;
--    end loop;
--end if;

--update temp_1 set n2=(Select max(ngay_ht) from bh_hd_goc_sc_no where so_id=n1 and no<>0 and ngay_ht<=n2);

--doanh thu duoi 6 thang
insert into temp_2(c1,c3,c4,c6,n1,n2,n3,n4,n5,n10, c30,c31,c32,c33)
    select goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,
        sum(n3),0,n2,goc.ngay_ht,1,so_id, phong,ma_kt,kieu_kt,nsd
        from bh_hd_goc goc,temp_1 where goc.ma_dvi=c1 and goc.so_id=n1
        and (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi)
        and PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2) < 182
        and (b_phong is null or goc.phong=b_phong)
--        and n3>0 --ktoan yc theo cong thuc bo tai chinh
        group by goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,n2,goc.ngay_ht,so_id, phong,ma_kt,kieu_kt,nsd;

--doanh thu du phong cua nhung don no tu 6  thang den 1 nam
insert into temp_2(c1,c3,c4,c6,n1,n2,n3,n4,n5,n10, c30,c31,c32,c33) 
    select goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,
    sum(n3),sum(n3)*30/100,n2,goc.ngay_ht,2,so_id, phong,ma_kt,kieu_kt,nsd
    from bh_hd_goc goc,temp_1
    where goc.ma_dvi=c1 and goc.so_id=n1
    and (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi)
    and PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2) between 182 and 365
    and (b_phong is null or goc.phong=b_phong)
--    and n3>0 --ktoan yc theo cong thuc bo tai chinh
    group by goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,n2,goc.ngay_ht,so_id, phong,ma_kt,kieu_kt,nsd;

--doanh thu du phong cua nhung don no tu 1 nam den 2 nam
insert into temp_2(c1,c3,c4,c6,n1,n2,n3,n4,n5,n10, c30,c31,c32,c33)  
    select goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,
    sum(n3),sum(n3)*50/100,n2,goc.ngay_ht,3,so_id, phong,ma_kt,kieu_kt,nsd
    from bh_hd_goc goc,temp_1
    where goc.ma_dvi=c1 and goc.so_id=n1
    and (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi)
    and PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2) between 366 and 730
    and (b_phong is null or goc.phong=b_phong)
--    and n3>0 --ktoan yc theo cong thuc bo tai chinh
    group by goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,n2,goc.ngay_ht,so_id, phong,ma_kt,kieu_kt,nsd;
--doanh thu du phong cua nhung don no tu 2 den 3 nam
insert into temp_2(c1,c3,c4,c6,n1,n2,n3,n4,n5,n10, c30,c31,c32,c33) select goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,
    sum(n3),sum(n3)*70/100,n2,goc.ngay_ht,4,so_id, phong,ma_kt,kieu_kt,nsd
    from bh_hd_goc goc,temp_1
    where goc.ma_dvi=c1 and goc.so_id=n1
    and (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi)
    and PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2)  between 731 and 1095
    and (b_phong is null or goc.phong=b_phong)
--    and n3>0 --ktoan yc theo cong thuc bo tai chinh
    group by goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,n2,goc.ngay_ht,so_id, phong,ma_kt,kieu_kt,nsd;
--doanh thu du phong cua nhung don no tu 3 nam tro len
insert into temp_2(c1,c3,c4,c6,n1,n2,n3,n4,n5,n10, c30,c31,c32,c33) select goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,
    sum(n3),sum(n3),n2,goc.ngay_ht,5,so_id,phong,ma_kt,kieu_kt,nsd
    from bh_hd_goc goc,temp_1
    where goc.ma_dvi=c1 and goc.so_id=n1
    and (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi)
    and PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2)  >1095
    and (b_phong is null or goc.phong=b_phong)
--    and n3>0 --ktoan yc theo cong thuc bo tai chinh
    group by goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,n2,goc.ngay_ht,so_id, phong,ma_kt,kieu_kt,nsd;

--theo cong thuc bo tai chinh
update temp_2 set n2=0 where n1<0;
/*
if b_tc='C' then
--neu tinh chat ='C' thi lay tong nghiep vu
    insert into ket_qua(c1,c3,c4,c10) select ma_dvi,ma,ten,tc from bh_ma_lhnv where ma_dvi=b_madvi and tc='T';
    update ket_qua kq set
        n1=(select sum(nvl(n1,0)) from temp_2 t where t.c3 like trim(kq.c7)||'%');
    update ket_qua kq set
        n2=(select sum(nvl(n2,0)) from temp_2 t where t.c3 like trim(kq.c7)||'%');
end if;
*/


if b_ma_nv is null then
    insert into ket_qua(c10,c1,c3,c4,c6,c8,n1,n2,n3,n4,n10,c29,c31,c32,c33)
        select to_char(n5),c1,c3,c4,c6,c8,sum(n1),sum(n2),n3,n4,n10,c29,c31,c32,c33 from temp_2 group by c1,c3,c4,c6,c8,n3,n4,n5,n10,c31,c32,c33,c29 order by n5;
else
    delete temp_3;
    insert into temp_3 (c1,n10) 
    select distinct c1,n10 from temp_2 a,bh_hd_goc_dk b
        where a.c1=b.ma_dvi and n10=so_id and lh_nv like b_ma_nv||'%';

    insert into ket_qua(c10,c1,c3,c4,c6,c8,n1,n2,n3,n4,n10,c29,c31,c32,c33)
        select to_char(n5),c1,c3,c4,c6,c8,sum(n1),sum(n2),n3,n4,n10,c30,c31,c32,c33 from temp_2 a,(select c1 ma_dvi,n10 so_id from temp_3) b
        where c1=ma_dvi and n10=so_id group by c1,c3,c4,c6,c8,n3,n4,n5,n10,c30,c31,c32,c33 order by n5;
end if;
if b_tra = 'K' then
    delete ket_qua where n10 in (select so_id from BCNAM_HD_GOC_NO_KH where ma_dvi=c1);
elsif b_tra = 'R' then
    delete ket_qua where n10 not in (select so_id from BCNAM_HD_GOC_NO_KH where ma_dvi=c1);
end if;
if b_phong is not null then
    delete ket_qua where c29<>b_phong;
