on (ma_dvi=ket_qua.c1 and so_id=ket_qua.n10)
when matched then update
set c33=nsd,c11=kieu_kt,c12=ma_kt,c13=to_char(ngay_hl,'dd/MM/yyyy'),c14=to_char(ngay_kt,'dd/MM/yyyy'),c34=ngay_cap,c35=ma_gt;
update ket_qua set n9=n3;
update ket_qua set (c8,n3)=(select max(lh_nv),max(a.ngay_tt) ngay_tt
                from bh_hd_goc_ttpt a
                where a.ngay_ht<=b_ngayc and pt<>'N' and ma_dvi=ket_qua.c1 and so_id=ket_qua.n10);
update ket_qua set c7=(select ten from bh_ma_lhnv where ma_dvi=FTBH_DVI_TA() and ma=c8);
update ket_qua set n11 = (select count(1) from (select distinct ma_dvi,so_id,so_id_tt from bh_hd_goc_ttpt where pt='C') where ma_dvi=ket_qua.c1 and so_id=ket_qua.n10 group by ma_dvi,so_id);
merge into ket_qua using bh_dl_ma_kh a on (c1=a.ma_dvi and c35=a.ma) when matched then update set c36=a.ten;
merge into ket_qua using bh_dl_ma_kh a on (c1='000' and c35=a.ma) when matched then update set c36=a.ten where c36 is null;
commit;
open cs_kq for select c10 as tc,c1 as ma_dvi, c2 as ten_dvi,c3 as so_hd,c4 as ma_kh,c11 kieu_kt,c12 ma_kt,c13 ngay_hl,c14 ngay_kt,
    c5 as ten_kh,c8 as ma_nv, c7 as ten_nv,PKH_SO_CNG(n3) ngay_ky,nvl(n1,0) as dtth,nvl(n2,0) as dtdp,PKH_SO_CNG(n9) ngay_hd ,
    c20 don,to_number(substr(to_char(n3),1,4)) nam, c29 phong,c33 NSD,n11 slcnp,c34 ngay_cap
    ,c35 ma_gt,c36 ten_dl
    from ket_qua where (b_loai is null or c30 like b_loai||'%');
--exception when others then raise_application_error(-20105,b_loi);
end;
