DROP PROCEDURE BC_BH_DT_DUPHONGCN_MOI;

CREATE OR REPLACE PROCEDURE BC_BH_DT_DUPHONGCN_MOI
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_MA_KH VARCHAR2,B_LOAI VARCHAR2,
    B_PHONG VARCHAR2,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
    B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NAM NUMBER;B_NGAYCN NUMBER;B_I1 NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
IF B_LOAI IS NOT NULL  AND B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL AND B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA;COMMIT;

PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;


SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO TEMP_1(C1,N1,C2,N2) SELECT MA_DVI,SO_ID,MA_NT,MAX(NGAY_HT) FROM BH_HD_GOC_SC_NO
        WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND NGAY_HT<=B_NGAYC
        GROUP BY MA_DVI,SO_ID,MA_NT;
ELSE
    INSERT INTO TEMP_1(C1,N1,C2,N2) SELECT MA_DVI,SO_ID,MA_NT,MAX(NGAY_HT) FROM BH_HD_GOC_SC_NO, TEMP_BC_DVI
        WHERE MA_DVI=DVI AND NGAY_HT<=B_NGAYC
        GROUP BY MA_DVI,SO_ID,MA_NT;
END IF;
UPDATE TEMP_1 SET N3=(SELECT TON_QD FROM BH_HD_GOC_SC_NO WHERE MA_DVI=C1 AND SO_ID=N1 AND NGAY_HT=N2 AND MA_NT=C2);
DELETE TEMP_1 WHERE N3=0;

INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),0,N2,GOC.NGAY_HT,1,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1 WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2) < 182
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;


INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3)*30/100,N2,GOC.NGAY_HT,2,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2) BETWEEN 182 AND 365
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;


INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3)*50/100,N2,GOC.NGAY_HT,3,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2) BETWEEN 366 AND 730
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;

INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3)*70/100,N2,GOC.NGAY_HT,4,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)  BETWEEN 731 AND 1095
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;

INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3),N2,GOC.NGAY_HT,5,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)  >1095
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;
IF B_MA_NV IS NULL THEN
    INSERT INTO KET_QUA(C10,C1,C3,C4,C6,C8,N1,N2,N3,N4,N10)
        SELECT TO_CHAR(N5),C1,C3,C4,C6,C8,SUM(N1),SUM(N2),N3,N4,N10 FROM TEMP_2 GROUP BY C1,C3,C4,C6,C8,N3,N4,N5,N10 ORDER BY N5;
ELSE
    DELETE TEMP_3;
    INSERT INTO TEMP_3 (C1,N10) SELECT DISTINCT C1,N10 FROM TEMP_2 A,BH_HD_GOC_DK B
        WHERE A.C1=B.MA_DVI AND N10=SO_ID AND LH_NV LIKE B_MA_NV||'%';

    INSERT INTO KET_QUA(C10,C1,C3,C4,C6,C8,N1,N2,N3,N4,N10)
        SELECT TO_CHAR(N5),C1,C3,C4,C6,C8,SUM(N1),SUM(N2),N3,N4,N10 FROM TEMP_2 A,(SELECT C1 MA_DVI,N10 SO_ID FROM TEMP_3) B
        WHERE C1=MA_DVI AND N10=SO_ID GROUP BY C1,C3,C4,C6,C8,N3,N4,N5,N10 ORDER BY N5;
END IF;
UPDATE KET_QUA SET C20=(SELECT SO_DON FROM BH_HD_GOC_VAT A,BH_HD_GOC_VAT_CT B
                WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID_VAT=B.SO_ID_VAT AND A.MA_DVI=KET_QUA.C1 AND B.SO_ID=N10 AND ROWNUM=1);
DELETE KET_QUA WHERE N1 IS NULL AND N2 IS NULL;
UPDATE KET_QUA SET C2=(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C1);
UPDATE KET_QUA SET (C5,C30)=(SELECT TEN,LOAI FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C4);

OPEN CS_KQ FOR SELECT C10 AS TC,C1 AS MA_DVI, C2 AS TEN_DVI,C3 AS SO_HD,C4 AS MA_KH,
    C5 AS TEN_KH,'' MA_NV, '' TEN_NV,PKH_SO_CNG(N3) NGAY_KY,NVL(N1,0) AS DTTH,NVL(N2,0) AS DTDP,PKH_SO_CNG(N3) NGAY_HD, -- ,C8 AS MA_NV, C7 AS TEN_NV
    C20 DON,TO_NUMBER(SUBSTR(TO_CHAR(N3),1,4)) NAM
    FROM KET_QUA WHERE (B_LOAI IS NULL OR C30 LIKE B_LOAI||'%');
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_DT_DUPHONGCN_TD;

CREATE OR REPLACE PROCEDURE BC_BH_DT_DUPHONGCN_TD
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_MA_KH VARCHAR2,B_LOAI VARCHAR2,
    B_PHONG VARCHAR2,B_TC VARCHAR2,B_SO NUMBER,B_KIEU VARCHAR2:='<=',B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,

    B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NAM NUMBER;B_NGAYCN NUMBER;B_I1 NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
IF B_LOAI IS NOT NULL  AND B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL AND B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA;COMMIT;

PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO TEMP_1(C1,N1,C2,N2) SELECT MA_DVI,SO_ID,MA_NT,MAX(NGAY_HT) FROM BH_HD_GOC_SC_NO
        WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND NGAY_HT<=B_NGAYC
        GROUP BY MA_DVI,SO_ID,MA_NT;
ELSE
    INSERT INTO TEMP_1(C1,N1,C2,N2) SELECT MA_DVI,SO_ID,MA_NT,MAX(NGAY_HT) FROM BH_HD_GOC_SC_NO, TEMP_BC_DVI 
        WHERE MA_DVI=DVI AND NGAY_HT<=B_NGAYC
        GROUP BY MA_DVI,SO_ID,MA_NT;
END IF;
UPDATE TEMP_1 SET N3=(SELECT TON_QD FROM BH_HD_GOC_SC_NO WHERE MA_DVI=C1 AND SO_ID=N1 AND NGAY_HT=N2 AND MA_NT=C2);
DELETE TEMP_1 WHERE N3=0;
INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),0,N2,GOC.NGAY_HT,1,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1 WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2) < 90
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;
INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3)*30/100,N2,GOC.NGAY_HT,2,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1  
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2) BETWEEN 90 AND 365
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;
INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3)*50/100,N2,GOC.NGAY_HT,3,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1  
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1 
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2) BETWEEN 366 AND 730
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;
INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3)*70/100,N2,GOC.NGAY_HT,4,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)  BETWEEN 731 AND 1095
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;
INSERT INTO TEMP_2(C1,C3,C4,C6,N1,N2,N3,N4,N5,N10) SELECT GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,
    SUM(N3),SUM(N3),N2,GOC.NGAY_HT,5,SO_ID
    FROM BH_HD_GOC GOC,TEMP_1  
    WHERE GOC.MA_DVI=C1 AND GOC.SO_ID=N1
    AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)
    AND PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)  >1095
    AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    GROUP BY GOC.MA_DVI,GOC.SO_HD,GOC.MA_KH,NV,N2,GOC.NGAY_HT,SO_ID;

merge into TEMP_2 using BH_HD_GOC on (MA_DVI=C1 and SO_ID=N10 ) when matched then update set c29=PHONG,c28=CB_QL;

IF B_MA_NV IS NULL THEN 
    INSERT INTO KET_QUA(C10,C1,C3,C4,C6,C8,N1,N2,N3,N4,N10,c28,c29) 
        SELECT TO_CHAR(N5),C1,C3,C4,C6,C8,SUM(N1),SUM(N2),N3,N4,N10,c28,c29 FROM TEMP_2 GROUP BY C1,C3,C4,C6,C8,N3,N4,N5,N10,c28,c29 ORDER BY N5;
ELSE
    DELETE TEMP_3;
    INSERT INTO TEMP_3 (C1,N10) SELECT DISTINCT C1,N10 FROM TEMP_2 A,BH_HD_GOC_DK B 
        WHERE A.C1=B.MA_DVI AND N10=SO_ID AND LH_NV LIKE B_MA_NV||'%';

    INSERT INTO KET_QUA(C10,C1,C3,C4,C6,C8,N1,N2,N3,N4,N10,c28,c29) 
        SELECT TO_CHAR(N5),C1,C3,C4,C6,C8,SUM(N1),SUM(N2),N3,N4,N10,c28,c29 FROM TEMP_2 A,(SELECT C1 MA_DVI,N10 SO_ID FROM TEMP_3) B
        WHERE C1=MA_DVI AND N10=SO_ID GROUP BY C1,C3,C4,C6,C8,N3,N4,N5,N10,c28,c29 ORDER BY N5;
END IF;
UPDATE KET_QUA SET C20=(SELECT SO_DON FROM BH_HD_GOC_VAT A,BH_HD_GOC_VAT_CT B 
                WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID_VAT=B.SO_ID_VAT AND A.MA_DVI=KET_QUA.C1 AND B.SO_ID=N10 AND ROWNUM=1);
DELETE KET_QUA WHERE N1 IS NULL AND N2 IS NULL;
UPDATE KET_QUA SET C2=(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C1);
UPDATE KET_QUA SET (C5,C30)=(SELECT TEN,LOAI FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C4);
--UPDATE KET_QUA SET C8=(SELECT NHOM FROM BH_NGUOIHD WHERE MA_DVI=KET_QUA.C1 AND SO_HD=KET_QUA.C3) WHERE C6='NG';
--UPDATE KET_QUA SET C7=(SELECT TEN FROM BH_NGUOI_MA_BH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C8) WHERE C6='NG';
--UPDATE KET_QUA SET C8=(SELECT NHOM_TAU FROM BH_TAUGCN  WHERE MA_DVI=KET_QUA.C1 AND SO_ID=KET_QUA.N10 AND ROWNUM=1) WHERE C6='TAU';
--UPDATE KET_QUA SET C8=(SELECT NHOM_TAU FROM BH_TAULGCN  WHERE MA_DVI=KET_QUA.C1 AND SO_ID=KET_QUA.N10 AND ROWNUM=1) WHERE C6='TAUL';
--UPDATE KET_QUA SET C7=(SELECT TEN FROM BH_TAU_MA_TAU WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C8) WHERE C6='TAU'  OR C6='TAUL';
--UPDATE KET_QUA SET C8=(SELECT MA_NHOM FROM BH_HANGGCN WHERE MA_DVI=KET_QUA.C1 AND SO_HD=KET_QUA.C3) WHERE C6='HANG';
--UPDATE KET_QUA SET C7=(SELECT TEN FROM BH_HANG_MA_HANG WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C8) WHERE C6='HANG';
--
--UPDATE KET_QUA SET C8=(SELECT MA_NHOM FROM BH_PHHGCN  WHERE MA_DVI=KET_QUA.C1 AND SO_HD=KET_QUA.C3) WHERE C6='PHH';
--UPDATE KET_QUA SET C7=(SELECT TEN FROM BH_MA_LHBH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C8) WHERE C6='PHH';
--
--UPDATE KET_QUA SET C8='XE',C7='Xe < t<' WHERE C6='XE' OR  C6='XEL';
--UPDATE KET_QUA SET C8='2B',C7='Xe m?y' WHERE C6='2B' OR C6='2BL';

UPDATE KET_QUA SET N5=PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N3);

IF B_KIEU='=' THEN DELETE KET_QUA WHERE N5<>B_SO; END IF;
IF B_KIEU='>' THEN DELETE KET_QUA WHERE N5<=B_SO; END IF;
IF B_KIEU='<' THEN DELETE KET_QUA WHERE N5>=B_SO; END IF;
IF B_KIEU='>=' THEN DELETE KET_QUA WHERE N5<B_SO; END IF;
IF B_KIEU='<=' THEN DELETE KET_QUA WHERE N5>B_SO; END IF;
commit;
OPEN CS_KQ FOR SELECT C10 AS TC,C1 AS MA_DVI, C2 AS TEN_DVI,C3 AS SO_HD,C4 AS MA_KH, 
    C5 AS TEN_KH,'' MA_NV, '' TEN_NV,PKH_SO_CNG(N3) NGAY_KY,NVL(N1,0) AS DTTH,NVL(N2,0) AS DTDP,PKH_SO_CNG(N3) NGAY_HD , --C8 AS MA_NV, C7 AS TEN_NV
    C20 DON,TO_NUMBER(SUBSTR(TO_CHAR(N3),1,4)) NAM, N5 SO_NGAY_TD,c28 CB_QL,c29 PHONG
    FROM KET_QUA WHERE (B_LOAI IS NULL OR C30 LIKE B_LOAI||'%');
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_GCN_HUY;

CREATE OR REPLACE PROCEDURE BC_BH_GCN_HUY
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_MA_DVI VARCHAR2,B_NV VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,
    B_PHONG VARCHAR2,B_LOAI VARCHAR2,B_MA_CB VARCHAR2,B_NGUON VARCHAR2,B_MA_DL VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NGAYD1 NUMBER;B_NOITE VARCHAR2(5);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';

B_NGAYD1:=PKH_NG_CSO(PKH_SO_CDT(B_NGAYD)-1);
B_NOITE:=FTT_TRA_NOITE(B_MA_DVI);
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; DELETE TEMP_3;DELETE TEMP_4;COMMIT;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);

INSERT INTO TEMP_2 (C1,C2,C3,C4,C5,C7,C20,C21,N2,N3,N14) SELECT SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,
    NV,'',PHI,THUE,SO_ID
    FROM V_BC_BH_DTPS_HUY WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
    AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_NV='*' OR NV=B_NV);


INSERT INTO TEMP_2 (C1,C2,C3,C4,C5,C7,C20,C21,N6,N7,N14) SELECT SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,
    NV,'',PHI,THUE,SO_ID
    FROM V_BC_BH_DTBH_MNVM_HUY WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
    AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_NV='*' OR NV=B_NV);
--LAM SACH
-- INSERT INTO TEMP_1(C1,C2,C3,C4,C5,C7,C20,C21,N10,N11,N12,N13,N14,C29,C28)
