--                 AND (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND (B_PHONG IS NULL OR PHONG=B_PHONG)
--                 AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH) AND (B_NV='*' OR NV=B_NV);

DELETE TEMP_1 WHERE N14 IN (SELECT SO_ID FROM BH_HD_GOC  WHERE NGAY_HT NOT BETWEEN B_NGAYD AND B_NGAYC);
DELETE TEMP_2 WHERE N14 IN (SELECT SO_ID FROM BH_HD_GOC  WHERE NGAY_HT NOT BETWEEN B_NGAYD AND B_NGAYC);

INSERT INTO TEMP_2 (C1,C2,C3,C4,C5,C7,C20,C21,N10,N11,N14)
    SELECT C1,C2,C3,C4,C5,C7,C20,C21,N10,N11,N14 FROM TEMP_1;


INSERT INTO KET_QUA(C20,C21,C1,C2,C3,C4,C5,C6,C7,N1,N2,N3,N4,N5,N6,N7,N8,N9,N10,N11,N12,N13,N30,N14)
    SELECT C20,C21,C1,C2,C3,C4,C5,C6,C7,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)+NVL(N2,0)),
    SUM(NVL(N5,0)+NVL(N3,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)+NVL(N6,0)),SUM(NVL(N9,0)+NVL(N7,0)),
    SUM(NVL(N10,0)),SUM(NVL(N11,0)),SUM(NVL(N12,0)+NVL(N10,0)),SUM(NVL(N13,0)+NVL(N11,0)),
    (CASE WHEN SUBSTR(C7,1,2)='XG' THEN 1 WHEN SUBSTR(C7,1,2)='CN' THEN 2
    WHEN SUBSTR(C7,1,2)='HH' THEN 3 WHEN SUBSTR(C7,1,2)='TT' THEN 4
    WHEN SUBSTR(C7,1,2)='TS' THEN 5 WHEN SUBSTR(C7,1,2)='HP' THEN 6
    WHEN SUBSTR(C7,1,2)='TN' THEN 7 ELSE 0 END), N14
    FROM TEMP_2 GROUP BY C20,C21,C1,C2,C3,C4,C5,C6,C7,N14;


DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N4,0)=0 AND NVL(N5,0)=0
    AND NVL(N6,0)=0 AND NVL(N7,0)=0 AND NVL(N8,0)=0 AND NVL(N9,0)=0 AND NVL(N10,0)=0 AND NVL(N11,0)=0 AND  NVL(N12,0)=0 AND NVL(N13,0)=0;

-- UPDATE KET_QUA SET N29=(SELECT 100-SUM(PT) FROM BH_HD_DO_TL
--     WHERE SO_ID=N14 AND PTHUC='C' AND LH_NV=C7 AND KIEU='D');
-- 
-- UPDATE KET_QUA SET N29=(SELECT SUM(PT) FROM BH_HD_DO_TL
--     WHERE SO_ID=N14 AND PTHUC='C' AND LH_NV=C7 AND KIEU='V') WHERE N29=0 OR N29 IS NULL;

INSERT INTO TEMP_3(C20,C21,C1,C2,C3,C4,C5,C6,N1,N2,N3,N4,N5,N6,N7,N8,N9,N10,N11,N12,N13,N14)
    SELECT C20,C21,C1,C2,C3,C4,C5,C6,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)+NVL(N2,0)),
    SUM(NVL(N5,0)+NVL(N3,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)+NVL(N6,0)),SUM(NVL(N9,0)+NVL(N7,0)),
    SUM(NVL(N10,0)),SUM(NVL(N11,0)),SUM(NVL(N12,0)+NVL(N10,0)),SUM(NVL(N13,0)+NVL(N11,0)),N14
    FROM KET_QUA GROUP BY C20,C21,C1,C2,C3,C4,C5,C6,N14;

UPDATE TEMP_3 SET (C17,N18)=(SELECT NV,NGAY_HT FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR NV=B_NV));
UPDATE TEMP_3 SET N19=(SELECT NGAY_HT FROM BH_HD_GOC_HU WHERE MA_DVI=B_MA_DVI AND SO_ID=N14);

--    UPDATE TEMP_3 SET (N16)=(SELECT SUM(PHI) FROM BH_XE_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17 like 'XE%';
--    UPDATE TEMP_3 SET (N16)=(SELECT SUM(PHI) FROM BH_2B_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17 like '2B%';
--
--UPDATE TEMP_3 SET N17=N16 WHERE C30=B_NOITE;
--UPDATE TEMP_3 SET N17=FTT_VND_QD(B_MA_DVI,N18,C30,N16) WHERE C30<>B_NOITE;

--IF B_NV='XE' THEN
--    INSERT INTO TEMP_4(N1,C1,C2)SELECT SO_ID,MA_DVI,GCN FROM BH_XE_DS, TEMP_3 WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR C17=B_NV);
--ELSIF B_NV='2B' THEN
--    INSERT INTO TEMP_4(N1,C1,C2)SELECT SO_ID,MA_DVI,GCN FROM BH_2B_DS, TEMP_3 WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR C17=B_NV);
--ELSIF B_NV='TAU' THEN
--    INSERT INTO TEMP_4(N1,C1,C2)SELECT SO_ID,MA_DVI,GCN FROM BH_tau_DS, TEMP_3 WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR C17=B_NV);
--ELSIF B_NV='HANG' THEN
--    INSERT INTO TEMP_4(N1,C1,C2)SELECT SO_ID,MA_DVI,''GCN FROM BH_hang, TEMP_3 WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR C17=B_NV);
--ELSIF B_NV='SK' THEN
--    INSERT INTO TEMP_4(N1,C1,C2)SELECT SO_ID,MA_DVI,''GCN FROM BH_sk_ds, TEMP_3 WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR C17=B_NV);
--ELSIF B_NV='NG' THEN
--    INSERT INTO TEMP_4(N1,C1,C2)SELECT SO_ID,MA_DVI,''GCN FROM BH_ng_ds, TEMP_3 WHERE MA_DVI=B_MA_DVI AND SO_ID=N14 AND (B_NV='*' OR C17=B_NV);
--END IF;
--UPDATE TEMP_4 SET (C4,N2,N6,N10,N17,N18,N19)=(SELECT C1,N2,N6,N10,N17,N18,N19 FROM TEMP_3 WHERE TEMP_3.N14=TEMP_4.N1);

COMMIT;
OPEN CS_KQ FOR SELECT C1 SO_HD,''gcn,N2 PHI_PS,N6 PHI_BH,N10 PHI_TT--,N17 PHI,
    ,PKH_SO_CNG(N18) NGAY_HT,PKH_SO_CNG(N19) NGAY_HUY FROM TEMP_3 ORDER BY N1,C1,C4,C2;
EXCEPTION WHEN OTHERS THEN IF B_LOI IS NULL THEN RAISE PROGRAM_ERROR; ELSE NULL; END IF;
