DROP PROCEDURE BC_BH_HD_CNQH;
CREATE OR REPLACE PROCEDURE BC_BH_HD_CNQH
 (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,
 B_LOAI_DT VARCHAR2,B_MA_DT VARCHAR2,B_NAM NUMBER,
 B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_DT OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
 B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_KIEU_KT VARCHAR(1);B_KIEU_DL VARCHAR(1);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
 B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_PHONG IS NOT NULL THEN
 SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;COMMIT;
	
INSERT INTO TEMP_1(N1,N2) SELECT SO_ID,NGAY_HT FROM BH_HD_GOC_SC_NO A WHERE MA_DVI=B_MA_DVI  
	AND NGAY_HT=(SELECT MAX(NGAY_HT) FROM BH_HD_GOC_SC_NO
	WHERE  MA_DVI=A.MA_DVI AND SO_ID=A.SO_ID AND NGAY_HT<=B_NGAYC) AND TON_QD<>0;
IF SUBSTR(B_LOAI_DT,1,1)='D'  THEN
 	B_KIEU_KT:='D';
	IF B_MA_DT IS NOT NULL THEN
		SELECT TEN INTO B_TEN_DT FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_DT;
	ELSE B_TEN_DT:=' ';END IF;
	IF B_LOAI_DT='D' THEN B_KIEU_DL:='';
	ELSIF B_LOAI_DT='D1' THEN
	  B_KIEU_DL:='K';
	ELSIF B_LOAI_DT='D2' THEN
	  B_KIEU_DL:='D';
	END IF;
 	INSERT INTO TEMP_2(C1,C2,N1,N2,N3,N4) SELECT MA_KH,MA_NT,SUM(PHI_QD),SUM(THUE_QD),SUM(TTOAN_QD),A.NGAY_HT
  		FROM BH_HD_GOC A,BH_HD_GOC_TTPT B,TEMP_1 C
		WHERE A.MA_DVI=B_MA_DVI AND B.MA_DVI=B_MA_DVI AND A.SO_ID=B.SO_ID
		AND KIEU_HD <>'V' AND A.SO_ID =N1 AND PT='C'
     		AND (B_NAM=0 OR PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)>=B_NAM)
		AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
		AND (B_MA_DT IS NULL OR MA_KT=B_MA_DT)
		AND (B_PHONG IS NULL OR PHONG=B_PHONG) GROUP BY MA_KH,MA_NT,A.NGAY_HT;
 	INSERT INTO TEMP_2(C1,C2,N1,N2,N3,N4) SELECT MA_KH,MA_NT,-SUM(PHI_QD),-SUM(THUE_QD),-SUM(TTOAN_QD),A.NGAY_HT
  		FROM BH_HD_GOC A,BH_HD_GOC_TTPT B,TEMP_1 C
		WHERE A.MA_DVI=B_MA_DVI AND B.MA_DVI=B_MA_DVI AND A.SO_ID=B.SO_ID
		AND KIEU_HD <>'V' AND A.SO_ID =N1 AND PT='N'
     		AND (B_NAM=0 OR PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)>=B_NAM)
		AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
		AND (B_MA_DT IS NULL OR MA_KT=B_MA_DT)
		AND (B_PHONG IS NULL OR PHONG=B_PHONG) GROUP BY MA_KH,MA_NT,A.NGAY_HT;

ELSE	IF B_MA_DT IS NOT NULL THEN
	   SELECT TEN INTO B_TEN_DT FROM HT_MA_CB WHERE MA_DVI=B_MA_DVI AND MA=B_MA_DT;
	ELSE B_TEN_DT:=' ';END IF;
	 INSERT INTO TEMP_2(C1,C2,N1,N2,N3,N4) SELECT MA_KH,MA_NT,SUM(PHI_QD),SUM(THUE_QD),SUM(TTOAN_QD),A.NGAY_HT
  		FROM BH_HD_GOC A,BH_HD_GOC_TTPT B,TEMP_1 C
		WHERE A.MA_DVI=B_MA_DVI AND B.MA_DVI=B_MA_DVI AND A.SO_ID=B.SO_ID
		AND KIEU_HD <>'V' AND A.SO_ID =N1 AND PT='C'
     		AND (B_NAM=0 OR PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)>=B_NAM)
		AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
		AND (B_MA_DT IS NULL OR CB_QL=B_MA_DT)
		AND (B_PHONG IS NULL OR PHONG=B_PHONG) GROUP BY MA_KH,MA_NT,A.NGAY_HT;
	 INSERT INTO TEMP_2(C1,C2,N1,N2,N3,N4) SELECT MA_KH,MA_NT,-SUM(PHI_QD),-SUM(THUE_QD),-SUM(TTOAN_QD),A.NGAY_HT
  		FROM BH_HD_GOC A,BH_HD_GOC_TTPT B,TEMP_1 C
		WHERE A.MA_DVI=B_MA_DVI AND B.MA_DVI=B_MA_DVI AND A.SO_ID=B.SO_ID
		AND KIEU_HD <>'V' AND A.SO_ID =N1 AND PT='N'
     		AND (B_NAM=0 OR PKH_SO_CDT(B_NGAYC)-PKH_SO_CDT(N2)>=B_NAM)
		AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
		AND (B_MA_DT IS NULL OR CB_QL=B_MA_DT)
		AND (B_PHONG IS NULL OR PHONG=B_PHONG) GROUP BY MA_KH,MA_NT,A.NGAY_HT;
END IF;
UPDATE TEMP_2 SET C2=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=TEMP_2.C1);
DELETE TEMP_2 WHERE NVL(N1,0)=0 AND NVL(N2,0)=0 AND NVL(N3,0)=0;
OPEN CS_KQ FOR SELECT C1 MA_DL,C2 TEN_DL,SUM(NVL(N1,0)) PHI_DT, SUM(NVL(N2,0)) THUE,SUM(NVL(N3,0)) TTOAN FROM TEMP_2 GROUP BY C1,C2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_HD_CNQHCT;
CREATE OR REPLACE PROCEDURE BC_BH_HD_CNQHCT
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_dt varchar2,
    b_ma_dt varchar2,b_nam number,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_ten_dt out varchar2,b_ten_phong out varchar2)
AS
 b_loi varchar2(100);b_ngaydn number;b_kieu_kt varchar(1);b_kieu_dl varchar(1);
 b_so_don varchar2(100);b_ngay_th  varchar2(100);
Begin
-- Giang bao cao cong no qua han
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
 b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
if b_phong is not null then
  select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_phong;
else b_ten_phong:=' ';end if;
delete temp_1;delete temp_2;commit;
--so ton chua thanh toan phi
insert into temp_1(n1,n2) select so_id,ngay_ht from bh_hd_goc_sc_no a where ma_dvi=b_ma_dvi
    and ngay_ht=(select max(ngay_ht) from bh_hd_goc_sc_no
    where  ma_dvi=a.ma_dvi and so_id=a.so_id and ngay_ht<=b_ngayc)  and ton_qd<>0;
if substr(b_loai_dt,1,1)='D'  then
    b_kieu_kt:='D';
    if b_ma_dt is not null then
        select ten into b_ten_dt from bh_dl_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma_dt;
    else b_ten_dt:=' ';end if;
    if b_loai_dt='D' then b_kieu_dl:='';
    elsif b_loai_dt='D1' then
      b_kieu_dl:='K';
    elsif b_loai_dt='D2' then
      b_kieu_dl:='D';
    end if;
    insert into temp_2(c1,c2,c3,n1,n2,n3,n4,n5) select ma_kh,ma_nt,so_hd,sum(PHI_QD),sum(thue_qd),sum(ttoan_qd),a.ngay_ht,b.ngay_tt
        from bh_hd_goc a,bh_hd_goc_ttpt b,temp_1 c
        where a.ma_dvi=b_ma_dvi and b.ma_dvi=b_ma_dvi and a.so_id=b.so_id
        and kieu_hd <>'V' and a.so_id =n1 and pt='C'
            and (b_nam=0 or PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2)>=b_nam)
        and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (b_ma_dt is null or ma_kt=b_ma_dt)
        and (b_phong is null or phong=b_phong) group by ma_kh,ma_nt,so_hd,a.ngay_ht,b.ngay_tt;

    insert into temp_2(c1,c2,c3,n1,n2,n3,n4,n5) select ma_kh,ma_nt,so_hd,-sum(PHI_QD),-sum(thue_qd),-sum(ttoan_qd),a.ngay_ht,b.ngay_tt
        from bh_hd_goc a,bh_hd_goc_ttpt b,temp_1 c
        where a.ma_dvi=b_ma_dvi and b.ma_dvi=b_ma_dvi and a.so_id=b.so_id
        and kieu_hd <>'V' and a.so_id =n1 and pt='N'
            and (b_nam=0 or PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2)>=b_nam)
        and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (b_ma_dt is null or ma_kt=b_ma_dt)
        and (b_phong is null or phong=b_phong) group by ma_kh,ma_nt,so_hd,a.ngay_ht,b.ngay_tt;

else    if b_ma_dt is not null then
        select ten into b_ten_dt from ht_ma_cb where ma_dvi=b_ma_dvi and ma=b_ma_dt;
    else b_ten_dt:=' ';end if;

    insert into temp_2(c1,c2,c3,n1,n2,n3,n4,n5) select ma_kh,ma_nt,so_hd,
        sum(PHI_QD),sum(thue_qd),sum(ttoan_qd),a.ngay_ht,b.ngay_tt
        from bh_hd_goc a,bh_hd_goc_ttpt b,temp_1 c
        where a.ma_dvi=b_ma_dvi and b.ma_dvi=b_ma_dvi and a.so_id=b.so_id
        and kieu_hd <>'V' and a.so_id =n1 and pt='C'
            and (b_nam=0 or PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2)>=b_nam)
        and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (b_ma_dt is null or cb_ql=b_ma_dt)
        and (b_phong is null or phong=b_phong) group by ma_kh,ma_nt,so_hd,a.ngay_ht,b.ngay_tt;

    insert into temp_2(c1,c2,c3,n1,n2,n3,n4,n5) select ma_kh,ma_nt,so_hd,
        -sum(PHI_QD),-sum(thue_qd),-sum(ttoan_qd),a.ngay_ht,b.ngay_tt
        from bh_hd_goc a,bh_hd_goc_ttpt b,temp_1 c
        where a.ma_dvi=b_ma_dvi and b.ma_dvi=b_ma_dvi and a.so_id=b.so_id
        and kieu_hd <>'V' and a.so_id =n1 and pt='N'
            and (b_nam=0 or PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n2)>=b_nam)
        and (b_kieu_kt is null or kieu_kt=b_kieu_kt)
        and (b_ma_dt is null or cb_ql=b_ma_dt)
        and (b_phong is null or phong=b_phong) group by ma_kh,ma_nt,so_hd,a.ngay_ht,b.ngay_tt;
end if;
update temp_2 set c2=(select ten from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=temp_2.c1);
delete temp_2 where nvl(n1,0)=0 and nvl(n2,0)=0 and nvl(n3,0)=0;
delete ket_qua;commit;
open cs_kq for select c1 ma_kh,c2 ten_kh,c3 so_hd,PKH_SO_CNG(n4) ngay_cap,c5 so_don,PKH_SO_CNG(min(n5)) ngay_tt,sum(nvl(n3,0)) tien
    from temp_2  group by c1,c2,c3,c4,c5,c6,n4;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_HD_HUY2;

CREATE OR REPLACE PROCEDURE BC_BH_HD_HUY2
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_MA_DVI VARCHAR2,B_NV VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,
    B_PHONG VARCHAR2,B_LOAI VARCHAR2,B_MA_CB VARCHAR2,B_NGUON VARCHAR2,B_MA_DL VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NGAYD1 NUMBER;B_NOITE VARCHAR2(5);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';

B_NGAYD1:=PKH_NG_CSO(PKH_SO_CDT(B_NGAYD)-1);
B_NOITE:=FTT_TRA_NOITE(B_MA_DVI);
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; DELETE TEMP_3;COMMIT;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);

INSERT INTO TEMP_2 (C1,C2,C3,C4,C5,C7,C20,C21,N2,N3,N14) SELECT SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,
    FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHI,THUE,SO_ID
    FROM V_BC_BH_DTPS_HUY WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
    AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_NV='*' OR NV=B_NV);


INSERT INTO TEMP_2 (C1,C2,C3,C4,C5,C7,C20,C21,N6,N7,N14) SELECT SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,
    FBC_MA_BH(MA_DVI,NV,SO_ID),FBC_MA_BH_TEN(MA_DVI,NV,SO_ID,NGAY_HT),PHI,THUE,SO_ID
    FROM V_BC_BH_DTBH_MNVM_HUY WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
    AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_NV='*' OR NV=B_NV);
--LAM SACH
