--    UPDATE TEMP_3 SET (N16, C30)=(SELECT SUM(PHI_DT), MAX(NT_TIEN) FROM BH_TAULGCN_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17='TAUL';
--    UPDATE TEMP_3 SET (N16, C30)=(SELECT SUM(PHI_DT), MAX(NT_TIEN) FROM BH_XEGCN_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17='XE';
--    UPDATE TEMP_3 SET (N16, C30)=(SELECT SUM(PHI), MAX(NT_TIEN) FROM BH_NGUOIHD_DSDK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17='NG';
--    UPDATE TEMP_3 SET (N16, C30)=(SELECT SUM(PHI_DT), MAX(NT_TIEN) FROM BH_2B_GCN_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17='2B';
--    UPDATE TEMP_3 SET (N16, C30)=(SELECT SUM(PHI_DT), MAX(NT_TIEN) FROM BH_TAUGCN_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17='TAU';
