--    UPDATE TEMP_3 SET (N16, C30)=(SELECT SUM(PHI_DT), MAX(NT_TIEN) FROM BH_PHHGCN_DK WHERE MA_DVI=B_MA_DVI AND SO_ID=N14) WHERE C17='PHH';
