DROP PROCEDURE BC_BH_HHHT_TONGHOP;

CREATE OR REPLACE PROCEDURE BC_BH_HHHT_TONGHOP    
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_KIEU VARCHAR2,B_PHONG VARCHAR2,B_NGUON VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_PHONG OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_KIEU_KT VARCHAR(1);B_KIEU_DL VARCHAR(1);
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_KIEU ='D' THEN B_KIEU_DL:=NULL ;B_KIEU_KT:='D';
ELSIF B_KIEU='D1' THEN B_KIEU_DL:='K'; B_KIEU_KT:='D';
ELSIF B_KIEU='D2' THEN B_KIEU_DL:='Y'; B_KIEU_KT:='D';
ELSIF B_KIEU ='M' THEN B_KIEU_DL:=NULL;B_KIEU_KT:='M'; 
ELSIF B_KIEU ='T' THEN B_KIEU_DL:=NULL;B_KIEU_KT:='T'; 
ELSE
B_KIEU_DL:=NULL;B_KIEU_KT:=NULL;
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA;COMMIT;

BC_BH_DTTT_MD(B_MA_DVI,B_MA_DVI,'',B_PHONG,'','','','',B_KIEU_KT,0,B_NGAYD,B_NGAYC,B_LOI);
INSERT INTO TEMP_2(C1,N1,N10)
    SELECT C11,N2,N10 FROM TEMP_1;

DELETE TEMP_1; COMMIT;
-- Hung chuyen view V_HH_DDUYET_TS
/*
INSERT INTO TEMP_1(C1,C3,N2,N5,N10,N11,C10) SELECT A.MA_KT,MA_NT,SUM(A.HHONG_QD),SUM(A.HTRO_QD),A.SO_ID,SO_ID_KT,HTOAN 
    FROM V_HH_DDUYET A,KT_1 C
    WHERE A.MA_DVI=B_MA_DVI AND SO_ID_KT=C.SO_ID AND SO_ID_KT<>0
    AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
    GROUP BY A.MA_KT,A.MA_NT,A.SO_ID,SO_ID_KT,HTOAN;
*/
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
INSERT INTO TEMP_1(C1,C3,N2,N5,N10,N11,C10) SELECT A.MA_KT,MA_NT,SUM(A.HHONG_QD),SUM(A.HTRO_QD),A.SO_ID,SO_ID_KT,HTOAN 
    FROM V_HH_DDUYET_TS A,KT_1 C
    WHERE A.MA_DVI=B_MA_DVI AND SO_ID_KT=C.SO_ID AND SO_ID_KT<>0
    AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
    GROUP BY A.MA_KT,A.MA_NT,A.SO_ID,SO_ID_KT,HTOAN;

INSERT INTO TEMP_2(C1,N2,N5,N10) SELECT C1,SUM(N2),SUM(N5),N10 FROM TEMP_1 WHERE C10='H' GROUP BY C1,N10;

INSERT INTO TEMP_2(C1,N3,N6,N10) SELECT C1,SUM(N2),SUM(N5),N10 FROM TEMP_1 WHERE C10='T' GROUP BY C1,N10;
/*
INSERT INTO TEMP_2(C1,C3,N3,N6,N10,N11) SELECT MA_KT,MA_NT,SUM(HHONG_QD),SUM(HTRO_QD),SO_ID,SO_ID_KT 
    FROM V_HH_DDUYET A WHERE MA_DVI=B_MA_DVI AND SO_ID_KT=0
     AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
    GROUP BY MA_KT,MA_NT,SO_ID,SO_ID_KT;
*/
INSERT INTO TEMP_2(C1,C3,N3,N6,N10,N11) SELECT MA_KT,MA_NT,SUM(HHONG_QD),SUM(HTRO_QD),SO_ID,SO_ID_KT 
    FROM V_HH_DDUYET_TS A WHERE MA_DVI=B_MA_DVI AND SO_ID_KT=0
     AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
    GROUP BY MA_KT,MA_NT,SO_ID,SO_ID_KT;

BC_BH_HH_CDUYET_MD(B_MA_DVI,B_PHONG,B_NGUON,B_NGAYD,B_NGAYC,'','');
INSERT INTO TEMP_2(C1,C3,N4,N7,N10,N11,N20) SELECT  C1,C3,N4,N6,N10,N11,N20 FROM TEMP_1;
UPDATE TEMP_2 SET C2=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=TEMP_2.C1);  
UPDATE TEMP_2 SET (C10)=(SELECT KIEU_KT FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=TEMP_2.N10);
INSERT INTO KET_QUA (C1,C2,N1,N2,N3,N4,N5,N6,N7) 
    SELECT C1,C2,SUM(N1),SUM(N2),SUM(N3),SUM(N4),SUM(N5),SUM(N6),SUM(N7) FROM TEMP_2 
    WHERE (B_KIEU_KT IS NULL OR C10=B_KIEU_KT)  GROUP BY C1,C2;
DELETE KET_QUA WHERE NVL(N1,0)=0 AND NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N4,0)=0;
OPEN CS_KQ FOR SELECT C2 TEN, C1 MA_DL,N1 DT,N2 HH_DTT,N3 HH_DCTT, N4 HH_CD,N5 HT_DTT,N6 HT_DCTT, N7 HT_CD
    FROM KET_QUA ORDER BY C1;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_HH_CDUYET;

CREATE OR REPLACE PROCEDURE BC_BH_HH_CDUYET
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_NV VARCHAR2,B_MA_DL VARCHAR2,
 B_PHONG VARCHAR2,B_NGUON VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_NV OUT VARCHAR2,
 B_TEN_DL OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
 B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_KIEU_KT VARCHAR(1);B_KIEU_DL VARCHAR(1);
BEGIN

    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');

    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    if b_ngayd is null or b_ngayc is null then
        b_loi:='loi:nhap ngay bao cao:loi'; raise program_error;
    end if;
    b_ngaydn:=round(b_ngayc,-4)+101;

    if b_phong is not null then select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_phong;
    else b_ten_phong:=' ';
    end if;
    if b_ma_dl is not null then select ten into b_ten_dl from bh_dl_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma_dl;
    else b_ten_dl:=' ';
    end if;
    if b_ma_nv is not null then select ten into b_ten_nv from bh_ma_lhnv where ma_dvi=b_ma_dvi and ma=b_ma_nv;
    else b_ten_nv:=' ';
    end if;
    delete temp_1;
--b_loi:='loi:'||b_ma_nv||':loi';raise PROGRAM_ERROR;
    BC_BH_HH_CDUYET_MD(b_ma_dvi,b_phong,b_nguon,b_ngayd,b_ngayc,b_ma_dl,b_ma_nv);
    delete temp_2;delete ket_qua;commit;
    insert into temp_2(c9, c20, c21, c23, n3, n1, n2, n9,c24, c25, c26)
        select c9, c20, c21, c23, n3, n1, n2, n9, c24, c25, c26 from temp_1;

    update temp_2 set (n4,n5,n6)=(select sum(phi_qd),sum(thue_qd),sum(ttoan_qd) from bh_hd_goc_ttpt
        where ma_dvi = c9 and so_id=n1 and so_id_tt=n2 and pt<>'C');

    update temp_2 set c21=(select ten from bh_dl_ma_kh where ma_dvi = b_ma_dvi and ma = c20);

    open cs_kq for select c9 ma_dvi,c20 ma_kh, c21 ten_kh, c23 so_hd,c24 lh_nv, c25 nsd,'' ngay_cap, substr(n9,7,2)||'/'||substr(n9,5,2)||'/'||substr(n9,1,4) ngay_tt,
        sum(n4) dthu, sum(n5) thue,sum(n6) ttoan,sum(n3) hhong from temp_2 group by c9, c20, c21, c23, n9,c24, c25 ;

    EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);

END;
/

DROP PROCEDURE BC_BH_HH_CDUYET_MD;

CREATE OR REPLACE PROCEDURE BC_BH_HH_CDUYET_MD
    (B_MA_DVI VARCHAR2,B_PHONG VARCHAR2,B_NGUON VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,
    B_MA_KT VARCHAR2,B_LH_NV VARCHAR2)
AS
BEGIN
DELETE TEMP_1; DELETE TEMP_2; DELETE TEMP_3; COMMIT;
IF B_MA_DVI<>'00' THEN
    INSERT INTO TEMP_3(N1,N2,C1) SELECT SO_ID,SO_ID_TT,MA_DVI FROM BH_HD_GOC_SC_HH
        WHERE MA_DVI=B_MA_DVI;
ELSE
    INSERT INTO TEMP_3(N1,N2,C1) SELECT SO_ID,SO_ID_TT,MA_DVI FROM BH_HD_GOC_SC_HH;
END IF;

INSERT INTO TEMP_2(N1,N2,C9,C1,N3,N4,N5,N6, N7, C20, C21,  C23, C24, C25,C26)
    SELECT A.SO_ID,A.SO_ID_TT,DVI_XL,MA_NT,
    SUM(FTT_TUNG_QD(C.C1,B_NGAYC,MA_NT,A.HHONG,'VND')),SUM(FTT_TUNG_QD(C.C1,B_NGAYC,MA_NT,A.HTRO,'VND')),0,0,
    SUM(FTT_TUNG_QD(C.C1,B_NGAYC,MA_NT,A.PHI,'VND')),
    A.MA_DL, A.PHONG, B.SO_HD,A.LH_NV,B.NSD, C.C1
    FROM BH_HD_GOC_TTPB A, BH_HD_GOC B, TEMP_3 C
    WHERE A.MA_DVI = C.C1 AND A.DVI_XL = B.MA_DVI AND A.SO_ID = B.SO_ID AND A.SO_ID=N1 AND A.SO_ID_TT=N2
    AND A.NGAY_HT <= B_NGAYC AND A.HHONG<>0
    AND (B_NGUON IS NULL OR MA_GT LIKE B_NGUON||'%')
    AND (B_PHONG IS NULL OR A.PHONG=B_PHONG) AND (B_MA_KT IS NULL OR MA_DL = B_MA_KT)
    GROUP BY A.SO_ID, A.SO_ID_TT, A.DVI_XL, A.MA_NT, A.MA_DL, A.PHONG, B.SO_HD, A.LH_NV,B.NSD, C.C1;

INSERT INTO TEMP_2(N1,N2,C9,C1,N3,N4,N5,N6,N7, C20, C21, C23, C24, C25, C26)
    SELECT B.SO_ID,B.SO_ID_TT,DVI_XL,B.MA_NT,
    -SUM(B.HHONG_QD),-SUM(B.HTRO_QD), 0,0, 0, B.MA_DL, B.PHONG, C.SO_HD, D.LH_NV, C.NSD, E.C1
    FROM BH_HD_GOC_HH A, BH_HD_GOC_HH_CT B, BH_HD_GOC C, BH_HD_GOC_HH_PT D, TEMP_3 E
    WHERE A.MA_DVI = E.C1
    AND A.SO_ID_HH=B.SO_ID_HH AND A.MA_DVI=B.MA_DVI AND B.SO_ID=C.SO_ID AND B.MA_DVI=C.MA_DVI
    AND A.SO_ID_HH=D.SO_ID_HH AND C.SO_ID=D.SO_ID AND B.SO_ID_HH=D.SO_ID_HH
    AND B.SO_ID_TT=N2 AND B.SO_ID=N1
    AND (B_NGUON IS NULL OR MA_GT LIKE B_NGUON||'%') AND A.NGAY_HT<=B_NGAYC
    AND (B_PHONG IS NULL OR A.PHONG=B_PHONG) AND (B_MA_KT IS NULL OR A.MA_DL = B_MA_KT)
    GROUP BY B.SO_ID,B.SO_ID_TT,DVI_XL,B.MA_NT, B.MA_DL, B.PHONG, C.SO_HD,D.LH_NV, C.NSD ,E.C1;

    INSERT INTO TEMP_1(N1,N2,C9,C1,N3,N4,N5,N6,N7, C20, C21, C22, C23, C24, C25,C26)
        SELECT N1,N2,C9,C1,SUM(N3),SUM(N4),SUM(N5),SUM(N6),SUM(N7), C20, C21, C22, C23, C24, C25, C26
        FROM TEMP_2 GROUP BY N1, N2, C9, C1, C20, C21, C22, C23, C24, C25, C26;

    UPDATE TEMP_1 SET N9=(SELECT NGAY_TT FROM BH_HD_GOC_TTPT WHERE MA_DVI=B_MA_DVI AND SO_ID=N1 AND SO_ID_TT=N2 AND ROWNUM=1);
    UPDATE TEMP_1 SET (C10, C11) = (SELECT MA_KH, TEN FROM BH_HD_GOC WHERE SO_ID = N1);

END;
/

DROP PROCEDURE BC_BH_HH_CTT;

CREATE OR REPLACE PROCEDURE BC_BH_HH_CTT
(B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DL VARCHAR2,B_PHONG VARCHAR2,B_NGUON VARCHAR2,
 B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_DL OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
 B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_KIEU_KT VARCHAR(1);B_KIEU_DL VARCHAR(1);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
 B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_PHONG IS NOT NULL THEN
 SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_DL IS NOT NULL THEN
 SELECT TEN INTO B_TEN_DL FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_DL;
ELSE B_TEN_DL:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA;COMMIT;

INSERT INTO TEMP_2(C1,C2,C3,N1,N3,N4,N5,N10) SELECT A.SO_CT,PHONG,MA_KT,NGAY_HT,
        SUM(HHONG_QD)-SUM(THUE_HH_QD),SUM(THUE_HH_QD),SUM(HHONG_QD),A.SO_ID_KT FROM V_HH_DDUYET A
    WHERE A.MA_DVI=B_MA_DVI AND SO_ID_KT<>0 AND A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)  GROUP BY A.SO_CT,PHONG,MA_KT,NGAY_HT,A.SO_ID_KT;
UPDATE TEMP_2 SET (N2,C10)=(SELECT NGAY_HT,HTOAN FROM KT_1 WHERE MA_DVI=B_MA_DVI AND SO_ID=TEMP_2.N10);
DELETE TEMP_2 WHERE C10='H';

INSERT INTO TEMP_2(C1,C2,C3,N1,N3,N4,N5,N10) SELECT A.SO_CT,PHONG,MA_KT,
     NGAY_HT,SUM(HHONG_QD)-SUM(THUE_HH_QD),SUM(THUE_HH_QD),SUM(HHONG_QD),A.SO_ID_KT
     FROM V_HH_DDUYET A WHERE A.MA_DVI=B_MA_DVI AND SO_ID_KT=0
     AND A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
     GROUP BY A.SO_CT,PHONG,MA_KT,NGAY_HT,A.SO_ID_KT;
UPDATE TEMP_2 SET C4=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=TEMP_2.C3);
DELETE TEMP_2 WHERE NVL(N3,0)=0 AND NVL(N4,0)=0 AND NVL(N5,0)=0;

OPEN CS_KQ FOR SELECT C1 SO_CT,C3 MA_DL,C4 TEN_DL,PKH_SO_CNG(N1) NGAYD,DECODE(N2,0,'',PKH_SO_CNG(N2)) NGAYTT,
 N3 HHONG, N4 THUE,N5 HH_THUC FROM TEMP_2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_HH_DTT;

CREATE OR REPLACE PROCEDURE BC_BH_HH_DTT
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DL VARCHAR2,B_PHONG VARCHAR2,B_NGUON VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_DL OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_DL IS NOT NULL THEN
    SELECT TEN INTO B_TEN_DL FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_DL;
ELSE B_TEN_DL:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA;COMMIT;

INSERT INTO TEMP_2(C1,C2,N1,N3,N4,N5,N10) 
SELECT A.SO_CT,PHONG,NGAY_HT,SUM(HHONG_QD)-SUM(THUE_HH_QD),SUM(THUE_HH_QD),SUM(HHONG_QD),A.SO_ID_KT
    FROM V_HH_DDUYET A WHERE A.MA_DVI=B_MA_DVI AND SO_ID_KT<>0
     AND A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR PHONG=B_PHONG)
     GROUP BY A.SO_CT,PHONG,NGAY_HT,A.SO_ID_KT;
UPDATE TEMP_2 SET (N2,C10)=(SELECT NGAY_HT,HTOAN FROM KT_1 WHERE MA_DVI=B_MA_DVI AND SO_ID=TEMP_2.N10);
DELETE TEMP_2 WHERE C10='T';
DELETE TEMP_2 WHERE NVL(N3,0)=0 AND NVL(N4,0)=0 AND NVL(N5,0)=0;
OPEN CS_KQ FOR SELECT C1 SO_CT,PKH_SO_CNG(N1) NGAYD,PKH_SO_CNG(N2) NGAYTT,
    N3 HHONG, N4 THUE,N5 HH_THUC FROM TEMP_2 ORDER BY N2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_HH_THCDUYET;

CREATE OR REPLACE PROCEDURE BC_BH_HH_THCDUYET
 (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_NGUON VARCHAR2,
 B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_NV OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
 B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_KIEU_KT VARCHAR(1);B_KIEU_DL VARCHAR(1);
BEGIN
    
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
    
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
     B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
    END IF;
    B_NGAYDN:=ROUND(B_NGAYC,-4)+101;
    
    IF B_PHONG IS NOT NULL THEN
     SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
    ELSE B_TEN_PHONG:=' ';
    END IF;
    IF B_MA_NV IS NOT NULL THEN
     SELECT TEN INTO B_TEN_NV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
    ELSE B_TEN_NV:=' ';
    END IF;
    
    BC_BH_HH_CDUYET_MD(B_MA_DVI,B_PHONG,B_NGUON,B_NGAYD,B_NGAYC,'',B_MA_NV);
    DELETE TEMP_2;COMMIT;
    INSERT INTO TEMP_2(C20, N3, N7)
        SELECT C20, SUM(N3), SUM(N7) FROM TEMP_1 GROUP BY C20;

    UPDATE TEMP_2 SET C2=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=TEMP_2.C20);
    commit;
    OPEN CS_KQ FOR SELECT C20 MA_DL,C2 TEN_DL,N7 DTHU, NVL(N7,0)+NVL(N2,0) TTOAN,N3 HHONG FROM TEMP_2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_HH_TONGHOP;

CREATE OR REPLACE PROCEDURE BC_BH_HH_TONGHOP
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_KIEU VARCHAR2,B_PHONG VARCHAR2,B_NGUON VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,B_TEN_PHONG OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_KIEU_KT VARCHAR(1);B_KIEU_DL VARCHAR(1);B_I1 NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_KIEU ='D' THEN B_KIEU_DL:=NULL ;B_KIEU_KT:='D';
ELSIF B_KIEU='D1' THEN B_KIEU_DL:='K'; B_KIEU_KT:='D';
ELSIF B_KIEU='D2' THEN B_KIEU_DL:='Y'; B_KIEU_KT:='D';
ELSIF B_KIEU ='M' THEN B_KIEU_DL:=NULL;B_KIEU_KT:='M'; 
ELSIF B_KIEU ='T' THEN B_KIEU_DL:=NULL;B_KIEU_KT:='T'; 
ELSE
B_KIEU_DL:=NULL;B_KIEU_KT:=NULL;
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA;COMMIT;
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);
-- LAM SACH
-- INSERT INTO TEMP_1(C1,C2,N1,N10,N11) SELECT B.MA_DVI,MA_KT,B.PHI,B.SO_ID,SO_ID_TT FROM V_BC_BH_DTTT_MM B 
--     WHERE MA_DVI=B_MA_DVI AND (B_PHONG IS NULL OR PHONG=B_PHONG);
INSERT INTO TEMP_2 (C1,N1,N10) SELECT C2,N1,N10 FROM TEMP_1;

DELETE TEMP_1; COMMIT;
INSERT INTO TEMP_1(C1,C3,N2,N10,N11,C10) SELECT A.MA_KT,MA_NT,SUM(A.HHONG_QD),A.SO_ID,SO_ID_KT,HTOAN 
    FROM V_HH_DDUYET A,KT_1 C
    WHERE A.MA_DVI=B_MA_DVI AND C.MA_DVI=B_MA_DVI AND SO_ID_KT=C.SO_ID AND SO_ID_KT<>0
    AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
    GROUP BY A.MA_KT,A.MA_NT,A.SO_ID,SO_ID_KT,HTOAN;

INSERT INTO TEMP_2(C1,N2,N10) SELECT C1,SUM(N2),N10 FROM TEMP_1 WHERE C10='H' GROUP BY C1,N10;

INSERT INTO TEMP_2(C1,N3,N10) SELECT C1,SUM(N2),N10 FROM TEMP_1 WHERE C10='T' GROUP BY C1,N10;

INSERT INTO TEMP_2(C1,C3,N3,N10,N11) SELECT A.MA_KT,MA_NT,SUM(A.HHONG_QD),A.SO_ID,SO_ID_KT 
    FROM V_HH_DDUYET A WHERE A.MA_DVI=B_MA_DVI AND SO_ID_KT=0
     AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
    GROUP BY A.MA_KT,A.MA_NT,A.SO_ID,SO_ID_KT;
    


BC_BH_HH_CDUYET_MD(B_MA_DVI,B_PHONG,B_NGUON,B_NGAYD,B_NGAYC,'','');
INSERT INTO TEMP_2(C1,C3,N4,N10,N11,N20) SELECT  C1,C3,N4,N10,N11,N20 FROM TEMP_1;
UPDATE TEMP_2 SET C2=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=TEMP_2.C1);  
UPDATE TEMP_2 SET (C10)=(SELECT KIEU_KT FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=TEMP_2.N10);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
INSERT INTO KET_QUA (C1,C2,N1,N2,N3,N4) SELECT C1,C2,SUM(N1),SUM(N2),SUM(N3),SUM(N4) FROM TEMP_2 
    WHERE (B_KIEU_KT IS NULL OR C10=B_KIEU_KT) GROUP BY C1,C2;
DELETE KET_QUA WHERE NVL(N1,0)=0 AND NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N4,0)=0;

OPEN CS_KQ FOR SELECT C2 TEN, C1 MA,N1 DTBH,N2 HH_DDTT,N3 HH_DDCTT, N4 HH_CD    
    FROM KET_QUA ORDER BY C1;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_TK_HANG_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TK_HANG_MD
    (b_madvi varchar2,b_ma_dvi varchar2,b_ngayd number,b_ngayc number,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_tc varchar2,b_so_id number,b_loi out varchar2)
AS
Begin
--BCNam: Module bao cao thong ke hang hoa, sua lai
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; return;
end if;

delete temp_1;commit;
--hang hoa
--b_tc='C' chay bao cao theo ngay cap; 'K' chay bao cao theo ngay hach toan
if b_tc='C' then
    insert into temp_1(c29,c1,c2,c3,c4,c5,c6,c7,c8,c17,c18,c19,c20,c21,n1,n2,n3,n4,n5,n6,d1,n7,n27,c23,c35,c25,c26,c27,c31,n9,n10,n11)
    select a.ma_dvi,VCHUYEN loai_pt,VCHUYEN ten_pt,'' so_chuyen,substr(cang_di,0,250),substr(cang_den,1,250),c_ctai,'' dk_bh,''gdinh,ma_kh,phong,ma_cb,
        PKH_SO_CNG(a.ngay_hl),nt_phi,a.so_id,''tl_phi,a.phi,'' tl_pphi,''pphi,b.tien,PKH_SO_DATE(a.ngay_cap),b.phi,a.ngay_ht,a.nt_tien,kieu_hd,a.ttrang,
        ''ten_hang,'','' dgoi,'',a.so_id_d,FBH_DONG_TL_DT(a.ma_dvi,a.so_id,0,b.lh_nv) --sluong|| '/' ||dvi_tinh
    from bh_hang_dk b,temp_bc_dvi tdv,bh_hang a --BH_HANG_ds c,
    where 
--    a.ma_dvi=c.ma_dvi and a.so_id=c.so_id and
    (b_ma_dvi is null or a.ma_dvi =tdv.dvi) and a.kieu_hd not in ('V','N')
    and (kieu_hd<>'B' or FBH_HD_KIEU_HD(a.ma_dvi, FBH_HD_SO_ID_BAO(a.ma_dvi, a.so_id_g)) not in('V','N'))
    and a.so_id=FBH_HD_SO_ID_BS(a.ma_dvi,a.so_id,b_ngayc)
    and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
    and (a.ngay_cap between b_ngayd and b_ngayc)
    and (b_so_id=0 or a.so_id = b_so_id) and (b_phong is null or a.phong=b_phong)
    and (b_ma_kh is null or a.ma_kh=b_ma_kh) and (b_ma_cb is null or a.ma_cb=b_ma_cb);
else
    insert into temp_1(c29,c1,c2,c3,c4,c5,c6,c7,c8,c17,c18,c19,c20,c21,n1,n2,n3,n4,n5,n6,d1,n7,n27,c23,c35,c25,c26,c27,c31,n9,n10,n11)
    select a.ma_dvi,VCHUYEN loai_pt,VCHUYEN ten_pt,'' so_chuyen,substr(cang_di,0,250),substr(cang_den,1,250),c_ctai,'' dk_bh,''gdinh,ma_kh,phong,ma_cb,
        PKH_SO_CNG(a.ngay_hl),nt_phi,a.so_id,''tl_phi,a.phi,'' tl_pphi,''pphi,b.tien,PKH_SO_DATE(a.ngay_cap),b.phi,a.ngay_ht,a.nt_tien,kieu_hd,a.ttrang,
        ''ten_hang,'','' dgoi,'',a.so_id_d,FBH_DONG_TL_DT(a.ma_dvi,a.so_id,0,b.lh_nv) --sluong|| '/' ||dvi_tinh
    from bh_hang_dk b,temp_bc_dvi tdv,bh_hang a --BH_HANG_ds c,
    where 
--    a.ma_dvi=c.ma_dvi and a.so_id=c.so_id and
    (b_ma_dvi is null or a.ma_dvi =tdv.dvi)
    and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.kieu_hd not in ('V','N')
    and (kieu_hd<>'B' or FBH_HD_KIEU_HD(a.ma_dvi, FBH_HD_SO_ID_BAO(a.ma_dvi, a.so_id_g)) not in('V','N'))
    and a.so_id=FBH_HD_SO_ID_BS(a.ma_dvi,a.so_id,b_ngayc)
    and (a.ngay_ht between b_ngayd and b_ngayc) and (b_so_id=0 or a.so_id = b_so_id)
    and (b_phong is null or phong=b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
    and (b_ma_cb is null or ma_cb=b_ma_cb);
end if;
-- ma_dvi:c1, so_hd c2, kieu_hd,loai hinh bao hiem c22, nguoi duoc bao hiem:c21, loai khach hang,phuong tien van chuyen:c7, doi tuong bao hiem:c31,ngay khoi hanh:c8,
--cang di:c11,cang den:c9,nt_tien:c23,tien_bh:n6, nt_phi:c21,phi: n3+n5, ty le dong
update temp_1 set (c22,c36)=(select lh_nv,ma from BH_HANG_dk where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and TC='C' and rownum=1);
--update temp_1 set n7=(select sum(phi_dt) from BH_HANGgcn_dk where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and so_id_dt=n9);
update temp_1 set c9= (select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='TEN' and g_tri is not null  and rownum=1);
update temp_1 set c10= (select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='BLNo' and g_tri is not null  and rownum=1);
update temp_1 set c11 =(select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='PACKING' and g_tri is not null  and rownum=1);
update temp_1 set c12 =(select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='QUANTITY' and g_tri is not null  and rownum=1);
update temp_1 set c13 =(select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='CONTAI' and g_tri is not null  and rownum=1);
update temp_1 set c14 =(select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='CONTRACT' and g_tri is not null  and rownum=1);
update temp_1 set c15 =(select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='COMMER' and g_tri is not null  and rownum=1);
update temp_1 set c16 =(select g_tri from bh_hd_goc_dt where ma_dvi=temp_1.c29 and so_id=temp_1.n1 and ma_tke='LC' and g_tri is not null and rownum=1);
--delete from temp_1 where n1 in (Select so_id from bh_hd_goc where kieu_hd='V');
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_KHAITHAC_HH_CANG;

CREATE OR REPLACE PROCEDURE BC_BH_KHAITHAC_HH_CANG
	(B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
	B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TC VARCHAR2,B_CANG_DI VARCHAR2,
	B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
	B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER;B_I1 NUMBER;
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_TK_HANG_MD(B_MADVI,B_MA_DVI,B_NGAYD,B_NGAYC,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,B_MA_CB,B_TC,0,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

UPDATE TEMP_1 SET N21=(SELECT A.TY_GIA FROM TT_TGTT A WHERE A.MA_DVI=TEMP_1.C1 AND
	A.NGAY=(SELECT MAX(B.NGAY) FROM TT_TGTT B WHERE B.MA_DVI=TEMP_1.C1 AND
	B.NGAY<=TO_DATE(TEMP_1.N7,'YYYYMMDD') AND B.MA=A.MA AND A.MA=TEMP_1.C12));
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
	INSERT INTO TEMP_2 (C1,C2,C4,C5,C6,C7,C9,C10,C11,N1,N2,N3,N4,N5,C13,C20,C24,C26,C8,C12,C22,D1)
		SELECT C29,FBH_HD_GOC_SO_HD(C29,N1),C9,C12,C11,C2,C4,C6,C5,N1,N6,N2,N4,N3+N5,C7,C17,C18,C19,C20,C21,C22,D1 FROM TEMP_1;
ELSE
	INSERT INTO TEMP_2 (C1,C2,C4,C5,C6,C7,C9,C10,C11,N1,N2,N3,N4,N5,C13,C20,C24,C26,C8,C12,C22,D1)
		SELECT C29,FBH_HD_GOC_SO_HD(C29,N1),C9,C12,C11,C2,C4,C6,C5,N1,N6,N2,N4,N3+N5,C7,C17,C18,C19,C20,C21,C22,D1
		FROM TEMP_1,TEMP_BC_DVI WHERE C29=DVI;
END IF;
UPDATE TEMP_2 SET (C2,C16,C13)=(SELECT SO_HD,CANG_DI,CANG_DEN FROM BH_HANG WHERE MA_DVI=C1 AND SO_ID=N1) WHERE C2 IS NULL;
UPDATE TEMP_2 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C22);
UPDATE TEMP_2 SET C21=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C20);
UPDATE TEMP_2 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C24);
UPDATE TEMP_2 SET C27=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C26);
UPDATE TEMP_2 SET C3=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_2.C1);
--UPDATE TEMP_2 SET C14=(SELECT TEN FROM BH_MA_CANG WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C12);
--UPDATE TEMP_2 SET C13=(SELECT TEN FROM BH_MA_CANG WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C15);
OPEN CS_KQ FOR SELECT C1 MA_DVI,C3 TEN_DVI,C20 MA_KH,C21 TEN_KH,C26 CB_QL,
	C27 TEN_CBQL,C24 PHONG, C25 TEN_PHONG,C22 LH_NV,C23 TEN_LHNV,
	C2 SO_HD,C4 TEN_HANG,C5 SL_HH,C6 PTHUC,C7 PTIEN, C8 NGAY_KH,C9 TU,C10 CTAI,C11 DEN,N2 TIEN_BH,
	C12 MA_NT,N3 PHI_C,N4 PHI_P,N5 PHI_T,C13 MA_DK,C28 TEN_DK_BH,TO_CHAR(D1,'dd/mm/yyyy') NGAY_CAP,	C16 CANG_DI,C13 CANG_DEN--,C14 TEN_CANG_DEN 
	FROM TEMP_2 WHERE (B_CANG_DI IS  NULL OR C12=B_CANG_DI) ORDER BY D1,C2;
END;
/
DROP PROCEDURE BC_BH_KHAITHAC_KYTHUAT;

CREATE OR REPLACE PROCEDURE BC_BH_KHAITHAC_KYTHUAT(
    b_madvi VARCHAR2,b_nsd VARCHAR2,b_pas VARCHAR2,b_ma_dvi VARCHAR2,b_ma_nv VARCHAR2,b_phong VARCHAR2,b_loai_kh VARCHAR2,
    b_ma_kh VARCHAR2,b_ma_cb VARCHAR2,b_tc VARCHAR2,b_ttrang VARCHAR2,b_ngayd NUMBER,b_ngayc NUMBER,
    cs_kq OUT pht_type.cs_type
)
AS
    b_loi  VARCHAR2(100);
    b_ngaydn NUMBER;
    b_rr VARCHAR2(100);
BEGIN
    -- Kiem tra user
    b_loi := FHT_MA_NSD_KTRA(b_madvi, b_nsd, b_pas, 'BH', 'PHH', 'X');
    IF b_loi IS NOT NULL THEN
  RAISE PROGRAM_ERROR;
    END IF;
    -- Kiem tra ngay bao cao
    IF b_ngayd IS NULL OR b_ngayc IS NULL THEN
  b_loi := 'loi:Nhap ngay bao cao:loi';
  RAISE PROGRAM_ERROR;
    END IF;

    b_ngaydn := ROUND(b_ngayd, -4) + 101;

    DELETE FROM temp_6;
    COMMIT;

    FOR r_lp IN (
        SELECT a.so_id, a.so_hd, a.ngay_cap, a.ten, a.ma_sp,a.kieu_kt,a.ma_kt,a.phong,a.ma_dvi,
        b.ma_nct, b.ma_ntb, b.dvi, b.ngay_hl, b.ngay_kt, a.nt_tien,b.so_id_dt
        FROM bh_pkt a
        JOIN bh_pkt_dvi b ON a.so_id = b.so_id
        WHERE a.ngay_ht BETWEEN b_ngayd AND b_ngayc
        and b.ma_dvi=a.ma_dvi and b.so_id=a.so_id
        and (b_ma_dvi is null or a.ma_dvi = b_ma_dvi) and (b_ma_kh is null or a.ma_kh = b_ma_kh)
        and (b_phong is null or a.phong = b_phong) order by ngay_cap,so_hd
    )
    LOOP
        SELECT LISTAGG(ma, ',') WITHIN GROUP (ORDER BY ma) into b_rr
            FROM (SELECT DISTINCT ma
                FROM bh_pkt_dk
                WHERE so_id = r_lp.so_id AND so_id_dt = r_lp.so_id_dt
                    AND TRIM(ma_ct) IS NULL and tc = 'T');

        FOR r IN (
        SELECT t.TONG_TIEN,t.TONG_THUE,t.TONG_TTOAN,t.TONG_PT
        FROM
            (
            SELECT  SUM(TIEN) AS TONG_TIEN,SUM(THUE) AS TONG_THUE, SUM(TTOAN) AS TONG_TTOAN, SUM(PT) AS TONG_PT
            FROM bh_pkt_dk
            WHERE so_id = r_lp.so_id AND so_id_dt = r_lp.so_id_dt
            AND lh_nv<>' '
            ) t
        )
        LOOP
            INSERT INTO temp_6 (n1, c1, n2, c2, c3, c5, c6,n3, n4, c7, n5, n6, n7, n8, n9,c9,c11,c12,c13,c14) VALUES (
            r_lp.so_id, r_lp.so_hd, r_lp.ngay_cap, r_lp.ten, FBH_PKT_SP_TEN(r_lp.ma_sp), b_rr, r_lp.dvi, r_lp.ngay_hl, r_lp.ngay_kt,
            r_lp.nt_tien, r_lp.so_id_dt, r.TONG_TIEN, r.TONG_THUE, r.TONG_TTOAN, r.TONG_PT,
            nvl(r_lp.ma_nct,r_lp.ma_ntb),
            r_lp.kieu_kt,r_lp.ma_kt,r_lp.phong,r_lp.ma_dvi
            );
        END LOOP;
    END LOOP;
    OPEN cs_kq FOR
      SELECT rownum stt,n1, c1 so_hd, PKH_SO_CNG(n2) ngay_cap, c2 ten, c3 ma_sp, c5 rr_bh, c6 ddiem,PKH_SO_CNG(n3) ngay_hl, PKH_SO_CNG(n4) ngay_kt, c7 ma_nt, n5 so_id_dt,
      FBH_CSO_TIEN_KNT(n6) tien, FBH_CSO_TIEN_KNT(n7) TONG_THUE, FBH_CSO_TIEN_KNT(n8) phi, n9 tyle, c9 doi_tuong, c11 kieu_kt, c12 ma_kt, c13 phong, c14 dvi
      FROM temp_6;
delete temp_6;
commit;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105, NVL(b_loi, SQLERRM));END;
/
DROP PROCEDURE BC_BH_KHAITHAC_TRACHNHIEM;

CREATE OR REPLACE PROCEDURE BC_BH_KHAITHAC_TRACHNHIEM
    (b_madvi VARCHAR2,b_nsd VARCHAR2,b_pas VARCHAR2,b_ma_dvi VARCHAR2,b_ma_nv VARCHAR2,b_phong VARCHAR2,b_loai_kh VARCHAR2,
    b_ma_kh VARCHAR2,b_ma_cb VARCHAR2,b_tc VARCHAR2,b_ttrang VARCHAR2,b_ngayd NUMBER,b_ngayc NUMBER,
    cs_kq OUT pht_type.cs_type)
AS
    b_loi  VARCHAR2(100);
    b_ngaydn NUMBER;
    b_rr VARCHAR2(100);
BEGIN
    -- Kiem tra user
    b_loi := FHT_MA_NSD_KTRA(b_madvi, b_nsd, b_pas, 'BH', 'PTN', 'X');
    IF b_loi IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    DELETE FROM temp_6;
    -- Kiem tra ngay bao cao
    IF b_ngayd IS NULL OR b_ngayc IS NULL THEN
      b_loi := 'loi:Nhap ngay bao cao:loi';RAISE PROGRAM_ERROR;
    END IF;
    b_ngaydn := ROUND(b_ngayd, -4) + 101;
    FOR r_lp IN (
        SELECT a.so_id, a.so_hd, a.ngay_cap, a.ten, a.ma_sp, a.kieu_kt, a.ma_kt, a.phong, a.ma_dvi, a.ngay_hl, a.ngay_kt, a.nt_tien,a.dchi
        FROM bh_ptn a
        WHERE a.ngay_ht BETWEEN b_ngayd AND b_ngayc
        and (b_ma_dvi is null or a.ma_dvi = b_ma_dvi) and (b_ma_kh is null or a.ma_kh = b_ma_kh)
        and (b_phong is null or a.phong = b_phong) order by ngay_cap,so_hd
    )
    LOOP
        SELECT LISTAGG(ma, ',') WITHIN GROUP (ORDER BY ma) into b_rr
        FROM (SELECT DISTINCT ma
            FROM bh_ptn_dk
            WHERE so_id = r_lp.so_id AND TRIM(ma_ct) IS NULL and tc = 'T');
        FOR r IN (
        SELECT t.TONG_TIEN,t.TONG_THUE,t.TONG_TTOAN,t.TONG_PT
        FROM
            (
            SELECT  SUM(TIEN) AS TONG_TIEN,SUM(THUE) AS TONG_THUE, SUM(TTOAN) AS TONG_TTOAN, SUM(PT) AS TONG_PT
            FROM bh_ptn_dk
            WHERE so_id = r_lp.so_id AND lh_nv<>' '
            ) t
        )
        LOOP
            INSERT INTO temp_6 (n1, c1, n2, c2, c3,c4, n3, n4, c6, c7, n6, n7, n8, n9, c11, c12, c13, c14) VALUES (
            r_lp.so_id, r_lp.so_hd, r_lp.ngay_cap, r_lp.ten, r_lp.ma_sp,FBH_HD_TXT('PTN',r_lp.ma_dvi,r_lp.so_id,'dtuong'), r_lp.ngay_hl, r_lp.ngay_kt,
            FBH_HD_TXT('PTN',r_lp.ma_dvi,r_lp.so_id,'dchiB'),r_lp.nt_tien, r.TONG_TIEN, r.TONG_THUE, r.TONG_TTOAN, r.TONG_PT,
            r_lp.kieu_kt,r_lp.ma_kt,r_lp.phong,r_lp.ma_dvi
            );
        END LOOP;
    END LOOP;

    OPEN cs_kq FOR
  SELECT rownum stt,n1, c1 so_hd, PKH_SO_CNG(n2) ngay_cap, c2 ten, c3 ma_sp, c4 doi_tuong, c6 ddiem,PKH_SO_CNG(n3) ngay_hl, PKH_SO_CNG(n4) ngay_kt, c7 ma_nt,
  FBH_CSO_TIEN_KNT(n6) tien, FBH_CSO_TIEN_KNT(n7) TONG_THUE, FBH_CSO_TIEN_KNT(n8) phi, n9 tyle, c11 kieu_kt, c12 ma_kt, c13 phong, c14 dvi
  FROM temp_6;

delete temp_6;
commit;
EXCEPTION
    WHEN OTHERS THEN
  RAISE_APPLICATION_ERROR(-20105, NVL(b_loi, SQLERRM));
END;
/

DROP PROCEDURE BC_BH_KTRU_THUE;

CREATE OR REPLACE PROCEDURE BC_BH_KTRU_THUE
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_LOAI VARCHAR2,
    B_PHONG VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
    B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
    SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA;COMMIT;
--LAM SACH
-- INSERT INTO TEMP_1 (C1,C2) SELECT LH_NV,'NG' FROM BH_NGUOI_PHI_CT WHERE MA_DVI=B_MA_DVI;

INSERT INTO TEMP_2(C10,C1,C2,C4,C6,N2,N3) SELECT CB_QL,NV.LH_NV,MA_NT,GOC.MA_KH,PHONG,
    SUM(DECODE(T_SUAT,10,phi_qd,0)),SUM(DECODE(T_SUAT,10,0,phi_qd)) FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
    WHERE GOC.MA_DVI=B_MA_DVI AND NV.MA_DVI=B_MA_DVI AND GOC.SO_ID=NV.SO_ID
    AND (NV.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND (B_PHONG IS NULL OR PHONG =B_PHONG)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
    GROUP BY CB_QL,NV.LH_NV,MA_NT,GOC.MA_KH,PHONG;
INSERT INTO TEMP_2(C1,C2,C4,C6,N2,N3) SELECT NV.LH_NV,NV.MA_NT,GOC.MA_KH,PHONG,
    SUM(DECODE(PT.T_SUAT,10,NV.THUE_QD*10,0)),SUM(DECODE(PT.T_SUAT,10,0,NV.THUE_QD*10)) FROM BH_HD_GOC_HU GOC,BH_HD_GOC_HUPT NV, BH_HD_GOC_TTPT PT
    WHERE GOC.MA_DVI=B_MA_DVI AND NV.MA_DVI=B_MA_DVI AND PT.MA_DVI=B_MA_DVI AND GOC.SO_ID=NV.SO_ID AND PT.SO_ID=NV.SO_ID
    AND NV.LH_NV=PT.LH_NV AND GOC.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
    AND (B_PHONG IS NULL OR PHONG =B_PHONG)
    AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%')
    GROUP BY NV.LH_NV,NV.MA_NT,GOC.MA_KH,PHONG;
UPDATE TEMP_2 SET N10=(SELECT A.TY_GIA FROM TT_TGTT A WHERE A.MA_DVI=B_MA_DVI AND
    A.NGAY=(SELECT MAX(B.NGAY) FROM TT_TGTT B WHERE B.MA_DVI=B_MA_DVI AND
    B.NGAY <=TO_DATE(TEMP_2.N1,'YYYYMMDD') AND B.MA=A.MA AND A.MA=TEMP_2.C2));
UPDATE TEMP_2 SET N3=N3*NVL(N10,1),N2=N2*NVL(N10,1);


UPDATE TEMP_2 SET C5=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI
    AND MA=TEMP_2.C4);
INSERT INTO TEMP_3 (C1,N2,N3) SELECT C1,SUM(N2),SUM(N3) FROM TEMP_2
    WHERE (B_LOAI IS NULL OR C5=B_LOAI) AND (B_PHONG IS NULL OR C6=B_PHONG) GROUP BY C1;
INSERT INTO KET_QUA(C1,C4,N2,N3,N5) SELECT C1,'C',SUM(N2),SUM(N3),SUM(N5) FROM TEMP_3 GROUP BY C1;
DELETE KET_QUA WHERE N2 IS NULL AND N3 IS NULL;

UPDATE KET_QUA SET C2=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI
    AND MA=KET_QUA.C1);
OPEN CS_KQ FOR SELECT C1 AS MA_NV, C2 AS TEN_NV,ROUND(NVL(N2,0)) AS DTCTHUE,ROUND(NVL(N3,0)) DTKCTHUE,
    ROUND(NVL(N3,0))+ROUND(NVL(N2,0)) TONG
    FROM KET_QUA ORDER BY C1;
EXCEPTION WHEN OTHERS THEN IF B_LOI IS NULL THEN RAISE PROGRAM_ERROR; ELSE  RAISE_APPLICATION_ERROR(-20105,B_LOI); END IF;
END;

/
drop PROCEDURE BC_BH_LAY_BC_BH_DTBH_MM;
CREATE OR REPLACE PROCEDURE BC_BH_LAY_BC_BH_DTBH_MM
    (b_ma_dvi varchar2, b_ngayd number, b_ngayc number)
AS
begin
if b_ma_dvi is not null then
    insert into TEMP_BC_BH_DTBH_MM
        SELECT goc.ma_dvi, goc.so_hd, goc.nv, goc.kieu_hd, goc.ma_kh, goc.ma_gt, goc.cb_ql, goc.phong,
            goc.kieu_kt, goc.ma_kt, PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(goc.ngay_kt), nv.ma_nt, nv.lh_nv, goc.so_id, nv.so_id_tt,
            goc.ngay_ht, nv.ngay_tt, phi_qd, thue_qd, nv.phi, nv.thue, 0, goc.ma_dvi
            FROM bh_hd_goc goc, bh_hd_goc_ttpt nv
            WHERE 
              --nv.ma_dvi LIKE b_ma_dvi||'%' AND 
              nv.ma_dvi = b_ma_dvi AND
              nv.ngay_tt BETWEEN b_ngayd AND b_ngayc AND nv.pt <> 'N'
              AND goc.kieu_hd NOT IN ('V', 'N')
              AND goc.ma_dvi = nv.ma_dvi AND goc.so_id = nv.so_id;

    insert into TEMP_BC_BH_DTBH_MM
        SELECT goc.ma_dvi, goc.so_hd, goc.nv, goc.kieu_hd, goc.ma_kh, goc.ma_gt, goc.cb_ql, goc.phong,
            goc.kieu_kt, goc.ma_kt, PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(goc.ngay_kt), nv.ma_nt, nv.lh_nv, goc.so_id, nv.so_id_tt,
            goc.ngay_ht, nv.ngay_tt, -nv.phi_qd, -nv.thue_qd, -nv.phi, -nv.thue, 4, goc.ma_dvi
