            goc.ngay_ht, nv.ngay_ht, DECODE (nv.kieu, 'V', nv.tien_qd, -nv.tien_qd),
              0, DECODE (nv.kieu, 'V', nv.tien, -nv.tien), 0, 3, goc.ma_dvi
            FROM bh_hd_goc goc, bh_hd_do_pb nv
            WHERE 
            --nv.ma_dvi LIKE b_ma_dvi||'%' AND 
            nv.ngay_ht BETWEEN b_ngayd AND b_ngayc
            AND nv.loai IN ('CH_LE_PH', 'DT_LE_TL', 'DT_LE_HU') and goc.so_id =20141112008694
            AND goc.ma_dvi = nv.dvi_xl AND goc.so_id = nv.so_id;

       --Dong bao hiem don vi
    insert into TEMP_BC_BH_DTBH_MM
        SELECT nv.ma_dvi, goc.so_hd, goc.nv, goc.kieu_hd, goc.ma_kh, goc.ma_gt, goc.cb_ql, nv.phong,
            goc.kieu_kt, goc.ma_kt, PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(goc.ngay_kt), nv.ma_nt, nv.lh_nv, goc.so_id, nv.so_id_tt,
            goc.ngay_ht, nv.ngay_ht, nv.phi_qd, 0, nv.phi, 0, 1, goc.ma_dvi
            FROM bh_hd_goc goc, bh_hd_goc_ttpb nv
            WHERE 
            --(b_ma_dvi is null or nv.ma_dvi LIKE b_ma_dvi||'%') AND 
            nv.ngay_ht BETWEEN b_ngayd AND b_ngayc
            AND nv.pt <> 'N' AND nv.pthuc IN ('D', 'P')
            AND goc.ma_dvi = nv.dvi_xl AND goc.so_id = nv.so_id;

    insert into TEMP_BC_BH_DTBH_MM
        SELECT goc.ma_dvi, goc.so_hd, goc.nv, goc.kieu_hd, goc.ma_kh, goc.ma_gt, goc.cb_ql, goc.phong,
            goc.kieu_kt, goc.ma_kt, PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(goc.ngay_hl), nv.ma_nt, nv.lh_nv, goc.so_id, nv.so_id_tt,
            goc.ngay_ht, nv.ngay_ht, -nv.phi_qd, 0, -nv.phi, 0, 2, goc.ma_dvi
            FROM bh_hd_goc goc, bh_hd_goc_ttpb nv
            WHERE 
            --(b_ma_dvi is null or goc.ma_dvi LIKE b_ma_dvi||'%') AND 
            nv.ngay_ht BETWEEN b_ngayd AND b_ngayc
            AND nv.pt <> 'N' AND nv.pthuc IN ('D', 'P')
            AND goc.ma_dvi = nv.dvi_xl AND goc.so_id = nv.so_id;
end if;
end;
/
drop procedure BC_BH_LAY_BC_BH_DTBH_MNVM;
CREATE OR REPLACE PROCEDURE BC_BH_LAY_BC_BH_DTBH_MNVM
    (b_ma_dvi varchar2, b_ngayd number, b_ngayc number)
AS
begin
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);
insert into TEMP_BC_BH_DTBH_MNVM
    SELECT ma_dvi, so_hd, a.nv, kieu_hd, ma_kh, nguon, cb_ql, phong,
        kieu_kt, ma_kt, ngay_hl, ngay_kt, ma_nt, lh_nv, so_id,
        ngay_ht, ngay_htnv, phi, thue, phi_nt, thue_nt, dbh, ma_dvig
        FROM TEMP_BC_BH_DTBH_MM a
        WHERE FBH_HD_NV_RUT(nv) IN (SELECT DISTINCT nv FROM temp_bc_nv);
end;
/

DROP function PKH_SO_DATE;

CREATE OR REPLACE function PKH_SO_DATE(b_so number) return date
AS
    b_c8 varchar2(8);
begin
-- chuyen ngay number sang date 
b_c8:=to_char(b_so);
return to_date(b_c8,'yyyyMMdd');
end;
/
DROP PROCEDURE BC_BH_LAY_BC_BH_DTPS_MM;
CREATE OR REPLACE PROCEDURE BC_BH_LAY_BC_BH_DTPS_MM
    (b_ma_dvi varchar2, b_ngayd number, b_ngayc number)
AS
begin
if b_ma_dvi is not null then
    insert into TEMP_BC_BH_DTPS_MM
      select goc.ma_dvi, goc.so_hd, goc.nv, goc.kieu_hd, goc.ma_kh, goc.ma_gt, goc.cb_ql, goc.phong, goc.kieu_kt,
              goc.ma_kt, PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(goc.ngay_kt), nv.ma_nt, nv.lh_nv, goc.so_id, goc.ngay_ht, nv.ngay_ht,
              case nv.ma_nt when 'VND' then nv.phi
                 else ftt_vnd_qd(goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.phi)
              end,
              case nv.ma_nt when 'VND' then nv.thue
                 else ftt_vnd_qd(goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.thue)
              end,
              nv.phi, nv.thue, nv.so_id_xl, goc.ma_dvi
         from bh_hd_goc goc, bh_hd_goc_cl nv
        where 
              --nv.ma_dvi like b_ma_dvi||'%' and  PKH_SO_CDT
              nv.ma_dvi = b_ma_dvi and
              nv.ngay_ht between b_ngayd AND b_ngayc
              and goc.ma_dvi = nv.ma_dvi and goc.so_id = nv.so_id
              and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=goc.ma_dvi and so_id=goc.so_id_d) not in ('V', 'N')
              and goc.ttrang = 'D';

--DQD rao cho bc quan tri dung
    insert into TEMP_BC_BH_DTPS_MM
       select goc.ma_dvi, goc.so_hd, goc.nv, goc.kieu_hd, goc.ma_kh, goc.ma_gt, goc.cb_ql, goc.phong, goc.kieu_kt,
              goc.ma_kt, PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(goc.ngay_kt), nv.ma_nt, nv.lh_nv, goc.so_id, goc.ngay_ht, c.n2,
              - (case nv.ma_nt when 'VND' then nv.phi
                    else FTT_VND_QD(goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.phi)
                 end),
              - (case nv.ma_nt when 'VND' then nv.thue
                    else FTT_VND_QD(goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.thue)
                 end),
              -nv.phi, -nv.thue, 0, goc.ma_dvi
         from bh_hd_goc goc, bh_hd_goc_cl nv,
              (select bh_hd_goc_hups.ma_dvi c1, so_id n1, ngay_ht n2
                 from bh_hd_goc_hups
                where tra = 0) c
        where
              --goc.ma_dvi like b_ma_dvi||'%'
              goc.ma_dvi = b_ma_dvi
              and goc.ma_dvi = c.c1 and goc.so_id = c.n1
              and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=goc.ma_dvi and so_id=goc.so_id_d) not in ('V', 'N')
              and goc.ttrang = 'D' and goc.ma_dvi = nv.ma_dvi and goc.so_id = nv.so_id
              and nv.ngay_ht between b_ngayd AND b_ngayc;

