DROP PROCEDURE BC_BH_LAY_BC_BH_DTPS_MNVM;
CREATE OR REPLACE PROCEDURE BC_BH_LAY_BC_BH_DTPS_MNVM
    (b_ma_dvi varchar2, b_ngayd number, b_ngayc number)
AS
begin
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
BC_BH_LAY_BC_BH_DTPS_MM(b_ma_dvi,b_ngayd,b_ngayc);
insert into TEMP_BC_BH_DTPS_MNVM
    SELECT ma_dvi, so_hd, a.nv, kieu_hd, ma_kh, nguon, cb_ql, phong,
        kieu_kt, ma_kt, ngay_hl, ngay_kt, ma_nt, lh_nv, so_id,
        ngay_ht, ngay_htnv, phi, thue, phi_nt, thue_nt, 0, ma_dvig
        FROM TEMP_BC_BH_DTPS_MM a
        WHERE nv IN (SELECT DISTINCT nv FROM temp_bc_nv);
end;
/
DROP PROCEDURE BC_BH_LAY_BC_BH_DTTT_MA_DT;
CREATE OR REPLACE PROCEDURE BC_BH_LAY_BC_BH_DTTT_MA_DT
    (b_ma_dvi varchar2, b_ngayd number, b_ngayc number)
AS
begin
--BCNam: da kiem tra va sua lai ok, ko sua lai
if b_ma_dvi is not null then
    --So thanh toan
    insert into TEMP_BC_BH_DTTT_MA_DT
        SELECT goc.ma_dvi, so_hd, nv, kieu_hd, ma_kh, ma_gt, cb_ql, phong,
            kieu_kt, ma_kt, PKH_SO_DATE(ngay_hl), PKH_SO_DATE(ngay_KT), ma_nt, lh_nv, ma_dt, nv.so_id_tt,
            goc.so_id, ngay, goc.ngay_ht, nv.ngay_tt, nv.ngay_ht, PHI_QD, thue_qd,
           -- goc.so_id, ngay, goc.ngay_ht, nv.ngay_tt, nv.ngay_tt, PHI_QD, thue_qd,
            --FTT_VND_QD (goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.hhong),
            nv.hhong_qd,
            nv.hhong,
            --FTT_VND_QD (goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.htro),
            nv.htro_qd,
            nv.htro, pt, 0, goc.ma_dvi
            FROM bh_hd_goc goc, bh_hd_goc_ttpt nv
            WHERE
            --nv.ma_dvi LIKE b_ma_dvi||'%' AND
            nv.ma_dvi = b_ma_dvi AND
            nv.ngay_ht BETWEEN b_ngayd AND b_ngayc AND nv.pt <> 'C' and nv.so_id_tt<>20190629934688
            AND kieu_hd NOT IN ('V', 'N') and goc.ma_dvi = nv.ma_dvi AND goc.so_id = nv.so_id ;

    --Loai tru cac mon cham dut chua thu tien
    insert into TEMP_BC_BH_DTTT_MA_DT
        SELECT /*+ parallel(4) */ goc.ma_dvi, so_hd, nv, kieu_hd, ma_kh, ma_gt, cb_ql, phong,
            kieu_kt, ma_kt, PKH_SO_DATE(ngay_hl), PKH_SO_DATE(ngay_HL), nv.ma_nt, lh_nv, ma_dt, nv.so_id_tt,
           -- goc.so_id, ngay, goc.ngay_ht, nv.ngay_tt, nv.ngay_tt, -PHI_QD, -thue_qd,
             goc.so_id, ngay, goc.ngay_ht, nv.ngay_tt, nv.ngay_ht, -PHI_QD, -thue_qd,
            -- -FTT_VND_QD (goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.hhong),
            -nv.hhong_qd,
            -nv.hhong,
            -- -FTT_VND_QD (goc.ma_dvi,nv.ngay_ht,nv.ma_nt,nv.htro),
            -nv.htro_qd,
            -nv.htro, pt, 0, goc.ma_dvi
            FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, bh_hd_goc_hups hu
            WHERE
            --nv.ma_dvi LIKE b_ma_dvi||'%' AND
            nv.ma_dvi = b_ma_dvi AND
            nv.ngay_ht BETWEEN b_ngayd AND b_ngayc AND nv.pt <> 'C'
            and hu.ngay_ht BETWEEN b_ngayd AND b_ngayc
            AND goc.ma_dvi = hu.ma_dvi AND goc.so_id = hu.so_id AND nv.ma_nt = hu.ma_nt AND no <> 0
            AND tra = 0 AND kieu_hd NOT IN ('V', 'N') AND nv.phi < 0 AND nv.so_id = so_id_tt and so_id_tt<>20190629934688
            and goc.ma_dvi = nv.ma_dvi AND goc.so_id = nv.so_id ;

    --Giam dong bao hiem
