        select  goc.ma_dvi,so_hd,nv,kieu_hd,ma_kh,ma_gt,cb_ql,goc.phong,kieu_kt,ma_kt,
            --PKH_SO_DATE(ngay_hl), PKH_SO_DATE(ngay_KT),ma_nt,nv.lh_nv,ma_dt,nv.so_id_tt,goc.so_id,ngay,goc.ngay_ht,nv.ngay_tt,nv.ngay_tt,
            PKH_SO_DATE(goc.ngay_hl), PKH_SO_DATE(ngay_KT),ma_nt,nv.lh_nv,ma_dt,nv.so_id_tt,goc.so_id,ngay,goc.ngay_ht,nv.ngay_tt,nv.ngay_ht,
