            FROM bh_hd_goc goc, bh_hd_goc_ttpb nv
            WHERE
            --nv.ma_dvi LIKE b_ma_dvi||'%'
            nv.ma_dvi = b_ma_dvi AND nv.ngay_ht BETWEEN b_ngayd AND b_ngayc
            AND nv.pthuc IN ('D', 'P') AND nv.pt <> 'C'
            AND goc.ma_dvi = nv.dvi_xl AND goc.so_id = nv.so_id;

    insert into TEMP_BC_BH_DTTT_MA_DT
