DROP PROCEDURE BC_BH_LKE_HHHT;

CREATE OR REPLACE PROCEDURE BC_BH_LKE_HHHT
 (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
 B_DLY VARCHAR2,B_PHONG VARCHAR2,
 B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
 B_TEN_DLY OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2)
AS
 B_LOI VARCHAR2(100);B_NGAYDN NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
 B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_DLY IS NOT NULL THEN
 SELECT TEN INTO B_TEN_DLY FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_DLY;
ELSE B_TEN_DLY:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
 SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA;COMMIT;

INSERT INTO TEMP_2(N1,C1,C2,C4,N2,N3)
	SELECT A.SO_ID_HH,PKH_SO_CNG(A.NGAY_HT),A.SO_ID_HH SO_CT,MA_DL,HHONG_QD,THUE_HH_QD
	FROM BH_HD_GOC_HH A,BH_HD_GOC_HH_PT B WHERE A.MA_DVI=B_MA_DVI AND B.MA_DVI=B_MA_DVI
	AND A.SO_ID_HH=B.SO_ID_HH
	AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_DLY IS NULL OR MA_DL=B_DLY);
INSERT INTO KET_QUA(C1,C2,N2,N3) SELECT C1,C2,SUM(N2),SUM(N3) FROM TEMP_2 GROUP BY C1,C2;


UPDATE KET_QUA SET N4=NVL(N2,0)-NVL(N3,0);
DELETE KET_QUA WHERE N2 IS NULL AND N3 IS NULL;
OPEN CS_KQ FOR SELECT ' ' SO_HD,C2 SO_PHIEU ,C1 NGAY,' ' TEN,
	ROUND(NVL(N2,0)) AS HOA_HONG,ROUND(NVL(N3,0)) AS K_TRU,ROUND(NVL(N4,0)) AS THANH_TOAN
	FROM KET_QUA ORDER BY C2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE bc_bh_nguoi_tke_kthac;
CREATE OR REPLACE PROCEDURE BC_BH_NGUOI_TKE_KTHAC
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong_x varchar2,b_ma_nv varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
as
    b_loi varchar2(100);b_ngaydn number;b_i1 number;b_phong varchar2(30):='';
begin
    b_loi:=fht_ma_nsd_ktra(b_madvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise program_error; end if;
    if b_ngayd is null or b_ngayc is null then
        b_loi:='loi:nhap ngay bao cao:loi'; raise program_error;
    end if;
    /*
    if b_ma_nv is null or b_ma_nv not like 'CN%' then
        b_loi:='loi:Loi chon ma nghiep vu can xem:loi';
    end if;
*/
--PBC_QUYEN_XEM_BC(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong_x,'NG',b_phong);
--if b_loi is not null then raise PROGRAM_ERROR; end if;

    --chen danh sach giay chung nhan vao
delete temp_1; delete temp_2; commit;
insert into temp_1(n1,n2,c1,n3,c2,c3,c4,c5,c6,c7,c8,c9,c10,c11,c12,c13,c14,n4,n5,c15,n6,c16,c18)
     select a.so_id, b.so_id_dt,a.ma_dvi,a.ngay_ht, a.so_hd, b.gcn, b.ten, b.dchi, b.gioi, b.ng_sinh,
                   b.cmt,PKH_SO_CNG(b.ngay_cap)ngay_cap,PKH_SO_CNG(b.ngay_hl) ngay_hl,
                   PKH_SO_CNG(b.ngay_kt) ngay_kt, b.mobi,
                   c.lh_nv, a.nt_tien, sum(c.tien), sum(c.pt),a.nt_phi,sum(c.phi),''cb_ql,''loai
                from bh_NG a, bh_ng_ds b, bh_ng_dk c
            where a.so_id = b.so_id and b.so_id = c.so_id and b.so_id_dt = c.so_id_dt
                and (b_ma_nv is null or c.lh_nv like '%'||b_ma_nv||'%')
                and a.ngay_ht between b_ngayd and b_ngayc
                and (b_ma_dvi is null or a.ma_dvi = b_ma_dvi)
                and (b_phong is null or a.phong = b_phong)
                and a.ttrang = 'D' and c.tien > 0 --and a.so_hd='08CN0215001201' and b.so_id_dt=20160203003278
            group by a.so_id, b.so_id_dt, a.ma_dvi, a.ngay_ht, a.so_hd, b.gcn, b.ten, b.dchi, b.gioi, b.ng_sinh,
                   b.cmt, b.ngay_cap, b.ngay_hl, b.ngay_kt,b.mobi,
                   c.lh_nv, a.nt_tien, a.nt_phi;
--   update temp_1 set c17=(select nhom from bh_nguoihd where ma_dvi=c1 and so_id=n1);
   merge into temp_1
   using bh_ng a
   on (ma_dvi=c1 and so_id=n1)
   when matched then update set
   c20=substr(DCHI,0,250);
   --phan tai nan
   --update temp_1 set n7=FBH_HOI_PHI_TNSK(c1,n1,n2,c17,c13,c18,'TN','');
   /*
   update temp_1 set n7=(select sum(b.phi) from bh_nguoihd a, bh_nguoihd_dsdk b
      where c1=a.ma_dvi and a.ma_dvi=b_ma_dvi and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and b.so_id=n1 and b.so_id_dt=n2 and
        nhom in ('CN.01.6.1','CN.01.7.1','CN.01.8.1','CN.10.1','CN.11.1','CN.12.1','CN.01.6','CN.01.7','CN.01.8','CN.10','CN.11','CN.12') and
        lh_nv in ('CN.01.6','CN.01.7','CN.01.8') and loai in ('D','E','F','G','H','I','J'));
   */
   --phan suc khoe -  noi tru
    --update temp_1 set n8=FBH_HOI_PHI_TNSK(c1,n1,n2,c17,c13,c18,'SK','NT');
   /*
   update temp_1 set n8=(select sum(b.phi) from bh_nguoihd a, bh_nguoihd_dsdk b
      where c1=a.ma_dvi and a.ma_dvi=b_ma_dvi and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and b.so_id=n1 and b.so_id_dt=n2 and
        nhom in ('CN.02.1.1','CN.02.2.1','CN.02.3.1','CN.10.1','CN.11.1','CN.12.1','CN.02.1','CN.02.2','CN.02.3','CN.10','CN.11','CN.12') and
        lh_nv in ('CN.02.1') and loai in ('A'));
        */
   --phan suc khoe - ngoai tru
   --update temp_1 set n9=FBH_HOI_PHI_TNSK(c1,n1,n2,c17,c13,c18,'SK','NGT');
   /*
   update temp_1 set n9=(select sum(b.phi) from bh_nguoihd a, bh_nguoihd_dsdk b
      where c1=a.ma_dvi and a.ma_dvi=b_ma_dvi and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and b.so_id=n1 and b.so_id_dt=n2 and
        nhom in ('CN.02.1.1','CN.02.2.1','CN.02.3.1','CN.10.1','CN.11.1','CN.12.1','CN.02.1','CN.02.2','CN.02.3','CN.10','CN.11','CN.12') and
        lh_nv in ('CN.02.2') and loai in ('B'));
        */
   --phan suc khoe - tu vong
   --update temp_1 set n10=FBH_HOI_PHI_TNSK(c1,n1,n2,c17,c13,c18,'SK','TV');
      /*
   update temp_1 set n10=(select sum(b.phi) from bh_nguoihd a, bh_nguoihd_dsdk b
      where c1=a.ma_dvi and a.ma_dvi=b_ma_dvi and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and b.so_id=n1 and b.so_id_dt=n2 and
        nhom in ('CN.02.1.1','CN.02.2.1','CN.02.3.1','CN.10.1','CN.11.1','CN.12.1','CN.02.1','CN.02.2','CN.02.3','CN.10','CN.11','CN.12') and
        lh_nv in ('CN.02.3') and loai in ('C'));
*/

-- update temp_1 set c13=(select ten from bh_ma_lhnv where c1=ma_dvi and c13=ma);
-- merge into temp_1
-- using bh_ma_lhnv
-- on (ma_dvi=c1 and ma=c13)
-- when matched then update 
-- set c13 = ten;
 insert into temp_2(c1,n3,c2,c3,c4,c5,c7,c6,c8,c12,c9,c10,c11,c13,c14,n4,n5,c15,n6,n7,n8,n9,n10,c16,c19,c20)
    select c1,n3,c2,c3,c4,c5,c7,c6,c8,c12,c9,c10,c11,c13,c14,sum(n4),sum(n5),c15,sum(n6),sum(n7),sum(n8),sum(n9),sum(n10),c16,c19,c20
     from temp_1 group by c1,n3,c2,c3,c4,c5,c7,c6,c8,c12,c9,c10,c11,c13,c14,c15,c16,c19,c20 order by c2,c3;
--duchq tra them 2 gia tri 2 cot nt_tien, nt_phi
 open cs_kq for
    select rownum stt,c1 ma_dvi,n3 ngay_ht,c2 so_hd,c3 gcn,c4 ten_khach,c5 dia_chi,c7 ngay_sinh,c6 gioi_tinh,c8 cmt,c12 dien_thoai,
        c9 ngay_cap,c10 ngay_hl,c11 ngay_kt,c13 ten_lhnv,c14 nt_tien,n4 tien_bh,n5 tl_phi,c15 nt_phi,n6 phi,
        n7 phi_tn,c16 cb_ql,c19 tenkh,c20 dchikh
     from temp_2 order by c2,c3;
exception when others then if b_loi is null then raise PROGRAM_ERROR; else  raise_application_error(-20105,b_loi); end if;
end;
/

DROP PROCEDURE BC_BH_NHANH_DT_DLTONG;

CREATE OR REPLACE PROCEDURE BC_BH_NHANH_DT_DLTONG
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DVI VARCHAR2,B_LOAI VARCHAR2,
    B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_NGUON VARCHAR2,
    B_MA_DT VARCHAR2, B_MA_DL VARCHAR2,B_KIEU_KT VARCHAR2,B_TC VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NGAYD1 NUMBER;
    B_MA_VP VARCHAR2(10);B_I1 NUMBER;B_KIEU VARCHAR2(1);B_I2 NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
B_NGAYD1:=PKH_NG_CSO(PKH_SO_CDT(B_NGAYD)-1);
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;

IF B_MA_DL IS NOT NULL THEN
    INSERT INTO TEMP_1 (C1,C2) SELECT DISTINCT MA_DVI,MA FROM BH_DL_MA_KH WHERE (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
        START WITH NVL(MA,' ')=B_MA_DL CONNECT BY PRIOR MA=MA_CT;   
ELSE
    B_LOI:='loi:Nhap ma dai ly tong:loi'; RAISE PROGRAM_ERROR;
END IF;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES (B_MA_DVI||'%',B_NGAYD,B_NGAYC);

INSERT INTO TEMP_2 (C29,C1,C2,C3,C4,C5,C7,N2,N3) 
    SELECT MA_DVI,SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,SUM(PHI),SUM(THUE)
    FROM V_BC_BH_DTPS_MM,TEMP_1 WHERE MA_DVI=C1 AND MA_KT=C2 
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
    AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT) AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
    GROUP BY MA_DVI,SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV;

INSERT INTO TEMP_2 (C29,C1,C2,C3,C4,C5,C7,N6,N7) 
    SELECT MA_DVI,SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,SUM(PHI),SUM(THUE)
    FROM V_BC_BH_DTBH_MM,TEMP_1 WHERE MA_DVI=C1 AND MA_KT=C2
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
    AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT) AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
    GROUP BY MA_DVI,SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV;
--LAM SACH
-- INSERT INTO TEMP_2 (C29,C1,C2,C3,C4,C5,C7,N10,N11) 
--     SELECT MA_DVI,SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV,SUM(PHI),SUM(THUE)
--     FROM V_BC_BH_DTTT_MM,TEMP_1 WHERE MA_DVI=C1 AND MA_KT=C2
--         AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
--     AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
--     AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT) AND (TRIM(B_NGUON) IS NULL OR TRIM(NGUON) LIKE B_NGUON||'%')
--     GROUP BY MA_DVI,SO_HD,MA_KH,CB_QL,PHONG,MA_KT,LH_NV;

IF B_LOAI_KH IS NOT NULL THEN
    UPDATE TEMP_2 SET C6=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_2.C29 AND MA=TEMP_2.C2);
    DELETE TEMP_2 WHERE  C6  NOT LIKE B_LOAI_KH||'%' OR C6 IS NULL;
END IF;
IF B_TC='0' THEN 
    INSERT INTO KET_QUA(C29,C7,C17,C4,C6,C20) SELECT '',MA,TEN,B_PHONG,B_LOAI_KH,'T' 
        FROM BH_MA_LHNV WHERE MA_DVI = B_MADVI AND TC='T' AND (B_MA_NV IS NULL OR MA LIKE B_MA_NV||'%') ;
    UPDATE KET_QUA KQ SET 
        N1=(SELECT SUM(NVL(N1,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N2=(SELECT SUM(NVL(N2,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N3=(SELECT SUM(NVL(N3,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N4=(SELECT SUM(NVL(N4,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N5=(SELECT SUM(NVL(N5,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N6=(SELECT SUM(NVL(N6,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N7=(SELECT SUM(NVL(N7,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N8=(SELECT SUM(NVL(N8,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N9=(SELECT SUM(NVL(N9,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N10=(SELECT SUM(NVL(N10,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N11=(SELECT SUM(NVL(N11,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N12=(SELECT SUM(NVL(N12,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%'),
        N13=(SELECT SUM(NVL(N13,0)) FROM TEMP_2 T WHERE T.C7 LIKE TRIM(KQ.C7)||'%');
    INSERT INTO KET_QUA(C20,C29,C1,C2,C3,C4,C5,C6,C7,N1,N2,N3,N4,N5,N6,N7,N8,N9,N10,N11,N12,N13)
        SELECT 'C','','','','','','','',C7,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),
        SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N9,0)),SUM(NVL(N10,0)),SUM(NVL(N11,0)),
        SUM(NVL(N12,0)),SUM(NVL(N13,0)) FROM TEMP_2 GROUP BY C7;
    UPDATE KET_QUA SET C17=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MADVI AND MA=KET_QUA.C7);
    
    UPDATE KET_QUA SET N30=1 WHERE C7 LIKE 'XG%';
    UPDATE KET_QUA SET N30=2 WHERE C7 LIKE 'CN%';
    UPDATE KET_QUA SET N30=3 WHERE C7 LIKE 'HH%';
    UPDATE KET_QUA SET N30=4 WHERE C7 LIKE 'TT%';
    UPDATE KET_QUA SET N30=5 WHERE C7 LIKE 'HH%';
    UPDATE KET_QUA SET N30=6 WHERE C7 LIKE 'TS%';
    UPDATE KET_QUA SET N30=7 WHERE C7 LIKE 'HP%';
    UPDATE KET_QUA SET N30=8 WHERE C7 LIKE 'TN%';
ELSIF B_TC='1' OR B_TC='2' THEN
    SELECT MA INTO B_MA_VP FROM HT_MA_DVI WHERE CAP=1;
    INSERT INTO KET_QUA(C20,C29,C1,C2,C3,C4,C5,C6,C7,N1,N2,N3,N4,N5,N6,N7,N8,N9,N10,N11,N12,N13) 
        SELECT 'T',C29,'','','','',C5,'',SUBSTR(C7,1,2),SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),
        SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N9,0)),SUM(NVL(N10,0)),SUM(NVL(N11,0)),
        SUM(NVL(N12,0)),SUM(NVL(N13,0)) FROM TEMP_2 GROUP BY C29,C5,C6,SUBSTR(C7,1,2);
    UPDATE KET_QUA SET C17=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C7);
    
    UPDATE KET_QUA SET N30=1 WHERE C7 LIKE 'XG%';
    UPDATE KET_QUA SET N30=2 WHERE C7 LIKE 'CN%';
    UPDATE KET_QUA SET N30=3 WHERE C7 LIKE 'HH%';
    UPDATE KET_QUA SET N30=4 WHERE C7 LIKE 'TT%';
    UPDATE KET_QUA SET N30=5 WHERE C7 LIKE 'HH%';
    UPDATE KET_QUA SET N30=6 WHERE C7 LIKE 'TS%';
    UPDATE KET_QUA SET N30=7 WHERE C7 LIKE 'HP%';
    UPDATE KET_QUA SET N30=8 WHERE C7 LIKE 'TN%';
    UPDATE KET_QUA SET C15=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C5);
    UPDATE KET_QUA SET C30=(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C29);    
END IF;
COMMIT;
DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N6,0)=0 AND NVL(N10,0)=0;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    
    OPEN CS_KQ FOR SELECT C20 TC,C29 MA_DVI,C30 TEN_DVI,C1 SO_HD,C2 MA_KH, C12 TEN_KH,C3 CB_QL, C13 TEN_CBQL,C4 PHONG,C14 TEN_PHONG, 
        C5 MA_DL, C15 TEN_DL,C6 LOAI_KH,C16 TEN_LOAI,C7 LH_NV,C17 TEN_LHNV,N1 KE_HOACH,
        N2 PHI_PS,N3 THUE_PS,N4+N2 PHI_PS_LK,N5+N3 THUE_S_LK,N6 PHI_BH,N7 THUE_BH,N8+N6 PHI_BH_LK,
        N9+N7 THUE_BH_LK,N10 PHI_TT,N11 THUE_TT,N12+N10 PHI_TT_LK,N13+N11 THUE_TT_LK FROM KET_QUA ORDER BY N30,C7;
ELSE
    
    OPEN CS_KQ FOR SELECT C20 TC,C29 MA_DVI,C30 TEN_DVI,C1 SO_HD,C2 MA_KH, C12 TEN_KH,C3 CB_QL, C13 TEN_CBQL,C4 PHONG,C14 TEN_PHONG, 
        C5 MA_DL, C15 TEN_DL,C6 LOAI_KH,C16 TEN_LOAI,C7 LH_NV,C17 TEN_LHNV,N1 KE_HOACH,
        N2 PHI_PS,N3 THUE_PS,N4+N2 PHI_PS_LK,N5+N3 THUE_S_LK,N6 PHI_BH,N7 THUE_BH,N8+N6 PHI_BH_LK,
        N9+N7 THUE_BH_LK,N10 PHI_TT,N11 THUE_TT,N12+N10 PHI_TT_LK,N13+N11 THUE_TT_LK FROM KET_QUA,TEMP_BC_DVI WHERE C29=DVI ORDER BY N30,C7;
END IF;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;

/
DROP PROCEDURE BC_BH_TB_TP;
-- chuclh: lay them cot ten can bo
CREATE OR REPLACE PROCEDURE BC_BH_TB_TP
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_phong varchar2,b_ma_kh varchar2,
    b_tc varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);
Begin
--BCNam Thong ke hop dong den han thanh toan phat sinh tu ngay_d den ngay_c bao cao
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
--cho nhung hop dong da phat hanh hoa don chua thu phi den hien tai
if b_tc is null or b_tc ='C'  then
    insert into temp_2(n1,c1,n2) select so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_no
        where ma_dvi=b_ma_dvi  group by so_id,ma_nt;
    insert into temp_3(n1,n2,n3) select a.so_id,a.no_qd,a.ton_qd from bh_hd_goc_sc_no a,temp_2 b
        where a.ma_dvi=b_ma_dvi and a.so_id=b.n1 and a.ma_nt=b.c1 and a.ngay_ht=b.n2;
end if;
--cho nhung hop dong chua phat hanh hoa don chua thu phi den hien tai
if b_tc is null or b_tc ='K'  then
    delete temp_2;commit;
    insert into temp_2(n1,c1,n2) select so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_phi
        where ma_dvi=b_ma_dvi group by so_id,ma_nt;
    insert into temp_3(n1,n2,n3,c1,c2,n6) select a.so_id,FTT_VND_QD(a.ma_dvi,a.ngay_ht,a.ma_nt,a.no),
        FTT_VND_QD(a.ma_dvi,a.ngay_ht,a.ma_nt,a.ton),a.ma_nt,a.ma_dvi,a.ngay_ht
        from bh_hd_goc_sc_phi a,temp_2 b where a.ma_dvi=b_ma_dvi and a.so_id=b.n1 and a.ma_nt=b.c1 and a.ngay_ht=b.n2;
end if;

insert into temp_1(c1,c2,n1,n2,n3) select goc.so_hd,goc.ten,goc.ngay_ht,sum(ph.n2),sum(ph.n3)
        from bh_hd_goc goc,temp_3 ph where goc.ma_dvi=b_ma_dvi and goc.so_id=ph.n1 and goc.ngay_ht between b_ngayd and b_ngayc
        and (b_phong is null or goc.phong=b_phong)  and (b_ma_kh is null or goc.ma_kh=b_ma_kh)
        group by goc.so_hd,goc.ten,goc.ngay_ht;

delete temp_1 where nvl(n3,0)=0;
insert into ket_qua(c1,c2,n1,n2,n3) select c1,c2,n1,sum(n2),sum(n3) from temp_1 group by c1,c2,n1;
update ket_qua set (c3,c4)=(select t1.ten,PKH_CNG_SO(ngay_hl) from
    bh_hd_goc t,ht_ma_nsd t1 where t.ma_dvi=b_ma_dvi and t.so_hd=c1 and t.nsd=t1.ma);
commit;
open cs_kq for select c1 so_hd,c2 as ten_kh,PKH_SO_CNG(n1) ngay_ht,c4 ngay_hl,n3 phi,c3 ma_cb
    from ket_qua order by c1;
exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP FUNCTION BCNAM_MA_CB_TEN;

CREATE OR REPLACE FUNCTION BCNAM_MA_CB_TEN
(
    b_ma_dvi nvarchar2,b_ma nvarchar2
)return nvarchar2
AS
    b_giatri_ra nvarchar2(50);
BEGIN
    b_giatri_ra:='';

    select min(ten) into b_giatri_ra from ht_ma_cb where ma_dvi=b_ma_dvi and ma=b_ma;

    return b_giatri_ra;
END;
/

DROP PROCEDURE BC_BH_TB_TT;
CREATE OR REPLACE PROCEDURE BC_BH_TB_TT
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2, B_PAS VARCHAR2,B_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_KH VARCHAR2,
    B_LOAI_KH VARCHAR2,B_MA_NV VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);
BEGIN
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

--    DELETE TEMP_1;COMMIT;
    execute immediate 'truncate table temp_1';
    INSERT INTO TEMP_1(C20, C21, C1,C2,C3,C4,N2,c7,c19)
        SELECT A.MA_DVI, A.PHONG, SO_HD,MA_KH,PKH_SO_CNG(A.NGAY_HT),PKH_SO_CNG(NGAY_KT),SUM(FTT_VND_QD(A.MA_DVI,A.NGAY_HT,MA_NT,TTOAN)),
            a.cb_ql,a.ma_dvi
        FROM BH_HD_GOC A, BH_HD_GOC_PT B WHERE A.KIEU_HD NOT IN ('V','N') AND A.MA_DVI LIKE B_DVI||'%'
        AND A.SO_ID=B.SO_ID AND A.MA_DVI=B.MA_DVI
        AND NGAY_KT BETWEEN B_NGAYD AND B_NGAYC
        AND (B_PHONG IS NULL OR PHONG=B_PHONG)  AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH) AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
        AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
        GROUP BY A.MA_DVI,A.PHONG,SO_HD,MA_KH,A.NGAY_HT,NGAY_KT,a.cb_ql,a.ma_dvi;

--    UPDATE TEMP_1 SET (C5,C6,C10, C11)=(SELECT TEN, DCHI,LOAI, PHONE FROM
--        BH_HD_MA_KH WHERE MA_DVI=C20 AND MA=C2);
    merge into TEMP_1 using BH_HD_MA_KH on (MA_DVI=C20 AND MA=C2) when matched then update set c5=ten,c6=dchi,c10=loai,c11=mobi;
 
    UPDATE TEMP_1 SET C21=(SELECT C21||' - '||TEN FROM HT_MA_PHONG WHERE MA_DVI=C20 AND MA=C21);
--    merge into TEMP_1 using HT_MA_PHONG on ( MA=C21) when matched then update set c21=TEN;
    
    UPDATE TEMP_1 SET C20=(SELECT C20||' - '||TEN FROM HT_MA_DVI WHERE MA=C20);
--    merge into TEMP_1 using HT_MA_DVI on ( MA=C20) when matched then update set C20=C20||' - '||TEN;

    OPEN CS_KQ FOR SELECT c19 ma_dvi, C1 SO_HD,C2 MA_KH, C5 TEN_KH,C6 DCHI_KH,C11 SO_DT, C3 NGAY_HT,C4 NGAY_HL,N2 PHI,
        C20 MA_DVI, C21 PHONG, c7 ma_cb, BCNAM_MA_CB_TEN(c19,c7) ten_cb FROM TEMP_1
        WHERE (B_LOAI_KH IS NULL OR  C10 LIKE B_LOAI_KH||'%') ORDER BY NGAY_HL;

--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_TB_TTXE;

CREATE OR REPLACE PROCEDURE BC_BH_TB_TTXE
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_dvi varchar2,b_phong varchar2,b_ma_kh varchar2,
    b_loai_kh varchar2,b_ma_nv varchar2,b_ma_cb varchar2,b_ma_dl varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);
Begin
--BCNam: Thong bao tai tuc cho nhung hop dong qua 15 ngay chua thanh toan

b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;--BCNam
delete temp_16;commit;

insert into temp_16(c1, c2, c3, c14, n1, n2, c4, c5, c6, c7, c8, c9, c10, c11, c12, c13, n3,c16,c19,c40,c22)
    select  b.ma_dvi, b.phong, b.ma_kh, b.so_hd,a.so_id, a.so_id_dt, a.gcn, b.ten, b.dchi, a.md_sd,
            a.loai_xe, a.bien_xe, a.hieu, ttai||'/'||so_cn, a.nam_sx,
            PKH_SO_CNG(a.ngay_kt), sum(c.phi),b.ma_cb,b.ma_dvi,'XE',b.mobi
            from bh_xe_ds a, bh_xe b, bh_xe_dk c
            where a.so_id=b.so_id and a.ma_dvi=b.ma_dvi and a.so_id=c.so_id and a.so_id_dt=c.so_id_dt
            and b.kieu_hd in ('G','T') and a.ngay_kt between b_ngayd and b_ngayc
            and b.ma_dvi like b_ma_dvi||'%'
            and (b_phong is null or b.phong=b_phong) and (b_ma_kh is null or b.ma_kh=b_ma_kh) and (b_ma_nv is null or c.lh_nv like b_ma_nv||'%')
            and (b_ma_dl is null or b.ma_kt=b_ma_dl)
            group by b.ma_dvi, b.phong, b.ma_kh, b.so_hd,a.so_id, a.so_id_dt, a.gcn, b.ten, b.dchi, a.md_sd,
            a.loai_xe, a.bien_xe, a.hieu, ttai||'/'||so_cn, a.nam_sx,
            PKH_SO_CNG(a.ngay_kt),b.ma_cb,b.ma_dvi,b.mobi;
--update temp_16 set c22= (select max(nd) from bh_kh_ttt_ct where so_id=n1 and ma_dvi=c1 and ma='MOBI_MUA') where c40='XE';
--update temp_16 set c22 = (select * from bh_xegcn
--insert into temp_16(c1, c2, c3, c14, n1, n2, c4, c5, c6, c7, c8, c9, c10, c11, c12, c13, n3,c16,c19,c40)
--    select  a.ma_dvi, a.phong, a.ma_kh, a.so_hd, a.so_id, 0, a.so_hd, a.ten, a.dchi, a.md_sd,
--            a.loai_xe, a.bien_xe, a.hieu_xe, ttai||'/'||so_cn, a.nam_sx,
--            PKH_SO_CNG(a.ngay_kt), sum(b.phi),a.cb_ql,a.ma_dvi,'XEL'
--            from bh_xelgcn a, bh_xelgcn_dk b
--            where a.so_id=b.so_id and a.ma_dvi=b.ma_dvi
--            and a.kieu_hd in ('G','T') and a.ngay_kt between b_ngayd and b_ngayc
--            and a.ma_dvi like b_ma_dvi||'%'
--            and (b_phong is null or a.phong=b_phong) and (b_ma_kh is null or a.ma_kh=b_ma_kh) and (b_ma_nv is null or b.lh_nv like b_ma_nv||'%')
--            and (b_ma_dl is null or a.ma_kt=b_ma_dl)
--            group by a.ma_dvi, a.phong, a.ma_kh, a.so_hd,a.so_id, a.so_hd, a.ten, a.dchi, a.md_sd,
--            a.loai_xe, a.bien_xe, a.hieu_xe, ttai||'/'||so_cn, a.nam_sx,
--            to_char(a.ngay_kt,'dd/MM/yyyy'),a.cb_ql,a.ma_dvi;
--update temp_16 set c22 = (select max(mobi) from bh_xelgcn where ma_dvi=c1 and so_id=n1 and ttrang='D') where c40='XEL';

update temp_16 set (c15,c17)=(Select mobi,loai from bh_hd_ma_kh where ma_dvi=c1 and ma=c3);
/*update
    (select temp_16.c15 temp_1_c15, temp_16.c15 temp_1_c17, bh_hd_ma_kh.phone bh_hd_ma_kh_phone, bh_hd_ma_kh.ma_kh bh_hd_ma_kh_ma_kh
        from temp_16, bh_hd_ma_kh
        where temp_16.c1 = bh_hd_ma_kh.ma_dvi and temp_16.c3 = bh_hd_ma_kh.ma)
    set temp_1_c15 = bh_hd_ma_kh_phone, temp_1_c17 = bh_hd_ma_kh_ma_kh;
*/
update temp_16 set c21=(Select c2||' - '||ten from ht_ma_phong where ma_dvi=c1 and ma=c2);
update temp_16 set c20=(Select c1||' - '||ten from ht_ma_dvi where ma=c1);
commit;
open cs_kq for
    select  c21 phong, c20 ma_dvi, c14 so_hd, c3 ma_kh, c15 SO_DT,c22 mobi_xel, c4 gcn,
            c5 ten_kh, c6 dchi_kh, c7 md_sd,  c9 bien_xe,
            c10 loai_xe, c11 so_cho, c12 nam_sx, c13 ngay_hl, n3 phi, c16 ma_cb,
            BCNAM_MA_CB_TEN(c19,c16) ten_cb,c17 loai_kh
    from temp_16;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_TB_TT_MAIL;

CREATE OR REPLACE PROCEDURE BC_BH_TB_TT_MAIL
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2, B_PAS VARCHAR2,B_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_KH VARCHAR2,
    B_LOAI_KH VARCHAR2,B_MA_NV VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);
BEGIN
--    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
--    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

--    DELETE TEMP_1;COMMIT;
    execute immediate 'truncate table temp_1';
    INSERT INTO TEMP_1(C20, C21, C1,C2,C3,C4,N2,c7,c19)
        SELECT A.MA_DVI, A.PHONG, SO_HD,MA_KH,PKH_SO_CNG(A.NGAY_HT),PKH_SO_CNG(NGAY_KT),SUM(FTT_VND_QD(A.MA_DVI,A.NGAY_HT,MA_NT,TTOAN)),
            a.cb_ql,a.ma_dvi
        FROM BH_HD_GOC A, BH_HD_GOC_PT B WHERE A.KIEU_HD NOT IN ('V','N') AND A.MA_DVI LIKE B_DVI||'%'
        AND A.SO_ID=B.SO_ID AND A.MA_DVI=B.MA_DVI
        AND NGAY_KT BETWEEN B_NGAYD AND B_NGAYC
        AND (B_PHONG IS NULL OR PHONG=B_PHONG)  AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH) AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
        AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
        GROUP BY A.MA_DVI,A.PHONG,SO_HD,MA_KH,A.NGAY_HT,NGAY_KT,a.cb_ql,a.ma_dvi;

--    UPDATE TEMP_1 SET (C5,C6,C10, C11)=(SELECT TEN, DCHI,LOAI, PHONE FROM
--        BH_HD_MA_KH WHERE MA_DVI=C20 AND MA=C2);
    merge into TEMP_1 using BH_HD_MA_KH on (MA_DVI=C20 AND MA=C2) when matched then update set c5=ten,c6=dchi,c10=loai,c11=mobi;
 
    UPDATE TEMP_1 SET C21=(SELECT C21||' - '||TEN FROM HT_MA_PHONG WHERE MA_DVI=C20 AND MA=C21);
--    merge into TEMP_1 using HT_MA_PHONG on ( MA=C21) when matched then update set c21=TEN;
    
    UPDATE TEMP_1 SET C20=(SELECT C20||' - '||TEN FROM HT_MA_DVI WHERE MA=C20);
--    merge into TEMP_1 using HT_MA_DVI on ( MA=C20) when matched then update set C20=C20||' - '||TEN;

    OPEN CS_KQ FOR SELECT c19 ma_dvi, C1 SO_HD,C2 MA_KH, C5 TEN_KH,C6 DCHI_KH,C11 SO_DT, C3 NGAY_HT,C4 NGAY_HL,N2 PHI,
        C20 MA_DVI, C21 PHONG, c7 ma_cb, BCNAM_MA_CB_TEN(c19,c7) ten_cb FROM TEMP_1
        WHERE (B_LOAI_KH IS NULL OR  C10 LIKE B_LOAI_KH||'%') ORDER BY NGAY_HL;

--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_THBT_MD;

CREATE OR REPLACE PROCEDURE BC_BH_THBT_MD
    (B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_N_DUYET VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2,B_BT VARCHAR2:='')
AS
    B_DATE_D DATE; B_DATE_C DATE;
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;COMMIT;
--B_DATE_D := PKH_SO_CDT(B_NGAYD);
--B_DATE_C := TO_DATE(PKH_SO_CNG(B_NGAYC) || ' 11:59:59 PM','dd/mm/yyyy HH:MI:SS AM');
IF B_BT='B' THEN
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,
    C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22,C20) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),
        PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        '' MA_NN,'' MA_MD,'' QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,(BT.NGAY_QD),SO_ID_HD,TIEN_BH,
        PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR,'T'
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE
        
        BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC
        AND BT.NGAY_QD<30000101 
        AND BT.MA_DVI=BT.MA_DVI_QL AND (B_MA_DVI IS NULL OR BT.MA_DVI_QL=B_MA_DVI) 
        AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
        AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%');   
        

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,
    C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22,C20) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),
        PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        '' MA_NN,'' MA_MD,'' QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,(BT.NGAY_QD),SO_ID_HD,TIEN_BH,
        PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR,'K'
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE 
        BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC
        AND BT.NGAY_QD<30000101
        AND BT.MA_DVI=BT.MA_DVI_XL AND BT.MA_DVI<> BT.MA_DVI_QL
        AND (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI)
        AND BT.MA_DVI IN (SELECT MA_DVI FROM BH_BT_HS_PB WHERE SO_ID=BT.SO_ID)
        AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
        AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%');
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,
    C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22,C20) 
    SELECT PB.MA_DVI,NV,SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),
        PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        '' MA_NN,'' MA_MD,'' QUY_LOI,'',NV.MA_NT,NV.LH_NV,BT.SO_ID,(BT.NGAY_QD),BT.SO_ID_HD,TIEN_BH,
        PT_BT,T_THAT,'' K_TRU,PB.TIEN,PB.TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR,'C'
    FROM BH_BT_HS_PB PB,BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE 
        BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC
        AND BT.NGAY_QD<30000101
        AND PB.DVI_XL=BT.MA_DVI_XL AND PB.SO_ID=BT.SO_ID AND PB.SO_ID=NV.SO_ID AND PB.DVI_XL=NV.MA_DVI
        AND PB.MA_DVI<>PB.DVI_XL 
        AND (B_MA_DVI IS NULL OR PB.MA_DVI=B_MA_DVI)
        AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%');

UPDATE TEMP_1 SET N7=ROUND(N7*(100- NVL((SELECT PT FROM BH_HD_DO_TL WHERE MA_DVI=C29 AND SO_ID=N13 AND PTHUC='D' AND ROWNUM=1),0))/100) WHERE C20='T';
UPDATE TEMP_1 SET N7=ROUND(N7*NVL((SELECT PT/100 FROM BH_HD_DO_TL WHERE NHA_BH=C29 AND SO_ID=N13  AND PTHUC='D' AND ROWNUM=1),1)) WHERE C20='K';
ELSIF  B_BT='B1' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22) 
    SELECT BT.MA_DVI_XL,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    '' MA_NN,'' MA_MD,'' QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,(BT.NGAY_QD),SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE 
    (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI) 
    AND (BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC)
    AND BT.NGAY_QD<30000101
    AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%');
ELSIF  B_BT='H1' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    '' MA_NN,'' MA_MD,'' QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,(BT.NGAY_QD),SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE 
    (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) 
    AND BT.NGAY_QD<30000101
    AND ((BT.NGAY_QD) BETWEEN B_NGAYD AND B_NGAYC)    
    AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>MA_DVI_XL
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
ELSIF  B_BT='H2' THEN

INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22) 
    SELECT BT.MA_DVI_XL,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    '' MA_NN,'' MA_MD,'' QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,(BT.NGAY_QD),SO_ID_HD,TIEN_BH,PT_BT,T_THAT,'' K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>MA_DVI_XL
    AND (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI) 

        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET)
    AND ((BT.NGAY_QD) BETWEEN B_NGAYD AND B_NGAYC)    
    AND BT.NGAY_QD<30000101

    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
ELSE
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N8,N14,c22) 
    SELECT BT.MA_DVI,NV,SO_HS,'',PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    ''MA_NN,''MA_MD,''QUY_LOI,'',MA_NT,LH_NV,BT.SO_ID,(BT.NGAY_QD),SO_ID_HD,TIEN_BH,PT_BT,T_THAT,''K_TRU,TIEN,TIEN_QD,BT.SO_ID_DT,BT.NGAY_HT,NGAY_XR
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) 

        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET)
    AND ((BT.NGAY_QD) BETWEEN B_NGAYD AND B_NGAYC)    
    AND BT.NGAY_QD<30000101

    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
END IF;

DELETE TEMP_1 WHERE N7=0;
update temp_1 set (c6,c4,c5,n11,c23)=(select phong,so_hd,ma_kh,ngay_ht,kieu_hd from bh_hd_goc
    where ma_dvi=temp_1.c29 and so_id=temp_1.n13);
/*
UPDATE 
       (SELECT TEMP_1.C6 TEMP_1_C6, TEMP_1.C4 TEMP_1_C4, TEMP_1.C5 TEMP_1_C5, TEMP_1.N11 TEMP_1_N11, TEMP_1.c22 TEMP_1_C21, 
       BH_HD_GOC.PHONG BH_HD_GOC_PHONG,BH_HD_GOC.SO_HD BH_HD_GOC_SO_HD,
       BH_HD_GOC.MA_KH BH_HD_GOC_MA_KH,BH_HD_GOC.NGAY_HT BH_HD_GOC_NGAY_HT,BH_HD_GOC.KIEU_HD BH_HD_GOC_KIEU_HD
              FROM TEMP_1, BH_HD_GOC 
             WHERE TEMP_1.C29 = BH_HD_GOC.MA_DVI AND TEMP_1.N13 = BH_HD_GOC.SO_ID)
       SET TEMP_1_C6 = BH_HD_GOC_PHONG, TEMP_1_C4 = BH_HD_GOC_SO_HD, TEMP_1_C5 = BH_HD_GOC_MA_KH, 
            TEMP_1_N11 = BH_HD_GOC_NGAY_HT, TEMP_1_C21 = BH_HD_GOC_KIEU_HD;
*/
         
DELETE TEMP_1 WHERE NVL(c23,'G')='V';
IF B_PHONG IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;
UPDATE 
    (SELECT TEMP_1.C16 TEMP_1_C16, BH_HD_MA_KH.LOAI BH_HD_MA_KH_LOAI 
        FROM TEMP_1, BH_HD_MA_KH 
        WHERE TEMP_1.C29 = BH_HD_MA_KH.MA_DVI AND TEMP_1.C5 = BH_HD_MA_KH.MA)
        SET TEMP_1_C16 = BH_HD_MA_KH_LOAI;

IF B_MA_KH IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C5<>B_MA_KH;
END IF;
IF B_LOAI_KH IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C16<>B_LOAI_KH;
END IF;
update temp_1 set c30=BC_HOI_LOAIXE(c29,c1,n13,n8,c18);
B_LOI:='';
--EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_THBT_MD_CD;

CREATE OR REPLACE PROCEDURE BC_BH_THBT_MD_CD
    (B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_N_DUYET VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2,B_BT VARCHAR2:='')
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;
DELETE TEMP_3;COMMIT;
INSERT INTO TEMP_3(C1,N1,N2)
    SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
        WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID;
IF B_BT='B' THEN
    if b_ma_dvi is not null then
        INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,C4,C5,N11,C21,C22)
        SELECT BT.MA_DVI,BT.NV,BT.SO_HS,'',GOC.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),
            '' KVUC,BT.N_TRINH,BT.N_DUYET,PKH_SO_CNG(BT.NGAY_QD),''MA_NN,''MA_MD,''QUY_LOI,'',
            NV.MA_NT,'',BT.NGAY_HT,NV.SO_ID_HD,BT.SO_ID,0,NV.CHI_QD,NV.CON_QD,NV.TIEN_QD,
            CASE MA_NT WHEN 'VND' THEN nv.TIEN ELSE FBH_TT_VND_QD(BT.NGAY_HT,MA_NT,nv.TIEN) END,NGAY_XR,BT.SO_HD,GOC.MA_KH,GOC.NGAY_HT,GOC.KIEU_HD,BT.NT_TIEN
        FROM BH_BT_HS BT 
        JOIN BH_BT_HS_DP NV ON BT.SO_ID = NV.SO_ID and BT.MA_DVI=NV.MA_DVI and BT.MA_DVI=NV.MA_DVI_QL
        JOIN TEMP_3 DP ON BT.MA_DVI=DP.C1 AND BT.SO_ID=DP.N1 AND NV.NGAY_DP=DP.N2 
        JOIN BH_HD_GOC GOC ON BT.SO_ID_HD = GOC.SO_ID AND BT.MA_DVI=GOC.MA_DVI
        WHERE 
        (BT.ngay_ht BETWEEN b_ngayd AND b_ngayc) AND
        (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) and BT.NGAY_QD>B_NGAYC and 
        (B_MA_KH IS NULL OR GOC.MA_KH=B_MA_KH) AND 
        (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET) order by BT.so_hs,BT.ngay_xr;
   else
        INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,c22,C4,C5,N11,C21)
            SELECT DISTINCT BT.MA_DVI,BT.NV,BT.SO_HS,'',GOC.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),
            '' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
            ''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,'',BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,
            CASE MA_NT WHEN 'VND' THEN NV.TIEN ELSE FTT_VND_QD(BT.MA_DVI,BT.NGAY_HT,MA_NT,NV.TIEN) END,NGAY_XR,
            GOC.SO_HD,GOC.MA_KH,GOC.NGAY_HT,GOC.KIEU_HD
            FROM BH_BT_HS BT,BH_BT_HS_DP NV,TEMP_3 DP,
            BH_HD_GOC GOC
            WHERE 
            (BT.ngay_ht BETWEEN b_ngayd AND b_ngayc) AND
            (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) and 
            BT.NGAY_QD>B_NGAYC and 
            BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI=NV.MA_DVI_QL
            AND BT.MA_DVI=DP.C1 AND BT.SO_ID=DP.N1 AND NV.NGAY_DP=DP.N2
            AND BT.MA_DVI=GOC.MA_DVI AND BT.SO_ID_HD=GOC.SO_ID
            AND (B_MA_KH IS NULL OR GOC.MA_KH=B_MA_KH)
            AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
   end if;     
ELSIF B_BT='B1' THEN
    INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,c22)
    SELECT BT.MA_DVI,BT.NV,BT.SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
    ''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,'',BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,
    CASE MA_NT WHEN 'VND' THEN TIEN ELSE FTT_VND_QD(BT.MA_DVI,BT.NGAY_HT,MA_NT,TIEN) END,NGAY_XR
    FROM BH_BT_HS BT,BH_BT_HS_DP NV ,(SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
    WHERE  ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID) DP
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID 
    AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
    AND (B_MA_DVI IS NULL OR BT.MA_DVI_XL = B_MA_DVI) 
    AND  NGAY_QD>B_NGAYC
    AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI)    
    AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
ELSIF B_BT='H1' THEN
    INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,c22) 
        SELECT BT.MA_DVI_QL,BT.NV,BT.SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),
        '' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        ''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,'',BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,
        CASE MA_NT WHEN 'VND' THEN TIEN ELSE FTT_VND_QD(BT.MA_DVI,BT.NGAY_HT,MA_NT,TIEN) END,NGAY_XR
        FROM BH_BT_HS BT,BH_BT_HS_DP NV ,(SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
        WHERE ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID) DP
        WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>NV.MA_DVI_QL
        AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
        AND  NGAY_QD>B_NGAYC
        AND (B_MA_DVI IS NULL OR BT.MA_DVI_QL = B_MA_DVI) 
        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
ELSIF B_BT='H2' THEN
    INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,c22) 
        SELECT BT.MA_DVI_QL,BT.NV,BT.SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),
        '' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
        ''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,'',BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,
        CASE MA_NT WHEN 'VND' THEN TIEN ELSE FTT_VND_QD(BT.MA_DVI,BT.NGAY_HT,MA_NT,TIEN) END,NGAY_XR
        FROM BH_BT_HS BT,BH_BT_HS_DP NV ,(SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
        WHERE ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID) DP
        WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>NV.MA_DVI_QL
        AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
        AND  NGAY_QD>B_NGAYC
        AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI)
        AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
END IF;
IF B_PHONG IS NOT NULL THEN 
    DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;
DELETE TEMP_1 WHERE NVL(C21,'G')='V';
UPDATE TEMP_1 SET N8=(SELECT SO_ID_DT FROM BH_BT_HS_NV WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N10 AND ROWNUM=1);
DELETE TEMP_1 WHERE N6=0;
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_THBT_MD_CDPS;
CREATE OR REPLACE PROCEDURE BC_BH_THBT_MD_CDPS
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_N_DUYET VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2,B_BT VARCHAR2:='')
AS
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';

DELETE TEMP_1;DELETE TEMP_3;COMMIT;
INSERT INTO TEMP_3(C1,N1,N2)
	SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
		WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID;

IF B_BT='B' THEN
--duchq tam bo truong lhnv do khong co trong bang BH_BT_HS
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,N10,N12,N13,N2,N3,N4,N5,N6,N7,C4,C5,N11,C21) 
	SELECT DISTINCT BT.MA_DVI,BT.NV,BT.SO_HS,'',GOC.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),
		'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
		''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,NV.TIEN_QD,
		GOC.SO_HD,GOC.MA_KH,GOC.NGAY_HT,GOC.KIEU_HD
	FROM BH_BT_HS BT,BH_BT_HS_DP NV,TEMP_3 DP,
		BH_HD_GOC GOC
	WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI=BT.MA_DVI_QL
		AND BT.MA_DVI=DP.C1 AND BT.SO_ID=DP.N1 AND NV.NGAY_DP=DP.N2
		AND BT.MA_DVI=GOC.MA_DVI AND BT.SO_ID_HD=GOC.SO_ID
		AND BT.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC		
		AND NGAY_QD>B_NGAYC
		AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI)
		
		AND (B_MA_KH IS NULL OR GOC.MA_KH=B_MA_KH)		
		AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
ELSIF B_BT='H' THEN
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,N10,N12,N13,N2,N3,N4,N5,N6,N7) 
	SELECT BT.MA_DVI,BT.NV,BT.SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
	''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,NV.TIEN_QD
	FROM BH_BT_HS BT,BH_BT_HS_DP NV ,(SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
	WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID) DP
	WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI<>BT.MA_DVI_QL
	AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
	AND BT.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
	AND NGAY_QD>B_NGAYC
	AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI)
	AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);

ELSE
INSERT INTO TEMP_1(C29,C1,C2,C3,C6,C19,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,N10,N12,N13,N2,N3,N4,N5,N6,N7) 
	SELECT BT.MA_DVI,BT.NV,BT.SO_HS,'',BT.PHONG,PKH_SO_CNG(NGAY_GUI),PKH_SO_CNG(NGAY_XR),'' KVUC,N_TRINH,N_DUYET,PKH_SO_CNG(NGAY_QD),
	''MA_NN,''MA_MD,''QUY_LOI,'',NV.MA_NT,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,NV.TIEN_QD
	FROM BH_BT_HS BT,BH_BT_HS_DP NV ,(SELECT MA_DVI,SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP
	WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI) AND ROUND(NGAY_DP,-2)<=ROUND(B_NGAYC,-2) GROUP BY MA_DVI,SO_ID) DP
	WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
	AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
	AND BT.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
	AND NGAY_QD>B_NGAYC
	AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI)
	AND (B_N_DUYET IS NULL OR N_DUYET=B_N_DUYET);
END IF;

UPDATE TEMP_1 SET (C6,C4,C5,N11,C21) =(SELECT PHONG,SO_HD,MA_KH,NGAY_HT,KIEU_HD FROM BH_HD_GOC WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N13 AND ROWNUM=1);
IF B_PHONG IS NOT NULL THEN 
	DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;

DELETE TEMP_1 WHERE NVL(C21,'G')='V';
DELETE TEMP_1 WHERE N6=0;
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_THDTDP;
CREATE OR REPLACE PROCEDURE BC_BH_THDTDP
	(B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
	B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_KIEU_KT VARCHAR2,B_TC VARCHAR2,
	B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
	B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NAM NUMBER;B_NGAYCN NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_NAM:=ROUND(B_NGAYC,-4);
B_NGAYCN:=ROUND(B_NGAYC,-4)+1231;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_6;COMMIT;

INSERT INTO TEMP_1(C29,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,C21,
	C12,C13,C14,C15,C17,C18,N10,N11,N12,N2,N3,N4) 
	SELECT GOC.MA_DVI,'' LH_BH,SO_HD,KIEU_HD,SO_HD,MA_KH,MA_KH,'' MA_CB,CB_QL,PHONG,KIEU_KT,MA_KT,'' KIEU_DL,
	'' GIO_HL,PKH_SO_CNG(NGAY_HL),'' GIO_KT,PKH_SO_CNG(NGAY_KT),MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,
	NV.NGAY_HT,SUM(phi_qd),NGAY_KT-NGAY_HL,NGAY_KT-(B_NGAYC) FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
	WHERE GOC.MA_DVI=NV.MA_DVI
	AND GOC.SO_ID=NV.SO_ID  AND KIEU_HD <>'V' AND PT<>'N'
	AND (NGAY_KT)>B_NGAYC
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL)
	AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	GROUP BY GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,PHONG,KIEU_KT,MA_KT,
	NGAY_HL,NGAY_KT,MA_NT,LH_NV,GOC.SO_ID,GOC.NGAY_HT,NV.NGAY_HT;

INSERT INTO TEMP_1(C29,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,C19,N10,N11,N12,N2,N3,N4) 
	SELECT GOC.MA_DVI,'' LH_BH,SO_HD,KIEU_HD,SO_HD,MA_KH,MA_KH,'' MA_CB,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
	'' GIO_HL,PKH_SO_CNG(NGAY_HL),'' GIO_KT,PKH_SO_CNG(NGAY_KT),
	MA_NT,NV.LH_NV,C.KIEU,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT,
	SUM(DECODE(C.KIEU,'V',phi_qd,-phi_qd)*C.PT/100),NGAY_KT-NGAY_HL,NGAY_KT-(B_NGAYC)
	FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV,TBH_TL C
	WHERE (B_PHONG IS NULL OR GOC.PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	AND GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID  AND NV.SO_ID=C.SO_ID AND NV.LH_NV=C.LH_NV
	AND PTHUC='C' AND NV.PT<>'N' AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND KIEU_HD NOT IN ('V','U','K') 
	AND (NGAY_KT)>B_NGAYC
	GROUP BY GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
	NGAY_HL,NGAY_KT,MA_NT,NV.LH_NV,C.KIEU,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT;
	
INSERT INTO TEMP_6(C1,N1,C3,C4,N2) SELECT MA_DVI,SO_ID,LH_NV,KIEU,SUM(PT) PT FROM TBH_PBO WHERE PTHUC NOT IN ('K','*') GROUP BY MA_DVI,SO_ID,LH_NV,KIEU;
INSERT INTO TEMP_1(C29,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,C12,C13,C14,C15,C17,C18,C19,N10,N11,N12,N2,N3,N4) 
	SELECT GOC.MA_DVI,'' LH_BH,SO_HD,KIEU_HD,SO_HD,MA_KH,MA_KH,'' MA_CB,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
	'' GIO_HL,PKH_SO_CNG(NGAY_HL),'' GIO_KT,PKH_SO_CNG(NGAY_KT),
	MA_NT,NV.LH_NV,C4,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT,
	SUM(DECODE(C4,'V',phi_qd,-phi_qd)*C.N2/100),NGAY_KT-NGAY_HL,NGAY_KT-(B_NGAYC)
	FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV,TEMP_6 C
	WHERE (B_PHONG IS NULL OR GOC.PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH) AND	(NGAY_KT)>B_NGAYC
	AND (B_MA_NV IS NULL OR NV.LH_NV LIKE B_MA_NV||'%') AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB)
	AND (B_MA_DL IS NULL OR MA_KT=B_MA_DL) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
	AND GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID  AND NV.SO_ID=C.N1 AND NV.LH_NV=C.C3
	AND NV.PT<>'N' AND (B_MA_DVI IS NULL OR GOC.MA_DVI = B_MA_DVI)
	AND KIEU_HD NOT IN ('V','U','K') 
	AND (NV.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC)
	GROUP BY GOC.MA_DVI,SO_HD,KIEU_HD,MA_KH,CB_QL,GOC.PHONG,KIEU_KT,MA_KT,
	NGAY_HL,NGAY_KT,MA_NT,NV.LH_NV,C4,GOC.SO_ID,GOC.NGAY_HT,GOC.NGAY_HT;

INSERT INTO KET_QUA(C20,C29,C1,C2,C3,C4,C5,C6,C7,N1,N2,N3,N4,C21) 
	SELECT 'C',C29,C2,C5,C8,C9,C11,C16,C18,SUM(NVL(N1,0)),SUM(NVL(N2,0)),NVL(N3,0),NVL(N4,0),C15
	FROM TEMP_1 GROUP BY C29,C2,C5,C8,C9,C11,C16,C18,N3,N4,C15;

UPDATE KET_QUA SET (c27,C12)=(SELECT loai,TEN FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C2);
UPDATE KET_QUA SET C13=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C3);
UPDATE KET_QUA SET C14=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C4);
UPDATE KET_QUA SET C15=(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C5);
UPDATE KET_QUA SET C16=(SELECT TEN FROM KH_MA_LOAI_DN WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.c27);
UPDATE KET_QUA SET C17=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C7);
UPDATE KET_QUA SET C30=(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C29);

OPEN CS_KQ FOR SELECT C20 TC,C29 MA_DVI,C30 TEN_DVI,C1 SO_HD,C2 MA_KH, C12 TEN_KH,C3 CB_QL, C13 TEN_CBQL,C4 PHONG,C14 TEN_PHONG, 
	C5 MA_DL, C15 TEN_DL,C28 LOAI_KH,C16 TEN_LOAI,C7 LH_NV,C17 TEN_LHNV,
	DECODE(N3,0,N2*N4,N2*N4) PHI_DP,N2 PHI_T,N3  SO_NGAYT,N4 SO_NGAYCL,N21 NGAY_KT FROM KET_QUA ORDER BY N30,C7;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_THDT_PSTRN;

CREATE OR REPLACE PROCEDURE BC_BH_THDT_PSTRN
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI VARCHAR2,B_MA_KH VARCHAR2,B_TIEN NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
    B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2,
    B_TEN_KHACH OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_I1 NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');

IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
    SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MADVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MADVI AND MA=B_LOAI;
ELSE    B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MADVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_KH IS NOT NULL THEN
    SELECT TEN INTO B_TEN_KHACH FROM BH_HD_MA_KH WHERE MA_DVI=B_MADVI AND MA=B_MA_KH;
ELSE B_TEN_KHACH:=' ';
END IF;
DELETE KET_QUA;
COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_DTCPSTN_MDM(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI,B_MA_KH,'','','',0,B_NGAYD,B_NGAYC,B_LOI);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO KET_QUA(C1,C2,C3,C4,N4,N5,N20,c7)
        SELECT C1,C2,C3,C4,SUM(N4),SUM(N5),N20,c10 FROM TEMP_2 GROUP BY C1,C2,C3,C4,N20,c10;
ELSE
    INSERT INTO KET_QUA(C1,C2,C3,C4,N4,N5,N20,c7)
        SELECT C1,C2,C3,C4,SUM(N4),SUM(N5),N20,c10 FROM TEMP_2,TEMP_BC_DVI WHERE C1=DVI GROUP BY C1,C2,C3,C4,N20,c10;
END IF;
--select * from bh_dl_ma_kh
UPDATE KET_QUA SET (C3,C5,C6) =(SELECT TEN,DCHI,MOBI FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C2);
UPDATE KET_QUA SET C10 =(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C1);
DELETE KET_QUA WHERE NVL(N4,0)=0 AND NVL(N5,0)=0;
OPEN CS_KQ FOR SELECT C1 MA_DVI,C10 TEN_DVI,C2 MA_KH,C3 TEN,C5 DCHI,C6 MOBI,c7 MA_KT,C4 SO_HD, N4 DTHU, N5 THUE,N20/10000 NAM
    FROM KET_QUA ORDER BY C1,C2,C3,C4;
-- EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_DTCPSTN_MDM;

CREATE OR REPLACE PROCEDURE BC_BH_DTCPSTN_MDM
    (b_madvi varchar2,b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_ma_dl varchar2,b_kieu_kt varchar2,b_so_id number,
    b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
    b_noite varchar2(5);
Begin
--BCNam: Doanh thu chua phat sinh trach nhiem, sua lai
--b_loi:='loi:BCNam:loi';
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; return;
end if;
b_loi:='loi:Loi doanh thu chua phat sinh trach nhiem:loi';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_3';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_4';
EXECUTE IMMEDIATE 'TRUNCATE TABLE blvp_temp_1';
commit;
--cac don con no den ngay
insert into temp_1(c29,n1,c1,n2,n3,n4) 
    select   ma_dvi,so_id,ma_nt,sum(no),sum(decode(sign(ngay_ht-b_ngayc),1,0,co)),min(ngay_ht)
    from bh_hd_goc_sc_phi where (b_ma_dvi is null or ma_dvi = b_ma_dvi) group by ma_dvi,so_id,ma_nt
    having sum(no)<>sum(decode(sign(ngay_ht-b_ngayc),1,0,co));-- and min(ngay_ht)<=b_ngayc;
--lay so phat sinh cua nhung don con no den ngay
insert into temp_3(c29,n1,c1,c2,n2,n4,n5,n6) 
    select   ma_dvi,so_id,ma_nt,lh_nv,ngay,sum(phi),sum(thue),sum(ttoan) from bh_hd_goc_cl
    where (b_ma_dvi is null or ma_dvi = b_ma_dvi) and ngay_ht<=b_ngayc and (ma_dvi,so_id,ma_nt) in (select c29,n1,c1 from temp_1)
    group by ma_dvi,so_id,ma_nt,lh_nv,ngay having sum(ttoan)<>0;
--tru di so phat hang hoa don
insert into temp_3(c29,n1,c1,c2,n2,n4,n5,n6) 
    select   ma_dvi,so_id,ma_nt,lh_nv,ngay,-sum(phi),-sum(thue),-sum(ttoan) from bh_hd_goc_ttpt
    where (b_ma_dvi is null or ma_dvi = b_ma_dvi) and ngay_tt<=b_ngayc
    and (ma_dvi,so_id,ma_nt) in (select c29,n1,c1 from temp_1) and pt<>'N'
    group by ma_dvi,so_id,ma_nt,lh_nv,ngay having sum(ttoan)<>0;
--gom tong
insert into temp_2(c1,c2,c3,c4,c10,c11,n20,n1,n2,n3,n4,n5,n6,n7)
        select   goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,round(goc.ngay_ht,-4),goc.ngay_ht,goc.so_id,n2,
        sum(FTT_VND_QD(goc.ma_dvi,ngay_ht,c1,nvl(n4,0))),sum(FTT_VND_QD(goc.ma_dvi,ngay_ht,c1,nvl(n5,0))),sum(nvl(n4,0)),sum(nvl(n5,0))
        from bh_hd_goc goc,temp_3 c
        where goc.ma_dvi=c29 
        --and (b_ma_dvi is null or goc.ma_dvi = b_ma_dvi)
        and goc.so_id=n1 and kieu_hd not in ('V','U','K')
        and (b_phong is null or phong =b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_nv is null or c2 like b_ma_nv||'%')
        group by goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,goc.ngay_ht,goc.so_id,n2;
--loai bo cac hop dong cham dut
delete from temp_2 where n2 in (select so_id from bh_hd_goc_hu where ngay_ht <= b_ngayc and ma_dvi=c1);
delete from temp_2 where n2 in (select so_id from bh_hd_goc where (ttrang='H' or ttrang='S') and ma_dvi=c1);
delete from temp_2 where n2 in (select so_id from bh_hd_goc where ma_dvi=c1 and ngay_kt<to_char(sysdate,'yyyyMMdd') and ma_dvi='034');

update temp_2 set n30=(select 100-sum(pt) from bh_hd_do_tl
    where ma_dvi=c1 and so_id=n2 and pthuc='C' and  kieu='D' and ph='C');

update temp_2 set n30=(select sum(pt) from bh_hd_do_tl
    where ma_dvi=c1 and so_id=n2 and pthuc='C' and kieu='V'  and ph='C') where n30=0 or n30 is null;
update temp_2 set n4=n4-n4*n30/100,n5=n5-n5*n30/100,n6=n6-n6*n30/100,n7=n7-n7*n30/100 where n30<>0;

--update temp_2 set n30=(select sum(phi) from bh_hd_goc_cl where so_id=n2 and ma_dvi=c1);
--update temp_2 set n29=n30-(select sum(phi) from bh_hd_goc_ttpt where so_id=n2 and ma_dvi=c1 and pt<>'N');

--update temp_2 set c6 =(select loai from bh_hd_ma_kh where ma_dvi=temp_2.c1 and ma=temp_2.c2);

update
       (select temp_2.c6 temp_2_c6, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from temp_2, bh_hd_ma_kh
             where temp_2.c1 = bh_hd_ma_kh.ma_dvi and temp_2.c2 = bh_hd_ma_kh.ma)
       set temp_2_c6 = bh_hd_ma_kh_loai;

--chi tiet theo nghiep vu
insert into temp_4(c1,c2,c3,c4,c10,c11,n20,n1,n2,n3,n4,n5,n6,n7,c27)
        select   goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,round(goc.ngay_ht,-4),goc.ngay_ht,goc.so_id,n2,
        sum(FTT_VND_QD(goc.ma_dvi,ngay_ht,c1,nvl(n4,0))),sum(FTT_VND_QD(goc.ma_dvi,ngay_ht,c1,nvl(n5,0))),sum(nvl(n4,0)),sum(nvl(n5,0)),c2
        from bh_hd_goc goc,temp_3 c
        where goc.ma_dvi=c29 
        --and (b_ma_dvi is null or goc.ma_dvi = b_ma_dvi)
        and goc.so_id=n1 and kieu_hd not in ('V','U','K')
        and (b_phong is null or phong =b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_nv is null or c2 like b_ma_nv||'%') --and so_hd='86/15/IHD-KT.1.1/000-TBH'
        group by goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,goc.ngay_ht,goc.so_id,n2,c2;
--loai bo cac hop dong cham dut
delete from temp_4 where n2 in (select so_id from bh_hd_goc_hu where ngay_ht <= b_ngayc and ma_dvi=c1);
delete from temp_4 where n2 in (select so_id from bh_hd_goc where (ttrang='H' or ttrang='S') and ma_dvi=c1);
--loai bo hop dong het hieu luc
delete from temp_4 where n2 in (select so_id from bh_hd_goc where ma_dvi=c1 and ngay_kt<to_char(sysdate,'yyyyMMdd'));

update temp_4 set n30=(select 100-sum(pt) from bh_hd_do_tl
    where ma_dvi=c1 and so_id=n2 and pthuc='C' and  kieu='D' and ph='C' and lh_nv in('*',c27));

update temp_4 set n30=(select sum(pt) from bh_hd_do_tl
    where ma_dvi=c1 and so_id=n2 and pthuc='C' and kieu='V' and ph='C' and lh_nv in('*',c27)) where n30=0 or n30 is null;
update temp_4 set n4=n4-n4*n30/100,n5=n5-n5*n30/100,n6=n6-n6*n30/100,n7=n7-n7*n30/100 where n30<>0;

--update temp_2 set n30=(select sum(phi) from bh_hd_goc_cl where so_id=n2 and ma_dvi=c1);
--update temp_2 set n29=n30-(select sum(phi) from bh_hd_goc_ttpt where so_id=n2 and ma_dvi=c1 and pt<>'N');

--update temp_2 set c6 =(select loai from bh_hd_ma_kh where ma_dvi=temp_2.c1 and ma=temp_2.c2);
--update temp_4 set c6 =(select loai from bh_hd_ma_kh where ma_dvi=temp_4.c1 and ma=temp_4.c2);

update
       (select temp_4.c6 temp_4_c6, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from temp_4, bh_hd_ma_kh
             where temp_4.c1 = bh_hd_ma_kh.ma_dvi and temp_4.c2 = bh_hd_ma_kh.ma)
       set temp_4_c6 = bh_hd_ma_kh_loai;

b_loi:='';
exception when others then null;
end;
/

drop PROCEDURE BC_BH_THDT_PSTRNCB;
CREATE OR REPLACE PROCEDURE BC_BH_THDT_PSTRNCB
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI VARCHAR2,B_MA_KH VARCHAR2,B_TIEN NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
    B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2,
    B_TEN_KHACH OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_I1 NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');

IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
    SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE    B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_KH IS NOT NULL THEN
    SELECT TEN INTO B_TEN_KHACH FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TEN_KHACH:=' ';
END IF;
DELETE KET_QUA;
COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_DTCPSTN_MDM(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI,B_MA_KH,'','','',0,B_NGAYD,B_NGAYC,B_LOI);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO KET_QUA(C1,C2,C3,C4,C10,C11,N4,N5,N20)
        SELECT C1,C2,C3,C4,C10,C11,SUM(N4),SUM(N5),N20 FROM TEMP_2 GROUP BY C1,C2,C3,C4,C10,C11,N20;
ELSE
    INSERT INTO KET_QUA(C1,C2,C3,C4,C10,C11,N4,N5,N20)
        SELECT C1,C2,C3,C4,C10,C11,SUM(N4),SUM(N5),N20 FROM TEMP_2,TEMP_BC_DVI WHERE C1=DVI
        GROUP BY C1,C2,C3,C4,C10,C11,N20;
END IF;
--UPDATE KET_QUA SET C3 =(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C2);
merge into ket_qua using BH_HD_MA_KH on (MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C2) when matched then update set c3= TEN;
--UPDATE KET_QUA SET C12 =(SELECT TEN FROM BH_DL_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C10);
merge into ket_qua using BH_DL_MA_KH on (MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C10) when matched then update set C12= TEN;
--UPDATE KET_QUA SET C13 =(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C11);
merge into ket_qua using HT_MA_CB on (MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C11) when matched then update set C13= TEN;
--UPDATE KET_QUA SET C20 =(SELECT TEN FROM T_MA_DVI WHERE MA=KET_QUA.C1);
merge into ket_qua using HT_MA_DVI on (MA=KET_QUA.C1) when matched then update set C20= TEN;
DELETE KET_QUA WHERE NVL(N4,0)=0 AND NVL(N5,0)=0;
OPEN CS_KQ FOR SELECT C1 MA_DVI,C20 TEN_DVI,C2 MA_KH,C3 TEN,C4 SO_HD,C10 MA_DL,C12 TEN_DL,C11 MA_CB,
    C13 TEN_CB, N4 DT_TT, N5 THUE,N20/10000 NAM FROM KET_QUA ORDER BY C1,C2,C3,C4;
 EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP procedure BC_BH_THDT_PSTRN_CTM2_WEB;
-- chuclh: sua ham cho chay tam
create or replace procedure BC_BH_THDT_PSTRN_CTM2_WEB
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai varchar2,b_ma_kh varchar2,b_tien number,
    b_ngayd number,b_ngayc number,b_kieu varchar2:='<=',cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tennv out varchar2,b_tenloai out varchar2,b_ten_phong out varchar2,
    b_ten_khach out varchar2)
as
    b_loi varchar2(100);b_ngaydn number;b_i1 number;
begin

b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');

if b_loi is not null then raise program_error; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise program_error;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
if b_ma_dvi is not null then
    select ten into b_dvi from ht_ma_dvi where ma=b_madvi;
else b_dvi:=' ';
end if;
if b_ma_nv is not null then
    select ten into b_tennv from bh_ma_lhnv where ma_dvi=b_madvi and ma=b_ma_nv;
else b_tennv:=' ';
end if;
if b_loai is not null then
    select ten into b_tenloai from kh_ma_loai_dn where ma_dvi=b_madvi and ma=b_loai;
else    b_tenloai:=' ';
end if;
if b_phong is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_madvi and ma=b_phong;
else b_ten_phong:=' ';
end if;
if b_ma_kh is not null then
    select ten into b_ten_khach from bh_hd_ma_kh where ma_dvi=b_madvi and ma=b_ma_kh;
else b_ten_khach:=' ';
end if;
delete ket_qua;
commit;
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise program_error; end if;
BC_BH_DTCPSTN_MDM(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai,b_ma_kh,'','','',0,b_ngayd,b_ngayc,b_loi);

select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    insert into ket_qua(c1,c2,c3,c4,n20,n3,n4,n5,n6, n28,c13)
        select c1,c2,c3,c4,n20,n3,sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n4,0))+sum(nvl(n5,0)), sum(n30),c13
        from temp_2 where n1 between b_ngayd and b_ngayc group by c1,c2,c3,c4,n20,n3,c13;
else
    insert into ket_qua(c1,c2,c3,c4,n20,n3,n4,n5,n6, n28,c13)
        select c1,c2,c3,c4,n20,n3,sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n4,0))+sum(nvl(n5,0)), sum(n30),c13
        from temp_2,temp_bc_dvi where c1=dvi and n1 between b_ngayd and b_ngayc group by c1,c2,c3,c4,n20,n3,c13;
end if;
select count(*) into b_i1 from ket_qua;

update ket_qua set (n30,c6,c7,c8,n10,c11,c12)=
(select so_id,ngay_hl,ngay_kt,ngay_cap,ngay_ht,
        --PKH_SO_CNG(ngay_hl) ngay_hl,PKH_SO_CNG(ngay_kt) ngay_kt,
        --pkh_so_cng(ngay_cap) ngay_cap,pkh_so_nam(ngay_ht) ngay_ht,
           phong,cb_ql
   from bh_hd_goc where ma_dvi=ket_qua.c1 and so_hd=ket_qua.c4 and nv=c13);
update ket_qua set n20=b_ngayc-n3 where n3>0;
--update ket_qua set c3 =(select ten from bh_hd_ma_kh where ma_dvi=ket_qua.c1 and ma=ket_qua.c2);
update
    (select ket_qua.c3 ket_qua_c3, bh_hd_ma_kh.ten bh_hd_ma_kh_ten
              from ket_qua, bh_hd_ma_kh
             where ket_qua.c1 = bh_hd_ma_kh.ma_dvi and ket_qua.c2 = bh_hd_ma_kh.ma)
       set ket_qua_c3 = bh_hd_ma_kh_ten;

update ket_qua set c10 =(select ten from ht_ma_dvi where ma=ket_qua.c1);
delete ket_qua where nvl(n4,0)=0 and nvl(n5,0)=0;
update ket_qua set n29=(select max(so_id_kt) from bh_hd_goc_nb where ma_dvi=ket_qua.c1 and so_id=ket_qua.n30);
update ket_qua set c29=(select pkh_so_cng(ngay_ht) from bh_kt where ma_dvi=ket_qua.c1 and so_id=ket_qua.n29) where n29<>0;
update ket_qua set c29='Chua hach toan' where n29=0;
if b_kieu='=' then delete ket_qua where n20<>b_tien; end if;
if b_kieu='>' then delete ket_qua where n20<=b_tien; end if;
if b_kieu='<' then delete ket_qua where n20>=b_tien; end if;
if b_kieu='>=' then delete ket_qua where n20<b_tien; end if;
if b_kieu='<=' then delete ket_qua where n20>b_tien; end if;
open cs_kq for select n30 tc,c1 ma_dvi,c10 ten_dvi,c2 ma_kh,c3 ten_kh,c4 so_hd,c5 ten_hd,c6 ngay_hld,
    c7 ngay_hlc,c8 ngay_capdon,pkh_so_cng(n3) ngay_tt,n20 ngay_qhan,n4 dthu, n5 thue,n6 phi_bh,c29 ttrang,n10 namps,
    c11 phong,c12 cb_ql, n28 tyle_dong
    from ket_qua order by c1,c2,c3,c4;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_THDT_PSTRN_DULIEU;

CREATE OR REPLACE PROCEDURE BC_BH_THDT_PSTRN_DULIEU
    (B_MADVI VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_I1 NUMBER;
BEGIN
DELETE KET_QUA;
BC_BH_DTCPSTN_MDM(B_MADVI,B_MADVI,'','','','','','','',0,B_NGAYD,B_NGAYC,B_LOI);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO KET_QUA(C1,C2,C3,C4,N4,N5,N20,c7,n2)
        SELECT C1,C2,C3,C4,SUM(N4),SUM(N5),N20,c10,n2 FROM TEMP_2 GROUP BY C1,C2,C3,C4,N20,c10,n2;
ELSE
    INSERT INTO KET_QUA(C1,C2,C3,C4,N4,N5,N20,c7,n2)
        SELECT C1,C2,C3,C4,SUM(N4),SUM(N5),N20,c10,n2 FROM TEMP_2,TEMP_BC_DVI WHERE C1=DVI GROUP BY C1,C2,C3,C4,N20,c10,n2;
END IF;
UPDATE KET_QUA SET (C3,C5,C6) =(SELECT TEN,DCHI,MOBI FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C2);
UPDATE KET_QUA SET C10 =(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C1);
update ket_qua set n3 = (select max(ngay_ht) from bh_hd_goc where so_id=n2 );
DELETE KET_QUA WHERE NVL(N4,0)=0 AND NVL(N5,0)=0;
OPEN CS_KQ FOR SELECT C1 MA_DVI,C10 TEN_DVI,C2 MA_KH,C3 TEN,C5 DCHI,C6 MOBI,c7 MA_KT,C4 SO_HD, N4 DTHU, N5 THUE,N20/10000 NAM, n3 ngay_ht
    FROM KET_QUA ORDER BY C1,C2,C3,C4;
 EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_THDT_TV_THBT;

CREATE OR REPLACE PROCEDURE BC_BH_THDT_TV_THBT
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,B_MA_KH VARCHAR2,
    B_LOAI VARCHAR2,B_LOAIBC VARCHAR2,B_PHONG VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA; COMMIT;
INSERT INTO TEMP_2(C1,C7,C2,C4,C3,C6,C5,N1,N4,N5,N2,N3)
        SELECT PKH_SO_CNG(NGAY_HT) NGAY_TH,SERI,SO_DON,'',TEN,MA_THUE,'',
        DECODE(T_SUAT,0,-1,T_SUAT),NGAY_HT,SO_ID,SUM(TIEN_QD),SUM(THUE_QD) FROM BH_BT_THOI  A
        WHERE A.MA_DVI=B_MA_DVI AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
        AND (B_PHONG IS NULL OR PHONG=B_PHONG)
        GROUP BY NGAY_HT,SERI,SO_DON,TEN,MA_THUE,T_SUAT,SO_ID;
INSERT INTO KET_QUA(C7,C1,C2,C4,C3,C6,N1,N2,N3,N4) SELECT C7,C1,C2,C4,C3,C6,N1,SUM(N2),SUM(N3),N4
    FROM TEMP_2 GROUP BY C7,C1,C2,C4,C3,C6,N1,N4;
DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N4,0)=0;
OPEN CS_KQ FOR SELECT ' ' MAU,NVL(C7,' ') SERI,NVL(C2,' ') SO_HD,' ' SO_PHU,' ' NHOM, ' ' TEN_NHOM,
    NVL(C1,' ') NGAY_CT,' ' NGAY_HT,' ' SO_CT_HT,NVL(C3,' ') TEN,NVL(C6,' ') MA_THUE,
    U'Ph\00ED b\1EA3o hi\1EC3m' HANG, NVL(N2,0) TIEN, NVL(N1,0) T_SUAT,NVL(N3,0) THUE,NVL(N2,0)+NVL(N3,0) T_TOAN,
    ' ' ND FROM KET_QUA ORDER BY N1,N4,C2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_THGD_MD;
/
CREATE OR REPLACE PROCEDURE BC_BH_THGD_MD
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
	B_MA_KH VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2,B_BT VARCHAR2:='')
AS
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';

DELETE TEMP_1;COMMIT;

IF B_BT='B' THEN
INSERT INTO TEMP_1(C29,C2,C3,C6,C11,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N14,N30) 
	SELECT BT.MA_DVI,SO_HS,'',PHONG,PKH_SO_CNG(BT.NGAY_QD),NV.MA_NT,LH_NV,NV.SO_ID,
	BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,NV.TIEN_QD,BT.NGAY_HT,NV.SO_ID_BT
	FROM BH_BT_GD_HS BT,BH_BT_GD_HS_PT NV
	WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID AND BT.MA_DVI=B_MADVI AND BT.TTRANG='D'
	AND  BT.NGAY_QD BETWEEN B_NGAYD AND B_NGAYC
	AND (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
END IF;
IF B_PHONG IS NOT NULL THEN 
	DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;
UPDATE TEMP_1 SET C16 =(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C29 AND MA=TEMP_1.C5);
IF B_MA_KH IS NOT NULL THEN 
	DELETE TEMP_1 WHERE C5<>B_MA_KH;
END IF;
DELETE TEMP_1 WHERE (B_LOAI_KH IS NOT NULL AND C16  NOT LIKE B_LOAI_KH||'%');
DELETE TEMP_1 WHERE N6=0;
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
DROP PROCEDURE BC_BH_THGD_MD_CD;

CREATE OR REPLACE PROCEDURE BC_BH_THGD_MD_CD
    (B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2,B_BT VARCHAR2:='')
AS
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;COMMIT;

IF B_BT='B' THEN
INSERT INTO TEMP_1(C29,C2,C3,C6,C11,C17,C18,N10,N12,N13,N2,N3,N4,N5,N6,N7,N14,N30)
    SELECT BT.MA_DVI,SO_HS,'',PHONG,PKH_SO_CNG(BT.NGAY_QD),NV.MA_NT,LH_NV,NV.SO_ID,
    BT.NGAY_HT,NV.SO_ID_HD,0,0,0,0,NV.TIEN,NV.TIEN_QD,BT.NGAY_HT,NV.SO_ID_BT
    FROM BH_BT_GD_HS BT,BH_BT_GD_HS_PT NV
    WHERE (B_MA_DVI IS NULL OR BT.MA_DVI = B_MA_DVI) AND  BT.NGAY_QD>B_NGAYC and TTRANG='D'
    AND NV.MA_DVI=BT.MA_DVI AND NV.SO_ID=BT.SO_ID
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%');
END IF;

DELETE TEMP_6; COMMIT;
INSERT INTO TEMP_6(C1,C2,N1,N2) SELECT DISTINCT A.MA_DVI,A.MA,N12,A.TY_GIA FROM TT_TGTT A,TEMP_1
    WHERE A.MA_DVI=TEMP_1.C29 AND MA=C17 AND
    A.NGAY=(SELECT MAX(B.NGAY) FROM TT_TGTT B WHERE B.MA_DVI=TEMP_1.C29 AND MA=C17 AND B.NGAY <=TO_DATE(TEMP_1.N12,'YYYYMMDD'));
COMMIT;
UPDATE TEMP_1 SET N21=(SELECT N2 FROM TEMP_6 WHERE C1=TEMP_1.C29 AND C2=TEMP_1.C17 AND N1=TEMP_1.N12);
UPDATE TEMP_1 SET N7=NVL(N6,0)*NVL(N21,1);
UPDATE TEMP_1 SET (C6,C4,C5,N11) =(SELECT PHONG,SO_HD,MA_KH,NGAY_HT FROM BH_HD_GOC WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N13);
IF B_PHONG IS NOT NULL THEN
    DELETE TEMP_1 WHERE C6<>B_PHONG;
END IF;
UPDATE TEMP_1 SET C16 =(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C29 AND MA=TEMP_1.C5);
IF B_MA_KH IS NOT NULL THEN
    DELETE TEMP_1 WHERE C5<>B_MA_KH;
END IF;
DELETE TEMP_1 WHERE (B_LOAI_KH IS NOT NULL AND C16  NOT LIKE B_LOAI_KH||'%');

B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/

DROP PROCEDURE BC_BH_THUC_THU_CH_LKH;

CREATE OR REPLACE PROCEDURE BC_BH_THUC_THU_CH_LKH
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai varchar2,
    b_lkh varchar2,b_ma_kh varchar2,b_ma_cb varchar2,b_nguon varchar2, b_ma_dt varchar2,b_kieu_kt varchar2,b_ma_dl varchar2,b_tien_d number,b_tien_c number,b_nhom  varchar2,
    b_ngayd number,b_ngayc number,b_ngayhl_d date,b_ngayhl_c date,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tennv out varchar2,b_tenloai out varchar2,
    b_ten_phong out varchar2,b_ten_khach out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_i1 number;
     b_loai_tmp varchar2(1000);
Begin
-- Bao cao chi tiet doanh thu ban hang theo nghiep vu chi tiet
-- BCNam
b_loai_tmp := null;
SELECT ';'||TRIM(b_loai)||';'||replace(rtrim(xmlagg(xmlelement(e, kq.ma||';'))
                     .extract('//text()'),
                     ';'),
               '#',
               '''''')||';'  into   b_loai_tmp
       FROM
               (SELECT distinct v.ma FROM kh_ma_loai_dn v WHERE v.ma_ct=b_loai)kq;
if b_loai is null then
  b_loai_tmp :=b_loai;
end if;

b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
if b_ma_dvi is not null then
    select ten into b_dvi from ht_ma_dvi where ma=b_ma_dvi;
else b_dvi:=' ';
end if;
if b_ma_nv is not null then
    select ten into b_tennv from bh_ma_lhnv where ma_dvi=b_madvi and ma=b_ma_nv;
else b_tennv:=' ';
end if;
if b_loai is not null then
    select ten into b_tenloai from kh_ma_loai_dn where ma_dvi=b_madvi and ma=b_loai;
else    b_tenloai:=' ';
end if;
if b_phong is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_madvi and ma=b_phong;
else b_ten_phong:=' ';
end if;
if b_ma_kh is not null then
    select ten into b_ten_khach from bh_hd_ma_kh where ma_dvi=b_madvi and ma=b_ma_kh;
else b_ten_khach:=' ';
end if;
if b_tien_c=0 and b_tien_d<>0 then b_n1:=b_tien_d; b_n2:=1.e18;
elsif b_tien_c=0 and b_tien_d=0 then b_n1:=-1.e18; b_n2:=1.e18;
elsif b_tien_d=0 then b_n1:=-1.e18; b_n2:=b_tien_c;
else b_n1:=b_tien_d; b_n2:=b_tien_c;
end if;
delete temp_1;delete temp_2;delete ket_qua; commit;
--Doanh thu
--Chi chay theo ngay chu khong chay theo ngay dau nam nua
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
delete temp_s_1;--lay theo ma khai thac
IF b_ma_dl IS NOT NULL THEN
    INSERT INTO TEMP_s_1 (C1,C2) SELECT DISTINCT MA_DVI,MA FROM BH_DL_MA_KH WHERE (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
        START WITH NVL(MA,' ')=b_ma_dl CONNECT BY PRIOR MA=MA_CT;
END IF;
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
commit;
BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngayd,b_ngayc);

insert into temp_1(c29,c28,c1,c2,c3,c4,c5,c7,n10,n1,n12,n14)
        select ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,round(sum(phi),0),sum(thue),ngay_htnv,so_id
            from TEMP_BC_BH_DTTT_MA_DT where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
                and ngay_htbs between b_ngayd and b_ngayc
                and (b_ma_cb is null or cb_ql=b_ma_cb)
                and (b_ma_kh is null or ma_kh=b_ma_kh)
                and (b_phong is null or phong=b_phong)
                and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
                and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
--                and FBH_HD_LKH(ma_dvig,so_id)=b_lkh
            group by ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,ngay_htnv,so_id,ma_kt;
--loc theo dai ly
IF b_ma_dl IS NOT NULL THEN
    INSERT INTO TEMP_s_1 (C1,C2) SELECT DISTINCT MA_DVI,MA FROM BH_DL_MA_KH WHERE (B_MA_DVI IS NULL OR MA_DVI = B_MA_DVI)
        START WITH NVL(MA,' ')=b_ma_dl CONNECT BY PRIOR MA=MA_CT;
    delete ket_qua a where (a.c29,a.c25) not in ( select c1,c2 from TEMP_s_1);
END IF;

select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    insert into ket_qua (c18,c29,c1,c2,c5,c6,c7,c11,n2,n3,n14)
       select c5,c29,c3,c2,c1,'',c7,c4,sum(n10),sum(n1),n14 from temp_1 group by c5,c29,c3,c2,c1,c7,c4,n14;--where n20 between b_ngayd and b_ngayc;
else
    insert into ket_qua (c18,c29,c1,c2,c5,c6,c7,c11,n2,n3,n14)
         select c5,c29,c3,c2,c1,'',c7,c4,sum(n10),sum(n1),n14 from temp_1,temp_bc_dvi where c29=dvi
            group by c5,c29,c3,c2,c1,c7,c4,n14;-- and n20 between b_ngayd and b_ngayc;
end if;
delete ket_qua where nvl(n2,0)=0 and nvl(n3,0)=0;
delete ket_qua where nvl(n2,0)=0;

update ket_qua set (c3,c8) =(select loai,ten from bh_hd_ma_kh where ma_dvi=ket_qua.c29 and ma=ket_qua.c2);
update ket_qua set c9 =(select ten from bh_ma_lhnv where ma_dvi=ket_qua.c29 and ma=ket_qua.c7);
update ket_qua set c10 =(select ten from kh_ma_loai_dn where ma_dvi=ket_qua.c29 and ma=ket_qua.c3);
update ket_qua set c12 =(select ten from ht_ma_phong where ma_dvi=ket_qua.c29 and ma=ket_qua.c11);
update ket_qua set c4 =(select ten from ht_ma_cb where ma_dvi=ket_qua.c29 and ma=ket_qua.c1);
/*
update
       (select ket_qua.c3 ket_qua_c3, ket_qua.c8 ket_qua_c8, bh_hd_ma_kh.ten bh_hd_ma_kh_ten, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from ket_qua, bh_hd_ma_kh
             where ket_qua.c29 = bh_hd_ma_kh.ma_dvi and ket_qua.c2 = bh_hd_ma_kh.ma)
       set ket_qua_c8 = bh_hd_ma_kh_ten, ket_qua_c3 = bh_hd_ma_kh_loai;
update
       (select ket_qua.c9 ket_qua_c9, bh_ma_lhnv.ten bh_ma_lhnv_ten
              from ket_qua, bh_ma_lhnv
             where ket_qua.c29 = bh_ma_lhnv.ma_dvi and ket_qua.c7 = bh_ma_lhnv.ma)
       set ket_qua_c9 = bh_ma_lhnv_ten;
update
       (select ket_qua.c10 ket_qua_c10, kh_ma_loai_dn.ten kh_ma_loai_dn_ten
              from ket_qua, kh_ma_loai_dn
             where ket_qua.c29 = kh_ma_loai_dn.ma_dvi and ket_qua.c3 = kh_ma_loai_dn.ma)
       set ket_qua_c10 = kh_ma_loai_dn_ten;
update
       (select ket_qua.c12 ket_qua_c12, ht_ma_phong.ten ht_ma_phong_ten
              from ket_qua, ht_ma_phong
             where ket_qua.c29 = ht_ma_phong.ma_dvi and ket_qua.c11 = ht_ma_phong.ma)
       set ket_qua_c12 = ht_ma_phong_ten;
update
       (select ket_qua.c4 ket_qua_c4, ht_ma_cb.ten ht_ma_cb_ten
              from ket_qua, ht_ma_cb
             where ket_qua.c29 = ht_ma_cb.ma_dvi and ket_qua.c1 = ht_ma_cb.ma)
       set ket_qua_c4 = ht_ma_cb_ten;
*/

UPDATE ket_qua SET (c13,c14,c15,c16) = (SELECT ksoat,dvi_ksoat,bcnam_so_ngay_f(ngay_cap),ma_gt from BH_HD_GOC WHERE ma_dvi=c29 and so_id=n14);
update ket_qua set c16=(select loai from bh_hd_ma_kh where ma_dvi=c29 and ma=c2);
update ket_qua set (n8) = (select DISTINCT sum(pt) FROM tbh_ghep_pbo where ma_dvi_hd=c29 and so_id_hd=n14
        and lh_nv=c7 group by so_id_hd,lh_nv);
update ket_qua set (n9) = (select DISTINCT sum(pt) FROM tbh_tm_pbo where ma_dvi_hd=c29 and so_id_hd=n14
        and lh_nv=c7 group by so_id_hd,lh_nv);
update
(
select ket_qua.c27 ket_qua_c27, BH_DL_MA_KH.ten BH_DL_MA_KH_ten from ket_qua,BH_DL_MA_KH where ket_qua.c18=BH_DL_MA_KH.ma and ket_qua.c29=BH_DL_MA_KH.ma_dvi
) set ket_qua_c27= BH_DL_MA_KH_ten;
if (SUBSTR(b_ma_nv,1,2)='CN') then
--   UPDATE ket_qua SET c20=(SELECT truong from bh_nguoihd WHERE ma_dvi=c29 and so_hd=c5) WHERE c7 like 'CN.4%';
--   UPDATE ket_qua SET c21=(SELECT ngsach from bh_nguoihd WHERE ma_dvi=c29 and so_hd=c5) WHERE c7 like 'CN.8%';
  commit;
  open cs_kq for select c1 cb_ql,c4 ten_cb,c2 ma_kh,c8 ten,c16 nhom_kh,c5 so_hd,c6 lh_bh,c7 lh_nv,c9 ten_lh_nv,
  c3 loai_kh,c10 ten_loai_kh, c11 phong,c12 ten_phong, nvl(n2,0) dt_tt, nvl(n3,0) thue
  ,case when c20 = '01' then 'Mau giao'
        when c20 = '02' then 'Tieu hoc'
        when c20 = '03' then 'THCS'
        when c20 = '04' then 'PTTH'
        when c20 = '05' then 'CD,DH'
        end truong_hoc
  ,c21 loai_ns, c13 ng_duyet,c14 dvi_duyet,c16  ma_gt,n8 cd_tl,n9 tm_tl,c19 KIEU_KT,c18 as ma_kt,c27 ten_kt
          from ket_qua a where (INSTR1(c3,b_loai_tmp)>0 or b_loai_tmp is null)/*(b_loai is null or c3=b_loai)*/ and (nvl(n2,0) between b_n1 and b_n2) order by c1,c2,c5;

else
  open cs_kq for
  select c1 cb_ql,c4 ten_cb,c2 ma_kh,c8 ten,c16 nhom_kh,c5 so_hd,c6 lh_bh,c7 lh_nv,c9 ten_lh_nv,
        c3 loai_kh,c10 ten_loai_kh, c11 phong,c12 ten_phong, nvl(n2,0) dt_tt, nvl(n3,0) thue, c13 ng_duyet,
        c14 dvi_duyet,c16  ma_gt,n8 cd_tl,n9 tm_tl,c19 KIEU_KT,c18 as ma_kt,c27 ten_kt
  from ket_qua a where (INSTR1(c3,b_loai_tmp)>0 or b_loai_tmp is null)/*(b_loai is null or c3=b_loai)*/ and (nvl(n2,0) between b_n1 and b_n2) order by c1,c2,c5;

end if;

--exception when others then raise_application_error(-20105,b_loi);
end;

/

DROP PROCEDURE BC_BH_THUC_THU_NAMPS;

CREATE OR REPLACE PROCEDURE BC_BH_THUC_THU_NAMPS
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_KIEU_KT VARCHAR2,B_NAM NUMBER,B_NAM_DEN NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
    B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,
    B_TEN_PHONG OUT VARCHAR2,B_TEN_KHACH OUT VARCHAR2)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_I1 NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
IF B_MA_DVI IS NOT NULL THEN
    SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
    SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
    SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE    B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN 
    SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_KH IS NOT NULL THEN
    SELECT TEN INTO B_TEN_KHACH FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TEN_KHACH:=' ';
END IF;
DELETE TEMP_2;DELETE KET_QUA; COMMIT;

PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES(B_MA_DVI, B_NGAYD, B_NGAYC);
IF B_I1=0 THEN
    INSERT INTO KET_QUA  (C29,C28,C1,C2,C5,C7,C11,N10,N11,N12,N2,N3) 
        SELECT MA_DVI,MA_DVIG,CB_QL,MA_KH,SO_HD,LH_NV,PHONG,SO_ID,NGAY,NGAY_HTNV,SUM(PHI),SUM(THUE)
        FROM V_BC_BH_DTTT_MA_DT WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI)
        AND NGAY_HTBS BETWEEN B_NGAYD AND B_NGAYC
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
        AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
        GROUP BY  MA_DVI,MA_DVIG,CB_QL,MA_KH,SO_HD,LH_NV,PHONG,SO_ID,NGAY,NGAY_HTNV;
ELSE
    INSERT INTO KET_QUA  (C29,C28,C1,C2,C5,C7,C11,N10,N11,N12,N2,N3) 
        SELECT MA_DVI,MA_DVIG,CB_QL,MA_KH,SO_HD,LH_NV,PHONG,SO_ID,NGAY,NGAY_HTNV,SUM(PHI),SUM(THUE)
        FROM V_BC_BH_DTTT_MA_DT,TEMP_BC_DVI WHERE (B_MA_DVI IS NULL OR MA_DVI=B_MA_DVI)
        AND NGAY_HTBS BETWEEN B_NGAYD AND B_NGAYC AND MA_DVI=DVI
            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
        AND (B_MA_CB IS NULL OR CB_QL=B_MA_CB) AND (B_KIEU_KT IS NULL OR KIEU_KT=B_KIEU_KT)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
        GROUP BY MA_DVI,MA_DVIG,CB_QL,MA_KH,SO_HD,LH_NV,PHONG,SO_ID,NGAY,NGAY_HTNV;
END IF;

UPDATE KET_QUA SET (N20)=(SELECT MAX(NGAY_HTNV) FROM V_BC_BH_DTBH_MA_DT
    WHERE MA_DVI=KET_QUA.C29 AND SO_ID=KET_QUA.N10 AND PHI<>0 AND DBH NOT IN (1,2,3) AND NGAY=KET_QUA.N11 AND NGAY_HTNV<=KET_QUA.N12) ;
UPDATE KET_QUA SET (N20)=(SELECT TO_NUMBER(SUBSTR(TO_CHAR(MAX(NGAY_HTNV)),1,4)) FROM V_BC_BH_DTBH_MA_DT
    WHERE MA_DVI=KET_QUA.C28 AND SO_ID=KET_QUA.N10 AND PHI<>0 AND DBH NOT IN (1,2,3) 
    AND NGAY=KET_QUA.N11 AND NGAY_HTNV<=KET_QUA.N12) WHERE C29<>C28;
DELETE KET_QUA WHERE NVL(N2,0)=0 AND NVL(N3,0)=0;
UPDATE KET_QUA SET (C8,C3) =(SELECT TEN,LOAI FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C2);
UPDATE KET_QUA SET C9 =(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C7);
UPDATE KET_QUA SET C10 =(SELECT TEN FROM KH_MA_LOAI_DN WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C3);
UPDATE KET_QUA SET C12 =(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C11);
UPDATE KET_QUA SET C4 =(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=KET_QUA.C29 AND MA=KET_QUA.C1);
OPEN CS_KQ FOR SELECT C1 CB_QL,C4 TEN_CB,C2 MA_KH,C8 TEN,C5 SO_HD,C6 LH_BH,C7 LH_NV,C9 TEN_LHNV,
        C3 LOAI_KH,C10 TEN_LKH, C11 PHONG,C12 TEN_PHONG, SUM(NVL(N2,0)) DT_TT, SUM(NVL(N3,0)) THUE,NVL(N20,0) NAM
        FROM KET_QUA A WHERE (NVL(B_NAM,0)=0 OR N20 BETWEEN B_NAM AND B_NAM_DEN) AND (B_LOAI IS NULL OR C3=B_LOAI )
        GROUP BY C1,C4,C2,C8,C5,C6,C7,C9,C3,C10,C11,C12,N20
        ORDER BY C1,C2,C5;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_THUPHI;

CREATE OR REPLACE PROCEDURE BC_BH_THUPHI
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,A_SO_HD PHT_TYPE.A_VAR,
    CS_KQ OUT PHT_TYPE.CS_TYPE,B_TTTOAN OUT NUMBER)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NGAYDNT NUMBER;B_NGAYCT NUMBER;
    B_NGAYCN NUMBER;B_711 VARCHAR2(10);B_712 VARCHAR2(10);B_713 VARCHAR2(10);
    B_714 VARCHAR2(10);B_715 VARCHAR2(10);B_MA_KHH VARCHAR(10);B_I1 NUMBER;
    B_TIEN NUMBER;B_TTOAN NUMBER;B_NV VARCHAR2(10);B_SO_ID NUMBER;B_KIEU_HD VARCHAR2(10);B_SO_ID_G NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
DELETE TEMP_1;DELETE TEMP_2; COMMIT;
B_LOI:='loi:Ma chua dang ky'||A_SO_HD(1)||B_MA_DVI||':loi';
B_TTOAN:=0;
FOR B_LP IN 1.. A_SO_HD.COUNT LOOP
SELECT NV,KIEU_HD,SO_ID,SO_ID_G INTO B_NV,B_KIEU_HD,B_SO_ID,B_SO_ID_G FROM BH_HD_GOC
    WHERE MA_DVI=B_MA_DVI AND SO_HD=A_SO_HD(B_LP);
B_LOI:='loi:Ma chua dang ky'||B_NV||B_MA_DVI||':loi';
IF B_NV='XE' THEN
    INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C19)
        SELECT   A.SO_ID_DT,A.GCN,C.SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,A.SO_CN,A.TTAI,PKH_SO_CNG(A.NGAY_HL),
        PKH_SO_CNG(A.NGAY_KT),b.PHI+b.THUE,'' muc_rr,PKH_SO_CNG(C.NGAY_CAP)
        FROM BH_XE_ds A,BH_XE_DK B, BH_XE C
        WHERE C.MA_DVI=B_MA_DVI AND C.SO_HD=A_SO_HD(B_LP)
            AND B.MA_DVI=B_MA_DVI AND B.SO_ID=C.SO_ID AND instr(nv_bh,'B')>0 --SUBSTR(MA,1,1)='B'
            AND A.MA_DVI=B_MA_DVI AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT;

--    INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C19)
--        SELECT  A.SO_ID_DT,A.GCN,C.SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
--        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,A.SO_CN,A.TTAI,PKH_SO_CNG(A.NGAY_HL),
--        PKH_SO_CNG(A.NGAY_KT),b.PHI+b.THUE,'' muc_rr,PKH_SO_CNG(C.NGAY_CAP)
--        FROM BH_XEGCN A,BH_XEGCN_DK B, BH_XEHDGOC C
--        WHERE C.MA_DVI=B_MA_DVI AND C.SO_HD=A_SO_HD(B_LP)
--            AND B.MA_DVI=B_MA_DVI AND B.SO_ID=C.SO_ID AND  SUBSTR(MA,1,1)='T'
--            AND A.MA_DVI=B_MA_DVI AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT;
IF B_KIEU_HD='B' THEN
    INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C19)
        SELECT  A.SO_ID_DT,A.GCN,C.SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,A.SO_CN,A.TTAI,PKH_SO_CNG(A.NGAY_HL),
        PKH_SO_CNG(A.NGAY_KT),-(b.PHI+b.THUE),'' muc_rr,PKH_SO_CNG(C.NGAY_CAP)
        FROM BH_XE_ds A,BH_XE_DK B, BH_XE C
        WHERE C.MA_DVI=B_MA_DVI AND C.SO_ID=B_SO_ID_G
        AND B.MA_DVI=B_MA_DVI AND B.SO_ID=C.SO_ID AND instr(nv_bh,'B')>0--SUBSTR(LOAI,1,1)='B'
        AND A.MA_DVI=B_MA_DVI AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT;
--    INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C19)
--        SELECT  A.SO_ID_DT,A.GCN,C.SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
--        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,A.SO_CN,A.TTAI,PKH_SO_CNG(A.NGAY_HL),
--        PKH_SO_CNG(A.NGAY_KT),-(b.PHI+b.THUE),'' muc_rr,PKH_SO_CNG(C.NGAY_CAP)
--        FROM BH_XEGCN A,core.BH_XEGCN_DK B, BH_XEHDGOC C
--        WHERE C.MA_DVI=B_MA_DVI AND C.SO_ID=B_SO_ID_G
--            AND B.MA_DVI=B_MA_DVI AND B.SO_ID=C.SO_ID AND SUBSTR(LOAI,1,1)='T'
--            AND A.MA_DVI=B_MA_DVI AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT;
END IF;
ELSIF B_NV='2B' THEN
    INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C17,C18)
        SELECT  A.SO_ID_DT,A.GCN,C.SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,0,0,PKH_SO_CNG(A.NGAY_HL),
        PKH_SO_CNG(A.NGAY_KT),b.PHI+b.THUE,'',PKH_SO_CNG(C.NGAY_CAP),PKH_SO_CNG(A.NGAY_CAP)
        FROM BH_2B_ds A,BH_2B_DK B,BH_2B C
        WHERE C.MA_DVI=B_MA_DVI AND C.SO_HD=A_SO_HD(B_LP)
            AND B.MA_DVI=B_MA_DVI AND B.SO_ID=C.SO_ID
            AND A.MA_DVI=B_MA_DVI AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT;
    IF B_KIEU_HD='B' THEN
        INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C17,C18)
        SELECT  A.SO_ID_DT,A.GCN,C.SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,0,0,PKH_SO_CNG(A.NGAY_HL),
        PKH_SO_CNG(A.NGAY_KT),-(b.PHI+b.THUE),'',PKH_SO_CNG(C.NGAY_CAP),PKH_SO_CNG(A.NGAY_CAP)
        FROM BH_2B_ds A,BH_2B_DK B,BH_2B C
        WHERE C.MA_DVI=B_MA_DVI AND C.SO_ID=B_SO_ID_G
            AND B.MA_DVI=B_MA_DVI AND B.SO_ID=C.SO_ID
            AND A.MA_DVI=B_MA_DVI AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT;
    END IF;
--ELSIF B_NV='XEL' THEN
--    INSERT INTO TEMP_1(N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,N4,C16,C19)
--        SELECT  A.SO_ID,A.SO_HD,SO_HD,'VANGLAI',a.tenc,'',a.tenc,A.dchic,
--        A.hieu,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,A.SO_CN,A.TTAI,PKH_SO_CNG(A.NGAY_HL),
--        PKH_SO_CNG(A.NGAY_KT),PHI_DT+B.THUE,'' muc_rr,PKH_SO_CNG(A.NGAY_CAP)
