        WHERE MA_DVI=B_MA_DVI AND SO_ID_TT IN (SELECT SO_ID_TT FROM BH_HD_GOC_TTHD WHERE MA_DVI=B_MA_DVI AND SO_ID= FBH_HD_GOC_SO_ID(MA_DVI,A_SO_HD(B_LP)) )
        AND  SO_ID_KT=0;
    B_TTOAN:=B_TTOAN+B_TIEN;
    */
    /*
    SELECT SUM(TTOAN_QD) INTO B_TIEN FROM  BH_HD_GOC_TTPS
        WHERE MA_DVI=B_MA_DVI AND SO_ID_TT IN (SELECT SO_ID_TT FROM BH_HD_GOC_TTHD WHERE MA_DVI=B_MA_DVI AND SO_ID=b_so_id)
        AND  SO_ID_KT=0;
    */

    SELECT SUM(TTOAN_QD) INTO B_TIEN FROM  BH_HD_GOC_TTPS
        WHERE MA_DVI=B_MA_DVI AND exists(SELECT SO_ID_TT FROM BH_HD_GOC_TTHD WHERE MA_DVI=B_MA_DVI AND SO_ID=b_so_id)
        AND  SO_ID_KT=0;

    B_TTOAN:=B_TTOAN+B_TIEN;

END LOOP;
