        SELECT  N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,SUM(N4),C16,C17,C18,C19 FROM TEMP_1
        GROUP BY N20,C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,C12,C13,C16,C17,C18,C19;
B_TTTOAN:=NVL(B_TTOAN,1);
COMMIT;
OPEN CS_KQ FOR SELECT  C1 SO_HD, C2 SO_HD_G,C3 MA_KH, C4 TEN_KH,C5 MA_THUE, C6 TEN_CXE,
    C7 D_CHI_CX,C16 LOAI_XE,C17 TEN_LOAI, C8 hieu, C9 BIEN_XE,C10 SO_KHUNG,C11 SO_MAY,
    NVL(N1,0) SO_CN,NVL(N2,0) T_TAI,NVL(N3,0) TIEN_XE,C12 NGAY_HL,C13 NGAY_KT,NVL(N4,0) TIEN,
    C17 NGAY_CAP_HD_XEMAY, C18 NGAY_CAP_GCN_XEMAY, C19 NGAY_CAP_HD_GCN_OTO FROM TEMP_2
    ORDER BY C1, C6, N1;
--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_THUPHIK;
-- chuclh: lay them tien tt
CREATE OR REPLACE PROCEDURE BC_BH_THUPHIK
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,a_so_hd pht_type.a_var,
    cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number;b_ngaydnt number;b_ngayct number;
    b_ngaycn number;b_711 varchar2(10);b_712 varchar2(10);b_713 varchar2(10);
    b_714 varchar2(10);b_715 varchar2(10);b_ma_khh varchar(10);b_i1 number;b_so_id number;
Begin
-- Bang ke xe thu phi khac xe co gioi
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
delete temp_1; commit;
b_loi:='loi:Ma chua dang ky:loi';
for b_lp in 1.. a_so_hd.count loop
    b_so_id:=FBH_HD_GOC_SO_ID_DAU(b_ma_dvi,a_so_hd(b_lp));
    insert into temp_1(c1,c2,c3,c4,n1,n2,c12,c13,n4,n5)
        select so_hd,ma_kh,ten,'',sum(phi_qd),sum(thue_qd),PKH_SO_CNG(ngay_hl),
        PKH_SO_CNG(ngay_kt),sum(ttoan),sum(ttoan_qd) from bh_hd_goc a,bh_hd_goc_ttpt b
        where a.ma_dvi=b_ma_dvi and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.so_id=b_so_id--and a.so_hd=a_so_hd(b_lp)
          and b.pt in ('N','G')
        group by so_hd,ma_kh,ten,a.ngay_hl,a.ngay_kt;
end loop;
update temp_1 set c4=(select cmt from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=temp_1.c2);
open cs_kq for select  c1 so_hd,c2 ma_kh, c3 ten_kh,c4 ma_thue,nvl(n1,0) phi,nvl(n2,0) thue,c12 ngay_hl,c13 ngay_kt,nvl(n4,0) ttoan,nvl(n5,0) so_tien_tt from temp_1;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_THU_HOI_CN;

CREATE OR REPLACE PROCEDURE BC_BH_THU_HOI_CN
	(B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
	B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI VARCHAR2,B_MA_KH VARCHAR2,
	B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE,
	B_DVI OUT VARCHAR2,B_TENNV OUT VARCHAR2,B_TENLOAI OUT VARCHAR2,B_TEN_PHONG OUT VARCHAR2,
	B_TEN_KHACH OUT VARCHAR2)
AS
	B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_NAM NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYC,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
B_NAM:=ROUND(B_NGAYC,-4)/10000;
IF B_MA_DVI IS NOT NULL THEN
	SELECT TEN INTO B_DVI FROM HT_MA_DVI WHERE MA=B_MA_DVI;
ELSE B_DVI:=' ';
END IF;
IF B_MA_NV IS NOT NULL THEN
	SELECT TEN INTO B_TENNV FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA_NV;
ELSE B_TENNV:=' ';
END IF;
IF B_LOAI IS NOT NULL THEN
	SELECT TEN INTO B_TENLOAI FROM KH_MA_LOAI_DN WHERE MA_DVI=B_MA_DVI AND MA=B_LOAI;
ELSE	B_TENLOAI:=' ';
END IF;
IF B_PHONG IS NOT NULL THEN
	SELECT TEN INTO B_TEN_PHONG FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_PHONG;
ELSE B_TEN_PHONG:=' ';
END IF;
IF B_MA_KH IS NOT NULL THEN
	SELECT TEN INTO B_TEN_KHACH FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA_KH;
ELSE B_TEN_KHACH:=' ';
END IF;
DELETE TEMP_2;DELETE KET_QUA; COMMIT;

INSERT INTO TEMP_2(C1,C2,C4,C5,N1,N2,N12,N10) SELECT NV.MA_DVI,MA_KH,SO_HD,LH_NV,NV.NGAY_TT,
	SUM(phi_qd),SUM(THUE_QD),NV.SO_ID FROM BH_HD_GOC GOC,BH_HD_GOC_TTPT NV
	WHERE GOC.MA_DVI=NV.MA_DVI AND GOC.SO_ID=NV.SO_ID
	AND (B_MA_DVI IS NULL OR GOC.MA_DVI=B_MA_DVI)	
	AND KIEU_HD <>'V' AND NV.NGAY_TT BETWEEN B_NGAYD AND B_NGAYC AND PT='N'
	AND (B_PHONG IS NULL OR PHONG =B_PHONG)
	AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
	AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
	GROUP BY NV.MA_DVI,MA_KH,SO_HD,LH_NV,NV.NGAY_TT,NV.SO_ID;
UPDATE TEMP_2 SET C3 =(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C2);
UPDATE TEMP_2 SET (N3,N4)=(SELECT MAX(NGAY_TT),TO_NUMBER(TO_CHAR(SUBSTR(MAX(NGAY_TT),1,4))) FROM BH_HD_GOC_TTPT 
	WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N10 AND PT='C');
INSERT INTO KET_QUA(C1,C2,C4,C5,N1,N3,N4,N2,N12)
	SELECT C1,C2,C4,C5,N1,N3,N4,SUM(N2),N12 FROM TEMP_2
	WHERE B_LOAI IS NULL OR C3=B_LOAI GROUP BY C1,C2,C4,C5,N1,N3,N4,N12;

UPDATE KET_QUA SET C10 =(SELECT TEN FROM HT_MA_DVI WHERE MA=KET_QUA.C1);

UPDATE KET_QUA SET C12 =(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C2);

UPDATE KET_QUA SET C15 =(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=KET_QUA.C1 AND MA=KET_QUA.C5);

OPEN CS_KQ FOR SELECT C1 MA_DVI,C10 TEN_DVI,C2 MA_KH,C12 TEN_KH,C4 SO_HD,C5 MA_NV,C15 TEN_NV,
	PKH_SO_CNG(N3) NGAY_NOPHI,PKH_SO_CNG(N1) NGAY_TT,N4 NAM,N2 PHI,N12 THUE
	FROM KET_QUA ORDER BY C1;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_TKE_HANG_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_HANG_MD
     (B_LOAI VARCHAR2,B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_MA_CB VARCHAR2,
     B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
DELETE TEMP_1;COMMIT;
IF B_LOAI='PS' THEN
    INSERT INTO TEMP_1(C29,C2,C3,C4,C5,C6,C7,C8,C17,C18,C19,C21,N1,N6,D1,N7,C23,C28,C25,C30)
          select a.ma_dvi,VCHUYEN ten_pt,'' so_chuyen,FBH_HANG_TXT(a.ma_dvi,a.so_id,'noi_di'),FBH_HANG_TXT(a.ma_dvi,a.so_id,'noi_den'),c_ctai,'' ma_dk,''gdinh,ma_kh,phong,ma_cb,
        nt_phi,a.so_id,a.tong_mtn,PKH_SO_DATE(a.ngay_cap),a.ngay_ht,a.nt_tien,kieu_hd,a.ttrang,fbh_hang_qtac_ten(a.qtac)
        from bh_hang a
        WHERE 
        (B_MA_DVI IS NULL OR A.MA_DVI = B_MA_DVI) AND TTRANG='D'
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND (B_MA_CB IS NULL OR ma_cb=B_MA_CB) AND KIEU_HD NOT IN ('B','V')
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH);
ELSIF B_LOAI='SD' THEN 
    INSERT INTO TEMP_1(C29,C2,C3,C4,C5,C6,C7,C8,C17,C18,C19,C21,N1,N6,D1,N7,C23,C28,C25,C30)
        select a.ma_dvi,VCHUYEN ten_pt,'' so_chuyen,FBH_HANG_TXT(a.ma_dvi,a.so_id,'noi_di'),FBH_HANG_TXT(a.ma_dvi,a.so_id,'noi_den'),c_ctai,'' ma_dk,''gdinh,ma_kh,phong,ma_cb,
        nt_phi,a.so_id,a.tong_mtn,PKH_SO_DATE(a.ngay_cap),a.ngay_ht,a.nt_tien,kieu_hd,a.ttrang,fbh_hang_qtac_ten(a.qtac)
        from bh_hang a
        WHERE 
        (B_MA_DVI IS NULL OR A.MA_DVI = B_MA_DVI) AND TTRANG='D'
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND (B_MA_CB IS NULL OR ma_cb=B_MA_CB) AND KIEU_HD NOT IN ('G','V','K') 
        AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH);    
END IF;
-- tinh phi bao hiem
UPDATE TEMP_1 SET (N3)=(select sum(phi) from bh_hang_dk where ma_dvi=C29 and so_id=N1 and lh_bh='C');
UPDATE TEMP_1 SET (N5)=(select sum(phi) from bh_hang_dk where ma_dvi=C29 and so_id=N1 and lh_bh<>'C');   
UPDATE TEMP_1 SET N8=NVL(N3,0)+NVL(N5,0);

UPDATE TEMP_1 SET C20=PKH_SO_CNG(FBH_HANG_TXT(C29,N1,'ngay_hl')) where FBH_HANG_TXT(C29,N1,'ngay_hl') not in (0,30000101);
-- ten phuong tien van chuyen
UPDATE TEMP_1 SET C2=(select LISTAGG(ten_pt, ',') WITHIN GROUP (ORDER BY so_id) AS names from BH_HANG_PTVC WHERE SO_id=N1 AND TEN_PT IS NOT NULL);
-- danh sach hang hoa
UPDATE TEMP_1 SET C26=(select LISTAGG(ten_hang, ',') WITHIN GROUP (ORDER BY so_id) AS names from BH_HANG_DS WHERE SO_id=N1 AND TEN_HANG IS NOT NULL);
-- ngay thanh toan gan nhat
UPDATE TEMP_1 SET N9=(SELECT MAX(NGAY) FROM bh_hd_goc_tt WHERE MA_DVI=C29 AND SO_ID=N1);
--ty le dong bh
UPDATE TEMP_1 SET (N10)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C29 and so_id=N1
        and pthuc='C' and FBH_DONG(C29,N1)='V');
UPDATE TEMP_1 SET (N11)=(select 100-sum(pt) from bh_hd_do_tl where ma_dvi=C29 and so_id=N1
        and pthuc='C' and FBH_DONG(C29,N1)='D'); 
             
UPDATE TEMP_1 SET C22=(SELECT LH_NV FROM BH_HANG_DK WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND ROWNUM=1);
UPDATE TEMP_1 SET N12=(SELECT SUM(PHI) FROM BH_HANG_DK WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1);
UPDATE TEMP_1 SET C9= (SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='TEN' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C10= (SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='BLNo' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C11 =(SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='PACKING' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C12 =(SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='QUANTITY' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C13 =(SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='CONTAI' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C14 =(SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='CONTRACT' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C15 =(SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='COMMER' AND G_TRI IS NOT NULL  AND ROWNUM=1);
UPDATE TEMP_1 SET C16 =(SELECT G_TRI FROM BH_HD_GOC_DT WHERE MA_DVI=TEMP_1.C29 AND SO_ID=TEMP_1.N1 AND MA_TKE='LC' AND G_TRI IS NOT NULL AND ROWNUM=1);
B_LOI:='';
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,'loi:Loi BC_BH_TKE_HANG_MD:loi');
END;
/
DROP PROCEDURE BC_BH_TKE_HANG_PS;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_HANG_PS
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_LOAI VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER;B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;
DELETE TEMP_1;DELETE TEMP_2; COMMIT;

PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_TKE_HANG_MD(B_LOAI,B_MADVI,B_MA_DVI,B_MA_KH,B_MA_NV,B_PHONG,B_MA_CB,B_NGAYD,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_TTRANG <>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO TEMP_2 (C1,C2,C4,C5,C6,C7,C9,C10,C11,N1,N6,N2,N3,N4,N5,N7,C13,C20,C24,C19,C8,C12,C22,D1,C14,C26,C27,C31,N8,N9,N10,N11,C36,N12,C30)
        SELECT C29,FBH_HD_GOC_SO_HD(C29,N1),C9,C12,C11,C2,C4,C6,C5,N1,N6,N2,N3,N4,N5,N7,C7,C17,C18,C19,C20,C21,C22,D1,C23,C26,C27,C31,N8,N9,N10,N11,C36,N12,C30 FROM TEMP_1
            WHERE (B_TTRANG1 IS NULL OR C25=B_TTRANG1);
ELSE
    INSERT INTO TEMP_2 (C1,C2,C4,C5,C6,C7,C9,C10,C11,N1,N6,N2,N3,N4,N5,N7,C13,C20,C24,C19,C8,C12,C22,D1,C14,C26,C27,C31,N8,N9,N10,N11,C36,N12,C30)
        SELECT C29,FBH_HD_GOC_SO_HD(C29,N1),C9,C12,C11,C2,C4,C6,C5,N1,N6,N2,N3,N4,N5,N7,C7,C17,C18,C19,C20,C21,C22,D1,C23,C26,C27,C31,N8,N9,N10,N11,C36,N12,C30
        FROM TEMP_1,TEMP_BC_DVI WHERE C29=DVI AND (B_TTRANG1 IS NULL OR C25=B_TTRANG1);
END IF;
UPDATE TEMP_2 SET C35=(SELECT TEN FROM BH_HANG_NHOM WHERE MA_DVI=C1 AND MA=B_MA_NV);
UPDATE TEMP_2 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C22);
UPDATE TEMP_2 SET C21=(SELECT TEN FROM bh_bt_hang WHERE MA_DVI=TEMP_2.C1 AND so_hd=TEMP_2.C2);
UPDATE TEMP_2 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C24);
UPDATE TEMP_2 SET C32=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C19);
UPDATE TEMP_2 SET C3=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_2.C1);
OPEN CS_KQ FOR SELECT C1 MA_DVI,C3 TEN_DVI,C20 MA_KH,C21 TEN_KH,C19 CB_QL,C35 TEN_NHOM,PKH_SO_CNG(N7) NGAY_HT,
    C24 PHONG, C25 TEN_PHONG,C22 LH_NV,C23 TEN_LHNV,C26 TEN_HANG,C27 LUONG, C7 TEN_PT,
    C2 SO_HD,C31 DGOI,C32 SL_HH,C33 PTHUC, C8 NGAY_KH,C9 TU,case when C10 = 'K' then 'Khong' else 'Co' end CTAI,C11 DEN,N6 TIEN,N15 DC_KHAC,
    C12 NT_PHI,N2 TL_PHI,N3 PHI,N4 TL_PPHI,N5 PPHI,C13 MA_DK,C28 TEN_DK_BH,TO_CHAR(D1,'dd/mm/yyyy') NGAY_CAP,
    C30 DK_RIENG,N12 PHI_DT,C14 NT_TIEN,N8 TPHI,PKH_SO_CNG(N9) NGAY_TT,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C36 GHI_CHU
    FROM TEMP_2 where nvl(c2, ' ') <> ' ' ORDER BY D1,C2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,'loi:Loi BC_BH_TKE_HANG_PS:loi');
END;
/
CREATE OR REPLACE PROCEDURE BC_BH_TKE_PHH_PS
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_LOAI VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER;B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;
DELETE TEMP_1;
DELETE TEMP_2;DELETE KET_QUA; COMMIT;
--PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
--IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
BC_BH_TKE_PHH_MD(B_LOAI,B_MADVI,B_MA_DVI,B_MA_KH,B_MA_NV,B_PHONG,B_MA_CB,B_NGAYD,B_NGAYC,B_TTRANG1,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
UPDATE TEMP_1 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C9);
UPDATE TEMP_1 SET C21=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C12) WHERE C21 IS NULL;
UPDATE TEMP_1 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C10);
UPDATE TEMP_1 SET C27=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C11);

UPDATE TEMP_1 SET C32=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_1.C1);

SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C23 TEN_LHNV,C31 RR_BH,C16 MA_DT,N9 MUC_MT,C29 MT_TIEN,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C33 DK_LUT,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N4 PHI,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU,'' DC_KHAC,
        N12 TIEN_THVC,N13 TIEN_GDKD,N14 PHI_THVC,N15 PHI_GDKD,C29 MUC_MT_THVC,N17 MUC_MT_GDKD,C19 MA_SP,C7 NGAY_CAP FROM TEMP_1 order by C15,C7;
ELSE
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C23 TEN_LHNV,C31 RR_BH,C16 MA_DT,N9 MUC_MT,C29 MT_TIEN,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C33 DK_LUT,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N4 PHI,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU,'' DC_KHAC,
        N12 TIEN_THVC,N13 TIEN_GDKD,N14 PHI_THVC,N15 PHI_GDKD,C29 MUC_MT_THVC,N17 MUC_MT_GDKD,C19 MA_SP,C7 NGAY_CAP FROM TEMP_1,TEMP_BC_DVI,BH_HD_GOC
        WHERE C1=DVI AND C1=MA_DVI AND N1=SO_ID AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) order by C15,C7;
END IF;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,'loi:Loi BC_BH_TKE_PHH_PS:loi');
END;
/
DROP PROCEDURE BC_BH_TKE_PHH_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_PHH_MD
     (B_LOAI VARCHAR2,B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,
        B_MA_CB VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_TTRANG VARCHAR2,B_LOI OUT VARCHAR2)
AS
     b_ngay number:=30000101;
BEGIN
B_LOI:='loi:Loi BC_BH_TKE_PHH_MD:loi';
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
DELETE TEMP_1; 
IF B_LOAI='PS' THEN
    INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,C30,N30,C31,N9,C33,c5,c6,N31)
        SELECT  A.MA_DVI,DVI,NT_TIEN,LVUC,'' MT_KTR,PHONG,MA_CB,MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),a.SO_HD,'',a.NT_PHI,FBH_PHH_SP_TEN(MA_SP),A.TEN,A.SO_ID,
        KIEU_HD,SO_ID_D,FBH_PHH_NHOM_CAT(dt.NHOM),'' MT_TIEN,DK_LUT,ddiem,kvuc,b.so_id_dt
        FROM BH_PHH A,BH_PHH_DVI B,bh_phh_dtuong dt
        WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND dt.ma = b.ma_dt
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) order by a.SO_HD,a.NGAY_HT;
    UPDATE TEMP_1 SET (N12,N14)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PHH_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh<>'KH');
    UPDATE TEMP_1 SET (N13,N15)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PHH_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='KH');
ELSIF B_LOAI='SD' THEN
    INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,C30,N30,C31,N9,C33,c5,c6,c7,N31)
        SELECT  A.MA_DVI,DVI,NT_TIEN,LVUC,'' MT_KTR,PHONG,MA_CB,MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),a.SO_HD,'',a.NT_PHI,FBH_PHH_SP_TEN(MA_SP),A.TEN,A.SO_ID,
        KIEU_HD,SO_ID_D,FBH_PHH_NHOM_CAT(dt.NHOM),'' MT_TIEN,DK_LUT,ddiem,kvuc,PKH_SO_CNG(a.NGAY_CAP),b.so_id_dt
        FROM BH_PHH A,BH_PHH_DVI B,bh_phh_dtuong dt
        WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND dt.ma = b.ma_dt
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND KIEU_HD in ('B','S') order by a.SO_HD,a.NGAY_HT;
    UPDATE TEMP_1 SET (N16,N17)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PHH_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ' and lbh<>'KH');
    UPDATE TEMP_1 SET (N18,N19)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PHH_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh<>'KH');
    
    UPDATE TEMP_1 SET (N20,N21)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PHH_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ' and lbh='KH');
    UPDATE TEMP_1 SET (N22,N23)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PHH_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='KH');
    
    UPDATE TEMP_1 SET N12 = N18 - N16, N14 = N19 - N17;
    UPDATE TEMP_1 SET N13 = N22 - N20, N15 = N23 - N21;
END IF;
UPDATE TEMP_1 SET (N10)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='V');

UPDATE TEMP_1 SET (N11)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='D');
B_LOI:='';
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
CREATE OR REPLACE PROCEDURE BC_BH_TKE_PKT_PS
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_LOAI VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER;B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;
DELETE TEMP_1; COMMIT;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
BC_BH_TKE_PKT_MD(B_LOAI,B_MADVI,B_MA_DVI,B_MA_KH,B_MA_NV,B_PHONG,B_MA_CB,B_NGAYD,B_NGAYC,B_TTRANG1,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
UPDATE TEMP_1 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C9);
UPDATE TEMP_1 SET C21=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C12) WHERE C21 IS NULL;
UPDATE TEMP_1 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C10);
UPDATE TEMP_1 SET C27=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C11);

UPDATE TEMP_1 SET C32=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_1.C1);

SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C23 TEN_LHNV,C31 RR_BH,C16 MA_DT,N9 MUC_MT,C29 MT_TIEN,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C33 DK_LUT,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N4 PHI,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU,'' DC_KHAC,
        N12 TIEN_THVC,N13 TIEN_GDKD,N14 PHI_THVC,N15 PHI_GDKD,N16 TIEN_LNHUAN,N17 PHI_LNHUAN,C19 MA_SP,C7 NGAY_CAP FROM TEMP_1 order by C15,C7;
ELSE
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C23 TEN_LHNV,C31 RR_BH,C16 MA_DT,N9 MUC_MT,C29 MT_TIEN,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C33 DK_LUT,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N4 PHI,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU,'' DC_KHAC,
        N12 TIEN_THVC,N13 TIEN_GDKD,N14 PHI_THVC,N15 PHI_GDKD,N16 TIEN_LNHUAN,N17 PHI_LNHUAN,C19 MA_SP,C7 NGAY_CAP FROM TEMP_1,TEMP_BC_DVI,BH_HD_GOC
        WHERE C1=DVI AND C1=MA_DVI AND N1=SO_ID AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) order by C15,C7;
END IF;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
CREATE OR REPLACE PROCEDURE BC_BH_TKE_PKT_MD
     (B_LOAI VARCHAR2,B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,
        B_MA_CB VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_TTRANG VARCHAR2,B_LOI OUT VARCHAR2)
AS
     b_ngay number:=30000101;
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
DELETE TEMP_1;
IF B_LOAI='PS' THEN
    INSERT INTO TEMP_1(C1,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,C30,N30,N9,C33,c5,c6,c7,N31)
        SELECT  A.MA_DVI,NT_TIEN,DVI,'' MT_KTR,PHONG,MA_CB,MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,FBH_PKT_SP_TEN(MA_SP),A.TEN,A.SO_ID,
        KIEU_HD,SO_ID_D,'' MT_TIEN,DK_LUT,ddiem,kvuc,PKH_SO_CNG(a.NGAY_CAP),b.so_id_dt
        FROM BH_PKT A,BH_PKT_DVI B
        WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) order by SO_HD,NGAY_HT;
    UPDATE TEMP_1 SET (N12,N14)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='TS');
    UPDATE TEMP_1 SET (N13,N15)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='KH');
    UPDATE TEMP_1 SET (N16,N17)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='BI');
ELSIF B_LOAI='SD' THEN
    INSERT INTO TEMP_1(C1,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,C30,N30,N9,C33,c5,c6,c7,N31)
        SELECT  A.MA_DVI,NT_TIEN,DVI,'' MT_KTR,PHONG,MA_CB,MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,FBH_PKT_SP_TEN(MA_SP),A.TEN,A.SO_ID,
        KIEU_HD,SO_ID_D,'' MT_TIEN,DK_LUT,ddiem,kvuc,PKH_SO_CNG(a.NGAY_CAP),b.so_id_dt
        FROM BH_PKT A,BH_PKT_DVI B
        WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND KIEU_HD in ('B','S') order by SO_HD,NGAY_HT;
        
    UPDATE TEMP_1 SET (N28,N29)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ' and lbh='TS');
    UPDATE TEMP_1 SET (N18,N19)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='TS');
    
    UPDATE TEMP_1 SET (N20,N21)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ' and lbh='KH');
    UPDATE TEMP_1 SET (N22,N23)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='KH');
    
    UPDATE TEMP_1 SET (N24,N25)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ' and lbh='BI');
    UPDATE TEMP_1 SET (N26,N27)=(SELECT SUM(TIEN),SUM(PHI + THUE) FROM BH_PKT_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ' and lbh='BI');
    
    UPDATE TEMP_1 SET N12 = N18 - N28, N14 = N19 - N29;
    UPDATE TEMP_1 SET N13 = N22 - N20, N15 = N23 - N21;
    UPDATE TEMP_1 SET N16 = N26 - N24, N17 = N27 - N25;
END IF;
UPDATE TEMP_1 SET (N10)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='V');

UPDATE TEMP_1 SET (N11)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='D');
B_LOI:='';
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,'loi:Loi BC_BH_TKE_PKT_MD:loi');
END;
/
DROP PROCEDURE BC_BH_TKE_PTN_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_PTN_MD
     (B_LOAI VARCHAR2,B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,
        B_MA_CB VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Loi BC_BH_TKE_PTN_MD:loi';
DELETE TEMP_1; DELETE TEMP_6;
IF B_LOAI='PS' THEN 
    INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,C30,N30,C31,N9,C7)
        SELECT  A.MA_DVI,''LVUC_KD,NT_TIEN,''DVI,''MT_KTR,PHONG,ma_cb,a.MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,MA_SP,A.TEN,A.SO_ID,KIEU_HD,SO_ID_D,''RR_BH,''MT_TIEN,PKH_SO_CNG(a.NGAY_CAP)
        FROM bh_ptn A where (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
        
    UPDATE TEMP_1 SET (N12,N14)=(SELECT SUM(TIEN),SUM(PHI) FROM BH_PTN_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ');
ELSIF B_LOAI='SD' THEN  
        INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,C30,N30,C31,N9,C7)
        SELECT  A.MA_DVI,''LVUC_KD,NT_TIEN,''DVI,''MT_KTR,PHONG,ma_cb,a.MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,MA_SP,A.TEN,A.SO_ID,KIEU_HD,SO_ID_D,''RR_BH,''MT_TIEN,PKH_SO_CNG(a.NGAY_CAP)
        FROM bh_ptn A
        WHERE KIEU_HD in ('B','S') AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC); 
        
    UPDATE TEMP_1 SET (N28,N29)=(SELECT SUM(TIEN),SUM(PHI) FROM BH_PTN_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ');
    UPDATE TEMP_1 SET (N18,N19)=(SELECT SUM(TIEN),SUM(PHI) FROM BH_PTN_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ');
    
    UPDATE TEMP_1 SET N12 = N18 - N28, N14 = N19 - N29;  
END IF;

UPDATE TEMP_1 SET (C4)=(FBH_HD_TXT('PTN',C1,N1,'dtuong'));

UPDATE TEMP_1 SET (N10)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='V');

UPDATE TEMP_1 SET (N11)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='D');
B_LOI:='';
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_TKE_PTN_PS;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_PTN_PS
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_LOAI VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER;B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;
--PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
--IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_TKE_PTN_MD(B_LOAI,B_MADVI,B_MA_DVI,B_MA_KH,B_MA_NV,B_PHONG,B_MA_CB,B_NGAYD,B_NGAYC,B_LOI);
UPDATE TEMP_1 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C9);
UPDATE TEMP_1 SET C21=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C12) WHERE C21 IS NULL;
UPDATE TEMP_1 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C10);
UPDATE TEMP_1 SET C27=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C11);

UPDATE TEMP_1 SET C32=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_1.C1);

IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C19 MA_SP,C31 RR_BH,C16 MA_DT,N9 MUC_MT,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C7 NGAY_CAP,N12 TIEN,N14 PHI,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU FROM TEMP_1,BH_HD_GOC
        WHERE C1=MA_DVI AND N1=SO_ID AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) order by C15,C7;
ELSE
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C19 MA_SP,C31 RR_BH,C16 MA_DT,N9 MUC_MT,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C7 NGAY_CAP,N12 TIEN,N14 PHI,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU FROM TEMP_1,TEMP_BC_DVI,BH_HD_GOC
        WHERE C1=DVI AND C1=MA_DVI AND N1=SO_ID AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) order by C15,C7;
END IF;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
CREATE OR REPLACE PROCEDURE BC_BH_TKE_HOP_PS
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_LOAI VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER;B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE KET_QUA; COMMIT;
--PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
--IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_TKE_HOP_MD(B_LOAI,B_MADVI,B_MA_DVI,B_MA_KH,B_MA_NV,B_PHONG,B_MA_CB,B_NGAYD,B_NGAYC,B_LOI);
UPDATE TEMP_1 SET C23=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C9);
UPDATE TEMP_1 SET C21=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C12) WHERE C21 IS NULL;
UPDATE TEMP_1 SET C25=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C10);
UPDATE TEMP_1 SET C27=(SELECT TEN FROM HT_MA_CB WHERE MA_DVI=TEMP_1.C1 AND MA=TEMP_1.C11);

UPDATE TEMP_1 SET C32=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_1.C1);

IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C19 MA_SP,C31 RR_BH,C16 MA_DT,N9 MUC_MT,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C7 NGAY_CAP,N12 TIEN,N14 PHI,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU,'' DC_KHAC FROM TEMP_1,BH_HD_GOC
        WHERE C1=MA_DVI AND N1=SO_ID AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) order by C15,C7;
ELSE
    OPEN CS_KQ FOR SELECT C1 MA_DVI,C32 TEN_DVI,C12 MA_KH,C21 TEN_KH,C11 CB_QL,
        C27 TEN_CBQL,C10 PHONG, C25 TEN_PHONG,C9 LH_NV,C19 MA_SP,C31 RR_BH,C16 MA_DT,N9 MUC_MT,
        C15 SO_HD,C4 DOI_TUONG,C5 DDIEM,C20 LH_BH,C13 NGAY_HL,C14 NGAY_KT,PKH_SO_CNG(N8) NGAY_TT,C7 NGAY_CAP,N12 TIEN,N14 PHI,
        C17 NT_PHI,C3 NT_TIEN,N6 TIEN,N7 TYLE,N10 TYLE_DO_FO,N11 TYLE_DO_LE,C24 GHI_CHU,'' DC_KHAC FROM TEMP_1,TEMP_BC_DVI,BH_HD_GOC
        WHERE C1=DVI AND C1=MA_DVI AND N1=SO_ID AND (B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) order by C15,C7;
END IF;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
CREATE OR REPLACE PROCEDURE BC_BH_TKE_HOP_MD
     (B_LOAI VARCHAR2,B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,
        B_MA_CB VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1; DELETE TEMP_6;
IF B_LOAI='PS' THEN
    INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C21,N1,C30,N30,C31,N9,C7)
        SELECT  A.MA_DVI,''LVUC_KD,NT_TIEN,''DVI,''MT_KTR,PHONG,ma_cb,a.MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,A.TEN,A.SO_ID,KIEU_HD,SO_ID_D,''RR_BH,''MT_TIEN,PKH_SO_CNG(a.NGAY_CAP)
        FROM bh_hop A where (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) and nv='HOP';

    UPDATE TEMP_1 SET (N12,N14)=(SELECT SUM(TIEN),SUM(PHI) FROM BH_HOP_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ');
ELSIF B_LOAI='SD' THEN
        INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C10,C11,C12,C13,C14,C15,C16,C17,C21,N1,C30,N30,C31,N9,C7)
        SELECT  A.MA_DVI,''LVUC_KD,NT_TIEN,''DVI,''MT_KTR,PHONG,ma_cb,a.MA_KH,PKH_SO_CNG(a.NGAY_HL),
        PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,A.TEN,A.SO_ID,KIEU_HD,SO_ID_D,''RR_BH,''MT_TIEN,PKH_SO_CNG(a.NGAY_CAP)
        FROM bh_hop A
        WHERE KIEU_HD in ('B','S') AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) and nv='HOP';

    UPDATE TEMP_1 SET (N28,N29)=(SELECT SUM(TIEN),SUM(PHI) FROM BH_HOP_DK WHERE MA_DVI=C1 AND SO_ID=N30 AND LH_NV<>' ');
    UPDATE TEMP_1 SET (N18,N19)=(SELECT SUM(TIEN),SUM(PHI) FROM BH_HOP_DK WHERE MA_DVI=C1 AND SO_ID=N1 AND LH_NV<>' ');

    UPDATE TEMP_1 SET N12 = N18 - N28, N14 = N19 - N29;
END IF;

UPDATE TEMP_1 SET (C4)=(FBH_HD_TXT('HOP',C1,N1,'dtuong'));
UPDATE TEMP_1 SET (C19)=(FBH_HD_TXT('HOP',C1,N1,'ma_sp'));

UPDATE TEMP_1 SET (N10)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='V');

UPDATE TEMP_1 SET (N11)=(select sum(pt) from bh_hd_do_tl where ma_dvi=C1 and so_id=N30
        and so_id_dt in(0,N31) and pthuc='C' and FBH_DONG(C1,N30)='D');
B_LOI:='';
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

-- chuclh: fix kieu
DROP PROCEDURE BC_BH_TKE_XE_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_XE_MD
    (b_loai varchar2,b_madvi varchar2,b_ma_dvi varchar2,b_ma_kh varchar2,b_ma_nv varchar2,b_phong varchar2,b_ma_cb varchar2,b_ngayd number,b_ngayc number,b_loi out varchar2)
as
   b_ghi_chu nvarchar2(200);
begin
-- Modull bao cao thong ke tai san ky thuat cho truong hop co mot don vi
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; return;
end if;
b_loi:='loi:Ma chua dang ky r4:loi';
/*
    temp_1  c1 ma_dvi,c2 so_hd,c3 gcn, c4 bien_xe,c5 hieu_xe,c6 ten,c7 ngay_hl,c8 ngay_kt,n1 so_id,n2 nam_sx, n3 so_cho,
        n4 ty_le_do_fo,n5 ty_le_do_le,c9 nt_tien n6 tien, c10 nt_phi, n7 phi_dt,c18 dk_bs, n8 ngay_tt, c11 lh_nv,n10 so_id_dt,
        c13 ma_kh,c14 phong,c15 ma_cb,c16 nha_bh,c17 ghi_chu, c19 xe_sx, c20 ten_dvi_do, c21 ten_nh_bh, c18 dk_bs
*/
delete temp_1; delete temp_6;
if b_loai='PS' then --/*+ parallel(4) */
    insert into temp_1(c1,c3,c4,c5,c6,c7,c8,n1,n2,n3,c9,n6,c10,n7,n10,c22)
        select  a.ma_dvi,a.gcn,a.bien_xe,a.hieu,tenc,PKH_SO_CNG(ngay_hl),PKH_SO_CNG(ngay_kt),
            a.so_id,a.nam_sx,a.so_cn,''nt_tien,sum(b.tien),''nt_phi,sum(b.ttoan),a.so_id_dt,PKH_SO_CNG(ngay_cap)
            from bh_xe_ds a,bh_xe_dk b  where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id --and kieu_hd='G'
            and (b_ma_dvi is null or a.ma_dvi = b_ma_dvi) and (b_ma_nv is null or lh_nv like  b_ma_nv||'%') and (a.ngay_cap between b_ngayd and b_ngayc)
            group by a.ma_dvi,a.gcn,a.bien_xe,a.hieu,tenc,ngay_hl,ngay_kt,a.so_id,a.nam_sx,a.so_cn,a.so_id_dt,ngay_cap;
end if;
update temp_1 set (c2,c30,n30,c12,c13,c14)=(select so_hd,kieu_hd,so_id_g,ma_kh,phong,ma_cb from bh_xe where ma_dvi=c1 and so_id=n1
    and (ngay_ht between b_ngayd and b_ngayc) and (b_ma_cb is null or ma_cb = b_ma_cb)
    and (b_phong is null or phong = b_phong) and (b_ma_kh is null or ma_kh = b_ma_kh));
update temp_1 set n8=(select max(ngay_tt) from bh_hd_goc_ttpt where ma_dvi=c1 and so_id=n1 and pt<>'C');
update temp_1 set n4=(select a.pt from bh_hd_do_tl a, bh_hd_do b  where a.ma_dvi=c1 and a.so_id=n1 and b.kieu='V');
update temp_1 set n5=(select a.pt from bh_hd_do_tl a, bh_hd_do b where a.ma_dvi=c1 and a.so_id=n1 and b.kieu='D');
update temp_1 set c16 =(select max(nha_bh) from bh_hd_do_tl where ma_dvi=c1 and so_id=n1);
update temp_1 set c20 =(select ten from bh_hd_do_tl a, ht_ma_dvi b where ma_dvi=c1 and so_id=n1
    and b.ma=a.nha_bh and c16=b.ma and pthuc='D');
update temp_1 set c21 =(select ten from bh_hd_do_tl a, tbh_ma_nbh b where a.ma_dvi=c1 and a.ma_dvi=b.ma_dvi and so_id=n1
    and b.ma=a.nha_bh and c16=b.ma and pthuc='C');
update temp_1 set c17 =(select decode(pthuc,'C',c21,c20)||' Ty le '|| pt from bh_hd_do_tl where ma_dvi=c1 and so_id=n1 and pt<100);

update temp_1 set c18=(select min(ma) from bh_hd_goc_dkbs where ma_dvi=c1 and so_id=n1);--BCNam
update temp_1 set c19=c5||'/'||n2;

if b_ma_cb is not null then
    delete temp_1 where c15 is null;
end if;
if b_ma_kh is not null then
    delete temp_1 where c13 is null;
end if;
if b_phong is not null then
    delete temp_1 where c14 is null;
end if;

b_loi:='';
exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_BH_TKE_XE_PS;

CREATE OR REPLACE PROCEDURE BC_BH_TKE_XE_PS
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_loai varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_ttrang varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number;b_i1 number;b_ttrang1 varchar2(10);
Begin
-- Nga--Bang ke don bao hiem phat sinh
--b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
--if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;delete temp_2;delete ket_qua; commit;

PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
BC_BH_TKE_XE_MD(b_loai,b_madvi,b_ma_dvi,b_ma_kh,b_ma_nv,b_phong,b_ma_cb,b_ngayd,b_ngayc,b_loi);

update temp_1 set c23=(select ten from bh_ma_lhnv where ma_dvi=temp_1.c1 and ma=temp_1.c11);
--update temp_1 set c21=(select ten from bh_hd_ma_kh where ma_dvi=temp_1.c1 and ma=temp_1.c12) where c21 is null;
--update temp_1 set c25=(select ten from ht_ma_phong where ma_dvi=temp_1.c1 and ma=temp_1.c10);
--update temp_1 set c27=(select ten from ht_ma_cb where ma_dvi=temp_1.c1 and ma=temp_1.c11);
--update temp_1 set c28=(select ten from bh_ma_ldt where ma_dvi=temp_1.c1 and ma=temp_1.c16);
update temp_1 set c32=(select ten from ht_ma_dvi where ma=temp_1.c1);
if b_ttrang<>'*' then b_ttrang1:=b_ttrang; end if;

  --  temp_1  c1 ma_dvi,c32 ma_dvi,c2 so_hd,c3 gcn, c4 bien_xe,c5 hieu_xe,c6 ten,c7 ngay_hl,c8 ngay_kt,n1 so_id,n2 nam_sx, n3 so_cho,
  --      n4 ty_le_do_fo,n5 ty_le_do_le,c9 nt_tien n6 tien, c10 nt_phi, n7 phi_dt,c18 dk_bs, n8 ngay_tt, c11 lh_nv,n10 so_id_dt

select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    open cs_kq for select c1 ma_dvi,c32 ten_dvi,c6 ten_kh,c11 lh_nv,c23 ten_lhnv,c22 ngay_cap,
        c2 so_hd,c7 ngay_hl,c8 ngay_kt,c9 nt_tien,n6 tien,c10 nt_phi,n7 phi,n4 tyle_do_fo,n5 tyle_do_le,
        n3 so_cn,c4 bien_xe,c3 gcn,n2 nam_sx,c5 hieu_xe,c18 dk_bs,c19 xe_sx,PKH_SO_CNG(n8) ngay_tt,c17 ghi_chu from temp_1,bh_hd_goc
        where c1=ma_dvi and n1=so_id and (b_ttrang1 is null or ttrang=b_ttrang1);
else
    open cs_kq for select c1 ma_dvi,c32 ten_dvi,c6 ten_kh,c11 lh_nv,c23 ten_lhnv,c22 ngay_cap,
        c2 so_hd,c7 ngay_hl,c8 ngay_kt,c9 nt_tien,n6 tien,c10 nt_phi,n7 phi,n4 tyle_do_fo,n5 tyle_do_le,
        n3 so_cn,c4 bien_xe,c3 gcn,n2 nam_sx,c5 hieu_xe,c18 dk_bs,c19 xe_sx,PKH_SO_CNG(n8) ngay_tt,c17 ghi_chu from temp_1,temp_bc_dvi,bh_hd_goc
        where c1=dvi and c1=ma_dvi and n1=so_id and (b_ttrang1 is null or ttrang=b_ttrang1);
end if;
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_TK_BT_TAU;

CREATE OR REPLACE PROCEDURE BC_BH_TK_BT_TAU
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_TTRANG VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER;B_I1 NUMBER;B_TTRANG1 VARCHAR2(10);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF FHT_MA_NSD_PHONG(B_MA_DVI,B_NSD)='TBH' THEN
    B_LOI:='loi:ban khong co quyen xem bao cao:loi';
    RAISE PROGRAM_ERROR;
END IF;

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;DELETE KET_QUA; COMMIT;

PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao boi thuong:loi'; RAISE PROGRAM_ERROR;
END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='TAU';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem nghiep vu nay:loi'; RAISE PROGRAM_ERROR;
END IF;
PBC_LAY_DVI(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
BC_BH_THBT_MD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,'','','',B_NGAYD,B_NGAYC,B_LOI,'B');

IF B_TTRANG<>'*' THEN B_TTRANG1:=B_TTRANG; END IF;
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_DVI;
IF B_I1=0 THEN
    INSERT INTO TEMP_2 (C1,C3,C8,C9,C12,C13,C14,N1,N2,N3,N6,N8) SELECT C29,C6,C12,C13,C2,C4,C7,N13,N10,N4,N6,N8
        FROM TEMP_1,BH_HD_GOC WHERE C29=MA_DVI AND N13=SO_ID AND FBC_HD_NV(C29,N13)=('HANG') AND(B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1);
ELSE
    INSERT INTO TEMP_2 (C1,C3,C8,C9,C12,C13,C14,N1,N2,N3,N6,N8) SELECT C29,C6,C12,C13,C2,C4,C7,N13,N10,N4,N6,N8
        FROM TEMP_1,TEMP_BC_DVI,BH_HD_GOC WHERE FBC_HD_NV(C29,N13)=('HANG') AND C29=MA_DVI AND N13=SO_ID AND
        C29=DVI AND(B_TTRANG1 IS NULL OR TTRANG=B_TTRANG1) ;
END IF;

--SELECT COUNT(*) INTO B_I1 FROM TEMP_2;
--IF B_I1>65000 THEN
--    B_LOI:='loi:So dong bao cao > 65000. Lien he voi Tin hoc de tro giup:loi'; RAISE PROGRAM_ERROR;
--END IF;


UPDATE TEMP_2 SET (C6,C7)=(SELECT TEN_TAU,TENc FROM BH_TAU_ds WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N1 AND SO_ID_DT=TEMP_2.N8);

UPDATE TEMP_2 SET C4=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C3);
UPDATE TEMP_2 SET C2=(SELECT TEN FROM HT_MA_DVI WHERE MA=TEMP_2.C1);

UPDATE TEMP_2 SET N7 =(SELECT SUM(TTOAN_QD) FROM BH_BT_GD_HS WHERE MA_DVI=TEMP_2.C1 AND SO_ID_BT=TEMP_2.N2);

UPDATE TEMP_2 SET N8 =(SELECT SUM(TTOAN_QD) FROM BH_CP WHERE MA_DVI=TEMP_2.C1 AND SO_HD=TEMP_2.C13);

UPDATE TEMP_2 SET N9= (SELECT SUM(TIEN) FROM BH_BT_NTBA_PS WHERE MA_DVI=TEMP_2.C1 AND SO_ID=TEMP_2.N2);

UPDATE TEMP_2 SET C10=(SELECT TEN FROM BH_MA_NN WHERE  MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C8);
UPDATE TEMP_2 SET C11=(SELECT TEN FROM BH_MA_MD WHERE  MA_DVI=TEMP_2.C1 AND MA=TEMP_2.C9);
OPEN CS_KQ FOR SELECT  C1 MA_DVI,C2 TEN_DVI,C3 PHONG,C4 TEN_PHONG,C12 SO_HS,C13 SO_HD,C7 CHU_TAU,C6 TEN_TAU,C14 NGAY_XR,C10 NGUYEN_NHA,
    C11 MUC_DO,N3 STTT,N4 GD1,N5 CP1,N6 STBT ,N7 GD2,N8 CP2,N9 DOI_NT3 FROM TEMP_2;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE BC_BH_TK_TAU_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TK_TAU_MD
    (b_madvi varchar2,b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
Begin
--BCNam: Module bao cao thong ke tau thuyen
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; return;
end if;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;
--tau  theo hop dong
insert into temp_1( c1,c2,c3,c4,c16,c6,c7,c8,c9,c10,c11,c15,n1,n2,n3,n4,n5,c22,c19,c14,c17,c25,c24,n6,c26,c27)
    select  a.ma_dvi,c.TEN_TAU,c.CAP,c.LOAI,to_char(c.NAM_SX),c.VLIEU,''PVI_HDONG,''CLB_BH,TTAI||'-'||CSUAT,a.nt_tien,a.nt_phi,
    c.gcn,a.so_id,c.gia,b.so_id_dt,sum(b.tien),sum(b.phi),'TAU',b.ma_dk,''KTRU,''mien_thuong,b.lh_nv,c.nhom,
    max(FBH_DONG_TL_DT(a.ma_dvi,a.so_id,b.so_id_dt,b.lh_nv)),PKH_SO_CNG(a.NGAY_HL),PKH_SO_CNG(a.NGAY_KT)
    from bh_tau a,BH_TAU_DK b,temp_bc_dvi tdv,bh_tau_ds c where
    (b_ma_dvi is null or a.ma_dvi =tdv.dvi)
    and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and (b_ma_nv is null or lh_nv like b_ma_nv||'%' )
    and b.ma_dvi=c.ma_dvi and b.so_id=c.so_id and c.so_id_dt=c.so_id_dt
    and a.so_id in (select so_id from bh_tau where (b_ma_dvi is null or ma_dvi =tdv.dvi)  and ngay_ht between b_ngayd and b_ngayc and (b_phong is null or phong=b_phong)) 
    and a.so_id=FBH_HD_SO_ID_BS(a.ma_dvi,a.so_id,b_ngayc)
    group by a.ma_dvi,c.TEN_TAU,c.CAP,c.LOAI,c.NAM_SX,c.VLIEU,TTAI||'-'||CSUAT,
    a.so_id,c.gia,b.so_id_dt,a.nt_tien,a.nt_phi,b.ma_dk,b.lh_nv,c.gcn,c.nhom,--c.CLB_BH,b.MIEN_THUONG,KTRU,
    PKH_SO_CNG(a.NGAY_HL),PKH_SO_CNG(a.NGAY_KT);
--tau  theo le select * from BH_TAU_DK
--insert into temp_1( c1,c2,c3,c4,c16,c6,c7,c8,c9,c10,c11,c15,n1,n2,n3,n4,n5,c22,c19,c14,c17,c25,c24,n6,c26,c27)
--    select  a.ma_dvi,TEN_TAU,CAP_TAU,LOAI_TAU,
--    to_char(NAM_SX),VLIEU,PVI_HDONG,CLB_BH,NT_KBAO,
--    b.nt_tien,b.nt_phi,a.so_hd,a.so_id,GIA_TAU,a.so_id,sum(b.tien),sum(b.phi),'TAUL',b.ma_dk,b.mt_ktr,b.mt_chu,
--    b.lh_nv,a.nhom_tau, max(FBH_DONG_TL_DT(a.ma_dvi,a.so_id,0,b.lh_nv)),PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT)
--    from bh_taulgcn a,bh_taulgcn_dk b,temp_bc_dvi tdv where --(b_ma_dvi is null or a.ma_dvi like tdv.dvi||'%')
--    (b_ma_dvi is null or a.ma_dvi =tdv.dvi)
--    and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id  and (b_ma_nv is null or  lh_nv like b_ma_nv||'%')
--    and a.ngay_ht between b_ngayd and b_ngayc 
--    and a.so_id=FBH_HD_SO_ID_BS(a.ma_dvi,a.so_id,b_ngayc)
--    and (b_phong is null or phong=b_phong)
--    group by a.ma_dvi,TEN_TAU,CAP_TAU,LOAI_TAU,NAM_SX,VLIEU,PVI_HDONG,CLB_BH,NT_KBAO, a.so_id,GIA_TAU,
--        a.so_id,b.nt_tien,b.nt_phi,pt,b.ma_dk,b.mt_ktr,b.mt_chu,b.lh_nv,a.so_hd,a.nhom_tau,
--        PKH_SO_CNG(NGAY_HL),PKH_SO_CNG(NGAY_KT);

delete from temp_1 where n1 in (Select so_id from bh_hd_goc where kieu_hd='V');
commit;
b_loi:='';
--exception when others then null;
end;
/

DROP PROCEDURE BC_BH_TK_TN_MD;

CREATE OR REPLACE PROCEDURE BC_BH_TK_TN_MD
	(B_MADVI VARCHAR2,B_MA_DVI VARCHAR2,B_MA_KH VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,B_LOI OUT VARCHAR2)
AS
BEGIN

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
	B_LOI:='loi:Nhap ngay bao cao:loi'; RETURN;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';

DELETE TEMP_1;
DELETE TEMP_6;
COMMIT;
--
--INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C9,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,N2,N6,N7,N3,N4,N5,C30,N30,C31)
--	SELECT  A.MA_DVI,''LVUC,NT_TIEN,DVI,''MT_KTR,LH_NV,PHONG,MA_CB,a.MA_KH,PKH_SO_CNG(a.NGAY_HL),
--	PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,MA_sp,A.TEN,A.SO_ID,TIEN,b.TIEN,PT,b.THUE,b.TTOAN,b.PHI,KIEU_HD,SO_ID_G,''RR_BH
--	FROM bh_ptn A,bh_ptn_dk B,bh_ptn_ds c  WHERE b.ma_dvi=c.ma_dvi and b.so_id=c.so_id and b.so_id_dt=c.so_id_dt and A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID
--	AND (B_MA_DVI IS NULL OR A.MA_DVI = B_MA_DVI) 	AND (B_MA_KH IS NULL OR A.MA_KH = B_MA_KH) 
--	AND (B_MA_NV IS NULL OR LH_NV LIKE  B_MA_NV||'%') 
--	AND (B_PHONG IS NULL OR A.PHONG = B_PHONG) AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C9,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,N2,N6,N7,N3,N4,N5,C30,N30,C31)
	SELECT  A.MA_DVI,''LVUC,NT_TIEN,''DVI,''MT_KTR,LH_NV,PHONG,MA_CB,a.MA_KH,PKH_SO_CNG(a.NGAY_HL),
	PKH_SO_CNG(a.NGAY_KT),SO_HD,'',a.NT_PHI,MA_sp,A.TEN,A.SO_ID,b.TIEN,b.TIEN,PT,b.THUE,b.TTOAN,b.PHI,KIEU_HD,SO_ID_G,''RR_BH
	FROM bh_ptn A,bh_ptn_dk B WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID
	AND (B_MA_DVI IS NULL OR A.MA_DVI = B_MA_DVI) 	AND (B_MA_KH IS NULL OR A.MA_KH = B_MA_KH) 
	AND (B_MA_NV IS NULL OR LH_NV LIKE  B_MA_NV||'%') 
	AND (B_PHONG IS NULL OR A.PHONG = B_PHONG) AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);


INSERT INTO TEMP_6(C1,C2,C3,C4,C8,C9,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,N2,N6,N7,N3,N4,N5,C30,N30,C31)
	 SELECT C1,C2,C3,C4,C8,C9,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,N2,N6,N7,N3,N4,N5,C30,N30,C31 FROM TEMP_1 WHERE C30='B';

INSERT INTO TEMP_1(C1,C2,C3,C4,C8,C9,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,N2,N6,N7,N3,N4,N5,C31)
	SELECT  C1,C2,C3,C4,C8,C9,C10,C11,C12,C13,C14,C15,C16,C17,C19,C21,N1,N2,-b.TIEN,PT,-b.THUE,-b.TTOAN,-b.PHI,C31
	FROM bh_ptn A,bh_ptn_dk B,TEMP_6 C  WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID AND A.MA_DVI=C.C1 AND A.SO_ID=C.N30;


UPDATE TEMP_1 SET C5 =(SELECT DCHI FROM bh_ptn WHERE MA_DVI=TEMP_1.C1 AND SO_ID=TEMP_1.N1);-- AND DVI=TEMP_1.C4);--DDIEM
--UPDATE TEMP_1 SET C6 =(SELECT KVUC FROM bh_ptn_Ds WHERE MA_DVI=TEMP_1.C1 AND SO_ID=TEMP_1.N1 AND DVI=TEMP_1.C4);
UPDATE TEMP_1 SET C7 =0;
--LAM SACH
-- UPDATE TEMP_1 SET C20 =(SELECT MIN(TEN) FROM BH_PTN_PHI_CT WHERE MA_DVI=TEMP_1.C1 AND MA_NHOM=TEMP_1.C19 AND LH_NV=C9);
B_LOI:='';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/
