CREATE OR REPLACE PROCEDURE BC_BH_TK_TSKT_MD
    (b_madvi varchar2,b_ma_dvi varchar2,b_ma_kh varchar2,b_ma_nv varchar2,b_phong varchar2,b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
