    select  a.ma_dvi,''LVUC_KD,NT_Tien,''DVI,'' mt_ktr,lh_nv,phong,'' cb_ql,ma_kh,PKH_SO_CNG(ngay_hl),
    PKH_SO_CNG(ngay_kt),so_hd,'',A.nt_phi,MA_SP,a.ten,a.so_id,b.tien,b.tien,pt,B.thue,B.ttoan,B.phi,kieu_hd,so_id_g,
    PKH_SO_CNG(ngay_cap),'' rr_bh,b.so_id_dt,a.ngay_ht
    from bh_phh a,bh_phh_dk b
    where  a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id=a.so_id
    and (b_ma_dvi is null or a.ma_dvi = b_ma_dvi) and (b_ma_kh is null or a.ma_kh = b_ma_kh)
    and (b_ma_nv is null or lh_nv like  b_ma_nv||'%')
