DROP PROCEDURE BC_BH_TUOI_NO;
CREATE OR REPLACE PROCEDURE BC_BH_TUOI_NO
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_loai varchar2,
    b_phong varchar2,b_tc varchar2,b_ngayc number,cs_kq out pht_type.cs_type,
    b_tennv out varchar2,b_tenloai out varchar2,b_ten_phong out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number;b_nam number;b_ngaycn number;b_i1 number;
Begin
-- Bao cao chi tiet tuoi no
-- Kieu: C- lay bao cao theo tong nghiep vu,K- khong lay bao cao theo tong nghiep vu
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_loi:='loi:Ma chua dang ky:loi';
if b_loai is not null  and b_ma_dvi is not null then
    select ten into b_tenloai from kh_ma_loai_dn where ma_dvi=b_ma_dvi and ma=b_loai;
else b_tenloai:=' ';
end if;
if b_phong is not null and b_ma_dvi is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_phong;
else b_ten_phong:=' ';
end if;
delete temp_1;delete temp_2;delete temp_3;delete temp_4;delete ket_qua;commit;
/* c1 ma_dvi,c2 ten_dvi,c3 so_hd,c4 ma_kh,c5 ten_kh,c6 ma_nv,c7 ten_nv,c8 ngay_ky,n1 dtth,n2 phi
c11 ma_dl,c15 ten_dl, c12 ngay_cap don, c13,c14  hieu luc ngay, han thanh toan,c20 hoa don,c21 ngay_hoa don,so ngay qua han tt,so ngay qua han cho no */
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
--lay cac don con no phi den ngayc
select count(*) into b_i1 from temp_bc_dvi;
/*
if b_i1=0 then
    insert into temp_1(c1,n1,c2,n2) select ma_dvi,so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_no
        where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht<=b_ngayc
        group by ma_dvi,so_id,ma_nt;
else
    insert into temp_1(c1,n1,c2,n2) select ma_dvi,so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_no, temp_bc_dvi
        where ma_dvi=dvi and ngay_ht<=b_ngayc
        group by ma_dvi,so_id,ma_nt;
end if;
update temp_1 set n3=(select ton_qd from bh_hd_goc_sc_no where ma_dvi=c1 and so_id=n1 and ngay_ht=n2 and ma_nt=c2);
delete temp_1 where n3=0;
*/
if b_i1=0 then
    insert into temp_1(c1,n1,c2,n2,n3)
        select sc.ma_dvi,sc.so_id,sc.ma_nt,sc.ngay_ht,sc.ton_qd from bh_hd_goc_sc_no sc,
            (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no, temp_bc_dvi
                where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht<=b_ngayc
                group by ma_dvi,so_id,ma_nt) ng
            where sc.ma_dvi=ng.ma_dvi and sc.so_id=ng.so_id and sc.ma_nt=ng.ma_nt and sc.ngay_ht=ng.ngay_ht
            and sc.ton_qd<>0;
else
    insert into temp_1(c1,n1,c2,n2,n3)
        select sc.ma_dvi,sc.so_id,sc.ma_nt,sc.ngay_ht,sc.ton_qd from bh_hd_goc_sc_no sc,
            (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no, temp_bc_dvi
                where ma_dvi=dvi and ngay_ht<=b_ngayc
                group by ma_dvi,so_id,ma_nt) ng
            where sc.ma_dvi=ng.ma_dvi and sc.so_id=ng.so_id and sc.ma_nt=ng.ma_nt and sc.ngay_ht=ng.ngay_ht
            and sc.ton_qd<>0;
end if;        

insert into temp_4(c1,n1,c2,n2,n4,n3) select a.ma_dvi,a.so_id,a.ma_nt,b.n2,a.ngay,sum(decode(a.pt,'C',a.ttoan_qd,-a.ttoan_qd))
    from bh_hd_goc_ttpt a,temp_1 b where a.ma_dvi=b.c1 and a.so_id=b.n1 and a.ma_nt=b.c2 and a.ngay_tt<=b_ngayc and a.pt in ('C','N') 
    group by a.ma_dvi,a.so_id,a.ma_nt,b.n2,a.ngay;

insert into temp_2(c1,c3,c4,c6,c11,c12,d3,d4,n1,n2,n3,n4,n5,n6,n10)
    select goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,ma_kt,PKH_SO_CNG(ngay_cap),PKH_SO_CDT(ngay_hl),PKH_SO_CDT(ngay_kt),
    sum(n3),0,n2,goc.ngay_ht,1,n4,so_id from bh_hd_goc goc,temp_4 where goc.ma_dvi=c1 and goc.so_id=n1
    --and (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi) 
    and (b_phong is null or phong=b_phong)
    group by goc.ma_dvi,goc.so_hd,goc.ma_kh,nv,n2,goc.ngay_ht,so_id,ma_kt,ngay_cap,ngay_hl,ngay_kt,n4;
if b_ma_nv is null then
    insert into ket_qua(c10,c1,c3,c4,c6,c8,c11,c12,d3,d4,n1,n2,n3,n4,n6,n10)
        select to_char(n5),c1,c3,c4,c6,c8,c11,c12,d3,d4,sum(n1),sum(n2),n3,n4,n6,n10
        from temp_2 group by c1,c3,c4,c6,c8,c11,c12,d3,d4,n3,n4,n5,n6,n10 order by n5;
else
    delete temp_3;
    insert into temp_3 (c1,n10) select distinct c1,n10 from temp_2 a,bh_hd_goc_dk b
        where a.c1=b.ma_dvi and n10=so_id and lh_nv like b_ma_nv||'%';
    insert into ket_qua(c10,c1,c3,c4,c6,c8,c11,c12,d3,d4,n1,n2,n3,n4,n6,n10)
        select to_char(n5),c1,c3,c4,c6,c8,c11,c12,d3,d4,sum(n1),sum(n2),n3,n4,n6,n10
        from temp_2 a,(select c1 ma_dvi,n10 so_id from temp_3) b
        where c1=ma_dvi and n10=so_id group by c1,c3,c4,c6,c8,c11,c12,d3,d4,n3,n4,n5,n6,n10 order by n5;
end if;
delete ket_qua where n1 is null and n2 is null;
update ket_qua set (c20,c21)=(select so_don,PKH_SO_CNG(ngay_ht) from bh_hd_goc_vat a,bh_hd_goc_vat_ct b
    where a.ma_dvi=b.ma_dvi and a.so_id_vat=b.so_id_vat and a.ma_dvi=ket_qua.c1 and b.so_id=n10 and rownum=1);

update ket_qua set c2=(select ten from ht_ma_dvi where ma=ket_qua.c1);
update ket_qua set (c15)=(select ten from bh_dl_ma_kh where ma_dvi=ket_qua.c1 and ma=ket_qua.c11);
--update ket_qua set (c5,c30)=(select ten,loai from bh_hd_ma_kh where ma_dvi=ket_qua.c1 and ma=ket_qua.c4);

/*
update
       (select ket_qua.c2 ket_qua_c2, ht_ma_dvi.ten ht_ma_dvi_ten
              from ket_qua, ht_ma_dvi
             where ket_qua.c1 = ht_ma_dvi.ma)
       set ket_qua_c2 = ht_ma_dvi_ten;
update
       (select ket_qua.c15 ket_qua_c15, bh_dl_ma_kh.ten bh_dl_ma_kh_ten
              from ket_qua, bh_dl_ma_kh
             where ket_qua.c1 = bh_dl_ma_kh.ma_dvi and ket_qua.c11 = bh_dl_ma_kh.ma)
       set ket_qua_c15 = bh_dl_ma_kh_ten;
*/
update
       (select ket_qua.c5 ket_qua_c5, ket_qua.c30 ket_qua_c30, bh_hd_ma_kh.ten bh_hd_ma_kh_ten, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from ket_qua, bh_hd_ma_kh
             where ket_qua.c1 = bh_hd_ma_kh.ma_dvi and ket_qua.c4 = bh_hd_ma_kh.ma)
       set ket_qua_c5 = bh_hd_ma_kh_ten, ket_qua_c30 = bh_hd_ma_kh_loai;

--n7 so ngay qua han ky thanh toan
update ket_qua set n7=PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n6);
--n8 so ngay qua han ky thanh toan
update ket_qua set n8=PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(n3);
--so ngay con lai so voi ngay cuoi bao cao
update ket_qua set n9=d4-PKH_SO_CDT(b_ngayc);
commit;
open cs_kq for select c1 as ma_dvi, c2 as ten_dvi,c4 as ma_kh,
    c5 as ten_kh,c11 as ma_dl, c15 as ten_dl,c3 as so_hd,c12 ngay_cap,to_char(d3,'dd/mm/yyyy') ngay_hl,to_char(d4,'dd/mm/yyyy') ngay_kt,
    PKH_SO_CNG(n6) han_tt,c20 so_hdon,c21 ngay_hd,n7 so_ngay_qhtt,n8 so_ngay_qhcn, n9 so_ngay_cl, nvl(n1,0) phi
    from ket_qua where (b_loai is null or c30 like b_loai||'%');
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_XE;

CREATE OR REPLACE PROCEDURE BC_BH_XE
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_dvi varchar2,
    b_ngayd number,b_ngayc number,
    b_ma_kh varchar2,b_ma_nv varchar2,b_so_hd_g varchar2,b_phong varchar2,b_hieu_xe varchar2,
    b_ma_bh varchar2,b_ma_dl varchar2,cs_kq out pht_type.cs_type,b_ten_kh out varchar2,b_dchi out varchar2)
as
    b_loi varchar2(100);b_ngaydn number;b_ngaydnt number;b_ngayct number;
    b_ngaycn number;b_711 varchar2(10);b_712 varchar2(10);b_713 varchar2(10);
    b_714 varchar2(10);b_715 varchar2(10);b_ma_khh varchar(50);b_i1 number;
begin
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise program_error; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:nhap ngay bao cao:loi'; raise program_error;
end if;
delete temp_1;
delete temp_3;
commit;
if b_ma_kh is not null then
    select ten,dchi into b_ten_kh,b_dchi from bh_hd_ma_kh where ma_dvi=b_madvi and  ma=b_ma_kh;
end if;
b_loi:='loi:ma chua dang ky:loi';

--select lh_nv into b_714 from bh_xe_phi_ct where ma_dvi=ftbh_dvi_ta() and loai='TV' and rownum=1; bh_xelgcn

if b_ma_dl is not null then
    insert into temp_3 (c1,c2) select distinct ma_dvi,ma from bh_dl_ma_kh where (b_ma_dvi is null or ma_dvi = b_ma_dvi)
        start with nvl(ma,' ')=b_ma_dl connect by prior ma=ma_ct;
    insert into temp_3 (c1,c2) values(b_ma_dvi,b_ma_dl);
else
    insert into temp_3 (c1,c2) select distinct ma_dvi,ma from bh_dl_ma_kh where (b_ma_dvi is null or ma_dvi = b_ma_dvi);
end if;

insert into temp_1(c30,c27,c28,n20,n29,c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,c11,n1,n2,c12,c13,c18,
n4,n5,n3,c16,c39,c40,n30)--,n6,n7,n8,n9,n10,n11,n12,n13
select a.ma_dvi,c.kieu_kt,c.ma_kt,a.so_id,a.so_id_dt,a.gcn,c.so_hd,c.ma_kh,c.ten,nv_bh,a.tenc,a.dchic,
a.hieu,a.bien_xe,a.so_khung,a.so_may,a.so_cn,a.ttai,PKH_SO_CNG(a.ngay_hl),PKH_SO_CNG(a.ngay_kt),PKH_SO_CNG(a.ngay_cap),
b.phi,b.thue,b.tien,
ma_dk,nam_sx,loai_xe,gia
from bh_xe_ds a,bh_xe_dk b, bh_hd_goc c
where (b_ma_dvi is null or a.ma_dvi=b_ma_dvi) and a.ma_dvi=b.ma_dvi and a.ma_dvi=c.ma_dvi
and a.so_id=b.so_id and a.so_id=c.so_id and a.so_id_dt=b.so_id_dt and kieu_hd in('G','T') and ttrang='D'
and (b_phong is null or c.phong=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
and (b_hieu_xe is null or a.hieu=b_hieu_xe)
and (b_so_hd_g is null or c.so_hd=b_so_hd_g)  and (b_ma_kh is null or c.ma_kh=b_ma_kh)
and c.ngay_ht between b_ngayd and b_ngayc;
--group by a.ma_dvi,c.kieu_kt,c.ma_kt,a.so_id,a.so_id_dt,a.gcn,c.so_hd,c.ma_kh,c.ten,a.tenc,a.dchic,nv_bh,
--a.hieu,a.bien_xe,a.so_khung,a.so_may,a.so_cn,a.ttai,a.ngay_hl,a.ngay_kt,a.ngay_cap,a.nam_sx,a.loai_xe,gia,ma_dk;

update temp_1 set c19 = (select max(ten) from bh_ma_dk where c30=ma_dvi and c16=ma);

open cs_kq for
select  a.c1 so_hd, a.c2 so_hd_g,a.c3 ma_kh, a.c4 ten_kh,a.c5 nv_bh
, a.c6 ten_cxe,a.c7 d_chi_cx,a.c16 ma_dk,a.c19 ten_dk,a.c17 ten_loai,a.c8 hieu_xe, a.c9 bien_xe,a.c10 so_khung,a.c11 so_may,a.c39 nam_sx,a.c40 loai_xe,
nvl(a.n1,0) so_cn,nvl(a.n2,0) t_tai,a.n30 gia,a.c12 ngay_hl,a.c13 ngay_kt,
nvl(sum(a.n4),0) phi,nvl(sum(a.n5),0) thue,nvl(sum(a.n3),0) tien_bh
--    nvl(sum(a.n4),0) phi711,nvl(sum(a.n5),0) thue711,nvl(sum(a.n6),0) phi712,nvl(sum(a.n7),0) thue712,
--    nvl(sum(a.n8),0) phi713,nvl(sum(a.n9),0) thue713,nvl(sum(a.n10),0) phi714,nvl(sum(a.n11),0) thue714,nvl(sum(a.n12),0) phi715,nvl(sum(a.n13),0) thue715,
--    nvl(sum(a.n15),0) tndsn,nvl(sum(a.n16),0) tndst,nvl(sum(a.n17),0) tndsl,nvl(sum(a.n18),0) tndsh,a.n39 phi_mr,a.n40 thue_mr
,a.c18 ngay_cap
from temp_1 a left join temp_3 b on(a.c27='T' or (a.c30=b.c1 and a.c28=b.c2)) where (b_ma_kh is null or a.c3 =b_ma_kh) 
group by a.c1, a.c2,a.c3, a.c4,a.c5, a.c6,a.c7,a.c16,a.c17,a.c8, a.c9,a.c10,a.c11,a.c39,a.c40, nvl(a.n1,0),nvl(a.n2,0),a.n39 ,a.n40,a.c18,a.c12,a.c13,a.c19  ,a.n30
order by a.c1;

exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BH_XECG_TKE_KTHAC;

CREATE OR REPLACE PROCEDURE BC_BH_XECG_TKE_KTHAC
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_so_hd varchar2,b_gcn varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
as
    b_loi varchar2(100);b_ngaydn number;b_i1 number;--b_phong varchar2(30);
begin
    b_loi:=fht_ma_nsd_ktra(b_madvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise program_error; end if;
   -- PBC_QUYEN_XEM_BC(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong_x,'XE',b_phong);
  --  if b_loi is not null then raise PROGRAM_ERROR; end if;

    if b_ngayd is null or b_ngayc is null then
        b_loi:='loi:nhap ngay bao cao:loi'; raise program_error;
    end if;

--n1 so_id, n2 so_id_dt, c1 ma_dvi, n3 ngay_ht, c2 so_hd, c3 gcn, c4 ten, c5 dchi, bh_xe
--c6 ma_gt, c7 kieu_hd,c8 bien_xe,c9 so_khung, c10 so_may,c11 hieu_xe,c12 loai_xe,
--n4 nam_sx,n5 ttai,n6 so_cn,c13 md_sd,n7 gia_xe,c14 ngay_cap,c15 ngay_hl,c16 ngay_kt,c17 lh_nv,
--n8 tien,c20 mt,n10 pt,n11 phi_dt phi_bh,n12 thue,n13 ttoan tong cong, c18 cb_ql, c19 ten_lhnv, n14 phi_tt,n15 ngay_tt

delete temp_1; delete temp_4;commit;
insert into temp_1(n1,n2,c1,n3,c2,c3,c4,c5,c6,c7,c8,c9,c10,c11,c12,n4,n5,n6,c13,n7,c14,c15,c16,c17,n8,c20,n10,n11,n12,n13,c18,c21,c22,c27,c28)
    select a.so_id, b.so_id_dt, a.ma_dvi, a.ngay_ht, a.so_hd, b.gcn, b.tenc, b.dchic, a.ma_gt, a.kieu_hd, b.bien_xe, b.so_khung, b.so_may,b.hieu,
                   b.loai_xe, b.nam_sx, b.ttai, b.so_cn, b.md_sd, b.gia, PKH_SO_CNG(a.ngay_cap) ngay_cap,PKH_SO_CNG(a.ngay_hl) ngay_hl,
                   PKH_SO_CNG(a.ngay_kt) ngay_kt,
                   c.lh_nv, sum(c.tien) tien, ''mt, sum(c.pt) pt, sum(c.phi) phi_dt, sum(c.thue) thue, sum(c.ttoan) ttoan,
                   a.cb_ql,b.gcn,b.gcn,a.ttrang,b.hang
                from bh_hd_goc a, bh_xe_ds b, bh_xe_dk c
            where (b_ma_dvi is null or a.ma_dvi = b_ma_dvi)
                  and a.ngay_ht between b_ngayd and b_ngayc and a.ttrang = 'D'
                  and (b_phong is null or a.phong = b_phong)
                  and (b_so_hd is null or a.so_hd = b_so_hd)
                  and a.so_id = b.so_id and b.so_id = c.so_id and b.so_id_dt = c.so_id_dt
                  and (b_gcn is null or b.gcn = b_gcn)
                  and (b_ma_nv is null or c.lh_nv like upper(b_ma_nv)||'%')
            group by a.so_id, b.so_id_dt, a.ma_dvi,a.ngay_ht, a.so_hd, b.gcn, b.tenc, b.dchic, a.ma_gt, a.kieu_hd,
                   b.bien_xe, b.so_khung, b.so_may,b.hieu,
                   b.loai_xe, b.nam_sx, b.ttai, b.so_cn, b.md_sd, b.gia, a.ngay_cap, a.ngay_hl, a.ngay_kt,
                   c.lh_nv,  a.cb_ql,b.gcn,b.gcn,a.ttrang,b.hang;

--insert into temp_1(n1,n2,c1,n3,c2,c3,c4,c5,c6,c7,c8,c9,c10,c11,c12,n4,n5,n6,c13,n7,c14,c15,c16,c17,n8,c20,n10,n11,n12,n13,c18,c21,c22,c27,c28)
--     select a.so_id, 0, a.ma_dvi,a.ngay_ht, a.so_hd, b.gcn_m||'+'||b.gcn_s gcn, b.ten, b.dchi, a.ma_gt,
--                a.kieu_hd, b.bien_xe, b.so_khung, b.so_may,b.hieu_xe,
--                   b.loai_xe, b.nam_sx, b.ttai, b.so_cn, b.md_sd, b.gia_xe, PKH_SO_CNG(a.ngay_cap) ngay_cap,PKH_SO_CNG(a.ngay_hl) ngay_hl,
--                   PKH_SO_CNG(a.ngay_kt) ngay_kt,
--                   c.lh_nv, sum(c.tien) tien, translate(c.mt using NCHAR_CS) mt, sum(c.pt) pt, sum(c.phi_dt) phi_dt, sum(c.thue) thue, sum(c.ttoan) ttoan,
--                   a.cb_ql,b.gcn_m,b.gcn_s,a.ttrang,b.hang_xe
--                from bh_hd_goc a, bh_xelgcn b, bh_xelgcn_dk c
--            where (b_ma_dvi is null or a.ma_dvi = b_ma_dvi)
--                  and a.ngay_ht between b_ngayd and b_ngayc
--                  and (b_phong is null or a.phong = b_phong)
--                  and (b_so_hd is null or a.so_hd = b_so_hd)
--                  and a.ttrang = 'D'
--                  and a.so_id = b.so_id and b.so_id = c.so_id
--                  and c.tien > 0
--                and (b_gcn is null or b.gcn_s = b_gcn)
--                and (b_ma_nv is null or c.lh_nv like upper(b_ma_nv)||'%')
--
--            group by a.so_id, a.ma_dvi, a.ngay_ht, a.so_hd, b.gcn_m||'+'||b.gcn_s, b.ten, b.dchi, a.ma_gt,
--                   a.kieu_hd, b.bien_xe, b.so_khung, b.so_may,b.hieu_xe,
--                   b.loai_xe, b.nam_sx, b.ttai, b.so_cn, b.md_sd, b.gia_xe, b.ngay_cap, b.ngay_hl, b.ngay_kt,
--                   c.lh_nv, c.mt, a.cb_ql,b.gcn_m,b.gcn_s,a.ttrang,b.hang_xe;

 update temp_1 set c19=(select max(nvl(ten,'')) from bh_ma_lhnv where ma_dvi=c1 and ma=c12);
 update temp_1 set c12=(select max(nvl(ten,'')) from bh_xe_loai where ma_dvi=c1 and ma=c12);

 --lay phi thuc thu
 update temp_1 set (n14)=(select sum(ttoan) from bh_hd_goc_ttpt
    where c1=ma_dvi and n1=so_id /*and ngay_ht between b_ngayd and b_ngayc */and pt<>'C');

 --update temp_1 set (c20)=(select nvl(max(PKH_SO_CNG(ngay_ht)),'') from bh_hd_goc_ttpt where ma_dvi=b_ma_dvi and c1=ma_dvi and n1=so_id and pt<>'C' and ngay_ht between b_ngayd and b_ngayc);
 --ngay thuc thu
 insert into temp_4(n1,c1,n2,n3,n4) select distinct a.so_id_tt,b.so_ct,a.so_id,a.ngay_ht,a.ngay
    from bh_hd_goc_ttpt a,bh_hd_goc_ttps b, temp_1 c
    where a.ma_dvi=b_ma_dvi and a.ngay_ht between b_ngayd and b_ngayc and a.pt<>'C'
    and c.c1=a.ma_dvi and c.n1=a.so_id and a.ma_dvi=b.ma_dvi and a.so_id_tt=b.so_id_tt;

for r_lp in (select n1,c1,n2,n3,n4 from temp_4 order by n3) loop

    update temp_1 a set c23=c23||';'||PKH_SO_CNG(r_lp.n3),c25=c25||';'||r_lp.c1,c24=c24||';'||PKH_SO_CNG(r_lp.n4)
        where a.n1=r_lp.n2;
end loop;


update temp_1 set c23= ltrim(c23,';'),c24= ltrim(c24,';'),c25= ltrim(c25,';');

 --ngay han thanh toan
