 delete temp_4; commit;
 insert into temp_4(n2,n3) select distinct so_id,ngay from bh_hd_goc_tt, temp_1 b where ma_dvi=b_ma_dvi and c1=ma_dvi and n1=so_id;
    for r_lp in (select n2,n3 from temp_4 order by n3) loop
          update temp_1 a set c24=c24||';'||PKH_SO_CNG(r_lp.n3) where a.n1=r_lp.n2;
    end loop;
    update temp_1 set c24= ltrim(c24,';');
