--so quyen
/*
update temp_1 set n21=(select so_to from hd_ma_hd where ma_dvi=b_ma_dvi and c1=ma_dvi and c21=ma);
update temp_1 set n22=to_number(substr(c22,length(c22)));
update temp_1 set n23=(to_number(c22)+(n21-n22))/n21;
update temp_1 set c26=(select ten_gon from ht_ma_dvi where ma=c1);
update temp_1 set c27=decode(c27,'D','Da duyet','T','Dang trinh','Huy');
update temp_1 set c27='Cham dut hop dong' where n1 in (select so_id from bh_hd_goc_hu where ma_dvi=c1 and ngay_ht between b_ngayd and b_ngayc);
update temp_1 set c29=(select nvl(to_char(con),'') from bh_hd_goc_hu where ma_dvi=c1 and so_id=n1 and ngay_ht between b_ngayd and b_ngayc);*/

commit;
 open cs_kq for
    select rownum stt, n1 so_id,n2 so_id_dt,c1 ma_dvi,c2 so_hd,c3 gcn,c4 ten_khach,c5 dia_chi,c6 nguon,c7 hinh_thuc,
        c8 bien_xe,c9 so_khung,c10 so_may,c11 hieu_xe,c12 loai_xe,n4 nam_sx,n5 ttai,n6 so_cn,c13 muc_dich,c13 md,n7 gia_tri,
        c14 ngay_cap,c15 ngay_hl,c16 ngay_kt,c17 lh_nv,n8 tien_bh,translate(n9 using NCHAR_CS) mien_thuong,n10 tl_phi,n11 phi_bh,n12 thue,
        n13 tong_cong,c18 cb_ql,c19 ten_lhnv,n14 phi_tt,replace(c23,'//,') ngay_tt,replace(c24,'//,') ngay_han_tt,
        c25 so_ct,n23 so_quyen,c6 ten_dvi,FBH_HD_GOC_SO_HD_D(c1,n1) so_hd_goc,PKH_SO_CNG(n3) ngay_ht,c27 ttrang_hd,c28 hang_xe,
        c29 con
         from temp_1 order by stt,c2,n2;

exception when others then if b_loi is null then raise PROGRAM_ERROR; else  raise_application_error(-20105,b_loi); end if;
end;
/

