N4,N5,N3,C16,C39,C40)--,N6,N7,N8,N9,N10,N11,N12,N13
SELECT A.MA_DVI,C.KIEU_KT,C.MA_KT,A.SO_ID,A.SO_ID_DT,A.GCN,C.SO_HD,C.MA_KH,C.TEN,NV_BH,A.TENC,A.DCHIC,
A.HIEU,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,'','',PKH_SO_CNG(A.NGAY_HL),PKH_SO_CNG(A.NGAY_KT),PKH_SO_CNG(A.NGAY_CAP),
B.PHI,B.THUE,B.TIEN,
MA_DK,NAM_SX,LOAI_XE
FROM BH_2B_DS A,BH_2B_DK B, BH_HD_GOC C
WHERE (B_MA_DVI IS NULL OR A.MA_DVI=B_MA_DVI) AND A.MA_DVI=B.MA_DVI AND A.MA_DVI=C.MA_DVI
AND A.SO_ID=B.SO_ID AND A.SO_ID=C.SO_ID AND A.SO_ID_DT=B.SO_ID_DT AND KIEU_HD IN('G','T') AND TTRANG='D'
AND (B_PHONG IS NULL OR C.PHONG=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV||'%')
AND (B_HIEU_XE IS NULL OR A.HIEU=B_HIEU_XE)
AND (B_SO_HD_G IS NULL OR C.SO_HD=B_SO_HD_G)  AND (B_MA_KH IS NULL OR C.MA_KH=B_MA_KH)
AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC;
--GROUP BY A.MA_DVI,C.KIEU_KT,C.MA_KT,A.SO_ID,A.SO_ID_DT,A.GCN,C.SO_HD,C.MA_KH,C.TEN,A.TENC,A.DCHIC,NV_BH,
--A.HIEU,A.BIEN_XE,A.SO_KHUNG,A.SO_MAY,A.NGAY_HL,A.NGAY_KT,A.NGAY_CAP,A.NAM_SX,MA_DK,A.LOAI_XE;

UPDATE TEMP_1 SET C19 = (SELECT MAX(TEN) FROM BH_MA_DK WHERE C30=MA_DVI AND C16=MA);

OPEN CS_KQ FOR SELECT  C1 SO_HD, C2 SO_HD_G,C3 MA_KH, C4 TEN_KH,C5 NV_BH, C6 TEN_CXE,
    C7 D_CHI_CX,A.C16 MA_DK,A.C19 TEN_DK, C8 HIEU_XE, C9 BIEN_XE,C10 SO_KHUNG,C11 SO_MAY,
    NVL(N1,0) SO_CN,NVL(N2,0) T_TAI,NVL(N3,0) TIEN_XE,C12 NGAY_HL,C13 NGAY_KT,
    A.N4 PHI,A.N5 THUE,A.N3 TIEN_BH
--    NVL(N4,0) PHI711,NVL(N5,0) THUE711,NVL(N6,0) PHI712,NVL(N7,0) THUE712, NVL(N8,0) PHI713,NVL(N9,0) THUE713,NVL(N10,0) PHI714,NVL(N11,0) THUE714,NVL(N12,0) PHI715,NVL(N13,0) THUE715
    FROM TEMP_1 A WHERE (B_PHONG IS NULL OR C20 =B_PHONG) ORDER BY C1;
-- EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
