DROP PROCEDURE BC_BH_XE_DT;

CREATE OR REPLACE PROCEDURE BC_BH_XE_DT
    (b_ma_dvi_nsd varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number;b_i1 number;b_ngayd1 number;
    b_c18 varchar2(50);b_n10 number;b_n17 number;b_n18 number;b_n19 number;b_n20 number;b_c26 varchar2(50);b_c16 varchar2(50);
Begin

/*if b_nsd = 'ADMIN' and b_ma_dvi_nsd='00' then b_loi:='loi:'||b_ma_dvi||'-'||b_phong||'-'||b_ma_nv||'-'||b_ngayd||'-'||b_ngayc||':loi';
raise PROGRAM_ERROR; end if;*/
--b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi_nsd,b_nsd,b_pas,'BH','','');
--if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_ngayd1:=PKH_NG_CSO(PKH_SO_CDT(b_ngayd)-1);
b_loi:='loi:Ma chua dang ky:loi';
--delete temp_m_1;delete temp_m_2;delete temp_3;delete temp_m_4;delete temp_5;delete ket_qua; commit;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_m_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_m_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_3';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_m_4';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_5';
EXECUTE IMMEDIATE 'TRUNCATE TABLE ket_qua';
PBC_LAY_DVI(b_ma_dvi_nsd,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;

--1. Lay doanh thu trong ky
--delete temp_bc_ts;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bc_ts';
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);

--doanh thu ban hang nghiep vu xe o to
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);
    insert into temp_m_4(c1,c2,n1,n3,n12) select ma_dvi,ma_dvig,so_id,max(ngay_htnv),sum(phi)
        from TEMP_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and nv in ('XE','XEL')
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%')  group by ma_dvi,ma_dvig,so_id;

--doanh thu thuc thu nghiep vu xe o to
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
    BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngayd,b_ngayc);
    insert into temp_m_4(c1,c2,n1,n3,n13) select ma_dvi,ma_dvig,so_id,max(ngay_htnv),sum(phi)
        from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and nv in ('XE','XEL')
        --and FBH_HD_SO_ID_DAU(ma_dvi,so_id_tt)<>so_id
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%') group by ma_dvi,ma_dvig,so_id;

--2. Lay doanh thu luy ke
if b_ngayd<>b_ngaydn then
--delete temp_bc_ts;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bc_ts';
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngaydn,b_ngayc);

        --doanh thu ban hang nghiep vu xe o to
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);
    insert into temp_m_4(c1,c2,n1,n3,n14) select ma_dvi,ma_dvig,so_id,max(ngay_htnv),sum(phi)
        from TEMP_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and nv in ('XE','XEL')
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%') group by ma_dvi,ma_dvig,so_id;
--doanh thu thuc thu nghiep vu xe o to
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
    BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngayd,b_ngayc);
    insert into temp_m_4(c1,c2,n1,n3,n15) select ma_dvi,ma_dvig,so_id,max(ngay_htnv),sum(phi)
        from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (ngay_htbs between b_ngaydn and b_ngayd1)
        and nv in ('XE','XEL')
        --and FBH_HD_SO_ID_DAU(ma_dvi,so_id_tt)<>so_id
        and (b_ma_nv is null or lh_nv like b_ma_nv||'%')  group by ma_dvi,ma_dvig,so_id;

end if;

update temp_m_4 set n14=nvl(n12,0)+nvl(n14,0),n15=nvl(n13,0)+nvl(n15,0);
--3. Lay doanh thu phat sinh
insert into temp_m_2(c1,c2,n1,n3,n12,n13,n14,n15) select c1,c2,n1,max(n3),sum(n12),sum(n13),sum(n14),sum(n15)
    from temp_m_4 group by c1,c2,n1;

--BCNam
update temp_m_2 set n2=FBH_HD_SO_ID_BS(c2,n1,n3);
insert into temp_3(c1,n1,n4,c6,c7,c8,c9,c10,d1,n12,n13,n14,n15,n16,n30,n29,d2,d3, c24, c25,c11,n21,c33,c35)
    select c1,a.so_id,a.so_id_dt,a.gcn,a.tenc,a.bien_xe,a.phi,a.nhom_xe,PKH_SO_DATE(a.ngay_cap),n12,n13,n14,n15,
        sum(b.phi), a.so_cn,sum(b.tien),PKH_SO_DATE(a.ngay_hl),PKH_SO_DATE(a.ngay_kt), hang, hieu,b.lh_nv,a.nam_sx,a.loai_xe,a.md_sd
        from bh_xe_ds a,bh_xe_dk b,temp_m_2
        where a.ma_dvi in (Select ma from ht_ma_dvi) and a.so_id=n2 and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
        and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.so_id_dt=b.so_id_dt
        group by c1,a.so_id,a.so_id_dt,a.gcn,a.tenc,a.bien_xe,a.phi,a.nhom_xe,a.ngay_cap,n12,n13,n14,n15,
                a.so_cn,a.ngay_hl,a.ngay_kt,hang, hieu,b.lh_nv,a.nam_sx,a.loai_xe,a.md_sd;
--insert into temp_3(c1,n1,c6,c7,c8,c9,c10,d1,n12,n13,n14,n15,n16, n30,n29,d2,d3, c24, c25,c11,n21,c33,c35)
--    select  c1,a.so_id,a.so_hd,a.ten,a.bien_xe,a.b_phi,a.nhom_xe,a.ngay_cap,n12,n13,n14,n15,
--        sum(b.phi_dt),a.so_cn,sum(b.tien),a.ngay_hl,a.ngay_kt, hang_xe, hieu_xe,b.lh_nv,a.nam_sx,a.loai_xe,a.md_sd
--        from bh_xelgcn a,bh_xelgcn_dk b,temp_m_2
--        where a.ma_dvi in (Select ma from ht_ma_dvi) and a.so_id=n2
--        and (b_ma_nv is null or lh_nv like b_ma_nv||'%') and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
--        group by c1,a.so_id,a.so_hd,a.ten,a.bien_xe,a.b_phi,a.nhom_xe,a.ngay_cap,n12,n13,n14,n15,
--                a.so_cn,a.ngay_hl,a.ngay_kt,hang_xe, hieu_xe,b.lh_nv,a.nam_sx,a.loai_xe,a.md_sd;

--delete from temp_3 where c1<>b_ma_dvi;
--update temp_3 set n29=(Select sum(tien) from bh_xegcn_dk where  (b_ma_nv is null or lh_nv like b_ma_nv||'%'))

-- update temp_3 a set (n17,n18)=(select sum(n16),count(*) from temp_3 b where a.n1=b.n1);
--delete temp_sl_idx_id;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_sl_idx_id';
insert into temp_sl_idx_id(so_id,n16,n20) select n1,sum(n16),count(*) from temp_3 group by n1;
--update temp_3 a set (n17,n18)=(select n16,n20 from temp_sl_idx_id b where so_id=a.n1);
merge into temp_3 a
using temp_sl_idx_id b
on (so_id=a.n1)
when matched then update
set a.n17=b.n16,a.n18=b.n20;

update temp_3 set n22=n12,n23=n13,n24=n14,n25=n15 where not (n18>1 and n17<>0);
update temp_3 set n22=round(n12*n16/n17,0),n23=round(n13*n16/n17,0),n24=round(n14*n16/n17,0),n25=round(n15*n16/n17,0)
    where n18>1 and n17<>0;

update temp_3 set (c13, c30, c15)=(select phong, so_hd, cb_ql from bh_hd_goc where ma_dvi=c1 and so_id=n1);

/*
update
       (select temp_3.c13 temp_3_c13, temp_3.c30 temp_3_c30, temp_3.c15 temp_3_c15,
            bh_hd_goc.phong bh_hd_goc_phong, bh_hd_goc.so_hd bh_hd_goc_so_hd, bh_hd_goc.cb_ql bh_hd_goc_cb_ql
              from temp_3, bh_hd_goc
             where temp_3.c1 = bh_hd_goc.ma_dvi and temp_3.n1 = bh_hd_goc.so_id)
       set temp_3_c13=bh_hd_goc_phong, temp_3_c30=bh_hd_goc_so_hd, temp_3_c15=bh_hd_goc_cb_ql;
*/

insert into ket_qua(c1,c13,c6,c7,c8,c9,c10,c11,d1,c22,n12,n13,n14,n15,n16,n30,n29,d2,d3, c30, c15, n1,n4,c24,c25,n21,c33,c35)
    select c1,c13,c6,c7,c8,c9,c10,c11,d1,'C',sum(n22),sum(n23),sum(n24),sum(n25),sum(n16),n30,n29,d2,d3,c30, c15,
        n1,n4,c24,c25,n21,c33,c35 from temp_3
        group by c1,c13,c6,c7,c8,c9,c10,c11,d1,n30,n29,d2,d3,c30, c15, n1,n4,c24,c25,n21,c33,c35;

