DROP PROCEDURE BC_BH_CNKH_BT_MD;

CREATE OR REPLACE PROCEDURE BC_BH_CNKH_BT_MD
    (b_ma_dvi varchar2,b_ngayd number,b_ngayc number)
AS
    b_loi varchar2(100);
Begin
-- Bao cao cong boi thuong
--delete temp_1;commit;
execute immediate 'truncate table temp_1';
/*  bo phat sinh tai don vi goc
--phat co,no khi duyet do nguoi khac BT ho
insert into temp_2(c1,n10,n2,n3) select hs.ma_dvi,hs.so_id,
    sum(tien_qd)+sum(thue_qd),sum(tien_qd)+sum(thue_qd) from bh_bt_hs hs, bh_bt_hs_nv nv
    where (b_ma_dvi is null or hs.ma_dvi=b_ma_dvi)
    and hs.ma_dvi=nv.ma_dvi and hs.so_id=nv.so_id and hs.ma_dvi<>hs.ma_dvi_xl
    and PKH_NG_CSO(ngay_qd) between b_ngayd and b_ngayc
    group by hs.ma_dvi,hs.so_id;
*/

/*
--  phat sinh co khi duyet boi thuong 
insert into temp_1(c1,n10,n2) select ma_dvi,so_id,sum(thu_qd)
    from bh_bt_hs_sc where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id;

-- phat sinh co khi thanh toan tien boi thuong 

insert into temp_1(c1,n10,n3) select ma_dvi,so_id,sum(chi_qd)
    from bh_bt_hs_sc where ngay_ht between b_ngayd and b_ngayc and (b_ma_dvi is null or ma_dvi=b_ma_dvi) group by ma_dvi,so_id;
*/

-- Hung gop sum(thu_qd) va sum(chi_qd)
insert into temp_1(c1,n10,n2,n3) select ma_dvi,so_id,sum(thu_qd),sum(chi_qd)
    from bh_bt_hs_sc 
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and 
    ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id;



/* du no dau ky n5 */

insert into temp_1(c1,n10,n6) select   a.ma_dvi,a.so_id,sum(a.ton_qd)
    from bh_bt_hs_sc a,(select ma_dvi,ma_nt,so_id,max(ngay_ht) ngay_ht from bh_bt_hs_sc where
        (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht<b_ngayd group by ma_dvi,ma_nt,so_id) b
    where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id having sum(a.ton_qd)<>0;

update temp_1 set n5=-n6,n6=0 where nvl(n6,0)<0;

--- no cuoi ky n14
insert into temp_1(c1,n10,n15) select   a.ma_dvi,a.so_id,sum(a.ton_qd)
    from bh_bt_hs_sc a,(select ma_dvi,ma_nt,so_id,max(ngay_ht) ngay_ht from bh_bt_hs_sc where
        (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht<=b_ngayc group by ma_dvi,ma_nt,so_id) b
    where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id having sum(a.ton_qd)<>0;

update temp_1 set n14=-n15,n15=0 where nvl(n15,0)<0;

update temp_1 set (n9)=(select max(so_id_hd) from bh_bt_hs where  ma_dvi=temp_1.c1 and so_id=temp_1.n10);
--update
--    (select temp_1.n9 t_n9, bh_bt_hs.so_id_hd hd_so_id
--        from temp_1, bh_bt_hs
--        where  bh_bt_hs.ma_dvi=temp_1.c1 and bh_bt_hs.so_id=temp_1.n10)
--        set t_n9 = hd_so_id;

update temp_1 set (c30)=(select kieu_hd from bh_hd_goc where ma_dvi=temp_1.c1 and so_id=temp_1.n9);
/*
update
    (select temp_1.c30 t_c30, bh_hd_goc.kieu_hd goc_kieu_hd
        from temp_1, bh_hd_goc
        where bh_hd_goc.ma_dvi=temp_1.c1 and bh_hd_goc.so_id=temp_1.n9)
        set t_c30 = goc_kieu_hd;
*/

--delete temp_1 where nvl(c30,'G')='V';
delete temp_1 where c30='V';
end;
/

drop PROCEDURE BC_BH_XN_NO_BT;
CREATE OR REPLACE PROCEDURE BC_BH_XN_NO_BT
	(B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
	B_MA_KH VARCHAR2,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
	B_LOI VARCHAR2(100);B_NGAYDN NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE TEMP_1;DELETE TEMP_2;COMMIT;
BC_BH_CNKH_BT_MD(B_MA_DVI,B_NGAYC,B_NGAYC);
INSERT INTO TEMP_2 (C29,N1,N4) SELECT C1,N10,SUM(N15) FROM TEMP_1 GROUP BY C1,N10;
UPDATE TEMP_2 SET (N13,C14,C4) =(SELECT SO_ID_HD,PKH_SO_CNG(NGAY_QD),SO_HS FROM BH_BT_HS WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N1);
UPDATE TEMP_2 SET (C1,C3)=(SELECT MA_KH,SO_HD FROM BH_HD_GOC WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N13);
UPDATE TEMP_2 SET (C2,C6) =(SELECT TEN,DCHI FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=TEMP_2.C1);
UPDATE TEMP_2 SET N2 =(SELECT SUM(TIEN_QD+THUE_QD) FROM BH_BT_HS_NV WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N1);
UPDATE TEMP_2 SET N3 =(SELECT SUM(TIEN_QD) FROM BH_BT_TT_PS WHERE MA_DVI=TEMP_2.C29 AND SO_ID=TEMP_2.N1);
UPDATE TEMP_2 A SET N6=(SELECT SUM(N4) FROM TEMP_2 WHERE C1=A.C1);
OPEN CS_KQ FOR SELECT C1 MA_KH,C2 TEN,C6 DCHI,C3 SO_HD,C4 SO_HS,N2 TIEN_PS,N3 TIEN_TRA,N4 TIEN_NO,C14 NGAY_DUYET,PKH_SO_CNG(N7) NGAY_TT ,N6 TONG
	FROM TEMP_2 ORDER BY C3;
--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BC_BH_DTCPSTN_MDM;
-- chuclh: hotfix cho chay ra du lieu
CREATE OR REPLACE PROCEDURE BC_BH_DTCPSTN_MDM
    (b_madvi varchar2,b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_ma_dl varchar2,b_kieu_kt varchar2,b_so_id number,
    b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
    b_noite varchar2(5); b_i1 number;
Begin
--BCNam: Doanh thu chua phat sinh trach nhiem, sua lai
--b_loi:='loi:BCNam:loi';
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; return;
end if;
b_loi:='loi:Loi doanh thu chua phat sinh trach nhiem:loi';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_3';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_4';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_5';
EXECUTE IMMEDIATE 'TRUNCATE TABLE blvp_temp_1';
commit;
--cac don con no den ngay
insert into temp_1(c29,n1,c1,n2,n3,n4) 
    select   ma_dvi,so_id,ma_nt,sum(no),sum(decode(sign(ngay_ht-b_ngayc),1,0,co)),min(ngay_ht)
    from bh_hd_goc_sc_phi where (b_ma_dvi is null or ma_dvi = b_ma_dvi) group by ma_dvi,so_id,ma_nt
    having sum(no)<>sum(decode(sign(ngay_ht-b_ngayc),1,0,co)) and min(ngay_ht)<=b_ngayc;
--lay so phat sinh cua nhung don con no den ngay
insert into temp_3(c29,n1,c1,c2,n2,n4,n5,n6) 
    select   ma_dvi,so_id,ma_nt,lh_nv,ngay,sum(phi),sum(thue),sum(ttoan) from bh_hd_goc_cl
    where (b_ma_dvi is null or ma_dvi = b_ma_dvi) and ngay_ht<=b_ngayc and (ma_dvi,so_id,ma_nt) in (select c29,n1,c1 from temp_1)
    group by ma_dvi,so_id,ma_nt,lh_nv,ngay having sum(ttoan)<>0;
--tru di so phat hang hoa don
insert into temp_3(c29,n1,c1,c2,n2,n4,n5,n6) 
    select   ma_dvi,so_id,ma_nt,lh_nv,ngay,-sum(phi),-sum(thue),-sum(ttoan) from bh_hd_goc_ttpt
    where (b_ma_dvi is null or ma_dvi = b_ma_dvi) and ngay_tt<=b_ngayc
    and (ma_dvi,so_id,ma_nt) in (select c29,n1,c1 from temp_1) and pt<>'N'
    group by ma_dvi,so_id,ma_nt,lh_nv,ngay having sum(ttoan)<>0;
--gom tong
insert into temp_2(c1,c2,c3,c4,c10,c11,n20,n1,n2,n3,c13,n4,n5)
        select   goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,round(goc.ngay_ht,-4),goc.ngay_ht,goc.so_id,n2,goc.nv,
        sum(nvl(n4,0)),sum(nvl(n5,0))
        from bh_hd_goc goc,temp_3 c
        where goc.ma_dvi=c29 and goc.so_id=c.n1
        --and (b_ma_dvi is null or goc.ma_dvi = b_ma_dvi)
        and goc.so_id=n1 and kieu_hd not in ('V','U','K')
        and (b_phong is null or phong =b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_nv is null or c2 like b_ma_nv||'%')
        group by goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,goc.ngay_ht,goc.ngay_ht,goc.so_id,n2,goc.nv;
--loai bo cac hop dong cham dut
delete from temp_2 where n2 in (select so_id from bh_hd_goc_hu where ngay_ht <= b_ngayc and ma_dvi=c1);
delete from temp_2 where n2 in (select so_id from bh_hd_goc where (ttrang='H' or ttrang='S') and ma_dvi=c1);
delete from temp_2 where n2 in (select so_id from bh_hd_goc where ma_dvi=c1 and ngay_kt<to_char(sysdate,'yyyyMMdd') and ma_dvi='034');
-- chuclh update vi do_tl khong con cot kieu va ph (khong ton tai)
update temp_2 set n30=(select 100-sum(a.pt) from bh_hd_do_tl a,bh_hd_do b
    where a.so_id=b.so_id and a.ma_dvi=c1 and a.so_id=n2 and a.pthuc='C' and  b.kieu='D');
-- chuclh update vi do_tl khong con cot kieu va ph (khong ton tai)
update temp_2 set n30=(select sum(a.pt) from bh_hd_do_tl a,bh_hd_do b
    where a.so_id=b.so_id and a.ma_dvi=c1 and a.so_id=n2 and a.pthuc='C' and b.kieu='V') where n30=0 or n30 is null;
update temp_2 set n4=n4-n4*n30/100,n5=n5-n5*n30/100,n6=n6-n6*n30/100,n7=n7-n7*n30/100 where n30<>0;

--update temp_2 set n30=(select sum(phi) from bh_hd_goc_cl where so_id=n2 and ma_dvi=c1);
--update temp_2 set n29=n30-(select sum(phi) from bh_hd_goc_ttpt where so_id=n2 and ma_dvi=c1 and pt<>'N');

--update temp_2 set c6 =(select loai from bh_hd_ma_kh where ma_dvi=temp_2.c1 and ma=temp_2.c2);

update
       (select temp_2.c6 temp_2_c6, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from temp_2, bh_hd_ma_kh
             where temp_2.c1 = bh_hd_ma_kh.ma_dvi and temp_2.c2 = bh_hd_ma_kh.ma)
       set temp_2_c6 = bh_hd_ma_kh_loai;

--chi tiet theo nghiep vu
insert into temp_4(c1,c2,c3,c4,c10,c11,n20,n1,n2,n3,n4,n5,n6,n7,c27)
        select   goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,round(goc.ngay_ht,-4),goc.ngay_ht,goc.so_id,n2,
        0,0,sum(nvl(n4,0)),sum(nvl(n5,0)),c2
        from bh_hd_goc goc,temp_3 c
        where goc.ma_dvi=c29 and goc.so_id=c.n1
        --and (b_ma_dvi is null or goc.ma_dvi = b_ma_dvi)
        and goc.so_id=n1 and kieu_hd not in ('V','U','K')
        and (b_phong is null or phong =b_phong) and (b_ma_kh is null or ma_kh=b_ma_kh)
        and (b_ma_nv is null or c2 like b_ma_nv||'%') --and so_hd='86/15/IHD-KT.1.1/000-TBH'
        group by goc.ma_dvi,ma_kh,c1,so_hd,ma_kt,cb_ql,goc.ngay_ht,goc.so_id,n2,c2;
--loai bo cac hop dong cham dut
delete from temp_4 where n2 in (select so_id from bh_hd_goc_hu where ngay_ht <= b_ngayc and ma_dvi=c1);
delete from temp_4 where n2 in (select so_id from bh_hd_goc where (ttrang='H' or ttrang='S') and ma_dvi=c1);
--loai bo hop dong het hieu luc
delete from temp_4 where n2 in (select so_id from bh_hd_goc where ma_dvi=c1 and ngay_kt<to_char(sysdate,'yyyyMMdd'));

-- chuclh: kieu khong con o bang tl
update temp_4 set n30=(select 100-sum(a.pt) from bh_hd_do_tl a,bh_hd_do b
    where a.so_id=b.so_id and a.ma_dvi=c1 and a.so_id=n2 and a.pthuc='C' and  b.kieu='D' and a.lh_nv in('*',c27));
-- chuclh: kieu khong con o bang tl
update temp_4 set n30=(select sum(a.pt) from bh_hd_do_tl a,bh_hd_do b
    where a.so_id=b.so_id and a.ma_dvi=c1 and a.so_id=n2 and a.pthuc='C' and b.kieu='V' and a.lh_nv in('*',c27)) where n30=0 or n30 is null;
update temp_4 set n4=n4-n4*n30/100,n5=n5-n5*n30/100,n6=n6-n6*n30/100,n7=n7-n7*n30/100 where n30<>0;

--update temp_2 set n30=(select sum(phi) from bh_hd_goc_cl where so_id=n2 and ma_dvi=c1);
--update temp_2 set n29=n30-(select sum(phi) from bh_hd_goc_ttpt where so_id=n2 and ma_dvi=c1 and pt<>'N');

--update temp_2 set c6 =(select loai from bh_hd_ma_kh where ma_dvi=temp_2.c1 and ma=temp_2.c2);
--update temp_4 set c6 =(select loai from bh_hd_ma_kh where ma_dvi=temp_4.c1 and ma=temp_4.c2);

update
       (select temp_4.c6 temp_4_c6, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from temp_4, bh_hd_ma_kh
             where temp_4.c1 = bh_hd_ma_kh.ma_dvi and temp_4.c2 = bh_hd_ma_kh.ma)
       set temp_4_c6 = bh_hd_ma_kh_loai;

b_loi:='';
exception when others then null;
end;
/

DROP PROCEDURE BC_BH_XN_NO_WEB;

CREATE OR REPLACE PROCEDURE BC_BH_XN_NO_WEB
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_dvi varchar2,b_ma_kh varchar2,b_phong varchar2,b_ngayc number,
     b_loai varchar:='C',b_nv varchar:='K',cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number;
Begin
-- bang ke xac nhan no cho khach hang
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;delete temp_2;delete temp_3;commit;
--so ton chua thanh toan phi
/** temp_1 c1 ma_kh,c2 ten ,c3 so_hd, c4 ngay_kt,c6 ma_nt, n7 ngay_ht,n1 so_id,2 phi,n3 phi_tt,n4 phi_no, n5 phi_no1 */
/*BC_BH_DTCPSTN_MD temp_2 c1 ma_dvi ,c2 ma_kh,c3 ma_nt,c4 so_hd,c10 ma_kt,c11 ma_cb_ql,n20 nam,n1 ngay,n2 so_id,n4 phi,n5 thue) */
BC_BH_DTCPSTN_MDM(b_madvi,b_ma_dvi,'',b_phong,'',b_ma_kh,'','','',0,19000000,b_ngayc,b_loi);
delete temp_1;

-- n5 so phi  cpstrn con no quy doi,n15 so phi  cpstrn con no nguyen te
insert into temp_1(c29,c1,c2,c3,c4,c6,n7,n1,n2,n3,n4,n5,n15,n20)
    select a.ma_dvi,c2,ten,c4,PKH_CNG_SO(ngay_kt),c3,n1,n2,0,0,0,sum(nvl(n4,0)+nvl(n5,0)),sum(nvl(n6,0)+nvl(n7,0)),1 from bh_hd_goc a,temp_2 
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and so_id=n2
    group by a.ma_dvi,c2,ten,c4,ngay_kt,c3,n1,n2;
/* Lay so con ton cong no */
insert into temp_1(c29,c1,c2,c3,c4,c5,c6,n7,n1,n2,n3,n4,n5,n20)
    select a.ma_dvi,ma_kh,ten,so_hd,PKH_CNG_SO(ngay_kt),PKH_CNG_SO(ngay_hl),ma_nt,max(b.ngay_ht),a.so_id,0,0,0,0,2
    from bh_hd_goc a,bh_hd_goc_sc_no b where (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
    and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and b.ngay_ht<=b_ngayc
    and (b_phong is null or phong=b_phong)
    group by a.ma_dvi,ma_kh,ten,so_hd,ngay_kt,ngay_hl,ma_nt,a.so_id;

update temp_1 set (n14,n4)=(select sum(ton),sum(ton_qd) from bh_hd_goc_sc_no where ma_dvi=c29 and so_id=n1 and ma_nt=c6 and ngay_ht=n7) where n20=2;

/*
-- Hung
   update
       (select temp_1.n14 temp_1_n14, temp_1.n4 temp_1_n4, 
            bh_hd_goc_sc_no.ton bh_hd_goc_sc_no_ton, bh_hd_goc_sc_no.ton_qd bh_hd_goc_sc_no_ton_qd
             from temp_1, bh_hd_goc_sc_no
             where temp_1.c29 = bh_hd_goc_sc_no.ma_dvi and temp_1.n1 = bh_hd_goc_sc_no.so_id 
                and temp_1.c6 = bh_hd_goc_sc_no.ma_nt and temp_1.n7 = bh_hd_goc_sc_no.ngay_ht)
       set temp_1_n14 = bh_hd_goc_sc_no_ton, temp_1_n4 = bh_hd_goc_sc_no_ton_qd;
*/
           
/* Lay so phat sinh */
delete temp_3;delete temp_6;
/*********
insert into temp_3(c29,n1,c1,n10,n2,n12) select goc.ma_dvi,goc.so_id,ma_nt,goc.ngay_ht,sum(FTT_VND_QD(goc.ma_dvi,goc.ngay_ht,ma_nt,ttoan)),sum(ttoan)
    from bh_hd_goc goc,bh_hd_goc_cl cl,(select distinct c29,n1 from temp_1) a
    where (b_ma_dvi is null or goc.ma_dvi=b_ma_dvi) and (b_ma_dvi is null or cl.ma_dvi=b_ma_dvi) and goc.ma_dvi=a.c29 and goc.so_id=cl.so_id 
        and cl.so_id=a.n1 group by goc.ma_dvi,goc.so_id,ma_nt,goc.ngay_ht;
insert into temp_6(c29,n1,n2,n12) select c29,n1,sum(n2),sum(n12) from temp_3 group by c29,n1 having sum(n2)<>0 and sum(n12)<>0;
***********/
--update temp_1 set (n2,n12)=(select n2,n12 from temp_6 where c29=temp_1.c29 and  n1=temp_1.n1);
/*
update temp_1 set (n2,n12)=(select sum(FTT_VND_QD(goc.ma_dvi,goc.ngay_ht,ma_nt,ttoan)),sum(ttoan)
    from bh_hd_goc goc,bh_hd_goc_cl cl where goc.ma_dvi=c29 and cl.ma_dvi=c29 and goc.so_id=cl.so_id and cl.so_id=n1);
*/

update temp_1 t set (n2,n12)=(select sum(FTT_VND_QD(goc.ma_dvi,goc.ngay_ht,cl.ma_nt,cl.ttoan)),sum(cl.ttoan)
    from bh_hd_goc_cl cl, bh_hd_goc goc where goc.ma_dvi=t.c29 and goc.so_id=t.n1 and cl.so_id=t.n1 and cl.ma_dvi=t.c29);
   
if b_nv<>'C' then
    -- Chay ton dong theo nghiep vu thi khong can lay so nay
    update temp_1 a set (n6,n16)=(select sum(n4+n5),sum(n14+n15) from temp_1 where c1=a.c1);
    update temp_1 set (n8,n18)=(select sum(FTT_VND_QD(a.ma_dvi,a.ngay_ht,b.nt_phi,b.tien)),sum(b.tien) from bh_hd_goc a,bh_hd_goc_dk  b 
           where a.ma_dvi=c29 and b.ma_dvi=c29 and a.so_id=b.so_id and a.so_id=temp_1.n1);
end if;
/* Lay so thu thuc */
update temp_1 set (n3,n13)=(select sum(ttoan_qd),sum(ttoan) 
    from bh_hd_goc_ttpt where ma_dvi=c29 and so_id=temp_1.n1 and pt<>'C' and ngay_ht<b_ngayc);
delete temp_1 where nvl(n4,0)+nvl(n5,0)=0;

/* Lay dia chi khach hang */
update temp_1 set (c2,c16) =(select ten,dchi from bh_hd_ma_kh where ma_dvi=c29 and ma=temp_1.c1);

if b_nv='C' then
    -- Xem theo nghiep vu
    delete temp_3;
    insert into temp_3 select * from temp_1 ;
    delete temp_1;
    update temp_3 set c3=(select min(nv) from bh_hd_goc where ma_dvi=c29 and so_id=n1);
    if b_ma_dvi is null then
        insert into temp_1(c1,c3,n2,n3,n4,n5,n6,n8,n12,n13,n14,n15,n16,n18) select c29,substr(c3,1,2),sum(n2),sum(n3),sum(n4),sum(n5),sum(n6),sum(n8),sum(n12),
            sum(n13),sum(n14),sum(n15),sum(n16),sum(n18) from temp_3 group by c29,substr(c3,1,2);
        update temp_1 set c16=(select min(ten) from ht_ma_dvi where ma=c1);
    else
        update temp_3 set c1=(select phong from bh_hd_goc where ma_dvi=c29 and so_id=n1);            
        insert into temp_1(c29,c1,c3,n2,n3,n4,n5,n6,n8,n12,n13,n14,n15,n16,n18) select c29,c1,substr(c3,1,2),sum(n2),sum(n3),sum(n4),sum(n5),sum(n6),sum(n8),sum(n12),
            sum(n13),sum(n14),sum(n15),sum(n16),sum(n18) from temp_3 group by c29,c1,substr(c3,1,2);
        update temp_1 set c16=(select min(ten) from ht_ma_phong where ma_dvi=c29 and ma=c1);
    end if;
    update temp_1 set c2='NghiOp vo xe < t<' where c3='XE';
    update temp_1 set c2='NghiOp vo Xe m?y' where c3='2B';
    update temp_1 set c2='NghiOp vo con ng-ei' where c3='NG';
    update temp_1 set c2='NghiOp vo h?ng h?a' where c3='HA';
    update temp_1 set c2='NghiOp vo t?u' where c3='TA';
    update temp_1 set c2='NghiOp vo t?i s?n ku thuEt' where c3='PH';
end if;
update temp_1 set (c17,c18)=(select cb_ql,ma_kt from bh_hd_goc where ma_dvi=c29 and so_id=n1);
update temp_1 set c19=(select ten from ht_ma_cb where ma_dvi=c29 and ma=c17);
commit;
if b_loai='C' then
    open cs_kq for select c3 so_hd,c19 ten_cb,c18 ma_dl,c5 ngay_hl,c4 ngay_kt,sum(nvl(n2,0)) phi,sum(nvl(n3,0)) phi_tt,sum(nvl(n4,0)) phi_no,
        c1 ma_kh,c2 ten,c16 dchi,c17 ma_cb,sum(nvl(n5,0)) phi_no1,PKH_SO_CNG(n7) han_tt ,sum(nvl(n6,0)) tong,sum(nvl(n8,0)) tien_bh,c6 ma_nt
        from temp_1 group by c1,c2,c5,c16,c6,c3,c4,n7,c17,c18,c19 order by c3;
else
    open cs_kq for select c3 so_hd,c19 ten_cb,c18 ma_dl,c5 ngay_hl,c4 ngay_kt,sum(nvl(n12,0)) phi,sum(nvl(n13,0)) phi_tt,sum(nvl(n14,0)) phi_no,
        c1 ma_kh,c2 ten,c16 dchi,c17 ma_cb,sum(nvl(n15,0)) phi_no1,PKH_SO_CNG(n7) han_tt ,sum(nvl(n16,0)) tong,sum(nvl(n18,0)) tien_bh,c6 ma_nt
        from temp_1 group by c1,c2,c5,c16,c6,c3,c4,n7,c17,c18,c19 order by c3;  
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BKE_THUPHI;

CREATE OR REPLACE PROCEDURE BC_BKE_THUPHI
      (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_ngay_d number,
      b_ngay_c number,cs1 out pht_type.cs_type,b_so_hd varchar2:='',b_phong varchar2:='')
AS
      b_loi varchar2(100);
begin
-- Bang ke thanh toan phi xe co gioi
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
open cs1 for select distinct FBH_HD_GOC_SO_HD(ma_dvi,FBH_HD_SO_ID_BS(ma_dvi,so_id,ngay_ht)) so_hd , 'X' tt
      from bh_hd_goc_tthd where ma_dvi=b_ma_dvi and ngay_ht between b_ngay_d and b_ngay_c
      and so_id in (select so_id from bh_hd_goc where ma_dvi=b_ma_dvi and nv in  ('XE','2B','XEL','2BL')
        and (b_phong is null or phong=b_phong) and (b_so_hd is null or so_hd like '%'||b_so_hd||'%')) order by so_hd;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BKE_THUPHIK;

CREATE OR REPLACE PROCEDURE BC_BKE_THUPHIK
      (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_ngay_d number,
       b_ngay_c number,cs1 out pht_type.cs_type,b_so_hd varchar2:='',b_phong varchar2:='')
AS
      b_loi varchar2(100);
begin
-- Hoi bang ke thanh toan phi khac xe co gioi
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
open cs1 for select distinct FBH_HD_GOC_SO_HD(ma_dvi,FBH_HD_SO_ID_BS(ma_dvi,so_id,ngay_ht)) so_hd , 'X' tt
      from bh_hd_goc_tthd where ma_dvi=b_ma_dvi and ngay_ht between b_ngay_d and b_ngay_c
      and so_id in(select so_id from bh_hd_goc where ma_dvi=b_ma_dvi and nv not in ('XE','2B','XEL','2BL')
      and pt  in ('N','G')  and (b_phong is null or phong=b_phong) and (b_so_hd is null or so_hd like '%'||b_so_hd||'%'));
exception when others then raise_application_error(-20105,b_loi);
end;
/

