DROP procedure BC_BK_CN_TON;

CREATE OR REPLACE procedure BC_BK_CN_TON
	(b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
	b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai varchar2,b_ma_kh varchar2,b_tien number,
	b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
	b_dvi out varchar2,b_tennv out varchar2,b_tenloai out varchar2,b_ten_phong out varchar2,
	b_ten_khach out varchar2)
AS
	b_loi varchar2(100);b_ngaydn number;b_i1 number;
Begin
-- bang ke cong no con ton
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
	b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
delete ket_qua;
commit;
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_loi:='loi:Lay so lieu no cuoi ky:loi';
delete temp_1;delete ket_qua;delete temp_2;
insert into temp_1(c1,n1,c2,n2) select ma_dvi,so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_no 
    where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and ngay_ht<=b_ngayc
    group by ma_dvi,so_id,ma_nt;

update temp_1 set n3=(select sum(ton_qd) from bh_hd_goc_sc_no where ma_dvi=c1 and so_id=n1 and ma_nt=c2 and ngay_ht=n2);
insert into temp_2(c1,c2,c4,c10,c11,n4) 
select ma_dvi,ma_kh,so_hd,ma_kt,cb_ql,sum(n3) from bh_hd_goc a,temp_1 b
where (b_ma_dvi is null or a.ma_dvi=b_ma_dvi) and a.ma_dvi=b.c1 and a.so_id=b.n1
and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_phong is null or phong=b_phong)
group by ma_dvi,ma_kh,so_hd,ma_kt,cb_ql;

select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
	insert into ket_qua(c1,c2,c3,c4,c10,c11,n4,n5,n20)
		select c1,c2,c3,c4,c10,c11,sum(n4),sum(n5),n20 from temp_2 group by c1,c2,c3,c4,c10,c11,n20;
else
	insert into ket_qua(c1,c2,c3,c4,c10,c11,n4,n5,n20)
		select c1,c2,c3,c4,c10,c11,sum(n4),sum(n5),n20 from temp_2,temp_bc_dvi where c1=dvi group by c1,c2,c3,c4,c10,c11,n20;
end if;
update ket_qua set c3 =(select ten from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=ket_qua.c2);
update ket_qua set c12 =(select ten from bh_dl_ma_kh where ma_dvi=b_ma_dvi and ma=ket_qua.c10);
update ket_qua set c13 =(select ten from ht_ma_cb where ma_dvi=b_ma_dvi and ma=ket_qua.c11);
update ket_qua set c20 =(select ten from ht_ma_dvi where ma=ket_qua.c1);
delete ket_qua where nvl(n4,0)=0 and nvl(n5,0)=0;
commit;
open cs_kq for select c1 ma_dvi,c20 ten_dvi,c2 ma_kh,c3 ten,c4 so_hd,c10 ma_dl,c12 ten_dl,c11 ma_cb,
	c13 ten_cb, n4 dt_tt from ket_qua order by c1,c2,c3,c4;
	exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BK_NOP_PHI;

CREATE OR REPLACE PROCEDURE BC_BK_NOP_PHI
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type,
    b_dvi out varchar2,b_tennv out varchar2,b_tenloai out varchar2,
    b_ten_phong out varchar2,b_ten_khach out varchar2)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number;
Begin
-- Bang ke nop phi theo can bo quan ly
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';
if b_ma_dvi is not null then
    select ten into b_dvi from ht_ma_dvi where ma=b_ma_dvi;
else b_dvi:=' ';
end if;
if b_ma_nv is not null then
    select ten into b_tennv from bh_ma_lhnv where ma_dvi=b_ma_dvi and ma=b_ma_nv;
else b_tennv:=' ';
end if;
if b_loai is not null then
    select ten into b_tenloai from kh_ma_loai_dn where ma_dvi=b_ma_dvi and ma=b_loai;
else    b_tenloai:=' ';
end if;
if b_phong is not null then
    select ten into b_ten_phong from ht_ma_phong where ma_dvi=b_ma_dvi and ma=b_phong;
else b_ten_phong:=' ';
end if;
if b_ma_kh is not null then
    select ten into b_ten_khach from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=b_ma_kh;
else b_ten_khach:=' ';
end if;
delete temp_1;delete temp_2;delete ket_qua; commit;
insert into temp_1(c1,c2,c3,c4,c5,n1,n2,c12,c13,n4)
    select so_hd,a.ma_kh,c.ten,c.cmt,cb_ql,sum(phi_qd),sum(thue_qd),PKH_CNG_SO(a.ngay_hl),
    PKH_CNG_SO(a.ngay_kt),sum(ttoan_qd) from bh_hd_goc a,bh_hd_goc_ttpt b,bh_hd_ma_kh c
    where a.ma_dvi=b_ma_dvi and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
    and a.ma_dvi=c.ma_dvi and a.ma_kh=c.ma and b.pt in ('N','G')
    and b.so_id_tt in (select so_id_tt from bh_hd_goc_ttps where ma_dvi=b_ma_dvi and so_id_kt=0)
    and (b.ngay_tt between b_ngayd and b_ngayc)
    and (b_phong is null or phong=b_phong)
    and (b_ma_kh is null or a.ma_kh=b_ma_kh)
    and (b_ma_nv is null or lh_nv like b_ma_nv||'%')
    and (b_ma_cb is null or cb_ql=b_ma_cb)
    group by so_hd,a.ma_kh,c.ten,c.cmt,cb_ql,a.ngay_hl,a.ngay_kt;
update temp_1 set c6 =(select ten from ht_ma_cb where ma_dvi=b_ma_dvi and ma=temp_1.c5);
update temp_1 set c3 =(select ten from bh_hd_ma_kh where ma_dvi=b_ma_dvi and ma=temp_1.c2);
open cs_kq for select c5 cb_ql,c6 ten_cb,c2 ma_kh,c3 ten,c1 so_hd,
    nvl(n1,0) dt_tt, nvl(n2,0) thue from temp_1  order by c1,c2,c5;
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_BT_NV_CGQ_DO_TAI;

CREATE OR REPLACE PROCEDURE BC_BT_NV_CGQ_DO_TAI
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_nguon varchar2, b_ma_dt varchar2,b_ma_dl varchar2,b_hd varchar2,b_tc varchar2,
    b_ngayd number,b_ngayc number,cs1 out pht_type.cs_type)
AS
    b_loi varchar2(100);b_i1 number;
Begin
    -- Bao cao ho so boi thuong chua giai quyet
    b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    if b_ngayd is null or b_ngayc is null then
        b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
    end if;
    b_loi:='loi:Ma chua dang ky:loi';
    --LAM SACH
