--         and a.nv in (Select nv from temp_bc_nv);

    if b_hd='T' then
        delete temp_6 where n7 not between b_ngayd and b_ngayc;
    end if;
    update temp_6 set n8=(Select sum(tien_qd) from bh_bt_gd_hs_pt where so_id_bt=n1 and so_id_hd=n3 and so_id_dt=n4 and lh_nv=c4);
    update temp_6 set n8=(Select case max(ma_nt) when 'VND' then sum(tien) else sum(tien_qd) end from bh_bt_gd_hs
                    where so_id_bt=n1 and so_id_hd=n3 and ngay_ht>=n7  and ngay_ht<b_ngayc) where n8=0 or n8 is null;
--     update temp_6 set n16=(select sum(tien_qd) from bh_bt_ntba_pb where ma_dvi=c1 and so_id_hd=n3 and (lh_nv='*' or lh_nv=c4));
--     update temp_6 set n9=(select sum(pt) from bh_hd_do_tl where so_id=n3 and (so_id_dt=0 or so_id_dt=n4) and (lh_nv='*' or lh_nv=c4)
