       commit;

    open cs1 for
        select c13 nhom_lhnv1, c15 nhom_lh_nv2, c5 ten_lhnv,
            round(n6) tien_bt, round(n8) tien_gd, round(n16) tien_thu, (nvl(n6,0)+nvl(n8,0)+nvl(n16,0)) bt_tong,
            round(n10) tien_bt_dong, round(n11) tien_gd_dong, round(n17) tien_thu_dong,
