    BBC_LAY_NV(b_madvi,b_nsd,'','');
    insert into temp_6(c1, c20, n1, c21, c2, c3, c4, n2, n3, n4, n5, n6, n7)
        select a.ma_dvi,a.ma_dvi_hd, a.so_id, b.so_hd, a.nv, a.phong, a.lh_nv, a.ngay_qd_n, a.so_id_hd, a.so_id_dt, a.tien, a.tien_qd, a.ngay_ht
        from bc_bh_bt_temp a, bh_hd_goc b where a.so_id_hd=b.so_id and a.ma_dvi_hd=b.ma_dvi
        and a.nv in (Select nv from temp_bc_nv);
    if b_hd='T' then
        delete temp_6 where n7 not between b_ngayd and b_ngayc;
    end if;
    update temp_6 set n8=(Select sum(tien_qd) from bh_bt_gd_hs_pt where so_id_bt=n1 and so_id_hd=n3 and so_id_dt=n4 and lh_nv=c4);
    update temp_6 set n8=(Select case ma_nt when 'VND' then tien else tien_qd end from bh_bt_gd_hs
                    where ma_dvi=c1 and so_id_bt=n1 and so_id_hd=n3 and ngay_ht>=n7  and ngay_ht<b_ngayc and rownum=1) where n8=0 or n8 is null;
