    update temp_6 set n10=round(n10*100/n20,4) where n20<>1;
    --them vao truong hop co dong
    update temp_6 set n8=round(n8*n20/100,0) where n20<>1;

    insert into temp_5(c4, n6, n8, n16, n10, n11, n17, n12, n13, n18, n14, n15, n19)
            select c4, sum(nvl(n6,0)), sum(nvl(n8,0)), sum(nvl(n16,0)),
                    sum(nvl(n6,0)*nvl(n9,0)/100), sum(nvl(n8,0)*nvl(n9,0)/100), sum(nvl(n16,0)*nvl(n9,0)/100),
                    sum(nvl(n6,0)*nvl(n10,0)/100), sum(nvl(n8,0)*nvl(n10,0)/100), sum(nvl(n16,0)*nvl(n10,0)/100),
                    sum(nvl(n6,0))-sum(nvl(n6,0)*nvl(n9,0)/100)- sum(nvl(n6,0)*nvl(n10,0)/100),
                    sum(nvl(n8,0))-sum(nvl(n8,0)*nvl(n9,0)/100)- sum(nvl(n8,0)*nvl(n10,0)/100),
                    sum(nvl(n16,0))-sum(nvl(n16,0)*nvl(n9,0)/100)- sum(nvl(n16,0)*nvl(n10,0)/100)
                    from temp_6 group by c4;

    update temp_5 set c5=(Select max(ten) from bh_ma_lhnv where ma=c4 );
--    update temp_5 set (c14, c15)=
--            (Select substr(c4,1,4),ten from bh_ma_lhnv where ma=substr(c4,1,4) and ma_dvi='000')
--            where substr(c4,1,2) in ('XG','TT','TN');
