--         (Select 'HP.1',ten from bh_ma_lhnv where ma='HP.1' and ma_dvi='000')
--         where substr(c4,1,4) in ('HP.1');
--     update temp_5 set c14='HP.K', c15='Nhom khac' where substr(c4,1,4) not in ('HP.1') and substr(c4,1,2)='HP';
--    update temp_5 set (c14, c15)=
--    (Select 'HH',ten from bh_ma_lhnv where ma='HH' and ma_dvi='000')
--    where substr(c4,1,2) in ('HH');
--
--    update temp_5 set (c12,c13)=(Select substr(c4,1,2),ten from bh_ma_lhnv where ma=substr(c4,1,2) and ma_dvi='000');
--    update temp_5 set c13='1. '||c13 where c12='CN';
--    update temp_5 set c13='2. '||c13 where c12='XG';
--    update temp_5 set c13='3. '||c13 where c12='HH';
--    update temp_5 set c13='4. '||c13 where c12='TT';
--    update temp_5 set c13='5. '||c13 where c12='TS';
--    update temp_5 set c13='6. '||c13 where c12='KT';
--    update temp_5 set c13='7. '||c13 where c12='HP';
--    update temp_5 set c13='8. '||c13 where c12='TN';
      commit;
    open cs1 for
        select '' nhom_lhnv1, '' nhom_lh_nv2, c5 ten_lhnv,
            round(n6) tien_bt, round(n8) tien_gd, round(n16) tien_thu, (nvl(n6,0)+nvl(n8,0)+nvl(n16,0)) bt_tong,
            round(n10) tien_bt_dong, round(n11) tien_gd_dong, round(n17) tien_thu_dong,
            round(n12) tien_bt_tai, round(n13) tien_gd_tai, round(n18) tien_thu_tai,
