DROP PROCEDURE BC_BT_SODU;
CREATE OR REPLACE PROCEDURE BC_BT_SODU
	(b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
	b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
	b_ma_kh varchar2,b_tc varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
	b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaynt number; b_i1 number;b_ngayd1 number;
Begin
-- Bao cao nhanh tinh hinh  boi thuong xem theo kieu tron thang
--tinh chat la C de in cac ma bao cao theo nghiep vu, tinh chat K in cac bao cao gom theo phong, theo don vi,khach hang vv...
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
	b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;delete temp_2;delete ket_qua; commit;
/*  c1 lh_nv,c2 so_hd,c3 ma_kh,c4 phong,c5 loai_kh,n13 so_id_hd
	n1 dtbh_lk,n2 tien_tk,n3 tien_lk */
b_ngaynt:=round(b_ngayc,-4)-10000 +1231;
b_ngayd1:=PKH_NG_CSO(PKH_SO_CDT(b_ngayd)-1);
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
	b_loi:='loi:Ban khong co quyen xem bao cao nay:loi'; raise PROGRAM_ERROR;
end if;
/* temp_1 c1 nv,c2 so_hs ,c3 gcn,c4 so_hd,c5 ma_kh,c6 phong
	c19 ngay_gui,c7 ngay_xr, c8  kvuc,c9 n_trinh, c10 n_duyet,c11 ngay_qd,
	c12 ma_nn,c13 ma_md,c14 quy_loi,c15 nd,c16 loai_kh,c17 ma_nt,c18 lh_nv,c20 nv, n10 so_id,n11 ngay_hthd,n12 ngay_htbt,n13 so_id_hd
	n2 tien_bh,n3 pt_bt, n4 t_that,n5 k_tru,n6 tien,n7 tien_qd,n8 so_id_dt
*/
/*  temp_2 c1 ma_dvi,c2 ma_kh,c3 ma_dl,c4 phong,c5 so_hd,c6 so_hs,c7 ngay_ht,c8 ngay_xr,c9 ngay_qd,c10 ngay_gui,
	n1 so_vudk,n2 tiendk,n3 so_vutang,n4 tientang,n5 so_vugiam,n6 tiengiam,n7 so_vuck,n8 tienck
*/
--ho so boi thuong dau ky 
BC_BH_THBT_MD_CD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngaydn,b_ngayd1,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,n1,n2,n10) 
	select c29,c5,'',c6,c4,c2,PKH_SO_CNG(n12),c7,c11,c19,1,n7,n10 from temp_1;
--ho so boi thuong phat sinh giam
BC_BH_THBT_MD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngayd,b_ngayc,b_loi,'B');
insert into temp_2 (c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,n5,n6,n10) 
	select c29,c5,'',c6,c4,c2,PKH_SO_CNG(n14),c7,c11,c19,1,n7,n10 from temp_1;
--trong ky
insert into temp_2 (c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,n15,n16,n10) 
	select c29,c5,'',c6,c4,c2,PKH_SO_CNG(n14),c7,c11,c19,1,n7,n10 from temp_1 where n14 between b_ngayd  and b_ngayc;
--ho so boi thuong cuoi ky 
BC_BH_THBT_MD_CD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngaydn,b_ngayc,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,n7,n8,n10) 
	select c29,c5,'',c6,c4,c2,PKH_SO_CNG(n12),c7,c11,c19,1,n7,n10 from temp_1;
--trong ky
insert into temp_2 (c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,n17,n18,n10) 
	select c29,c5,'',c6,c4,c2,PKH_SO_CNG(n12),c7,c11,c19,1,n7,n10 from temp_1 where n12 between b_ngayd and b_ngayc;
--ho so boi thuong phat sinh tang
--cuoiky-dk+giam
BC_BH_BTHS_MD(b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngayd,b_ngayc,b_loi);
insert into temp_2 (c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,n3,n4,n10) 
	select c29,c5,'',c6,c4,c2,PKH_SO_CNG(n12),c7,c11,c19,1,
	case c17 when U'VND' then n6 else FTT_VND_QD(c29,n12,c17,n6) end,n10  from temp_1 where n6<>0;
--update temp_2 set n3=nvl(n7,0)-nvl(n1,0),n4=nvl(n8,0)-nvl(n2,0)+ nvl(n6,0);

--update temp_2 set c3=(select ma_kt from bh_hd_goc where ma_dvi=c1 and so_hd=c5);
MERGE INTO temp_2
    USING bh_hd_goc
    ON (temp_2.c1 = bh_hd_goc.ma_dvi AND temp_2.c5 = bh_hd_goc.so_hd)
    WHEN MATCHED THEN
    UPDATE SET temp_2.c3 = bh_hd_goc.ma_kt;


update temp_2  set c11=(select ten from ht_ma_dvi where ma=temp_2.c1);

--update temp_2  set c12=(select ten from bh_hd_ma_kh where ma_dvi=temp_2.c1 and ma=temp_2.c2);

update (select temp_2.c12 temp_2_c12, bh_hd_ma_kh.ten bh_hd_ma_kh_ten
             from   temp_2, bh_hd_ma_kh
             where  temp_2.c1 = bh_hd_ma_kh.ma_dvi
                    and temp_2.c2 = bh_hd_ma_kh.ma)
    set temp_2_c12 = bh_hd_ma_kh_ten;
    

update temp_2  set c13=(select ten from bh_dl_ma_kh where ma_dvi=temp_2.c1 and ma=temp_2.c3);
update temp_2  set c14=(select ten from ht_ma_phong where ma_dvi=temp_2.c1 and ma=temp_2.c4);
--update temp_2  set c17=(select ten from bh_ma_lhnv where ma_dvi=ket_qua.c29 and ma=ket_qua.c7);
--update temp_2 set c20=(select substr(nd,1,250) from bh_bt_hs where ma_dvi=b_ma_dvi and so_id=temp_2.n10 and rownum=1);
select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
	open cs_kq for select c1 ma_dvi,c11 ten_dvi,c2 ma_kh,c12 ten_kh,c3 ma_dl,c13 ten_dl,
		c4 ma_phong,c14 ten_phong,c5 so_hd,c6 so_hs,c7 ngay_ht,c8 ngay_xr,c9 ngay_qd,c10 ngay_gui,
		sum(nvl(n1,0)) so_vudk,sum(nvl(n2,0)) tien_dk,sum(nvl(n3,0)) so_vutang,sum(nvl(n4,0)) tientang,
		sum(nvl(n5,0)) so_vugiam,sum(nvl(n6,0)) tiengiam,sum(nvl(n15,0)) so_vugiam_tk,sum(nvl(n16,0)) tiengiam_tk,
		sum(nvl(n7,0)) so_vuck,sum(nvl(n8,0)) tienck,sum(nvl(n17,0)) so_vuck_tk,sum(nvl(n18,0)) tienck_tk
		from temp_2 group by c1,c11,c2,c12,c3,c13,c4,c14,c5,c6,c7,c8,c9,c10  order by c1,c6;
else
	open cs_kq for select c1 ma_dvi,c11 ten_dvi,c2 ma_kh,c12 ten_kh,c3 ma_dl,c13 ten_dl,
		c4 ma_phong,c14 ten_phong,c5 so_hd,c6 so_hs,c7 ngay_ht,c8 ngay_xr,c9 ngay_qd,c10 ngay_gui,
		sum(nvl(n1,0)) so_vudk,sum(nvl(n2,0)) tien_dk,sum(nvl(n3,0)) so_vutang,sum(nvl(n4,0)) tientang,
		sum(nvl(n5,0)) so_vugiam,sum(nvl(n6,0)) tiengiam,sum(nvl(n15,0)) so_vugiam_tk,sum(nvl(n16,0)) tiengiam_tk,
		sum(nvl(n7,0)) so_vuck,sum(nvl(n8,0)) tienck,sum(nvl(n17,0)) so_vuck_tk,sum(nvl(n18,0)) tienck_tk
		from temp_2 group by c1,c11,c2,c12,c3,c13,c4,c14,c5,c6,c7,c8,c9,c10  order by c1,c6;
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_CONT_EMAIL;

