/******************************************************************************
   NAME:       BC_CONT_EMAIL
   PURPOSE:    

   REVISIONS:
   Ver        Date        Author           Description
   ---------  ----------  ---------------  ------------------------------------
   1.0        10/28/2024   adminlocal       1. Created this procedure.

   NOTES:

   Automatically available Auto Replace Keywords:
      Object Name:     BC_CONT_EMAIL
      Username:        adminlocal (set in TOAD Options, Procedure Editor)
      Table Name:       (set in the "New PL/SQL Object" dialog)

******************************************************************************/
as
BEGIN
   delete temp_s_1;
   insert into temp_s_1 (c1) values('HO');
