DROP PROCEDURE BC_CT_DT_GOC_NGUON;

CREATE OR REPLACE PROCEDURE BC_CT_DT_GOC_NGUON
(
    b_ma_dvi varchar2, b_nsd varchar2, b_pas varchar2,
    b_dvi varchar2, b_phong varchar2, b_lhnv varchar2,
    b_ma_kh varchar2, b_loai_kh varchar2, b_ma_dt varchar2, b_ma_dl varchar2, b_nguon varchar2,
    b_ngayd number, b_ngayc number, cs1 out  pht_type.cs_type
)
as
    b_loi nvarchar2(250);b_ngaydn number; b_ng varchar2(20); b_i1 number; b_dvi_bc varchar2(10);
begin
-- BCNam dieu chinh bao cao doanh thu chi tiet
    b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
--   if b_nguon is null then
--        b_loi:='loi:1Chon ma gioi thieu khai thac:loi';
--        raise PROGRAM_ERROR;
--    end if;

    b_ngaydn:=round(b_ngayd,-4)+101;
    --delete temp_bc_nv; delete temp_bc_ts; delete temp_2; commit;
    execute immediate 'truncate table temp_bc_nv';
    execute immediate 'truncate table temp_bc_ts';
    execute immediate 'truncate table temp_2';
    --BCNam: Cho Ban KHCN xem so lieu
    if b_nsd = 'KHCN' and b_ma_dvi ='00' then
        BBC_LAY_NV('00','ADMIN','','');
    else
        BBC_LAY_NV(b_ma_dvi,b_nsd,'','');
    end if;
    if b_dvi='00' or b_dvi ='' then
        b_dvi_bc:='00';
    else
        b_dvi_bc:=b_dvi;
    end if;
    insert into temp_bc_ts values (b_dvi_bc||'%',b_ngayd,b_ngayc);
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MNVM';
    BC_BH_LAY_BC_BH_DTPS_MNVM(b_dvi_bc,b_ngayd,b_ngayc);
    insert into temp_2 (n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n2, n3)
        select so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
        from TEMP_BC_BH_DTPS_MNVM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
        and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
        and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%'
        group by so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
    -- doanht hu ban hang trong ky
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MNVM';
    BC_BH_LAY_BC_BH_DTBH_MNVM(b_dvi_bc,b_ngayd,b_ngayc);
    insert into temp_2 (n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n4, n5)
        select so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
        from TEMP_BC_BH_DTBH_MNVM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
        and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
        and (b_ma_dl is null or ma_kt=b_ma_dl)  and ma_dvi like b_dvi_bc||'%'
        group by so_id, ma_dvig, ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
    -- doanh thu thuc thu trong ky
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
    BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi_bc,b_ngayd,b_ngayc);
    insert into temp_2 (n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
        select so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
        from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
        and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
        and (b_ma_dl is null or ma_kt=b_ma_dl)  and ma_dvi like b_dvi_bc||'%'
        group by so_id, ma_dvig, ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;

    --doanh thu luy ke
    --rao luy ke theo yc cua Han
--    if b_ngayd<>b_ngaydn then
--        delete temp_bc_ts;
--        insert into temp_bc_ts values (b_dvi||'%',b_ngaydn,b_ngayc);
--
--        EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MNVM';
--        BC_BH_LAY_BC_BH_DTPS_MNVM(b_dvi_bc,b_ngaydn,b_ngayc);
--        insert into temp_2 (n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n8, n9)
--            select so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
--            from TEMP_BC_BH_DTPS_MNVM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%'
--            group by so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
--        -- doanht hu ban hang trong ky
--        EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MNVM';
--        BC_BH_LAY_BC_BH_DTBH_MNVM(b_dvi_bc,b_ngaydn,b_ngayc);
--        insert into temp_2 (n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n10, n11)
--            select so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
--            from TEMP_BC_BH_DTBH_MNVM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%'
--            group by so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
--        -- doanh thu thuc thu trong ky
--        EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--        BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi_bc,b_ngaydn,b_ngayc);
--        insert into temp_2 (n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n12, n13)
--            select so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
--            from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%'
--            group by so_id, ma_dvig, ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
--    else
--        update temp_2 set n8=n2, n10=n4, n12=n6;
--    end if;

    delete temp_3; 
    insert into temp_3(c1, c2, c3, c4, c5, c6, c7, c8, c19, n2, n3, n4, n5, n6,n7,n8,n9,n10,n11,n12,n13,n1,c14)
        select c1, c2, c3, c4, c5, c6, c7, substr(c8,1,2), ten,
            sum(n2) dt_ps_tk, sum(n3) thue_ps_tk, sum(n4) dt_bh_tk, sum(n5) thue_bh_tk, sum(n6) dt_tt_tk,
            sum(n7) thue_tt_tk,sum(n8) dt_ps_lk, sum(n9) thue_ps_lk, sum(n10) dt_bh_lk, sum(n11) thue_bh_lk,
            sum(n12) dt_tt_lk, sum(n13) thue_tt_lk,n20,nv
        from temp_2, bh_hd_goc
        where so_id=n20 and ma_dvi=c20
        group by c1, c2, c3, c4, c5, c6, c7, substr(c8,1,2),ten,n20,nv;

    -- Hung kiem tra so hang phai < 65000
    /*
    select count(*) into b_i1 from temp_3;
    if b_i1>65000 then
        b_loi:='loi:So dong bao cao > 65000, khong mo duoc excel:loi'; raise PROGRAM_ERROR;
    end if;
    */

    if b_loai_kh is not null then
        update temp_3 set c20=(Select loai from bh_hd_ma_kh where ma_dvi=c1 and ma=c4);
        /*
        update
            (select temp_3.c20 temp_3_c20, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
                from temp_3, bh_hd_ma_kh
                where temp_3.c1 = bh_hd_ma_kh.ma_dvi and temp_3.c4 = bh_hd_ma_kh.ma)
                set temp_3_c20 = bh_hd_ma_kh_loai;
        */
        delete temp_3 where c20 not like b_loai_kh||'%';
    end if;

    --update temp_3 set c21=(Select ten from bh_ma_lhnv where ma_dvi='000' and ma=substr(c8,1,2));
    merge into temp_3
    using (Select ten,ma from bh_ma_lhnv where ma_dvi='000')a
    on (a.ma = substr(c8,1,2)) when matched then update
    set c21 = a.ten;
    --update temp_3 set c22=(Select nvl(ten,'N/A') from kh_ma_nhang where ma_dvi='00' and ma=c5);
--     merge into temp_3
--     using (Select ten,ma from kh_ma_nhang where ma_dvi='00')a
--     on (a.ma = c5) when matched then update
--     set c22 = a.ten;
    
    merge into temp_3
    using (Select ten,ma_dvi,ma from bh_dl_ma_kh )a
    on (a.ma = c5 and a.ma_dvi=c1) when matched then update
    set c29 = a.ten;
    
    --update temp_3 set (c24,c25)=(Select ma_kh,tax from bh_hd_ma_kh where ma_dvi=c1 and ma=c4);
    update
            (select temp_3.c24 temp_3_c20, bh_hd_ma_kh.loai bh_hd_ma_kh_ma_kh,temp_3.c25 temp_3_c25, bh_hd_ma_kh.cmt bh_hd_ma_kh_tax,
                temp_3.c32 temp_3_c32,bh_hd_ma_kh.cmt bh_hd_ma_kh_so_cmt
                from temp_3, bh_hd_ma_kh
                where temp_3.c1 = bh_hd_ma_kh.ma_dvi and temp_3.c4 = bh_hd_ma_kh.ma)
                set temp_3_c20 = bh_hd_ma_kh_ma_kh,temp_3_c25=bh_hd_ma_kh_tax,temp_3_c32=bh_hd_ma_kh_so_cmt ;--temp_3_c31=bh_hd_ma_kh_tax,

--    if b_lhnv like 'TS%' then
        update temp_3 set (c15,n15)=(select min(nt_tien),nvl(sum(tien),0) from bh_hd_goc_dk where ma_dvi=c1 and so_id=n1);
       

       merge into temp_3
       using bh_hd_goc a
       on (c1=a.ma_dvi and n1=a.so_id)
       when matched then update
         --LAM SACH
       set c26 = a.nsd,c27 = a.ma_kt,c28=a.kieu_kt,c30=ma_gt,c34=a.ngay_hl,c35=a.ngay_kt,c36=a.ngay_cap;
--        delete temp_3 where trim(c30)='' and c27 not in (select ma from KH_MA_NHANG where c27=ma and ma_dvi=c1);--han
       merge into temp_3
       using bh_ng a
       on (c1=a.ma_dvi and n1=a.so_id)
       when matched then update set c33 = a.cmt;
       commit;
    open cs1 for
        select c1 ma_dvi, c2 phong, c3 so_hd, c4 ma_kh, c19 ten_kh, c5||' - '||c22 ma_nguon,c29 ma_nguon_dl, c21 ten_lhnv, c22 ten_nguon,
            sum(n2) dt_ps_tk, sum(n3) thue_ps_tk, sum(n4) dt_bh_tk, sum(n5) thue_bh_tk, sum(n6) dt_tt_tk, sum(n7) thue_tt_tk,
            sum(n8) dt_ps_lk, sum(n9) thue_ps_lk, sum(n10) dt_bh_lk, sum(n11) thue_bh_lk, sum(n12) dt_tt_lk,
            sum(n13) thue_tt_lk, c24 loai_kh, c25 tax,c15 nt_tien, n15 tien_bh,c26 nsd,c27 ma_kt,c28 kieu_kt,c25 MST,c32 CMT_NG_MUA,c33 CMT_NG_HUONG,c34 ngay_hl,c35 ngay_kt,c36 ngay_cap
            ,c37 pp_tl,c38 pp_tinh
        from temp_3 group by c1, c2, c3, c4, c19, c5, c21, c22, c24,c25,c15,n15,c26,c27,c28,c29,c32,c33,c34,c35,c36,c37,c38;

exception when others then raise_application_error(-20105,b_loi);
end;

/

DROP PROCEDURE BC_CT_DT_HH_NGUON;

CREATE OR REPLACE PROCEDURE BC_CT_DT_HH_NGUON
(
    b_ma_dvi varchar2, b_nsd varchar2, b_pas varchar2,
    b_dvi varchar2, b_phong varchar2, b_lhnv varchar2,
    b_ma_kh varchar2, b_loai_kh varchar2, b_ma_dt varchar2, b_ma_dl varchar2, b_nguon varchar2,
    b_ngayd number, b_ngayc number, cs1 out  pht_type.cs_type
)
as
    b_loi nvarchar2(250);b_ngaydn number; b_ng varchar2(20); b_i1 number;
begin
    b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
--    if b_nguon is null then
--        b_loi:='loi:Chon ma gioi thieu khai thac:loi';
--        raise PROGRAM_ERROR;
--    end if;

    delete temp_bc_nv; delete temp_bc_ts; commit;
    BBC_LAY_NV(b_ma_dvi,b_nsd,'','');

    delete temp_bc_ts;
    insert into temp_bc_ts values (b_dvi||'%',b_ngayd,b_ngayc);
    delete temp_1;

    insert into temp_1(c1, n1, c2, c3, c4, c5, c6, c7, c8, n2, c9)
        select ma_dvi, so_id, so_hd, nv, ma_kh, nguon, phong, ma_kt, lh_nv, phi, ma_dvig
        from v_bc_bh_dtps_mm where (b_nguon is null or nguon like b_nguon||'%') and (b_ma_dl is null or ma_kt = b_ma_dl)
        and (b_phong is null or phong = b_phong) and (b_ma_kh is null or ma_kh = b_ma_kh);

    insert into temp_1(c1, n1, c2, c3, c4, c5, c6, c7, c8, n3, c9)
        select ma_dvi, so_id, so_hd, nv, ma_kh, nguon, phong, ma_kt, lh_nv, phi, ma_dvig
        from V_BC_BH_DTBH_MM where(b_nguon is null or nguon like b_nguon||'%') and (b_ma_dl is null or ma_kt = b_ma_dl)
        and (b_phong is null or phong = b_phong) and (b_ma_kh is null or ma_kh = b_ma_kh);
--LAM SACH
--     insert into temp_1(c1, n1, c2, c3, c4, c5, c6, c7, c8, n4, c9)
--         select ma_dvi, so_id, so_hd, nv, ma_kh, nguon, phong, ma_kt, lh_nv, phi, ma_dvig
--         from v_bc_bh_dttt_mm where (b_nguon is null or nguon like b_nguon||'%') and (b_ma_dl is null or ma_kt = b_ma_dl)
--         and (b_phong is null or phong = b_phong) and (b_ma_kh is null or ma_kh = b_ma_kh);

    delete temp_2;

    insert into temp_2(c1, n1, c2, c3, c4, c7, c8, n2, n3, n4, c9)
        select c1, n1, c2, c3, c4, c7, c8, sum(n2), sum(n3), sum(n4),c9
            from temp_1 group by c1, n1, c2, c3, c4, c7, c8, c9;

    update temp_2 set (c15, n15)=(Select max(nt_tien), sum(tien) from bh_hd_goc_dk
                                where ma_dvi = c9 and so_id = n1 and lh_nv = c8);
    update temp_2 set (n6, n7) = (Select max(hhong_tl), sum(FTT_VND_QD(ma_dvi,b_ngayc,ma_nt,hhong)) from bh_hd_goc_ttpb where
                                ma_dvi = c1 and so_id = n1 and ngay_ht between b_ngayd and b_ngayc
                                and pt <> 'C' and ma_dl = c7 and lh_nv = c8);

    update temp_2 set c10 = (Select ten from bh_ma_lhnv where ma_dvi = c1 and ma = c8);
    update temp_2 set c11 = (Select ten from bh_ma_lhnv where ma_dvi = c1 and ma = substr(c8,1,2));
    update temp_2 set c12 = (select ten from bh_hd_goc where so_id = n1 and ma_dvi = c9);

    open cs1 for
        select n1, c9, c1 ma_dvi, c2 so_hd, c5 gioi_thieu, c8 lhnv, c10 ten_lhnv, c11 nhom_lhnv, c12 ten_kh,
               n2 ps_tk, n3 tt_tk, n4 tt_lk, n6 hhong_tl, n7 hhong, n15 tien_bh, c15 nt_tien_bh
        from temp_2 order by c11, c2, c8;
    commit;
exception when others then raise_application_error(-20105,b_loi);
end;

/

DROP PROCEDURE BC_DS_XE_GCN_HUY;

CREATE OR REPLACE PROCEDURE BC_DS_XE_GCN_HUY
(
    b_ma_dvi varchar2, b_nsd varchar2, b_pas varchar2, 
    b_dvi varchar2, b_nv varchar2, b_ngayd number, b_ngayc number,
    cs1 out pht_type.cs_type
)
as
    b_loi nvarchar2(250);
begin
    b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
    delete temp_1;commit;
    if b_nv is not null and b_nv not in ('XE','2B') then
        b_loi:='loi:Chon nghiep vu xe o to hoac xe may:loi';            
        raise PROGRAM_ERROR;
    end if;
    if b_nv = 'XE' then
        insert into temp_1(c20, c1, c2, c3, c4, c5, c6, c7, c8,
                          c9, n1, d1, d2, d3)
            select a.ma_dvi, a.so_hd, a.phong, 'XE', b.gcn, a.ten ,''dchi, b.bien_xe, b.so_khung, 
                b.so_may, b.ttoan, PKH_SO_DATE(a.ngay_hl), PKH_SO_DATE(a.ngay_kt), PKH_SO_DATE(a.ngay_cap)  from bh_hd_goc a, bh_xe_ds  b
                where a.ngay_ht between b_ngayd and b_ngayc and a.ttrang = 'H' and a.ma_dvi = b_dvi and a.ma_dvi = b.ma_dvi and a.so_id = b.so_id;
--        insert into temp_1(c20, c1, c2, c3, c4, c5, c6, c7, c8,
--                          c9, n1, d1, d2, d3)
--                          
--            select a.ma_dvi, a.so_hd, a.phong, 'XEL',a.so_hd, a.ten ,a.dchi, a.bien_xe, a.so_khung, 
--                a.so_may, a.ttoan, a.ngay_hl, a.ngay_kt, a.ngay_cap  from bh_xelgcn a
--                where a.ngay_ht between b_ngayd and b_ngayc and a.ttrang = 'H' and a.ma_dvi = b_dvi;
    end if;    

    if b_nv = '2B' then    
       insert into temp_1(c20, c1, c2, c3, c4, c5, c6, c7, c8,
                          c9, n1, d1, d2, d3)
        select a.ma_dvi, a.so_hd, a.phong,'2B', b.gcn, a.ten ,''dchi, b.bien_xe, b.so_khung, 
            b.so_may, b.ttoan phi, PKH_SO_DATE(a.ngay_hl), PKH_SO_DATE(a.ngay_kt), PKH_SO_DATE(a.ngay_cap)  from bh_hd_goc a, bh_2b_ds  b
            where a.ngay_ht between b_ngayd and b_ngayc and a.ttrang = 'H' and a.ma_dvi = b_dvi and a.ma_dvi = b.ma_dvi and a.so_id = b.so_id;    
        
--        insert into temp_1(c20, c1, c2, c3, c4, c5, c6, c7, c8,
--                          c9, n1, d1, d2, d3)
--        select a.ma_dvi, a.so_hd, a.phong,'2BL',a.so_hd, a.ten ,''dchi, a.bien_xe, a.so_khung, 
--            a.so_may, a.ttoan phi, a.ngay_hl, a.ngay_kt, a.ngay_cap  from bh_2blgcn a
--            where a.ngay_ht between b_ngayd and b_ngayc and a.ttrang = 'H' and a.ma_dvi = b_dvi;
    end if;
    
    open cs1 for
        select c20 ma_dvi, c1 so_hd, c2 phong, c3 nv, c4 gcn, c5 ten_kh, c6 dia_chi, c7 bien_xe, c8 so_khung,
                          c9 so_may, n1 phi_bh, d1 ngay_hl, d2 ngay_kt, d3 ngay_cap
        from temp_1;
    exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_DTHU_GOC_TBH_CT;
CREATE OR REPLACE PROCEDURE BC_DTHU_GOC_TBH_CT
    (b_ma_dvi varchar2, b_nsd varchar2, b_pas varchar2,
    b_dvi varchar2, b_phong varchar2, b_ma_kh varchar2,b_nguon varchar2,
    b_loai_kh varchar2, b_lh_nv varchar2, b_ma_dt varchar2, b_kieu_dt varchar2,
    b_ngayd number, b_ngayc number, cs1 out pht_type.cs_type)
as
    b_loi nvarchar2(250); b_tle_ptl number; b_i1 number;b_so_id number;b_ky_tt nvarchar2(20);b_ky_tt_all nvarchar2(2000);
    b_ten_proc varchar2(40);b_ngaydn number;
begin
--b_loi:='loi:'||b_kieu_dt||'-:loi';  raise PROGRAM_ERROR;
    --Bao cao doanh thu chi tiet co phi tai
    --BCNam bo sung lay du lieu theo nhu cau MIC
    b_ngaydn := substr(b_ngayc,0,4)||'0101';
    b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
/*
   -- Lock: de single run
   select count(*) into b_i1 from cmc_lock_proc where ten_proc='BC_DTHU_GOC_TBH_CT';
   if b_i1>0 then
       b_loi:='loi:loi chay timeout procedure:loi';
       select ten_proc into b_ten_proc from cmc_lock_proc where ten_proc='BC_DTHU_GOC_TBH_CT' for update;
   end if;*/
    --NGA_BC_LUU_TYLE_TBH_TUDONG();
    --BC_DT_DTUONG_THOP_DT(b_dvi, b_phong, b_ma_kh, b_loai_kh, b_lh_nv, b_ngayd, b_ngayc);
    NGA_BC_DT_DTUONG_THOP_DT(b_dvi, b_phong, b_ma_kh, b_loai_kh, b_lh_nv, b_ngayd, b_ngayc);
  
    EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_5';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_6';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE blvp_temp_1';
    commit;
    b_tle_ptl:=0;
    BBC_LAY_NV(b_ma_dvi,b_nsd,'','');

    insert into temp_6(c1, c20, c21, c2, n1, n2, c3, c4, c5, n3, n4, n5,c14,c15,c6,c9)
        select a.ma_dvi, a.ma_dvi_g, b.so_hd, a.phong, a.so_id, a.so_id_dt, a.nv, a.lh_nv, a.ma_dt,
            dt_ps, dt_bh, dt_tt,b.ma_gt,b.ma_kt,b.ma_kh,b.ten
            from bh_bc_dt_dtuong_temp a, bh_hd_goc b
            where
                 (b_dvi is null or a.ma_dvi like b_dvi||'%') and (b_phong is null or a.phong=b_phong)
                --and a.ngay between b_ngayd and b_ngayc
                and (b_lh_nv is null or a.lh_nv like b_lh_nv||'%') and (b_ma_dt is null or a.ma_dt like b_ma_dt||'%')
                and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
                and a.nv in (Select nv from temp_bc_nv)
                and a.ma_dvi_g=b.ma_dvi and a.so_id=b.so_id;

    if b_kieu_dt='PS' then
        delete temp_6 where nvl(n3,0)=0;
    elsif b_kieu_dt='BH' then
        delete temp_6 where nvl(n4,0)=0;
    elsif b_kieu_dt='TT' then
        delete temp_6 where nvl(n5,0)=0;
    end if;

   --lay so id tai co dinh
    merge into temp_6
    using (select max(so_id)so_id,so_id_hd,so_id_dt,ma_dvi_hd from tbh_ghep_hd group by so_id_hd,so_id_dt,ma_dvi_hd)a
    on (n1=a.so_id_hd and n2=a.so_id_dt and a.ma_dvi_hd=c20)
    when matched then
    update set n39=a.so_id;
    --lay so id tai tam thoi
    merge into temp_6
    using (select max(so_id)so_id,so_id_hd,so_id_dt,ma_dvi_hd from tbh_tm_hd group by so_id_hd,so_id_dt,ma_dvi_hd)a
    on (n1=a.so_id_hd and n2=a.so_id_dt and a.ma_dvi_hd=c20)
    when matched then
    update set n38=a.so_id;

    --lay ti le tai cd
    merge into temp_6
    using (select sum(pt)pt,sum(pt_hh)pt_hh,so_id from tbh_ghep_phi where phi>=0 group by so_id)a
    on (n39=a.so_id)
    when matched then
    update set n37=a.pt,n36=a.pt_hh,c42=a.pt;
    
    merge into temp_6
    using (select sum(pt)pt,so_id,lh_nv from tbh_ghep_pbo where phi>=0 group by so_id,lh_nv)a
    on (n39=a.so_id and c4=a.lh_nv)
    when matched then
    update set n34=a.pt;
    
    update temp_6 set n37 = null where n34 is null;
    update temp_6 set n34 = null;
    
    --lay ti le tai tm
    merge into temp_6
--    using (select sum(pt)pt,sum(pt_hh)pt_hh,so_id from tbh_tm_phi where phi>=0 group by so_id)a
--     using (select sum(a.pt)pt,sum(a.pt_hh)pt_hh,b.so_id_hd,b.so_id_dt from tbh_tm_phi a,tbh_tm_hd b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and
--             a.phi>=0  
--             group by b.so_id_hd,b.so_id_dt )a
--     on (n1=a.so_id_hd and n2=a.so_id_dt)
--     when matched then
--     update set n34=a.pt,n40=a.pt_hh;
    
--     merge into temp_6
    using (select sum(pt)pt,so_id,lh_nv,so_id_dt from tbh_tm_pbo where phi>=0 group by so_id,so_id_dt,lh_nv)a
    on (n38=a.so_id and c4=a.lh_nv and n2=a.so_id_dt)
    when matched then
    update set n20=a.pt;
    
    update temp_6 set n34 = null where n20 is null;
    update temp_6 set n20 = null;
    -------
--    return;
--     update temp_6 set (c30,n20)=(select max(kieu),sum(pt) from bh_hd_do_tl
--         where so_id=n1 and so_id_dt in (0,n2) and lh_nv in('*',c4)
--                        and kieu='V' and pthuc='C');

--    merge into temp_6 a
--        using (select so_id,so_id_dt,lh_nv,max(kieu) kieu,sum(pt) pt from bh_hd_do_tl
--                where kieu='V' and pthuc='C' group by so_id,so_id_dt,lh_nv) b
--        on (b.so_id=a.n1 and b.so_id_dt in (a.n2,0) and b.lh_nv in(a.c4,'*'))
--        when matched then
--        update set a.c30 = b.kieu,a.n20 = b.pt;

    update temp_6 set n20=1 where n20 is null or n20=0;


--     update temp_6 set (c26,n28) = (select max(kieu),sum(pt) FROM bh_hd_do_tl
--         where  so_id=n1 and (so_id_dt=0 or so_id_dt=n2) and (lh_nv='*' or lh_nv=c4) and pthuc='C'); --ma_dvi=c1 and
--    update temp_6 a set (c26,n28) = (select c26,n28 from temp_6 b where a.n1=b.n1 and a.n2=b.n2 and a.c4=b.c4 and n28 > 0) where n28 is null and c26 is not null;
--    merge into temp_6 a
--        using (select ma_dvi,so_id,so_id_dt,lh_nv,max(kieu) kieu,sum(pt) pt from bh_hd_do_tl
--                where pthuc='C' group by ma_dvi,so_id,so_id_dt,lh_nv) b
--        on (/*b.ma_dvi=a.c1 and*/ b.so_id=a.n1 and b.so_id_dt in (a.n2,0) and b.lh_nv in(a.c4,'*'))
--        when matched then
--        update set a.c26 = b.kieu,a.n28 = b.pt;
--10m
    insert into temp_5(c20, n1, n2, c2,c21, n6, n7, n8, n9, n10, n11, c24, c4)
        select c20, n1, n2, c2, c21,round((n37/n20)*n3/100),round(((n37/n20)*n3/100)*(n36/100)),
                round(((n37/n20)*n4)/100),round((((n37/n20)*n4)/100)*(n36/100)),round(((n37/n20)*n5)/100),round((((n37/n20)*n5)/100)*(n36/100)),'' pthuc, c4
                from temp_6;
                --where (so_id_dt=0 or so_id_dt=n2) and lh_nv=c4 and n37huc not in ('F') and ngay<=b_ngayc and ma_dvi=c20 and so_id=FTBH_GHEP_SO_ID_BS(c20,n1,b_ngayc);

   insert into temp_5(c20, n1, n2, c2,c21, n12, n13, n14, n15, n16, n17, c24, c4)
        select c20, n1, n2, c2, c21,round((n34/n20)*n3/100),round(((n34/n20)*n3/100)*(n40/100)),
                round(((n34/n20)*n4)/100),round((((n34/n20)*n4)/100)*(n40/100)),round(((n34/n20)*n5)/100),
                round((((n34/n20)*n5)/100)*(n40/100)),'' pthuc, c4
                from temp_6;
                --where (so_id_dt=0 or so_id_dt=n2) and lh_nv=c4 and pthuc in ('F')  and ngay<=b_ngayc and ma_dvi=c20 and so_id=FTBH_GHEP_SO_ID_BS(c20,n1,b_ngayc);
    /*
    update temp_6 t1 set (n6, n7, n8, n9, n10, n11,n12, n13, n14, n15, n16, n17)=
                (select sum(n6), sum(n7), sum(n8), sum(n9), sum(n10), sum(n11),sum(n12),
                    sum(n13), sum(n14), sum(n15), sum(n16), sum(n17) from temp_5 t2
                    where t1.c20=t2.c20 and t1.n1=t2.n1 and t1.n2=t2.n2 and t1.c2=t2.c2 and t1.c4 = t2.c4);
    */
    --delete temp_idx;
    execute immediate 'truncate table temp_idx';
    insert into temp_idx(ma,so,n2,c2,c4, n6, n7, n8, n9, n10, n11,n12, n13, n14, n15, n16, n17)
        select c20,n1,n2,c2,c4, sum(n6), sum(n7), sum(n8), sum(n9), sum(n10), sum(n11),sum(n12),
