    merge into temp_6 t1
    using temp_idx t2
    on (t1.c20=t2.ma and t1.n1=t2.so and t1.n2=t2.n2 and t1.c2=t2.c2 and t1.c4 = t2.c4)
    when matched then update
    set t1.n6=t2.n6,t1.n7=t2.n7,
