    t1.n10=t2.n10,t1.n11=t2.n11,
    t1.n12=t2.n12,t1.n13=t2.n13,
    t1.n14=t2.n14,t1.n15=t2.n15,
    t1.n16=t2.n16,t1.n17=t2.n17;--return;
