--            end if;
--        end loop;
--        --update temp_6 SET c23 = substr(b_ky_tt_all,1,250) where n1 = b_so_id.n1;
--        update temp_6 SET c23 = substr(b_ky_tt_all,1,250) where rowid = b_so_id.rowid;
--        b_ky_tt_all:='';
--        
--        for b_ky_tt in (select ngay_ht from bh_hd_goc_tthd where so_id = b_so_id.n1 and pt <> 'N' order by ngay_ht) loop
--            if b_ky_tt.ngay_ht is not null and b_ky_tt.ngay_ht between b_ngayd and b_ngayc then
--                b_ky_tt_all := b_ky_tt_all||to_char(bcnam_so_ngay_f(b_ky_tt.ngay_ht))||';';
--            end if;
--        end loop;
--        --update temp_6 SET c25 = substr(b_ky_tt_all,1,250) where n1 = b_so_id.n1;
--        update temp_6 SET c25 = substr(b_ky_tt_all,1,250) where rowid = b_so_id.rowid;
--        b_ky_tt_all:='';
--    end loop;
--tam rao lai ghep vao vong loop o tren
--    for b_so_id in (select n1,rowid from temp_6) loop
--        for b_ky_tt in (select ngay_ht from bh_hd_goc_tthd where so_id = b_so_id.n1 and pt <> 'N' order by ngay_ht) loop
--            if b_ky_tt.ngay_ht is not null and b_ky_tt.ngay_ht between b_ngayd and b_ngayc then
--                b_ky_tt_all := b_ky_tt_all||to_char(bcnam_so_ngay_f(b_ky_tt.ngay_ht))||';';
--            end if;
--        end loop;
--        --update temp_6 SET c25 = substr(b_ky_tt_all,1,250) where n1 = b_so_id.n1;
--        update temp_6 SET c25 = substr(b_ky_tt_all,1,250) where rowid = b_so_id.rowid;
--        b_ky_tt_all:='';
--    end loop;

 /*   --lay so id tai
    merge into temp_6
    using (select max(so_id)so_id,so_id_hd,so_id_dt,ma_dvi_hd from tbh_ghep_hd group by so_id_hd,so_id_dt,ma_dvi_hd)a
    on (n1=a.so_id_hd and n2=a.so_id_dt and a.ma_dvi_hd=c20)
    when matched then
    update set n39=a.so_id;*/

    --lay so chung tu tai co dinh
    merge into temp_6
    using (select max(so_ct)so_ct,so_id from tbh_ghep group by so_id)a
    on (a.so_id=n39)
    when matched then update
    set c39 = a.so_ct;
    --lay so chung tu tai tam
    merge into temp_6
    using (select max(so_ct)so_ct,so_id from tbh_tm group by so_id)a
    on (a.so_id=n38)
    when matched then update
    set c40 = a.so_ct;

    --lay tien tai co dinh
    merge into temp_6
    using (select sum(nvl(tien,0))tien,so_id from tbh_ghep_phi group by so_id)a
    on (a.so_id=n39)
    when matched then update
    set n21 = a.tien;--n38

    --lay tien tai tam
    merge into temp_6
    using (select sum(nvl(tien,0))tien,so_id from tbh_tm_phi group by so_id)a
    on (a.so_id=n38)
    when matched then update
    set n32 = a.tien;--n38

    --lay phi chuyen tai trong ky va luy ke
    merge into temp_6
    using (select sum(nvl(tien,0))tien,SO_ID_PS from tbh_xl_pbo where ngay_ht between b_ngayd and b_ngayc  group by SO_ID_PS)a
    on (a.SO_ID_PS=n39)
    when matched then update
    set n37 = a.tien;

    merge into temp_6
    using (select sum(nvl(tien,0))tien,SO_ID_PS from tbh_xl_pbo where ngay_ht between b_ngayd and b_ngayc  group by SO_ID_PS)a
    on (a.SO_ID_PS=n38)
    when matched then update
    set n33 = a.tien;

    update temp_6 set n37=nvl(n37,0)+nvl(n33,0);

    merge into temp_6
    using (select sum(nvl(tien,0))tien,SO_ID_PS from tbh_xl_pbo where ngay_ht <= b_ngayc group by SO_ID_PS)a
    on (a.SO_ID_PS=n39)
    when matched then update
    set n36 = a.tien;

    merge into temp_6
    using (select sum(nvl(tien,0))tien,SO_ID_PS from tbh_xl_pbo where ngay_ht <= b_ngayc group by SO_ID_PS)a
    on (a.SO_ID_PS=n38)
    when matched then update
    set n35 = a.tien;
    update temp_6 set n36=nvl(n36,0)+nvl(n35,0);

    if b_kieu_dt='PS' then
        open cs1 for select c1 ma_dvi, c21 so_hd, c2 phong, c3 nv, c4 ma_nv, c29 nhom_lhnv,c6 ma_kh,c9 ten_kh,
             c22 nhom_kh,c24 loai_kh,c10 so_gcn,c11 ten_dtbh,c7 ngay_hl,c8 ngay_kt,
             c16 nt_tien,round(sum(n22)) tien_bh,c17 nt_phi,round(sum(n23)) phi_bh,round(sum(n3)) dt_bh,
             n18 tle_cd,round(sum(n6)) cd_phi, round(sum(n7)) cd_hhong,
             n24 tle_tt,round(sum(n12)) tt_phi, round(sum(n13)) tt_hhong,
             round(sum(nvl(n6,0)+nvl(n12,0))) tai_phi_tong, round(sum(nvl(n7,0)+nvl(n13,0))) tai_hhong_tong,
             round(sum(nvl(n3,0)-nvl(n6,0)-nvl(n12,0))) phi_giu,
             c5 ma_dt,c19 nhom_dt,c12 kvuc,c14 ma_gt,c15 ma_kt,c26 do_kieu, n28 do_tle,
             substr(n26,1,4) nam_ps_hd,c32 TEN_DVI_RR,c33 DDIEMRR,n30 SO_DVIRR,c34 SO_DT
             ,n36 phi_chuyentai_luy, n37 phi_chuyentai_trongky,n21 tien_tai_cd,c39 so_ct_cd,n32 tien_tai_tt,c40 so_ct_tt
        from temp_6 group by c1,c7,c8, c21, c2, c3, c5,c19,c10,c11,c12,c14,c15,c16,c17,c4,c29,c6,c9, n22, n18, n24,
                n26, n20,c26,n28,c22,c24,c32,c33,n30,c34,n36,n37,n21,c39,n32,c40
        order by c1,c2;
    elsif b_kieu_dt='BH' then
        open cs1 for select c1 ma_dvi, c21 so_hd, c2 phong, c3 nv, c4 ma_nv, c29 nhom_lhnv,c6 ma_kh,c9 ten_kh,
        c22 nhom_kh,c24 loai_kh,c10 so_gcn,c11 ten_dtbh,c7 ngay_hl,c8 ngay_kt,
        c16 nt_tien,round(sum(n22)) tien_bh,c17 nt_phi,round(sum(n23)) phi_bh,round(sum(n4)) dt_bh,
        n18 tle_cd,c42,round(sum(n8)) cd_phi, round(sum(n9)) cd_hhong,
        n24 tle_tt,n34,round(sum(n14)) tt_phi, round(sum(n15)) tt_hhong,
        round(sum(nvl(n8,0)+nvl(n14,0))) tai_phi_tong, round(sum(nvl(n9,0)+nvl(n15,0))) tai_hhong_tong,
        round(sum(nvl(n4,0)-nvl(n8,0)-nvl(n14,0))) phi_giu,
        c5 ma_dt,c19 nhom_dt,c12 kvuc,c14 ma_gt,c15 ma_kt,c26 do_kieu, n28 do_tle,
        substr(n26,1,4) nam_ps_hd, c23 ky_tt, c25 ngay_tt,c27 SDBS,c32 TEN_DVI_RR,c33 DDIEMRR,n30 SO_DVIRR,c34 SO_DT
        ,n36 phi_chuyentai_luy, n37 phi_chuyentai_trongky,n21 tien_tai_cd,c39 so_ct_cd,n32 tien_tai_tt,c40 so_ct_tt,c41 ma_dt,
        c43 bien_xe,c44 so_khung,c45 so_may,d1 ngay_hl_xe,d2 ngay_kt_xe
        from temp_6 group by c1,c7,c8, c21, c2, c3, c5,c19,c10,c11,c12,c14,c15,c16,c17,c4,c29,c6,c9, n22, n18, n24,
        n26,c26,n28,c22,c24,c23,c25,c27,c32,c33,n30,c34,n36,n37,n21,c39,n32,c40,c41,n34,c42,c43,c44,c45,d1,d2
        order by c1,c2;
    elsif b_kieu_dt='TT' then
        open cs1 for select c1 ma_dvi, c21 so_hd, c2 phong, c3 nv, c4 ma_nv, c29 nhom_lhnv,c6 ma_kh,c9 ten_kh,
             c22 nhom_kh,c24 loai_kh,c10 so_gcn,c11 ten_dtbh,c7 ngay_hl,c8 ngay_kt,
             c16 nt_tien,round(sum(n22)) tien_bh,c17 nt_phi,round(sum(n23)) phi_bh,round(sum(n5)) dt_bh,
             n18 tle_cd,c42,round(sum(n10)) cd_phi, round(sum(n11)) cd_hhong,
             n24 tle_tt,n34,round(sum(n16)) tt_phi, round(sum(n17)) tt_hhong,
             round(sum(nvl(n10,0)+nvl(n16,0))) tai_phi_tong, round(sum(nvl(n11,0)+nvl(n17,0))) tai_hhong_tong,
             round(sum(nvl(n5,0)-nvl(n10,0)-nvl(n16,0))) phi_giu,
             c5 ma_dt,c19 nhom_dt,c12 kvuc,c14 ma_gt,c15 ma_kt,c26 do_kieu, n28 do_tle,
             substr(n26,1,4) nam_ps_hd,c32 TEN_DVI_RR,c33 DDIEMRR,n30 SO_DVIRR,c34 SO_DT
             ,n36 phi_chuyentai_luy, n37 phi_chuyentai_trongky,n21 tien_tai_cd,c39 so_ct_cd,n32 tien_tai_tt,c40 so_ct_tt
        from temp_6
        group by c1,c7,c8, c21, c2, c3, c5,c19,c10,c11,c12,c14,c15,c16,c17,c4,c29,c6,c9, n22, n18, n24,
            n26, n20,c26,n28,c22,c24,c32,c33,n30,c34,n36,n37,n21,c39,n32,c40,n34,c42
        order by c1,c2;
    end if;
  -- exception when others then raise_application_error(-20105,b_loi);
commit;
end;

