DROP PROCEDURE BC_NV_DT_GOC_NGUON;

CREATE OR REPLACE PROCEDURE BC_NV_DT_GOC_NGUON
(
    b_ma_dvi varchar2, b_nsd varchar2, b_pas varchar2,
    b_dvi varchar2, b_phong varchar2, b_lhnv varchar2,
    b_ma_kh varchar2, b_loai_kh varchar2, b_ma_dt varchar2, b_ma_dl varchar2, b_nguon varchar2,
    b_ngayd number, b_ngayc number, cs1 out  pht_type.cs_type
)
as
    b_loi nvarchar2(250);b_ngaydn number; b_ng varchar2(20); b_dvi_bc varchar2(10);
begin
-- BCNam dieu chinh bao cao doanh thu nghiep vu
    b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
    if b_loi is not null then raise PROGRAM_ERROR; end if;
--    if b_nguon is null then
--        b_loi:='loi:Chon ma gioi thieu khai thac:loi';
--        raise PROGRAM_ERROR;
--    end if;
    b_ngaydn:=round(b_ngayd,-4)+101;
    --BCNam: Cho Ban KHCN xem so lieu
    if b_nsd = 'KHCN' and b_ma_dvi ='00' then
        BBC_LAY_NV('00','ADMIN','','');
    else
        BBC_LAY_NV(b_ma_dvi,b_nsd,'','');
    end if;
    if b_dvi='00' or b_dvi is null then
        b_dvi_bc:='';
    else
        b_dvi_bc:=b_dvi;
    end if;
    delete temp_bc_ts; delete temp_2; commit;
    insert into temp_bc_ts values (b_dvi_bc||'%',b_ngayd,b_ngayc);
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
    BC_BH_LAY_BC_BH_DTPS_MM(b_dvi_bc,b_ngayd,b_ngayc);
    insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n2, n3)
        select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
        from TEMP_BC_BH_DTPS_MM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
        and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
        and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%' and nv in (Select distinct nv from temp_bc_nv)
        group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(b_dvi_bc,b_ngayd,b_ngayc);
    insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n4, n5)
        select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
        from TEMP_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
        and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
        and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%' and nv in (Select distinct nv from temp_bc_nv)
        group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;

    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
    BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi_bc,b_ngayd,b_ngayc);
    insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
        select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
        from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
        and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
        and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%' and nv in (Select distinct nv from temp_bc_nv)
        group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;

    --doanh thu luy ke
    --rao luy ke theo yc cua Han
--    if b_ngayd<>b_ngaydn then
--        EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
--        BC_BH_LAY_BC_BH_DTPS_MM(b_dvi_bc,b_ngaydn,b_ngayc);
--        insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n8, n9)
--            select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
--            from TEMP_BC_BH_DTPS_MM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%' and nv in (Select distinct nv from temp_bc_nv)
--            group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
--
--        EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
--        BC_BH_LAY_BC_BH_DTBH_MM(b_dvi_bc,b_ngaydn,b_ngayc);
--        insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n10, n11)
--            select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
--            from TEMP_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%' and nv in (Select distinct nv from temp_bc_nv)
--            group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
--
--        EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--        BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi_bc,b_ngaydn,b_ngayc);
--        insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n12, n13)
--            select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
--            from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi_bc||'%' and nv in (Select distinct nv from temp_bc_nv)
--            group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
--    else
--        update temp_2 set n8=n2, n9=n3, n10=n4, n11=n5, n12=n6, n13=n8;
--    end if;

    delete temp_3; commit;
    insert into temp_3(c1, c2, c3, c4, c5, c6, c7, c8, n2, n3, n4, n5, n6, n7, n8, n9, n10, n11, n12, n13)
        select c1, c2, c3, c4, c5, c6, c7, c8,
            sum(n2) dt_ps_tk, sum(n3) thue_ps_tk, sum(n4) dt_bh_tk, sum(n5) thue_bh_tk, sum(n6) dt_tt_tk, sum(n7) thue_tt_tk,
            sum(n8) dt_ps_lk, sum(n9) thue_ps_lk, sum(n10) dt_bh_lk, sum(n11) thue_bh_lk, sum(n12) dt_tt_lk, sum(n13) thue_tt_lk
        from temp_2 group by c1, c2, c3, c4, c5, c6, c7,c8;

    if b_loai_kh is not null then
        update
            (select temp_3.c20 temp_3_c20, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from temp_3, bh_hd_ma_kh
             where temp_3.c1 = bh_hd_ma_kh.ma_dvi and temp_3.c4 = bh_hd_ma_kh.ma)
            set temp_3_c20 = bh_hd_ma_kh_loai;
        delete temp_3 where c20 not like b_loai_kh||'%';
    end if;

    update temp_3 set c11=(select min(ten)ten from bh_ma_lhnv where ma=c8);
    update temp_3 set (c14, c15)=(Select substr(c8,1,2),min(ten)ten from bh_ma_lhnv where ma=substr(c8,1,4));

    commit;
    
    commit;
    open cs1 for
        select c11 ten, c14 ma_gon, c15 ten_goc_2, sum(n14) bh_ck_nt,
            sum(n2) ps_tk, sum(n4) bh_tk, sum(n6) tt_tk,
            sum(n8) ps_lk, sum(n10) bh_lk,  sum(n12) tt_lk
        from temp_3 group by c11,c14, c15;
  --  exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE BC_PT_CONG_NO;
CREATE OR REPLACE PROCEDURE BC_PT_CONG_NO
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_tc varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaydt number; b_ngayct number;
    b_d1 date;b_d2 date;b_i1 number;
Begin
-- Bao cao phan tich cong no
-- Thang , quy
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;delete temp_2;delete ket_qua; commit;
/*  c1 lh_nv,c2 so_hd,c3 ma_kh,c4 phong,c5 loai_kh,n13 so_id_hd n1 dtbh_lk,n2 tien_tk,n3 tien_lk */
--ngayd cung ky quy truoc
if b_tc='Q' then
    b_d1:=ADD_MONTHS(PKH_SO_CDT(b_ngayd),-3);
    b_d2:=ADD_MONTHS(PKH_SO_CDT(b_ngayc),-3);
else
    b_d1:=ADD_MONTHS(PKH_SO_CDT(b_ngayd),-1);
    b_d2:=ADD_MONTHS(PKH_SO_CDT(b_ngayc),-1);
end if;
b_ngaydt:=to_number(to_char(b_d1,'yyyymmdd'));
b_ngayct:=to_number(to_char(b_d2,'yyyymmdd'));
/* n3 so du dau ky truoc,n4 so du cuoi ky truoc,n5 so du con lai tu dau ky,n6 dau ky nay, n7 so du cuoi ky, n8 so du con lai tu cuoi ky*/
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
--so_du dau ky truoc
insert into temp_1 (c1,n1,c2,n2,n3)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<b_ngaydt group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;
--so_du dau ky nay--so du cuoi ky truoc
insert into temp_1 (c1,n1,c2,n2,n4,n6)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd),sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<b_ngayd group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;
--so_du cuoi ky
insert into temp_1 (c1,n1,c2,n2,n7)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<=b_ngayc group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngaydt,b_ngayct);
--doanh thu ky truoc
insert into temp_1 (c1,n1,c2,n2,n9)
    select a.ma_dvi,a.so_id,ma_nt,ngay_ht,sum(phi+thue) from V_BC_BH_DTBH_MM a
    group by a.ma_dvi,a.so_id,ma_nt,ngay_ht;
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
--doanh thu ky nay
insert into temp_1 (c1,n1,c2,n2,n10)
    select a.ma_dvi,a.so_id,a.ma_nt,ngay_ht,sum(phi+thue) from V_BC_BH_DTBH_MM a
    group by a.ma_dvi,a.so_id,ma_nt,ngay_ht;
insert into temp_2 (c29,n1,c2,n2,n3,n4,n5,n6,n7,n8,n9,n10)
    select c1,n1,c2,n2,sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0)) from temp_1 group by  c1,n1,c2,n2;
update temp_2 set n5=n4 where n3<>0;
update temp_2 set n8=n7 where n6<>0;
update  temp_2 set c4=(select phong from bh_hd_goc where ma_dvi= temp_2.c29 and so_id=temp_2.n1);
update  temp_2 set c30=(select ten from ht_ma_dvi where ma= temp_2.c29);
update  temp_2 set c14=(select ten from ht_ma_phong where ma_dvi=temp_2.c29 and ma= temp_2.c4);
--tong van phong
insert into ket_qua(n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 1,'A',c29,c30,sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp='C') group by c29,c30;
--chi tiet van phong
delete temp_3;
insert into temp_3(n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 2,'',c4,c14,sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp='C') group by c4,c14 order by c4;
insert into ket_qua( n20,c20,c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n9,n10) select n20,to_char(rownum),c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n9,n10 from temp_3;
--Tong cac chi nhanh
insert into ket_qua( n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 3,'B','',U'C\00E1c chi nh\00E1nh',sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp<>'C');
--Chi tiet cac don vi
delete temp_3;
insert into temp_3( n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 4,'',c29,c30,sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp<>'C') group by c29,c30 order by c29;
insert into ket_qua( n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)  select  n20,to_char(rownum),c29,c30,n3,n4,n5,n6,n7,n8,n9,n10 from temp_3;
commit;
select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    open cs_kq for select c20 tc,c29 ma_dvi,c30 ten_dvi,'' ma_phong,'' ten_p,nvl(n9,0) dthu_kt,nvl(n3,0) cn_dk_kt,nvl(n4,0) cn_ck_kt,
        nvl(n5,0) cn_ck_cl_kt,nvl(n10,0) dthu_kn,nvl(n6,0) cn_dk_kn,nvl(n7,0) cn_ck_kn,nvl(n8,0) cn_ck_cl_kn from ket_qua;
else
    open cs_kq for select c20 tc,c29 ma_dvi,c30 ten_dvi,'' ma_phong,'' ten_p,n9 dthu_kt,n3 cn_dk_kt,n4 cn_ck_kt,
        n5 cn_ck_cl_kt,n10 dthu_kn,n6 cn_dk_kn,n7 cn_ck_kn,n8 cn_ck_cl_kn from ket_qua,temp_bc_dvi where c29=dvi;
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_PT_CONG_NO_NAM;
CREATE OR REPLACE PROCEDURE BC_PT_CONG_NO_NAM
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_tc varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaydt number; b_ngayct number;
    b_d1 date;b_d2 date;b_i1 number;
Begin
-- Bao cao phan tich cong no cung ky nam truoc
-- Thang , quy
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;delete temp_2;delete ket_qua; commit;
/*  c1 lh_nv,c2 so_hd,c3 ma_kh,c4 phong,c5 loai_kh,n13 so_id_hd n1 dtbh_lk,n2 tien_tk,n3 tien_lk */
--ngayd cung ky nam truoc
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_d1:=ADD_MONTHS(PKH_SO_CDT(b_ngayd),-12);
b_d2:=ADD_MONTHS(PKH_SO_CDT(b_ngayc),-12);
b_ngaydt:=to_number(to_char(b_d1,'yyyymmdd'));
b_ngayct:=to_number(to_char(b_d2,'yyyymmdd'));
/* n3 so du dau ky truoc,n4 so du cuoi ky truoc,n5 so du con lai tu dau ky,n6 dau ky nay, n7 so du cuoi ky, n8 so du con lai tu cuoi ky*/
--so_du dau ky truoc
insert into temp_1 (c1,n1,c2,n2,n3)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<b_ngaydt group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;
--so du cuoi ky truoc
insert into temp_1 (c1,n1,c2,n2,n4)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<=b_ngayct group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;

--so_du dau ky nay
insert into temp_1 (c1,n1,c2,n2,n6)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<b_ngayd group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;
--so_du cuoi ky
insert into temp_1 (c1,n1,c2,n2,n7)
    select a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht,sum(a.ton_qd) from bh_hd_goc_sc_no a,
        (select ma_dvi,so_id,ma_nt,max(ngay_ht) ngay_ht from bh_hd_goc_sc_no where (b_ma_dvi is null or ma_dvi=b_ma_dvi)
        and ngay_ht<=b_ngayc group by ma_dvi,so_id,ma_nt) b where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
        and a.ma_nt=b.ma_nt and a.ngay_ht=b.ngay_ht group by a.ma_dvi,a.so_id,a.ma_nt,a.ngay_ht having sum(a.ton_qd)<>0;
--doanh thu ky truoc
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngaydt,b_ngayct);
insert into temp_1 (c1,n1,c2,n2,n9)
    select a.ma_dvi,a.so_id,ma_nt,ngay_ht,sum(phi+thue) from V_BC_BH_DTBH_MM a
    group by a.ma_dvi,a.so_id,ma_nt,ngay_ht;
--doanh thu ky nay
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
insert into temp_1 (c1,n1,c2,n2,n10)
    select a.ma_dvi,a.so_id,a.ma_nt,ngay_ht,sum(phi+thue) from V_BC_BH_DTBH_MM a
    group by a.ma_dvi,a.so_id,ma_nt,ngay_ht;
insert into temp_2 (c29,n1,c2,n2,n3,n4,n5,n6,n7,n8,n9,n10)
    select c1,n1,c2,n2,sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0)) from temp_1 group by  c1,n1,c2,n2;
update temp_2 set n5=n4 where n3<>0;
update temp_2 set n8=n7 where n6<>0;
update  temp_2 set c4=(select phong from bh_hd_goc where ma_dvi= temp_2.c29 and so_id=temp_2.n1);
update  temp_2 set c30=(select ten from ht_ma_dvi where ma= temp_2.c29);
update  temp_2 set c14=(select ten from ht_ma_phong where ma_dvi=temp_2.c29 and ma= temp_2.c4);
--tong van phong
insert into ket_qua(n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 1,'A',c29,c30,sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp='C') group by c29,c30;
--chi tiet van phong
delete temp_3;
insert into temp_3(n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 2,'',c4,c14,sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp='C') group by c4,c14 order by c4;
insert into ket_qua( n20,c20,c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n9,n10) select n20,to_char(rownum),c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n9,n10 from temp_3;
--Tong cac chi nhanh
insert into ket_qua( n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 3,'B','',U'C\00E1c chi nh\00E1nh',sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp<>'C');
--Chi tiet cac don vi
delete temp_3;
insert into temp_3( n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)
    select 4,'',c29,c30,sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n9,0)),sum(nvl(n10,0))
    from temp_2 where c29 in (select ma from ht_ma_dvi where vp<>'C') group by c29,c30 order by c29;
insert into ket_qua( n20,c20,c29,c30,n3,n4,n5,n6,n7,n8,n9,n10)  select  n20,to_char(rownum),c29,c30,n3,n4,n5,n6,n7,n8,n9,n10 from temp_3;
commit;
select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    open cs_kq for select c20 tc,c29 ma_dvi,c30 ten_dvi,'' ma_phong,'' ten_p,nvl(n9,0) dthu_kt,nvl(n3,0) cn_dk_kt,nvl(n4,0) cn_ck_kt,
        nvl(n5,0) cn_ck_cl_kt,nvl(n10,0) dthu_kn,nvl(n6,0) cn_dk_kn,nvl(n7,0) cn_ck_kn,nvl(n8,0) cn_ck_cl_kn from ket_qua;
else
    open cs_kq for select c20 tc,c29 ma_dvi,c30 ten_dvi,'' ma_phong,'' ten_p,nvl(n9,0) dthu_kt,nvl(n3,0) cn_dk_kt,nvl(n4,0) cn_ck_kt,
        nvl(n5,0) cn_ck_cl_kt,nvl(n10,0) dthu_kn,nvl(n6,0) cn_dk_kn,nvl(n7,0) cn_ck_kn,nvl(n8,0) from ket_qua,temp_bc_dvi where c29=dvi;
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/
-- chuclh: fixed
DROP PROCEDURE BC_QT_NHANH_BT_NHOM_XE;

CREATE OR REPLACE PROCEDURE BC_QT_NHANH_BT_NHOM_XE
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_ma_dl varchar2,b_tc varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaynt number;b_i1 number;
    b_ngay_c number; b_d1 number; b_d2 number;b_dkbs varchar(4000);
Begin
--BCNam: boi thuong theo nhom xe
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngay_c:=20150917;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
delete bc_bh_bt_temp;delete ket_qua; commit;
PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
    b_loi:='loi:Ban khong co quyen xem bao cao nay:loi'; raise PROGRAM_ERROR;
end if;
b_ngaynt:=round(b_ngayc,-4)-10000 +1231;
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,b_ngayd,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;

PBC_BH_TH_BT_PB_MD('T');
insert into bc_bh_bt_temp (ma_dvi,phong,n2,so_id,nv,ngay_ht,so_id_hd,ma_dvi_hd,so_id_dt)
            select ma_dvi,phong,tien_qd,so_id,nv,ngay_ht,so_id_hd,ma_dvi_hd,so_id_dt from bc_bh_bt_hs_temp
            where ngay_qd_n<30000101 and nv in ('XE','XEL') and (b_phong is null or phong=b_phong)
                                        and (b_ma_nv is null or lh_nv like b_ma_nv ||'%');
PBC_BH_BT_CGQ_MD('T');
insert into bc_bh_bt_temp (ma_dvi,phong, n4,so_id,nv,ngay_ht,so_id_hd,ma_dvi_hd,so_id_dt)
            select ma_dvi,c3,n5,so_id,c2,n2,n3,c4,so_id_dt from temp_bt_1
            where c2 in('XE','XEL') and (b_phong is null or c3=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv ||'%');


/*insert into bc_bh_bt_temp(ma_dvi,phong,n8,so_id_hd,ma_dvi_hd,nv) select ma_dvi,phong,sum(phi),so_id,ma_dvig,nv
    from V_BC_BH_DTBH_MM where (b_ma_nv is null or lh_nv like b_ma_nv ||'%') and nv in ('XE','XEL')
    group by ma_dvi,phong,so_id,ma_dvig,nv;*/


delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,20000101,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
PBC_BH_TH_BT_PB_MD('T');
insert into bc_bh_bt_temp (ma_dvi,phong,n3,so_id,nv,ngay_ht,so_id_hd,ma_dvi_hd,so_id_dt)
    select ma_dvi,phong,tien_qd,so_id,nv,ngay_ht,so_id_hd,ma_dvi_hd,so_id_dt from bc_bh_bt_hs_temp
                                    where ngay_qd_n<30000101 and nv in ('XE','XEL') and (b_phong is null or phong=b_phong)
                                        and (b_ma_nv is null or lh_nv like b_ma_nv ||'%');
                                        
PBC_BH_BT_CGQ_MD('T');
insert into bc_bh_bt_temp (ma_dvi,phong,n5,so_id,nv,ngay_ht,so_id_hd,ma_dvi_hd,so_id_dt)
    select ma_dvi,c3, n5,so_id,c2,n2,n3,c4,so_id_dt from temp_bt_1 where c2 in('XE','XEL')
                                            and (b_phong is null or c3=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv ||'%');
--BCNam sua lai
--update bc_bh_bt_temp t1 set (c3,c10,d1,d2,n17,c12)=(select ''nhom_xe,so_hd,PKH_SO_CNG_DATE(ngay_hl),PKH_SO_CNG_DATE(ngay_kt),''nam_sx,''md_sd from bh_xe where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd and rownum=1);-- where nv='XEL';
--update bc_bh_bt_temp t1 set c3=(select nhom_xe from bh_xegcn where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd and rownum=1) where nv='XE';
update bc_bh_bt_temp t1 set (c3,c10,d1,d2,n17,c12)=(select nhom_xe,gcn,PKH_SO_DATE(ngay_hl),PKH_SO_DATE(ngay_kt),nam_sx,md_sd from bh_xe_ds where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd and so_id_dt=t1.so_id_dt and rownum=1) ;--where nv='XE';
--if b_ma_nv = 'XG.2.4' then
--update ket_qua set c27 = (select max(a.ma) from bh_hd_goc_dkbs a where a.bt = (select max(bt) from bh_hd_goc_dkbs where a.ma_dvi=ma_dvi and a.lh_nv=lh_nv and a.so_id=so_id and lh_nv='XG.2.4')
--and a.lh_nv='XG.2.4' and a.so_id=n1 and a.ma_dvi=c1 and a.lh_nv=c11);
--end if;

--b_dkbs:='';
--for r_lp in (select a.*,a.rowid as PR_ID from bc_bh_bt_temp a)
--loop
-- b_dkbs:='';
-- for r_lp1 in (select ma from  bh_hd_goc_dkbs where so_id <> 1 and ma_dvi=r_lp.ma_dvi_hd and so_id=r_lp.so_id_hd and (so_id_dt = 0 or so_id_dt=r_lp.so_id_dt)) 
--  loop
--   b_dkbs:=b_dkbs||r_lp1.ma||',';
--  end loop;
-- update bc_bh_bt_temp set c13 = substr(b_dkbs,0,200) where rowid=r_lp.pr_id;
-- b_dkbs:='';
--end loop;
--commit;

update bc_bh_bt_temp t1 set (c4,c5,c6,c7,c8)=(select so_hd,ma_kh,ma_kt,kieu_kt,cb_ql from bh_hd_goc where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd);
--update bc_bh_bt_temp t1 set c9=(select loai from bh_hd_ma_kh where ma_dvi=t1.ma_dvi_hd and ma=t1.c5);
merge into bc_bh_bt_temp t1 
using bh_hd_ma_kh t2
on (t2.ma_dvi=t1.ma_dvi_hd and t2.ma=t1.c5)
when matched then update set c9=loai;
update bc_bh_bt_temp t1 set (c2,c11)=(select so_hs,nsd from bh_bt_hs where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id);
update bc_bh_bt_temp t1 set c30=(select ten from ht_ma_dvi where ma= t1.ma_dvi);
update bc_bh_bt_temp set n9=n2 where ngay_ht between b_ngayd and b_ngayc;
update bc_bh_bt_temp set n6=nvl(n2,0)+nvl(n4,0),n7=nvl(n3,0)+nvl(n5,0),n12=nvl(n9,0)+nvl(n4,0);
delete bc_bh_bt_temp where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n4,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n7,0)=0 and nvl(n8,0)=0;
update bc_bh_bt_temp t1 set n13=(select nvl(sum(a.pt),0) from bh_hd_do_tl a, bh_hd_do b where a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd
    and a.ma_dvi = b.ma_dvi and a.so_id=b.so_id
    and (so_id_dt=0 or so_id_dt=t1.so_id_dt) and b.kieu='D' and pthuc='C');
update bc_bh_bt_temp t1 set n14=(select nvl(sum(a.pt),0) from bh_hd_do_tl a, bh_hd_do b where a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd
    and (so_id_dt=0 or so_id_dt=t1.so_id_dt) and b.kieu='V' and pthuc='C');

if b_loai_kh is not null then
    delete bc_bh_bt_temp where c9<> b_loai_kh;
end if;
if b_ma_kh is not null then
    delete bc_bh_bt_temp where c5<> b_ma_kh;
end if;
if b_ma_cb is not null then
    delete bc_bh_bt_temp where c8<> b_ma_cb;
end if;
if b_ma_dl is not null then
    delete bc_bh_bt_temp where c6<> b_ma_dl and c7 not in('D','M');
