commit;
insert into ket_qua(c26,n15,c29,c30,c2,c3,c4,c5,n2,n3,n4,n5,n6,n7,n10,n11,n12,n13,n14,c11,c10,d1,d2,n17,c12,c13)
    select ma_dvi_hd,so_id_hd,ma_dvi,c30,c2,c3,c4,phong,round(sum(nvl(n2,0))),sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),
            sum(nvl(n8,0)),sum(nvl(n9,0)),sum(n12),n13,n14,c11,c10,d1,d2,n17,c12,c13
            from bc_bh_bt_temp group by ma_dvi_hd,so_id_hd,ma_dvi,c30,c2,c3,c4,phong,n13,n14,c11,c10,d1,d2,n17,c12,c13;

--merge into ket_qua
--using (select min(nt_tien)nt_tien,sum(tien)tien,ma_dvi,so_id from bh_xelgcn_dk where lh_nv like 'XG%' group by ma_dvi,so_id)a
--on(a.ma_dvi=c26 and a.so_id=n15)
--when matched then update
--set c15=a.nt_tien,n16=a.tien
--where n16 is null;
merge into ket_qua
using (select sum(tien)tien,ma_dvi,so_id from bh_xe_dk group by ma_dvi,so_id)a
on(a.ma_dvi=c29 and a.so_id=n15)
when matched then update
set c15='',n16=a.tien
where n16 is null;
--update ket_qua set c31 =BCNam_nhom_xe_ten(c29,c3);
merge into ket_qua
using (select ma,min(ten)ten from bh_xe_nhom group by ma) a
on (a.ma=c3)
when matched then update set c31=a.ten;

open cs_kq for select c29 ma_dvi,c30 ten_dvi,c5 phong,c3 nhom,c31 nhom_xe,
        c2 so_hs,c4 so_hd,nvl(n10,0) tien_bh,
        n11 tk_ht,n12 tk_t_ht,decode(n10,0,0,round(n12/n10,2)) pt_ht,decode(n10,0,0,round(n6/n10,2)) pt,
        nvl(n2,0) tk_c,nvl(n4,0) tk_u,nvl(n6,0) tk_t,nvl(n3,0) lk_c,
        nvl(n5,0) lk_u,nvl(n7,0) lk_t,n13 do_lead,n14 do_follow,c11 nguoi_mo
        ,n16 tien,c15 nt_tien,c10 GCN,d1 ngay_hl,d2 ngay_kt,n17 nam_sx,c12 md_sd,c13 dkbs
        from ket_qua order by c29,c5,c3,c2;

exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_QT_NHANH_BT_TONG_DL;
CREATE OR REPLACE PROCEDURE BC_QT_NHANH_BT_TONG_DL
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_ma_kh varchar2,b_tc varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaynt number;b_i1 number;
Begin
-- Bao cao nhanh tinh hinh  boi thuong tong theo dai ly
--tinh chat la C de in cac ma bao cao theo nghiep vu, tinh chat K in cac bao cao gom theo phong, theo don vi,khach hang vv...
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
b_loi:='loi:thang do duc:loi';
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
delete temp_1;delete temp_2;delete ket_qua; commit;
/*  c1 lh_nv,c2 so_hd,c3 ma_kh,c4 phong,c5 loai_kh,n13 so_id_hd
    n1 dtbh_lk,n2 tien_tk,n3 tien_lk */
--ngay cuoi nam truoc
PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
    b_loi:='loi:Ban khong co quyen xem bao cao nay:loi'; raise PROGRAM_ERROR;
end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_ngaynt:=round(b_ngayc,-4)-10000 +1231;
--doanh thu ban hang luy ke
delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngaydn,b_ngayc);
insert into temp_2 (c29,c1,c2,c3,c4,c5,n13,n1) select a.ma_dvi,lh_nv,so_hd,a.ma_kh,phong,b.loai,so_id,sum(phi)
    from V_BC_BH_DTBH_MM a,bh_hd_ma_kh b where a.ma_dvi=b.ma_dvi and a.ma_kh=b.ma
    and (b_phong is null or phong=b_phong) and (b_ma_kh is null or a.ma_kh=b_ma_kh)
    and (b_ma_nv is null or lh_nv like b_ma_nv||'%') and (b_loai_kh is null or loai like b_loai_kh||'%')
    group by a.ma_dvi,lh_nv,a.ma_kh,so_hd,phong,loai,so_id;
--boi thuong
BC_BH_THBT_MD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngayd,b_ngayc,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c29,c1,c2,c3,c4,c5,n13,n2,n14) select c29,c18,c4,c5,c6,c16,n13,n7,n14 from temp_1;
--boi thuong luy ke
BC_BH_THBT_MD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngaydn,b_ngayc,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c29,c1,c2,c3,c4,c5,n13,n3,n14) select c29,c18,c4,c5,c6,c16,n13,n7,n14 from temp_1;
--chua giai quyet
BC_BH_THBT_MD_CDPS(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngayd,b_ngayc,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c29,c1,c2,c3,c4,c5,n13,n4,n12,c12) select c29,c18,c4,c5,c6,c16,n13,n7,n12,c17 from temp_1;
--chua giai quyet luy ke
BC_BH_THBT_MD_CD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',b_ngaydn,b_ngayc,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c29,c1,c2,c3,c4,c5,n13,n5,n12,c12,c15) select c29,c18,c4,c5,c6,c16,n13,n7,n12,c17,c7 from temp_1;
--uoc boi thuong ngay cuoi nam truoc
BC_BH_THBT_MD_CD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,'',0,b_ngaynt,b_loi,'B');
if b_loi is not null then raise PROGRAM_ERROR; end if;
insert into temp_2 (c29,c1,c2,c3,c4,c5,n13,n8,n12,c12) select c29,c18,c4,c5,c6,c16,n13,n7,n12,c17 from temp_1;


--if b_ma_dvi='003' then
--    DELETE from temp_2 where c1='003' and c4 in ('KVYB','KVLC');
--end if;
---------------------------------------
update temp_2 set n6=nvl(n2,0)+nvl(n4,0),n7=nvl(n3,0)+nvl(n5,0);
update temp_2 set n15=nvl(n5,0) where to_number(substr(to_char(n12),1,4))<=to_number(substr(to_char(b_ngaynt),1,4));
update temp_2 set n16=nvl(n2,0) where to_number(substr(to_char(n14),1,4))<=to_number(substr(to_char(b_ngaynt),1,4));

update temp_2 set (c27,c28)=(select ma_kt,kieu_kt from bh_hd_goc where ma_dvi=temp_2.c29 and so_id=temp_2.n13);
update  temp_2 set c30=(select ten from bh_dl_ma_kh where ma_dvi= temp_2.c29 and ma=temp_2.c27) where c28='D';
update  temp_2 set c30=(select ten from ht_ma_cb where ma_dvi= temp_2.c29 and ma=temp_2.c27) where c28='T';
--Chi tiet cac dai ly
delete temp_3;
insert into temp_3( n20,c20,c27,c28,c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n15,n16)
    select 4,'',c27,c28,c29,c30,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),
    sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),sum(nvl(n15,0)),sum(nvl(n16,0))
    from temp_2 group by c27,c28,c29,c30 order by c27;

insert into ket_qua( n20,c20,c27,c28,c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n15,n16)
    select  n20,to_char(rownum),c27,c28,c29,c30,n1,n2,n3,n4,n5,n6,n7,n8,n15,n16 from temp_3;
commit;
select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    open cs_kq for select c20 tc,c27 ma_dvi,c30 ten_dvi,'' ma_nv,'' ten_nv,'' so_hd,'' ma_kh, '' ten_kh,'' phong,'' ten_phong,
        '' loai_kh,'' ten_loai,nvl(n1,0) dtbh_lk,nvl(n2,0) tien_gq_tk,nvl(n4,0) tien_td_tk,nvl(n6,0) tien_tk,nvl(n3,0) tien_gq_lk,
        nvl(n5,0) tien_td_lk,nvl(n7,0) tien_lk,nvl(n8,0) tien_unt,nvl(n15,0) tien_xrnt,nvl(n16,0) tien_gq_tknt
        from ket_qua order by n20,c29;
else
    open cs_kq for select c20 tc,c27 ma_dvi,c30 ten_dvi,'' ma_nv,'' ten_nv,'' so_hd,'' ma_kh, '' ten_kh,'' phong,'' ten_phong,
        '' loai_kh,'' ten_loai,nvl(n1,0) dtbh_lk,nvl(n2,0) tien_gq_tk,nvl(n4,0) tien_td_tk,nvl(n6,0) tien_tk,nvl(n3,0) tien_gq_lk,
        nvl(n5,0) tien_td_lk,nvl(n7,0) tien_lk,nvl(n8,0) tien_unt,nvl(n15,0) tien_xrnt,nvl(n16,0) tien_gq_tknt
        from ket_qua,temp_bc_dvi where c29=dvi order by n20,c29;
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE BC_TA_CD;

CREATE OR REPLACE PROCEDURE BC_TA_CD(B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
B_LOI VARCHAR2(100);B_MA_DVI_HO VARCHAR2(50);B_NGAYD_DATE DATE;B_NGAYC_DATE DATE;
BEGIN
--BAO CAO TAI CO DINH
DELETE TEMP_1;
--B_NGAYD_DATE:=TO_DATE(B_NGAYD,'YYYYMMDD');
--B_NGAYC_DATE:=TO_DATE(B_NGAYC,'YYYYMMDD');
--SELECT max(MA) INTO B_MA_DVI_HO FROM HT_MA_DVI WHERE VP='C';
select min(dvi_ta) INTO B_MA_DVI_HO from tbh_dvi_ta;
INSERT INTO TEMP_1(C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,N3)
SELECT G.SO_HD SO_HD_TA,D.SO_HD, BCNAM_SO_NGAY_F(A.NGAY_HT) NGAY_XU_LY, A.SO_CT, BCNAM_SO_NGAY_F(A.NGAY_HL)NGAY_HL, BCNAM_SO_NGAY_F(A.NGAY_KT)NGAY_KT, A.NT_TIEN, A.NT_PHI, B.PTHUC,
BCNAM_SO_NGAY_F(B.NGAY_HL) NGAY_HIEULUC, B.MA_TA,SUM(B.PT)PT,SUM(B.TIEN)TIEN,SUM(B.PHI)PHI --,           B.TL_THUE,           B.THUE,           B.PT_HH,           B.HHONG
FROM TBH_GHEP      A,
TBH_GHEP_PHI  B,
(SELECT DISTINCT SO_ID,SO_ID_HD FROM TBH_GHEP_HD)   C,
BH_HD_GOC   D,
--TBH_GHEP_TL E,--(SELECT SO_ID,MAX(SO_ID_TA)SO_ID_TA FROM TBH_GHEP_TL GROUP BY SO_ID)E,
(SELECT * FROM TBH_HD_DI WHERE MA_DVI=B_MA_DVI_HO) G
WHERE     A.SO_ID = B.SO_ID
AND A.SO_ID = C.SO_ID
AND C.SO_ID_HD = D.SO_ID
AND B.SO_ID=B.SO_ID AND B.SO_ID_TA=G.SO_ID
--AND G.PTHUC = B.PTHUC AND B.PTHUC = B.PTHUC AND B.MA_TA = B.MA_TA
AND (B_MA_NV IS NULL OR B.MA_TA LIKE B_MA_NV||'%')
AND B.PT > 0
AND D.TTRANG = 'D'
--AND D.NV = 'PHH' 
AND D.NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
GROUP BY 
B.SO_ID,G.SO_HD,D.SO_HD, BCNAM_SO_NGAY_F(A.NGAY_HT), A.SO_CT, BCNAM_SO_NGAY_F(A.NGAY_HL), BCNAM_SO_NGAY_F(A.NGAY_KT), A.NT_TIEN, A.NT_PHI, B.PTHUC,--B.NHA_BH MA_NHA_BH, B.NHA_BH TEN_NHA_BH,
BCNAM_SO_NGAY_F(B.NGAY_HL), B.MA_TA;

--SELECT * FROM TBH_GHEP WHERE SO_ID=20241010000081
--SELECT * FROM TBH_GHEP_HD WHERE SO_ID=20241010000081
--SELECT * FROM TBH_GHEP_PHI WHERE SO_ID=20241010000081
--SELECT * FROM BH_HD_GOC WHERE SO_ID IN (20241009000001,20241009000003)
--SELECT * FROM TBH_GHEP_HD WHERE SO_ID=20241010000081

OPEN CS_KQ FOR
SELECT C1 SO_HD_TA,C2 SO_HD,C3 NGAY_XU_LY,C4 SO_CT,C5 NGAY_HL,C6 NGAY_KT,C7 NT_TIEN,C8 NT_PHI,C9 PTHUC,C10 NGAY_HIEULUC,C11 MA_TA,N1 PT,N2 TIEN,N3 PHI 
FROM TEMP_1;

END;
/
DROP PROCEDURE BC_TA_TM;

CREATE OR REPLACE PROCEDURE BC_TA_TM(B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
B_LOI VARCHAR2(100);B_MA_DVI_HO VARCHAR2(50);B_NGAYD_DATE DATE;B_NGAYC_DATE DATE;
BEGIN
--BAO CAO TAI TAM THOI
DELETE TEMP_1;
--B_NGAYD_DATE:=TO_DATE(B_NGAYD,'YYYYMMDD');
--B_NGAYC_DATE:=TO_DATE(B_NGAYC,'YYYYMMDD');
--SELECT MA INTO B_MA_DVI_HO FROM HT_MA_DVI WHERE VP='C';
select min(dvi_ta) INTO B_MA_DVI_HO from tbh_dvi_ta;
INSERT INTO TEMP_1(C1,C2,C3,C4,C5,C6,C7,C8,C9,C10,C11,N1,N2,N3)
SELECT G.SO_HD SO_HD_TA,D.SO_HD, BCNAM_SO_NGAY_F(A.NGAY_HT) NGAY_XU_LY, A.SO_CT, BCNAM_SO_NGAY_F(A.NGAY_HL)NGAY_HL, BCNAM_SO_NGAY_F(A.NGAY_KT)NGAY_KT, A.NT_TIEN, A.NT_PHI, B.PTHUC,
BCNAM_SO_NGAY_F(B.NGAY_HL) NGAY_HIEULUC, B.MA_TA,SUM(B.PT)PT,SUM(B.TIEN)TIEN,SUM(B.PHI)PHI --,           B.TL_THUE,           B.THUE,           B.PT_HH,           B.HHONG
FROM TBH_GHEP      A,
TBH_GHEP_PHI  B,
(SELECT DISTINCT SO_ID,SO_ID_HD FROM TBH_GHEP_HD)   C,
BH_HD_GOC   D,
--TBH_GHEP_TL E,--(SELECT SO_ID,MAX(SO_ID_TA)SO_ID_TA FROM TBH_GHEP_TL GROUP BY SO_ID)E,
(SELECT * FROM TBH_HD_DI WHERE MA_DVI=B_MA_DVI_HO) G
WHERE     A.SO_ID = B.SO_ID
AND A.SO_ID = C.SO_ID
AND C.SO_ID_HD = D.SO_ID
AND B.SO_ID=B.SO_ID AND B.SO_ID_TA=G.SO_ID
--AND G.PTHUC = B.PTHUC AND B.PTHUC = B.PTHUC AND B.MA_TA = B.MA_TA
AND B.PT > 0 AND D.TTRANG = 'D'
AND (B_MA_NV IS NULL OR B.MA_TA LIKE B_MA_NV||'%')
AND D.NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
GROUP BY 
