DROP PROCEDURE BC_TH_DT_GOC_NGUON;

CREATE OR REPLACE PROCEDURE BC_TH_DT_GOC_NGUON
(
b_ma_dvi varchar2, b_nsd varchar2, b_pas varchar2,
b_dvi varchar2, b_phong varchar2, b_lhnv varchar2,
b_ma_kh varchar2, b_loai_kh varchar2, b_ma_dt varchar2, b_ma_dl varchar2, b_nguon varchar2,
b_ngayd number, b_ngayc number, cs1 out  pht_type.cs_type
)
as
b_loi nvarchar2(250);b_ngaydn number;b_ng varchar2(20);
begin
-- BCNam: bao cao doanh thu nguon khai thac theo MIC
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--    if b_nguon is null then
--        b_loi:='loi:Chon ma gioi thieu khai thac:loi';
--        raise PROGRAM_ERROR;
--    end if;

b_ngaydn:=round(b_ngayd,-4)+101;
--BCNam: Cho Ban KHCN xem so lieu
if b_nsd = 'KHCN' and b_ma_dvi ='00' then
    BBC_LAY_NV('00','ADMIN','','');
else
    BBC_LAY_NV(b_ma_dvi,b_nsd,'','');
end if;

delete temp_bc_ts; delete temp_2;delete temp_1; commit;
insert into temp_bc_ts values (b_dvi||'%',b_ngayd,b_ngayc);
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MM';
BC_BH_LAY_BC_BH_DTPS_MM(b_dvi,b_ngayd,b_ngayc);
insert into temp_1 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n2, n3,n10)
    select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue),ngay_htnv
    from TEMP_BC_BH_DTPS_MM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
    and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
    and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi||'%' and nv in (Select distinct nv from temp_bc_nv)
    group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,ngay_htnv;
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
BC_BH_LAY_BC_BH_DTBH_MM(b_dvi,b_ngayd,b_ngayc);
insert into temp_1 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n4, n5,n10)
    select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue),ngay_htnv
    from TEMP_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
    and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
    and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi||'%' and nv in (Select distinct nv from temp_bc_nv)
    group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,ngay_htnv;

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi,b_ngayd,b_ngayc);
insert into temp_1 (c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7,n10)
    select ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue),ngay_htnv
    from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
    and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
    and (b_ma_dl is null or ma_kt=b_ma_dl) and ma_dvi like b_dvi||'%' and nv in (Select distinct nv from temp_bc_nv)
    group by ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,ngay_htnv;
    
--doanh thu phat sinh  trong ky
insert into temp_2 (c1, c2, c3, c4, c5, c6, c7, n2, n4, n6, c8, n1)
    select c1, c2, c3, c4, c5, c6, c7,sum(n2), sum(n4),sum(n6),c8,n1
    from temp_1
        where --(b_dvi is null or ma_dvi = b_dvi) and (b_phong is null or phong=b_phong)
--            and (b_lhnv is null or lh_nv like b_lhnv||'%')
--            and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
--            and nv in (Select distinct nv from temp_bc_nv) and
         n10 between b_ngayd and b_ngayc
    group by c1, c2, c3, c4, c5, c6, c7,c8,n1;

commit;
open cs1 for
    select c1 ma_dvi, c2 phong, c3 so_hd, c4 ma_kh, c6 cb_ql, c7 ma_kt, n2 dtps, n4 dtbh, n6 dttt, c8 lh_nv--, n1
        from temp_2 order by c2, c1;

--    exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP FUNCTION BC_TL_HHONG;

CREATE OR REPLACE FUNCTION BC_TL_HHONG
    (b_ma_dvi varchar2,b_ma varchar2,b_lhnv varchar2,b_ngay number) return  number
as
    b_ngay_m number;b_hhong number;
begin

select nvl(max(ngay),0) into b_ngay_m from bh_dl_ma_kh_lhnv where
    ma_dvi=b_ma_dvi and ma=b_ma and lh_nv=b_lhnv and ngay<=b_ngay;
if b_ngay_m=0 then b_hhong:=0;
else    select hhong into b_hhong from bh_dl_ma_kh_lhnv where
    ma_dvi=b_ma_dvi and ma=b_ma and lh_nv=b_lhnv and ngay=b_ngay_m;
end if;
return b_hhong;
end;
/

DROP FUNCTION BC_TL_HTRO;

CREATE OR REPLACE FUNCTION BC_TL_HTRO
    (B_MA_DVI VARCHAR2,B_MA VARCHAR2,B_LHNV VARCHAR2,B_NGAY NUMBER) RETURN  NUMBER
AS
    B_NGAY_M NUMBER;B_HTRO NUMBER;
BEGIN

SELECT NVL(MAX(NGAY),0) INTO B_NGAY_M FROM BH_DL_MA_KH_LHNV WHERE
    MA_DVI=B_MA_DVI AND MA=B_MA AND LH_NV=B_LHNV AND NGAY<=B_NGAY;
IF B_NGAY_M=0 THEN  B_HTRO:=0;
ELSE    SELECT HTRO INTO B_HTRO FROM BH_DL_MA_KH_LHNV WHERE
    MA_DVI=B_MA_DVI AND MA=B_MA AND LH_NV=B_LHNV AND NGAY=B_NGAY_M;
END IF;
RETURN B_HTRO;
END;
/

