drop PROCEDURE BKT_BCKHAI;

CREATE OR REPLACE PROCEDURE BKT_BCKHAI
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_ma_bc varchar2,
    b_ngd number, b_ngc number, cs_kq out pht_type.cs_type,b_chon varchar2:='X')
AS
    b_loi varchar2(100);b_ngay_ht number;b_i1 number;b_i2 number;b_lenh varchar2(250);
    b_ngdn number;b_ngcn number;b_ngdn2 number;b_ngcn2 number;
    b_ngd2 number;b_ngc2 number;
    cs_tam pht_type.cs_type;b_dvi_tam varchar2(20);b_tenkh_tam varchar2(200);
    b_ngdqt number;b_ngcqt number;b_ngdt number;b_ngct number;
    b_ngdqt2 number;b_ngcqt2 number;
    b_ngdt2 number;b_ngct2 number;

/*
declare
    cs1 pht_type.cs_type;
begin
BKT_BCKHAI('00','TIN','CC2310','R_KT_CDKT_B01DN_TS',20210201,20210228,cs1);
end;

R_KT_CDKT_B01DN_NV

*/

begin
BKT_DAU_CUOI_QUY (b_ngd,b_ngdqt,b_ngcqt);BKT_DAU_CUOI_THANG (b_ngd,b_ngdt,b_ngct);
b_ngdn:= round(b_ngd,-4)+101;b_ngcn:= round(b_ngd,-4)+1331;
b_ngd2:=b_ngd-10000;b_ngc2:=b_ngc-10000;
BKT_DAU_CUOI_QUY (b_ngd2,b_ngdqt2,b_ngcqt2);BKT_DAU_CUOI_THANG (b_ngd2,b_ngdt2,b_ngct2);
b_ngdn2:= round(b_ngd2,-4)+101;b_ngcn2:= round(b_ngd2,-4)+1331;

if b_nsd='bctk' and b_pas='bctk' then
    b_loi:='';
else
    b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'KT','KT','NQ');
    if b_loi <> '' then raise PROGRAM_ERROR;end if;
end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR;end if;
delete ket_qua;delete temp_1;delete temp_2;delete temp_3;delete temp_4;commit;
select max(ngay_ht) into b_ngay_ht from kt_bctk where ma_dvi=b_ma_dvi and ma_bc=b_ma_bc and ngay_ht<=b_ngc;
--select max(ngay_ht) into b_ngay_ht from kt_bctk where ma_dvi=b_ma_dvi and ma_bc=b_ma_bc and ngay_ht<=b_ngd;
if b_ngay_ht is null then b_loi:='loi:Bao cao chua khai:loi';raise PROGRAM_ERROR;end if;
--temp_1(c1,n1,n2)ma,cot,tien
-- Lay toan bo so du cong no dua vao bang temp_1;
--temp_1: n1=no_dau_nt,n2=co_dau_nt,n3=no_cuoi_nt,n4=co_cuoi_nt,n5=no_dau_nnay,n6=co_dau_nnay,n7=no_cuoi_nnay,n8=co_cuoi_nnay
select count(*) into b_i1 from kt_bctk_nv where ma_dvi=b_ma_dvi and nv='CN'
    and exists (select * from kt_bctk where ma_dvi=b_ma_dvi and ma_bc=b_ma_bc and ngay_ht=b_ngay_ht and kt_bctk.id_ma=kt_bctk_nv.id_ma);
if b_i1>0 then
    --BKT_BCTK_LAY_SODUCN (b_ma_dvi,b_ngd,b_ngc);
--     BKT_BCTK_LAY_SODUCN_KO_CN_BH (b_ma_dvi,b_ngd,b_ngc);

    -- Hung: Bo sung ngay 06/01/2021(Bc tk 1311% Duong viet)
    -- 1311 (Bao cao BH->Bao cao ke toan->Bao cao chi tiet so du tai khoan cong no->Bao cao chi tiet: chon ma_tk=13118
    --delete temp_1 where c4 like '13118%';
    --delete temp_1 where c4='33111' or c4='33112' or c4='33113';
    delete temp_1 where c4 like '1311%';
