update ket_qua set c10='0' where c1 not in (select distinct rtrim(ma_ct) from kt_bctk where
    ma_dvi=b_ma_dvi and ma_bc=b_ma_bc and ngay_ht=b_ngay_ht and trim(ma_ct) is not null);
