if b_loi is not null then raise PROGRAM_ERROR;end if;

delete temp_1;
update ket_qua set c1=' ' where c5='K';update ket_qua set c2=substr(c2,instr(c2,'/')+1);
open cs_kq for select nvl(c6,' ') so_tt,nvl(c1,' ') ma,nvl(c2,' ') ten,nvl(c5,' ') ht,nvl(c15,' ') cap,nvl(n1,0) n1,nvl(n2,0) n2,nvl(n3,0) n3,
