    nvl(n13,0) n13,nvl(n14,0) n14,nvl(n15,0) n15,nvl(n16,0) n16,nvl(n17,0) n17,nvl(n18,0) n18,nvl(n19,0) n19,nvl(n20,0) n20,
    nvl(n21,0) n21,nvl(n22,0) n22,nvl(n23,0) n23,nvl(n24,0) n24,nvl(n25,0) n25,nvl(n26,0) n26,nvl(n27,0) n27,nvl(n28,0) n28,n29
    from ket_qua where c5 <>'T' order by n29;
b_lenh:=to_char(round(b_ngd,-2)/100)||'-'||to_char(round(b_ngc,-2)/100);
if b_chon='L' then
    delete ktb_bc where ma_dvi=b_ma_dvi and ma_bc=b_ma_bc and loai=b_lenh;
    insert into ktb_bc select b_ma_dvi,b_ma_bc,'',b_lenh,nvl(c6,' ') so_tt,to_char(rownum),b_ngd,b_ngc,c1,c2,c15,c5,
        n1,n2,n3,n4,n5,n6,n7,n8,n9,n10,n11,n12,n13,n14,n15,n16,n17,n18,n19,n20,n21,
        n22,n23,n24,n25,n26,n27,n28,b_nsd
        from ket_qua where c5 <>'T';
    update ktb_bc set ten_bc=(select max(ten_bc) from kt_bctk where ma_dvi=b_ma_dvi and ma_bc=b_ma_bc
        and ngay_ht=b_ngay_ht)
        where ma_dvi=b_ma_dvi and ma_bc=b_ma_bc and loai=b_lenh;
end if;
exception when PROGRAM_ERROR then raise_application_error (-20105,b_loi);
end;
