DROP PROCEDURE BKT_BCTK_LAY_SODUCN_KO_CN_BH;

CREATE OR REPLACE PROCEDURE BKT_BCTK_LAY_SODUCN_KO_CN_BH (b_ma_dvi varchar2,b_ngd number,b_ngc number)
AS
    b_loi varchar2(100);
    b_ngdqt number;b_ngcqt number;b_ngdt number;b_ngct number;b_ngdn number;b_ngcn number;
    b_ngd2 number;b_ngc2 number;b_ngdqt2 number;b_ngcqt2 number;
    b_ngdt2 number;b_ngct2 number;b_ngdn2 number;b_ngcn2 number;
        cs_tam pht_type.cs_type;b_tam varchar2(10);
begin
BKT_DAU_CUOI_QUY (b_ngd,b_ngdqt,b_ngcqt);BKT_DAU_CUOI_THANG (b_ngd,b_ngdt,b_ngct);
b_ngdn:= round(b_ngd,-4)+101;b_ngcn:= round(b_ngd,-4)+1331;
b_ngd2:=b_ngd-10000;b_ngc2:=b_ngc-10000;
BKT_DAU_CUOI_QUY (b_ngd2,b_ngdqt2,b_ngcqt2);BKT_DAU_CUOI_THANG (b_ngd2,b_ngdt2,b_ngct2);
b_ngdn2:= round(b_ngd2,-4)+101;b_ngcn2:= round(b_ngd2,-4)+1331;
delete temp_1;
--begin BKT_BCTK_LAY_SODUCN('01',20080101,20081231);end;
