    n4=co_cuoi_nt,

    n5=no_dau_nnay,
    n6=co_dau_nnay,

    n7=no_cuoi_nnay,
    n8=co_cuoi_nnay
*************************************************************/
------------------------------------------------------------------------------------------------------------------------
