-- 		from cn_ps_temp_ct group by ma_tk;
-- end loop;

-- Chuyen doan code don tong o cuoi len
insert into temp_1(c30,c4,n1,n2,n3,n4,n5,n6,n7,n8,n20) select c30,c4,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n8,0)),1 from temp_1 group by c30,c4;
delete temp_1 where nvl(n20,0)<>1;commit;
return;

-----Hung
--- Bo khong xu ly code lay cong no BH



------------------------------------------------------------------------------------------------------------------------
--Lay so lieu cong no tu Nghiep vu bao hiem
------------------------------------------------------------------------------------------------------------------------
if length(nvl(b_ma_dvi,' '))>=3 then

    --13111: Cong no khach hang, 13119: Thu ho phi, 33113: Cong no giam dinh,33112: Cong no dai ly,33111: Cong no boi thuong
    --b_ma_tk='13111'
    -- KHach hang
    --Nam truoc
    BKT_LAY_SODU_CNBH_CDKT(b_ma_dvi,'13111',b_ngdn2,b_ngcn2,b_loi);
    --out: temp_3(c2,c3,c4,n14,n15): ma_dvi,ma_kh,no_ck,co_ck
    insert into temp_1(c30,c4,n1,n2,n3,n4) select c2,'1311',sum(n5),sum(n6),sum(n14),sum(n15) from temp_3 group by c2;
    -- Nam nay
    BKT_LAY_SODU_CNBH_CDKT(b_ma_dvi,'13111',b_ngd,b_ngc,b_loi);
    --out: temp_3(c2,c3,c4,n14,n15): ma_dvi,ma_kh,no_ck,co_ck
    insert into temp_1(c30,c4,n5,n6,n7,n8) select c2,'1311',sum(n5),sum(n6),sum(n14),sum(n15) from temp_3 group by c2;
    ------------------------------------------------------------------------------------------------------------------------
    /*
    --b_ma_tk='13119'
    -- Thu ho phi
