DROP PROCEDURE BKT_DAU_CUOI_QUY;

CREATE OR REPLACE PROCEDURE BKT_DAU_CUOI_QUY
	(B_NGAYD NUMBER,B_NGAYDQT IN OUT NUMBER,B_NGAYCQT IN OUT NUMBER, B_CHON VARCHAR2 :='1')
AS
	
	B_C2 CHAR(2);B_I NUMBER;B_I1 NUMBER;B_QUY NUMBER;
BEGIN

B_C2:= SUBSTR(TO_CHAR(B_NGAYD),5,2);
B_I1:= TO_NUMBER(B_C2);
B_QUY:= CEIL(B_I1/3);
IF B_QUY > 1 THEN
	B_I1:= B_QUY - 1;
  	B_I:= (B_I1 - 1) * 3 + 1;
		IF B_I <= 9 THEN
			B_C2:= '0'||TO_CHAR(B_I);
		ELSE
			B_C2:=TO_CHAR(B_I);
		END IF;
	B_NGAYDQT:=TO_NUMBER(SUBSTR(TO_CHAR(B_NGAYD),1,4) || B_C2 || '01');
	B_I := (B_QUY - 1) * 3;
	IF B_I <= 9 THEN
  		B_C2 := '0' || TO_CHAR(B_I);
  	ELSE
		  B_C2:=TO_CHAR(B_I);
  	END IF;
  	B_NGAYCQT:=TO_NUMBER(SUBSTR(TO_CHAR(B_NGAYD),1,4) || B_C2 || '31');
ELSE
	IF B_CHON='1' THEN
		B_NGAYDQT:=0;B_NGAYCQT:=0;
	ELSE
		B_NGAYDQT:= ROUND(B_NGAYD,-4) - 10000 + 0101;
		B_NGAYCQT:= ROUND(B_NGAYD,-4) -10000 + 1231;
	END IF;
END IF;
END;
/

DROP PROCEDURE BKT_DAU_CUOI_THANG;

CREATE OR REPLACE PROCEDURE BKT_DAU_CUOI_THANG
	(B_NGAYD NUMBER,B_NGAYDT IN OUT NUMBER,B_NGAYCT IN OUT NUMBER)
AS
	B_C2 CHAR(2);B_I NUMBER;B_I1 NUMBER;B_QUY NUMBER;
BEGIN

B_C2:= SUBSTR(TO_CHAR(B_NGAYD),5,2);
B_I1:= TO_NUMBER(B_C2)-1;
IF B_I1>0 THEN
	B_NGAYDT:=ROUND(B_NGAYD,-4)+B_I1*100;
	B_NGAYCT:=ROUND(B_NGAYD,-4)+B_I1*100+99;
ELSE
	B_NGAYDT:=0;B_NGAYCT:=0;
END IF;
END;
/

