        INSERT INTO TEMP_3(C2,C3,N5,N6,N14,N15) SELECT C20,'33112',SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N14,0)),SUM(NVL(N15,0)) FROM TEMP_2 GROUP BY C20;

    ELSIF B_MA_TK='33113' THEN
        INSERT INTO TEMP_1(C20,N1,N6) SELECT /*+ USE_NL(a, b) */ A.MA_DVI,A.SO_ID,SUM(A.TON_QD) FROM BH_BT_GD_SC A,
            (SELECT MA_DVI,MA_NT,SO_ID,MAX(NGAY_HT) NGAY_HT FROM BH_BT_GD_SC WHERE 
                NGAY_HT<B_NGAYD GROUP BY MA_DVI,MA_NT,SO_ID) B
            WHERE A.MA_DVI=B.MA_DVI AND A.MA_NT=B.MA_NT AND A.SO_ID=B.SO_ID AND A.NGAY_HT=B.NGAY_HT
            GROUP BY A.MA_DVI,A.SO_ID HAVING SUM(A.TON_QD)<>0;


        UPDATE TEMP_1 SET N19=(SELECT SO_ID_BT FROM BH_BT_GD_HS WHERE MA_DVI=C20 AND SO_ID=N1);

        UPDATE TEMP_1 SET N20=(SELECT SO_ID_HD FROM BH_BT_HS WHERE MA_DVI=C20 AND SO_ID=N19);

        DELETE TEMP_1 WHERE FBH_HD_KIEU_HD(C20,N20)='V';

        UPDATE TEMP_1 SET N5=-N6,N6=0 WHERE N6<0;
        update temp_1 set c5=(select phong from bh_hd_goc where ma_dvi=temp_1.c20 and so_id=temp_1.n20);
        delete temp_1 where c5='TBH';

        INSERT INTO TEMP_2(C20,N5,N6) SELECT C20,SUM(NVL(N5,0)),SUM(NVL(N6,0)) FROM TEMP_1 GROUP BY C20;

        DELETE TEMP_1;COMMIT;

        INSERT INTO TEMP_1(C20,N1,N15) SELECT /*+ USE_NL(a, b) */ A.MA_DVI,A.SO_ID,SUM(A.TON_QD) FROM BH_BT_GD_SC A,
            (SELECT MA_DVI,MA_NT,SO_ID,MAX(NGAY_HT) NGAY_HT FROM BH_BT_GD_SC WHERE 
                NGAY_HT<=B_NGAYC GROUP BY MA_DVI,MA_NT,SO_ID) B
            WHERE A.MA_DVI=B.MA_DVI AND A.MA_NT=B.MA_NT AND A.SO_ID=B.SO_ID AND A.NGAY_HT=B.NGAY_HT
            GROUP BY A.MA_DVI,A.SO_ID HAVING SUM(A.TON_QD)<>0;

        UPDATE TEMP_1 SET N19=(SELECT SO_ID_BT FROM BH_BT_GD_HS WHERE MA_DVI=C20 AND SO_ID=N1);

        UPDATE TEMP_1 SET N20=(SELECT SO_ID_HD FROM BH_BT_HS WHERE MA_DVI=C20 AND SO_ID=N19);

        DELETE TEMP_1 WHERE FBH_HD_KIEU_HD(C20,N20)='V';
        update temp_1 set c5=(select phong from bh_hd_goc where ma_dvi=temp_1.c20 and so_id=temp_1.n20);
        delete temp_1 where c5='TBH';

        UPDATE TEMP_1 SET N14=-N15,N15=0 WHERE N15<0;
        INSERT INTO TEMP_2(C20,N14,N15) SELECT C20,SUM(NVL(N14,0)),SUM(NVL(N15,0)) FROM TEMP_1 GROUP BY C20;

        INSERT INTO TEMP_3(C2,C3,N5,N6,N14,N15) SELECT C20,'33113',SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N14,0)),SUM(NVL(N15,0)) FROM TEMP_2
            GROUP BY C20;
    END IF;
end if;
DELETE TEMP_1;
-- DELETE TEMP_CN;
DELETE TEMP_2;COMMIT;
EXCEPTION
    WHEN PROGRAM_ERROR THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
    WHEN OTHERS THEN NULL;
END;

/

drop procedure BKT_TH_PSTK;

create or replace procedure BKT_TH_PSTK
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2, b_ngayd number,b_ngayc number,b_ma_tk varchar2,b_ma_tke varchar2,
    cs_cdpsct out pht_type.cs_type,b_l_ct varchar2,b_goptk varchar2:='K')
AS
    b_loi varchar2(100);b_matk varchar2(20);b_matke varchar2(20);b_ngay0 number;b_i number;
begin
-- Bang tong hop phat sinh tai khoan
-- Neu can do lai cho don vi dang dung 5.10 cung duoc
-- Update 14/06/04
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'KT','KT','NX');
if b_loi is not null then raise PROGRAM_ERROR;end if;
delete ket_qua;delete temp_1;commit;
b_matk:=nvl(b_ma_tk,' ');b_matke:=nvl(b_ma_tke,' ');
b_ngay0:= round(b_ngayd,-4)+101;
-- Dau ky
-- ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)->ma_tk,ma_tke,no_dk,co_dk
-- no_ps,co_ps,lk_no_ps,lk_co_ps,no_ck,co_ck
-- insert into ket_qua (c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
--     select ma_tk,ma_tke,no_ck,co_ck,0,0,0,0,0,0,1 from kt_sc
--     where ma_dvi=b_ma_dvi and (ma_tk,ma_tke,ngay_ht) in
--     (select ma_tk,ma_tke,max(ngay_ht) from kt_sc where ma_dvi=b_ma_dvi and
--         (b_matk=' ' or b_matk is null or ma_tk like b_matk||'%') and
--         (b_matke=' ' or b_matke is null or ma_tke like b_matke) and ngay_ht<b_ngayd 
--     group by ma_tk,ma_tke);
-- Phat sinh
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_tk_no,ma_tke_no,0,0,nvl(sum(tien),0),0,0,0,0,0,1 from kt_3
    where ma_dvi=b_ma_dvi and (b_matk=' ' or ma_tk_no like b_matk||'%') and (b_matke=' ' or ma_tke_no like b_matke) 
        and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)  and ngay_ht between b_ngayd and b_ngayc 
    group by ma_tk_no,ma_tke_no;
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_tk_co,ma_tke_co,0,0,0,nvl(sum(tien),0),0,0,0,0,1 from kt_3
    where ma_dvi=b_ma_dvi and (b_matk=' ' or ma_tk_co like b_matk||'%') and  (b_matke=' ' or ma_tke_co like b_matke) 
        and (b_l_ct is null  or nvl(l_ct,' ')=b_l_ct) and ngay_ht between b_ngayd and b_ngayc 
    group by ma_tk_co,ma_tke_co;
-- Luy ke phat sinh
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_tk_no,ma_tke_no,0,0,0,0,nvl(sum(tien),0),0,0,0,1 from kt_3
    where ma_dvi=b_ma_dvi and (b_matk=' ' or ma_tk_no like b_matk||'%') and (b_matke=' ' or ma_tke_no like b_matke) 
        and (b_l_ct is null  or nvl(l_ct,' ')=b_l_ct) and ngay_ht between b_ngay0 and b_ngayc 
    group by ma_tk_no,ma_tke_no;
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_tk_co,ma_tke_co,0,0,0,0,0,nvl(sum(tien),0),0,0,1 from kt_3
    where ma_dvi=b_ma_dvi and (b_matk=' ' or ma_tk_co like b_matk||'%') and (b_matke=' ' or ma_tke_co like b_matke) 
        and (b_l_ct is null  or nvl(l_ct,' ')=b_l_ct) and ngay_ht between b_ngay0 and b_ngayc 
    group by ma_tk_co,ma_tke_co;
-- Cuoi ky
-- insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select kt_sc.ma_tk,kt_sc.ma_tke,0,0,0,0,0,0,no_ck,co_ck,1 from kt_sc,
--     (select ma_tk,ma_tke,max(ngay_ht) as ngay_ht from kt_sc 
--         where ma_dvi=b_ma_dvi and (b_matk=' ' or ma_tk like b_matk||'%') 
--             and (b_matke=' ' or ma_tke like b_matke) and ngay_ht<=b_ngayc  
--         group by ma_tk,ma_tke) ng_c
--     where kt_sc.ma_dvi=b_ma_dvi and kt_sc.ma_tk=ng_c.ma_tk and kt_sc.ma_tke=ng_c.ma_tke  and kt_sc.ngay_ht=ng_c.ngay_ht;

insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) 
    select c1,c2,sum(n1),sum(n2),sum(n3),sum(n4),sum(n5),sum(n6),sum(n7),sum(n8),0 
    from ket_qua group by c1,c2;
delete ket_qua where n15<>0;commit;

/*
update ket_qua set n1=n1-n2,n2=0,n3=n3-n4,n4=0,n5=n5-n6,n6=0,n7=n7-n8,n8=0 where substr(c1,1,1) in('2','4','6','8');
update ket_qua set n2=n2-n1,n1=0,n4=n4-n3,n3=0,n6=n6-n5,n5=0,n8=n8-n7,n7=0 where substr(c1,1,1) in('1','3','5','7','9');
*/
-- update ket_qua set c20=(select tc from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);
update ket_qua set n1=n1-n2,n2=0,n3=n3-n4,n4=0,n5=n5-n6,n6=0,n7=n7-n8,n8=0 where c20 like '%T2:N%';
update ket_qua set n2=n2-n1,n1=0,n4=n4-n3,n3=0,n6=n6-n5,n5=0,n8=n8-n7,n7=0 where c20 like '%T2:C%';
update ket_qua set n1=case when n1-n2>0 then n1-n2 else 0 end,n2=case when n1-n2<0 then n2-n1 else 0 end,
        n3=case when n3-n4>0 then n3-n4 else 0 end,n4=case when n3-n4<0 then n4-n3 else 0 end,
        n5=case when n5-n6>0 then n5-n6 else 0 end,n6=case when n5-n6<0 then n6-n5 else 0 end,
        n7=case when n7-n8>0 then n7-n8 else 0 end,n8=case when n7-n8<0 then n8-n7 else 0 end
    where c20 like '%T2:T%';

insert into ket_qua(c1,c2,n1,n2,n3,n4,n15)
    select c1,c2,decode(n1,0,n2,n1),decode(n3,0,n4,n3),decode(n5,0,n6,n5),decode(n7,0,n8,n7),1 
    from ket_qua where n15=0;
delete ket_qua where n15<>1;
-- update ket_qua set c5=(select max(nhom) from kt_ma_tktke where ma_dvi=b_ma_dvi and ma_tk=c1);
insert into temp_1 (c1,n1,n2,n3,n4) select c1,sum(n1),sum(n2),sum(n3),sum(n4) from ket_qua group by c1;
-- insert into ket_qua(c1,c2,c5,n1,n2,n3,n4,n15) select  c1,b.ma,c5,sum(n1),sum(n2),sum(n3),sum(n4),2
--  from ket_qua a,(select nhom,ma,ten from kt_ma_tke where ma_dvi=b_ma_dvi and tc='T') b where a.c5=b.nhom and 
--  a.c2 like b.ma||'%' group by c1,b.ma,c5;
update ket_qua set (n5,n6,n7,n8)=(select n1,n2,n3,n4 from temp_1 where temp_1.c1=ket_qua.c1);
-- c3,c4->ten_ma_tk,ten_ma_tke
delete temp_2;commit;
if b_goptk='K' then
    insert into temp_2(c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15) select c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15 from ket_qua;
else
    insert into temp_2(c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15) select substr(c1,1,3),c2,c3,c4,c5,sum(n1),sum(n2),sum(n3),
        sum(n4),0,0,0,0,n15 from ket_qua group by substr(c1,1,3),c2,c3,c4,c5,n15;
    update temp_2 set (n5,n6,n7,n8)=(select sum(n1),sum(n2),sum(n3),sum(n4) from temp_1 where substr(temp_1.c1,1,3)=temp_2.c1 group by substr(temp_1.c1,1,3));
end if;
-- update temp_2 set c3=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);
-- update temp_2 set c4=(select ten from kt_ma_tke where ma_dvi=b_ma_dvi and ma=c2 and nhom=c5);
/*
open cs_cdpsct for select nvl(c1,'KXD') ma_tk,nvl(c3,N'Kh�ng x�c d?nh') ten_ma_tk,
        nvl(c2,'KXD') ma_tke,nvl(c4,N'Kh�ng x�c d?nh') ten_ma_tke,nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck, 
        nvl(n5,0) tdk,nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,n15 nhom 
    from temp_2  order by c1,c2;
*/
open cs_cdpsct for select nvl(c1,'KXD') ma_tk,nvl(c3,U'Kh\00F4ng x\00E1c \0111\1ECBnh') ten_ma_tk,nvl(c2,'KXD') ma_tke,nvl(c4,U'Kh\00F4ng x\00E1c \0111\1ECBnh') ten_ma_tke,
    nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,
    n15 nhom from temp_2  order by c1,c2;
exception
    when PROGRAM_ERROR then raise_application_error(-20105,b_loi);
    when others then raise;
end;

/
drop procedure BKT_TH_PSTK_DB;

CREATE OR REPLACE procedure BKT_TH_PSTK_DB
 (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,
  b_ngayd number,b_ngayc number,b_ct varchar2,b_ma_tk varchar2,b_ma_tke varchar2,
  cs_cdpsct out pht_type.cs_type,b_l_ct varchar2:=' ',b_goptk varchar2:='K')
AS
 b_loi varchar2(100);b_matk varchar2(20);b_matke varchar2(20);b_ngay0 number;b_i number;
begin
-- Bang tong hop phat sinh tai khoan
-- Update 10/4/2008
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'KT','KT','NX');
if b_loi is not null then raise PROGRAM_ERROR;end if;
delete ket_qua;delete temp_1;b_matk:=nvl(b_ma_tk,' ');b_matke:=nvl(b_ma_tke,' ');
b_ngay0:= round(b_ngayd,-4)+101;
-- Dau ky
-- ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)->ma_tk,ma_tke,no_dk,co_dk
-- no_ps,co_ps,lk_no_ps,lk_co_ps,no_ck,co_ck
insert into ket_qua (c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select kt_sc.ma_tk,kt_sc.ma_tke,no_ck,co_ck,0,0,0,0,0,0,1 from kt_sc,
  (select ma_tk,ma_tke,max(ngay_ht) as ngay_ht from kt_sc
  where (b_ct is null or kt_sc.ma_dvi=b_ct) and (ma_tk like b_matk or b_matk=' ') and 
  (ma_tke like b_matke or b_matke=' ') and ngay_ht<b_ngayd
 group by ma_tk,ma_tke) ng_d
 where (b_ct is null or kt_sc.ma_dvi=b_ct) and kt_sc.ma_tk=ng_d.ma_tk and kt_sc.ma_tke=ng_d.ma_tke
 and kt_sc.ngay_ht=ng_d.ngay_ht;
-- Phat sinh
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select ma_tk_no,ma_tke_no,0,0,nvl(sum(tien),0),0,0,0,0,0,1 from kt_3
 where (b_ct is null or ma_dvi=b_ct) and (ma_tk_no like b_matk or b_matk=' ') and 
 (ma_tke_no like b_matke or b_matke=' ') and
 (nvl(l_ct,' ')<>b_l_ct or b_l_ct=' ')
 and ngay_ht between b_ngayd and b_ngayc
 group by ma_tk_no,ma_tke_no;
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select ma_tk_co,ma_tke_co,0,0,0,nvl(sum(tien),0),0,0,0,0,1 from kt_3
 where (b_ct is null or ma_dvi=b_ct) and (ma_tk_co like b_matk or b_matk=' ') and 
 (ma_tke_co like b_matke or b_matke=' ') and
 (nvl(l_ct,' ')<>b_l_ct or b_l_ct=' ')
 and ngay_ht between b_ngayd and b_ngayc
 group by ma_tk_co,ma_tke_co;
-- Luy ke phat sinh
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select ma_tk_no,ma_tke_no,0,0,0,0,nvl(sum(tien),0),0,0,0,1 from kt_3
 where (b_ct is null or ma_dvi=b_ct) and (ma_tk_no like b_matk or b_matk=' ') and 
 (ma_tke_no like b_matke or b_matke=' ') and
 (nvl(l_ct,' ')<>b_l_ct or b_l_ct=' ')
 and ngay_ht between b_ngay0 and b_ngayc
 group by ma_tk_no,ma_tke_no;
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select ma_tk_co,ma_tke_co,0,0,0,0,0,nvl(sum(tien),0),0,0,1 from kt_3
 where (b_ct is null or ma_dvi=b_ct) and (ma_tk_co like b_matk or b_matk=' ') and 
 (ma_tke_co like b_matke or b_matke=' ') and
 (nvl(l_ct,' ')<>b_l_ct or b_l_ct=' ')
 and ngay_ht between b_ngay0 and b_ngayc
 group by ma_tk_co,ma_tke_co;
-- Cuoi ky
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select kt_sc.ma_tk,kt_sc.ma_tke,0,0,0,0,0,0,no_ck,co_ck,1 from kt_sc,
 (select ma_tk,ma_tke,max(ngay_ht) as ngay_ht from kt_sc
 where (b_ct is null or ma_dvi=b_ct) and (ma_tk like b_matk or b_matk=' ') and 
 (ma_tke like b_matke or b_matke=' ') and ngay_ht<=b_ngayc
 group by ma_tk,ma_tke) ng_c
 where (b_ct is null or kt_sc.ma_dvi=b_ct) and kt_sc.ma_tk=ng_c.ma_tk and kt_sc.ma_tke=ng_c.ma_tke
 and kt_sc.ngay_ht=ng_c.ngay_ht;
insert into ket_qua(c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)
 select c1,c2,sum(n1),sum(n2),sum(n3),sum(n4),sum(n5),sum(n6),sum(n7),sum(n8),0
 from ket_qua group by c1,c2;
delete ket_qua where n15<>0;
update ket_qua set n1=n1-n2,n2=0,n3=n3-n4,n4=0,n5=n5-n6,n6=0,n7=n7-n8,n8=0 
        where substr(c1,1,1) in('2','4','6','8');
update ket_qua set n2=n2-n1,n1=0,n4=n4-n3,n3=0,n6=n6-n5,n5=0,n8=n8-n7,n7=0 
        where substr(c1,1,1) in('1','3','5','7','9');
insert into ket_qua(c1,c2,n1,n2,n3,n4,n15)
    select c1,c2,decode(n1,0,n2,n1),decode(n3,0,n4,n3),decode(n5,0,n6,n5),decode(n7,0,n8,n7),1
    from ket_qua where n15=0;
delete ket_qua where n15<>1;
update ket_qua set c5=(select max(nhom) from kt_ma_tktke where ma_dvi=b_ma_dvi and ma_tk=c1);
insert into temp_1 (c1,n1,n2,n3,n4) select c1,sum(n1),sum(n2),sum(n3),sum(n4) from ket_qua
    group by c1;
insert into ket_qua(c1,c2,c5,n1,n2,n3,n4,n15) select  c1,b.ma,c5,sum(n1),sum(n2),sum(n3),sum(n4),2
 from ket_qua a,(select nhom,ma,ten from kt_ma_tke where ma_dvi=b_ma_dvi and tc='T') b
    where a.c5=b.nhom and a.c2 like b.ma||'%' group by c1,b.ma,c5;
/*
-- c3,c4->ten_ma_tk,ten_ma_tke
update ket_qua set c3=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);
update ket_qua set c4=(select ten from kt_ma_tke where ma_dvi=b_ma_dvi and ma=c2 and nhom=c5);
--update ket_qua set c4=c3 where c4 is null;
update ket_qua set (n5,n6,n7,n8)=(select n1,n2,n3,n4 from temp_1 where temp_1.c1=ket_qua.c1);
open cs_cdpsct for select nvl(c1,' ') ma_tk,nvl(c3,' ') ten_ma_tk,nvl(c2,' ') ma_tke,nvl(c4,' ') ten_ma_tke,
 nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,nvl(n6,0) tps,
    nvl(n7,0) tlk_ps,nvl(n8,0) tck,n15 nhom from ket_qua
 order by c1,c2;
*/
delete temp_2;commit;
if b_goptk='K' then
    insert into temp_2(c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15) select c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15 from ket_qua;
else
    insert into temp_2(c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15) select substr(c1,1,3),c2,c3,c4,c5,sum(n1),sum(n2),sum(n3),
        sum(n4),sum(n5),sum(n6),sum(n7),sum(n8),n15 from ket_qua group by substr(c1,1,3),c2,c3,c4,c5,n15;
    update temp_2 set (n5,n6,n7,n8)=(select sum(n1),sum(n2),sum(n3),sum(n4) from temp_1 where substr(temp_1.c1,1,3)=temp_2.c1 group by substr(temp_1.c1,1,3));
end if;
update temp_2 set c3=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);
update temp_2 set c4=(select ten from kt_ma_tke where ma_dvi=b_ma_dvi and ma=c2 and nhom=c5);
open cs_cdpsct for select nvl(c1,'KXD') ma_tk,nvl(c3,N'Kh�ng x�c d?nh') ten_ma_tk,nvl(c2,'KXD') ma_tke,nvl(c4,N'Kh�ng x�c d?nh') ten_ma_tke,
    nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,
    n15 nhom from temp_2  order by c1,c2;
exception
 when PROGRAM_ERROR then raise_application_error(-20105,b_loi);
 when others then raise;
end;
/
drop procedure BKT_TH_PSTK_LAYPS;

create or replace procedure BKT_TH_PSTK_LAYPS
 (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2, b_ngayd number,b_ngayc number,b_ma_dvi_m varchar2,
  b_ma_tk varchar2,b_ma_tke varchar2,cs_cdpsct out pht_type.cs_type,b_l_ct varchar2,b_goptk_in varchar2:='K',
  b_klke varchar2:='T',b_slhtl varchar2:='K',b_tkct_in varchar2:='K')
AS
 b_loi varchar2(100);b_matk varchar2(20);b_matke varchar2(20);b_ngay0 number;b_i number;b_ngaydn number;
 b_loai_ps varchar2(1):='N';b_dvi_ct varchar2(10);b_goptk varchar2(1);b_tkct varchar2(1);
 b_ktra_pti number;
begin
--- Khong dung, khong xoa bang TEMP_SL trong thu tuc nay. Vi thu tuc nay duoc thu tuc khac goi su dung.
---- Bo xung them bien b_htlai (9/2008) Hiep
---- Bang tong hop phat sinh tai khoan
---- Update 17/4/2008
---- Bao cao nay chi lay phat sinh. Bao cao nay giong nhu so cai
---- Cai nay lam theo yeu cau
---- b_ma_dvi_m is null la bao cao dia ban
---- b_klke: T: Tai khoan, D Don vi
---- Begin KT_MICVP.BKT_TH_PSTK_LAYPS('00','BC','mic123',20080401,20080630,'','642%',' ',:cs1,'','C','T','C'); end;
/******************
01/2010.......
Them bien b_ktra_pti de loai chung tu hach toan lai cua PTI
cac chung tu co ma HTCN
Neu don vi hach toan sai thi cung chiu thoi
*******************/
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'KT','KT','NX');
if b_loi is not null then raise PROGRAM_ERROR;end if;
delete ket_qua;delete temp_1;delete temp_2;commit;
b_matk:=nvl(b_ma_tk,' ');b_matke:=nvl(b_ma_tke,' ');b_ngaydn:= round(b_ngayd,-4)+0101;
select count(*) into b_ktra_pti from ht_ma_dvi where upper(ten_dbo) like '%PTI%';
-- Dau ky
-- ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15)->ma_dvi,ma_tk,ma_tke,no_dk,co_dk
-- no_ps,co_ps,lk_no_ps,lk_co_ps,no_ck,co_ck
b_goptk:=b_goptk_in;b_tkct:=b_tkct_in;
select count(*) into b_i from ht_ma_dvi where ten like '%SHB-VINACOMIN%';
if b_i>0 then b_goptk:='K';b_tkct:='K';end if;
if substr(b_ma_tk,1,3) in ('515','711') then b_loai_ps:='C'; end if;
--and l_ct<>'HTCN'  
if b_loai_ps='N' then
-- Phat sinh thuc
    -- Dau ky theo phat sinh no: n1
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,nvl(sum(tien),0),0,0,
        0,0,0,0,0,1 from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_no like b_matk) 
        and (b_matke=' ' or ma_tke_no like b_matke) and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)  and ngay_ht < b_ngayd 
            group by ma_dvi,ma_tk_no,ma_tke_no;
    --dieuchinh
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,-nvl(sum(tien),0),0,0,
        0,0,0,0,0,1 from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) 
        and not (ma_tk_no like '136%' or ma_tk_no like '336%' or ma_tk_no like '911%') and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)
        and ngay_ht < b_ngayd  group by ma_dvi,ma_tk_co,ma_tke_co;
    -- Neu la PTI thi xoa bo nhung chung tu HTCN la nhung chung tu hach toan lai tai cong ty    
    if b_ktra_pti>0 and b_ma_dvi='00' and nvl(b_l_ct,' ')=' ' then
        insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,-nvl(sum(tien),0),0,0,
            0,0,0,0,0,1 from kt_3 where (ma_dvi='00') and (b_matk=' ' or ma_tk_no like b_matk) 
            and (b_matke=' ' or ma_tke_no like b_matke) and nvl(l_ct,' ')='HTCN'  and ngay_ht < b_ngayd 
            group by ma_dvi,ma_tk_no,ma_tke_no;
    end if;
    -- Phat sinh no trong ky: n2
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,0,nvl(sum(tien),0),0,0,0,0,0,0,1 
         from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_no like b_matk) 
         and (b_matke=' ' or ma_tke_no like b_matke) and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)and ngay_ht between b_ngayd and b_ngayc
         group by ma_dvi,ma_tk_no,ma_tke_no;
    --Dieu chinh
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,0,-nvl(sum(tien),0),0,0,0,0,0,0,1 
         from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) 
         and not (ma_tk_no like '136%' or ma_tk_no like '336%' or ma_tk_no like '911%') and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)
         and ngay_ht between b_ngayd and b_ngayc  group by ma_dvi,ma_tk_co,ma_tke_co;
-- Neu la PTI thi xoa bo nhung chung tu HTCN la nhung chung tu hach toan lai tai cong ty
    if b_ktra_pti>0 and b_ma_dvi='00' and nvl(b_l_ct,' ')=' ' then
        insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,0,-nvl(sum(tien),0),0,0,0,0,0,0,1 
             from kt_3 where ma_dvi='00' and (b_matk=' ' or ma_tk_no like b_matk) 
             and (b_matke=' ' or ma_tke_no like b_matke) and (nvl(l_ct,' ')='HTCN') and ngay_ht between b_ngayd and b_ngayc
             group by ma_dvi,ma_tk_no,ma_tke_no;    
    end if;
    -- Luy ke phat sinh no tu dau nam chay bao cao: n3
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,0,0,nvl(sum(tien),0),0,0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_no like b_matk) 
        and (b_matke=' ' or ma_tke_no like b_matke) and (b_l_ct is null  or nvl(l_ct,' ')=b_l_ct) and ngay_ht between b_ngaydn and b_ngayc
        group by ma_dvi,ma_tk_no,ma_tke_no;
    --dieu chinh
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,0,0,-nvl(sum(tien),0),0,0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) 
         and not (ma_tk_no like '136%' or ma_tk_no like '336%' or ma_tk_no like '911%') and (b_l_ct is null  or nvl(l_ct,' ')=b_l_ct) 
        and ngay_ht between b_ngaydn and b_ngayc group by ma_dvi,ma_tk_co,ma_tke_co;    
    -- Neu la PTI thi xoa bo nhung chung tu HTCN la nhung chung tu hach toan lai tai cong ty
    if b_ktra_pti>0 and b_ma_dvi='00' and nvl(b_l_ct,' ')=' ' then
        insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,0,0,-nvl(sum(tien),0),0,0,0,0,0,1 
            from kt_3 where ma_dvi='00' and (b_matk=' ' or ma_tk_no like b_matk) 
            and (b_matke=' ' or ma_tke_no like b_matke) and nvl(l_ct,' ')='HTCN' and ngay_ht between b_ngaydn and b_ngayc
            group by ma_dvi,ma_tk_no,ma_tke_no;        
    end if;
    -- Cuoi ky theo phat sinh no: 
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,0,0,0,nvl(sum(tien),0),0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_no like b_matk) 
        and (b_matke=' ' or ma_tke_no like b_matke) and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct) and ngay_ht <=b_ngayc 
        group by ma_dvi,ma_tk_no,ma_tke_no;
    --dieu chinh
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,0,0,0,-nvl(sum(tien),0),0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) 
         and not (ma_tk_no like '136%' or ma_tk_no like '336%' or ma_tk_no like '911%') and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct) 
        and ngay_ht <=b_ngayc group by ma_dvi,ma_tk_co,ma_tke_co;    
    -- Neu la PTI thi xoa bo nhung chung tu HTCN la nhung chung tu hach toan lai tai cong ty
    if b_ktra_pti>0 and b_ma_dvi='00' and nvl(b_l_ct,' ')=' ' then
        insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_no,ma_tke_no,0,0,0,-nvl(sum(tien),0),0,0,0,0,1 
            from kt_3 where ma_dvi='00' and (b_matk=' ' or ma_tk_no like b_matk) 
            and (b_matke=' ' or ma_tke_no like b_matke) and nvl(l_ct,' ')='HTCN' and ngay_ht <=b_ngayc 
            group by ma_dvi,ma_tk_no,ma_tke_no;    
    end if;
else -- Phat sinh co
-- Phat sinh thuc
    -- Dau ky theo phat sinh co: n1
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,nvl(sum(tien),0),0,0,0,0,0,0,0,1 
        from kt_3  where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) 
        and (b_matke=' ' or ma_tke_co like b_matke) and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)  
        and ngay_ht < b_ngayd group by ma_dvi,ma_tk_co,ma_tke_co;
    -- Phat sinh co trong ky: n2
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,0,nvl(sum(tien),0),0,0,0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) 
        and (b_matke=' ' or ma_tke_co like b_matke) and (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)  and ngay_ht between b_ngayd 
        and b_ngayc group by ma_dvi,ma_tk_co,ma_tke_co;
    -- Luy ke phat sinh co tu dau nam chay bao cao: n3
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,0,0,nvl(sum(tien),0),0,0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) and (b_matke=' ' or ma_tke_co like b_matke) and
        (b_l_ct is null  or nvl(l_ct,' ')=b_l_ct) and ngay_ht between b_ngaydn and b_ngayc  group by ma_dvi,ma_tk_co,ma_tke_co;
    -- Cuoi ky theo phat sinh co: n4
    insert into ket_qua(c10,c1,c2,n1,n2,n3,n4,n5,n6,n7,n8,n15) select ma_dvi,ma_tk_co,ma_tke_co,0,0,0,nvl(sum(tien),0),0,0,0,0,1 
        from kt_3 where (b_ma_dvi_m is null or ma_dvi=b_ma_dvi_m) and (b_matk=' ' or ma_tk_co like b_matk) and (b_matke=' ' or ma_tke_co like b_matke) and
         (b_l_ct is null or nvl(l_ct,' ')=b_l_ct)  and ngay_ht <=b_ngayc group by ma_dvi,ma_tk_co,ma_tke_co;
end if;
-- Loai bo cac tai khoan co tinh chat hach toan lai
-----------------------------------------------------------------------------------------------------------------
if b_slhtl='C' then
    delete ket_qua where c10<>b_ma_dvi and c1 in (select ma from kt_ma_tk where ma_dvi=b_ma_dvi and instr(tc,'HT:C')>0);
end if;
-----------------------------------------------------------------------------------------------------------------
-- Lay tong so lam chan trang theo tai khoan goc phat sinh
insert into temp_1 (c1,n1,n2,n3,n4) select c1,sum(n1),sum(n2),sum(n3),sum(n4) from ket_qua where n15=1 group by c1;
-- c3,c4->ten_ma_tk,ten_ma_tke
-- Lay nhom thong ke tai khoan
update ket_qua set c5=(select max(nhom) from kt_ma_tktke where ma_dvi=ket_qua.c10 and ma_tk=ket_qua.c1);
if b_goptk='C' then
    -- Lam cho nhung don vi co ma thong ke cua tai khoan chi phi (ABIC,MIC,PTI)
    insert into ket_qua(c10,c1,c2,c5,n1,n2,n3,n4,n5,n6,n7,n8,n15,n20) select c10,substr(c1,1,3),c2,c5,sum(n1),sum(n2),sum(n3),
        sum(n4),0,0,0,0,n15,1 from ket_qua group by c10,substr(c1,1,3),c2,c5,n15;
    delete ket_qua where nvl(n20,0)<>1;
    delete temp_1;
    -- Lay tong so lam chan trang theo tai khoan cap 1 trong truong hop muon gop tai khoan
    insert into temp_1 (c1,n1,n2,n3,n4) select c1,sum(n1),sum(n2),sum(n3),sum(n4) from ket_qua where n15=1 group by c1;
end if;
--Tong hop dua ra so lieu.
if b_klke='T' then
    -- Liet ke theo tai khoan. 
    delete temp_2;commit;
    insert into temp_2(c1,c2,c5,n1,n2,n3,n4,n15) select  c1,b.ma,b.nhom,sum(n1),sum(n2),sum(n3),sum(n4),2
         from ket_qua a,(select distinct nhom,ma from kt_ma_tke where ma_dvi=b_ma_dvi and tc='T') b 
          where trim(nvl(a.c5,' '))=trim(b.nhom) and trim(nvl(a.c2,' ')) like b.ma||'%' group by c1,b.ma,b.nhom;
    /***
        if b_ma_dvi<>'00' then
            insert into ket_qua(c1,c2,c5,n1,n2,n3,n4,n15) select c1,c2,c5,n1,n2,n3,n4,n15 from temp_2;
        else
            delete temp_2;
            insert into    
            --select * from kt_ma_tke
        end if;
    ***/
    delete temp_3;
    insert into temp_3(c1,c2,c5,n1,n2,n3,n4,n15) select c1,c2,c5,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),9 from  ket_qua group by c1,c2,c5;
    ---delete ket_qua where nvl(n15,0)<>9;
    update temp_3 set (n5,n6,n7,n8)=(select n1,n2,n3,n4 from temp_1 where temp_1.c1=temp_3.c1);
    update temp_3 set c3=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);
    update temp_3 set c4=(select min(ten) from kt_ma_tke where ma_dvi=b_ma_dvi and ma=nvl(c2,' ') and nhom=nvl(c5,' '));
    if b_tkct='C' then 
        --if b_ktra_pti>0 and b_ma_dvi='00' then
            -- Chi o PTI moi lam tro nay
        --    delete temp_3 where nvl(c2,'KXD')='KXD' or nvl(c4,'KXD')='KXD';
        --end if;      
    --Chuyen ra bang temp_4 de dua sang thu tuc BKT_TH_PSTK_LAYPS_BCD
    delete temp_4;
    insert into temp_4(c1,c2,c3,c4,c5,n1) select b_ma_dvi_m,nvl(c1,'KXD') ma_tk,nvl(c3,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,
        nvl(c2,'KXD') ma_tke,nvl(c4,'Khai t�n th?ng k�') ten_ma_tke,nvl(n2,0) ps from temp_3 
               where nvl(n2,0)<>0 or nvl(n3,0)<>0 order by c1,c2;
        open cs_cdpsct for select nvl(c1,'KXD') ma_tk,nvl(c3,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c2,'KXD') ma_tke,
           nvl(c4,U'Khai t\FFFDn th?ng k\FFFD') ten_ma_tke,nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,
           nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,n15 nhom from temp_3 
               where nvl(n2,0)<>0 or nvl(n3,0)<>0 order by c1,c2;
    else
       -- Dung cho nhung don vi khong chi tiet thong ke tai khoan
       -- SVIC khong co ma thong ke cho tai khoan chi phi nen moi phai lam the nay
       update temp_3 set c21=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=substr(c1,1,3));
       -- Lay tong so lam chan trang
       delete temp_1;
       insert into temp_1 (c1,n1,n2,n3,n4) select substr(c1,1,3),sum(n1),sum(n2),sum(n3),sum(n4) from temp_3 group by substr(c1,1,3);
       update temp_3 set (n5,n6,n7,n8)=(select n1,n2,n3,n4 from temp_1 where temp_1.c1=substr(temp_3.c1,1,3));
    --Chuyen ra bang temp_4 de dua sang thu tuc BKT_TH_PSTK_LAYPS_BCD
    delete temp_4;
    insert into temp_4(c1,c2,c3,c4,c5,n1) select b_ma_dvi_m,nvl(substr(c1,1,3),'KXD') ma_tk,nvl(c21,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c1,'KXD') ma_tke,
           nvl(c3,U'Khai t\FFFDn th?ng k\FFFD') ten_ma_tke,nvl(n2,0) ps from temp_3 where nvl(n2,0)<>0 or nvl(n3,0)<>0 order by c1,c2;
       open cs_cdpsct for select nvl(substr(c1,1,3),'KXD') ma_tk,nvl(c21,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c1,'KXD') ma_tke,
           nvl(c3,U'Khai t\FFFDn th?ng k\FFFD') ten_ma_tke,nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,
           nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,n15 nhom from temp_3 
               where nvl(n2,0)<>0 or nvl(n3,0)<>0 order by c1,c2;
    end if;    
else
    if b_tkct='C' then 
        -- Liet ke theo don vi
        delete temp_3;
        insert into temp_3(c10,c1,n1,n2,n3,n4,n20) select c10,c1,sum(nvl(n1,0)) dk,sum(nvl(n2,0)) ps,sum(nvl(n3,0)) lk_ps,
            sum(nvl(n4,0)) ck,9  from ket_qua group by c10,c1;
        --delete ket_qua where nvl(n20,0)<>9;
        update temp_3 set c3=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);
        update temp_3 set c11 =(select ten from ht_ma_dvi where ma=c10);
        update temp_3 set (n5,n6,n7,n8)=(select n1,n2,n3,n4 from temp_1 where temp_1.c1=temp_3.c1);
    --Chuyen ra bang temp_4 de dua sang thu tuc BKT_TH_PSTK_LAYPS_BCD
    delete temp_4;
    insert into temp_4(c1,c2,c3,c4,c5,n1) select b_ma_dvi_m,nvl(c1,'KXD') ma_tk,nvl(c3,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c10,'KXD') ma_tke,
            nvl(c11,U'Khai t\FFFDn th?ng k\FFFD') ten_ma_tke,nvl(n2,0) ps from temp_3 where nvl(n2,0)<>0 or nvl(n3,0)<>0 order by c1,c10;
        open cs_cdpsct for select nvl(c1,'KXD') ma_tk,nvl(c3,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c10,'KXD') ma_tke,
            nvl(c11,U'Khai t\FFFDn th?ng k\FFFD') ten_ma_tke,nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,
            nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,0 nhom from temp_3 
            where nvl(n2,0)<>0 or nvl(n3,0)<>0  order by c1,c10;
    else -- Dung cho nhung don vi khong chi tiet thong ke tai khoan
        delete temp_3;
        insert into temp_3(c10,c1,n1,n2,n3,n4,n20) select c10,c1,sum(nvl(n1,0)) dk,sum(nvl(n2,0)) ps,sum(nvl(n3,0)) lk_ps,
            sum(nvl(n4,0)) ck,9  from ket_qua group by c10,c1;
        -- delete ket_qua where nvl(n20,0)<>9;
        update temp_3 set c11 =(select ten from ht_ma_dvi where ma=c10);
        update temp_3 set (n5,n6,n7,n8)=(select n1,n2,n3,n4 from temp_1 where temp_1.c1=temp_3.c1);
        delete temp_1;
        insert into temp_1(c1,c10,c11,n1,n2,n3,n4,n5,n6,n7,n8) select substr(c1,1,3),c10,c11,sum(n1),sum(n2),sum(n3),sum(n4),
            sum(n5),sum(n6),sum(n7),sum(n8) from temp_3 group by substr(c1,1,3),c10,c11;
        update temp_1 set c3=(select ten from kt_ma_tk where ma_dvi=b_ma_dvi and ma=c1);    
    --Chuyen ra bang temp_4 de dua sang thu tuc BKT_TH_PSTK_LAYPS_BCD
    delete temp_4;
    insert into temp_4(c1,c2,c3,c4,c5,n1) select b_ma_dvi_m,nvl(c1,'KXD') ma_tk,nvl(c3,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c10,'KXD') ma_tke,
            nvl(c11,U'Khai t\FFFDn don v?') ten_ma_tke,nvl(n2,0) ps from temp_1 where nvl(n2,0)<>0 or nvl(n3,0)<>0 order by c1,c10;
        open cs_cdpsct for select nvl(c1,'KXD') ma_tk,nvl(c3,U'Khai t\FFFDn t\FFFDi kho?n') ten_ma_tk,nvl(c10,'KXD') ma_tke,
            nvl(c11,U'Khai t\FFFDn don v?') ten_ma_tke,nvl(n1,0) dk,nvl(n2,0) ps,nvl(n3,0) lk_ps,nvl(n4,0) ck,nvl(n5,0) tdk,
            nvl(n6,0) tps,nvl(n7,0) tlk_ps,nvl(n8,0) tck,0 nhom from temp_1 
            where nvl(n2,0)<>0 or nvl(n3,0)<>0  order by c1,c10;
    end if;
end if;
exception
  when PROGRAM_ERROR then raise_application_error(-20105,b_loi);
  when others then raise;
end;
/
drop PROCEDURE BKT_TH_PSTK_LAYPS_BCD;

CREATE OR REPLACE PROCEDURE BKT_TH_PSTK_LAYPS_BCD
 (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2, B_NGAYD NUMBER,B_NGAYC NUMBER,B_MA_DVI_M VARCHAR2,
  B_MA_TK VARCHAR2,B_MA_TKE VARCHAR2,CS_KQ OUT PHT_TYPE.CS_TYPE,B_L_CT VARCHAR2,B_GOPTK_IN VARCHAR2:='K',
  B_KLKE VARCHAR2:='T',B_SLHTL VARCHAR2:='K',B_TKCT_IN VARCHAR2:='K')
AS
    CS_KQ_TEMP PHT_TYPE.CS_TYPE;B_LOI VARCHAR2(254);B_LENH VARCHAR2(254);B_LENH1 VARCHAR2(254);B_LENH2 VARCHAR2(254);
    B_COT NUMBER;B_BANG NUMBER;B_PS VARCHAR2(1);B_TEN_PS VARCHAR2(100);B_MA VARCHAR2(10);B_TEN VARCHAR2(100);B_I NUMBER;
	B_ROW NUMBER;B_TKCT VARCHAR2(1);B_GOPTK VARCHAR2(1);B_I1  NUMBER;B_I2  NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'KT','KT','NX');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR;END IF;
B_GOPTK:=B_GOPTK_IN;B_TKCT:=B_TKCT_IN;
DELETE TEMP_SL;
FOR B_LP IN (SELECT DISTINCT MA_DVI FROM KT_SC WHERE (B_MA_DVI_M IS NULL OR MA_DVI=B_MA_DVI_M) ORDER BY MA_DVI) LOOP
    BKT_TH_PSTK_LAYPS(B_MA_DVI,B_NSD,B_PAS,B_NGAYD,B_NGAYC,B_LP.MA_DVI,B_MA_TK,B_MA_TKE,CS_KQ_TEMP,B_L_CT,B_GOPTK_IN,B_KLKE,B_SLHTL,B_TKCT_IN);
    
    INSERT INTO TEMP_SL(C1,C2,C3,C4,C5,N1) SELECT C1,C4,C5,' ',' ',SUM(NVL(N1,0)) FROM temp_4 GROUP BY C1,C4,C5;
END LOOP;
DELETE TEMP_1;DELETE TEMP_2;DELETE TEMP_3;
INSERT INTO TEMP_2(C1,C2) SELECT DISTINCT MA,TEN FROM HT_MA_DVI WHERE MA IN (SELECT DISTINCT C1 FROM TEMP_SL);
B_COT:= 1;B_BANG:=1;B_LOI:='loi:Loi xoay bang:loi';B_ROW:=1;
FOR B_RC IN (SELECT C1 MA_DVI,C2 TEN_DVI FROM TEMP_2 ORDER BY C1) LOOP
	B_LENH:='';
	B_LENH:='insert into temp_3(c3,c4,c5,c6,c7,c8,c1'||TO_CHAR(B_COT)||',c2'||TO_CHAR(B_COT)||',n1'||TO_CHAR(B_COT)||',n30)';
	B_LENH:=B_LENH||' select c2,c3,c4,c5,''1'',''S? ph?t sinh trong k?'','''||B_RC.MA_DVI||''','''||B_RC.TEN_DVI||'''';
    	B_LENH:=B_LENH||',n1,'||TO_CHAR(B_BANG)||' from temp_sl where c1='''||B_RC.MA_DVI||'''';
	
	IF B_LENH IS NOT NULL THEN EXECUTE IMMEDIATE B_LENH;END IF;
    	B_COT:=B_COT+1;
	IF B_COT=10 THEN B_BANG:=B_BANG+1;B_COT:=1;END IF;
END LOOP;

B_I1:=1;
WHILE B_I1 <=9 LOOP
    DELETE TEMP_1;B_LENH:='';
    B_LENH:='insert into temp_1(c1'||TO_CHAR(B_I1)||',c2'||TO_CHAR(B_I1)||',n30)';
    B_LENH:=B_LENH||' select distinct c1'||TO_CHAR(B_I1)||',c2'||TO_CHAR(B_I1)||',n30 from temp_3 where c1'||TO_CHAR(B_I1)||' is not null';
    EXECUTE IMMEDIATE B_LENH;
    B_LENH:='update temp_3 set (c1'||TO_CHAR(B_I1)||',c2'||TO_CHAR(B_I1)||')';
    B_LENH:=B_LENH||'=(select c1'||TO_CHAR(B_I1)||',c2'||TO_CHAR(B_I1)||' from temp_1 where n30=temp_3.n30)';
    EXECUTE IMMEDIATE B_LENH;
    B_I1:=B_I1+1;      
END LOOP;    
INSERT INTO KET_QUA (C3,C4,C5,C6,C7,C8,C11,C12,C13,C14,C15,C16,C17,C18,C19,C21,C22,C23,C24,C25,C26,C27,C28,
    C29,N11,N12,N13,N14,N15,N16,N17,N18,N19,N30) SELECT C3,C4,C5,C6,C7,C8,C11,C12,C13,C14,C15,C16,C17,C18,C19,C21,C22,C23,C24,C25,
	C26,C27,C28,C29,SUM(NVL(N11,0)),SUM(NVL(N12,0)),SUM(NVL(N13,0)),SUM(NVL(N14,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),
    SUM(NVL(N18,0)),SUM(NVL(N19,0)),N30
	FROM TEMP_3 GROUP BY C3,C4,C5,C6,C7,C8,C11,C12,C13,C14,C15,C16,C17,C18,C19,C21,C22,C23,C24,C25,C26,C27,C28,C29,N30;
UPDATE KET_QUA SET C10='C?ng',N10=NVL(N11,0)+ NVL(N12,0)+ NVL(N13,0)+ NVL(N14,0)+ NVL(N15,0)+ NVL(N16,0)+ NVL(N17,0)+ NVL(N18,0)+ NVL(N19,0);
B_I1:=1;
WHILE B_I1 <=9 LOOP
    DELETE TEMP_1;B_LENH:='';
    B_LENH:='update temp_3 set c2'||TO_CHAR(B_I1)||'=(select ten from ht_ma_dvi where ma=c1'||TO_CHAR(B_I1)||')';
    EXECUTE IMMEDIATE B_LENH;
    B_I1:=B_I1+1;      
END LOOP;
commit;
OPEN CS_KQ FOR SELECT NVL(C7,' ') LOAI_PS,NVL(C8,' ') TEN_PS,NVL(N30,0) BANG,NVL(C3,' ') MA_TK,NVL(C4,' ') TEN_TK,NVL(C5,' ') MA_TKE,
    NVL(C6,' ') TEN_TKE,NVL(C10,' ') MA1 ,NVL(C11,' ') MA2,NVL(C12,' ') MA3,NVL(C13,' ') MA4,NVL(C14,' ') MA5,NVL(C15,' ') MA6,
    NVL(C16,' ') MA7,NVL(C17,' ') MA8,NVL(C18,' ') MA9,NVL(C19,' ') MA10, NVL(C20,' ') TEN1,NVL(C21,' ') TEN2,NVL(C22,' ') TEN3,
    NVL(C23,' ') TEN4,NVL(C24,' ') TEN5,NVL(C25,' ') TEN6, NVL(C26,' ') TEN7,NVL(C27,' ') TEN8,NVL(C28,' ') TEN9,NVL(C29,' ') TEN10,
    NVL(N10,0) COT1,NVL(N11,0) COT2,NVL(N12,0) COT3,NVL(N13,0) COT4,NVL(N14,0) COT5,NVL(N15,0) COT6,NVL(N16,0) COT7,NVL(N17,0) COT8,
    NVL(N18,0) COT9,NVL(N19,0)  COT10 FROM KET_QUA WHERE NVL(C7,' ')<>' ' AND NVL(N30,0)<>0
    ORDER BY N30,C7,C3,C10,C11,C12,C13,C14,C15,C16,C17,C18,C19;
EXCEPTION
  WHEN PROGRAM_ERROR THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
  WHEN OTHERS THEN RAISE;
END;
/

