DROP PROCEDURE BTBH_BKPHI_NHAN_MOI;

CREATE OR REPLACE PROCEDURE BTBH_BKPHI_NHAN_MOI
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI_BC VARCHAR2,B_MA_NT VARCHAR2,
    B_NGAYD_PS NUMBER,B_NGAYC_PS NUMBER,
    B_NGAYD_HD NUMBER,B_NGAYC_HD NUMBER,
    CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100); B_NOITE VARCHAR2(5); B_PT_LL NUMBER:=100; B_SO_ID_TA NUMBER:=0; B_PTHUC VARCHAR2(1); B_NV VARCHAR2(5);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
B_LOI:='loi:Loi tong hop bao cao:loi';
B_NOITE:=FTT_TRA_NOITE(B_MA_DVI);
DELETE TEMP_1; DELETE TEMP_2; DELETE TEMP_3; COMMIT;
INSERT INTO TEMP_2(C1,N1,N2,N3,C5,C3,N6,N7)
    SELECT MA_DVI_PS,SO_ID_PS,0 SO_ID_DT,SO_ID_TA_PS,MA_TA,ma_nt,NGAY_HT,SUM(TIEN) FROM TBH_XL_pbo
    WHERE (B_MA_DVI_BC IS NULL OR B_MA_DVI_BC=MA_DVI_PS)
        AND KIEU='V' AND LOAI='G' AND (B_MA_NT IS NULL OR ma_nt=B_MA_NT)
        AND NGAY_HT BETWEEN B_NGAYD_PS AND B_NGAYC_PS
        AND FBH_HD_NGAY_TAI(MA_DVI,SO_ID_PS) BETWEEN B_NGAYD_HD AND B_NGAYC_HD
    GROUP BY MA_DVI_PS,SO_ID_PS,SO_ID_TA_PS,MA_TA,ma_nt,NGAY_HT; --,SO_ID_DT
UPDATE TEMP_2 SET C6=(SELECT MIN(TEN) FROM BH_MA_LHNV_TAI WHERE MA_DVI=C1 AND MA=C5);
UPDATE TEMP_2 SET (c11,C12,C15,C13,C14)=(SELECT so_hd,ma_kh,ten,BCNAM_SO_NGAY_F(NGAY_HL),BCNAM_SO_NGAY_F(NGAY_kt) FROM BH_hd_goc WHERE MA_DVI=C1 AND SO_ID=N1 and rownum=1);
UPDATE TEMP_2 SET N8=(SELECT sum(tien) FROM bh_hd_goc_dk WHERE MA_DVI=C1 AND SO_ID=N1);
UPDATE TEMP_2 SET C15=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=C1 AND MA=C12);

COMMIT;
OPEN CS_KQ FOR
    SELECT C1 MA_DVI_PS,C5 MA_TA,C6 TEN_MA_TA,C11 SO_HD,C12 MA_KH,C15 TEN_KH,C13 NGAY_HL,C14 NGAY_KT, --,C16 DT_BH
        C3 MA_NT,N8 TIEN_BH,N7 PHI_TAI --N9 PHI_BH,N4 TL_TAI,N5 TIEN_TAI,
    FROM TEMP_2 ORDER BY c1;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BTBH_PRE_BOR_HANG_KH;

CREATE OR REPLACE PROCEDURE BTBH_PRE_BOR_HANG_KH
(
    B_MA_DVI VARCHAR2, B_NSD VARCHAR2, B_PAS VARCHAR2, B_DVI_X VARCHAR2,B_NV VARCHAR2,B_LHNV VARCHAR2,
    B_MA_DT VARCHAR2, B_DKLUT VARCHAR2, B_NGAYD NUMBER, B_NGAYC NUMBER, B_NGAYD_KY NUMBER, B_NGAYC_KY NUMBER, B_NGAYD_TT NUMBER, B_NGAYC_TT NUMBER, CS1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI NVARCHAR2(250); B_DVI VARCHAR2(10):='';
BEGIN
    DELETE TEMP_5;DELETE TEMP_1;COMMIT;
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

    IF B_DVI_X='00' THEN B_DVI:='';
    ELSE B_DVI:=B_DVI_X; END IF;

    INSERT INTO TEMP_5(N1,C1,C2,N2,C19) SELECT A.SO_ID_HD, A.MA_DVI_HD, A.NV, B.SO_ID_DT,C.NGAY_HL
        FROM TBH_CBI A, TBH_CBI_HD B, BH_HD_GOC C WHERE A.MA_DVI=B_MA_DVI AND A.MA_DVI=B.MA_DVI AND A.MA_DVI_HD=C.MA_DVI
            AND A.MA_DVI_HD=B.MA_DVI_HD AND A.SO_ID=B.SO_ID AND A.SO_ID_HD=B.SO_ID_HD AND A.SO_ID_HD=C.SO_ID
            AND (B_DVI IS NULL OR A.MA_DVI_HD=B_DVI) 
            --AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
            AND C.NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
            AND TTRANG='D' AND KIEU_XL='K' AND A.NV=B_NV;

--    DELETE TBH_GHEP_TL_TEMP;  DELETE TBH_GHEP_CXL_TL_TEMP;COMMIT;
--    FOR R_LP IN (SELECT DISTINCT N1,C1 FROM TEMP_5) LOOP
--        BC_BTBH_CXL_TL(R_LP.C1,R_LP.N1);
--    END LOOP;

    UPDATE TEMP_5 SET (C6,C11,N15,N16)=(SELECT MIN(LH_NV),MIN(TEN), SUM(TIEN), SUM(PHI) FROM BH_HANG_DK
        WHERE (B_DVI IS NULL OR MA_DVI=B_DVI) AND SO_ID=N1 AND MA_DVI=C1 AND BT<1000001 AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%')); --AND SO_ID_DT=N2 
    UPDATE TEMP_5 SET C15=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=C6);
--    UPDATE TEMP_5 SET (C10,C12, N17, C14, C16,C17, D1, D2)=(SELECT TEN_HANG,SO_HD, NGAY_HT, TEN, noi_di, noi_den, NGAY_HL, NGAY_KT  FROM BH_HANG_DS
--        WHERE (B_DVI IS NULL OR MA_DVI=B_DVI) AND MA_DVI=C1 AND SO_ID=N1);
    
--    UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=TEMP_5.N1 AND SO_ID_DT=TEMP_5.N2
--        AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
    insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
    UPDATE TEMP_5 a SET (N12,N13,n10)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);
--    UPDATE TEMP_5 SET N10=NVL(N16,0)*NVL(N12,0)/100;
    update temp_5 set (c12, n17, c14, c16,c17, d1, d2)=(Select so_hd, ngay_ht, ten, cang_di, cang_den, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT)  from BH_HANG where ma_dvi=c4 and so_id=FBH_HD_SO_ID_BS(c4,n3,n29));
    update temp_5 set (N18,N19) = (select max(ngay),max(ngay_tt) from bh_hd_goc_ttpt where so_id=n1 and ma_dvi=c1 and pt<>'C');
    delete temp_5 where n18 < B_NGAYD_KY and n18 >B_NGAYC_KY ;
    delete temp_5 where n19 < B_NGAYD_TT and n18 >B_NGAYC_TT ;
    
    OPEN CS1 FOR
    SELECT C1 MA_DVI_PS, C2 NV, C3 MA_NT, C4 MA_DVI_HD, N3 SO_ID_HD,
    N4 SO_ID_DT, C6 LH_NV,C15 TEN_LHNV,  N17 NGAY_HD, C12 SO_HD, C16 DI_TU, C17 DI_DEN, C14 TEN_KHACH, C10 TEN_HANGHOA, C11 TEN_PHUONGTIEN,
    N15 TIEN_BH, N16 PHI_BH,C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,N10 PHI_SHARE, N11 HHONG_SHARE,
    TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT,n18 NGAY_KY_TT,n19 NGAY_TT
    FROM TEMP_5 ORDER BY N2,N17;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BTBH_PRE_BOR_NG_KH;

CREATE OR REPLACE PROCEDURE BTBH_PRE_BOR_NG_KH
(
    B_MA_DVI VARCHAR2, B_NSD VARCHAR2, B_PAS VARCHAR2, B_DVI_X VARCHAR2,B_NV VARCHAR2,B_LHNV VARCHAR2,
    B_MA_DT VARCHAR2, B_DKLUT VARCHAR2, B_NGAYD NUMBER, B_NGAYC NUMBER, B_NGAYD_KY NUMBER, B_NGAYC_KY NUMBER, B_NGAYD_TT NUMBER, B_NGAYC_TT NUMBER, CS1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI NVARCHAR2(250);B_DVI VARCHAR2(10):='';
BEGIN
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    DELETE TEMP_5; DELETE TBH_GHEP_TL_TEMP; DELETE TBH_GHEP_CXL_TL_TEMP;COMMIT;

    IF B_DVI_X='00' THEN B_DVI:='';
    ELSE B_DVI:=B_DVI_X; END IF;

    INSERT INTO TEMP_5(N1,C1,C2,N2) SELECT A.SO_ID_HD, A.MA_DVI_HD, A.NV, B.SO_ID_DT
        FROM TBH_CBI A, TBH_CBI_HD B, BH_HD_GOC C WHERE A.MA_DVI=B_MA_DVI AND A.MA_DVI=B.MA_DVI AND A.MA_DVI_HD=C.MA_DVI
            AND A.MA_DVI_HD=B.MA_DVI_HD AND A.SO_ID=B.SO_ID AND A.SO_ID_HD=B.SO_ID_HD AND A.SO_ID_HD=C.SO_ID
            AND (B_DVI IS NULL OR A.MA_DVI_HD=B_DVI) 
            --AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
            AND NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
            AND TTRANG='D' AND KIEU_XL='K' AND A.NV=B_NV;
--return;
--    FOR R_LP IN (SELECT DISTINCT N1,C1 FROM TEMP_5) LOOP
--        BC_BTBH_CXL_TL(R_LP.C1,R_LP.N1);
--    END LOOP;

    UPDATE TEMP_5 SET (C12, N17, C20)=(SELECT SO_HD, NGAY_HT,NV FROM BH_HD_GOC WHERE SO_ID=N1 AND MA_DVI=C1);
    UPDATE TEMP_5 SET (C10, C11,  D1, D2)=(SELECT TEN,GCN, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT)
        FROM BH_NG_DS WHERE SO_ID=N1 AND SO_ID_DT=N2 AND MA_DVI=C1);

    
   
    UPDATE TEMP_5 SET (C6,N15, N16)=(SELECT LH_NV,TIEN, PHI FROM BH_NG_DK
        WHERE MA_DVI=C1 AND SO_ID=N1 AND SO_ID_DT=N2 AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%')) ;

        
    
--    UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=N1 AND SO_ID_DT=N2
--        AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
--    UPDATE TEMP_5 SET N14=NVL(N16,0)*NVL(N12,0)/100;
    insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
    UPDATE TEMP_5 a SET (N12,N13,N14)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);
    
--    update temp_5 set (N18,N19) = (select max(ngay),max(ngay_tt) from bh_hd_goc_ttpt where so_id=n1 and ma_dvi=c1 and pt<>'C');
--    delete temp_5 where n18 < B_NGAYD_KY and n18 >B_NGAYC_KY ;
--    delete temp_5 where n19 < B_NGAYD_TT and n18 >B_NGAYC_TT ;
    
    OPEN CS1 FOR
       SELECT C1 MA_DVI_PS, C2 NV, C3 NT_TIEN , C4 MA_DVI_HD, N3 SO_ID_HD,
           N4 SO_ID_DT, C6 LHNV,  N17 NGAY_HD, C12 SO_HD, C10 TEN_KH, C11 GCN,
           TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT,
           N15 TIEN_BH, N16 PHI_BH,C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,N14 PHI_SHARE
           FROM TEMP_5 ORDER BY N17;
    COMMIT;
   EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BTBH_PRE_BOR_PHH_KH;

CREATE OR REPLACE PROCEDURE BTBH_PRE_BOR_PHH_KH
(
    B_MA_DVI VARCHAR2, B_NSD VARCHAR2, B_PAS VARCHAR2, B_DVI_X VARCHAR2,B_NV VARCHAR2,B_LHNV VARCHAR2,
    B_MA_DT VARCHAR2, B_DKLUT VARCHAR2, B_NGAYD NUMBER, B_NGAYC NUMBER, B_NGAYD_KY NUMBER, B_NGAYC_KY NUMBER, B_NGAYD_TT NUMBER, B_NGAYC_TT NUMBER, CS1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI NVARCHAR2(250); B_DVI VARCHAR2(10):='';
BEGIN
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    
    
    DELETE TEMP_5;DELETE TBH_GHEP_TL_TEMP;  DELETE TBH_GHEP_CXL_TL_TEMP;COMMIT;
IF B_DVI_X='00' THEN B_DVI:='';
    ELSE B_DVI:=B_DVI_X; END IF;

    INSERT INTO TEMP_5(N1,C1,C2,N2) SELECT A.SO_ID_HD, A.MA_DVI_HD, A.NV, B.SO_ID_DT
        FROM TBH_CBI A, TBH_CBI_HD B, BH_HD_GOC C WHERE A.MA_DVI=B_MA_DVI AND A.MA_DVI=B.MA_DVI AND A.MA_DVI_HD=C.MA_DVI
            AND A.MA_DVI_HD=B.MA_DVI_HD AND A.SO_ID=B.SO_ID AND A.SO_ID_HD=B.SO_ID_HD AND A.SO_ID_HD=C.SO_ID
            AND (B_DVI IS NULL OR A.MA_DVI_HD=B_DVI) 
            --AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
            AND NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
            AND TTRANG='D' AND KIEU_XL='K' AND A.NV=B_NV;

--    FOR R_LP IN (SELECT DISTINCT N1,C1 FROM TEMP_5) LOOP
--        BC_BTBH_CXL_TL(R_LP.C1,R_LP.N1);
--    END LOOP;

    IF B_NV='PHH' THEN
        UPDATE TEMP_5 SET (C13,C10,C11,c18)=(SELECT MA_DT, DVI, DDIEM,DK_LUT FROM BH_PHH_DVI WHERE SO_ID=N1 AND SO_ID_DT=N2 AND MA_DVI=C1);
        UPDATE TEMP_5 SET (C12,N17,C14, D1, D2)=(SELECT SO_HD, NGAY_HT, TEN, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT) FROM BH_HD_GOC WHERE MA_DVI=C1 AND SO_ID=N1);
        UPDATE TEMP_5 SET (C6,N15,N16)=(SELECT MAX(LH_NV),SUM(TIEN),SUM(PHI) FROM BH_PHH_DK WHERE (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') AND SO_ID=N1 AND SO_ID_DT=N2);
        
--        UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=TEMP_5.N1 AND SO_ID_DT=TEMP_5.N2
--            AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
--        UPDATE TEMP_5 SET N14=NVL(N16,0)*NVL(N12,0)/100;
        insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
        UPDATE TEMP_5 a SET (N12,N13,N14)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);

        UPDATE TEMP_5 SET C17=C6;
        UPDATE TEMP_5 SET C15=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI='000' AND MA=C17);
        IF B_MA_DT IS NOT NULL THEN
            DELETE TEMP_5 WHERE C13 NOT LIKE B_MA_DT||'%';
        END IF;
        IF B_DKLUT='K' THEN
            DELETE TEMP_5 WHERE c18='C';
            UPDATE TEMP_5 SET N10=ROUND(N10/11), N14=ROUND(N14/11),  N20=ROUND(N20/11);
        ELSIF B_DKLUT='C' THEN
            DELETE TEMP_5 WHERE c18='K';
            UPDATE TEMP_5 SET N10=ROUND((N10*0.1)/1.1), N14=ROUND((N14*0.1)/1.1), N20=ROUND((N20*0.1)/1.1);
        END IF;
        OPEN CS1 FOR
            SELECT C1 MA_DVI_PS, C2 NV, C3 NT_TIEN, C4 MA_DVI_HD, N3 SO_ID_HD,
               N4 SO_ID_DT, C17 LH_NV,C15 TEN_LHNV,  N17 NGAY_HD, C12 SO_HD, C14 TEN_KHACH,
               TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT, C10 TEN_RUIRO, C11 TEN_DIADIEM,
               N15 TIEN_BH, N16 PHI_BH, C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,
               N14 PHI_SHARE--, N10 PHI_TK, N20 PHI_LK, N11 HHONG_SHARE--, N25 BH_TRONGKY, N26 BH_LUYKE, N27 TTHU_TRONGKY, N28 TTHU_LUYKE,               N29 TY_LE_DONG
               FROM TEMP_6 ORDER BY N17;
    ELSIF B_NV='PKT' THEN
        UPDATE TEMP_5 SET (C10,C11,c18)=(SELECT DVI, DDIEM,DK_LUT FROM BH_PKT_DVI WHERE SO_ID=N1 AND SO_ID_DT=N2 AND MA_DVI=C1);
        UPDATE TEMP_5 SET (C12,N17,C14,D1,D2)=(SELECT SO_HD, NGAY_HT, TEN, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT) FROM BH_HD_GOC WHERE MA_DVI=C4 AND SO_ID=N1);
        UPDATE TEMP_5 SET (C6,N15,N16)=(SELECT MAX(LH_NV),SUM(TIEN),SUM(PHI) FROM BH_PKT_DK --MAX(MA_DT), C13,
            WHERE (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') AND SO_ID=N1 AND SO_ID_DT=N2);
        UPDATE TEMP_5 SET C15=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI='00' AND MA=C6);
        
--        UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=TEMP_5.N1 AND SO_ID_DT=TEMP_5.N2
--            AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
--        UPDATE TEMP_5 SET N14=NVL(N16,0)*NVL(N12,0)/100;
        insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
        UPDATE TEMP_5 a SET (N12,N13,N14)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);

        IF B_MA_DT IS NOT NULL THEN
            DELETE TEMP_5 WHERE C13 NOT LIKE B_MA_DT||'%';
        END IF;
        IF B_MA_DT IS NOT NULL THEN
            DELETE TEMP_5 WHERE C13 NOT LIKE B_MA_DT||'%';
        END IF;
        IF B_DKLUT='K' THEN
            DELETE TEMP_5 WHERE c18='C';
        ELSIF B_DKLUT='C' THEN
            DELETE TEMP_5 WHERE c18='K';
        END IF;
        OPEN CS1 FOR
        SELECT C1 MA_DVI_PS, C2 NV, C3 NT_TIEN, C4 MA_DVI_HD, N3 SO_ID_HD,
           N4 SO_ID_DT, C6 LH_NV,C15 TEN_LHNV,  N17 NGAY_HD, C12 SO_HD, C14 TEN_KHACH, TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT, C10 TEN_RUIRO, C11 TEN_DIADIEM,
           N15 TIEN_BH, N16 PHI_BH,C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,N14 PHI_SHARE--, N10 PHI_TK, N20 PHI_LK, N11 HHONG_SHARE
           --,N25 BH_TRONGKY, N26 BH_LUYKE, N27 TTHU_TRONGKY, N28 TTHU_LUYKE,  N29 TY_LE_DONG
           FROM TEMP_5 ORDER BY N17;
    ELSIF B_NV='PTN' THEN
        UPDATE TEMP_5 SET (C10, C11)=(SELECT TEN, DCHI FROM bh_ptn WHERE SO_ID=N1 AND MA_DVI=C1); -- AND SO_ID_DT=N2
        UPDATE TEMP_5 SET (C12, N17, C14, D1, D2)=(SELECT SO_HD, NGAY_HT,TEN, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT) FROM BH_HD_GOC WHERE MA_DVI=C1 AND SO_ID=N2);
        UPDATE TEMP_5 SET (C6,N15,N16)=(SELECT LH_NV,TIEN,PHI FROM bh_ptn_DK
            WHERE (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') AND SO_ID=N1 );--AND SO_ID_DT=N2);
        UPDATE TEMP_5 SET C15=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI='00' AND MA=C6);
        
--        UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=TEMP_5.N1 AND SO_ID_DT=TEMP_5.N2
--            AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
--        UPDATE TEMP_5 SET N14=NVL(N16,0)*NVL(N12,0)/100;
        insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
        UPDATE TEMP_5 a SET (N12,N13,N14)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);
        
--        update temp_5 set (N18,N19) = (select max(ngay),max(ngay_tt) from bh_hd_goc_ttpt where so_id=n1 and ma_dvi=c1 and pt<>'C');
--        delete temp_5 where n18 < B_NGAYD_KY and n18 >B_NGAYC_KY ;
--        delete temp_5 where n19 < B_NGAYD_TT and n18 >B_NGAYC_TT ;
    
        OPEN CS1 FOR
        SELECT C1 MA_DVI_PS, C2 NV, C3 NT_TIEN, C4 MA_DVI_HD, N3 SO_ID_HD,
           N4 SO_ID_DT, C6 LH_NV,C15 TEN_LHNV,  N17 NGAY_HD, C12 SO_HD, C14 TEN_KHACH, TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT, C10 TEN_RUIRO, C11 TEN_DIADIEM,
           N15 TIEN_BH, N16 PHI_BH,C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,N14 PHI_SHARE--, N10 PHI_TK, N20 PHI_LK,N11 HHONG_SHARE
           --,N25 BH_TRONGKY, N26 BH_LUYKE, N27 TTHU_TRONGKY, N28 TTHU_LUYKE, N29 TY_LE_DONG
           FROM TEMP_5 ORDER BY N17;
    END IF;

EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE BTBH_PRE_BOR_TAU_KH;

CREATE OR REPLACE PROCEDURE BTBH_PRE_BOR_TAU_KH 
(
   B_MA_DVI VARCHAR2, B_NSD VARCHAR2, B_PAS VARCHAR2, B_DVI_X VARCHAR2,B_NV VARCHAR2,B_LHNV VARCHAR2,
    B_MA_DT VARCHAR2, B_DKLUT VARCHAR2, B_NGAYD NUMBER, B_NGAYC NUMBER, B_NGAYD_KY NUMBER, B_NGAYC_KY NUMBER, B_NGAYD_TT NUMBER, B_NGAYC_TT NUMBER, CS1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI NVARCHAR2(250); B_DVI VARCHAR2(10):=''; 
BEGIN
    DELETE TEMP_5; DELETE TBH_GHEP_TL_TEMP;  DELETE TBH_GHEP_CXL_TL_TEMP;COMMIT;
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    IF B_DVI_X='00' THEN B_DVI:='';
    ELSE B_DVI:=B_DVI_X; END IF;
    
    INSERT INTO TEMP_5(N1,C1,C2,N2) SELECT A.SO_ID_HD, A.MA_DVI_HD, A.NV, B.SO_ID_DT
        FROM TBH_CBI A, TBH_CBI_HD B, BH_HD_GOC C WHERE A.MA_DVI=B_MA_DVI AND A.MA_DVI=B.MA_DVI AND A.MA_DVI_HD=C.MA_DVI 
            AND A.MA_DVI_HD=B.MA_DVI_HD AND A.SO_ID=B.SO_ID AND A.SO_ID_HD=B.SO_ID_HD AND A.SO_ID_HD=C.SO_ID
            AND (B_DVI IS NULL OR A.MA_DVI_HD=B_DVI) 
            --AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
            AND NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
            AND TTRANG='D' AND KIEU_XL='K' AND A.NV=B_NV;
--            
--    FOR R_LP IN (SELECT DISTINCT N1,C1 FROM TEMP_5) LOOP
--        BC_BTBH_CXL_TL(R_LP.C1,R_LP.N1);
--    END LOOP;
    UPDATE TEMP_5 SET (C13, C10, D1, D2)=(SELECT GCN, TEN_TAU, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT) FROM BH_TAU_DS
                                                WHERE SO_ID=N3 AND SO_ID_DT=N4 AND MA_DVI=C4) ;
    UPDATE TEMP_5 SET (C6,N15,N16)=(SELECT MAX(LH_NV),SUM(TIEN),SUM(PHI) FROM BH_TAU_DK 
        WHERE SO_ID=N1 AND SO_ID_DT=N2 AND MA_DVI=C1 AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%'));
--    UPDATE TEMP_5 SET (C6,N15,N16)=(SELECT MAX(LH_NV),SUM(TIEN),SUM(PHI_DT) FROM BH_TAULGCN_DK 
--        WHERE SO_ID=N1 AND MA_DVI=C1 AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%')) WHERE C2='TAUL';
--    UPDATE TEMP_5 SET (C12, C13, C10, N17,C14, D1, D2)=(SELECT SO_HD, SO_HD, TEN_TAU, NGAY_HT,TEN, NGAY_HL, NGAY_KT FROM BH_TAULGCN 
--                                                WHERE SO_ID=N3 AND MA_DVI=C4) WHERE C2='TAUL';
--    UPDATE TEMP_5 SET (C12, N17, C14)=(SELECT SO_HD, NGAY_HT, TEN FROM BH_HD_GOC WHERE MA_DVI=C1 AND SO_ID=N1) WHERE C2='TAU';
    
    
--    UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=TEMP_5.N1 AND SO_ID_DT=TEMP_5.N2 
--        AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
--    UPDATE TEMP_5 SET N10=NVL(N16,0)*NVL(N12,0)/100;   
    insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
        UPDATE TEMP_5 a SET (N12,N13,N14)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);   
    
    UPDATE TEMP_5 SET C15=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI='000' AND MA=C6);
    IF B_MA_DT IS NOT NULL THEN
        DELETE TEMP_5 WHERE C13 NOT LIKE B_MA_DT||'%';
    END IF;
    
    update temp_5 set (N18,N19) = (select max(ngay),max(ngay_tt) from bh_hd_goc_ttpt where so_id=n1 and ma_dvi=c1 and pt<>'C');
    delete temp_5 where n18 < B_NGAYD_KY and n18 >B_NGAYC_KY ;
    delete temp_5 where n19 < B_NGAYD_TT and n18 >B_NGAYC_TT ;
    
    OPEN CS1 FOR 
        SELECT C1 MA_DVI_PS, C2 NV, C3 MA_NT, C4 MA_DVI_HD, N3 SO_ID_HD, 
           N4 SO_ID_DT, C6 LH_NV,C15 TEN_LHNV,  N17 NGAY_HD, C12 SO_HD, C13 SO_GCN, C10 TEN_TAU, C14 TEN_KHACH, 
           TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT,
           N15 TIEN_BH, N16 PHI_BH,C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,N10 PHI_SHARE--, N11 HHONG_SHARE
           FROM TEMP_5 ORDER BY N17;
    
   EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);    
END;
/
DROP PROCEDURE BTBH_PRE_BOR_XE_KH;

CREATE OR REPLACE PROCEDURE BTBH_PRE_BOR_XE_KH
(
    B_MA_DVI VARCHAR2, B_NSD VARCHAR2, B_PAS VARCHAR2, B_DVI_X VARCHAR2,B_NV VARCHAR2,B_LHNV VARCHAR2,
    B_MA_DT VARCHAR2, B_DKLUT VARCHAR2, B_NGAYD NUMBER, B_NGAYC NUMBER, B_NGAYD_KY NUMBER, B_NGAYC_KY NUMBER, B_NGAYD_TT NUMBER, B_NGAYC_TT NUMBER, CS1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI NVARCHAR2(250);B_DVI VARCHAR2(10):='';
BEGIN
    B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
    IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
    DELETE TEMP_5; DELETE TBH_GHEP_TL_TEMP; DELETE TBH_GHEP_CXL_TL_TEMP;COMMIT;

    IF B_DVI_X='00' THEN B_DVI:='';
    ELSE B_DVI:=B_DVI_X; END IF;

    INSERT INTO TEMP_5(N1,C1,C2,N2) SELECT A.SO_ID_HD, A.MA_DVI_HD, A.NV, B.SO_ID_DT
        FROM TBH_CBI A, TBH_CBI_HD B, BH_HD_GOC C WHERE A.MA_DVI=B_MA_DVI AND A.MA_DVI=B.MA_DVI AND A.MA_DVI_HD=C.MA_DVI
            AND A.MA_DVI_HD=B.MA_DVI_HD AND A.SO_ID=B.SO_ID AND A.SO_ID_HD=B.SO_ID_HD AND A.SO_ID_HD=C.SO_ID
            AND (B_DVI IS NULL OR A.MA_DVI_HD=B_DVI) 
            --AND C.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
            AND C.NGAY_HL BETWEEN B_NGAYD AND B_NGAYC
            AND TTRANG='D' AND KIEU_XL='K' AND A.NV=B_NV;
--return;
--    FOR R_LP IN (SELECT DISTINCT N1,C1 FROM TEMP_5) LOOP
--        BC_BTBH_CXL_TL(R_LP.C1,R_LP.N1);
--    END LOOP;

    UPDATE TEMP_5 SET (C12, N17, C20)=(SELECT SO_HD, NGAY_HT,NV FROM BH_HD_GOC WHERE SO_ID=N1 AND MA_DVI=C1);
    UPDATE TEMP_5 SET (C10, C11, C14, D1, D2, C21)=(SELECT 'Bien xe: '||BIEN_XE||NVL2(SO_KHUNG,'',' - ')||SO_KHUNG||NVL2(SO_MAY,'',' - ')||SO_MAY,GCN, TENC, PKH_SO_CNG_DATE(NGAY_HL), PKH_SO_CNG_DATE(NGAY_KT), HIEU
        FROM BH_XE_DS WHERE SO_ID=N1 AND SO_ID_DT=N2 AND MA_DVI=C1);
--    UPDATE TEMP_5 SET (C10, C11, C14, D1, D2, C21)=(SELECT 'Bien xe: '||BIEN_XE||NVL2(SO_KHUNG,'',' - ')||SO_KHUNG||NVL2(SO_MAY,'',' - ')||SO_MAY,SO_HD,TEN, NGAY_HL, NGAY_KT, HIEU_XE
--        FROM BH_XELGCN WHERE SO_ID=N1 AND MA_DVI=C1) WHERE C20='XEL';
    
   
    UPDATE TEMP_5 SET (C6,N15, N16)=(SELECT LH_NV,TIEN, PHI FROM BH_XE_DK
        WHERE MA_DVI=C1 AND SO_ID=N1 AND SO_ID_DT=N2 AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%'));
--    UPDATE TEMP_5 SET (C6,N15, N16)=(SELECT LH_NV,MAX(TIEN),MAX(PHI_DT) FROM BH_XELGCN_DK
--        WHERE MA_DVI=C1 AND SO_ID=N2 AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') GROUP by ma_dvi,so_id,lh_nv) WHERE C20='XEL' ;
        
    
--    UPDATE TEMP_5 SET (N12,N13)=(SELECT SUM(PT),SUM(TIEN) FROM TBH_GHEP_CXL_TL_TEMP WHERE SO_ID_HD=N1 AND SO_ID_DT=N2
--        AND MA_TA=FBH_MA_LHNV_TAI(C1,C6));
--    UPDATE TEMP_5 SET N14=NVL(N16,0)*NVL(N12,0)/100;
    insert into temp_1(n1,n2,c1,n3,n4,n5) select so_id_hd,so_id_dt,ma_ta,sum(pt),sum(tien),sum(phi) from V_TA_CD group by so_id_hd,so_id_dt,ma_ta;
    UPDATE TEMP_5 a SET (N12,N13,N14)=(SELECT sum(n3),sum(n4),sum(n5) from temp_1 b where a.N1=b.n1 and a.n2=b.n2 and FBH_MA_LHNV_TAI(C6)=b.c1);   
    
--    update temp_5 set (N18,N19) = (select max(ngay),max(ngay_tt) from bh_hd_goc_ttpt where so_id=n1 and ma_dvi=c1 and pt<>'C');
--    delete temp_5 where n18 < B_NGAYD_KY and n18 >B_NGAYC_KY ;
--    delete temp_5 where n19 < B_NGAYD_TT and n18 >B_NGAYC_TT ;
    
    OPEN CS1 FOR
       SELECT C1 MA_DVI_PS, C2 NV, C3 NT_TIEN , C4 MA_DVI_HD, N3 SO_ID_HD,
           N4 SO_ID_DT, C6 LHNV,  N17 NGAY_HD, C12 SO_HD, C14 TEN_KHACH, C10 BIEN_XE, C11 GCN,
           TO_CHAR(D1,'dd/MM/yyyy') NGAY_HL, TO_CHAR(D2,'dd/MM/yyyy') NGAY_KT,
           N15 TIEN_BH, N16 PHI_BH,C7 NT_TIEN_TAI, ROUND(N12,6) TY_LE_SHARE, N13 TIEN_SHARE,N14 PHI_SHARE
           --N11 HHONG_SHARE, C21 HIEU_XE,n18 NGAY_KY_TT,n19 NGAY_TT
           FROM TEMP_5 ORDER BY N17;
    COMMIT;
   --EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE cc_bkt_doncap;

CREATE OR REPLACE PROCEDURE cc_bkt_doncap (b_loi out varchar2)
AS
    b_dau char(1);b_i1 number;b_i2 number;b_i3 number;b_n1 number;
    b_n2 number;b_n3 number;b_n4 number;b_n5 number;
    b_n6 number;b_n7 number;b_n8 number;b_n9 number;
    b_n10 number;b_n11 number;b_n12 number;b_n13 number;
    b_n14 number;b_n15 number;b_n16 number;b_n17 number;b_n18 number;
    b_n19 number;b_n20 number;b_n21 number;b_n22 number;b_n23 number;
    b_n24 number;b_n25 number;b_n26 number;b_n27 number;b_n28 number;
    b_c1 char(1);b_hs number;b_ma varchar2(10);b_ma_ct varchar2(10);
    b_tong number;con_tinh boolean;b_dk number;b_tt char(1);
    b_ktra number;b_ktra_lap number;b_ktra_con_tinh number;
/*-- Don cap trong bao cao,
    - ket_qua(c1,c2,n1-n29,c3,c4,n30,c5,c10)->ma,ten,cot1-cot28,xep,ma_ct,dau,hs,ht,c10->'1','0'
      duoc xap xep nhu trong phan nhap dinh nghia bao cao
    - Cac ma co dinh nghia so lieu da duoc tinh c10='0'
    - Cac ma chua duoc tinh c10='1'
--*/
begin
--select count(*) into b_ktra_con_tinh from ket_qua where c10='1';
con_tinh:=true;
select count(*) into b_tong from ket_qua;
while con_tinh loop
    b_dk:=1;
    b_ktra:=0;
    select count(*) into b_ktra_con_tinh from ket_qua where c10='1';
    while b_dk<=b_tong loop
        select c1,c10 into b_ma,b_tt from ket_qua where n29=b_dk;
        b_i1:=0;
        -- Them bien de kiem tra so luong lap
        b_ktra:=b_ktra+1;
        if b_ktra>100 then
            b_loi:='loi:Khai bao trung ma: '||trim(b_ma)||':loi';
            -- raise PROGRAM_ERROR;
            return;
        end if;
        ----
        if b_tt ='0' then       --- Da tinh
            b_dk:=b_dk+1;
        else                    --- Chua tinh
            select c1,instr(c2,'/') into b_ma,b_i2 from ket_qua where n29=b_dk;
            b_i1:=b_dk+1;           --- dich xuong ma con
            if b_i1<=b_tong then
            select min(c3) into b_ma_ct from ket_qua where n29=b_i1;
            --BCNam tam bo kiem tra ma_ct
            --if b_ma_ct is null then
            --    b_loi:='loi:Khai bao sai ma tong: '||b_i1||':loi';
            --    return;
            --end if;
            select c3,instr(c2,'/') into b_ma_ct,b_i3 from ket_qua where n29=b_i1;
            else exit;end if;
            b_ktra_lap:=1;
            while b_i3>b_i2 loop
                select c10,' ' into b_tt,b_c1 from ket_qua where n29=b_i1;
                if b_tt='1'then b_c1:='T';exit; end if;
                if b_ma_ct=b_ma then
                    select c4,n30 into b_dau,b_hs from ket_qua where n29=b_i1;
                    if b_dau='+' then
                        select n1*b_hs,n2*b_hs,n3*b_hs,n4*b_hs,n5*b_hs,n6*b_hs,n7*b_hs,n8*b_hs,n9*b_hs,
                                n10*b_hs,n11*b_hs,n12*b_hs,n13*b_hs,n14*b_hs,n15*b_hs,n16*b_hs,
                                n17*b_hs,n18*b_hs,n19*b_hs,n20*b_hs,n21*b_hs,n22*b_hs,n23*b_hs,
                                n24*b_hs,n25*b_hs,n26*b_hs,n27*b_hs,n28*b_hs
                            into b_n1,b_n2,b_n3,b_n4,b_n5,b_n6,b_n7,b_n8,b_n9,b_n10,b_n11,
                                b_n12,b_n13,b_n14,b_n15,b_n16,b_n17,b_n18,b_n19,b_n20,b_n21,
                                b_n22,b_n23,b_n24,b_n25,b_n26,b_n27,b_n28
                            from ket_qua where n29=b_i1;
                    elsif b_dau='-' then
                        select -n1*b_hs,-n2*b_hs,-n3*b_hs,-n4*b_hs,-n5*b_hs,-n6*b_hs,-n7*b_hs,-n8*b_hs,
                                -n9*b_hs,-n10*b_hs,-n11*b_hs,-n12*b_hs,-n13*b_hs,-n14*b_hs,-n15*b_hs,
                                -n16*b_hs,-n17*b_hs,-n18*b_hs,-n19*b_hs,-n20*b_hs,-n21*b_hs,-n22*b_hs,
                                -n23*b_hs,-n24*b_hs,-n25*b_hs,-n26*b_hs,-n27*b_hs,-n28*b_hs
                            into b_n1,b_n2,b_n3,b_n4,b_n5,b_n6,b_n7,b_n8,b_n9,b_n10,b_n11,
                                  b_n12,b_n13,b_n14,b_n15,b_n16,b_n17,b_n18,b_n19,b_n20,b_n21,
                                b_n22,b_n23,b_n24,b_n25,b_n26,b_n27,b_n28
                        from ket_qua where n29=b_i1;
                    else
                        b_n1:=0;b_n2:=0;b_n3:=0;b_n4:=0;b_n5:=0;b_n6:=0;b_n7:=0;b_n8:=0;b_n9:=0;
                        b_n10:=0;b_n11:=0; b_n12:=0;b_n13:=0;b_n14:=0;b_n15:=0;b_n16:=0;b_n17:=0;
                        b_n18:=0;b_n19:=0;b_n20:=0;b_n21:=0;b_n22:=0;b_n23:=0;b_n24:=0;b_n25:=0;
                        b_n26:=0;b_n27:=0;b_n28:=0;

                    end if;
                    update ket_qua set n1=n1+b_n1,n2=n2+b_n2,n3=n3+b_n3,n4=n4+b_n4,n5=n5+b_n5,n6=n6+b_n6,
                        n7=n7+b_n7,n8=n8+b_n8,n9=n9+b_n9,n10=n10+b_n10,n11=n11+b_n11,n12=n12+b_n12,
                        n13=n13+b_n13,n14=n14+b_n14,n15=n15+b_n15,n16=n16+b_n16,n17=n17+b_n17,n18=n18+b_n18,
                        n19=n19+b_n19,n20=n20+b_n20,n21=n21+b_n21,n22=n22+b_n22,n23=n23+b_n23,
                        n24=n24+b_n24,n25=n25+b_n25,n26=n26+b_n26,n27=n27+b_n27,n28=n28+b_n28
                        where n29 = b_dk;
                end if;
                b_i1:=b_i1+1;
                if b_i1<= b_tong then select c3,instr(c2,'/') into b_ma_ct,b_i3 from ket_qua where n29=b_i1;
                else exit;end if;
                b_ktra_lap:=b_ktra_lap+1;
                if b_ktra_lap>100 then
                    b_loi:='loi:Khai bao trung ma: '||trim(b_ma)||' ma chi tiet '||b_ma_ct||':loi';
                    --raise PROGRAM_ERROR;
                    return;
                end if;
            end loop;
            if b_c1 <>'T' then
                update ket_qua set c10='0' where n29=b_dk;
                update ket_qua set (n1,n2,n3,n4,n5,n6,n7,n8,n9,n10,n11,n12,n13,n14,n15,n16,n17,n18,
                    n19,n20,n21,n22,n23,n24,n25,n26,n27,n28,c10)=
                    (select n1,n2,n3,n4,n5,n6,n7,n8,n9,n10,n11,n12,n13,n14,n15,n16,n17,n18,
                        n19,n20,n21,n22,n23,n24,n25,n26,n27,n28,c10
                        from ket_qua a where a.n29 = b_dk)
                    where c1=b_ma and n29>b_dk;
            else
                update ket_qua set n1=0,n2=0,n3=0,n4=0,n5=0,n6=0,n7=0,n8=0,n9=0,
                    n10=0,n11=0,n12=0,n13=0,n14=0,n15=0,n16=0,n17=0,n18=0,
                    n19=0,n20=0,n21=0,n22=0,n23=0,n24=0,n25=0,n26=0,n27=0,
                    n28=0 where n29=b_dk;
            end if;
            b_dk:=b_i1;
        end if;
    end loop;
    select count(*) into b_i1 from ket_qua where c10='1';
    if b_i1>0 then con_tinh:=true;else con_tinh:=false;end if;
    if con_tinh and b_i1=b_ktra_con_tinh then
        b_loi:='loi:Khai trung bao cao - lien he voi CNTT de duoc ho tro:loi'; return;
    end if;
end loop;
end;
/

DROP PROCEDURE DQD_BC_BH_CNKH_KH_MD;

CREATE OR REPLACE PROCEDURE DQD_BC_BH_CNKH_KH_MD
     (b_ma_dvi varchar2,b_ma_kh varchar2,b_phong varchar2,
    b_ngayd number,b_ngayc number)
AS
Begin
-- Bao cao cong no khach hang - module chi tiet

/*************************
OUTPUT: temp_1
c1 ma_dvi, c2 ma_kh, c3 nd, n1 ps_no, n2 ps_co, n3 ngay_ht
**************************/
--Sua them tien chenh lech ty gia khi thanh toan
--delete temp_1;commit;
execute immediate 'truncate table temp_1';execute immediate 'truncate table temp_s_1';
/* phat sinh no bao gom ca mon huy */
execute immediate 'truncate table temp_bc_ts';
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
--insert into temp_s_1(c1,c2) select ma_dvi,so_id_tt from bh_hd_goc_ttct where pt = 'M'; --voucher 
insert into temp_1(c1,c2,c3,n3,n1) select  ma_dvi,ma_kh,so_hd,ngay_tt,sum(phi)
   from 
   (
    select a.ma_dvi,a.ma_kh,a.so_hd,b.ngay_tt,b.phi_dt_qd+b.thue_qd phi from bh_hd_goc a, v_bh_hd_goc_ttpt_cn b
    where
    a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
--    and (a.ma_dvi,b.so_id_tt) not in (select c1,c2 from temp_s_1) --bo voucher 
    and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
    and b.phi>0
    and b.ngay_tt between b_ngayd and b_ngayc--nga sua lai lay theo ngay xem bao cao
    and (b_ma_kh is null or a.ma_kh=b_ma_kh) and (b_phong is null or a.phong=b_phong)
    )
    group by ma_dvi,ma_kh,so_hd,ngay_tt;
--cho nay tru di voucher(phai xu ly rieng vi co nhung voucher ko phai toan bo)
insert into temp_1(c1,c2,c3,n3,n1) select  ma_dvi,ma_kh,so_hd,ngay_tt,-sum(phi)
   from 
   (
    select a.ma_dvi,a.ma_kh,a.so_hd,b.ngay_tt,c.tien_qd phi from bh_hd_goc a, v_bh_hd_goc_ttpt_cn b,bh_hd_goc_ttct c
    where
    a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and b.ma_dvi=c.ma_dvi and b.so_id_tt=c.so_id_tt
    and c.pt='M'
    and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
    and b.phi>0
    and b.ngay_tt between b_ngayd and b_ngayc--nga sua lai lay theo ngay xem bao cao
    and (b_ma_kh is null or a.ma_kh=b_ma_kh) and (b_phong is null or a.phong=b_phong)
    )
    group by ma_dvi,ma_kh,so_hd,ngay_tt;
--    union all
insert into temp_1(c1,c2,c3,n3,n1) select  ma_dvi,ma_kh,so_hd,ngay_tt,sum(phi)
   from 
   (
    --giam cac mon qua dai ly thu ho
   select a.ma_dvi,a.ma_kh,a.so_hd,b.ngay_tt,-(b.phi_dt_qd+b.thue_qd) phi from bh_hd_goc a, v_bh_hd_goc_ttpt_cn b,bh_hd_goc_ttct c ---(b.phi_dt_qd+b.thue_qd)
    where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
    and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
--    and b.phi>0
    and b.ngay_tt between b_ngayd and b_ngayc  --nga sua lai lay theo ngay xem bao cao
--    and b.so_id_tt not in (select so_id_tt from bh_hd_goc_ttps where ngay_ht between b_ngayd and b_ngayc and htoan = 'T') --da xu ly sach ttpt 20210107
--    and b.so_id_tt not in (select so_id_tt from bh_hd_goc_ttct where ngay_ht between 20201210 and 20201210 and pt = 'M') --bo voucher 
    and c.ma_dvi=a.ma_dvi and c.so_id_tt=b.so_id_tt  and c.pt ='D' --in ('D','T')
    and (b_ma_kh is null or a.ma_kh=b_ma_kh) and (b_phong is null or a.phong=b_phong)
    )
group by ma_dvi,ma_kh,so_hd,ngay_tt;
--     union all
insert into temp_1(c1,c2,c3,n3,n1) select  ma_dvi,ma_kh,so_hd,ngay_tt,sum(phi)
   from 
   (
--giam cac mon Bao an khong dua vao cong no /*+ USE_NL(C2,B3) ORDERED */
    select a.ma_dvi,a.ma_kh,a.so_hd,b.ngay_tt,-(b.phi_dt_qd+b.thue_qd) phi from bh_hd_goc a, v_bh_hd_goc_ttpt_cn b,bh_nggcn_ba c
    where
    a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
    and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
    and b.phi>0
--    and b.so_id_tt not in (select so_id_tt from bh_hd_goc_ttps where ngay_ht between b_ngayd and b_ngayc and htoan = 'T') --da xu ly sach ttpt 20210107
    and c.ma_dvi=a.ma_dvi and c.so_id=a.so_id
    and (b_ma_kh is null or a.ma_kh=b_ma_kh) and (b_phong is null or a.phong=b_phong)
   )
   group by ma_dvi,ma_kh,so_hd,ngay_tt;

--Giam ps no,co cac mon thanh toan phi G qua B khong phat sinh no 13111 chi phat sinh no 13112
    --chon cac mon thanh toan qua B
    execute immediate 'truncate table temp_6';
    insert into temp_6(c1,c2,n1) select a.ma_dvi,a.ma_kh,a.so_id_tt from bh_hd_goc_ttps a, bh_hd_goc_ttct b
        where a.ngay_ht between b_ngayd and b_ngayc
        and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt = 'B' and a.htoan<>'T'
        and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
        and (b_phong is null or a.phong=b_phong)
        and (b_ma_kh is null or a.ma_kh=b_ma_kh);
        --giam so tien cho cac hop dong thanh toan luon pt='G'
    insert into temp_1(c1,c2,c3,n3,n1,n2)
        select a.ma_dvi,b.c2,FBH_HD_GOC_SO_HD(a.ma_dvi,a.so_id),a.ngay_ht,-sum(a.tien_qd),-sum(a.tien_qd)
        from bh_hd_goc_tthd a,temp_6 b where a.ma_dvi=b.c1 and a.so_id_tt=b.n1 and a.pt='G'
        --and a.so_id_tt in (select so_id_tt from bh_hd_goc_ttps where ngay_ht between b_ngayd and b_ngayc and htoan <> 'T')
        group by a.ma_dvi,b.c2,a.so_id,a.ngay_ht;
/*
--Chung tu chi tien
insert into temp_1(c1,c2,c3,n3,n1) select ma_dvi,ma_kh,so_ct||':'||PKH_SO_CNG(ngay_ht),ngay_ht,sum(tien_qd) from bh_kh_cn_tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='C'
    and (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_phong is null or phong=b_phong)
    group by ma_dvi,ma_kh,so_ct,ngay_ht;

--Chung tu chuyen tien
insert into temp_1(c1,c2,c3,n3,n1) select ma_dvi,ma_kh,so_ct||':'||PKH_SO_CNG(ngay_ht),ngay_ht,sum(tien_qd) from bh_kh_cn_tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='D'
    and (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_phong is null or phong=b_phong)
    group by ma_dvi,ma_kh,so_ct,ngay_ht;

--- phat sinh co
--Chung tu thu T
insert into temp_1(c1,c2,c3,n3,n2) select ma_dvi,ma_kh,so_ct||':'||PKH_SO_CNG(ngay_ht),ngay_ht,sum(tien_qd) from bh_kh_cn_tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='T'
    and (b_ma_dvi is null or ma_dvi=b_ma_dvi)
    and (b_ma_kh is null or ma_kh=b_ma_kh)and (b_phong is null or phong=b_phong)
    group by ma_dvi,ma_kh,so_ct,ngay_ht;
--Chung tu chuyen tien Di phong khac
insert into temp_1(c1,c2,c3,n3,n2) select ma_dvi,ma_kh,so_ct||':'||PKH_SO_CNG(ngay_ht),ngay_ht,sum(tien_qd_m) from bh_kh_cn_tu
    where ngay_ht between b_ngayd and b_ngayc and l_ct='D'
