insert into temp_1(c1,c2,c3,n3,n2) select a.ma_dvi,a.ma_kh,'BT-'||so_ct||':'||PKH_SO_CNG(a.ngay_ht),a.ngay_ht,sum(b.tien_qd) from bh_bt_tt a,bh_bt_tt_ct b
    where a.ngay_ht between b_ngayd and b_ngayc
    and b.ma_dvi=a.ma_dvi and b.so_id_tt=a.so_id_tt and b.pt='C'
    and (b_ma_dvi is null or a.ma_dvi=b_ma_dvi)
    and (b_ma_kh is null or a.ma_kh=b_ma_kh)and (b_phong is null or a.phong=b_phong)
    group by a.ma_dvi,a.ma_kh,so_ct,a.ngay_ht;
--update temp_1 set n1=nvl(n1,0);
--update temp_1 set n2=nvl(n2,0);
update temp_1 set n1=0 where n1 is null;
update temp_1 set n2=0 where n2 is null;
End;
/

DROP PROCEDURE DQD_BC_BH_TK_KT_MD;

CREATE OR REPLACE PROCEDURE DQD_BC_BH_TK_KT_MD
    (b_madvi varchar2,b_ma_dvi varchar2,b_ma_kh varchar2,b_ma_nv varchar2,b_phong varchar2,b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
Begin
-- Modull bao cao thong ke tai san ky thuat cho truong hop co mot don vi
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; return;
end if;
b_loi:='loi:Ma chua dang ky:loi';
/*
    temp_1  c1 ma_dvi,c2 LVUC_KD,c3 NTE_TS, c4 DVI,c5 DDIEM, c6 KVUC, c7 BHANH,c8 muc_ktr,c9 lh_nv,n1 so_id,n2 GIA_TS, n3 thue,n4 ttoan,n5 phi_dt,
    c10 phong,c11 cb_ql,c12 ma_kh,c13 ngay_hl,c14 ngay_kt,c15 so_hd,c16 ma_dt,c17 ma_nt
*/

delete temp_1;
delete temp_6;
commit;

insert into temp_1(n11,c1,c5,c3,c4,c8,c9,c10,c11,c12,c13,c14,c15,c16,c17,c19,c21,n1,n2,n6,n7,n3,n4,n5,c30,n30,c31)
    select  b.so_id_dt,a.ma_dvi,''LVUC,''NT_Tien,c.dvi,''mt_ktr,lh_nv,phong,ma_cb,ma_kh,PKH_SO_CNG(a.ngay_hl),
    PKH_SO_CNG(a.ngay_kt),so_hd,'',''nt_phi,ma_sp,a.ten,a.so_id,b.tien,b.tien,pt,b.thue,b.ttoan,b.phi,kieu_hd,so_id_g,
    ''rr_bh
    from bh_pkt a,bh_pkt_dk b,bh_pkt_dvi c  where b.ma_dvi=c.ma_dvi and b.so_id=c.so_id and b.so_id_dt=c.so_id_dt and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
    and (b_ma_dvi is null or a.ma_dvi = b_ma_dvi)   and (b_ma_kh is null or a.ma_kh = b_ma_kh)
    and (b_ma_nv is null or lh_nv like  b_ma_nv||'%')
    and (b_phong is null or a.phong = b_phong) and (a.ngay_ht between b_ngayd and b_ngayc);

--tru di so goc
insert into temp_6(n11,c1,c5,c3,c4,c8,c9,c10,c11,c12,c13,c14,c15,c16,c17,c19,c21,n1,n2,n6,n7,n3,n4,n5,c30,n30,c31)
     select n11,c1,c5,c3,c4,c8,c9,c10,c11,c12,c13,c14,c15,c16,c17,c19,c21,n1,n2,n6,n7,n3,n4,n5,c30,n30,c31 from temp_1 where c30='B';

-- insert into temp_1(n11,c1,c5,c3,c4,c8,c9,c10,c11,c12,c13,c14,c15,c16,c17,c19,c21,n1,n2,n6,n7,n3,n4,n5,c31)
--     select  n11,c1,c5,c3,c4,c8,c9,c10,c11,c12,c13,c14,c15,c16,c17,c19,c21,n1,n2,-tien,pt,-thue,-ttoan,-phi,c31
--     from bh_pktgcn a,bh_pkt_dk b,temp_6 c  where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.ma_dvi=c.c1 and a.so_id=c.n30;
--insert into temp_s_1 (c1,n1,n9,c4)
--select c1,n1,n9,c4 from temp_1 where n1=20210615034419;

update temp_1 set (c2,c6) =(select substr(ddiem,0,999),kvuc from bh_pkt_dvi where ma_dvi=temp_1.c1 and so_id=temp_1.n1 and so_id_dt=temp_1.n11 );--and ma_dt=temp_1.c4
--update temp_1 set c6 =(select kvuc from bh_pkt_dvi where ma_dvi=temp_1.c1 and so_id=temp_1.n1 ); --and ma_dt=temp_1.c4
update temp_1 set c7 =0;
--update temp_1 set c16=(select max(ma_dt) from bh_pkt_dk where ma_dvi=temp_1.c1 and so_id=temp_1.n1 and dvi=temp_1.c4 and rownum=1);

-- update temp_1 set c20 =(select min(ten) from bh_pkt_phi_ct where ma_dvi=temp_1.c1 and ma_nhom=temp_1.c19 and lh_nv=c9);
b_loi:='';
exception when others then null;
end;

/

DROP PROCEDURE DQD_BC_DT_DTUONG_THOP_HANG;
CREATE OR REPLACE PROCEDURE DQD_BC_DT_DTUONG_THOP_HANG
    (b_dvi varchar2, b_phong varchar2, b_ma_kh varchar2, b_loai_kh varchar2, b_lh_nv varchar2,
        b_ngayd number, b_ngayc number)
as
    b_loi nvarchar2(250);
begin
--     delete temp_5; delete temp_6; delete temp_3;commit; 
        execute immediate 'truncate table temp_5';
        execute immediate 'truncate table temp_6';
        execute immediate 'truncate table temp_3';
--    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n11, n12, n13, c22, c25, n20)
--        select ma_dvi, ma_dvi_g, phong, max(ngay), so_id, lh_nv, nv, sum(dt_ps), sum(dt_bh), sum(dt_tt), ma_kh, nguon, max(ngay_htnv)
--            from BH_THANG2D_BC_DT_LUU where nv = 'HANG' and ngay between b_ngayd and b_ngayc
--            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%') 
--            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
--            and (b_phong is null or phong=b_phong)      
--            group by ma_dvi, ma_dvi_g, phong, so_id, lh_nv, nv, ma_kh, nguon;
    
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n11, c22, c25, n20)
        select ma_dvi, ma_dvi, phong, ngay_ht, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from TEMP_BC_BH_DTPS_MNVM where nv ='HANG'-- and ngay_htnv between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, phong, ngay_ht,so_id, lh_nv, nv, ma_kh,nguon, ngay_htnv;
            
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n12, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from TEMP_BC_BH_DTBH_MM where nv ='HANG'-- and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;
                   
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n13, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh,nguon,  ngay_htnv
            from TEMP_BC_BH_DTTT_MA_DT where nv ='HANG' --and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;      
            
     --cap nhat so_id_cuoi cung
    delete temp_5 where n11=0 and n12=0 and n13=0;

    insert into temp_3(c1, c20, c3, n1, n2, c4,c5,n11,n12,n13, c22,c25, n20)
        select c1, c20, c3, max(n1), n2, c4,c5, sum(n11),sum(n12),sum(n13),c22,c25,max(n20) from temp_5
            group by c1, c20, c3, n2, c4,c5,c22,c25;

    update temp_3 set n4=FBH_HD_SO_ID_BS(c20,n2,b_ngayc);
    
    insert into temp_6(c1, c20, c25, n2, n3, c4, c3, n5, c5, c10, n10, c22, n11, n12, n13, n20)
        select t.c1, t.c20, t.c25, t.n2, '', t.c4, '',b.phi, --(b.phi_dt/100)*FBH_DONG_TL_DI(c20,n4,b.so_id_dt,c4,c10),
            t.c5, t.c3, t.n1, t.c22, t.n11, t.n12, t.n13, t.n20
            from bh_hang_dk b,temp_3 t
            where b.ma_dvi=t.c20 and b.so_id=t.n4 and b.lh_nv=t.c4
            and b.phi<>0;

    update temp_6 set n21=n11,n22=n12,n23=n13;
--    update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10);
    update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10 and a.c1=b.c1);--a.n3=b.n3 and
    update temp_6 a set n17 = (select sum(n5) from temp_6 b where a.c4=b.c4 and b.n2=a.n2 and a.c1=b.c1);    
--    merge into temp_6 a
--        using (select n2,c4,c20,c10,sum(n5) n5,count(*) dem from temp_6 group by n2,c4,c20,c10) b
--        on (b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10)
--        when MATCHED then
--        update set a.n17 = b.n5,a.n18 = b.dem;

--n12 phi ban hang
--n5 phi ps d/t
--n17 phi ps tong
    update temp_6 set n21=round(nvl(n11,0)*n5/n17),n22=round(nvl(n12,0)*n5/n17),n23=round(nvl(n13,0)*n5/n17)
        where n18>1 and n17<>0;
    insert into bh_bc_dt_dtuong_temp
        select c1, c10, n10, n2, n3, c22,'', c5, c4, c3, sum(n21), sum(n22), sum(n23), c20, c25, n20
            from temp_6 group by c1, c10, n10, n2, n3, c22, c5, c4, c3,c20, c25, n20;
           
--    update temp_5 set n4=FBH_HD_SO_ID_BS(c20,n2,n1); 
--    insert into temp_6(c1, c20,c25, n2, n3, c4, c3, n5, c5, c10, n10, c22, n11, n12, n13, n20)
--        select t.c1, t.c20,t.c25, t.n2, a.so_id_dt, t.c4, '',a.phi_dt,
--            t.c5, t.c3, t.n1, t.c22, t.n11, t.n12, t.n13, t.n20
--            from bh_hhgcn_dk a,temp_5 t
--            where a.ma_dvi=t.c20 and a.so_id=t.n4 and a.lh_nv=t.c4 and a.phi_dt<>0;
--        --group by c1, c20, n2, b.so_id_dt, c4, a.ma_dt,b.phi_dt, c5, c3, n1, c22, n11, n12, n13;
--    delete temp_6 where n11 = 0 and n12 = 0 and n13 = 0;  
--    update temp_6 set n21=n11,n22=n12,n23=n13;
--    --update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10);
--    merge into temp_6 a
--        using (select n2,c4,c20,c10,sum(n5) n5,count(*) dem from temp_6 group by n2,c4,c20,c10) b
--        on (b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10)
--        when MATCHED then
--        update set a.n17 = b.n5,a.n18 = b.dem;
--    update temp_6 set n21=round(nvl(n11,0)*n5/n17),n22=round(nvl(n12,0)*n5/n17),n23=round(nvl(n13,0)*n5/n17)
--        where n18>1 and n17<>0; 
--     insert into bh_bc_dt_dtuong_temp
--        select c1, c10, n10, n2, n3, c22,'', c5, c4, c3, sum(n21), sum(n22), sum(n23), c20, c25, n20
--            from temp_6 group by c1, c10, n10, n2, n3, c22, c5, c4, c3,c20, c25, n20;  
    commit;                  
    exception when others then rollback; raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE DQD_DO_TT_TON;

CREATE OR REPLACE PROCEDURE DQD_DO_TT_TON
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_ngayd number, b_ngayc number,cs1 out pht_type.cs_type)
AS
    b_loi varchar2(100); b_i1 number; b_phong varchar2(10);
begin
-- Dan - Liet ke no dong bao hiem
delete temp_m_5; delete temp_2; delete temp_3; commit;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
--b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','DO','X');
--if b_loi is not null then raise PROGRAM_ERROR; end if;

insert into temp_m_5(c10,n1,n2) select a.ma_dvi,a.so_id,a.so_id_ps from bh_hd_do_sc_ps a,bh_hd_do_ps b
where a.ma_dvi=b.ma_dvi and b.so_id=a.so_id
and b.so_id_ps=a.so_id_ps and b.ngay_ht betwEen b_ngayd and b_ngayc ;
--return;
insert into temp_2(c10,n1,n2,c1,c2,c3,c4,n3,n4) select ma_dvi,so_id,so_id_ps,nhom,loai,nv,ma_nt,tien,thue
    from bh_hd_do_ps where nhom='D' and (ma_dvi,so_id,so_id_ps) in (select c10,n1,n2 from temp_m_5) ;
    --and ngay_ht between b_ngayd and b_ngayc
insert into temp_2(c10,n1,n2,c1,c2,c3,c4,n3,n4) select a.ma_dvi,so_id,so_id_ps,nhom,loai,nv,ma_nt,-tien,-thue
    from bh_hd_do_tt b, bh_hd_do_ct a where b.ma_dvi=a.ma_dvi and a.so_id_tt=b.so_id_tt
    and (a.ma_dvi,a.so_id,a.so_id_ps) in (select c10,n1,n2 from temp_m_5);
insert into temp_3(c10,n1,n2,c1,c2,c3,c4,n3,n4) select c10,n1,n2,c1,c2,c3,c4,sum(n3),sum(n4)
    from temp_2 group by c10,n1,n2,c1,c2,c3,c4 having sum(n3)<>0 or sum(n4)<>0;
update temp_3 set n10=(select min(ngay_ht) from bh_hd_do_ps where ma_dvi=c10 and so_id=n1 and so_id_ps=n2);
update temp_3 set c5=FBH_DONG(c10,n1),c6=FBH_HD_GOC_SO_HD(c10,n1);
open cs1 for select c10 ma_dvi,n1 so_id,c5 kieu,c6 so_hd,n2 so_id_ps,n10 ngay_ht,c1 nhom,c2 loai,c3 nv,c4 ma_nt,n3 tien,n4 thue
    from temp_3 order by c10,c5,c6,n10,c1,c2,c4;
--delete temp_m_5; delete temp_2; delete temp_3; commit;
exception when others then if b_loi is null then raise PROGRAM_ERROR; else  raise_application_error(-20105,b_loi); end if;
end;
/

DROP PROCEDURE DQD_MAIL_TD_TT_TON;

CREATE OR REPLACE PROCEDURE DQD_MAIL_TD_TT_TON
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,cs1 out pht_type.cs_type)
AS
    b_loi varchar2(100); b_i1 number; b_i2 number; b_phong varchar2(10); b_ma_kh varchar2(20);
begin
execute immediate 'truncate table temp_s_1';
execute immediate 'truncate table temp_s_2';
execute immediate 'truncate table temp_s_3';
    insert into temp_s_1(n1,c1,c2,c3) select so_id,so_hd,kieu_kt,ma_kt
        from bh_hd_goc_sc_phi_ton where ma_dvi=b_ma_dvi and ma_dvi not in ('00','099','014') ;
    insert into temp_s_1(n1,c1,c2,c3) select so_id,so_hd,kieu_kt,ma_kt
        from bh_hd_goc_sc_no_ton where ma_dvi=b_ma_dvi and ma_dvi not in ('00','099','014');
        
insert into temp_s_3(n1,n2,c2,c3,n3) select so_id,ngay,'G',ma_nt,sum(ttoan) from bh_hd_goc_cl
    where ma_dvi=b_ma_dvi and so_id in (select distinct n1 from temp_s_1) group by so_id,ngay,ma_nt;
insert into temp_s_3(n1,n2,c2,c3,n3) select so_id,ngay,'G',ma_nt,-sum(ttoan) from bh_hd_goc_ttpt
    where ma_dvi=b_ma_dvi and pt not in('N','H') and so_id in (select n1 from temp_s_1) group by so_id,ngay,ma_nt;
insert into temp_s_3(n1,n2,c2,c3,n3) select so_id,ngay,'N',ma_nt,sum(ttoan) from bh_hd_goc_ttpt
    where ma_dvi=b_ma_dvi and pt='C' and so_id in (select distinct n1 from temp_s_1) group by so_id,ngay,ma_nt;
insert into temp_s_3(n1,n2,c2,c3,n3) select so_id,ngay,'N',ma_nt,-sum(ttoan) from bh_hd_goc_ttpt
    where ma_dvi=b_ma_dvi and pt='N' and so_id in (select distinct n1 from temp_s_1) group by so_id,ngay,ma_nt;

insert into temp_s_2(n1,n2,c2,c3,n3) select n1,n2,c2,c3,sum(n3) from temp_s_3 group by n1,n2,c2,c3 having sum(n3)<>0;
--update temp_s_2 set c1=(select distinct c1 from temp_s_1 where n1=temp_s_2.n1);
merge into TEMP_S_2 b using (select distinct n1,c1 from temp_s_1)a on (a.n1=b.n1) when matched then update set b.c1=a.c1;
--ALTER SYSTEM KILL SESSION '5153, 48954';
merge into temp_s_2
using (select distinct so_id_hd from tbh_ghep_pbo) a
on (a.so_id_hd=n1)
when matched then update
set c4='TCD';

merge into temp_s_2
using (select distinct so_id_hd from tbh_tm_pbo) a
on (a.so_id_hd=n1)
when matched then update
set c4='TM';

open cs1 for select n1 so_id,c1 so_hd,c2 pt,n2 ngay,c3 ma_nt,n3 phi,0 tien,'' tt from temp_s_2 order by c1,c2 DESC;--,n2,c3 DESC;
exception when others then if b_loi is null then raise PROGRAM_ERROR; else raise_application_error(-20105,b_loi); end if;
end;
/
DROP PROCEDURE DQD_MAIL_TKE_DENHAN_TTUC;

CREATE OR REPLACE PROCEDURE DQD_MAIL_TKE_DENHAN_TTUC
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2, B_PAS VARCHAR2,B_DVI VARCHAR2,B_NGAY varchar2,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);cs sys_refcursor;b_ngayc number;b_ngayd number;
BEGIN
b_ngayd:= to_char(to_date(B_NGAY,'dd/MM/yyyy'),'yyyyMMdd');
b_ngayc:= pkh_ng_cso(to_date(b_ngayd,'yyyyMMdd')+6);
BC_BH_TB_TT_MAIL('00', 'ADMIN', '$isAll', B_DVI, '', '', '', '', '', '', b_ngayd, b_ngayc, cs);
--lay sdt nv skl
--merge into temp_1 using bh_skl a on(c19=a.ma_dvi and a.so_hd=c1) when matched then update set c5=ten,c2=dchi,c11=mobi where c11 is null and c25='SKL';

--thong tin HRM
--update temp_1 set c30 = (select max(ma_hr) from ht_ma_cb where c19=ma_dvi and c7=ma and trim(mail) is not null);
update temp_1 set c30 = (select max(mail) from ht_ma_cb where c7=ma and trim(mail) is not null);
--update temp_1 set c32 = (select max(mail) from ht_ma_cb where c30=ma_hr and trim(mail) is not null);
--update temp_1 set c33 = (select max(mail) from ht_ma_cb where c30=ma_hr and trim(mail) is not null);

open cs_kq for
SELECT c20 ten_dvi,c19 ma_dvi, C1 SO_HD,c25 nv,C26 MA_KH, C5 TEN_KH,C3 NGAY_HT,c27 ngay_hl,C4 NGAY_kt,N2 PHI,
C21 PHONG, c7 ma_cb,c30 mail_cb, c22 ten_cb,c29 nsd FROM TEMP_1 where c19=B_DVI
ORDER BY c19,C4;
--EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE DQD_TB_TTP;

CREATE OR REPLACE PROCEDURE DQD_TB_TTP
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_phong varchar2,b_email varchar2,
    b_tc varchar2,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);
Begin
-- ke hop dong den han thanh toan phat sinh tu ngay_d den ngay_c bao cao
--b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
--if b_loi is not null then raise PROGRAM_ERROR; end if;
delete temp_1;delete temp_2;delete temp_3;delete ket_qua;commit;
--cho nhung hop dong da phat hanh hoa don chua thu phi den hien tai
if b_tc is null or b_tc ='C'  then
    insert into temp_2(n1,c1,n2) select so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_no
        where (ma_dvi=b_ma_dvi or b_ma_dvi is null)  group by so_id,ma_nt;
    insert into temp_3(n1,n2,n3) select a.so_id,a.no_qd,a.ton_qd from bh_hd_goc_sc_no a,temp_2 b
        where (ma_dvi=b_ma_dvi or b_ma_dvi is null) and a.so_id=b.n1 and a.ma_nt=b.c1 and a.ngay_ht=b.n2;
end if;
--cho nhung hop dong chua phat hanh hoa don chua thu phi den hien tai
if b_tc is null or b_tc ='K'  then
    delete temp_2;commit;
    insert into temp_2(n1,c1,n2) select so_id,ma_nt,max(ngay_ht) from bh_hd_goc_sc_phi
        where ma_dvi=b_ma_dvi group by so_id,ma_nt;
    insert into temp_3(n1,n2,n3,c1,c2,n6) select a.so_id,FTT_VND_QD(a.ma_dvi,a.ngay_ht,a.ma_nt,a.no),
        FTT_VND_QD(a.ma_dvi,a.ngay_ht,a.ma_nt,a.ton),a.ma_nt,a.ma_dvi,a.ngay_ht
        from bh_hd_goc_sc_phi a,temp_2 b where (ma_dvi=b_ma_dvi or b_ma_dvi is null) and a.so_id=b.n1 and a.ma_nt=b.c1 and a.ngay_ht=b.n2;
end if;

insert into temp_1(c5,c1,c2,n1,n2,n3) select goc.ma_dvi,goc.so_hd,goc.ten,goc.ngay_ht,sum(ph.n2),sum(ph.n3)
        from bh_hd_goc goc,temp_3 ph where goc.so_id=ph.n1 and goc.ngay_ht between (b_ngayd-7) and b_ngayc--goc.ma_dvi=b_ma_dvi and 
--        and (b_phong is null or goc.phong=b_phong)  and (b_ma_kh is null or goc.ma_kh=b_ma_kh)
        group by goc.ma_dvi,goc.so_hd,goc.ten,goc.ngay_ht;

delete temp_1 where nvl(n3,0)=0;
--select * from ht_ma_cb where ma='05'
insert into ket_qua(c5,c1,c2,n1,n2,n3) select c5,c1,c2,n1,sum(n2),sum(n3) from temp_1 group by c5,c1,c2,n1;
update ket_qua set (c7,c4)=(select max(cb_ql),PKH_SO_CNG(max(ngay_hl)) from bh_hd_goc where ma_dvi=c5 and so_hd=c1);
update ket_qua set c8 = (select max(mail) from ht_ma_cb where ma=c7 and ma_dvi=c5);

commit;
open cs_kq for select c5 ma_dvi,c1 so_hd,c2 as ten_kh,PKH_SO_CNG(n1) ngay_ht,c4 ngay_hl,n3 phi,c7 ma_cb,c8 email
    from ket_qua where upper(trim(c8))=upper(trim(b_email)) order by c1;
--exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP FUNCTION FBC_HD_NV;

CREATE OR REPLACE FUNCTION FBC_HD_NV(B_MA_DVI VARCHAR2,B_SO_ID NUMBER) RETURN VARCHAR2
AS
    B_KQ VARCHAR2(10);
BEGIN

SELECT MIN(NV) INTO B_KQ FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID;
RETURN B_KQ;
END;
/
