    (b_ma_dvi varchar2,cs_ta out pht_type.cs_type,b_loai varchar2,b_ngayd number,b_nv varchar2)
AS
begin
-- Dan - Liet ke hop dong tai
/*
if trim(b_nv) is null then
    open cs_ta for select so_hd from tbh_hd_di where ma_dvi=b_ma_dvi and nv=b_nv and ngay_bd>=b_ngayd order by so_hd;
else
