DROP FUNCTION F_LAY_TEN_DT_BH;

CREATE OR REPLACE FUNCTION F_LAY_TEN_DT_BH
(
    B_MA_DVI VARCHAR2, B_SO_ID NUMBER, B_NV VARCHAR2
)
RETURN NVARCHAR2
AS
    B_KET_QUA NVARCHAR2(4000);
    R LAY_TEN_DT_BH%ROWTYPE;
    CS1 PHT_TYPE.CS_TYPE;
    I NUMBER;
    B_I1 NUMBER;
BEGIN
    IF B_NV = 'XE' THEN
        OPEN CS1 FOR
            SELECT BIEN_XE TEN FROM BH_XE_ds WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY BIEN_XE;        
        SELECT COUNT(*) INTO B_I1 FROM BH_XE_ds WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
--    ELSIF B_NV = 'XEL' THEN
--        OPEN CS1 FOR
--            SELECT BIEN_XE TEN FROM BH_XELGCN WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY BIEN_XE;        
--        SELECT COUNT(*) INTO B_I1 FROM BH_XELGCN WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    ELSIF B_NV = 'NG' THEN
        OPEN CS1 FOR
            SELECT TEN FROM BH_NG_DS WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY TEN;        
        SELECT COUNT(*) INTO B_I1 FROM BH_NG_DS WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    ELSIF B_NV = 'HANG' THEN
        OPEN CS1 FOR
            SELECT TEN_HANG TEN FROM BH_HANG_Ds WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY TEN_HANG;        
        SELECT COUNT(*) INTO B_I1 FROM BH_HANG_Ds WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
--    ELSIF B_NV = 'TAUL' THEN
--        OPEN CS1 FOR
--            SELECT TEN_TAU TEN FROM BH_TAULGCN WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY TEN_TAU;        
--        SELECT COUNT(*) INTO B_I1 FROM BH_TAULGCN WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    ELSIF B_NV = 'TAU' THEN
        OPEN CS1 FOR
            SELECT TEN FROM BH_TAU WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY TEN;        
       SELECT COUNT(*) INTO B_I1 FROM BH_TAU WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    ELSIF B_NV = 'PHH' THEN    
        OPEN CS1 FOR
            SELECT DVI TEN FROM BH_phh_DVI WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY DVI;        
       SELECT COUNT(*) INTO B_I1 FROM BH_phh_DVI WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    ELSIF B_NV = 'PKT' THEN    
        OPEN CS1 FOR
            SELECT TEN FROM BH_PKT_dk WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY ten;        
       SELECT COUNT(*) INTO B_I1 FROM BH_PKT_dk WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    ELSIF B_NV = 'PTN' THEN
        OPEN CS1 FOR
            SELECT TEN FROM bh_ptn WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI ORDER BY ten;        
       SELECT COUNT(*) INTO B_I1 FROM bh_ptn WHERE SO_ID = B_SO_ID AND MA_DVI = B_MA_DVI;
    END IF;
    I:=0;
    B_KET_QUA:='';
    IF B_I1 <> 0 THEN
        IF B_NV NOT IN ('2B','2BL','NG') THEN
            LOOP          
              FETCH CS1 INTO R;
                   I:=I+1; 
                   B_KET_QUA := B_KET_QUA || R.TEN ||', ';               
              EXIT WHEN I >= B_I1;           
           END LOOP; 
       ELSIF B_NV = 'NG' THEN
            B_KET_QUA:='Danh sach nguoi bao hiem kinh kem';
       ELSE
            B_KET_QUA:='Danh sach xe may bao hiem kinh kem';            
       END IF;                
    END IF;
    RETURN B_KET_QUA;
END;
DROP TABLE LAY_TEN_DT_BH;

CREATE TABLE LAY_TEN_DT_BH
(
  TEN  NVARCHAR2(250)
);


