--  execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--  BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi, b_ngayd, b_ngayc);-- doanh thu thuc thu
