--   execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
--   --BC_BH_LAY_BC_BH_DTBH_MNVM(b_dvi, b_ngayd, b_ngayc);-- doanh thu ban hang
--   BC_BH_LAY_BC_BH_DTBH_MM(b_dvi, b_ngayd, b_ngayc);
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n12, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from TEMP_BC_BH_DTBH_MM where nv in ('NG')-- and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;
--  commit;
--  execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--  BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi, b_ngayd, b_ngayc);-- danh thu thuc thu
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n13, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh,nguon,  ngay_htnv
            from temp_bc_bh_dttt_ma_dt where nv in ('NG') --and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;
--return;
    delete temp_5 where n11=0 and n12=0 and n13=0;

    insert into temp_3(c1, c20, c3, n1, n2, c4,c5,n11,n12,n13, c22,c25, n20)
        select c1, c20, c3, max(n1), n2, c4,c5, sum(n11),sum(n12),sum(n13),c22,c25,max(n20) from temp_5
            group by c1, c20, c3, n2, c4,c5,c22,c25;

    --cap nhat so_id_cuoi cung
    update temp_3 set n4=FBH_HD_SO_ID_BS(c20,n2,b_ngayc);
--b_ma_dvi varchar2,b_so_id number,b_so_id_dt number,b_lh_nv varchar2,b_ma_dvi_do varchar2
    insert into temp_6(n2,c1, c20, c25, n4, n3, c4, c3, n5, c5, c10, n10, c22, n11, n12, n13, n20)
    select /*+ parallel(4) */ n2,c1, c20, c25, n4, b.so_id_dt, c4, '',(b.phi/100)*FBH_DONG_TL_DI(c20,n4,b.so_id_dt,c4,c10),
        c5, c3, n1, c22, n11, n12, n13, n20
        from bh_ng_ds a,(select * from bh_ng_dk where phi >0) b,temp_3
        where a.ma_dvi=c20 and a.so_id=n4
        and b.ma_dvi=a.ma_dvi and b.so_id=a.so_id and b.so_id_dt = a.so_id_dt
        and b.lh_nv=c4 ;
        --group by c1, c20, n2, b.so_id_dt, c4, a.ma_dt,b.phi_dt, c5, c3, n1, c22, n11, n12, n13;
    delete temp_6 where n11 = 0 and n12 = 0 and n13 = 0;
    update temp_6 set n21=n11,n22=n12,n23=n13;
    delete temp_m_2;
    insert into temp_m_2 (n4,c4,c20,c10,c1,n5,n6)
    select b.n4,b.c4,b.c20,b.c10 ,b.c1,sum(nvl(n5,0))n5,count(*)n6 from temp_6 b group by b.n4,b.c4,b.c20,b.c10 ,b.c1;
    merge into temp_6 a using temp_m_2 b on (b.n4=a.n4 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10 and a.c1=b.c1) when matched then update set a.n17=b.n5,a.n18=b.n6;
--     update temp_6 a set (n17,n18)=(select sum(nvl(n5,0)),count(*) from temp_6 b where b.n4=a.n4 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10 and a.c1=b.c1);
    delete temp_m_2;
    insert into temp_m_2(c4,n4,c1,c10,n5)
    select b.c4,b.n4,b.c1,b.c10,sum(n5)n5 from temp_6 b group by b.c4,b.n4,b.c1,b.c10;
    merge into temp_6 a using temp_m_2 b on ( a.c4=b.c4 and b.n4=a.n4 and a.c1=b.c1 and a.c10=b.c10) when matched then update set  a.n17=b.n5;
-- update temp_6 a set n17 = (select sum(n5) from temp_6 b where a.c4=b.c4 and b.n4=a.n4 and a.c1=b.c1 and a.c10=b.c10);
-- merge into temp_6 a
-- using (select c10,c4,n4,c1,sum(n5)n5 from temp_6 b group by c4,n4,c1,c10)b
-- on (a.c4=b.c4 and b.n4=a.n4 and a.c1=b.c1 and a.c10=b.c10)
-- when matched then update set a.n17=b.n5;
--    update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where  b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10 and a.c1=b.c1);--a.n3=b.n3 and
    
        update temp_6 set n21=round(nvl(n11,0)*n5/n17),n22=round(nvl(n12,0)*n5/n17),n23=round(nvl(n13,0)*n5/n17)
        where n18>1 and n17<>0;
     insert into bh_bc_dt_dtuong_temp
        select c1, c10, n10, n4, n3, c22,'', c5, c4, c3, sum(nvl(n21,0)), sum(nvl(n22,0)), sum(nvl(n23,0)), c20, c25, n20
            from temp_6 group by c1, c10, n10, n4, n3, c22, c5, c4, c3,c20, c25, n20;
--    exception when others then rollback; raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE nga_bc_dt_dtuong_thop_phh;

CREATE OR REPLACE PROCEDURE nga_bc_dt_dtuong_thop_phh
    (b_dvi varchar2, b_phong varchar2, b_ma_kh varchar2, b_loai_kh varchar2, b_lh_nv varchar2,
        b_ngayd number, b_ngayc number)
as
    b_loi nvarchar2(250);
begin
--BCNam: da sua OK, ko sua lai
--    delete temp_5; delete temp_6; delete temp_3;commit;.
    execute immediate 'TRUNCATE TABLE temp_5';
    execute immediate 'TRUNCATE TABLE temp_6';
    execute immediate 'TRUNCATE TABLE temp_3';
    /*
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n11, n12, n13, c22, c25, n20)
        select ma_dvi, ma_dvi_g, phong, max(ngay), so_id, lh_nv, nv, sum(dt_ps), sum(dt_bh), sum(dt_tt), ma_kh, nguon, max(ngay_htnv)
            from BH_THANG2D_BC_DT_LUU where nv='PHH' and ngay between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong=b_phong)
            group by ma_dvi, ma_dvi_g, phong, so_id, lh_nv, nv, ma_kh, nguon;
     */
--  execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MNVM';
--  BC_BH_LAY_BC_BH_DTPS_MNVM(b_dvi, b_ngayd, b_ngayc);-- doanh thu phat sinh
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n11, c22, c25, n20)
        select ma_dvi, ma_dvi, phong, ngay_ht, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from TEMP_BC_BH_DTPS_MNVM where nv in ('PHH')-- and ngay_htnv between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, phong, ngay_ht,so_id, lh_nv, nv, ma_kh,nguon, ngay_htnv;
--   commit;
--   execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
--   --BC_BH_LAY_BC_BH_DTBH_MNVM(b_dvi, b_ngayd, b_ngayc);-- doanh thu ban hang
--   BC_BH_LAY_BC_BH_DTBH_MM(b_dvi, b_ngayd, b_ngayc);
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n12, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from TEMP_BC_BH_DTBH_MM where nv in ('PHH')-- and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;
--  commit;
--  execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--  BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi, b_ngayd, b_ngayc);-- danh thu thuc thu
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n13, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh,nguon,  ngay_htnv
            from TEMP_BC_BH_DTTT_MA_DT where nv in ('PHH') --and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;

    --cap nhat so_id_cuoi cung
    delete temp_5 where n11=0 and n12=0 and n13=0;

    insert into temp_3(c1, c20, c3, n1, n2, c4,c5,n11,n12,n13, c22,c25, n20)
        select c1, c20, c3, max(n1), n2, c4,c5, sum(n11),sum(n12),sum(n13),c22,c25,max(n20) from temp_5
            group by c1, c20, c3, n2, c4,c5,c22,c25;

    update temp_3 set n4=FBH_HD_SO_ID_BS(c20,n2,b_ngayc);

    /*
    insert into temp_6(c1, c20, c25, n2, n3, c4, c3, n5, c5, c10, n10, c22, n11, n12, n13, n20)
        select t.c1, t.c20, t.c25, t.n2, b.so_id_dt, t.c4, a.ma_dt,b.phi_dt,
            t.c5, t.c3, t.n1, t.c22, t.n11, t.n12, t.n13, t.n20
            from bh_phhgcn_dk b,bh_phhgcn_dvi a,temp_5 t
            where a.ma_dvi=t.c20 and a.so_id=t.n4 and b.lh_nv=t.c4
            and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.so_id_dt=b.so_id_dt
            and b.phi_dt<>0;
        --group by c1, c20, n2, b.so_id_dt, c4, a.ma_dt,b.phi_dt, c5, c3, n1, c22, n11, n12, n13;
    */
delete temp_m_3;
insert into temp_m_3 (c1,n1,n2,c2,n3) 
select ma_dvi,so_id,so_id_dt,lh_nv,phi from bh_phh_dk where phi<>0;
    insert into temp_6(c1, c20, c25, n2, n3, c4, c3, n5, c5, c10, n10, c22, n11, n12, n13, n20)
        select t.c1, t.c20, t.c25, t.n2, b.n2, t.c4, a.ma_dt,b.n3,--(b.n3/100)*FBH_DONG_TL_DI(t.c20,t.n4,b.n2,t.c4,t.c1),
            t.c5, t.c3, t.n1, t.c22, t.n11, t.n12, t.n13, t.n20
            from temp_m_3 b,bh_phh_dvi a,temp_3 t --(select * from bh_phhgcn_dk where phi_dt<>0)
            where 
            b.c1=t.c20 and b.n1=t.n4 and b.c2=t.c4
            and a.ma_dvi=b.c1 and a.so_id=b.n1 and b.n2 in (a.so_id_dt,0); --so id dtuong check thay co = 1 --,1
--            and b.phi_dt<>0;
--return;
delete temp_m_3;
    update temp_6 set n21=n11,n22=n12,n23=n13;
    update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where  b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10 and a.c1=b.c1);--a.n3=b.n3 and
    update temp_6 a set n17 = (select sum(n5) from temp_6 b where a.c4=b.c4 and b.n2=a.n2 and a.c1=b.c1);
    
--    merge into temp_6 a
--        using (select n2,c4,c20,c10,sum(n5) n5,count(*) dem from temp_6 group by n2,c4,c20,c10) b
--        on (b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10)
--        when MATCHED then
--        update set a.n17 = b.n5,a.n18 = b.dem;
  
--n12 phi ban hang
--n5 phi ps d/t
--n17 phi ps tong
    
    update temp_6 set n21=round(nvl(n11,0)*n5/n17),n22=round(nvl(n12,0)*n5/n17),n23=round(nvl(n13,0)*n5/n17)
        where n18>1 and n17<>0;
--    update temp_6 a set n22 = n12/n18;
    insert into bh_bc_dt_dtuong_temp
        select c1, c10, n10, n2, n3, c22,'', c5, c4, c3, sum(n21), sum(n22), sum(n23), c20, c25, n20
            from temp_6 group by c1, c10, n10, n2, n3, c22, c5, c4, c3,c20, c25, n20;
    commit;
--    exception when others then rollback; raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE NGA_BC_DT_DTUONG_THOP_PKT;

CREATE OR REPLACE PROCEDURE NGA_BC_DT_DTUONG_THOP_PKT
    (b_dvi varchar2, b_phong varchar2, b_ma_kh varchar2, b_loai_kh varchar2, b_lh_nv varchar2,
    b_ngayd number, b_ngayc number)
as
    b_loi nvarchar2(250);
begin
--BCNam: da sua OK, cam sua lai
--    delete temp_5; delete temp_6; delete temp_3;commit;
    execute immediate 'TRUNCATE TABLE temp_5';
    execute immediate 'TRUNCATE TABLE temp_6';
    execute immediate 'TRUNCATE TABLE temp_3';
   /* insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n11, n12, n13, c22, c25, n20)
        select ma_dvi, ma_dvi_g, phong, max(ngay), so_id, lh_nv, nv, sum(dt_ps), sum(dt_bh), sum(dt_tt), ma_kh, nguon, max(ngay_htnv)
            from BH_THANG2D_BC_DT_LUU where nv = 'PKT' and ngay between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong=b_phong)
            group by ma_dvi, ma_dvi_g, phong, so_id, lh_nv, nv, ma_kh, nguon;*/
--  execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MNVM';
--  BC_BH_LAY_BC_BH_DTPS_MNVM(b_dvi, b_ngayd, b_ngayc);-- doanh thu phat sinh
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n11, c22, c25, n20)
        select ma_dvi, ma_dvi, phong, ngay_ht, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from temp_bc_bh_dtps_mnvm where nv in ('PKT')-- and ngay_htnv between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, phong, ngay_ht,so_id, lh_nv, nv, ma_kh,nguon, ngay_htnv;
--   commit;
--   execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
--   --BC_BH_LAY_BC_BH_DTBH_MNVM(b_dvi, b_ngayd, b_ngayc);-- doanh thu ban hang
--   BC_BH_LAY_BC_BH_DTBH_MM(b_dvi, b_ngayd, b_ngayc);
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n12, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh, nguon, ngay_htnv
            from TEMP_BC_BH_DTBH_MM where nv in ('PKT')-- and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;
--  commit;
--  execute immediate 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--  BC_BH_LAY_BC_BH_DTTT_MA_DT(b_dvi, b_ngayd, b_ngayc);-- danh thu thuc thu
    insert into temp_5(c1, c20, c3, n1, n2, c4,c5, n13, c22, c25, n20)
        select ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, sum(phi), ma_kh,nguon,  ngay_htnv
            from temp_bc_bh_dttt_ma_dt where nv in ('PKT') --and ngay_ht_pt between b_ngayd and b_ngayc
            and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lh_nv is null or lh_nv like b_lh_nv||'%')
            and (b_ma_kh is null or ma_kh like b_ma_kh||'%')
            and (b_phong is null or phong like b_phong||'%')
            group by ma_dvi, ma_dvig, phong, ngay_htnv, so_id, lh_nv, nv, ma_kh, nguon, ngay_htnv;

    delete temp_5 where n11=0 and n12=0 and n13=0;

    insert into temp_3(c1, c20, c3, n1, n2, c4,c5,n11,n12,n13, c22,c25, n20)
        select c1, c20, c3, max(n1), n2, c4,c5, sum(n11),sum(n12),sum(n13),c22,c25,max(n20) from temp_5
            group by c1, c20, c3, n2, c4,c5,c22,c25;

    --cap nhat so_id_cuoi cung
    update temp_3 set n4=FBH_HD_SO_ID_BS(c20,n2,b_ngayc);
    insert into temp_6(c1, c20, c25, n2, n3, c4, c3, n5, c5, c10, n10, c22, n11, n12, n13, n20)
    select c1,c20, c25, n2, b.so_id_dt, c4, b.ma,(b.phi/100)*FBH_DONG_TL_DI(c20,n4,b.so_id_dt,c4,c1),
    c5, c3, n1, c22, n11, n12, n13, n20
        from bh_pkt_dvi a,(select * from bh_pkt_dk where phi<>0) b,temp_3
        where a.ma_dvi=c20 and a.so_id=n4
        and b.ma_dvi=a.ma_dvi and b.so_id=a.so_id and b.so_id_dt = a.so_id_dt
        and b.lh_nv=c4;-- and b.phi_dt<>0;

    delete temp_6 where n11 = 0 and n12 = 0 and n13 = 0;
    --update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10);
    update temp_6 a set (n17,n18)=(select sum(n5),count(*) from temp_6 b where b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10 and a.c1=b.c1);--a.n3=b.n3 and
    update temp_6 a set n17 = (select sum(n5) from temp_6 b where a.c4=b.c4 and b.n2=a.n2 and a.c1=b.c1);    
--    merge into temp_6 a
--        using (select n2,c4,c20,c10,sum(n5) n5,count(*) dem from temp_6 group by n2,c4,c20,c10) b
--        on (b.n2=a.n2 and b.c4=a.c4 and b.c20=a.c20 and a.c10=b.c10)
--        when MATCHED then
--        update set a.n17 = b.n5,a.n18 = b.dem;

    update temp_6 set n21=n11,n22=n12,n23=n13;
    update temp_6 set n21=round(n11*n5/n17,0),n22=round(n12*n5/n17,0),n23=round(n13*n5/n17,0)
