--thay t.n1 bang t.n2
        insert into temp_idx (ma,so, c1,c3, c20,c22,c25, n1,n2,n3,c10,d1,n11,n12,n13,n16,c29,c6, n20)
            select t.c6,t.n2,t.c1,t.c3,t.c2,t.c22,t.c25,t.n2,a.so_id_dt,t.n3,''muc_rr,PKH_SO_CNG_DATE(a.ngay_cap),t.n11,t.n12,t.n13,(b.phi/100)*FBH_DONG_TL_DI(c2,n2,b.so_id_dt,c6,c1),
            t.c29,b.lh_nv, t.n20
                from bh_xe_dk b,bh_xe_ds a,temp_4 t
                where t.c29='XE' and b.ma_dvi=t.c2 and b.so_id=t.n2 and b.lh_nv=t.c6
                and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
                and a.so_id_dt=b.so_id_dt;
    --            and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id
                --group by c1,c3,c2,c22,a.so_id,a.so_id_dt,n3,a.muc_rr,a.ngay_cap,n11,n12,n13,c29,b.lh_nv;

    delete temp_idx where nvl(n11,0)=0 and nvl(n12,0)=0 and nvl(n13,0)=0;
     /*
     insert into temp_idx_1 (ma,so, n17,n18) select c6,n1,sum(n16),count(*) from temp_idx group by n1,c6;
     update temp_idx a set (n17,n18)=(select n17,n18 from temp_idx_1 b where a.so=b.so and a.ma=b.ma);
     */
--    merge into temp_idx a
--        using (select c6 ma,n1 so,sum(n16) n17,count(*) n18 from temp_idx group by n1,c6) b
--        on (a.so=b.so and a.ma=b.ma)
--        when MATCHED then
--        update set a.n17 = b.n17,a.n18 = b.n18;
--n16 phi ps tung dtuong
--n12 tong phi bh
--n17 tong ps
-- update temp_idx a set (n17,n18)=(select sum(nvl(n16,0)),count(*) from temp_idx b where b.so=a.so and b.c6=a.c6 and b.c20=a.c20 and a.c3=b.c3 and a.c1=b.c1);
 merge into temp_idx a using (select so,c6,c20,c3,c1,sum(nvl(n16,0))n16,count(*)sl from temp_idx b group by so,c6,c20,c3,c1 )b
 on (b.so=a.so and b.c6=a.c6 and b.c20=a.c20 and a.c3=b.c3 and a.c1=b.c1)
 when matched then update set n17=b.n16,n18=b.sl;
 
-- update temp_idx a set n17 = (select sum(n16) from temp_idx b where a.c6=b.c6 and b.so=a.so and a.c1=b.c1);
 merge into temp_idx a
 using (select c6,so,c1,sum(n16)n16 from temp_idx group by c6,so,c1)b
  on ( a.c6=b.c6 and b.so=a.so and a.c1=b.c1)
 when matched then update set a.n17=b.n16;

     update temp_idx set n21=n11,n22=n12,n23=n13;
     update temp_idx set n21=round(n11*n16/n17,0),n22=round(n12*n16/n17,0),n23=round(n13*n16/n17,0)
         where n18>1 and n17<>0;
     --update temp_3 set (c13, c30, c15)=(select phong, so_hd, cb_ql from bh_hd_goc where ma_dvi=c1 and so_id=n1);

     insert into bh_bc_dt_dtuong_temp
        select c1, c3, n3, n1, n2, c22,c23,c29, c6, c10, sum(nvl(n21,0)), sum(nvl(n22,0)), sum(nvl(n23,0)), c20, c25, n20 from temp_idx
        group by c1, c3, n3, n1, n2, c22,c23,c29, c6, c10,c20, c25, n20;
     commit;

   -- exception when others then rollback; raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE PBC_BH_BC_DT_BT;

CREATE OR REPLACE PROCEDURE PBC_BH_BC_DT_BT
 (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ngayd number,b_ngayc number,b_lhnv varchar2,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_i1 number;
Begin
-- Bao cao DT BT
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayc,-4)+101;b_loi:='loi:Ma chua dang ky:loi';

delete temp_2;delete temp_3;delete ket_qua; delete bc_bh_bt_temp;

delete temp_bc_ts;
insert into temp_bc_ts values (b_ma_dvi,b_ngayd,b_ngayc);
-- trong ky
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
--n2: phi trong ky BH
--n3: thue trong ky BH
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2 (c29,c1,c2,c5,c6,c7,n2,n3,n1,c13,c14,c22,c23,c21,c30,c15) select ma_dvi,cb_ql,ma_kh,so_hd,'',lh_nv,sum(phi),
sum(thue),so_id,kieu_kt,ma_kt,to_char(ngay_hl,'dd/MM/yyyy'),to_char(ngay_kt,'dd/MM/yyyy'),nv,ma_dvig,ngay_ht
from TEMP_BC_BH_DTBH_MM where lh_nv like b_lhnv||'%'
group by ma_dvi,cb_ql,ma_kh,so_hd,lh_nv,so_id,kieu_kt,ma_kt,ngay_hl,ngay_kt,nv,ma_dvig,ngay_ht;
--n8 n9 TT
BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2(c29,c1,c2,c5,c6,c7,n8,n9,n1,c13,c14,c22,c23,c21,c30,c15)
select ma_dvi,cb_ql,ma_kh,so_hd,'',lh_nv,sum(nvl(phi,0)),
sum(nvl(thue,0)),so_id,kieu_kt,ma_kt,to_char(ngay_hl,'dd/MM/yyyy'),to_char(ngay_kt,'dd/MM/yyyy'),nv,ma_dvig,ngay_ht
from TEMP_BC_BH_DTTT_MA_DT where lh_nv like b_lhnv||'%'
group by ngay_hl,ngay_kt,ma_dvi,ma_dvig,so_hd,ma_kh,cb_ql,phong,ma_kt,lh_nv,ngay_htnv,so_id,kieu_kt,nv,ngay_ht;
-- boi thuong trong ky
delete temp_bc_ts;
insert into temp_bc_ts select ma,b_ngayd,b_ngayc from ht_ma_dvi;
PBC_BH_TH_BT_PB_MD('T');
insert into bc_bh_bt_temp(ma_dvi,n6,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd)
                    select ma_dvi,tien_qd,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd from bc_bh_bt_hs_temp
                                    where ngay_qd_n<30000101 and lh_nv like b_lhnv||'%';
--update temp_2 set (n6)=(select nvl(sum(n6),0) from bc_bh_bt_temp where ma_dvi_hd=temp_2.c30 and so_id_hd=temp_2.n1 and lh_nv=temp_2.c7);
merge into temp_2 c
using ( select nvl(sum(n6),0)n6,ma_dvi_hd,so_id_hd,lh_nv from bc_bh_bt_temp group by ma_dvi_hd,so_id_hd,lh_nv )a
on (a.ma_dvi_hd=c.c30 and a.so_id_hd=c.n1 and a.lh_nv=c.c7)
when matched then update set c.n6 = a.n6;

--update temp_2 set (n7)=(select nvl(sum(n7),0) from bc_bh_bt_temp where ma_dvi_hd=temp_2.c30 and so_id_hd=temp_2.n1 and lh_nv=temp_2.c7);
--merge into temp_2 c
--using ( select nvl(sum(n7),0)n7,ma_dvi_hd,so_id_hd,lh_nv from bc_bh_bt_temp group by ma_dvi_hd,so_id_hd,lh_nv )a
--on (a.ma_dvi_hd=c.c30 and a.so_id_hd=c.n1 and a.lh_nv=c.c7)
--when matched then update set c.n7 = a.n7;

--tong hop
--n2:phi BH,n8 phi TT, n4 phi cung ky, n6 bt trong ky,n7 bt cung ky
insert into temp_3(c29,c1,c2,c5,c6,c7,n2,n8,n4,n6,n7,n1,c13,c14,c22,c23,c21,c30,c15)
    select c29,c1,c2,c5,c6,c7,nvl(sum(n2),0)+nvl(sum(n3),0),nvl(sum(n8),0)+nvl(sum(n9),0),nvl(sum(n4),0)+nvl(sum(n5),0),nvl(sum(n6),0),nvl(sum(n7),0),n1,c13,c14,c22,c23,c21,c30,c15 
    from temp_2
        group by c29,c1,c2,c5,c6,c7,n1,c13,c14,c22,c23,c21,c30,c15;
delete temp_3 where nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n4,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n7,0)=0;
---
--delete temp_3 where c7 not like b_lhnv||'%';
open cs_kq for
select c29 ma_dvi,c1 cb_ql,c2 ma_kh,c5 so_hd,c7 lh_nv,c13 kieu_kt,c14 ma_kt,c21 nv,c22 ngay_hl,c23 ngay_kt,c30 ma_dvig,
n1 so_id,n2 phi_bh,n8 phi_TT,n6 bt,c15 ngay_ht from temp_3;

--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE PBC_BH_BT_CGQ_MD;

CREATE OR REPLACE PROCEDURE PBC_BH_BT_CGQ_MD(b_tc varchar2)
AS
begin
--BCNam da sua lai
--delete temp_bt_1;delete temp_bt_2;delete temp_bt_3; commit;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_3';

-- Lay so lieu trong bang bh_bt_hs_dp_ct
PBC_BH_BT_CQG_CT(b_tc);
-- Lay so lieu trong bang bh_bt_hs_dp
--PBC_BH_BT_CQG(b_tc);
--Sua them bang phu
PBC_BH_BT_CQG_SUA(b_tc);

insert into temp_bt_2 (ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,n6,n7,so_id_dt,c1,c4,n8)
    select a.ma_dvi,a.c2,a.c3,a.lh_nv,a.so_id,a.n2,a.n3,a.n4,a.n5,nv.tien,nv.tien_qd,nv.so_id_dt,c1,c4,n6
    from temp_bt_3 a,bh_bt_hs_nv nv
    where nv.ma_dvi=a.ma_dvi and nv.so_id=a.so_id;
-- Tong hop so lieu
delete temp_bt_2 a where (a.ma_dvi,a.so_id) in (select b.ma_dvi,b.so_id from temp_bt_1 b);
update temp_bt_2 a set n9=(select sum(n7) from temp_bt_2 b where b.ma_dvi=a.ma_dvi and b.so_id=a.so_id group by b.ma_dvi,b.so_id);
update temp_bt_2 set n1= round(n7*n5/n9,0) where n9<>0;

insert into temp_bt_1(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,c4,n6)
    select ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n1,so_id_dt,c4,n8 from temp_bt_2;
update temp_bt_1 tp set tp.c5 = (select hs.nsd from bh_bt_hs hs where hs.ma_dvi=tp.ma_dvi and hs.so_id=tp.so_id);
delete from temp_bt_1 where SUBSTR(lh_nv,1,2) not in (Select nv from temp_bc_nv) and c3 not in (Select phong from temp_bc_phong);
end;
/
-- chuclh
DROP PROCEDURE PBC_BH_BT_CQG_CT;

CREATE OR REPLACE PROCEDURE PBC_BH_BT_CQG_CT(b_tc varchar2)
-- Boi thuong chua giai quyet lay so lieu trong bang bh_bt_hs_dp_ct
AS
begin
-- Tu lam
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_DVI_SO_ID_NG';
insert into TEMP_DVI_SO_ID_NG (ma_dvi,so_id,ngay)
    select a.ma_dvi,a.so_id,max(ngay_dp) ngay_dp from bh_bt_hs_dp_ct a,temp_bc_ts t
        where a.ma_dvi=t.ma_dvi and round(ngay_dp,-2)<=round(t.ngayc,-2) and lh_nv is not null group by a.ma_dvi,a.so_id;

if PKH_MA_MA(b_tc,'T') or PKH_MA_MA(b_tc,'*')  then --
insert into temp_bt_1(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,c1,c4,n6)
    select distinct bt.ma_dvi,bt.nv,bt.phong,lh_nv,bt.so_id,bt.ngay_ht,bt.so_id_hd,nv.tien,nv.tien_qd,bt.so_id_dt,'T',bt.ma_dvi_ql,(bt.ngay_qd)
        from bh_bt_hs bt,bh_bt_hs_dp_ct nv,TEMP_DVI_SO_ID_NG dp,temp_bc_ts ts
    where
        bt.ma_dvi=ts.ma_dvi and bt.ngay_ht between ts.ngayd and ts.ngayc
        and ngay_qd>ts.ngayc
        and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
        and bt.ma_dvi_xl=bt.ma_dvi_ql
        and bt.ma_dvi=ma_dvi_ql
        and dp.ma_dvi=bt.ma_dvi and dp.so_id=bt.so_id
        and nv.ma_dvi=bt.ma_dvi and nv.so_id=bt.so_id  and nv.ngay_dp=dp.ngay;

/*
insert into temp_bt_1(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,c1,c4,n6)
select distinct bt.ma_dvi,bt.nv,bt.phong,lh_nv,bt.so_id,bt.ngay_ht,nv.so_id_hd,nv.tien,nv.tien_qd,nv.so_id_dt,'T',bt.ma_dvi_ql,PKH_NG_CSO(bt.ngay_qd)
    from bh_bt_hs bt,bh_bt_hs_dp_ct nv,(select a.ma_dvi,a.so_id,max(ngay_dp) ngay_dp from bh_bt_hs_dp_ct a,temp_bc_ts t
        where a.ma_dvi=t.ma_dvi and round(ngay_dp,-2)<=round(t.ngayc,-2) and lh_nv is not null group by a.ma_dvi,a.so_id) dp,temp_bc_ts ts
    where
        bt.ma_dvi=ts.ma_dvi and bt.ngay_ht between ts.ngayd and ts.ngayc
        --and to_char(ngay_qd,'yyyymmdd')>ts.ngayc
        and ngay_qd>PKH_SO_CDT(ts.ngayc)
        and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
        and bt.ma_dvi_xl=bt.ma_dvi_ql
        and bt.ma_dvi=ma_dvi_ql
        and dp.ma_dvi=bt.ma_dvi and dp.so_id=bt.so_id
        and nv.ma_dvi=bt.ma_dvi and nv.so_id=bt.so_id  and nv.ngay_dp=dp.ngay_dp;
*/

end if;

-- Don vi khac lam ho
if PKH_MA_MA(b_tc,'N') or PKH_MA_MA(b_tc,'*') or PKH_MA_MA(b_tc,'T')  then
/*
insert into temp_bt_1(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,c1,c4,n6)
select distinct bt.ma_dvi,bt.nv,bt.phong,lh_nv,bt.so_id,bt.ngay_ht,nv.so_id_hd,nv.tien,nv.tien_qd,nv.so_id_dt,'N',bt.ma_dvi_ql,PKH_NG_CSO(bt.ngay_qd)
    from bh_bt_hs bt,bh_bt_hs_dp_ct nv,(select a.ma_dvi,a.so_id,max(ngay_dp) ngay_dp from bh_bt_hs_dp_ct a,temp_bc_ts t
        where a.ma_dvi=t.ma_dvi and round(ngay_dp,-2)<=round(t.ngayc,-2) and lh_nv is not null group by a.ma_dvi,a.so_id) dp,temp_bc_ts ts
    where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi=ts.ma_dvi and bt.ma_dvi=ma_dvi_ql
        and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id
        and bt.ma_dvi=dp.ma_dvi and bt.so_id=dp.so_id and nv.ngay_dp=dp.ngay_dp
        and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
        and bt.ngay_ht between ts.ngayd and ts.ngayc and to_char(ngay_qd,'yyyymmdd')>ts.ngayc;
*/
insert into temp_bt_1(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,c1,c4,n6)
select distinct bt.ma_dvi,bt.nv,bt.phong,lh_nv,bt.so_id,bt.ngay_ht,bt.so_id_hd,nv.tien,nv.tien_qd,bt.so_id_dt,'N',bt.ma_dvi_ql,(bt.ngay_qd)
    from bh_bt_hs bt,bh_bt_hs_dp_ct nv,TEMP_DVI_SO_ID_NG dp,temp_bc_ts ts
    where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi=ts.ma_dvi and bt.ma_dvi=ma_dvi_ql
        and bt.ngay_ht between ts.ngayd and ts.ngayc
        and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
        and nv.ma_dvi=bt.ma_dvi and nv.so_id=bt.so_id
        and dp.ma_dvi=bt.ma_dvi and dp.so_id=bt.so_id and dp.ngay=nv.ngay_dp
        and ngay_qd>ts.ngayc;

end if;

--  lam ho don vi khac
IF PKH_MA_MA(B_TC,'H') OR PKH_MA_MA(B_TC,'*') THEN
INSERT INTO TEMP_BT_1(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,SO_ID_DT,C1,C4,N6)
SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,BT.so_id_hd,NV.TIEN,NV.TIEN_QD,NV.SO_ID_DT,'H',BT.MA_DVI_QL,(BT.NGAY_QD)
    FROM BH_BT_HS BT,BH_BT_HS_NV NV,TEMP_BC_TS TS
    WHERE BT.MA_DVI_XL<>BT.MA_DVI_QL AND BT.MA_DVI=TS.MA_DVI
        AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
        AND BT.MA_DVI=MA_DVI_XL
        AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
        AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) not in ('V','N')
        AND ngay_qd>TS.NGAYC;
END IF;

--delete from temp_bt_1 where SUBSTR(lh_nv,1,2) not in (Select nv from temp_bc_nv) and c3 not in (Select phong from temp_bc_phong);
--BCNam
update TEMP_BT_1 set c3 = (select max(phong) from bh_hd_goc goc where goc.ma_dvi=ma_dvi and goc.so_id=n3);
end;
/
-- chuclh: hotfix
DROP PROCEDURE PBC_BH_BT_CQG_SUA;

CREATE OR REPLACE PROCEDURE PBC_BH_BT_CQG_SUA(B_TC VARCHAR2)
AS
BEGIN
IF PKH_MA_MA(B_TC,'T') OR PKH_MA_MA(B_TC,'*') THEN
/*
    INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
        SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'T',BT.MA_DVI_QL,PKH_NG_CSO(BT.NGAY_QD)
            FROM BH_BT_HS BT,BH_BT_HS_DP NV,
                (SELECT A.MA_DVI,A.SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP A,TEMP_BC_TS T
                  WHERE A.MA_DVI=T.MA_DVI AND ROUND(NGAY_DP,-2)<=ROUND(T.NGAYC,-2) AND LH_NV IS NOT NULL GROUP BY A.MA_DVI,A.SO_ID) DP,
                    TEMP_BC_TS TS
            WHERE BT.MA_DVI=TS.MA_DVI AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
                AND BT.MA_DVI_XL=BT.MA_DVI_QL
                AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) NOT IN ('V','N')
                AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
                AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
                AND TO_CHAR(BT.NGAY_QD,'yyyymmdd')>TS.NGAYC;
*/
--        INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
--        SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'T',BT.MA_DVI_QL,PKH_NG_CSO(BT.NGAY_QD)
--            FROM BH_BT_HS BT,BH_BT_HS_DP NV,
--                (SELECT A.MA_DVI,A.SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP A,TEMP_BC_TS T
--                  WHERE A.MA_DVI=T.MA_DVI AND ROUND(NGAY_DP,-2)<=ROUND(T.NGAYC,-2) AND LH_NV IS NOT NULL GROUP BY A.MA_DVI,A.SO_ID) DP,
--                    TEMP_BC_TS TS
--            WHERE BT.MA_DVI=TS.MA_DVI AND TO_CHAR(BT.NGAY_QD,'yyyymmdd')>TS.NGAYC and BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
--                AND BT.MA_DVI_XL=BT.MA_DVI_QL
--                AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) NOT IN ('V','N')
--                AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
--                AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP;

    EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_m_3';--delete temp_m_3;
    insert into temp_m_3(c1,c2,c3,c4,n1,n2,n3,n4,n5,c5,c6,n7,n8,n9)
    SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,ct.LH_NV,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'T',BT.MA_DVI_QL,(BT.NGAY_QD),BT.SO_ID_HD,nv.NGAY_DP
    from BH_BT_HS BT,BH_BT_HS_DP NV,TEMP_BC_TS TS, bh_bt_hs_dp_ct ct
    where
    BT.MA_DVI=TS.MA_DVI
    --AND BT.NGAY_QD > to_date(TS.NGAYC,'yyyyMMdd')
    and ngay_qd > ts.ngayc
    and BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
    AND BT.MA_DVI_XL=BT.MA_DVI_QL
    AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    and BT.ma_dvi=ct.ma_dvi and BT.so_id=ct.so_id;
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BT_3';
    --delete TEMP_BT_3;
    insert into TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,c6)
    select distinct c1,c2,c3,c4,n1,n2,n3,n4,n5,c5,c6,n7--,n8,n9
    from temp_m_3,(SELECT A.MA_DVI,A.SO_ID,MAX(a.NGAY_DP) NGAY_DP FROM BH_BT_HS_DP A,TEMP_BC_TS T,bh_bt_hs_dp_ct ct
      WHERE A.MA_DVI=T.MA_DVI and a.ma_dvi=ct.ma_dvi and a.so_id=ct.so_id AND ROUND(A.NGAY_DP,-2)<=ROUND(T.NGAYC,-2) AND LH_NV IS NOT NULL GROUP BY A.MA_DVI,A.SO_ID) DP
    where
    c1=DP.MA_DVI AND n1=DP.SO_ID AND n9=DP.NGAY_DP
    AND FBH_HD_KIEU_HD(c6,n8) NOT IN ('V','N');--
END IF;

IF PKH_MA_MA(B_TC,'N') OR PKH_MA_MA(B_TC,'*') OR PKH_MA_MA(B_TC,'T') THEN
/*
    INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
        SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'N',BT.MA_DVI_QL,PKH_NG_CSO(BT.NGAY_QD)
            FROM BH_BT_HS BT,BH_BT_HS_DP NV,
                (SELECT A.MA_DVI,A.SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP A,TEMP_BC_TS T
                  WHERE A.MA_DVI=T.MA_DVI AND ROUND(NGAY_DP,-2)<=ROUND(T.NGAYC,-2) AND LH_NV IS NOT NULL GROUP BY A.MA_DVI,A.SO_ID) DP,
                TEMP_BC_TS TS
            WHERE
                BT.MA_DVI=TS.MA_DVI AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
                AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) NOT IN ('V','N')
                AND BT.MA_DVI_XL<>BT.MA_DVI_QL  AND BT.MA_DVI=MA_DVI_QL
                AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
                AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP
                AND TO_CHAR(NGAY_QD,'yyyymmdd')>TS.NGAYC;
*/
--    INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
--        SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'N',BT.MA_DVI_QL,PKH_NG_CSO(BT.NGAY_QD)
--            FROM BH_BT_HS BT,BH_BT_HS_DP NV,
--                (SELECT A.MA_DVI,A.SO_ID,MAX(NGAY_DP) NGAY_DP FROM BH_BT_HS_DP A,TEMP_BC_TS T
--                  WHERE A.MA_DVI=T.MA_DVI AND ROUND(NGAY_DP,-2)<=ROUND(T.NGAYC,-2) AND LH_NV IS NOT NULL GROUP BY A.MA_DVI,A.SO_ID) DP,
--                TEMP_BC_TS TS
--            WHERE
--                BT.MA_DVI=TS.MA_DVI AND TO_CHAR(NGAY_QD,'yyyymmdd')>TS.NGAYC AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
--                AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) NOT IN ('V','N')
--                AND BT.MA_DVI_XL<>BT.MA_DVI_QL  AND BT.MA_DVI=MA_DVI_QL
--                AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
--                AND BT.MA_DVI=DP.MA_DVI AND BT.SO_ID=DP.SO_ID AND NV.NGAY_DP=DP.NGAY_DP;

    --delete TEMP_5;
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_5';
    insert into TEMP_5(C1,C2,C3,N1,N2,N3,N4,N5)
    select  BT.MA_DVI,BT.NV,BT.PHONG,BT.SO_ID,BT.NGAY_HT,BT.MA_DVI_QL,(BT.NGAY_QD), SO_ID_HD
    from BH_BT_HS BT, TEMP_BC_TS TS
    WHERE BT.MA_DVI=TS.MA_DVI AND ngay_qd>TS.NGAYC AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
    AND BT.MA_DVI_XL<>BT.MA_DVI_QL  AND BT.MA_DVI=MA_DVI_QL;
    INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
    select  distinct C1 as MA_DVI,C2 as NV,C3 as PHONG,LH_NV,N1 as SO_ID,N2 as NGAY_HT,NV.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'T',N3 as MA_DVI_QL,N4 as NGAY_QD
    from TEMP_5,BH_BT_HS_DP NV,(SELECT A.MA_DVI,A.SO_ID,MAX(A.NGAY_DP) NGAY_DP,ct.LH_NV FROM BH_BT_HS_DP A,TEMP_BC_TS T,bh_bt_hs_dp_ct ct
                      WHERE A.MA_DVI=T.MA_DVI and a.ma_dvi=ct.ma_dvi and a.so_id=ct.so_id and a.ma_dvi=ct.ma_dvi and a.so_id=ct.so_id AND ROUND(A.NGAY_DP,-2)<=ROUND(T.NGAYC,-2) AND LH_NV IS NOT NULL GROUP BY A.MA_DVI,A.SO_ID,ct.LH_NV) DP
    WHERE
    FBH_HD_KIEU_HD(N3,N5) NOT IN ('V','N')
    AND C1=NV.MA_DVI AND N1=NV.SO_ID
                    AND C1=DP.MA_DVI AND N1=DP.SO_ID
                    AND NV.NGAY_DP=DP.NGAY_DP;

END IF;
IF PKH_MA_MA(B_TC,'H') OR PKH_MA_MA(B_TC,'*') THEN
/*
    INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
        SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,NV.SO_ID_BS,NV.TIEN,NV.TIEN_QD,'H',BT.MA_DVI_QL,PKH_NG_CSO(BT.NGAY_QD)
            FROM BH_BT_HS BT,BH_BT_HS_NV NV,TEMP_BC_TS TS
            WHERE
                BT.MA_DVI=TS.MA_DVI AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
                AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) NOT IN ('V','N')
                AND BT.MA_DVI_XL<>BT.MA_DVI_QL AND BT.MA_DVI=BT.MA_DVI_XL
                AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
                AND TO_CHAR(NGAY_QD,'yyyymmdd')>TS.NGAYC;
*/
    INSERT INTO TEMP_BT_3(MA_DVI,C2,C3,LH_NV,SO_ID,N2,N3,N4,N5,C1,C4,N6)
        SELECT DISTINCT BT.MA_DVI,BT.NV,BT.PHONG,LH_NV,BT.SO_ID,BT.NGAY_HT,BT.SO_ID_HD,NV.TIEN,NV.TIEN_QD,'H',BT.MA_DVI_QL,(BT.NGAY_QD)
            FROM BH_BT_HS BT,BH_BT_HS_NV NV,TEMP_BC_TS TS
            WHERE
                BT.MA_DVI=TS.MA_DVI AND ngay_qd>TS.NGAYC AND BT.NGAY_HT BETWEEN TS.NGAYD AND TS.NGAYC
                AND FBH_HD_KIEU_HD(BT.MA_DVI_QL,BT.SO_ID_HD) NOT IN ('V','N')
                AND BT.MA_DVI_XL<>BT.MA_DVI_QL AND BT.MA_DVI=BT.MA_DVI_XL
                AND BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID;

END IF;
UPDATE TEMP_BT_3 SET C3 = (SELECT MAX(PHONG) FROM BH_HD_GOC GOC WHERE GOC.MA_DVI=MA_DVI AND GOC.SO_ID=N3);
END;
/

DROP PROCEDURE PBC_BH_BT_NAM;

CREATE OR REPLACE PROCEDURE PBC_BH_BT_NAM
     (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_MA_NV VARCHAR2,B_PHONG VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_NGUON VARCHAR2, B_MA_DT VARCHAR2,B_MA_DL VARCHAR2,B_TC VARCHAR2,
    B_NGAYD_HD NUMBER,B_NGAYC_HD NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_I1 NUMBER;
BEGIN
B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE BC_BH_BT_TEMP;DELETE KET_QUA; COMMIT;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;
DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,B_NGAYD,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

PBC_BH_TH_BT_PB_MD(B_TC);
INSERT INTO BC_BH_BT_TEMP (NV,MA_DVI,LH_NV,PHONG,N1,SO_ID,NGAY_HT,SO_ID_HD,MA_DVI_HD) 
                      SELECT  NV,MA_DVI,LH_NV,PHONG,TIEN_QD,SO_ID,NGAY_HT,SO_ID_HD,MA_DVI_HD FROM BC_BH_BT_HS_TEMP 
                        WHERE NGAY_QD_N<30000101 AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC AND (B_PHONG IS NULL OR PHONG=B_PHONG)
                            AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%');
DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,20000101,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;                                    

PBC_BH_BT_CGQ_MD(B_TC);
INSERT INTO BC_BH_BT_TEMP (NV,MA_DVI,LH_NV,PHONG,N2,SO_ID,NGAY_HT,SO_ID_HD,MA_DVI_HD) 
                      SELECT C2,MA_DVI,LH_NV,C3,N5,SO_ID,N2,N3,C4 FROM TEMP_BT_1 
                        WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%'); 

DELETE BC_BH_BT_TEMP WHERE NGAY_HT NOT BETWEEN B_NGAYD AND B_NGAYC;
UPDATE BC_BH_BT_TEMP T1 SET (N3,C1,C8,C9,C10,C11)=(SELECT NGAY_HT,SO_HD,MA_KH,MA_KT,KIEU_KT,CB_QL FROM BH_HD_GOC WHERE MA_DVI=T1.MA_DVI_HD AND SO_ID=T1.SO_ID_HD);
UPDATE BC_BH_BT_TEMP T1 SET C12=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=T1.MA_DVI_HD AND MA=T1.C8);
DELETE BC_BH_BT_TEMP WHERE N3 NOT BETWEEN B_NGAYD_HD AND B_NGAYC_HD;
UPDATE BC_BH_BT_TEMP T1 SET (C2,C3,C4)=(SELECT PKH_SO_CNG(NGAY_XR),PKH_SO_CNG(NGAY_GUI),SO_HS FROM BH_BT_HS
                                        WHERE MA_DVI=T1.MA_DVI AND SO_ID=T1.SO_ID);
UPDATE BC_BH_BT_TEMP T1 SET N4=SUBSTR(N3,0,4); 
UPDATE BC_BH_BT_TEMP T1 SET N5=NVL(N1,0)+NVL(N2,0);
UPDATE BC_BH_BT_TEMP T1 SET C5=(SELECT TEN FROM HT_MA_DVI WHERE MA=T1.MA_DVI);
UPDATE BC_BH_BT_TEMP T1 SET C6=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=T1.MA_DVI AND MA=T1.PHONG);
IF B_LOAI_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C12<> B_LOAI_KH;
END IF;
IF B_MA_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C8<> B_MA_KH;
END IF;
IF B_MA_CB IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C11<> B_MA_CB;
END IF;
IF B_MA_DL IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C9<> B_MA_DL AND C10 NOT IN('D','M');
END IF;
DELETE KET_QUA;                                     
INSERT INTO KET_QUA(C1,C2,C3,C4,C5,C6,C7,N1,N2,N3,N4)
    SELECT MA_DVI,C2,C3,C4,C1,C5,C6,SUM(N1),SUM(N2),SUM(N5),N4 FROM BC_BH_BT_TEMP GROUP BY MA_DVI,C2,C3,C4,C1,C5,C6,N4; 
       
OPEN CS_KQ FOR SELECT C1 MA_DVI,C2 NGAY_XR,C3 NGAY_MO,C4 SO_HS,C5 SO_HD,C6 TEN_DVI,C7 TEN_PHONG,N1 TIEN_GQ,
                                N2 TIEN_TD,N3 TIEN_TONG,ROUND(N4) NAM,N5 STT FROM KET_QUA;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE PBC_BH_BT_QT_DVI;

CREATE OR REPLACE PROCEDURE PBC_BH_BT_QT_DVI
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_NV VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,
    B_TC VARCHAR2,B_NGAYD_LK NUMBER,B_NGAYC_LK NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_NGAYNT NUMBER;B_I1 NUMBER;
    B_NGAY_C NUMBER; B_D1 NUMBER; B_D2 NUMBER;B_NGAYD_NT NUMBER;B_NGAYC_NT NUMBER;
    B_NGAYD_LK_NT NUMBER;B_NGAYC_LK_NT NUMBER;B_MA_VP VARCHAR2(10);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');

IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;


IF FHT_MA_NSD_PHONG(B_MA_DVI,B_NSD)='TBH' THEN
    B_LOI:='loi:ban khong co quyen xem bao cao:loi';
    RAISE PROGRAM_ERROR;
END IF;


IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYD_NT:=ROUND(B_NGAYD)-10000;
B_NGAYC_NT:=ROUND(B_NGAYC)-10000;



B_NGAYDN:=ROUND(B_NGAYC,-4)+101;

B_NGAYD_LK_NT:=20000101;
B_NGAYC_LK_NT:=B_NGAYC;

B_LOI:='loi:Ma chua dang ky:loi';
DELETE BC_BH_BT_TEMP;DELETE KET_QUA; COMMIT;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYNT:=ROUND(B_NGAYC,-4)-10000 +1231;

DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,B_NGAYD,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;


INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,N25,SO_ID_HD,MA_DVI_HD, LH_NV) SELECT A.MA_DVI,A.PHONG,SUM(PHI),A.SO_ID,A.MA_DVIG, A.LH_NV
    FROM V_BC_BH_DTBH_MM A WHERE (B_PHONG IS NULL OR PHONG=B_PHONG)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%') AND SUBSTR(LH_NV,1,2) IN (SELECT NV FROM TEMP_BC_NV)
    GROUP BY A.MA_DVI,A.PHONG,A.SO_ID,A.MA_DVIG, A.LH_NV;




PBC_BH_TH_BT_PB_MD('T');







INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,N17,NGAY_HT,SO_ID_HD,MA_DVI_HD, LH_NV)
                SELECT MA_DVI,PHONG,SUM(TIEN_QD),NGAY_HT,SO_ID_HD,MA_DVI_HD, LH_NV FROM BC_BH_BT_HS_TEMP
                WHERE NGAY_QD_N<30000101 AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
                    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%') GROUP BY MA_DVI,PHONG,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV;

PBC_BH_BT_CGQ_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,N4,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                SELECT MA_DVI,C3,SUM(N5),N2,N3,C4, LH_NV FROM TEMP_BT_1
                WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND  (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
                                    GROUP BY MA_DVI,C3,N2,N3,C4,LH_NV;

DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,B_NGAYDN,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;


IF B_NGAYD=B_NGAYDN THEN
    UPDATE BC_BH_BT_TEMP SET N1=N25;
ELSE
    INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,N1,SO_ID_HD,MA_DVI_HD,LH_NV) SELECT A.MA_DVI,A.PHONG,SUM(PHI),A.SO_ID,A.MA_DVIG,LH_NV
        FROM V_BC_BH_DTBH_MM A WHERE (B_PHONG IS NULL OR PHONG=B_PHONG)
        AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%') AND SUBSTR(LH_NV,1,2) IN (SELECT NV FROM TEMP_BC_NV)
        GROUP BY A.MA_DVI,A.PHONG,A.SO_ID,A.MA_DVIG,LH_NV;
END IF;

PBC_BH_TH_BT_PB_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,N3,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                SELECT MA_DVI,PHONG,SUM(TIEN_QD),NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV FROM BC_BH_BT_HS_TEMP
                WHERE NGAY_QD_N<30000101 AND (B_PHONG IS NULL OR PHONG=B_PHONG) 
                    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%') GROUP BY MA_DVI,PHONG,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV;
DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,20000101,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

PBC_BH_BT_CGQ_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,N5,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                SELECT MA_DVI,C3,SUM(N5),N2,N3,C4,LH_NV FROM TEMP_BT_1
                WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
                                    GROUP BY MA_DVI,C3,N2,N3,C4,LH_NV;

--UPDATE BC_BH_BT_TEMP SET MA_DVI='0010' WHERE MA_DVI='001' AND LH_NV='CN.3.6';


UPDATE BC_BH_BT_TEMP SET N6=NVL(N2,0)+NVL(N4,0),N7=NVL(N3,0)+NVL(N5,0),N26=NVL(N21,0)+NVL(N23,0),N27=NVL(N22,0)+NVL(N24,0);
UPDATE BC_BH_BT_TEMP SET N15=NVL(N5,0) WHERE TO_NUMBER(SUBSTR(TO_CHAR(N12),1,4))<=TO_NUMBER(SUBSTR(TO_CHAR(B_NGAYNT),1,4));
UPDATE BC_BH_BT_TEMP SET N16=NVL(N2,0) WHERE TO_NUMBER(SUBSTR(TO_CHAR(N14),1,4))<=TO_NUMBER(SUBSTR(TO_CHAR(B_NGAYNT),1,4));
UPDATE BC_BH_BT_TEMP T1 SET C30=(SELECT TEN FROM HT_MA_DVI WHERE MA= T1.MA_DVI);


UPDATE BC_BH_BT_TEMP T1 SET C14=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=T1.MA_DVI AND MA= T1.PHONG);
UPDATE BC_BH_BT_TEMP T1 SET (C1,C2,C3,C5)=(SELECT MA_KH,MA_KT,KIEU_KT,CB_QL FROM BH_HD_GOC WHERE MA_DVI=T1.MA_DVI_HD AND SO_ID=T1.SO_ID_HD);
UPDATE BC_BH_BT_TEMP T1 SET C4=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=T1.MA_DVI_HD AND MA=T1.C1);
IF B_LOAI_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C4<> B_LOAI_KH;
END IF;
IF B_MA_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C1<> B_MA_KH;
END IF;
IF B_MA_CB IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C5<> B_MA_CB;
END IF;
IF B_MA_DL IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C2<> B_MA_DL AND C3 NOT IN('D','M');
END IF;
SELECT MA INTO B_MA_VP FROM HT_MA_DVI WHERE VP='C' AND ROWNUM=1;

INSERT INTO KET_QUA( N20,C20,C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27)
    SELECT 1,'A',MA_DVI,C30,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),SUM(NVL(N5,0)),
    SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),SUM(NVL(N18,0)),SUM(NVL(N19,0)),
    SUM(NVL(N25,0)),SUM(NVL(N26,0)),SUM(NVL(N27,0))
    FROM BC_BH_BT_TEMP WHERE MA_DVI=B_MA_VP GROUP BY MA_DVI,C30;

DELETE TEMP_4;
INSERT INTO TEMP_4( N20,C20,C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27)
    SELECT 2,'',PHONG,C14,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),
    SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),SUM(NVL(N18,0)),
    SUM(NVL(N19,0)),SUM(NVL(N25,0)),SUM(NVL(N26,0)),SUM(NVL(N27,0))
    FROM BC_BH_BT_TEMP WHERE MA_DVI=B_MA_VP GROUP BY PHONG,C14 ORDER BY PHONG ;
INSERT INTO KET_QUA( N20,C20,C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27)
    SELECT N20,TO_CHAR(ROWNUM),C29,C30,NVL(N1,0),NVL(N2,0),NVL(N3,0),NVL(N4,0),NVL(N5,0),
    NVL(N6,0),NVL(N7,0),NVL(N8,0),NVL(N15,0),NVL(N16,0),NVL(N17,0),NVL(N18,0),NVL(N19,0),
    NVL(N25,0),NVL(N26,0),NVL(N27,0) FROM TEMP_4;

INSERT INTO KET_QUA( N20,C20,C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27)
    SELECT 3,'B','',U'C\00E1c chi nh\00E1nh',SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),
    SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),SUM(NVL(N18,0)),
    SUM(NVL(N19,0)),SUM(NVL(N25,0)),SUM(NVL(N26,0)),SUM(NVL(N27,0))
    FROM BC_BH_BT_TEMP WHERE MA_DVI<>B_MA_VP;



DELETE TEMP_4;
INSERT INTO TEMP_4( N20,C20,C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27)
    SELECT 4,'',MA_DVI,C30,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),SUM(NVL(N5,0)),
    SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),SUM(NVL(N18,0)),
    SUM(NVL(N19,0)),SUM(NVL(N25,0)),SUM(NVL(N26,0)),SUM(NVL(N27,0))
    FROM BC_BH_BT_TEMP WHERE MA_DVI<>B_MA_VP GROUP BY MA_DVI,C30 ORDER BY MA_DVI;



INSERT INTO KET_QUA( N20,C20,C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27)
    SELECT  N20,TO_CHAR(ROWNUM),C29,C30,N1,N2,N3,N4,N5,N6,N7,N8,N15,N16,N17,N18,N19,N25,N26,N27 FROM TEMP_4;


UPDATE KET_QUA SET N28=NVL(N17,0)+NVL(N4,0);

--UPDATE KET_QUA SET C30=(SELECT MAX(TEN_GON) FROM HT_MA_DVI WHERE MA=C29) WHERE N20=4;
--UPDATE KET_QUA SET C30='MIC - HCM bao hiem suc khoe nhom va tai nan nhom' WHERE C29='0010';


COMMIT;
OPEN CS_KQ FOR SELECT C20 CT,C29 MA_DVI,C30 TEN_DVI,
        NVL(N1,0) DTBH_LK,NVL(N2,0) TIEN_GQ_TK,NVL(N4,0) TIEN_TD_TK,NVL(N6,0) TIEN_TK,NVL(N3,0) TIEN_GQ_LK,
        NVL(N5,0) TIEN_TD_LK,NVL(N7,0) TIEN_LK,NVL(N8,0) TIEN_UNT,NVL(N15,0) TIEN_XRNT,NVL(N16,0) TIEN_GQ_TKNT,
        NVL(N17,0) TIEN_GQTK_HT,NVL(N18,0) TIEN_GQTK_XR,NVL(N19,0) TIEN_UTK_XR,NVL(N25,0) DTBH,
        DECODE(NVL(N25,0),0,0,ROUND(ROUND(N6/N25,4)*100,2)) DT_PT,
        DECODE(NVL(N1,0),0,0,ROUND(ROUND(N7/N1,4)*100,2)) DT_LK_PT,
        DECODE(NVL(N26,0),0,0,ROUND(ROUND(N6/N26,4)*100,2)) PT,
        DECODE(NVL(N27,0),0,0,ROUND(ROUND(N7/N27,4)*100,2)) LK_PT,
        N28 TIEN_TK_HT,N26 TIEN_PT,
        DECODE(NVL(N25,0),0,0,ROUND(ROUND(N28/N25,4)*100,2)) DT_PT_HT
        FROM KET_QUA ORDER BY N20,C29;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE PBC_BH_BT_QT_NV;

CREATE OR REPLACE PROCEDURE PBC_BH_BT_QT_NV
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_NV VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_TC VARCHAR2,
    B_NGAYD_LK NUMBER,B_NGAYC_LK NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_NGAYNT NUMBER; B_I1 NUMBER;
    B_NGAYD_NT NUMBER;B_NGAYC_NT NUMBER;B_NGAYD_LK_NT NUMBER;B_NGAYC_LK_NT NUMBER;
BEGIN


B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');

IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;


IF FHT_MA_NSD_PHONG(B_MA_DVI,B_NSD)='TBH' THEN
    B_LOI:='loi:ban khong co quyen xem bao cao:loi';
    RAISE PROGRAM_ERROR;
END IF;

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;
B_NGAYD_LK_NT:=ROUND(B_NGAYD_LK)-10000;
B_NGAYC_LK_NT:=ROUND(B_NGAYC_LK)-10000;
B_NGAYD_NT:=ROUND(B_NGAYD)-10000;
B_NGAYC_NT:=ROUND(B_NGAYC)-10000;

B_LOI:='loi:Ma chua dang ky:loi';
DELETE BC_BH_BT_TEMP;DELETE KET_QUA; COMMIT;
B_NGAYNT:=ROUND(B_NGAYC,-4)-10000 +1231;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;

DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,B_NGAYD,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
INSERT INTO BC_BH_BT_TEMP (MA_DVI,LH_NV,PHONG,SO_ID_HD,MA_DVI_HD,N25) SELECT A.MA_DVI,LH_NV,PHONG,SO_ID,MA_DVIG,SUM(PHI)
    FROM V_BC_BH_DTBH_MM A WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
    AND SUBSTR(LH_NV,1,2) IN (SELECT NV FROM TEMP_BC_NV)
    GROUP BY A.MA_DVI,LH_NV,PHONG,SO_ID,MA_DVIG;

PBC_BH_TH_BT_PB_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,LH_NV,PHONG,N16,SO_ID_HD,MA_DVI_HD)
                SELECT MA_DVI,LH_NV,PHONG,SUM(TIEN_QD),SO_ID_HD,MA_DVI_HD FROM BC_BH_BT_HS_TEMP
                WHERE NGAY_QD_N<30000101 AND NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
                    AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
                GROUP BY MA_DVI,LH_NV,PHONG,SO_ID_HD,MA_DVI_HD;

PBC_BH_BT_CGQ_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,LH_NV,PHONG,N4,SO_ID_HD,MA_DVI_HD)
                SELECT MA_DVI,LH_NV,C3,SUM(N5),N3,C4 FROM TEMP_BT_1
                WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
                GROUP BY MA_DVI,LH_NV,C3,N3,C4;

DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,B_NGAYDN,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
INSERT INTO BC_BH_BT_TEMP (MA_DVI,LH_NV,PHONG,SO_ID_HD,MA_DVI_HD,N1) SELECT A.MA_DVI,LH_NV,PHONG,SO_ID,MA_DVIG,SUM(PHI)
    FROM V_BC_BH_DTBH_MM A WHERE (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_KH IS NULL OR MA_KH=B_MA_KH)
    AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%') AND SUBSTR(LH_NV,1,2) IN (SELECT NV FROM TEMP_BC_NV)
    GROUP BY A.MA_DVI,LH_NV,PHONG,SO_ID,MA_DVIG;



PBC_BH_TH_BT_PB_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,LH_NV,PHONG,N3,SO_ID_HD,MA_DVI_HD)
                SELECT MA_DVI,LH_NV,PHONG,SUM(TIEN_QD),SO_ID_HD,MA_DVI_HD FROM BC_BH_BT_HS_TEMP
                WHERE NGAY_QD_N<30000101 AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
                GROUP BY MA_DVI,LH_NV,PHONG,SO_ID_HD,MA_DVI_HD;


DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,20000101,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

PBC_BH_BT_CGQ_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,LH_NV,PHONG,N5,SO_ID_HD,MA_DVI_HD)
                SELECT MA_DVI,LH_NV,C3,SUM(N5),N3,C4 FROM TEMP_BT_1
                WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%')
                GROUP BY MA_DVI,LH_NV,C3,N3,C4;

UPDATE BC_BH_BT_TEMP SET N1=NVL(N1,0),N2=NVL(N2,0),N3=NVL(N3,0),N4=NVL(N4,0),N5=NVL(N5,0),
                    N21=NVL(N21,0),N22=NVL(N22,0),N23=NVL(N23,0),N24=NVL(N24,0),N16=NVL(N16,0);
UPDATE BC_BH_BT_TEMP SET N6=N2+N4,N7=N3+N5,N25=N21+N23,N26=N22+N24,N17=N4;
UPDATE BC_BH_BT_TEMP T1 SET (C1,C2,C3,C5)=(SELECT MA_KH,MA_KT,KIEU_KT,CB_QL FROM BH_HD_GOC WHERE MA_DVI=T1.MA_DVI_HD AND SO_ID=T1.SO_ID_HD);
UPDATE BC_BH_BT_TEMP T1 SET C4=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=T1.MA_DVI_HD AND MA=T1.C1);
IF B_LOAI_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C4<> B_LOAI_KH;
END IF;
IF B_MA_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C1<> B_MA_KH;
END IF;
IF B_MA_CB IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C5<> B_MA_CB;
END IF;
IF B_MA_DL IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C2<> B_MA_DL AND C3 NOT IN('D','M');
END IF;


--    INSERT INTO KET_QUA(C1,C11,C20,N30) SELECT MA,TEN,TC,(CASE SUBSTR(MA,1,2) WHEN 'XG' THEN 1 ELSE (CASE SUBSTR(MA,1,2) WHEN 'CN' THEN 2 ELSE
--        (CASE SUBSTR(MA,1,2) WHEN 'HH' THEN 3 ELSE (CASE SUBSTR(MA,1,2) WHEN 'TT' THEN 4 ELSE
--        (CASE SUBSTR(MA,1,2) WHEN 'TS' THEN 5 ELSE (CASE SUBSTR(MA,1,2) WHEN 'HP' THEN 6 ELSE
--        (CASE SUBSTR(MA,1,2) WHEN 'TN' THEN 7 ELSE 0 END)  END) END) END) END) END) END) FROM BH_MA_LHNV WHERE MA_DVI=B_MADVI AND TC='T';
--    UPDATE KET_QUA KQ
--        SET (N1,N2,N3,N4,N5,N6,N7,N8,N14,N15,N16,N17,N20,N25,N26) =(SELECT SUM(NVL(N1,0)),SUM(NVL(N2,0)),
--    SUM(NVL(N3,0)),SUM(NVL(N4,0)),SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),
--    SUM(NVL(N14,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),SUM(NVL(N20,0)),SUM(NVL(N25,0)),SUM(NVL(N26,0))
--    FROM BC_BH_BT_TEMP T WHERE T.LH_NV LIKE TRIM(KQ.C1)||'%');


DELETE KET_QUA WHERE NVL(N1,0)=0 AND NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N4,0)=0 AND NVL(N5,0)=0 AND NVL(N6,0)=0 AND NVL(N7,0)=0 AND NVL(N8,0)=0;
INSERT INTO KET_QUA( C20,C1,N1,N2,N3,N4,N5,N6,N7,N8,N14,N15,N16,N17,N20,N25,N26,N30)
    SELECT 'C',LH_NV,SUM(NVL(N1,0)),SUM(NVL(N2,0)),SUM(NVL(N3,0)),SUM(NVL(N4,0)),
    SUM(NVL(N5,0)),SUM(NVL(N6,0)),SUM(NVL(N7,0)),SUM(NVL(N8,0)),SUM(NVL(N14,0)),SUM(NVL(N15,0)),SUM(NVL(N16,0)),SUM(NVL(N17,0)),
    SUM(NVL(N20,0)),SUM(NVL(N25,0)),SUM(NVL(N26,0)),
    LH_NV
    FROM BC_BH_BT_TEMP GROUP BY LH_NV;
UPDATE KET_QUA SET C11=(SELECT '-'||TEN FROM BH_MA_LHNV WHERE MA=KET_QUA.C1) WHERE C20='C';

COMMIT;
    OPEN CS_KQ FOR SELECT C20 TC,C29 MA_DVI,C30 TEN_DVI,C1 MA_NV,C11 TEN_NV,C2 SO_HD,C3 MA_KH,
        C13 TEN_KH,C4 PHONG,C14 TEN_PHONG,C5 LOAI_KH,C15 TEN_LOAI,N1 DTBH_LK,N2 TIEN_GQ_TK,
        N4 TIEN_TD_TK,N6 TIEN_TK,N3 TIEN_GQ_LK,N5 TIEN_TD_LK,N7 TIEN_LK,N8 TIEN_UNT,
        N14  TIEN_GQNT,N15  TIEN_UCLNT,N16 TIEN_GQPSTK,N17 TIEN_UCLTK,N20 DTBH,DECODE(NVL(N20,0),0,0,ROUND(N6/N20,2)) DT_PT,
        DECODE(NVL(N1,0),0,0,ROUND(N3/N1,2)) DT_LK_PT,DECODE(NVL(N25,0),0,0,ROUND(N6/N25,2)) PT,
        DECODE(NVL(N26,0),0,0,ROUND(N7/N26,2)) LK_PT
        FROM KET_QUA ORDER BY N30,C1;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP PROCEDURE PBC_BH_BT_TD_NVXE;
CREATE OR REPLACE PROCEDURE PBC_BH_BT_TD_NVXE
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,
    B_MA_DVI VARCHAR2,B_PHONG VARCHAR2,B_MA_NV VARCHAR2,B_LOAI_KH VARCHAR2,
    B_MA_KH VARCHAR2,B_MA_CB VARCHAR2,B_MA_DL VARCHAR2,B_HD VARCHAR2,B_TC VARCHAR2,
    B_NGAYD_LK NUMBER,B_NGAYC_LK NUMBER,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_I1 NUMBER;
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_LOI:='loi:Ma chua dang ky:loi';
DELETE BC_BH_BT_TEMP;COMMIT;
PBC_LAY_NV(B_MADVI,B_MA_DVI,B_NSD,B_PAS,B_PHONG);
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;
DELETE TEMP_BC_TS;
PBC_BH_TS(B_MADVI,B_NSD,B_MA_DVI,B_NGAYD,B_NGAYC,B_LOI);
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
PBC_BH_BT_CGQ_MD(B_TC);
DELETE TEMP_BT_1 WHERE (C2<>'XE' AND C2 <>'XEL' AND C2<>'2B' AND C2<>'2BL');
INSERT INTO BC_BH_BT_TEMP(MA_DVI,SO_ID,NV,PHONG,LH_NV,NGAY_QD_N,MA_DVI_HD,SO_ID_HD,SO_ID_DT,TIEN,TIEN_QD,NGAY_HT,TC)
SELECT MA_DVI,SO_ID,C2,C3,LH_NV,N6,C4,N3,SO_ID_DT,N4,N5,N2,C1 FROM TEMP_BT_1  
    WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND (B_MA_NV IS NULL OR LH_NV LIKE B_MA_NV ||'%');
UPDATE BC_BH_BT_TEMP T1 SET (C4,C5,C18,C3,C6)=
                (SELECT SO_HD,MA_KH,CB_QL,MA_KT,KIEU_KT FROM BH_HD_GOC G WHERE G.MA_DVI=T1.MA_DVI_HD AND G.SO_ID=T1.SO_ID_HD AND ROWNUM=1);
--UPDATE BC_BH_BT_TEMP T1 SET C8=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=T1.MA_DVI_HD AND MA=T1.C1); 
update
    (select bc_bh_bt_temp.c8 bc_bh_bt_temp_c8, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
        from bc_bh_bt_temp, bh_hd_ma_kh
        where bc_bh_bt_temp.ma_dvi_hd = bh_hd_ma_kh.ma_dvi and bc_bh_bt_temp.c1 = bh_hd_ma_kh.ma)
    set bc_bh_bt_temp_c8 = bh_hd_ma_kh_loai;
      
UPDATE BC_BH_BT_TEMP T1 SET (C2,C7,C19)=(SELECT SO_HS,PKH_SO_CNG(NGAY_XR),PKH_SO_CNG(NGAY_GUI) FROM BH_BT_HS BT
                                    WHERE BT.MA_DVI=T1.MA_DVI AND BT.SO_ID=T1.SO_ID);
UPDATE BC_BH_BT_TEMP T1 SET (C22,C23) =(SELECT DISTINCT GCN,BIEN_XE FROM BH_XE_DS A,BH_BT_HS_NV B 
    WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID_DT=B.SO_ID_DT AND A.MA_DVI=T1.MA_DVI_HD
    AND A.SO_ID=FBH_HD_SO_ID_BS(T1.MA_DVI_HD,T1.SO_ID_HD,30000101) AND B.SO_ID=T1.SO_ID AND ROWNUM=1) WHERE T1.NV='XE';
UPDATE BC_BH_BT_TEMP T1 SET (C22,C23) =(SELECT DISTINCT GCN,BIEN_XE FROM BH_2B_DS A,BH_BT_HS_NV B 
    WHERE A.MA_DVI=B.MA_DVI AND A.SO_ID_DT=B.SO_ID_DT AND A.MA_DVI=T1.MA_DVI_HD
    AND A.SO_ID=FBH_HD_SO_ID_BS(T1.MA_DVI_HD,T1.SO_ID_HD,30000101) AND B.SO_ID=T1.SO_ID AND ROWNUM=1) WHERE C30='2B';
BC_BH_THGD_MD_CD(B_MADVI,B_MA_DVI,B_MA_NV,B_PHONG,B_LOAI_KH,B_MA_KH,B_NGAYD,B_NGAYC,B_LOI,'B');
UPDATE BC_BH_BT_TEMP T1 SET N7=(SELECT SUM(N7) FROM TEMP_1 WHERE C29=T1.MA_DVI AND N30=T1.SO_ID AND C18=T1.LH_NV);
UPDATE BC_BH_BT_TEMP T1 SET C28=(SELECT TEN FROM HT_MA_DVI WHERE MA=T1.MA_DVI);     
UPDATE BC_BH_BT_TEMP T1 SET C26=(SELECT TEN FROM HT_MA_PHONG WHERE MA_DVI=T1.MA_DVI AND MA=T1.PHONG);
UPDATE BC_BH_BT_TEMP T1 SET C21=(SELECT TEN FROM BH_MA_LHNV WHERE MA_DVI=T1.MA_DVI AND MA=T1.LH_NV);
--UPDATE BC_BH_BT_TEMP T1 SET C25=(SELECT TEN FROM BH_HD_MA_KH WHERE MA_DVI=T1.MA_DVI AND MA=T1.C5);
update
    (select bc_bh_bt_temp.c25 bc_bh_bt_temp_c25, bh_hd_ma_kh.ten bh_hd_ma_kh_ten
        from bc_bh_bt_temp, bh_hd_ma_kh
        where bc_bh_bt_temp.ma_dvi = bh_hd_ma_kh.ma_dvi and bc_bh_bt_temp.c5 = bh_hd_ma_kh.ma)
    set bc_bh_bt_temp_c25 = bh_hd_ma_kh_ten;

UPDATE BC_BH_BT_TEMP T1 SET N29=(SELECT NVL(MAX(NGAY_TT),30000101) FROM BH_HD_GOC_TTPT WHERE MA_DVI=T1.MA_DVI_HD AND SO_ID=T1.SO_ID_HD AND PT<>'C');

UPDATE BC_BH_BT_TEMP T1 SET N28=PKH_SO_CDT(B_NGAYC)-TO_DATE(C19,'dd/mm/yyyy') WHERE C19<>'01/01/3000';
if b_hd='T' then
    delete bc_bh_bt_temp where n20 not between b_ngayd and b_ngayc;
end if;
IF B_LOAI_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C8<> B_LOAI_KH;
END IF;
IF B_MA_KH IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C5<> B_MA_KH;
END IF;
IF B_MA_CB IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C18<> B_MA_CB;
END IF;
IF B_MA_DL IS NOT NULL THEN
    DELETE BC_BH_BT_TEMP WHERE C3<> B_MA_DL AND C6 NOT IN('D','M');
END IF;
COMMIT;

OPEN CS_KQ FOR SELECT MA_DVI, C28 TEN_DVI, PHONG, C26 TEN_PHONG, LH_NV, C21 TEN_NV, C25 TEN_KH, C4 SO_GCN, 
    DECODE(N29,30000101,'Ch-a nep phY',PKH_SO_CNG(N29)) NGAY_TT, C2 SO_HS,
    C7 NGAY_XR, C19 NGAY_GUI, PKH_SO_CNG(NGAY_HT) NGAY_HS, NVL(N28,0) NGAY_TD,NVL(TIEN_QD,0) TIEN_U ,NVL(N7,0) TIEN_GDU,C22 GCN,C23 BIEN_XE
    FROM BC_BH_BT_TEMP ORDER BY MA_DVI,PHONG,LH_NV,C5;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE PBC_BH_NHANH_BT_LKH;

CREATE OR REPLACE PROCEDURE PBC_BH_NHANH_BT_LKH
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_ma_nv varchar2,b_phong varchar2,b_loai_kh varchar2,
    b_lkh varchar2,b_ma_kh varchar2,b_ma_cb varchar2,b_nguon varchar2, b_ma_dt varchar2,b_ma_dl varchar2,b_hd varchar2,b_tc varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_i1 number;
Begin
-- Bao cao nhanh tinh hinh  boi thuong
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');

if b_loi is not null then raise PROGRAM_ERROR; end if;
--BCNam: Ko xem bao cao phong TBH
iF FHT_MA_NSD_PHONG(b_ma_dvi,b_nsd)='TBH' then
    b_loi:='loi:Ban khong co quyen xem bao cao:loi';
    raise PROGRAM_ERROR;
end if;

if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:='loi:Ma chua dang ky:loi';
--delete bc_bh_bt_temp;delete ket_qua;commit;
EXECUTE IMMEDIATE 'TRUNCATE TABLE bc_bh_bt_temp';
EXECUTE IMMEDIATE 'TRUNCATE TABLE ket_qua';
commit;

PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
    b_loi:='loi:Ban khong co quyen xem bao cao nay:loi'; raise PROGRAM_ERROR;
end if;
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,b_ngayd,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;

--boi thuong
PBC_BH_TH_BT_PB_MD(b_tc);

--if b_madvi='001' and b_nsd='ADMIN' then return; end if;

insert into bc_bh_bt_temp (ma_dvi,lh_nv,phong,so_id_hd,n2,ma_dvi_hd,so_id)
                    select t.ma_dvi,t.lh_nv,t.phong,t.so_id_hd,t.tien_qd,t.ma_dvi_hd,t.so_id from bc_bh_bt_hs_temp t, bh_hd_goc goc
                    where t.ngay_qd_n<30000101 and (b_phong is null or t.phong=b_phong)
                    and goc.so_id=t.so_id_hd and goc.ma_dvi=t.ma_dvi_hd
                    and (b_ma_nv is null or t.lh_nv like b_ma_nv ||'%')
                    and (trim(b_nguon) is null or trim(goc.ma_gt) like b_nguon||'%')
                    and (b_ma_kh is null or goc.ma_kh = b_ma_kh)
                    and (b_ma_cb is null or goc.cb_ql = b_ma_cb)
                    --and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                    and (b_ma_dl is null or goc.ma_kt = b_ma_dl);
PBC_BH_BT_CGQ_MD(b_tc);
insert into bc_bh_bt_temp (ma_dvi,lh_nv,phong,so_id_hd,n2,ma_dvi_hd,so_id) select t.ma_dvi,t.lh_nv,t.c3,t.n3,t.n5,t.c4,t.so_id from temp_bt_1 t, bh_hd_goc goc
                    where (b_phong is null or c3=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv ||'%')
                    and goc.so_id=t.n3 and goc.ma_dvi=t.c4
                    and (trim(b_nguon) is null or trim(goc.ma_gt) like b_nguon||'%')
                    and (b_ma_kh is null or goc.ma_kh = b_ma_kh)
                    and (b_ma_cb is null or goc.cb_ql = b_ma_cb)
                    --and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                    and (b_ma_dl is null or goc.ma_kt = b_ma_dl);
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,b_ngaydn,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);
insert into bc_bh_bt_temp (ma_dvi,lh_nv,phong,so_id_hd,n1,ma_dvi_hd) select ma_dvi,lh_nv,phong,so_id,phi,ma_dvig
    from TEMP_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv ||'%')
        and (trim(b_nguon) is null or trim(nguon) like b_nguon||'%')
        and (b_ma_kh is null or ma_kh = b_ma_kh)
        and (b_ma_cb is null or cb_ql = b_ma_cb)
--        and FBH_HD_LKH(ma_dvi,so_id)=b_lkh
        and (b_ma_dl is null or ma_kt = b_ma_dl);
PBC_BH_TH_BT_PB_MD(b_tc);
insert into bc_bh_bt_temp (ma_dvi,lh_nv,phong,so_id_hd,n3,ma_dvi_hd,so_id)
                    select t.ma_dvi,t.lh_nv,t.phong,t.so_id_hd,t.tien_qd,t.ma_dvi_hd,t.so_id from bc_bh_bt_hs_temp t, bh_hd_goc goc
                    where t.ngay_qd_n<30000101 and (b_phong is null or t.phong=b_phong)
                    and (b_ma_nv is null or lh_nv like b_ma_nv ||'%')
                    and goc.so_id=t.so_id_hd and goc.ma_dvi=t.ma_dvi_hd
                    and (b_ma_nv is null or t.lh_nv like b_ma_nv ||'%')
                    and (trim(b_nguon) is null or trim(goc.ma_gt) like b_nguon||'%')
                    and (b_ma_kh is null or goc.ma_kh = b_ma_kh)
                    and (b_ma_cb is null or goc.cb_ql = b_ma_cb)
                    --and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                    and (b_ma_dl is null or goc.ma_kt = b_ma_dl);
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,20000101,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
PBC_BH_BT_CGQ_MD(b_tc);
insert into bc_bh_bt_temp (ma_dvi,lh_nv,phong,so_id_hd,n5,ma_dvi_hd,so_id)  select t.ma_dvi,t.lh_nv,t.c3,t.n3,t.n5,t.c4,t.so_id from temp_bt_1 t, bh_hd_goc goc
                    where (b_phong is null or t.c3=b_phong) and (b_ma_nv is null or t.lh_nv like b_ma_nv ||'%')
                    and goc.so_id=t.n3 and goc.ma_dvi=t.c4
                    and (trim(b_nguon) is null or trim(goc.ma_gt) like b_nguon||'%')
                    and (b_ma_kh is null or goc.ma_kh = b_ma_kh)
                    and (b_ma_cb is null or goc.cb_ql = b_ma_cb)
                    --and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                    and (b_ma_dl is null or goc.ma_kt = b_ma_dl);


update bc_bh_bt_temp set n1=nvl(n1,0),n2=nvl(n2,0),n3=nvl(n3,0),n4=nvl(n4,0),n5=nvl(n5,0);
update bc_bh_bt_temp set n6=n2+n4,n7=n3+n5;

--update
--       (select bc_bh_bt_temp.c3 bc_bh_bt_temp_c3,bh_hd_goc.ma_kh bh_hd_goc_ma_kh, bc_bh_bt_temp.c1 bc_bh_bt_temp_c1,
--        bc_bh_bt_temp.c4 bc_bh_bt_temp_c4, bc_bh_bt_temp.c5 bc_bh_bt_temp_c5, bc_bh_bt_temp.c2 bc_bh_bt_temp_c2,
--        bh_hd_goc.ma_kt bh_hd_goc_ma_kt, bh_hd_goc.kieu_kt bh_hd_goc_kieu_kt,
--       bh_hd_goc.cb_ql bh_hd_goc_cb_ql, bh_hd_goc.so_hd bh_hd_goc_so_hd
--              from bc_bh_bt_temp, bh_hd_goc
--             where bh_hd_goc.ma_dvi = bc_bh_bt_temp.ma_dvi_hd and bh_hd_goc.so_id = bc_bh_bt_temp.so_id_hd)
--       set bc_bh_bt_temp_c3 = bh_hd_goc_ma_kh, bc_bh_bt_temp_c1 = bh_hd_goc_ma_kt,
--        bc_bh_bt_temp_c4 = bh_hd_goc_kieu_kt, bc_bh_bt_temp_c5 = bh_hd_goc_cb_ql, bc_bh_bt_temp_c2 = bh_hd_goc_so_hd;
update bc_bh_bt_temp set (c3,c1,c4,c5,c2) = (select ma_kh,ma_kt,kieu_kt,cb_ql,so_hd from bh_hd_goc where ma_dvi=ma_dvi_hd and so_id=so_id_hd);

update bc_bh_bt_temp t1 set n20=(select ngay_ht from bh_bt_hs where ma_dvi=t1.ma_dvi and so_id=t1.so_id);

 update bc_bh_bt_temp t1 set (c13,c6)=(select ten,loai from bh_hd_ma_kh where ma_dvi=t1.ma_dvi and ma=t1.c3);

--update
--    (select bc_bh_bt_temp.c13 bc_bh_bt_temp_c13, bc_bh_bt_temp.c6 bc_bh_bt_temp_c6,
--        bh_hd_ma_kh.ten bh_hd_ma_kh_ten, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
--        from bc_bh_bt_temp, bh_hd_ma_kh
--        where bh_hd_ma_kh.ma_dvi = bc_bh_bt_temp.ma_dvi and bh_hd_ma_kh.ma = bc_bh_bt_temp.c3)
--        set bc_bh_bt_temp_c13 = bh_hd_ma_kh_ten, bc_bh_bt_temp_c6 = bh_hd_ma_kh_loai;

 update bc_bh_bt_temp t1 set c14=(select ten from ht_ma_phong where ma_dvi=t1.ma_dvi and ma=t1.phong);

--update
--    (select bc_bh_bt_temp.c14 bc_bh_bt_temp_c14, ht_ma_phong.ten ht_ma_phong_ten
--     from bc_bh_bt_temp, ht_ma_phong
--     where bc_bh_bt_temp.ma_dvi = ht_ma_phong.ma_dvi and bc_bh_bt_temp.phong = ht_ma_phong.ma)
--     set  bc_bh_bt_temp_c14 = ht_ma_phong_ten;

 update bc_bh_bt_temp t1 set c15=(select ten from kh_ma_loai_dn where ma_dvi=t1.ma_dvi and ma=t1.c6);
--update bc_bh_bt_temp t1 set c30=(select ten from ht_ma_dvi where ma=t1.ma_dvi);

update bc_bh_bt_temp t1 set c11=(select ten from bh_ma_lhnv where ma_dvi=t1.ma_dvi and ma=t1.lh_nv) where c20='C';
--update
--    (select bc_bh_bt_temp.c15 bc_bh_bt_temp_c15, kh_ma_loai_dn.ten kh_ma_loai_dn_ten
--    from kh_ma_loai_dn, bc_bh_bt_temp
--    where kh_ma_loai_dn.ma_dvi = bc_bh_bt_temp.ma_dvi and kh_ma_loai_dn.ma = bc_bh_bt_temp.c6)
--    set bc_bh_bt_temp_c15 = kh_ma_loai_dn_ten;

--update
--    (select bc_bh_bt_temp.c30 bc_bh_bt_temp_c30, ht_ma_dvi.ten ht_ma_dvi_ten
--    from ht_ma_dvi, bc_bh_bt_temp
--    where ht_ma_dvi.ma = bc_bh_bt_temp.c6)
--    set bc_bh_bt_temp_c30 = ht_ma_dvi_ten;
update bc_bh_bt_temp set c30 = (select max(ten) from ht_ma_dvi where ma=ma_dvi);
if b_hd='T' then
    delete bc_bh_bt_temp where n20 not between b_ngayd and b_ngayc;
end if;
if b_loai_kh is not null then
    delete bc_bh_bt_temp where c6<> b_loai_kh;
end if;
if b_ma_kh is not null then
    delete bc_bh_bt_temp where c3<> b_ma_kh;
end if;
if b_ma_cb is not null then
    delete bc_bh_bt_temp where c5<> b_ma_cb;
end if;
if b_ma_dl is not null then
    delete bc_bh_bt_temp where c1<> b_ma_dl and c4 not in('D','M');
end if;
commit;

-----------------------------------------------------------------------------------------------------------------------
if b_tc='C' then
    insert into ket_qua(c1,c11,c20,n30) select ma,ten,tc,(case substr(ma,1,2) when 'XG' then 1 else
        (case substr(ma,1,2) when 'CN' then 2 else
        (case substr(ma,1,2) when 'HH' then 3 else (case substr(ma,1,2) when 'TT' then 4 else
        (case substr(ma,1,2) when 'TS' then 5 else (case substr(ma,1,2) when 'HP' then 6 else
        (case substr(ma,1,2) when 'TN' then 7 else 0 end)  end) end) end) end) end) end)
        from bh_ma_lhnv where ma_dvi=b_madvi and tc='T';

    update ket_qua kq set (n1,n2,n3,n4,n5,n6,n7,c2,c3,c13,c14,c6,c15,c30) =(select sum(nvl(n1,0)),sum(nvl(n2,0)),
        sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),c2,c3,c13,c14,c6,c15,c30
        from bc_bh_bt_temp t where t.lh_nv like trim(kq.c1)||'%' and rownum=1 group by c2,c3,c13,c14,c6,c15,c30);
end if;

    insert into ket_qua( c20,c29,c1,c2,c3,c4,c6,c11,c13,c14,c15,c30,n1,n2,n3,n4,n5,n6,n7,n12,n30)
        select 'C',ma_dvi,lh_nv,c2,c3,phong,c6,c11,c13,c14,c15,c30,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
        sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n12,0)),
        (case when substr(lh_nv,1,2)='XG' then 1 else (case when substr(lh_nv,1,2)='CN' then 2 else
        (case when substr(lh_nv,1,2)='HH' then 3 else (case when substr(lh_nv,1,2)='TT' then 4 else
        (case when substr(lh_nv,1,2)='TS' then 5 else (case when substr(lh_nv,1,2)='HP' then 6 else
        (case when substr(lh_nv,1,2)='TN' then 7 else 0 end)  end) end) end) end) end) end)
        from bc_bh_bt_temp group by ma_dvi,lh_nv,c2,c3,phong,c6,c11,c13,c14,c15,c30;

update ket_qua t1 set c11=(select ten from bh_ma_lhnv where ma_dvi=t1.c29 and ma=t1.c1) where c20='C';
commit;
open cs_kq for select c20 tc,c29 ma_dvi,c30 ten_dvi,c1 ma_nv,c11 ten_nv,c2 so_hd,c3 ma_kh, c13 ten_kh,c4 phong,c14 ten_phong,
      c6 loai_kh,c15 ten_loai,nvl(n1,0) dtbh_lk,nvl(n2,0) tien_gq_tk,nvl(n4,0) tien_td_tk,nvl(n6,0) tien_tk,nvl(n3,0) tien_gq_lk,nvl(n5,0) tien_td_lk,
      nvl(n7,0) tien_lk from ket_qua order by n30,c1;
--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE PBC_BH_QT_BT_TD;
CREATE OR REPLACE PROCEDURE PBC_BH_QT_BT_TD
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_ma_kh varchar2,b_loai_kh varchar2,b_ma_cb varchar2,
    b_ma_dl varchar2,b_hd varchar2,b_tc varchar2,b_ngayd_lk number,b_ngayc_lk number,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_i1 number;b_vtri number:=0;b_ma_cb_hd varchar2(20);b_ma_cb_hs varchar2(20);
Begin
--BCNam: Bao cao HSBT chua giai quyet, the hien 100% so uoc
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
iF FHT_MA_NSD_PHONG(b_ma_dvi,b_nsd)='TBH' then
    b_loi:='loi:Ban khong co quyen xem bao cao:loi';
    raise PROGRAM_ERROR;
end if;

if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_loi:='loi:Ma chua dang ky:loi';
if b_ma_cb is not null then
    b_vtri:=instr(trim(b_ma_cb),'/');
    if b_vtri >= 1 then
        b_ma_cb_hs:=substr(trim(b_ma_cb),b_vtri+1);
    end if;
    if b_vtri > 1 then
        b_ma_cb_hd:= substr(trim(b_ma_cb),1,b_vtri-1);
    elsif b_vtri = 0 then
        b_ma_cb_hd:= b_ma_cb;
    end if;
end if;
--b_loi:='loi:Nhap ngay bao cao'||b_ma_cb_hd||':loi'; raise PROGRAM_ERROR;
delete bc_bh_bt_temp;commit;
PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
    b_loi:='loi:Ban khong co quyen xem bao cao nay:loi'; raise PROGRAM_ERROR;
end if;
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,20000101,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
PBC_BH_BT_CGQ_MD(b_tc);
insert into bc_bh_bt_temp(ma_dvi,so_id,nv,phong,lh_nv,ngay_qd_n,ma_dvi_hd,so_id_hd,so_id_dt,tien,tien_qd,ngay_ht,tc,c9)
select t.ma_dvi,t.so_id,t.c2,t.c3,t.lh_nv,t.n6,t.c4,t.n3,t.so_id_dt,sum(t.n4),sum(t.n5),t.n2,t.c1,t.c5
       from temp_bt_1 t, bh_hd_goc goc
            where (b_phong is null or t.c3=b_phong) and (b_ma_nv is null or t.lh_nv like b_ma_nv ||'%')
                        and goc.ma_dvi=t.c4 and goc.so_id=t.n3
                       -- and (trim(b_nguon) is null or trim(goc.ma_gt) like b_nguon||'%')
                        and (b_ma_kh is null or goc.ma_kh = b_ma_kh)
                        and (b_ma_cb_hd is null or goc.cb_ql = b_ma_cb_hd)
                        and (b_ma_cb_hs is null or t.c5 = b_ma_cb_hs)
                        and (b_ma_dl is null or goc.ma_kt = b_ma_dl)
                        and (b_ma_dvi is null or t.ma_dvi=b_ma_dvi)
    group by t.ma_dvi,t.so_id,t.c2,t.c3,t.lh_nv,t.n6,t.c4,t.n3,t.so_id_dt,t.n2,t.c1,t.c5;

update bc_bh_bt_temp t1 set (c4,c5,c18,c3,c6)=
                (select so_hd,ma_kh,cb_ql,ma_kt,kieu_kt from bh_hd_goc g where g.ma_dvi=t1.ma_dvi_hd and g.so_id=t1.so_id_hd and rownum=1);
update bc_bh_bt_temp t1 set c8=(select loai from bh_hd_ma_kh where ma_dvi=t1.ma_dvi_hd and ma=t1.c1);
update bc_bh_bt_temp t1 set (c2,c7,c19)=(select max(so_hs),to_char(max(ngay_xr),'dd/mm/yyyy'),to_char(max(ngay_gui),'dd/mm/yyyy') from bh_bt_hs bt
                                    where bt.so_id=t1.so_id);
update bc_bh_bt_temp t1 set (c22,c23) =(select distinct gcn,bien_xe from bh_xe_ds a,bh_bt_hs_nv b
    where a.ma_dvi=b.ma_dvi and a.so_id_dt=b.so_id_dt and a.ma_dvi=t1.ma_dvi_hd
    and a.so_id=FBH_HD_SO_ID_BS(t1.ma_dvi_hd,t1.so_id_hd,30000101) and b.so_id=t1.so_id and rownum=1) where t1.nv='XE';
update bc_bh_bt_temp t1 set (c22,c23) =(select distinct gcn,bien_xe from bh_2b_ds a,bh_bt_hs_nv b
    where a.ma_dvi=b.ma_dvi and a.so_id_dt=b.so_id_dt and a.ma_dvi=t1.ma_dvi_hd
    and a.so_id=FBH_HD_SO_ID_BS(t1.ma_dvi_hd,t1.so_id_hd,30000101) and b.so_id=t1.so_id and rownum=1) where c30='2B';

BC_BH_THGD_MD_CD(b_madvi,b_ma_dvi,b_ma_nv,b_phong,b_loai_kh,b_ma_kh,b_ngayd,b_ngayc,b_loi,'B');
update bc_bh_bt_temp t1 set n7=(select sum(n7) from temp_1 where c29=t1.ma_dvi and n30=t1.so_id and c18=t1.lh_nv);
update bc_bh_bt_temp t1 set n7=(select sum(tien) from bh_bt_gd_hs hs where hs.ma_dvi=t1.ma_dvi and hs.so_id_bt=t1.so_id);
update bc_bh_bt_temp t1 set c28=(select ten from ht_ma_dvi where ma=t1.ma_dvi);
update bc_bh_bt_temp t1 set c26=(select ten from ht_ma_phong where ma_dvi=t1.ma_dvi and ma=t1.phong);
update bc_bh_bt_temp t1 set c21=(select ten from bh_ma_lhnv where ma_dvi=t1.ma_dvi and ma=t1.lh_nv);
update bc_bh_bt_temp t1 set c25=(select ten from bh_hd_ma_kh where ma_dvi=t1.ma_dvi and ma=t1.c5);
update bc_bh_bt_temp t1 set n29=(select nvl(max(ngay_tt),30000101) from bh_hd_goc_ttpt where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd and pt<>'C');
--BCNam bo sung
--Duchq bo tam truong kieu do table bh_hd_do_tl khong c? truong kieu
update bc_bh_bt_temp t1 set n13=(Select nvl(sum(pt),0) from bh_hd_do_tl where pthuc='C' and so_id=t1.so_id_hd and
        ma_dvi=t1.ma_dvi and (lh_nv=t1.lh_nv or lh_nv='*'));
update bc_bh_bt_temp t1 set n13=100 where n13 is null or n13=0;
--{So ngay ton dong} = {ngay bao cao} - {ngay gui yeu cau boi thuong}
update bc_bh_bt_temp t1 set n28=PKH_SO_CDT(b_ngayc)-to_date(c19,'dd/mm/yyyy') where c19<>'01/01/3000';
update bc_bh_bt_temp t1 set (n20,c20)=(select ngay_ht,nsd from bh_bt_hs where ma_dvi=t1.ma_dvi and so_id=t1.so_id);
-- update bc_bh_bt_temp t1 set n30=(Select sum(a.tien) from bh_xegcn_dk a where a.lh_nv=t1.lh_nv and a.so_id=t1.so_id_hd and a.so_id_dt=t1.so_id_dt) where so_id_dt<>0;
-- update bc_bh_bt_temp t1 set n30=(Select sum(a.tien) from bh_xelgcn_dk a where a.lh_nv=t1.lh_nv and a.so_id=t1.so_id_hd) where so_id_dt=0;

if b_hd='T' then
    delete bc_bh_bt_temp where n20 not between b_ngayd and b_ngayc;
end if;

if b_loai_kh is not null then
    delete bc_bh_bt_temp where c8<> b_loai_kh;
end if;
if b_ma_kh is not null then
    delete bc_bh_bt_temp where c5<> b_ma_kh;
end if;
if b_ma_cb_hd is not null then
    delete bc_bh_bt_temp where c18<> b_ma_cb_hd;
end if;
if b_ma_dl is not null then
    delete bc_bh_bt_temp where c3<> b_ma_dl and c6 not in('D','M');
end if;

-- Hung kiem tra so hang phai < 65000
--select count(*) into b_i1 from bc_bh_bt_temp;
--if b_i1>65000 then
--    b_loi:='loi:So dong bao cao > 65000, khong mo duoc Excel:loi'; raise PROGRAM_ERROR;
--end if;

commit;
-------------------------------------------------------------------------
open cs_kq for select ma_dvi, c28 ten_dvi, phong, c26 ten_phong, c18 cb_ql,lh_nv, c21 ten_nv, c25 ten_kh, c4 so_gcn,
    decode(n29,30000101,'Chua nop phi',PKH_SO_CNG(n29)) ngay_tt, c2 so_hs,
    c7 ngay_xr, c19 ngay_gui, PKH_SO_CNG(ngay_ht) ngay_hs, nvl(n28,0) ngay_td,
    nvl(tien_qd,0) tien_u ,nvl(n7,0) tien_gdu,c22 gcn,c23 bien_xe,
    n30 tien_bh, n10 tyle_taicd, n11 tyle_taitt, n12 tyle_taiphityle,c20 nsd
    from bc_bh_bt_temp order by ma_dvi,phong,c18,lh_nv,c5;
exception when others then raise_application_error(-20105,b_loi);
End;

/

DROP PROCEDURE PBC_BH_TH_BT_PB_MD;

CREATE OR REPLACE PROCEDURE PBC_BH_TH_BT_PB_MD (b_tc varchar2)
AS
begin
-- Lay du lieu boi thuong da phan bo chi phi theo Dong BH noi bo
--delete temp_bt_1;delete temp_bt_2;delete bc_bh_bt_hs_temp;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE bc_bh_bt_hs_temp';
/*
insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1)
    select nv.ma_dvi, nv.so_id, nv.lh_nv, 0, nv.ma_dvi,hs.phong
        from bh_bt_hs_nv nv,bh_bt_hs hs, temp_bc_ts ts
        where nv.ma_dvi=ts.ma_dvi and nv.tien_qd=0
        and hs.ngay_qd between ts.ngayd and ts.ngayc
        and hs.so_id=nv.so_id and hs.ma_dvi=nv.ma_dvi;
*/
insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1)
    select nv.ma_dvi, nv.so_id, nv.lh_nv, 0, nv.ma_dvi,hs.phong
        from bh_bt_hs_nv nv,bh_bt_hs hs, temp_bc_ts ts
        where hs.ngay_qd between ts.ngayd and ts.ngayc and hs.ma_dvi=ts.ma_dvi
        and hs.so_id=nv.so_id and hs.ma_dvi=nv.ma_dvi and nv.tien_qd=0;
delete temp_bt_1 a where exists(select * from bh_bt_hs_pb pb,temp_bc_ts ts where pb.ma_dvi=a.ma_dvi
    and ngay_ht between ts.ngayd and ts.ngayc and so_id=a.so_id);

--insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1) select pb.ma_dvi,so_id,lh_nv,tien_qd,pb.dvi_xl,pb.phong
--    from bh_bt_hs_pb pb,temp_bc_ts ts where pb.ma_dvi=ts.ma_dvi and ngay_ht between ts.ngayd and ts.ngayc;

insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1) select pb.ma_dvi,so_id,lh_nv,tien_qd,pb.dvi_xl,pb.phong
    from bh_bt_hs_pb pb,temp_bc_ts ts where
    ngay_ht between ts.ngayd and ts.ngayc and tien_qd<>-1
    and pb.ma_dvi=ts.ma_dvi;

merge into temp_bt_1 c
using (select phong,ma_dvi,so_id from bh_bt_hs group by phong,ma_dvi,so_id )a
on (a.ma_dvi=c.ma_dvi and a.so_id=c.so_id)
when matched then
update set c.c1=a.phong;

--Tat ca
if b_tc='*' then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,bt.ngay_qd ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and nv.so_id=t.so_id and (bt.ma_dvi_ql=t.dvi_xl or bt.ma_dvi=bt.ma_dvi_xl) and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
            and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=bt.ma_dvi_ql and so_id=bt.so_id_hd) not in ('V', 'N');

elsif b_tc='K' then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,bt.ngay_qd ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and nv.so_id=t.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl
            --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
            and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=bt.ma_dvi_ql and so_id=bt.so_id_hd) not in ('V', 'N')
            and bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi_xl<>ts.ma_dvi and bt.ma_dvi_ql<>ts.ma_dvi;
end if;
if PKH_MA_MA(b_tc,'T') then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,bt.ngay_qd ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and nv.so_id=t.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id -- and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl
            --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
            and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=bt.ma_dvi_ql and so_id=bt.so_id_hd) not in ('V', 'N');

    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,bt.ngay_qd ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and nv.so_id=t.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id-- and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl
            --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
            and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=bt.ma_dvi_ql and so_id=bt.so_id_hd) not in ('V', 'N')
            and bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi_ql=ts.ma_dvi;
end if;

if PKH_MA_MA(b_tc,'N') then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,bt.ngay_qd ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and nv.so_id=t.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl
            --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
            and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=bt.ma_dvi_ql and so_id=bt.so_id_hd) not in ('V', 'N')
            and bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi_ql=ts.ma_dvi;
end if;

if PKH_MA_MA(b_tc,'H') then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,bt.ngay_qd ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and nv.so_id=t.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl
            --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd) not in ('V','N')
            and (select nvl(min(kieu_hd),' ') from bh_hd_goc where ma_dvi=bt.ma_dvi_ql and so_id=bt.so_id_hd) not in ('V', 'N')
            and bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi_xl=ts.ma_dvi;
end if;


-- Hung sua: Nga bao ban goc khong co distinct. Neu cos van de thif trao doi voi MIC (tai sao them distinct Nam tra loi chong trung)
/*
update temp_bt_2 t2 set n8=(select DISTINCT t2.n5 * t1.n2 from temp_bt_1 t1
       where t1.ma_dvi=t2.ma_dvi and t1.so_id=t2.so_id and t1.lh_nv=t2.lh_nv and t1.n2<>0 and t1.c1=t2.c3);
*/

--update temp_bt_2 t2 set n8=(select t2.n5 * t1.n2 from temp_bt_1 t1
--       where t2.ma_dvi=t1.ma_dvi and t2.so_id=t1.so_id and t2.lh_nv=t1.lh_nv and t1.n2<>0 and t1.c1=t2.c3 and rownum=1);

merge into temp_bt_2 t2
using (select nvl(max(n2),0)n2,ma_dvi,so_id,lh_nv,c1 from temp_bt_1 t1 where n2<>0 group by ma_dvi,so_id,lh_nv,c1 )b-- group by ma_dvi,so_id,lh_nv,c1
on (t2.ma_dvi=b.ma_dvi and t2.so_id=b.so_id and t2.lh_nv=b.lh_nv and b.c1=t2.c3 )
when matched then
update set t2.n8 = b.n2;
update temp_bt_2 set n8 = n5*n8;
/*
update temp_bt_2 t2 set n9=(select sum(t.n5) from temp_bt_2 t
                        where t.ma_dvi=t2.ma_dvi and t.so_id=t2.so_id and t.lh_nv=t2.lh_nv and t.c3=t2.c3);
*/
merge into temp_bt_2
    using (select ma_dvi,so_id,lh_nv,c3,sum(nvl(n5,0)) n5 from temp_bt_2 group by ma_dvi,so_id,lh_nv,c3) t
    on (t.ma_dvi=temp_bt_2.ma_dvi and t.so_id=temp_bt_2.so_id and t.lh_nv=temp_bt_2.lh_nv and t.c3=temp_bt_2.c3)
    when matched then
    update set temp_bt_2.n9 = t.n5;

update temp_bt_2 set n1=round(n8/n9,2) where n9<>0;
insert into bc_bh_bt_hs_temp select ma_dvi,so_id,c2,c3,lh_nv,n2,c6,n3,so_id_dt,n4,n1,n7,c5 from temp_bt_2;
--Xoa cac nghiep vu khong duoc xem
--delete from bc_bh_bt_hs_temp where substr(lh_nv,1,2) not in (Select nv from temp_bc_nv) and phong not in (Select phong from temp_bc_phong);

/*
insert into bc_bh_bt_hs_temp
    select ma_dvi,so_id,c2,c3 phong,lh_nv,n2,c6,n3,so_id_dt,n4,
        case when n9<>0 then round(n8/n9,2) else 0 end n1,n7,c5
        from temp_bt_2 a where not exists(select nv from temp_bc_nv where nv=substr(a.lh_nv,1,2))
            and not exists(select phong from temp_bc_phong where phong=a.c3);
*/
end;
/

DROP PROCEDURE PBC_BH_TH_BT_PB_MD_TNDS;

CREATE OR REPLACE PROCEDURE PBC_BH_TH_BT_PB_MD_TNDS(b_tc varchar2)
AS
begin 

--delete temp_bt_1;delete temp_bt_2;delete bc_bh_bt_hs_temp; 
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_2';
EXECUTE IMMEDIATE 'TRUNCATE TABLE bc_bh_bt_hs_temp';
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_3';
--chen nhung vu ton that duyet=0    
--insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1)
--    select nv.ma_dvi, nv.so_id, nv.lh_nv, 0, nv.ma_dvi,hs.phong
--    from bh_bt_hs_nv nv,bh_bt_hs hs, temp_bc_ts ts 
--    where nv.ma_dvi=ts.ma_dvi and hs.so_id=nv.so_id and hs.ma_dvi=nv.ma_dvi
--    and nv.tien_qd=0 and TO_NUMBER(to_char(hs.ngay_qd,'yyyymmdd'))<=ts.ngayc and to_number(to_char(hs.ngay_qd,'yyyymmdd')) between ts.ngayd and ts.ngayc 
--    and nv.so_id not in (select so_id
--       from bh_bt_hs_pb pb,temp_bc_ts ts where pb.ma_dvi=ts.ma_dvi and ngay_ht between ts.ngayd and ts.ngayc)
--    group by nv.ma_dvi, nv.so_id, nv.lh_nv, nv.ma_dvi,hs.phong;
insert into temp_bt_3(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1)
    select nv.ma_dvi, nv.so_id, nv.lh_nv, 0, nv.ma_dvi,hs.phong
    from bh_bt_hs_nv nv,bh_bt_hs hs, temp_bc_ts ts 
    where nv.ma_dvi=ts.ma_dvi and hs.so_id=nv.so_id and hs.ma_dvi=nv.ma_dvi
    and nv.tien_qd=0 and ngay_qd<=ts.ngayc and ngay_qd between ts.ngayd and ts.ngayc 
    --and nv.so_id not in (select so_id
    --   from bh_bt_hs_pb pb,temp_bc_ts ts where pb.ma_dvi=ts.ma_dvi and ngay_ht between ts.ngayd and ts.ngayc)
    group by nv.ma_dvi, nv.so_id, nv.lh_nv, nv.ma_dvi,hs.phong;
delete temp_bt_3 where so_id in  (select so_id from bh_bt_hs_pb pb,temp_bc_ts ts where pb.ma_dvi=ts.ma_dvi and ngay_ht between ts.ngayd and ts.ngayc);
insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1)  select ma_dvi,so_id,lh_nv,n2,dvi_xl,c1 from temp_bt_3;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_3';

-- Lay du lieu boi thuong da phan bo chi phi theo Dong BH noi bo
insert into temp_bt_1(ma_dvi,so_id,lh_nv,n2,dvi_xl,c1) select pb.ma_dvi,so_id,lh_nv,tien_qd,pb.dvi_xl,pb.phong
    from bh_bt_hs_pb pb,temp_bc_ts ts where pb.ma_dvi like ts.ma_dvi and ngay_ht between ts.ngayd and ts.ngayc;


--Tat ca
if b_tc='*' then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and (bt.ma_dvi_ql=t.dvi_xl or bt.ma_dvi=bt.ma_dvi_xl) and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V';
            
    
    
  /*-- Giam dong bao hiem neu co
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi, '', d.phong, t.lh_nv, 0, d.ngay_ht, t.so_id, 
            tien, tien_qd, 0, d.ngay_ht, 'T', t.ma_dvi
            from bh_hd_do_pt t, bh_hd_do_tt d, temp_bc_ts ts
            where t.so_id_tt=d.so_id_tt and t.loai='DT_LE_BT' and t.nv='T' and t.ma_dvi=d.ma_dvi
            and t.ma_dvi=ts.ma_dvi; */


-- Khoan phai chi do Dong BH noi bo (khong phai don vi ky hop dong, khong phai don vi lam ho so boi thuong)
elsif b_tc='K' then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V'
            and bt.ma_dvi_xl<>ts.ma_dvi and bt.ma_dvi_ql<>ts.ma_dvi;
end if;

--return;
--Tu lam
if PKH_MA_MA(b_tc,'T') then
    /*
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,pkh_ng_cso(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bt_1 t
        where bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id-- and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V';
    */
--return;
--    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
--        select /*+ hint FULL(bt) */ t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,pkh_ng_cso(bt.ngay_qd) ngay_qd_n,so_id_hd,
--                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
--        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bt_1 t
--        where bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id
--            and bt.ma_dvi=bt.ma_dvi_xl and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V'
--            and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id;
--
--    -- chen them nguoi khac bt ho minh
--    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
--        select /*+ hint FULL(bt) */ t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,pkh_ng_cso(bt.ngay_qd) ngay_qd_n,so_id_hd,
--                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
--        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
--        where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id
--            and bt.ma_dvi=bt.ma_dvi_xl and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V'
--        and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and bt.ma_dvi_ql=ts.ma_dvi;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_3';
insert into temp_bt_3(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
select * from(       
select   t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,'T',bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id
            and bt.ma_dvi=bt.ma_dvi_xl --and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V'
        and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and bt.ma_dvi_ql=ts.ma_dvi
union all
select   t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,'T',bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bt_1 t--,BH_HD_GOC goc
        where bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id
            and bt.ma_dvi=bt.ma_dvi_xl 
            and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id)a
where  FBH_HD_KIEU_HD(a.ma_dvi_ql,a.so_id_hd)<>'V';
insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6) select ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6 from temp_bt_3;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bt_3';
commit;
end if;
-- Nguoi khac lam ho
if PKH_MA_MA(b_tc,'N') then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V'
             and bt.ma_dvi_ql=ts.ma_dvi;
end if;
-- lam ho nguoi khac
if PKH_MA_MA(b_tc,'H') then
    insert into temp_bt_2(ma_dvi,c2,c3,lh_nv,so_id,n2,n3,n4,n5,so_id_dt,n7,c5,c6)
        select t.ma_dvi,bt.nv,t.c1 phong,nv.lh_nv,bt.so_id,(bt.ngay_qd) ngay_qd_n,so_id_hd,
                tien,tien_qd,nv.so_id_dt,bt.ngay_ht,b_tc,bt.ma_dvi_ql
        from bh_bt_hs bt,bh_bt_hs_nv nv,temp_bc_ts ts,temp_bt_1 t
        where bt.ma_dvi_xl<>bt.ma_dvi_ql and bt.ma_dvi=nv.ma_dvi and bt.so_id=nv.so_id and bt.ma_dvi_ql=t.dvi_xl and bt.so_id=t.so_id and t.lh_nv=nv.lh_nv
            and bt.ma_dvi=bt.ma_dvi_xl and FBH_HD_KIEU_HD(bt.ma_dvi_ql,bt.so_id_hd)<>'V'
            and bt.ma_dvi_xl=ts.ma_dvi;
end if;

--update temp_bt_2 t2 set n8=(select   t2.n5 * max(t1.n2) from temp_bt_1 t1 
--                                   where t1.ma_dvi=t2.ma_dvi and t1.so_id=t2.so_id and t1.lh_nv=t2.lh_nv and t1.n2<>0);
merge into temp_bt_2
using (select ma_dvi,so_id,lh_nv,max(n2)n2max from temp_bt_1 where n2<>0 group by ma_dvi,so_id,lh_nv)t1
on (t1.ma_dvi=temp_bt_2.ma_dvi and t1.so_id=temp_bt_2.so_id and t1.lh_nv=temp_bt_2.lh_nv and t1.n2max<>0)
when matched then update set
n8 = temp_bt_2.n5 * nvl(n2max,0);
  
--update temp_bt_2 t2 set n9=(select  sum(t.n5) from temp_bt_2 t  where t.ma_dvi=t2.ma_dvi and t.so_id=t2.so_id and t.lh_nv=t2.lh_nv);
merge into temp_bt_2
using (select ma_dvi,so_id,lh_nv,sum(n5)n5sum from temp_bt_1 group by ma_dvi,so_id,lh_nv)t
on (t.ma_dvi=temp_bt_2.ma_dvi and t.so_id=temp_bt_2.so_id and t.lh_nv=temp_bt_2.lh_nv)
when matched then update set
n9 = nvl(n5sum,0);
 
update temp_bt_2 set n1=round(n8/n9,0) where n9<>0;
insert into bc_bh_bt_hs_temp select ma_dvi,so_id,c2,c3,lh_nv,n2,c6,n3,so_id_dt,n4,n1,n7,c5 from temp_bt_2;

end;
