DROP PROCEDURE PBC_BH_TS;

CREATE OR REPLACE PROCEDURE PBC_BH_TS
 (b_ma_dvi varchar2,b_nsd varchar2,b_dvi varchar2,b_ngayd number,b_ngayc number,b_loi out varchar2)
AS
    b_i1 number;b_i2 number;
begin
delete temp_bc_ts;
select count(*) into b_i1 from ht_ma_nsd_qly where ma_dvi=b_ma_dvi and ma=b_nsd and md='BH' and rownum=1;
if b_dvi is null then
    if b_i1>0 then
        insert into temp_bc_ts
            select distinct dvi,b_ngayd,b_ngayc from ht_ma_nsd_qly where ma_dvi=b_ma_dvi and ma=b_nsd and md='BH';
    else
        insert into temp_bc_ts select ma,b_ngayd,b_ngayc from ht_ma_dvi;
    end if;
else
    select count(*) into b_i2 from ht_ma_nsd_qly where ma_dvi=b_ma_dvi and ma=b_nsd and dvi=b_dvi and md='BH';
    --if b_i2=0 and b_i1<>0 then
     --   b_loi:='loi:Ban khong co quyen xem bao cao don vi nay 4:loi'; return;
    --else
        insert into temp_bc_ts values(b_dvi,b_ngayd,b_ngayc);
    --end if;
end if;
commit;
b_loi:='';
exception when others then null;
end;
/

DROP PROCEDURE PBC_BH_XE_TNDS;

CREATE OR REPLACE PROCEDURE PBC_BH_XE_TNDS
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_loai_kh varchar2,b_kieu_kt varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi nvarchar2(100);b_ngaydn number;b_ma_vp varchar2(20);
begin
--Bao cao bao hiem bat buoc TNDS cua chu xe co gioi
-- BCNam: Dang kiem tra, dieu chinh
b_ngaydn:=round(b_ngayd,-4)+101;
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
--b_loi:='loi:BCNam:loi';
if b_loi is not null then raise PROGRAM_ERROR; end if;
delete temp_1;delete temp_2;delete temp_3;delete ket_qua;delete temp_bc_ts;commit;
select max(ma) into b_ma_vp from ht_ma_dvi where vp='C' and rownum=1;
---Lay du lieu cuoi ky------------
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,b_ngaydn,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;

EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_1(c8,n1,c1,c3,c4,n10,c2,c5,d1,d2,c6,c7,c9,n3,n4) 
select ma_dvi,phi,nv,lh_nv,phong,so_id,'TK',so_hd,ngay_hl,ngay_kt,ma_kh,ma_dvig,nguon,ngay_ht,ngay_htnv
from TEMP_BC_BH_DTBH_MM
where
(b_phong is null or phong=b_phong) and (b_ma_dvi is null or ma_dvi=b_ma_dvi)
and nv in ('2B','2BL','XE','XEL');
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
BC_BH_LAY_BC_BH_DTBH_MM(b_ma_dvi,b_ngaydn,b_ngayc);
insert into temp_1(c8,n2,c1,c3,c4,n10,c2,c5,d1,d2,c6,c7,c9,n3,n4) 
select ma_dvi,phi,nv,lh_nv,phong,so_id,'LK',so_hd,ngay_hl,ngay_kt,ma_kh,ma_dvig,nguon,ngay_ht,ngay_htnv
from TEMP_BC_BH_DTBH_MM
where
(b_phong is null or phong=b_phong)  and (b_ma_dvi is null or ma_dvi=b_ma_dvi)
and nv in ('2B','2BL','XE','XEL');
insert into temp_2(c8,c7,c6,c9,c4,n10,c1,c3,n4,c5,d1,d2,n1,n2)
select c8 ma_dvi,c7 ma_dvig,c6 ma_kh,c9 nguon,c4 phong,n10 so_id,c1 nv,c3 lh_nv,n4 ngay_htnv,c5 so_hd,d1 ngay_hl,d2 ngay_kt,sum(n1) dtbh_tk,sum(n2) dtbh_lk from temp_1 group by c8,c7,c6,c9,c4,n10,c1,c3,n4,c5,d1,d2;

insert into temp_3(c8,c7,c6,c9,c4,n10,c1,c3,n4,c5,d1,d2,n1,n2,n5,n11,c20) --n11 so_id_dt
select c8,c7,c6,c9,c4,n10,c1,c3,n4,c5,d1,d2,n1,n2,b.phi,b.so_id_dt,a.gcn
from temp_2 t,bh_xe_ds a
,(select ma_dvi,so_id,so_id_dt,lh_nv,sum(tien)tien,sum(phi)phi from bh_xe_dk where lh_nv in (select MA from bh_ma_lhnv where nv like '%XE%' and BB='B') group by ma_dvi,so_id,so_id_dt,lh_nv) b
where t.c1 like 'XE%' and t.c8=b.ma_dvi and t.n10=b.so_id and t.c3=b.lh_nv
and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.SO_ID_DT=b.SO_ID_DT;
--select * from bh_xe_ds where so_id in (select n10 from temp_2) 
--select * from bh_ma_lhnv
--lay dtps oto
merge into temp_3 a using (select n10,c3,c7,c4,c8,sum(n5)TONG_DTPS from temp_3 group by n10,c3,c7,c4,c8)b
on(a.n10=b.n10 and a.c3=b.c3 and a.c7=b.c7 and a.c8=b.c8)--and a.c4=b.c4 
when matched then update set n6=b.TONG_DTPS;
merge into temp_3 a using (select n10,c3,c7,c4,c8,count(1)sl from temp_3 group by n10,c3,c7,c4,c8)b
on(a.n10=b.n10 and a.c3=b.c3 and a.c7=b.c7 and a.c8=b.c8)--and a.c4=b.c4 
when matched then update set n7=b.sl;
--lay dtps 2b
insert into temp_3(c8,c7,c6,c9,c4,n10,c1,c3,n4,c5,d1,d2,n1,n2,n5,n11,c20) --n11 so_id_dt
select c8,c7,c6,c9,c4,n10,c1,c3,n4,c5,d1,d2,n1,n2,b.phi,b.so_id_dt,a.gcn
from temp_2 t,bh_2b_ds a
,(select ma_dvi,so_id,so_id_dt,lh_nv,sum(tien)tien,sum(phi)phi from bh_2b_dk where ttoan <>0 and lh_nv in (select MA from bh_ma_lhnv where nv like '%2B%' and BB='B') group by ma_dvi,so_id,so_id_dt,lh_nv) b
where t.c1 like '2B%' and t.c8=b.ma_dvi and t.n10=b.so_id and t.c3=b.lh_nv
and a.ma_dvi=b.ma_dvi and a.so_id=b.so_id and a.SO_ID_DT=b.SO_ID_DT;
merge into temp_3 a using (select n10,c3,c7,c4,c8,sum(n5)TONG_DTPS from temp_3 group by n10,c3,c7,c4,c8)b
on(a.n10=b.n10 and a.c3=b.c3 and a.c7=b.c7 and a.c8=b.c8)-- and a.c4=b.c4
when matched then update set n6=b.TONG_DTPS;
merge into temp_3 a using (select n10,c3,c7,c4,c8,count(1)sl from temp_3 group by n10,c3,c7,c4,c8)b
on(a.n10=b.n10 and a.c3=b.c3 and a.c7=b.c7 and a.c8=b.c8) -- and a.c4=b.c4
when matched then update set n7=b.sl;
--pb dthu theo tl
update temp_3 set n8= (n5/n6);--tl
update temp_3 set n15= n8*n1,n16=n8*n2;--dtbh_tk,dtbh_lk
update temp_3 set (c21,c22)=(select min(PKH_SO_CNG(NGAY_CAP)),min(ma_kt) from bh_hd_goc where so_id=n10);

commit;
open cs_kq for 
select c8 ma_dvi,c7 ma_dvig,c6 ma_kh,c22 ma_kt,c4 phong,c1 nv,c3 lh_nv,n4 ngay_htnv,c5 so_hd,c20 gcn,c21 ngay_cap,d1 ngay_hl,d2 ngay_kt,n15 dtbh_tk,n16 dtbh_lk from temp_3;

--exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE PBC_BH_XE_TNDS_CT;

CREATE OR REPLACE PROCEDURE PBC_BH_XE_TNDS_CT
    (b_ma_nv varchar2,b_phong varchar2,b_sl varchar2,b_dvi varchar2:='',b_ngayd number:=0,b_ngayc number:=0)
AS

begin
--delete temp_s_1;delete bc_bh_bt_temp;commit;
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_s_1';
EXECUTE IMMEDIATE 'TRUNCATE TABLE bc_bh_bt_temp';
--b_sl: kieu so lieu D: Dau ky, C: Cuoi ky
------------Soluong, phi---------------------
/*
insert into temp_s_1(c29,n1,c1,c3,c4,n11,c2) select ma_dvi,phi,nv,lh_nv,phong,so_id,b_sl
    from V_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and nv in ('2B','2BL','XE','XEL');  
*/

if b_ngayd<>0 then
    EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MM';
    BC_BH_LAY_BC_BH_DTBH_MM(b_dvi,b_ngayd,b_ngayc);
    insert into temp_s_1(c8,n1,c1,c3,c4,n10,c2) 
        select ma_dvi,phi,nv,lh_nv,phong,so_id,b_sl
            from TEMP_BC_BH_DTBH_MM
            --from bh_kq 
            where --chitieu='DTBH' and ngay_dulieu between b_ngayd and b_ngayc and
            (b_phong is null or phong=b_phong) and nv in ('2B','2BL','XE','XEL');
else
    insert into temp_s_1(c8,n1,c1,c3,c4,n10,c2) select ma_dvi,phi,nv,lh_nv,phong,so_id,b_sl
        from V_BC_BH_DTBH_MM where (b_phong is null or phong=b_phong) and nv in ('2B','2BL','XE','XEL');  
end if;    

update temp_s_1 set c5=(select ma_sp from bh_2b_ds where ma_dvi=c8 and so_id=n10 and rownum=1);-- where c1='2B';
--update temp_s_1 set c5=(select loai_xe from bh_2blgcn where ma_dvi=c8 and so_id=n10) where c1='2BL';
--merge into temp_s_1 using bh_2blgcn on ( ma_dvi=c8 and so_id=n10 ) when matched then update set c5 = loai_xe where c1 = '2BL';
-- update temp_s_1 set (c6,n3,n4,c7)=(select md_sd,ttai,so_cn,loai_xe  from bh_xegcn where ma_dvi=c8 and so_id=n10 and rownum=1);-- where c1='XE';
--update temp_s_1 set (c6,n3,n4,c7)=(select md_sd,ttai,so_cn,loai_xe from bh_xelgcn where ma_dvi=c8 and so_id=n10) where c1='XEL';
-- merge into temp_s_1 using bh_xelgcn on ( ma_dvi=c8 and so_id=n10 ) when matched then update set c6=md_sd,n3=ttai,n4=so_cn,c7=loai_xe where c1 = 'XEL';
-----------Boi thuong, vu tai nan -------------------  
PBC_BH_TH_BT_PB_MD_TNDS('T');
--return;
insert into bc_bh_bt_temp(ma_dvi,tien_qd,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd,c2) 
        select t1.ma_dvi,tien_qd,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd,b_sl from bc_bh_bt_hs_temp t1,temp_bc_ts ts
        where t1.ma_dvi=ts.ma_dvi and t1.ngay_ht between ts.ngayd and ts.ngayc and
        ngay_qd_n<30000101 and nv in ('2B','2BL','XE','XEL')
                    and (b_ma_nv is null or lh_nv like b_ma_nv||'%');  
update bc_bh_bt_temp t1 set c5=(select ma_sp from bh_2b_ds a where a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd and rownum=1);-- where t1.nv='2B';
--update bc_bh_bt_temp t1 set c5=(select loai_xe from bh_2blgcn a where a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd) where t1.nv='2BL';
--merge into bc_bh_bt_temp t1 using bh_2blgcn a on ( a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd ) when matched then update set c5 = loai_xe where t1.nv = '2BL';
update bc_bh_bt_temp t1 set (c6,n3,n4,c7)=(select md_sd,ttai,so_cn,loai_xe from bh_xe_ds a where a.ma_dvi=t1.ma_dvi_hd 
                                                    and a.so_id=t1.so_id_hd and rownum=1) where t1.nv='XE';
-- update bc_bh_bt_temp t1 set (c6,n3,n4,c7)=(select md_sd,ttai,so_cn,loai_xe from bh_xelgcn a where a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd) where t1.nv='XEL';
--merge into bc_bh_bt_temp t1 using bh_xelgcn a on ( a.ma_dvi=t1.ma_dvi_hd and a.so_id=t1.so_id_hd ) when matched then update 
--set c6=md_sd,n3=ttai,n4=so_cn,c7=loai_xe where t1.nv = 'XEL';                   
end;

