DROP PROCEDURE PBC_BH_XE_TNDS_MD;

CREATE OR REPLACE PROCEDURE PBC_BH_XE_TNDS_MD
    (b_lh_nv varchar2,b_loai_xe varchar2,b_md_sd varchar2,b_oto_loai varchar2,b_sl varchar2,b_kieu varchar2,
        b_tu number,b_den number,b_stt number,b_stt_c varchar2,b_nv nvarchar2)
AS
begin
-- b_md_sd: muc dich su dung, b_kieu: trong tai hoac so cho ngoi
--so luong

if (b_tu=0) and (b_den=0) then
    insert into temp_m_2(c1,c2,c3,c4,c5,n2,n13,n14,n15,c6,c7)
        values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,
            (select count(*) from temp_s_1 where c3=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                b_tu,b_den,b_stt,b_stt_c,b_nv);
else
    if b_kieu='N' then
        insert into temp_m_2(c1,c2,c3,c4,c5,n2,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select count(*) from temp_s_1
                                            where n4 between b_tu and b_den and
                                           c3=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
    elsif b_kieu='T' then
         insert into temp_m_2(c1,c2,c3,c4,c5,n2,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select count(*) from temp_s_1
                                            where n3 between b_tu and b_den and
                                           c3=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
    end if;
end if;

--Phi
if (b_tu=0) and (b_den=0) then
    insert into temp_m_2(c1,c2,c3,c4,c5,n4,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select sum(n1) from temp_s_1
                                            where c3=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
else
   if b_kieu='N' then
        insert into temp_m_2(c1,c2,c3,c4,c5,n4,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select sum(n1) from temp_s_1
                                            where n4 between b_tu and b_den and
                                            c3=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
   elsif b_kieu='T' then
        insert into temp_m_2(c1,c2,c3,c4,c5,n4,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select sum(n1) from temp_s_1
                                            where n3 between b_tu and b_den and
                                            c3=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
   end if;
end if;
--Vu tai nan
if (b_tu=0) and (b_den=0) then
    insert into temp_m_2(c1,c2,c3,c4,c5,n6,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select count(*) from bc_bh_bt_temp
                                            where lh_nv=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
else
    if b_kieu='N' then
        insert into temp_m_2(c1,c2,c3,c4,c5,n6,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select count(*) from bc_bh_bt_temp
                                            where n4 between b_tu and b_den and
                                            lh_nv=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
    elsif b_kieu='T' then
         insert into temp_m_2(c1,c2,c3,c4,c5,n6,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select count(*) from bc_bh_bt_temp
                                            where n3 between b_tu and b_den and
                                            lh_nv=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
    end if;
end if;
--Boi thuong
if (b_tu=0) and (b_den=0) then
    insert into temp_m_2(c1,c2,c3,c4,c5,n10,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select sum(tien_qd) from bc_bh_bt_temp
                                            where lh_nv=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
else
   if b_kieu='N' then
        insert into temp_m_2(c1,c2,c3,c4,c5,n10,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select sum(tien_qd) from bc_bh_bt_temp
                                            where n4 between b_tu and b_den and
                                            lh_nv=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
   elsif b_kieu='T' then
        insert into temp_m_2(c1,c2,c3,c4,c5,n10,n13,n14,n15,c6,c7) values(b_lh_nv,b_loai_xe,b_md_sd,b_oto_loai,b_sl,(select sum(tien_qd) from bc_bh_bt_temp
                                            where n3 between b_tu and b_den and
                                            lh_nv=b_lh_nv and (b_loai_xe is null or c5 like b_loai_xe||'%') and
                                            (b_md_sd is null or c6 like b_md_sd||'%') and (b_oto_loai is null or c7 like b_oto_loai||'%')),
                                            b_tu,b_den,b_stt,b_stt_c,b_nv);
   end if;
end if;
end;
/

drop PROCEDURE PBC_CT_CHUA_HT;

CREATE OR REPLACE PROCEDURE PBC_CT_CHUA_HT
    (B_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,B_NGAYD NUMBER,B_NGAYC NUMBER,
        B_MA_DVI VARCHAR2,B_MA_PH VARCHAR2,B_L_CT VARCHAR2,B_SO_HD VARCHAR2,CS1 OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100); B_NGAYD_D DATE:=PKH_SO_CDT(B_NGAYD); B_NGAYC_D DATE:=PKH_SO_CDT(B_NGAYC); B_DVI_TA VARCHAR2(10);
BEGIN

DELETE TEMP_1; COMMIT;
B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','KT','NX');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
B_DVI_TA:=FTBH_DVI_TA();
IF B_L_CT='HD_NB' THEN
    INSERT INTO TEMP_1(N1,N2,C1,C4,N3,N4)
        SELECT SO_ID,NGAY_HT,SO_HD,'VND',TIEN,SO_ID_D FROM BH_HD_GOC_NB WHERE
        MA_DVI=B_MA_DVI AND SO_ID_KT=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
    UPDATE TEMP_1 SET (C10,C2,C6,C7)=(SELECT PHONG,TEN,MA_DVI,NSD FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=N4);
ELSIF B_L_CT='HD_TT' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C4,N3,C5,C6,C7)
        SELECT A.PHONG,A.SO_ID_TT,A.NGAY_HT,FBH_HD_GOC_SO_HD(B_MA_DVI,B.SO_ID),B.MA_NT,B.TIEN,A.MA_KH,A.MA_DVI,A.NSD
        FROM BH_HD_GOC_TTPS A,BH_HD_GOC_TTHD B WHERE
        A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0 AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND B.MA_DVI=B_MA_DVI AND B.SO_ID_TT=A.SO_ID_TT;
    UPDATE TEMP_1 SET C3=(SELECT MIN(PT) FROM BH_HD_GOC_TTPT WHERE MA_DVI=B_MA_DVI AND SO_ID_TT=N1);
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='HD_HU' THEN
    INSERT INTO TEMP_1(N1,N2,C1,C4,N3)
        SELECT A.SO_ID,A.NGAY_HT,FBH_HD_GOC_SO_HD(B_MA_DVI,A.SO_ID),B.MA_NT,B.TRA
        FROM BH_HD_GOC_HU A,BH_HD_GOC_HUPS B WHERE
        A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0 AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND B.MA_DVI=B_MA_DVI AND B.SO_ID=A.SO_ID;
    UPDATE TEMP_1 SET (C10,C2,C6,C7)=(SELECT PHONG,TEN,MA_DVI,NSD FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=N1);
ELSIF B_L_CT='PB_TT' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C4,N3,C5,C6,C7)
        SELECT A.PHONG,A.SO_ID_TT,A.NGAY_HT,FBH_HD_GOC_SO_HD(A.MA_DVI,B.SO_ID),B.MA_NT,b.phi,A.MA_KH,B.DVI_XL,A.NSD
        FROM BH_HD_GOC_TTPS A,BH_HD_GOC_TTPB B WHERE A.MA_DVI=B.DVI_XL AND A.SO_ID_TT=B.SO_ID_TT
        AND B.MA_DVI=B_MA_DVI AND B.SO_ID_KT=0 AND (B.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM BH_HD_MA_KH WHERE MA_DVI=C6 AND MA=C5);
ELSIF B_L_CT='PB_HU' THEN
    INSERT INTO TEMP_1(N1,N2,C1,C4,N3,C6,C7)
        SELECT A.SO_ID,A.NGAY_HT,FBH_HD_GOC_SO_HD(A.MA_DVI,A.SO_ID),B.MA_NT,b.phi,B.DVI_XL,A.NSD
        FROM BH_HD_GOC_HU A,BH_HD_GOC_TTPB B WHERE A.MA_DVI=B.DVI_XL AND A.SO_ID=B.SO_ID
        AND B.MA_DVI=B_MA_DVI AND B.SO_ID_KT=0 AND (B.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
    UPDATE TEMP_1 SET (C10,C2)=(SELECT PHONG,TEN FROM BH_HD_GOC WHERE MA_DVI=C6 AND SO_ID=N1);
ELSIF B_L_CT='KH_CN' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C3,C4,N3,C5,C6,C7)
        SELECT PHONG,SO_ID,NGAY_HT,SO_CT,L_CT,MA_NT,TIEN,MA_KH,MA_DVI,NSD FROM BH_KH_CN_TU WHERE
        MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='DL_CN' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C3,C4,N3,C5,C6,C7)
        SELECT PHONG,SO_ID,NGAY_HT,L_CT,MA_NT,TIEN,MA_KH,MA_DVI,NSD FROM BH_DL_CN_TU WHERE
        MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='DL_HH' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C4,N3,C5,C6,C7)
        SELECT A.PHONG,A.SO_ID_HH,A.NGAY_HT,FBH_HD_GOC_SO_HD(B_MA_DVI,B.SO_ID),B.MA_NT,B.HHONG+B.HTRO TIEN,A.MA_DL,A.MA_DVI,A.NSD
        FROM BH_HD_GOC_HH A,BH_HD_GOC_HH_CT B WHERE
        A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0 AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND B.MA_DVI=B_MA_DVI AND B.SO_ID_HH=A.SO_ID_HH;
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM BH_DL_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='BT_CN' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C3,C4,N3,C6,C7)
        SELECT PHONG,SO_ID,NGAY_HT,FBH_BT_HS_SOHS(B_MA_DVI,SO_ID_HS),FBH_BT_HS_HD_TEN(B_MA_DVI,SO_ID_HS),L_CT,MA_NT,TIEN,MA_DVI,NSD
        FROM BH_BT_TU WHERE MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
ELSIF B_L_CT='BT_DU' THEN
    INSERT INTO TEMP_1(C10,N1,D1,C4,N3,C6,C7)
        SELECT A.PHONG,A.SO_ID,PKH_SO_DATE(A.NGAY_QD),B.MA_NT,SUM(B.TIEN)+SUM(B.THUE),A.MA_DVI,A.NSD FROM BH_BT_HS A,BH_BT_HS_NV B WHERE
        A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0 AND (a.ngay_qd BETWEEN B_NGAYD AND B_NGAYC) AND
        B.MA_DVI=B_MA_DVI AND B.SO_ID=A.SO_ID GROUP BY A.PHONG,A.SO_ID,A.NGAY_QD,B.MA_NT,A.MA_DVI,A.NSD;
    UPDATE TEMP_1 SET C1=FBH_BT_HS_SOHS(B_MA_DVI,N1),C2=FBH_BT_HS_HD_TEN(B_MA_DVI,N1),N2=PKH_NG_CSO(D1);
ELSIF B_L_CT='PB_BT' THEN
    INSERT INTO TEMP_1(C6,C10,N1,N2,C4,N3)
        SELECT DVI_XL,PHONG,SO_ID,NGAY_HT,MA_NT,SUM(TIEN) FROM BH_BT_HS_PB WHERE
        MA_DVI=B_MA_DVI AND SO_ID_KT=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) GROUP BY DVI_XL,PHONG,SO_ID,NGAY_HT,MA_NT;
    UPDATE TEMP_1 SET C1=FBH_BT_HS_SOHS(C11,N1),C2=FBH_BT_HS_HD_TEN(C11,N1);
ELSIF B_L_CT='BT_CH' THEN
    INSERT INTO TEMP_1(C10,N1,N2,N5,C4,N3,C6,C7)
        SELECT A.PHONG,A.SO_ID_TT,A.NGAY_HT,MIN(B.SO_ID),B.MA_NT,SUM(B.TIEN),A.MA_DVI,A.NSD FROM BH_BT_TT A,BH_BT_TT_PS B WHERE
        A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0 AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND
        B.MA_DVI=B_MA_DVI AND B.SO_ID_TT=A.SO_ID_TT GROUP BY A.PHONG,A.SO_ID_TT,A.NGAY_HT,B.MA_NT;
    UPDATE TEMP_1 SET C1=FBH_BT_HS_SOHS(B_MA_DVI,N5),C2=FBH_BT_HS_HD_TEN(B_MA_DVI,N5);
ELSIF B_L_CT='BT_TH' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C4,N3,C6,C7)
        SELECT PHONG,SO_ID,NGAY_HT,FBH_BT_HS_SOHS(B_MA_DVI,SO_ID_HS),FBH_BT_HS_HD_TEN(B_MA_DVI,SO_ID_HS),MA_NT,TTOAN,MA_DVI,NSD
        FROM BH_BT_THOI WHERE MA_DVI=B_MA_DVI AND SO_ID_KT=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
-- ELSIF B_L_CT='GD_CN' THEN
--     INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C3,C4,N3,C6,C7)
--         SELECT PHONG,SO_ID,NGAY_HT,FBH_BT_GD_SO_HS(B_MA_DVI,SO_ID_HS),FBH_BT_GD_TEN(B_MA_DVI,SO_ID_HS),L_CT,MA_NT,TIEN,MA_DVI,NSD
--         FROM BH_BT_GD_TU WHERE MA_DVI=B_MA_DVI AND SO_ID_KT=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
ELSIF B_L_CT='GD_HT' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C4,N3,C6,C7)
        SELECT PHONG,SO_ID,NGAY_QD,SO_HS,MA_NT,TTOAN,MA_DVI,NSD FROM BH_BT_GD_HS WHERE
        MA_DVI=B_MA_DVI AND SO_ID_KT=0 AND (NGAY_QD BETWEEN B_NGAYD AND B_NGAYC);
-- ELSIF B_L_CT='GD_TT' THEN
--     INSERT INTO TEMP_1(C10,N1,N2,N5,C4,N3,C6,C7)
--         SELECT A.PHONG,A.SO_ID_TT,A.NGAY_HT,MIN(B.SO_ID),B.MA_NT,SUM(B.TIEN),A.MA_DVI,A.NSD FROM BH_BT_GD_TT A,BH_BT_GD_TT_PS B
--         WHERE A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0 AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND
--         B.MA_DVI=B_MA_DVI AND B.SO_ID_TT=A.SO_ID_TT GROUP BY A.PHONG,A.SO_ID_TT,A.NGAY_HT,B.MA_NT;
--     UPDATE TEMP_1 SET C1=FBH_BT_GD_SO_HS(B_MA_DVI,N5),C2=FBH_BT_GD_TEN(B_MA_DVI,N5);
ELSIF B_L_CT='HK_CN' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C3,C4,N3,C6,C7)
        SELECT PHONG,SO_ID,NGAY_HT,FBH_BT_HS_SOHS(B_MA_DVI,SO_ID_HS),FBH_BT_HS_HD_TEN(B_MA_DVI,SO_ID_HS),L_CT,MA_NT,TIEN,MA_DVI,NSD
        FROM BH_BT_HK_TU WHERE MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
ELSIF B_L_CT='TB_TH' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C4,N3,C6,C7)
        SELECT PHONG,SO_ID,NGAY_HT,FBH_BT_HS_SOHS(B_MA_DVI,SO_ID_HS),FBH_BT_HS_HD_TEN(B_MA_DVI,SO_ID_HS),MA_NT,TIEN,MA_DVI,NSD
        FROM BH_BT_NTBA_TT WHERE MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
ELSIF B_L_CT='KHAC' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C3,C4,N3,C6,C7) SELECT PHONG,SO_ID,NGAY_HT,SO_CT,ND,L_CT,MA_NT,TIEN,MA_DVI,NSD
        FROM BH_CP WHERE MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
ELSIF B_L_CT='DO_CN' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C3,C4,N3,C5,C6,C7)
        SELECT ''PHONG,SO_ID,NGAY_HT,L_CT,MA_NT,TIEN,NHA_BH,MA_DVI,NSD FROM BH_DO_BH_CN WHERE
        MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM TBH_MA_NBH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='DO_TT' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C3,C4,N3,C5,C6,C7)
        SELECT PHONG,A.SO_ID_TT,A.NGAY_HT,FBH_HD_GOC_SO_HD(B_MA_DVI,B.SO_ID),B.LOAI,B.MA_NT,B.TIEN TIEN,A.NHA_BH,A.MA_DVI,A.NSD
        FROM BH_HD_DO_TT A,BH_HD_DO_CT B WHERE A.MA_DVI=B_MA_DVI AND A.SO_ID_KT=0
        AND (A.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND B.MA_DVI=B_MA_DVI AND B.SO_ID_TT=A.SO_ID_TT;
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM TBH_MA_NBH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='TA_CN' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C3,C4,N3,C5,C6,C7)
        SELECT B_DVI_TA,SO_ID,NGAY_HT,L_CT,MA_NT,TIEN,NHA_BH,MA_DVI,NSD FROM TBH_NHA_BH_CN WHERE
        MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM TBH_MA_NBH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='TA_TT' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C4,N3,C5,C6,C7) SELECT B_DVI_TA,SO_ID_TT,NGAY_HT,SO_CT,NT_TRA,TRA,NHA_BH,MA_DVI,NSD
        FROM TBH_TT WHERE MA_DVI=B_MA_DVI AND SO_ID_KT=0 AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC);
    UPDATE TEMP_1 SET C2=(SELECT NVL(MIN(TEN),'Ma da bi xoa') FROM TBH_MA_NBH WHERE MA_DVI=B_MA_DVI AND MA=C5);
ELSIF B_L_CT='TA_KH' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C3,C4,N3,C6,C7) SELECT B_DVI_TA,SO_ID,NGAY_HT,SO_CT,''ND,L_CT,MA_NT, 0 TIEN_C_QD,MA_DVI,NSD
        FROM TBH_CP WHERE MA_DVI=B_MA_DVI AND (NGAY_HT BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
ELSIF B_L_CT='BA_P' THEN
    INSERT INTO TEMP_1(C10,N1,N2,C1,C2,C3,C4,N3,C6,C7)
        SELECT PHONG,SO_ID,NGAY_CAP,GCN_S,TEN||DECODE(KIEU_HD,'G','','(nt_chenh:'||TO_CHAR(CHENH+TTOAN)||')'),'P',NT_PHI,TTOAN,MA_DVI,NSD
        FROM BH_NGGCN_BA WHERE MA_DVI=B_MA_DVI AND (NGAY_CAP BETWEEN B_NGAYD AND B_NGAYC) AND SO_ID_KT=0;
END IF;
IF B_MA_PH IS NOT NULL THEN DELETE TEMP_1 WHERE C10<>B_MA_PH; END IF;

IF B_SO_HD IS NOT NULL THEN DELETE TEMP_1 WHERE C1 IS NULL OR UPPER(C1) NOT LIKE B_SO_HD; END IF;
OPEN CS1 FOR SELECT C6 MA_DVI, C7 NSD, C10 PHONG, B_L_CT L_CT ,N1 SO_ID,N2 NGAY,C1 SO_HD,C2 TEN,C3 PT,C4 MA_NT,N3 TIEN FROM TEMP_1 ORDER BY N2,N1,C1,C4;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP procedure PBC_HOI_DVINV;

CREATE OR REPLACE procedure PBC_HOI_DVINV
 (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_quyendv out varchar2)
AS
	b_loi varchar2(100);b_i1 number;
begin
-- Hoi quyen don vi cua nsd theo nghiep vu chung
--	b_quyendv:='1' xem mot don vi
--	b_quyendv:='2' xem nhieu don vi
select count(*) into b_i1 from ht_ma_nsd_qly where ma_dvi=b_ma_dvi and ma=b_nsd and md='BH';
if b_i1 =1 then
	b_quyendv:='1';
else
	b_quyendv:='2';
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP procedure PBC_HOI_QPNV;
CREATE OR REPLACE procedure PBC_HOI_QPNV
 (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_phong_nsd out varchar2,b_quyen out varchar2)

AS
 b_loi varchar2(100);b_i1 number;
begin
-- Hoi phong cua nsd,quyen cua nguoi su dung
b_phong_nsd:=FHT_MA_NSD_PHONG(b_ma_dvi,b_nsd);
select count(*) into b_i1 from ht_ma_nsd_nv where ma_dvi=b_ma_dvi and ma=b_nsd and instr(tc,'X')>0 and md='BH' and nv in ('PHH','HANG','XE','2B','NG','TAU');
if b_i1<>0 then
	b_quyen:=4;
else
	b_quyen:=0;
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP FUNCTION PBC_HOI_QU;
CREATE OR REPLACE FUNCTION PBC_HOI_QU
 (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2) RETURN VARCHAR2
AS
    B_LOI VARCHAR2(100);B_I1 NUMBER;B_I2 NUMBER;
BEGIN
B_I2:=0;
SELECT COUNT(*) INTO B_I1 FROM HT_MA_NSD_NV WHERE MA_DVI=B_MA_DVI AND MA=B_NSD AND INSTR(TC,'X')>0 AND NV='PHH' AND MD='BH';
IF B_I1<>0 THEN B_I2:=B_I2+1; END IF;
SELECT COUNT(*) INTO B_I1 FROM HT_MA_NSD_NV WHERE MA_DVI=B_MA_DVI AND MA=B_NSD AND INSTR(TC,'X')>0 AND NV='2B' AND MD='BH';
IF B_I1<>0 THEN B_I2:=B_I2+1;END IF;
SELECT COUNT(*) INTO B_I1 FROM HT_MA_NSD_NV WHERE MA_DVI=B_MA_DVI AND MA=B_NSD AND INSTR(TC,'X')>0 AND NV='XE' AND MD='BH';
IF B_I1<>0 THEN B_I2:=B_I2+1; END IF;
SELECT COUNT(*) INTO B_I1 FROM HT_MA_NSD_NV WHERE MA_DVI=B_MA_DVI AND MA=B_NSD AND INSTR(TC,'X')>0 AND NV='NG' AND MD='BH';
IF B_I1<>0 THEN B_I2:=B_I2+1; END IF;
SELECT COUNT(*) INTO B_I1 FROM HT_MA_NSD_NV WHERE MA_DVI=B_MA_DVI AND MA=B_NSD AND INSTR(TC,'X')>0 AND NV='TAU' AND MD='BH';
IF B_I1<>0 THEN B_I2:=B_I2+1; END IF;
SELECT COUNT(*) INTO B_I1 FROM HT_MA_NSD_NV WHERE MA_DVI=B_MA_DVI AND MA=B_NSD AND INSTR(TC,'X')>0 AND NV='HANG' AND MD='BH';
IF B_I1<>0 THEN B_I2:=B_I2+1; END IF;
IF B_I2=6 THEN RETURN 'C'; ELSE RETURN 'K'; END IF;
END;
/
DROP PROCEDURE PBC_LAY_DVI;
CREATE OR REPLACE PROCEDURE PBC_LAY_DVI
 (b_madvi varchar2,b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_loi out varchar2)
AS
    b_i1 number;b_i2 number;
begin
-- BCNam: Lay danh sach don vi, mac dinh tai 00
EXECUTE IMMEDIATE 'TRUNCATE TABLE temp_bc_dvi';
select count(*) into b_i1 from ht_ma_nsd_qly where ma_dvi=b_madvi and ma=b_nsd and md='BH';
if b_ma_dvi is null or b_ma_dvi='00' then
    if b_i1 > 0 then
        insert into temp_bc_dvi(dvi) select dvi from ht_ma_nsd_qly where ma_dvi=b_madvi and ma=b_nsd and md='BH';
    elsif b_i1 = 0 then
        insert into temp_bc_dvi(dvi) select ma from ht_ma_dvi where ma_goc='00';
    end if;
else
    select count(*) into b_i2 from ht_ma_nsd_qly where ma_dvi=b_madvi and dvi=b_ma_dvi and ma=b_nsd and md='BH';
    if b_i2=0 and b_i1<>0 then
        b_loi:='loi: Ban khong co quyen xem bao cao don vi nay 3:loi'; return;
    else
        insert into temp_bc_dvi(dvi) values (b_ma_dvi);
    end if;
end if;
commit;
b_loi:='';
exception when others then null;
end;
/

DROP PROCEDURE PBC_LAY_NV;

CREATE OR REPLACE PROCEDURE PBC_LAY_NV
 (b_madvi varchar2,b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2,b_phong varchar2)
AS
    b_i1 number;b_i2 number;
begin
-- Lay danh sach nghiep vu
delete temp_bc_phong;
delete temp_bc_nv;
insert into temp_bc_nv(nv) select nv from ht_ma_nsd_nv where ma_dvi=b_madvi and ma=b_nsd and (instr(tc,'X')>0 or instr(tc,'N')>0) and md='BH';
if PBC_HOI_QU(b_ma_dvi,b_nsd,b_pas)<>'C' and b_phong is not null then
    --xem so lieu cua phong minh
    insert into temp_bc_nv(nv) select nv from ht_ma_nsd_nv where ma_dvi=b_madvi and ma=b_nsd and instr(tc,'N')>0 and md='BH';
end if;


select count(*) into b_i2 from temp_bc_nv where nv='2B';

if b_i2 >0 then
    insert into temp_bc_nv(nv) values('2BL');
    insert into temp_bc_nv(nv) values('XG');
end if;
select count(*) into b_i2 from temp_bc_nv where nv='XE';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('XEL');
    insert into temp_bc_nv(nv) values('XG');
end if;

select count(*) into b_i2 from temp_bc_nv where nv='TAU';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('TAUL');
    insert into temp_bc_nv(nv) values('TT');
    insert into temp_bc_nv(nv) values('HK');
    insert into temp_bc_nv(nv) values('NL');
    insert into temp_bc_nv(nv) values('CN.6');
end if;

select count(*) into b_i2 from temp_bc_nv where nv='PHH';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('TS');
    insert into temp_bc_nv(nv) values('HP');
end if;

select count(*) into b_i2 from temp_bc_nv where nv='PKT';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('KT');
end if;
select count(*) into b_i2 from temp_bc_nv where nv='PTN';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('TN');
end if;
select count(*) into b_i2 from temp_bc_nv where nv='HOP';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('HOP');
end if;
select count(*) into b_i2 from temp_bc_nv where nv='HANG';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('HH');
end if;

select count(*) into b_i2 from temp_bc_nv where nv='NG';
if b_i2 >0 then
    insert into temp_bc_nv(nv) values('CN');
    insert into temp_bc_nv(nv) values('SK');
    insert into temp_bc_nv(nv) values('SKL');
end if;


commit;
end;
/
DROP PROCEDURE PBC_TS_BC_QTRI;
CREATE OR REPLACE PROCEDURE PBC_TS_BC_QTRI(b_ma_dvi varchar2,b_ngayd number,b_ngayc number,b_phong varchar2,b_lhnv varchar2,b_ma_kh varchar2,b_nguon varchar2,b_ma_dl varchar2)
as
begin
delete temp_bc_ts;delete BH_THANG2D_BC_DT_LUU;commit;
insert into temp_bc_ts values (b_ma_dvi||'%',b_ngayd,b_ngayc);
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTPS_MNVM';
BC_BH_LAY_BC_BH_DTPS_MNVM(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n2, n3)
select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
from TEMP_BC_BH_DTPS_MNVM where 
(b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
and (b_ma_dl is null or ma_kt=b_ma_dl) 
and ma_dvi like b_ma_dvi||'%'
group by nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
-- doanht hu ban hang trong ky
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTBH_MNVM';
BC_BH_LAY_BC_BH_DTBH_MNVM(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n4, n5)
select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
from TEMP_BC_BH_DTBH_MNVM where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
and (b_ma_dl is null or ma_kt=b_ma_dl)  and ma_dvi like b_ma_dvi||'%'
group by nv,so_id, ma_dvig, ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
-- doanh thu thuc thu trong ky
EXECUTE IMMEDIATE 'TRUNCATE TABLE TEMP_BC_BH_DTTT_MA_DT';
BC_BH_LAY_BC_BH_DTTT_MA_DT(b_ma_dvi,b_ngayd,b_ngayc);
insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
from TEMP_BC_BH_DTTT_MA_DT where (b_phong is null or phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
and (b_ma_kh is null or ma_kh=b_ma_kh) and (b_nguon is null or nguon like b_nguon||'%')
and (b_ma_dl is null or ma_kt=b_ma_dl)  and ma_dvi like b_ma_dvi||'%'
group by nv,so_id, ma_dvig, ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id;
end;
/
