DROP PROCEDURE PBH_BC_DT_BT_GOC_XE;

CREATE OR REPLACE PROCEDURE PBH_BC_DT_BT_GOC_XE
     (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,
    b_ma_kh varchar2,b_ma_cb varchar2,b_ma_dl varchar2,b_loai_kh varchar2,b_kieu_kt varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaynt number;b_i1 number;
    b_ngay_c number; b_d1 number; b_d2 number;b_ma_vp varchar2(20);b_i2 number;
begin

--if b_nsd='ADMIN' and b_madvi='00' then  b_loi:='loi:11-'||b_ma_dvi||':loi'; raise PROGRAM_ERROR; end if;

--b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
--if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;
PBC_LAY_NV(b_madvi,b_ma_dvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
    b_loi:='loi:Ban khong co quyen xem bao cao nay1:loi'; raise PROGRAM_ERROR;
end if;
delete bc_bh_bt_temp;delete ket_qua; commit;
delete temp_bc_ts;
if b_ma_dvi='00' then
    PBC_BH_TS(b_madvi,b_nsd,'',b_ngayd,b_ngayc,b_loi);
else
    PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,b_ngayd,b_ngayc,b_loi);
end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;
--tien da duyet
PBC_BH_TH_BT_PB_MD('T');
insert into bc_bh_bt_temp(ma_dvi,n2,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd)
                    select ma_dvi,tien_qd,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd from bc_bh_bt_hs_temp
                    where ngay_qd_n<30000101 and ngay_ht between b_ngayd and b_ngayc
                                and nv in ('2B','2BL','XE','XEL') and (b_phong is null or phong=b_phong)
                                and (b_ma_nv is null or lh_nv like b_ma_nv||'%');

-- Doanh thu ban hang
insert into bc_bh_bt_temp(ma_dvi,n8,nv,lh_nv,phong,so_id_hd,ma_dvi_hd) select ma_dvi,phi,nv,lh_nv,phong,so_id,ma_dvig
    from V_BC_BH_DTBH_MM where (b_ma_nv is null or lh_nv like b_ma_nv||'%') and (b_phong is null or phong=b_phong) and nv in ('2B','2BL','XE','XEL')
--insert into bc_bh_bt_temp(ma_dvi,n8,nv,lh_nv,phong,so_id_hd,ma_dvi_hd) select ma_dvi,phi,nv,lh_nv,phong,so_id,ma_dvig
--    from bh_kq where (b_ma_nv is null or lh_nv like b_ma_nv||'%')
    and (b_phong is null or phong=b_phong) and ngay_htnv between b_ngayd and b_ngayc --and chitieu='DTBH'
    and nv in ('2B','2BL','XE','XEL');

-- chua giai quyet
PBC_BH_BT_CGQ_MD('T');
insert into bc_bh_bt_temp(ma_dvi,n4,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd)
                    select ma_dvi,n5,so_id,c2,lh_nv,c3,n2,n3,c4 from temp_bt_1 where c2 in('XE','XEL','2B','2BL')
                        and n2 between b_ngayd and b_ngayc and (b_phong is null or c3=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv||'%');
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,b_ngaydn,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
-- boi thuong luy ke
PBC_BH_TH_BT_PB_MD('T');
insert into bc_bh_bt_temp(ma_dvi,n3,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd)
                    select ma_dvi,tien_qd,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd from bc_bh_bt_hs_temp
                                    where ngay_qd_n<30000101 and nv in ('2B','2BL','XE','XEL') and (b_phong is null or phong=b_phong)
                                        and (b_ma_nv is null or lh_nv like b_ma_nv||'%');
delete temp_bc_ts;
PBC_BH_TS(b_madvi,b_nsd,b_ma_dvi,20000101,b_ngayc,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
-- chua giai quyet luy ke
PBC_BH_BT_CGQ_MD('T');
insert into bc_bh_bt_temp(ma_dvi,n5,so_id,nv,lh_nv,phong,ngay_ht,so_id_hd,ma_dvi_hd)
                    select ma_dvi,n5,so_id,c2,lh_nv,c3,n2,n3,c4 from temp_bt_1 where c2 in('XE','XEL','2B','2BL')
                                            and (b_phong is null or c3=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv||'%');
--update bc_bh_bt_temp t1 set c5=(select muc_rr from bh_xelgcn  where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd and rownum=1) where nv='XEL';--
--update bc_bh_bt_temp t1 set c5=(select muc_rr from bh_xegcn where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd and rownum=1) where nv='XE';--ma_dvi=c29 and
update bc_bh_bt_temp set n6=nvl(n2,0)+nvl(n4,0),n7=nvl(n3,0)+nvl(n5,0);
 update bc_bh_bt_temp t1 set c15=(select ten from ht_ma_dvi where ma= t1.ma_dvi);
 update bc_bh_bt_temp t1 set c16=(select ten from ht_ma_phong where ma_dvi=t1.ma_dvi and ma=t1.phong);
--update
--       (select bc_bh_bt_temp.c15 bc_bh_bt_temp_c15, ht_ma_dvi.ten ht_ma_dvi_ten
--              from bc_bh_bt_temp, ht_ma_dvi
--             where bc_bh_bt_temp.ma_dvi = ht_ma_dvi.ma)
--       set bc_bh_bt_temp_c15 = ht_ma_dvi_ten;
--update
--       (select bc_bh_bt_temp.c16 bc_bh_bt_temp_c16, ht_ma_phong.ten ht_ma_phong_ten
--              from bc_bh_bt_temp, ht_ma_phong
--             where bc_bh_bt_temp.ma_dvi = ht_ma_phong.ma_dvi and bc_bh_bt_temp.phong = ht_ma_phong.ma)
--       set bc_bh_bt_temp_c16 = ht_ma_phong_ten;

update bc_bh_bt_temp t1 set (c10,c11,c12,c13,c30)=(select ma_kh,ma_kt,kieu_kt,cb_ql,so_hd from bh_hd_goc where ma_dvi=t1.ma_dvi_hd and so_id=t1.so_id_hd);
update
       (select /*+ parallel(4) */ bc_bh_bt_temp.c14 bc_bh_bt_temp_c14, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from bc_bh_bt_temp, bh_hd_ma_kh
             where bc_bh_bt_temp.ma_dvi_hd = bh_hd_ma_kh.ma_dvi and bc_bh_bt_temp.c10 = bh_hd_ma_kh.ma)
       set bc_bh_bt_temp_c14 = bh_hd_ma_kh_loai;

if b_loai_kh is not null then
    delete bc_bh_bt_temp where c14<> b_loai_kh;
end if;
if b_ma_kh is not null then
    delete bc_bh_bt_temp where c10<> b_ma_kh;
end if;
if b_ma_cb is not null then
    delete bc_bh_bt_temp where c13<> b_ma_cb;
end if;
if b_ma_dl is not null then
    delete bc_bh_bt_temp where c11<> b_ma_dl and c12 not in('D','M');
end if;
select max(ma) into b_ma_vp from ht_ma_dvi where vp='C' and rownum=1;
--select * from bc_bh_bt_temp
update bc_bh_bt_temp b set c29 =(select so_hs from bh_bt_hs a where a.ma_dvi=b.ma_dvi and a.so_id=b.so_id);-- where n5 <>0 or n3 <>0;
commit;
open cs_kq for
select ma_dvi,c15 ten_dvi,nv,lh_nv,c30 so_hd,c29 so_hs,phong,c16 ten_phong,ma_dvi_hd,c10 ma_kh,c14 loai_kh,c11 ma_kt,c13 kieu_kt,c13 cb_ql,n8 phi,n2 bt_dgq_tk,n3 bt_dgq_lk,n4 bt_cgq_tk,n5 bt_cgq_lk from bc_bh_bt_temp
order by ma_dvi,so_id,so_id_hd;
end;
/

DROP PROCEDURE PBH_BC_QT_DT_GD_NEW_MIC;
CREATE OR REPLACE PROCEDURE PBH_BC_QT_DT_GD_NEW_MIC
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_loai_kh varchar2,b_kieu_kt varchar2,
    b_kieu varchar2,b_ngayd_lk number,b_ngayc_lk number,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100); b_ngay_c number; b_d1 number; b_d2 number;
    b_ma_vp varchar2(20);b_i1 number;b_kieu1 varchar2(20);b_ngayd_nt number;b_ngayc_nt number;
begin
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
--b_loi:='loi:BCNam:loi';
if b_loi is not null then raise PROGRAM_ERROR; end if;
--select max(ngayc) into b_ngay_c from kt_baocao.bh_bc_qt_dt where kieu=b_kieu;
--select ngay into b_ngay_c from bh_bc_sl_ts where loai='QT_DT' and kieu=b_kieu;
b_ngay_c:=b_ngayc;
b_ngayd_nt:=round(b_ngayd)-10000;
b_ngayc_nt:=round(b_ngayc)-10000;
delete ket_qua;delete temp_3;delete temp_1;delete temp_5;commit;
b_d1:=b_ngayd; b_d2:=b_ngayc;
--4. Lay so lieu cung ky nam truoc
--PBH_THANG2D_BC_QT_TH(b_madvi,b_nsd,b_pas,b_ngayd_nt,b_ngayc_nt);
PBC_TS_BC_QTRI(b_ma_dvi,b_ngayd_nt,b_ngayc_nt,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,nv,lh_nv,dt_ps,thue_dtps,dt_bh,thue_dtbh,dt_tt,thue_dttt)
    select c20,c2,c10,c8,sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)) from temp_2 group by c20,c2,c10,c8;
insert into temp_5(c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6)
    select ma_dvi,phong,'',lh_nv,'',sum(dt_ps),sum(thue_dtps),sum(dt_bh),sum(thue_dtbh),sum(dt_tt),sum(thue_dttt)
    from BH_THANG2D_BC_DT_LUU where (b_ma_dvi is null or ma_dvi=b_ma_dvi) 
--      and (b_phong is null or phong=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv||'%') (ngay between b_ngayd_nt and b_ngayc_nt) and 
    group by ma_dvi,phong,lh_nv;

PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
select ma into b_ma_vp from ht_ma_dvi where vp='C' and rownum=1;
if b_ma_dvi is null then
    select count(*) into b_i1 from bh_ma_lhnv_kh where
        ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    if b_i1<>0 then
        insert into temp_3(c1,c8,n7) select dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
        insert into temp_1(c1,c8,n7) select dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    else
        insert into temp_3(c1,c8,n7) select ma_dvi,ma,kh from bh_ma_lhnv_kh where
            (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
        insert into temp_1(c1,c8,n7) select ma_dvi,ma,kh from bh_ma_lhnv_kh where
            (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    end if;
-- so van phong
    insert into temp_3(c1,c2,c8,n7) select ma_dvi,dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_ma_vp and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    insert into temp_1(c1,c2,c8,n7) select ma_dvi,dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_ma_vp and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
else
    select count(*) into b_i1 from bh_ma_lhnv_kh where
        ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    if b_i1=0 then b_kieu1:='C'; else b_kieu1:='P'; end if;
    insert into temp_3(c1,c8,c2,n7) select ma_dvi,ma,dvi,kh from bh_ma_lhnv_kh where
        ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
         and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu=b_kieu1 and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    insert into temp_1(c1,c8,c2,n7) select ma_dvi,ma,dvi,kh from bh_ma_lhnv_kh where
        ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu=b_kieu1 and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
end if;
update temp_3 set c9=(select ten from ht_ma_phong where ma_dvi=temp_3.c1 and ma=temp_3.c2);
update temp_3 set c10=(select ten from ht_ma_dvi where ma=temp_3.c1);
update temp_1 set c9=(select ten from ht_ma_phong where ma_dvi=temp_1.c1 and ma=temp_1.c2);
update temp_1 set c10=(select ten from ht_ma_dvi where ma=temp_1.c1);
update temp_5 set c9=(select ten from ht_ma_phong where ma_dvi=temp_5.c1 and ma=temp_5.c2);
update temp_5 set c10=(select ten from ht_ma_dvi where ma=temp_5.c1);

--tong doanh thu
insert into ket_qua (n20,c20,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 1,'A',U'Doanh thu b\1E9Ao hi\1EC3m g\1ED1c',sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3;
update ket_qua kq set n25=(select sum(nvl(n3,0)) from temp_1 t);-- where kq.n20=1;
update ket_qua kq set n26=(select sum(nvl(n3,0)) from temp_5 t);
--tong van phong
insert into ket_qua (c1,n20,c20,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select c1,2,'I',c10,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3 where c1 =b_ma_vp group by c10,c1;
update ket_qua kq set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1=b_ma_vp and t.c1=kq.c1 group by c10,c1);
update ket_qua kq set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1=b_ma_vp and t.c1=kq.c1 group by c10,c1);
--chi tiet van phong
delete temp_4;
insert into temp_4(n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 3,'',c2,c9,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3 where c1=b_ma_vp group by c2,c9 order by c2;
update temp_4 t4 set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1=b_ma_vp and t.c2=t4.c1 group by c2,c9);
update temp_4 t4 set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1=b_ma_vp and t.c2=t4.c1 group by c2,c9);
insert into ket_qua (n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26)
    select  n20,to_char(rownum),c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26 from temp_4;
delete temp_4 where c1='000' and c10 is null;
--Tong cac chi nhanh
insert into ket_qua (n20,c20,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 4,'II',U'C\00E1c chi nh\00E1nh',sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3 where c1 <>b_ma_vp ;
update ket_qua kq set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1<>b_ma_vp) where kq.n20=4;
update ket_qua kq set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1<>b_ma_vp) where kq.n20=4;
--Chi tiet cac don vi
delete temp_4;
insert into temp_4(n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 5,'',c1,c10,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0))
    from temp_3 where c1 <> b_ma_vp group by c1,c10 order by c1;
update temp_4 t4 set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1 <> b_ma_vp and t.c1=t4.c1 group by c1,c10);
update temp_4 t4 set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1 <> b_ma_vp and t.c1=t4.c1 group by c1,c10);
insert into ket_qua (n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26)
    select n20,to_char(rownum),c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26
     from temp_4;
/**/
commit;

update ket_qua set c10=(Select max(ten_gon) from ht_ma_dvi where ma=c1) where n20=5;

select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    open cs_kq for select c20 ct,c1 ma_dvi,c10 ten_dvi,nvl(n7,0) ke_hoach,
        nvl(n1,0) phi_ps,nvl(n2,0) thue_ps,nvl(n11,0) phi_ps_lk,nvl(n12,0)+nvl(n2,0) thue_ps_lk,--+nvl(n1,0)
        nvl(n3,0) phi_bh,nvl(n4,0) thue_bh,nvl(n13,0) phi_bh_lk,--+nvl(n3,0)
        nvl(n14,0)+nvl(n4,0) thue_bh_lk,nvl(n5,0) phi_tt,nvl(n6,0) thue_tt,nvl(n15,0) phi_tt_lk,--+nvl(n5,0)
        nvl(n16,0)+nvl(n6,0) thue_tt_lk,nvl(n25,0) phi_bh_pt,nvl(n26,0) phi_bh_cknt,
        decode(nvl(n7,0),0,0,round(round(n13/n7,4)*100,2))  pt_kh,decode(nvl(n25,0),0,0,round(round(n3/n25,4)*100,2)) pt,
        decode(nvl(n26,0),0,0,round(round(n3/n26,4)*100,2)) pt_cknt
        from ket_qua order by n20,c1;
else
    open cs_kq for select c20 ct,c1 ma_dvi,c10 ten_dvi,nvl(n7,0) ke_hoach,
        nvl(n1,0) phi_ps,nvl(n2,0) thue_ps,nvl(n11,0) phi_ps_lk,nvl(n12,0)+nvl(n2,0) thue_ps_lk,--+nvl(n1,0)
        nvl(n3,0) phi_bh,nvl(n4,0) thue_bh,nvl(n13,0) phi_bh_lk,--+nvl(n3,0)
        nvl(n14,0)+nvl(n4,0) thue_bh_lk,nvl(n5,0) phi_tt,nvl(n6,0) thue_tt,nvl(n15,0) phi_tt_lk,--+nvl(n5,0)
        nvl(n16,0)+nvl(n6,0) thue_tt_lk,nvl(n25,0) phi_bh_pt,nvl(n26,0) phi_bh_cknt,
        decode(nvl(n7,0),0,0,round(round(n13/n7,4)*100,2)) pt_kh,decode(nvl(n25,0),0,0,round(round(n3/n25,4)*100,2)) pt,
        decode(nvl(n26,0),0,0,round(round(n3/n26,4)*100,2)) pt_cknt
        from ket_qua,temp_bc_dvi where c1=dvi order by n20,c1;
end if;
exception when others then if b_loi is null then raise PROGRAM_ERROR; else null; end if;
end;
/

DROP PROCEDURE PBH_BC_QT_DT_NV_GD_MIC;
CREATE OR REPLACE PROCEDURE PBH_BC_QT_DT_NV_GD_MIC
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,b_phong varchar2,b_ma_nv varchar2,b_loai_kh varchar2,b_kieu_kt varchar2,
    b_kieu varchar2,b_ngayd_lk number,b_ngayc_lk number,b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100); b_ngay_c number; b_d1 number; b_d2 number;
    b_ma_vp varchar2(20);b_i1 number;b_kieu1 varchar2(20);
    b_ngayd_nt number;b_ngayc_nt number;
begin
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--select ngay into b_ngay_c from bh_bc_sl_ts where loai='QT_DT' and kieu=b_kieu;
b_ngayd_nt:=round(b_ngayd)-10000;
b_ngayc_nt:=round(b_ngayc)-10000;
delete ket_qua;delete temp_3;delete temp_1;delete temp_5;commit;
b_d1:=b_ngayd; b_d2:=b_ngayc;
--4. Lay so lieu cung ky nam truoc
--PBH_THANG2D_BC_QT_TH(b_madvi,b_nsd,b_pas,b_ngayd_nt,b_ngayc_nt);
PBC_TS_BC_QTRI(b_ma_dvi,b_ngayd_nt,b_ngayc_nt,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,nv,lh_nv,dt_ps,thue_dtps,dt_bh,thue_dtbh,dt_tt,thue_dttt)
    select c20,c2,c10,c8,sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)) from temp_2 group by c20,c2,c10,c8;
insert into temp_5(c1,c2,c3,c4,c5,n1,n2,n3,n4,n5,n6)
    select ma_dvi,phong,'',lh_nv,'',sum(dt_ps),sum(thue_dtps),sum(dt_bh),sum(thue_dtbh),sum(dt_tt),sum(thue_dttt)
    from BH_THANG2D_BC_DT_LUU where (b_ma_dvi is null or ma_dvi=b_ma_dvi) 
--      and (b_phong is null or phong=b_phong) and (b_ma_nv is null or lh_nv like b_ma_nv||'%') (ngay between b_ngayd_nt and b_ngayc_nt) and 
    group by ma_dvi,phong,lh_nv;

PBC_LAY_DVI(b_madvi,b_ma_dvi,b_nsd,b_pas,b_loi);
if b_loi is not null then raise PROGRAM_ERROR; end if;
select ma into b_ma_vp from ht_ma_dvi where vp='C' and rownum=1;
if b_ma_dvi is null then
    select count(*) into b_i1 from bh_ma_lhnv_kh where
        ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    if b_i1<>0 then
        insert into temp_3(c1,c8,n7) select dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
        insert into temp_1(c1,c8,n7) select dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_madvi and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    else
        insert into temp_3(c1,c8,n7) select ma_dvi,ma,kh from bh_ma_lhnv_kh where
            (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
        insert into temp_1(c1,c8,n7) select ma_dvi,ma,kh from bh_ma_lhnv_kh where
            (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='C' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    end if;
-- so van phong
    insert into temp_3(c1,c2,c8,n7) select ma_dvi,dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_ma_vp and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    insert into temp_1(c1,c2,c8,n7) select ma_dvi,dvi,ma,kh from bh_ma_lhnv_kh where
            ma_dvi=b_ma_vp and (b_ma_nv is null or ma like b_ma_nv||'%')
            and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
else
    select count(*) into b_i1 from bh_ma_lhnv_kh where
        ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu='P' and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    if b_i1=0 then b_kieu1:='C'; else b_kieu1:='P'; end if;
    insert into temp_3(c1,c8,c2,n7) select ma_dvi,ma,dvi,kh from bh_ma_lhnv_kh where
        ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
         and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu=b_kieu1 and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
    insert into temp_1(c1,c8,c2,n7) select ma_dvi,ma,dvi,kh from bh_ma_lhnv_kh where
        ma_dvi=b_ma_dvi and (b_ma_nv is null or ma like b_ma_nv||'%')
        and substr(ngay,1,4)=substr(b_ngayd,1,4) and kieu=b_kieu1 and kh<>0 and SUBSTR(ma,1,2) in (Select nv from temp_bc_nv);
end if;
update temp_3 set c9=(select ten from ht_ma_phong where ma_dvi=temp_3.c1 and ma=temp_3.c2);
update temp_3 set c10=(select ten from ht_ma_dvi where ma=temp_3.c1);
update temp_1 set c9=(select ten from ht_ma_phong where ma_dvi=temp_1.c1 and ma=temp_1.c2);
update temp_1 set c10=(select ten from ht_ma_dvi where ma=temp_1.c1);
update temp_5 set c9=(select ten from ht_ma_phong where ma_dvi=temp_5.c1 and ma=temp_5.c2);
update temp_5 set c10=(select ten from ht_ma_dvi where ma=temp_5.c1);

--tong doanh thu
insert into ket_qua (n20,c20,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 1,'A',U'Doanh thu b\1E9Ao hi\1EC3m g\1ED1c',sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3;
update ket_qua kq set n25=(select sum(nvl(n3,0)) from temp_1 t);-- where kq.n20=1;
update ket_qua kq set n26=(select sum(nvl(n3,0)) from temp_5 t);
--tong van phong
insert into ket_qua (c1,n20,c20,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select c1,2,'I',c10,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3 where c1 =b_ma_vp group by c10,c1;
update ket_qua kq set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1=b_ma_vp and t.c1=kq.c1 group by c10,c1);
update ket_qua kq set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1=b_ma_vp and t.c1=kq.c1 group by c10,c1);
--chi tiet van phong
delete temp_4;
insert into temp_4(n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 3,'',c2,c9,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3 where c1=b_ma_vp group by c2,c9 order by c2;
update temp_4 t4 set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1=b_ma_vp and t.c2=t4.c1 group by c2,c9);
update temp_4 t4 set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1=b_ma_vp and t.c2=t4.c1 group by c2,c9);
insert into ket_qua (n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26)
    select  n20,to_char(rownum),c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26 from temp_4;
delete temp_4 where c1='000' and c10 is null;
--Tong cac chi nhanh
insert into ket_qua (n20,c20,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 4,'II',U'C\00E1c chi nh\00E1nh',sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0)) from temp_3 where c1 <>b_ma_vp ;
update ket_qua kq set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1<>b_ma_vp) where kq.n20=4;
update ket_qua kq set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1<>b_ma_vp) where kq.n20=4;
--Chi tiet cac don vi
delete temp_4;
insert into temp_4(n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16)
    select 5,'',c1,c10,sum(nvl(n1,0)),sum(nvl(n2,0)),sum(nvl(n3,0)),sum(nvl(n4,0)),
    sum(nvl(n5,0)),sum(nvl(n6,0)),sum(nvl(n7,0)),sum(nvl(n11,0)),sum(nvl(n12,0)),sum(nvl(n13,0)),sum(nvl(n14,0)),
    sum(nvl(n15,0)),sum(nvl(n16,0))
    from temp_3 where c1 <> b_ma_vp group by c1,c10 order by c1;
update temp_4 t4 set n25=(select sum(nvl(n3,0)) from temp_1 t where t.c1 <> b_ma_vp and t.c1=t4.c1 group by c1,c10);
update temp_4 t4 set n26=(select sum(nvl(n3,0)) from temp_5 t where t.c1 <> b_ma_vp and t.c1=t4.c1 group by c1,c10);
insert into ket_qua (n20,c20,c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26)
    select n20,to_char(rownum),c1,c10,n1,n2,n3,n4,n5,n6,n7,n11,n12,n13,n14,n15,n16,n25,n26
     from temp_4;
/**/
commit;

update ket_qua set c10=(Select max(ten_gon) from ht_ma_dvi where ma=c1) where n20=5;

select count(*) into b_i1 from temp_bc_dvi;
if b_i1=0 then
    open cs_kq for select c20 ct,c1 ma_dvi,c10 ten_dvi,nvl(n7,0) ke_hoach,
        nvl(n1,0) phi_ps,nvl(n2,0) thue_ps,nvl(n11,0) phi_ps_lk,nvl(n12,0)+nvl(n2,0) thue_ps_lk,--+nvl(n1,0)
        nvl(n3,0) phi_bh,nvl(n4,0) thue_bh,nvl(n13,0) phi_bh_lk,--+nvl(n3,0)
        nvl(n14,0)+nvl(n4,0) thue_bh_lk,nvl(n5,0) phi_tt,nvl(n6,0) thue_tt,nvl(n15,0) phi_tt_lk,--+nvl(n5,0)
        nvl(n16,0)+nvl(n6,0) thue_tt_lk,nvl(n25,0) phi_bh_pt,nvl(n26,0) phi_bh_cknt,
        decode(nvl(n7,0),0,0,round(round(n13/n7,4)*100,2))  pt_kh,decode(nvl(n25,0),0,0,round(round(n3/n25,4)*100,2)) pt,
        decode(nvl(n26,0),0,0,round(round(n3/n26,4)*100,2)) pt_cknt
        from ket_qua order by n20,c1;
else
    open cs_kq for select c20 ct,c1 ma_dvi,c10 ten_dvi,nvl(n7,0) ke_hoach,
        nvl(n1,0) phi_ps,nvl(n2,0) thue_ps,nvl(n11,0) phi_ps_lk,nvl(n12,0)+nvl(n2,0) thue_ps_lk,--+nvl(n1,0)
        nvl(n3,0) phi_bh,nvl(n4,0) thue_bh,nvl(n13,0) phi_bh_lk,--+nvl(n3,0)
        nvl(n14,0)+nvl(n4,0) thue_bh_lk,nvl(n5,0) phi_tt,nvl(n6,0) thue_tt,nvl(n15,0) phi_tt_lk,--+nvl(n5,0)
        nvl(n16,0)+nvl(n6,0) thue_tt_lk,nvl(n25,0) phi_bh_pt,nvl(n26,0) phi_bh_cknt,
        decode(nvl(n7,0),0,0,round(round(n13/n7,4)*100,2)) pt_kh,decode(nvl(n25,0),0,0,round(round(n3/n25,4)*100,2)) pt,
        decode(nvl(n26,0),0,0,round(round(n3/n26,4)*100,2)) pt_cknt
        from ket_qua,temp_bc_dvi where c1=dvi order by n20,c1;
end if;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP FUNCTION PBH_HD_GOC_DHD_SHD;

CREATE OR REPLACE FUNCTION PBH_HD_GOC_DHD_SHD
    (B_MA_DVI VARCHAR2,B_SO_ID NUMBER,B_NGAY_HT NUMBER) RETURN VARCHAR2
AS
    B_LOI VARCHAR2(100); B_NGAY_M NUMBER; B_SO_HD VARCHAR2(50):='';
BEGIN

IF B_SO_ID IS NOT NULL THEN
    SELECT MIN(SO_HD) INTO B_SO_HD FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID;
END IF;
RETURN B_SO_HD;
END;
/

DROP FUNCTION PBH_HD_GOC_DHD_SOID;

CREATE OR REPLACE FUNCTION PBH_HD_GOC_DHD_SOID (B_MA_DVI VARCHAR2,B_SO_HD VARCHAR2) RETURN NUMBER
AS
	B_LOI VARCHAR2(100); B_SO_ID NUMBER:=0;
BEGIN

IF B_SO_HD IS NOT NULL THEN
	SELECT NVL(MAX(SO_ID),0) INTO B_SO_ID FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_HD=B_SO_HD;
END IF;
RETURN B_SO_ID;
END;
/
DROP PROCEDURE PBH_HIEPHOI_BH;

CREATE OR REPLACE PROCEDURE PBH_HIEPHOI_BH
      (b_madvi varchar2,b_nsd varchar2,b_pas varchar2,
    b_ma_dvi varchar2,loai varchar2,b_ngay_d number, b_ngay_c number ,cs1 out pht_type.cs_type)
AS
      b_loi varchar2(100);cs sys_refcursor;--b_ngay_d number;b_ngay_c number;
begin
delete temp_1;

if loai='KO' then
insert into temp_1 (c2,c1,c3,n4,n5,n6,n1,n2,c4)
select c.ma_kh, c.ma_dvi, a.gcn, b.phi, c.ngay_ht, c.ngay_ht, c.so_id, a.so_id_dt, b.lh_nv from bh_xe_ds a,bh_xe_dk b,bh_xe c where c.ttrang='D' and c.ma_dvi=b.ma_dvi and c.so_id=b.so_id and b.MA_DVI=a.MA_DVI and a.so_id=b.so_id and a.so_id_dt=b.SO_ID_DT and lh_nv in (select MA from bh_ma_lhnv where nv like '%XE%' and BB='B') ;
merge into temp_1 a 
using (select ma_dvi, so_id, max(ngay_hl) ngay_hl, max(ngay_kt) ngay_kt, max(loai_xe) loai_xe, max(bien_xe) bien_xe, max(so_khung)so_khung, max(so_may)so_may, max(nam_sx)nam_sx, max(gio_hl)gio_hl,max(gio_kt)gio_kt from bh_xe_ds group by ma_dvi, so_id) b 
on (a.c1 = b.ma_dvi and a.n1 = b.so_id) 
when matched then update 
set a.d1 = PKH_SO_CNG_DATE(b.ngay_hl), a.d2 = PKH_SO_CNG_DATE(b.ngay_kt), a.c10 = b.loai_xe, a.c11 = b.bien_xe, a.c12= b.so_khung, a.c13 = b.so_may, a.c14 = b.nam_sx, a.c15 = b.gio_hl, a.c16 = b.gio_kt;

    delete TEMP_HH_KO;
    insert into TEMP_HH_KO
    select b.ten CH_TEN_CHU_XE , --X
    case when fbh_hh_lay_nhomkh(a.c2, a.c1) is null then 'LC01' else fbh_hh_lay_nhomkh(a.c2, '') end CH_LA_TO_CHUC,  --X
    ' ' CH_SO_ID,       --X
    'TP01' CH_TINH_THANH_PHO,  --X
    ' ' CH_DIA_CHI,
    ' ' CH_DIEN_THOAI,
    ' ' CH_NGUOI_DAI_DIEN,
    ' ' LX_TEN_LAI_XE,
    ' ' LX_SO_GIAY_PHEP_LAI_XE,
    ' ' LX_SO_CMT,
    ' ' LX_NAM_SINH,
    ' ' LX_GIOI_TINH,
    ' ' LX_LOAI_BANG,
    ' ' LX_NGAY_HIEU_LUC,
    ' ' LX_NGAY_HET_HIEU_LUC,
--    mic_hh_lay_maloaixe(a.c10) XE_LOAI_XE, --X
    '  ' XE_LOAI_XE,
    ' ' XE_HANG_XE,
    ' ' XE_HIEU_XE,
    ' ' XE_DONG_XE,
    ' ' XE_MAU_SON,
    a.c11 XE_BIEN_SO, --*
    a.c12 XE_SO_KHUNG,
    a.c13 XE_SO_MAY, 
    a.c14 XE_NAM_SX,
    ' ' XE_DUNG_TICH,
    ' ' XE_TRONG_TAI, --* mic_hh_lay_trongtai(a.ttai)
    ' ' XE_SO_CHO_NGOI,
    ' ' XE_MUC_DICH_SD, --X case b.md_sd when 'K' then 'MD02' when 'C' then 'MD01' end
--    case when mic_hh_lay_tinhtp('', a.c1) is null then 'TP01' else mic_hh_lay_tinhtp('', a.c1) end XE_TINH_THANH_PHO,
    '  ' XE_TINH_THANH_PHO,
    a.c3 GCN_SO_GCN, --X
    ' ' GCN_LOAI_SAN_PHAM_BH,
    ' ' GCN_CONG_TY_BH,
--    case when mic_hh_lay_madvi(a.c1) is null then '1414' else mic_hh_lay_madvi(a.c1) end GCN_CHI_NHANH,  --X
    '  ' GCN_CHI_NHANH,
    ' ' GCN_PHONG_GD,
--    case when mic_hh_lay_tinhtp('', a.c1) is null then 'TP01' else mic_hh_lay_tinhtp('', a.c1) end GCN_TINH_THANH_PHO, --X
    '  ' GCN_TINH_THANH_PHO,
    ' ' GCN_SO_HOP_DONG,
    to_char(a.d1, 'ddMMyyyy') GCN_NGAY_HIEU_LUC,  --X
    to_char(a.d2, 'ddMMyyyy') GCN_NGAY_HET_HIEU_LUC,  --X
    a.n4 GCN_PHI_BAO_HIEM, --X
    to_char(to_date(a.n5,'yyyyMMdd'), 'ddMMyyyy') GCN_NGAY_NOP_PHI, --X
    ' ' GCN_NGUOI_THU_HUONG,
    ' ' GCN_DIA_CHI_NGUOI_THU_HUONG,
    ' ' GCN_DOI_TUONG_CAP,
    ' ' GCN_NGUOI_BAN_BH,
    ' ' GCN_NGAY_BAN_BH,
    ' ' HOAN_PHI,
    ' ' GCN_MUC_TNDS_VE_NGUOI,
    ' ' GCN_MUC_TNDS_VE_TS,
    ' ' GCN_MUC_TNDS_HANG_HOA,
    ' ' GCN_MUC_TN_NGUOI_TREN_XE,
    ' ' GCN_MUC_TN_VAT_CHAT_XE,
    a.n1,a.n2
    FROM temp_1 a,bh_hd_goc b 
    where 
    a.n1=b.so_id
    and a.n5 between b_ngay_d and b_ngay_c 
    and a.c4 in (select MA from bh_ma_lhnv where nv like '%XE%' and BB='B')
    and a.n4 is not null 
    and a.n4 <> 0 
    and b.ttrang='D';
    merge into TEMP_HH_KO b using (select so_id,so_id_dt,max(ttai)ttai,max(md_sd)md_sd from bh_xe_ds group by so_id,so_id_dt) a on (a.so_id=b.so_id and a.so_id_dt=b.so_id_dt) 
    when matched then update set b.XE_TRONG_TAI=nvl(a.ttai,'300'),
    b.XE_MUC_DICH_SD = case a.md_sd when 'K' then 'MD02' when 'C' then 'MD01' end;
    open cs1 for select CH_TEN_CHU_XE, CH_LA_TO_CHUC, CH_SO_ID, 
    CH_TINH_THANH_PHO, CH_DIA_CHI, CH_DIEN_THOAI, 
    CH_NGUOI_DAI_DIEN, LX_TEN_LAI_XE, LX_SO_GIAY_PHEP_LAI_XE, 
    LX_SO_CMT, LX_NAM_SINH, LX_GIOI_TINH, 
    LX_LOAI_BANG, LX_NGAY_HIEU_LUC, LX_NGAY_HET_HIEU_LUC, 
    XE_LOAI_XE, XE_HANG_XE, XE_HIEU_XE, 
    XE_DONG_XE, XE_MAU_SON, XE_BIEN_SO, 
    XE_SO_KHUNG, XE_SO_MAY, XE_NAM_SX, 
    XE_DUNG_TICH, XE_TRONG_TAI, XE_SO_CHO_NGOI, 
    XE_MUC_DICH_SD, XE_TINH_THANH_PHO, GCN_SO_GCN, 
    GCN_LOAI_SAN_PHAM_BH, GCN_CONG_TY_BH, GCN_CHI_NHANH, 
    GCN_PHONG_GD, GCN_TINH_THANH_PHO, GCN_SO_HOP_DONG, 
    GCN_NGAY_HIEU_LUC, GCN_NGAY_HET_HIEU_LUC, round(GCN_PHI_BAO_HIEM) GCN_PHI_BAO_HIEM, 
    GCN_NGAY_NOP_PHI, GCN_NGUOI_THU_HUONG, GCN_DIA_CHI_NGUOI_THU_HUONG, 
    GCN_DOI_TUONG_CAP, GCN_NGUOI_BAN_BH, GCN_NGAY_BAN_BH, 
    HOAN_PHI, GCN_MUC_TNDS_VE_NGUOI, GCN_MUC_TNDS_VE_TS, 
    GCN_MUC_TNDS_HANG_HOA, GCN_MUC_TN_NGUOI_TREN_XE, GCN_MUC_TN_VAT_CHAT_XE
    from TEMP_HH_KO;
end if;



-- if loai='KX' then
-- insert into temp_1 (c2,c1,c3,n4,n5,n6,n1,n2,c4)
-- select c.ma_kh, c.ma_dvi, a.gcn, b.phi, c.ngay_ht, c.ngay_ht, c.so_id, a.so_id_dt, b.lh_nv from bh_2b_ds a,bh_2b_dk b,bh_2b c 
-- where c.ttrang='D' and c.ma_dvi=b.ma_dvi and c.so_id=b.so_id and b.MA_DVI=a.MA_DVI and a.so_id=b.so_id and a.so_id_dt=b.SO_ID_DT 
-- and lh_nv in (select MA from bh_ma_lhnv where nv like '%2B%' and BB='B') ;
-- 
-- merge into temp_1 a 
-- using (select ma_dvi, so_id,so_id_dt, max(ngay_hl) ngay_hl, max(ngay_kt) ngay_kt, '' loai_xe, max(bien_xe) bien_xe, max(so_khung)so_khung, max(so_may)so_may, max(nam_sx)nam_sx, max(gio_hl)gio_hl,max(gio_kt)gio_kt 
--        from bh_2b_ds group by ma_dvi, so_id, so_id_dt) b 
-- on (a.c1 = b.ma_dvi and a.n1 = b.so_id and a.n2=b.so_id_Dt) 
-- when matched then update 
-- set a.d1 = PKH_SO_CDT(b.ngay_hl), a.d2 = PKH_SO_CDT(b.ngay_kt), a.c10 = b.loai_xe, a.c11 = b.bien_xe, a.c12= b.so_khung, a.c13 = b.so_may, a.c14 = b.nam_sx, a.c15 = b.gio_hl, a.c16 = b.gio_kt;

--     delete TEMP_HH_KX;
--     insert into TEMP_HH_KX
--     select distinct b.ten CH_TEN_CHU_XE , --X
--     'LC01' CH_LA_TO_CHUC,  --X
--     '' CH_SO_ID,       --X  -----------
--     'TP01' CH_TINH_THANH_PHO,  --X   -----------
--     '' CH_DIA_CHI,
