DROP PROCEDURE PBH_THANG2D_BC_QT_DVI_NV;

CREATE OR REPLACE PROCEDURE PBH_THANG2D_BC_QT_DVI_NV
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2, b_dvi varchar2, b_phong varchar2,b_nguon varchar2, b_loai_kh varchar2,
    b_lhnv varchar2, b_ngayd number,b_ngayc number,cs1 out pht_type.cs_type)
AS
    b_ngaydn number; b_d1 date; b_d2 date; b_ngayc_d date;b_loi varchar2(100);
    b_ngayd_nt number;b_ngayc_nt number;b_ngaydn_nt number;
begin
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
delete temp_1;delete ket_qua;commit;

b_ngaydn:=round(b_ngayd,-4)+101;
b_ngayd_nt:=round(b_ngayd)-10000;
b_ngayc_nt:=round(b_ngayc)-10000;
b_ngaydn_nt:=round(b_ngayd_nt,-4)+101;
--THANG2d_PBC_LAY_NV(b_ma_dvi,b_nsd,'','');
--return;
BBC_LAY_NV(b_ma_dvi,b_nsd,'','');

------------------------------So cac don vi--------------------------------
    PBC_TS_BC_QTRI(b_dvi,b_ngayd,b_ngayc,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,nv,lh_nv,dt_ps,dt_bh,dt_tt)
    select c20,c2,c10,c8,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c20,c2,c10,c8;
    -- So trong ky
    insert into temp_1(c8,c9,c30,c10, n1, n3, n5)
        select ma_dvi, '', nv,substr(lh_nv,1,4), sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
        from BH_THANG2D_BC_DT_LUU where (b_dvi is null or ma_dvi like b_dvi||'%')  -- ngay between b_ngayd and b_ngayc and substr(lh_nv,1,4) in ('XG.1','XG.2') and ma_dvi<>'000'
--        and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_loai_kh is null or loai_kh like b_loai_kh||'%')
--        and (b_lhnv is null and lh_nv like b_lhnv||'%') 
--        and (b_phong is null or phong=b_phong)
--        and (trim(b_nguon) is null or nguon like b_nguon||'%')
--        and nv in (Select nv from temp_bc_nv) 
        group by ma_dvi, phong,nv, substr(lh_nv,1,4);

   insert into temp_1(c8,c9,c30,c10, n1, n3, n5)
        select ma_dvi, '',nv, substr(lh_nv,1,2), sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
