--        and (trim(b_nguon) is null or nguon like b_nguon||'%')
--        and nv in (Select nv from temp_bc_nv)
--        and FBH_HD_LKH(ma_dvi,so_id)=b_lkh
        group by ma_dvi, phong,nv, substr(lh_nv,1,4);

   insert into temp_1(c8,c9,c30,c10, n8, n10, n12)
        select ma_dvi, '',nv, substr(lh_nv,1,2), sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
        from BH_THANG2D_BC_DT_LUU where (b_dvi is null or ma_dvi like b_dvi||'%')
--        ngay between b_ngaydn_nt and b_ngayc_nt and substr(lh_nv,1,2) <>'XG' and ma_dvi<>'000'
--        and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_loai_kh is null or loai_kh like b_loai_kh||'%')
--        and (b_lhnv is null or lh_nv like b_lhnv||'%')  and (b_phong is null or phong=b_phong)
--        and (trim(b_nguon) is null or nguon like b_nguon||'%')
--        and nv in (Select nv from temp_bc_nv)
--        and FBH_HD_LKH(ma_dvi,so_id)=b_lkh
        group by ma_dvi, phong,nv, substr(lh_nv,1,2);

delete ket_qua;

insert into ket_qua (c8, c9, c10, n30, n1, n2, n3, n4, n5, n6, n7, n8, n9, n10, n11, n12)
    select c8,c9, c10, sum(nvl(n30,0)), sum(nvl(n1,0)), sum(nvl(n2,0)),
        sum(nvl(n3,0)), sum(nvl(n4,0)), sum(nvl(n5,0)), sum(nvl(n6,0)), sum(nvl(n7,0)),
        sum(nvl(n8,0)), sum(nvl(n9,0)), sum(nvl(n10,0)), sum(nvl(n11,0)), sum(nvl(n12,0)) from temp_1
        group by c8, c9, c10;

delete ket_qua where nvl(n30,0)=0 and nvl(n1,0)=0 and nvl(n2,0)=0 and nvl(n3,0)=0
        and nvl(n4,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0;
    --ten lhnv
    update ket_qua set c11=(Select ten from bh_ma_lhnv where ma_dvi='000' and ma=c10);
    --ten_nhom 000 + ten cac phong ban
    update ket_qua set (c12, c13)=(Select ten,'1. '||(Select ten from ht_ma_dvi where ma=c8) from ht_ma_phong where ma_dvi='000' and ma=c9)
        where c8='000';
    update ket_qua set (c12, c13)=(Select ten_gon,'2. Cac cong ty thanh vien' from ht_ma_dvi where ma=c8) where c8<>'000';

commit;
open cs1 for
select  c11 ten_nv, c12 ten_donvi, c13 ten_dvi_goc,
round(n30) dt_kh, round(n1) ps_tk, round(n2) ps_lk, round(n3) bh_tk, round(n4) bh_lk,
round(n5) tt_tk, round(n6) tt_lk, round(n7) ps_ck_nt, round(n8) ps_lk_nt, round(n9) bh_tk_nt, round(n10) bh_lk_nt,
round(n11) tt_ck_nt, round(n12) tt_lk_nt,
case round(n9) when 0 then 0 else round(n3/n9,4)*100 end pt_tk_nt,
case round(n10) when 0 then 0 else round(n4/n10,4)*100 end pt_lk_nt,
case round(n30) when 0 then 0 else round(n4/n30,4)*100 end pt_kh
from ket_qua order by c13, c8, c11;--where substr(c10,1,2)='XG'

exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE PBH_THANG2D_BC_QT_NV;
CREATE OR REPLACE PROCEDURE PBH_THANG2D_BC_QT_NV
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2, b_dvi varchar2, b_phong varchar2,b_nguon varchar2, b_loai_kh varchar2, b_lhnv varchar2,
    b_ngayd number,b_ngayc number,cs1 out pht_type.cs_type)
AS
    b_ngaydn number; b_d1 date; b_d2 date; b_ngayc_d date;b_loi varchar2(100);
    b_ngayd_nt number;b_ngayc_nt number;b_ngaydn_nt number;b_lkh varchar2(10);
begin
--BCNam: Sua lai lay so lieu theo dung don vi quan ly
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;

b_lkh:='';
if b_loai_kh is not null then
    b_lkh:=b_loai_kh;
end if;

delete temp_1;delete ket_qua;commit;
b_ngaydn:=round(b_ngayd,-4)+101;

b_ngayd_nt:=round(b_ngayd)-10000;
b_ngayc_nt:=round(b_ngayc)-10000;
b_ngaydn_nt:=round(b_ngayd_nt,-4)+101;
--THANG2d_PBC_LAY_NV(b_ma_dvi,b_nsd,'','');
BBC_LAY_NV(b_ma_dvi,b_nsd,'','');
--return;
PBC_TS_BC_QTRI(b_dvi,b_ngayd,b_ngayc,'','','','','');
insert into BH_THANG2D_BC_DT_LUU(nv,ma_dvi,phong,lh_nv,dt_ps,dt_bh,dt_tt)
select c10,c20,c2,c8,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c10,c20,c2,c8;
insert into temp_1(c10,c30, n1, n3, n5)
    select lh_nv, nv, sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
    from BH_THANG2D_BC_DT_LUU where nv in (Select nv from temp_bc_nv)
--    ngay between b_ngayd and b_ngayc
--    and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lkh is null or loai_kh like b_lkh||'%')
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_phong is null or phong=b_phong)
--    and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    and nv in (Select nv from temp_bc_nv)
    group by lh_nv, nv;
--doanh thu luy ke
insert into temp_1(c10, c30, n2, n4, n6)
    select lh_nv,nv, sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
    from BH_THANG2D_BC_DT_LUU where nv in (Select nv from temp_bc_nv)
--    ngay between b_ngaydn and b_ngayc
--    and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lkh is null or loai_kh like b_lkh||'%')
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_phong is null or phong=b_phong)
--    and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    and nv in (Select nv from temp_bc_nv)
    group by lh_nv,nv;


/*update temp_1 set (n2, n4, n6)=
    (select sum(dt_ps), sum(dt_bh), sum(dt_tt)
    from BH_THANG2D_BC_DT_LUU where ngay between b_ngaydn and b_ngayc and lh_nv=c10);
*/

PBC_TS_BC_QTRI(b_dvi,b_ngayd_nt,b_ngayc_nt,'','','','','');
insert into BH_THANG2D_BC_DT_LUU(nv,ma_dvi,phong,lh_nv,dt_ps,dt_bh,dt_tt)
select c10,c20,c2,c8,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c10,c20,c2,c8;
--doanh thu nam truoc trong ky
insert into temp_1(c10,c30, n7, n9, n11)
    select lh_nv,nv, sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
    from BH_THANG2D_BC_DT_LUU where nv in (Select nv from temp_bc_nv)
--    ngay between b_ngayd_nt and b_ngayc_nt
--    and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lkh is null or loai_kh like b_lkh||'%')
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_phong is null or phong=b_phong)
--    and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    and nv in (Select nv from temp_bc_nv)
    group by lh_nv, nv;

--doanh thu nam truoc luy ke
insert into temp_1(c10,c30, n8, n10, n12)
    select lh_nv, nv, sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
    from BH_THANG2D_BC_DT_LUU where nv in (Select nv from temp_bc_nv)
--    ngay between b_ngaydn_nt and b_ngayc_nt
--    and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lkh is null or loai_kh like b_lkh||'%')
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_phong is null or phong=b_phong)
--    and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    and nv in (Select nv from temp_bc_nv)
    group by lh_nv,nv;

--chen ke hoach doanh thu khong co ma o trong bang ket qua
insert into temp_1(c10, n30)
    (select ma, sum(kh) from bh_ma_lhnv_kh where substr(ngay,1,4)=substr(b_ngaydn,1,4)
    and kieu in ('C','P') and ma_dvi in ('00','000') and dvi<>'TBH'
    group by ma);

insert into ket_qua(c10, n1, n2, n3, n4, n5, n6, n7, n8,n9,n10, n11, n12, n30)
    select c10, sum(nvl(n1,0)), sum(nvl(n2,0)), sum(nvl(n3,0)), sum(nvl(n4,0)), sum(nvl(n5,0)), sum(nvl(n6,0)),
    sum(nvl(n7,0)), sum(nvl(n8,0)), sum(nvl(n9,0)), sum(nvl(n10,0)), sum(nvl(n11,0)), sum(nvl(n12,0)), sum(nvl(n30,0))
    from temp_1 group by c10;

/*--chen ke hoach doanh thu khong co ma o trong bang ket qua
insert into ket_qua(c10, n30)
    (select ma, sum(kh) from bh_ma_lhnv_kh where substr(ngay,1,4)=substr(b_ngaydn,1,4)
    and ma not in (Select c10 from temp_1) and kieu in ('C','P') and ma_dvi in ('00','000') and dvi<>'TBH'
    group by ma);*/

/*--ke hoach doanh thu
update ket_qua set n30=(Select sum(kh) from bh_ma_lhnv_kh where substr(ngay,1,4)=substr(b_ngaydn,1,4)
    and ma = c10 and kieu in ('C','P') and ma_dvi in ('00','000') and dvi<>'TBH');
*/

delete ket_qua where nvl(n1,0)=0 and nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n4,0)=0
                and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n30,0)=0 and nvl(n7,0)=0 and nvl(n8,0)=0;


update ket_qua set (c14, c15)=
    (Select substr(c10,1,4),ten from bh_ma_lhnv where ma=substr(c10,1,4) and ma_dvi='000')
    where substr(c10,1,2) in ('XG','TT','TN');


--Nhom con nguoi
update ket_qua set (c14, c15)=
    (Select 'CN.3',ten from bh_ma_lhnv where ma='CN.3' and ma_dvi='000')
    where substr(c10,1,4) in ('CN.3');


update ket_qua set (c14, c15)=
    (Select 'CN.4',ten from bh_ma_lhnv where ma='CN.4' and ma_dvi='000')
    where substr(c10,1,4) in ('CN.4');

update ket_qua set (c14, c15)=
    (Select 'CN.5',ten from bh_ma_lhnv where ma='CN.5' and ma_dvi='000')
    where substr(c10,1,4) in ('CN.5');

update ket_qua set c14='CN.K', c15=U'Nhom khac' where substr(c10,1,4) not in ('CN.5','CN.4','CN.3') and substr(c10,1,2)='CN';

/*update ket_qua set n29=(Select sum(kh) from bh_ma_lhnv_kh where ma like 'CN.%' and substr(ngay,1,4)=substr(b_ngaydn,1,4)
    and (substr(ma,1,5) not in ('CN.5','CN.4','CN.3'))
    and kieu in ('C') and ma_dvi in ('00','000') and dvi<>'TBH') where c14='CN.K';
*/

--Nhom ky thuat
update ket_qua set (c14, c15)=
    (Select 'KT.1',ten from bh_ma_lhnv where ma='KT.1' and ma_dvi='000')
    where substr(c10,1,4) in ('KT.1');

update ket_qua set (c14, c15)=
    (Select 'KT.2',ten from bh_ma_lhnv where ma='KT.2' and ma_dvi='000')
    where substr(c10,1,4) in ('KT.2');

update ket_qua set c14='KT.K', c15='Nhom khac' where substr(c10,1,4) not in ('KT.1','KT.2') and substr(c10,1,2)='KT';

/*update ket_qua set n29=(Select sum(kh) from bh_ma_lhnv_kh where ma like 'KT.%' and substr(ngay,1,4)=substr(b_ngaydn,1,4)
    and (ma not like 'KT.1%' and ma not like 'KT.2%')
    and kieu in ('C','P') and ma_dvi in ('00','000') and dvi<>'TBH') where c14='KT.K';*/

update ket_qua set (c14, c15)=
    (Select 'TS.1.1',ten from bh_ma_lhnv where ma='TS.1.1' and ma_dvi='000')
    where substr(c10,1,6) in ('TS.1.1');
update ket_qua set (c14, c15)=
    (Select 'TS.1.2',ten from bh_ma_lhnv where ma='TS.1.2' and ma_dvi='000')
    where substr(c10,1,6) in ('TS.1.2');

update ket_qua set (c14, c15)=
    (Select 'TS.2',ten from bh_ma_lhnv where ma='TS.2' and ma_dvi='000')
    where substr(c10,1,4) in ('TS.2');

update ket_qua set (c14, c15)=
    (Select 'TS.3',ten from bh_ma_lhnv where ma='TS.3' and ma_dvi='000')
    where substr(c10,1,4) in ('TS.3');

update ket_qua set (c14, c15)=
    (Select 'HP.1',ten from bh_ma_lhnv where ma='HP.1' and ma_dvi='000')
    where substr(c10,1,4) in ('HP.1');
update ket_qua set c14='HP.K', c15='Nhom khac' where substr(c10,1,4) not in ('HP.1') and substr(c10,1,2)='HP';

update ket_qua set (c14, c15)=
    (Select 'HH',ten from bh_ma_lhnv where ma='HH' and ma_dvi='000')
    where substr(c10,1,2) in ('HH');

update ket_qua set (c14, c15)=
    (Select 'HK',ten from bh_ma_lhnv where ma='HK' and ma_dvi='000')
    where substr(c10,1,2) in ('HK');


update ket_qua set (c12,c13)=(Select substr(c10,1,2),ten from bh_ma_lhnv where ma=substr(c10,1,2) and ma_dvi='000');
update ket_qua set c13='1. '||c13 where c12='CN';
update ket_qua set c13='2. '||c13 where c12='XG';
update ket_qua set c13='3. '||c13 where c12='HH';
update ket_qua set c13='4. '||c13 where c12='TT';
update ket_qua set c13='5. '||c13 where c12='TS';
update ket_qua set c13='6. '||c13 where c12='KT';
update ket_qua set c13='7. '||c13 where c12='HP';
update ket_qua set c13='8. '||c13 where c12='TN';
update ket_qua set c13='9. '||c13 where c12='HK';

update ket_qua set c11=(select ten from bh_ma_lhnv where ma=c10 and ma_dvi='000');

delete temp_1; commit;
insert into temp_1(c10, c11, c12, c13, c14, c15, n30, n1, n2, n3, n4, n5, n6, n7, n8, n9, n10, n11, n12, n13, n14, n20, n29, n28, n27)
            select c10, c11, c12, c13, c14, c15, sum(n30), sum(n1), sum(n2), sum(n3), sum(n4), sum(n5), sum(n6), sum(n7), sum(n8), sum(n9), sum(n10), sum(n11)
            , sum(n12), n13, n14, n20, sum(n29), sum(n28), sum(n27)
            from ket_qua group by c10, c11, c12, c13, c14, c15, n13, n14, n20 order by c13;

open cs1 for
select c10 ma, c11 ten, c12 ma_goc_1, c13 ten_goc_1,c14 ma_goc_2,c15 ten_goc_2,
    round(n30) DT_KH, round(n1) ps_tk, round(n2) ps_lk, round(n3) bh_tk, round(n4) bh_lk,
    round(n5) tt_tk, round(n6) tt_lk, round(n7) ps_ck_nt, round(n8) ps_lk_nt, round(n9) bh_ck_nt, round(n10) bh_lk_nt,
    round(n11) tt_ck_nt, round(n12) tt_lk_nt,
    case round(n9) when 0 then 0 else round(n3/n9,4)*100 end ty_le_tk_nt,
    case round(n10) when 0 then 0 else round(n4/n10,4)*100 end ty_le_lk_nt,
    case round(n30) when 0 then 0 else round(n4/n30,4)*100 end ty_le_kh, n20 sap_xep,
    nvl(n29,0) ke_hoach, n28 tong_kh, n27 ke_hoach_gr1
    from temp_1 ;
--select c10 ma, c11 ten, c12 ma_goc_1, c13 ten_goc_1,c14 ma_goc_2,c15 ten_goc_2,
--    round(n30) DT_KH, round(n1) ps_tk, round(n2) ps_lk, round(n3) bh_tk, round(n4) bh_lk,
--    round(n5) tt_tk, round(n6) tt_lk, round(n7) ps_ck_nt, round(n8) ps_lk_nt, round(n9) bh_ck_nt, round(n10) bh_lk_nt,
--    round(n11) tt_ck_nt, round(n12) tt_lk_nt,
--    case round(n9) when 0 then 0 else round(n3/n9,4)*100 end ty_le_tk_nt,
--    case round(n10) when 0 then 0 else round(n4/n10,4)*100 end ty_le_lk_nt,
--    case round(n30) when 0 then 0 else round(n4/n30,4)*100 end ty_le_kh, n20 sap_xep,
--    nvl(n29,0) ke_hoach, n28 tong_kh, n27 ke_hoach_gr1
--    from temp_1 where c10 not in 'CN.3.6._' or c10 not like 'CN.3.6.__';


--exception when others then raise_application_error(-20105,b_loi);
end;
/
DROP PROCEDURE PBH_THANG2D_BC_QT_NV_LKH;

CREATE OR REPLACE PROCEDURE PBH_THANG2D_BC_QT_NV_LKH
    (b_ma_dvi varchar2,b_nsd varchar2,b_pas varchar2, b_dvi varchar2, b_phong varchar2,b_nguon varchar2, b_loai_kh varchar2,b_lkh varchar2, b_lhnv varchar2,
    b_ngayd number,b_ngayc number,cs1 out pht_type.cs_type)
AS
    b_ngaydn number; b_d1 date; b_d2 date; b_ngayc_d date;b_loi varchar2(100);
    b_ngayd_nt number;b_ngayc_nt number;b_ngaydn_nt number;b_lkh2 varchar2(10);
begin
--BCNam: Sua lai lay so lieu theo dung don vi quan ly
b_loi:=FHT_MA_NSD_KTRA(b_ma_dvi,b_nsd,b_pas,'BH','','');
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_lkh2:='';
if b_loai_kh is not null then
    b_lkh2:=b_loai_kh;
end if;
delete temp_1;delete ket_qua;delete ket_qua;delete temp_bc_ts;commit;
b_ngaydn:=round(b_ngayd,-4)+101;
b_ngayd_nt:=round(b_ngayd)-10000;
b_ngayc_nt:=round(b_ngayc)-10000;
b_ngaydn_nt:=round(b_ngayd_nt,-4)+101;
--THANG2d_PBC_LAY_NV(b_ma_dvi,b_nsd,'','');
BBC_LAY_NV(b_ma_dvi,b_nsd,'','');
PBC_TS_BC_QTRI(b_dvi,b_ngayd,b_ngayc,'','','','','');
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(nv,lh_nv,dt_ps,dt_bh,dt_tt)
    select c8,c10,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c10,c8;
--return;
insert into temp_1(c10,c30, n1, n3, n5)
    select lh_nv, nv, sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
    from BH_THANG2D_BC_DT_LUU --where ngay between b_ngayd and b_ngayc
--    and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lkh2 is null or loai_kh like b_lkh2||'%')
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_phong is null or phong=b_phong)
--    and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    and nv in (Select nv from temp_bc_nv)
--    and FBH_HD_LKH(ma_dvi,so_id)=b_lkh
    group by lh_nv, nv;
--return;
PBC_TS_BC_QTRI(b_dvi,b_ngaydn,b_ngayc,'','','','','');
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(nv,lh_nv,dt_ps,dt_bh,dt_tt)
    select c8,c10,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c10,c8;
--doanh thu luy ke
insert into temp_1(c10, c30, n2, n4, n6)
    select lh_nv,nv, sum(nvl(dt_ps,0)), sum(nvl(dt_bh,0)), sum(nvl(dt_tt,0))
    from BH_THANG2D_BC_DT_LUU --where ngay between b_ngaydn and b_ngayc
--    and (b_dvi is null or ma_dvi like b_dvi||'%') and (b_lkh2 is null or loai_kh like b_lkh2||'%')
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_phong is null or phong=b_phong)
