DROP PROCEDURE PBH_THANG2D_BT_QT_DVI;
CREATE OR REPLACE PROCEDURE PBH_THANG2D_BT_QT_DVI
    (B_MADVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2, B_DVI VARCHAR2, B_PHONG VARCHAR2,B_NGUON VARCHAR2, B_LOAI_KH VARCHAR2, B_LHNV VARCHAR2,
    B_NGAYD NUMBER,B_NGAYC NUMBER,CS_KQ OUT PHT_TYPE.CS_TYPE)
AS
    B_LOI VARCHAR2(100);B_NGAYDN NUMBER; B_N1 NUMBER; B_N2 NUMBER; B_NGAYNT NUMBER;B_I1 NUMBER;
    B_NGAY_C NUMBER; B_D1 NUMBER; B_D2 NUMBER;B_NGAYD_NT NUMBER;B_NGAYC_NT NUMBER;
    B_NGAYD_LK_NT NUMBER;B_NGAYC_LK_NT NUMBER;B_MA_VP VARCHAR2(10);   
    b_ten_proc varchar2(40); 
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MADVI,B_NSD,B_PAS,'BH','','');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;

-- Hung kiem tra trong gio hanh chinh
--if trim(to_char(sysdate,'DAY')) not in ('SATURDAY','SUNDAY') then
--    if extract(hour from cast(sysdate as timestamp))>7 and extract(hour from cast(sysdate as timestamp))<18 then
--        if trim(b_dvi) is null and b_nsd not in ('ADMIN','BC','TIN','LNH01') then
--            b_loi:='loi:Chay dia ban. De nghi chay ngoai gio:loi';
--            raise_application_error(-20105,b_loi);
--        end if;
--        if (PKH_SO_CDT(b_ngayc)-PKH_SO_CDT(b_ngayd)>366) and (b_nsd<>'ADMIN' or b_nsd<>'BC') then
--            b_loi:='loi:Khoang ngay > 365 ngay. De nghi chay ngoai gio:loi';
--            raise_application_error(-20105,b_loi);
--        end if;
--    end if;
--end if;

--PBC_LAY_NV(B_MADVI,B_MADVI,B_NSD,B_PAS,B_PHONG);
BBC_LAY_NV(b_madvi,b_nsd,'','');
SELECT COUNT(*) INTO B_I1 FROM TEMP_BC_NV WHERE NV='BT';
IF B_I1=0 THEN
    B_LOI:='loi:Ban khong co quyen xem bao cao nay:loi'; RAISE PROGRAM_ERROR;
END IF;

IF B_NGAYD IS NULL OR B_NGAYC IS NULL THEN
    B_LOI:='loi:Nhap ngay bao cao:loi'; RAISE PROGRAM_ERROR;
END IF;
B_NGAYDN:=ROUND(B_NGAYD,-4)+101;


DELETE BC_BH_BT_TEMP;DELETE KET_QUA; COMMIT;
DELETE TEMP_BC_TS;
INSERT INTO TEMP_BC_TS VALUES(B_DVI||'%',B_NGAYD, B_NGAYC);

--THANG2D_PBC_LAY_NV(B_MADVI,B_NSD,'','');
BBC_LAY_NV(b_madvi,b_nsd,'','');

PBC_THANG2D_TH_BT_PB_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,C30,N1,NGAY_HT,SO_ID_HD,MA_DVI_HD, LH_NV)
                SELECT T.MA_DVI,T.PHONG,T.NV, SUM(T.TIEN_QD),T.NGAY_HT,T.SO_ID_HD,T.MA_DVI_HD, T.LH_NV FROM BC_BH_BT_HS_TEMP T, BH_HD_GOC GOC
                WHERE T.NGAY_QD_N<30000101 AND T.NGAY_HT BETWEEN B_NGAYD AND B_NGAYC
                AND T.NV IN (SELECT NV FROM TEMP_BC_NV)
                AND (B_PHONG IS NULL OR T.PHONG=B_PHONG) AND (B_LHNV IS NULL OR T.LH_NV LIKE B_LHNV||'%')
                AND GOC.MA_DVI=T.MA_DVI_HD AND GOC.SO_ID=T.SO_ID_HD
                AND (TRIM(B_NGUON) IS NULL OR GOC.MA_GT LIKE B_NGUON||'%')

                GROUP BY T.MA_DVI,T.PHONG,T.NV,T.NGAY_HT,T.SO_ID_HD,T.MA_DVI_HD,T.LH_NV;

DELETE TEMP_BC_TS;

INSERT INTO TEMP_BC_TS VALUES(B_DVI||'%',B_NGAYD, B_NGAYC);
PBC_THANG2D_BT_CGQ_MD('T');
INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,C30,N2,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                SELECT T.MA_DVI,T.C3,T.C2,SUM(T.N5),T.N2,T.N3,T.C4, T.LH_NV FROM TEMP_BT_1 T, BH_HD_GOC GOC
                WHERE (B_PHONG IS NULL OR T.C3=B_PHONG) AND (B_LHNV IS NULL OR T.LH_NV LIKE B_LHNV||'%')
                
                AND EXISTS(SELECT NV FROM TEMP_BC_NV WHERE NV=T.C2 AND ROWNUM=1)
                AND GOC.MA_DVI=T.C4 AND GOC.SO_ID=T.N3
                AND (TRIM(B_NGUON) IS NULL OR GOC.MA_GT LIKE B_NGUON||'%')
                GROUP BY T.MA_DVI,T.C3,T.C2,T.N2,T.N3,T.C4,T.LH_NV;

IF B_NGAYDN=B_NGAYD THEN
    UPDATE BC_BH_BT_TEMP SET N4=N1, N5=N2;
ELSE
    DELETE TEMP_BC_TS;
    INSERT INTO TEMP_BC_TS VALUES(B_DVI||'%',B_NGAYDN, B_NGAYC);
    
    PBC_THANG2D_TH_BT_PB_MD('T');
    INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,C30,N4,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                    SELECT T.MA_DVI,T.PHONG,T.NV,SUM(T.TIEN_QD),T.NGAY_HT,T.SO_ID_HD,T.MA_DVI_HD,T.LH_NV FROM BC_BH_BT_HS_TEMP T, BH_HD_GOC GOC
                    WHERE T.NGAY_QD_N<30000101 AND T.NGAY_HT BETWEEN B_NGAYDN AND B_NGAYC
                    AND (B_PHONG IS NULL OR T.PHONG=B_PHONG) AND (B_LHNV IS NULL OR T.LH_NV LIKE B_LHNV||'%')
                    AND T.NV IN (SELECT NV FROM TEMP_BC_NV)
                    AND GOC.MA_DVI=T.MA_DVI_HD AND GOC.SO_ID=T.SO_ID_HD
                    AND (TRIM(B_NGUON) IS NULL OR GOC.MA_GT LIKE B_NGUON||'%')
                    GROUP BY T.MA_DVI,T.PHONG,T.NV,T.NGAY_HT,T.SO_ID_HD,T.MA_DVI_HD,T.LH_NV;
    DELETE TEMP_BC_TS;
    INSERT INTO TEMP_BC_TS VALUES(B_DVI||'%',B_NGAYDN, B_NGAYC);
    PBC_THANG2D_BT_CGQ_MD('T');
    INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,C30,N5,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                    SELECT T.MA_DVI,T.C3,T.C2,SUM(T.N5),T.N2,T.N3,T.C4,T.LH_NV FROM TEMP_BT_1 T, BH_HD_GOC GOC
                    WHERE (B_PHONG IS NULL OR C3=B_PHONG) AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%')
                    
                    AND EXISTS(SELECT NV FROM TEMP_BC_NV WHERE NV=T.C2 AND ROWNUM=1)
                    AND GOC.MA_DVI=T.C4 AND GOC.SO_ID=T.N3
                    AND (TRIM(B_NGUON) IS NULL OR GOC.MA_GT LIKE B_NGUON||'%')
                    GROUP BY T.MA_DVI,T.C2,T.C3,T.N2,T.N3,T.C4,T.LH_NV;

END IF;


DELETE TEMP_BC_TS;
 INSERT INTO TEMP_BC_TS VALUES(B_DVI||'%',B_NGAYDN, B_NGAYC);
 
 PBC_THANG2D_TH_BT_PB_MD('T');
 INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,C30, N7,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                 SELECT T.MA_DVI,T.PHONG,T.NV, SUM(T.TIEN_QD),T.NGAY_HT,T.SO_ID_HD,T.MA_DVI_HD,T.LH_NV FROM BC_BH_BT_HS_TEMP T, BH_HD_GOC GOC
                 WHERE T.NGAY_QD_N<30000101 AND T.NGAY_HT BETWEEN 20000101 AND B_NGAYC
                 AND (B_PHONG IS NULL OR T.PHONG=B_PHONG) AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%')
                 AND T.NV IN (SELECT NV FROM TEMP_BC_NV)
                 AND GOC.SO_ID=T.SO_ID_HD AND GOC.MA_DVI=T.MA_DVI_HD
                 AND (TRIM(B_NGUON) IS NULL OR GOC.MA_GT LIKE B_NGUON||'%')
                 GROUP BY T.MA_DVI,T.PHONG,T.NV,T.NGAY_HT,T.SO_ID_HD,T.MA_DVI_HD,T.LH_NV;
 DELETE TEMP_BC_TS;
 INSERT INTO TEMP_BC_TS VALUES(B_DVI||'%',20000101, B_NGAYC);
 PBC_THANG2D_BT_CGQ_MD('T');
 INSERT INTO BC_BH_BT_TEMP (MA_DVI,PHONG,C30, N8,NGAY_HT,SO_ID_HD,MA_DVI_HD,LH_NV)
                 SELECT T.MA_DVI,T.C3,T.C2, SUM(T.N5),T.N2,T.N3,T.C4,T.LH_NV FROM TEMP_BT_1 T, BH_HD_GOC GOC
                 WHERE (B_PHONG IS NULL OR T.C3=B_PHONG) AND (B_LHNV IS NULL OR T.LH_NV LIKE B_LHNV||'%')
                 
                 AND EXISTS(SELECT NV FROM TEMP_BC_NV WHERE NV=T.C2 AND ROWNUM=1)
                 AND GOC.SO_ID=T.N3 AND GOC.MA_DVI=T.C4
                 AND (TRIM(B_NGUON) IS NULL OR GOC.MA_GT LIKE B_NGUON||'%')
                 GROUP BY T.MA_DVI,T.C3,T.C2,T.N2,T.N3,T.C4,T.LH_NV;

DELETE KET_QUA;DELETE TEMP_6;



IF B_DVI IS NULL THEN
    INSERT INTO TEMP_6(C1, C2, C30, N1, N2, N4, N5, N7, N8)
        SELECT B.MA_DVI, A.PHONG, MA_KH, SUM(N1), SUM(N2), SUM(N4), SUM(N5), SUM(N7), SUM(N8)
            FROM BC_BH_BT_TEMP B, BH_HD_GOC A
            WHERE (B_DVI IS NULL OR B.MA_DVI LIKE B_DVI||'%')
            AND A.MA_DVI=B.MA_DVI AND A.SO_ID=B.SO_ID_HD
            AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%')
            AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
            AND A.PHONG<>'QPAN'
            GROUP BY B.MA_DVI, A.PHONG, MA_KH;

    PBC_TS_BC_QTRI(b_dvi,b_ngayd,b_ngayc,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,ma_kh,dt_ps,dt_bh,dt_tt)
    select c20,c2,c4,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c20,c2,c4;
     INSERT INTO TEMP_6(C1, C2, C30, N10)
        SELECT MA_DVI,PHONG,MA_KH, SUM(DT_BH)
            FROM BH_THANG2D_BC_DT_LUU WHERE (b_dvi is null or ma_dvi like b_dvi||'%')
--            MA_DVI='000' AND NGAY BETWEEN B_NGAYD AND B_NGAYC
--            AND NV IN (SELECT NV FROM TEMP_BC_NV)
--            AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') AND (B_LOAI_KH IS NULL OR LOAI_KH LIKE B_LOAI_KH||'%')
--            AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (TRIM(B_NGUON) IS NULL OR NGUON LIKE B_NGUON||'%')
--            AND PHONG<>'QPAN'
            GROUP BY MA_DVI, PHONG, MA_KH;
    
    UPDATE TEMP_6 SET C29=(SELECT LOAI FROM BH_HD_MA_KH WHERE MA_DVI=C1 AND MA=C30);
    INSERT INTO KET_QUA(C1, C2, N1, N2, N4, N5, N7, N8,N10,N11)
        SELECT C1, C2, SUM(N1), SUM(N2), SUM(N4), SUM(N5), SUM(N7), SUM(N8),SUM(N10),SUM(N11) FROM TEMP_6
        WHERE (B_LOAI_KH IS NULL OR C29 LIKE B_LOAI_KH||'%')
        GROUP BY C1, C2;
    
END IF;


DELETE TEMP_6; COMMIT;
INSERT INTO TEMP_6(C1,C2, C30,N1, N2, N4, N5, N7, N8)
    SELECT A.MA_DVI, '', B.MA_KH, SUM(N1), SUM(N2), SUM(N4), SUM(N5), SUM(N7), SUM(N8)
        FROM BC_BH_BT_TEMP A, BH_HD_GOC B
        WHERE (B_DVI IS NULL OR A.MA_DVI LIKE B_DVI||'%') AND A.MA_DVI<>'000'
        AND (B_LHNV IS NULL OR A.LH_NV LIKE B_LHNV||'%')
        AND (B_PHONG IS NULL OR A.PHONG=B_PHONG)
        AND B.SO_ID=A.SO_ID_HD AND B.MA_DVI=A.MA_DVI_HD
        GROUP BY A.MA_DVI, B.MA_KH;

    PBC_TS_BC_QTRI(b_dvi,b_ngayd,b_ngayc,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,ma_kh,dt_ps,dt_bh,dt_tt)
    select c20,c2,c4,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c20,c2,c4;

INSERT INTO TEMP_6 (C1,C2,C30,N10)
    SELECT MA_DVI,'',MA_KH, SUM(DT_BH)
    FROM BH_THANG2D_BC_DT_LUU WHERE (b_dvi is null or ma_dvi like b_dvi||'%') 
--    MA_DVI LIKE B_DVI||'%' AND NGAY BETWEEN B_NGAYD AND B_NGAYC
--    AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') AND (B_LOAI_KH IS NULL OR LOAI_KH LIKE B_LOAI_KH||'%')
--    AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND MA_DVI<>'000'
--    AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (TRIM(B_NGUON) IS NULL OR NGUON LIKE B_NGUON||'%')
--    AND NV IN (SELECT NV FROM TEMP_BC_NV)
    GROUP BY MA_DVI, MA_KH;

INSERT INTO TEMP_6 (C1,C2, C30,N11)
    SELECT MA_DVI,'',MA_KH, SUM(DT_BH)
    FROM BH_THANG2D_BC_DT_LUU WHERE (b_dvi is null or ma_dvi like b_dvi||'%') 
--    MA_DVI LIKE B_DVI||'%' AND NGAY BETWEEN B_NGAYDN AND B_NGAYC
--    AND (B_LHNV IS NULL OR LH_NV LIKE B_LHNV||'%') AND (B_LOAI_KH IS NULL OR LOAI_KH LIKE B_LOAI_KH||'%')
--    AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND MA_DVI<>'000'
--    AND (B_PHONG IS NULL OR PHONG=B_PHONG) AND (TRIM(B_NGUON) IS NULL OR NGUON LIKE B_NGUON||'%')
--    AND NV IN (SELECT NV FROM TEMP_BC_NV)
    GROUP BY MA_DVI, MA_KH;

DELETE TEMP_6 WHERE NVL(N10,0)=0 AND NVL(N11,0)=0 AND NVL(N1,0)=0 AND NVL(N2,0)=0 AND NVL(N3,0)=0 AND NVL(N4,0)=0 AND NVL(N5,0)=0 AND NVL(N6,0)=0 AND NVL(N7,0)=0 AND NVL(N8,0)=0;



UPDATE
       (SELECT TEMP_6.C29 TEMP_6_C29, BH_HD_MA_KH.LOAI BH_HD_MA_KH_LOAI
              FROM TEMP_6, BH_HD_MA_KH
             WHERE TEMP_6.C1 = BH_HD_MA_KH.MA_DVI AND TEMP_6.C30 = BH_HD_MA_KH.MA)
       SET TEMP_6_C29 = BH_HD_MA_KH_LOAI;


INSERT INTO KET_QUA(C1, N1, N2, N4, N5, N7, N8,N10,N11)
  SELECT C1, SUM(N1), SUM(N2), SUM(N4), SUM(N5), SUM(N7), SUM(N8),SUM(N10),SUM(N11) FROM TEMP_6
  WHERE (B_LOAI_KH IS NULL OR C29 LIKE B_LOAI_KH||'%')
  GROUP BY C1;

UPDATE KET_QUA SET (C11, C12)=(SELECT TEN_GON,'2. Cac cong ty thanh vien' FROM HT_MA_DVI WHERE MA=C1) WHERE C1<>'000';

COMMIT;
OPEN CS_KQ FOR
    SELECT C1, C2, C11 TEN_DVI, C12 TEN_DVI_GOC, ROUND(N10) DT_TK, ROUND(N11) DT_LK,
        ROUND(N1) DGQ_TK, ROUND(N2) CON_U_TK, ROUND(NVL(N1,0)+NVL(N2,0)) TONG_PS_TK, CASE ROUND(N10) WHEN 0 THEN 0 ELSE ROUND((NVL(N1,0)+NVL(N2,0))/N10,4)*100 END TY_LE_TK,
        ROUND(N4) DGQ_LK, ROUND(N5) CON_U_LK, ROUND(NVL(N4,0)+NVL(N5,0)) TONG_PS_LK, CASE ROUND(N11) WHEN 0 THEN 0 ELSE ROUND((NVL(N4,0)+NVL(N5,0))/N11,4)*100 END TY_LE_LK,
        ROUND(N7) DGQ_LK_BTXX, ROUND(N8) TONG_TON
    FROM KET_QUA;
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/
DROP PROCEDURE PBH_THANG2D_BT_QT_DVI_LKH;
CREATE OR REPLACE PROCEDURE PBH_THANG2D_BT_QT_DVI_LKH
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2, b_dvi varchar2, b_phong varchar2,b_nguon varchar2, b_loai_kh varchar2, b_lkh varchar2,b_lhnv varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaynt number;b_i1 number;
    b_ngay_c number; b_d1 number; b_d2 number;b_ngayd_nt number;b_ngayc_nt number;
    b_ngayd_lk_nt number;b_ngayc_lk_nt number;b_ma_vp varchar2(10);
Begin
-- Bao cao nhanh tinh hinh  boi thuong tong
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
--if b_nsd <> 'BCNam' then raise PROGRAM_ERROR; end if;
PBC_LAY_NV(b_madvi,b_madvi,b_nsd,b_pas,b_phong);
select count(*) into b_i1 from temp_bc_nv where nv='BT';
if b_i1=0 then
    b_loi:='loi:Ban khong co quyen xem bao cao nay:loi'; raise PROGRAM_ERROR;
end if;

if b_ngayd is null or b_ngayc is null then
    b_loi:='loi:Nhap ngay bao cao:loi'; raise PROGRAM_ERROR;
end if;
b_ngaydn:=round(b_ngayd,-4)+101;

--b_loi:='loi:Ma chua dang ky:loi';
delete bc_bh_bt_temp;delete ket_qua; commit;

-- So lieu trong ky
delete temp_bc_ts;

insert into temp_bc_ts values(b_dvi||'%',b_ngayd, b_ngayc);

THANG2d_PBC_LAY_NV(b_madvi,b_nsd,'','');

PBC_THANG2D_TH_BT_PB_MD('T');
insert into bc_bh_bt_temp (ma_dvi,phong,c30,n1,ngay_ht,so_id_hd,ma_dvi_hd, lh_nv)
                select t.ma_dvi,t.phong,t.nv, sum(t.tien_qd),t.ngay_ht,t.so_id_hd,t.ma_dvi_hd, t.lh_nv from bc_bh_bt_hs_temp t, bh_hd_goc goc
                where t.ngay_qd_n<30000101 and t.ngay_ht between b_ngayd and b_ngayc
                and t.nv in (Select nv from temp_bc_nv)
                and (b_phong is null or t.phong=b_phong) and (b_lhnv is null or t.lh_nv like b_lhnv||'%')
                and goc.ma_dvi=t.ma_dvi_hd and goc.so_id=t.so_id_hd
                and (trim(b_nguon) is null or goc.ma_gt like b_nguon||'%')
                and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh

                group by t.ma_dvi,t.phong,t.nv,t.ngay_ht,t.so_id_hd,t.ma_dvi_hd,t.lh_nv;
--chua giai quyet ==> OK
delete temp_bc_ts;
--PBC_BH_TS(b_madvi,b_nsd,'',b_ngayd,b_ngayc,b_loi);
insert into temp_bc_ts values(b_dvi||'%',b_ngayd, b_ngayc);
PBC_THANG2D_BT_CGQ_MD('T');
insert into bc_bh_bt_temp (ma_dvi,phong,c30,n2,ngay_ht,so_id_hd,ma_dvi_hd,lh_nv)
                select t.ma_dvi,t.c3,t.c2,sum(t.n5),t.n2,t.n3,t.c4, t.lh_nv from temp_bt_1 t, bh_hd_goc goc
                where (b_phong is null or t.c3=b_phong) and (b_lhnv is null or t.lh_nv like b_lhnv||'%')
                --and t.c2 in (Select nv from temp_bc_nv)
                and exists(Select nv from temp_bc_nv where nv=t.c2 and rownum=1)
                and goc.ma_dvi=t.c4 and goc.so_id=t.n3
                and (trim(b_nguon) is null or goc.ma_gt like b_nguon||'%')
                and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                group by t.ma_dvi,t.c3,t.c2,t.n2,t.n3,t.c4,t.lh_nv;

-- So lieu luy ke tu dau nam
if b_ngaydn=b_ngayd then
    update bc_bh_bt_temp set n4=n1, n5=n2;
else
    delete temp_bc_ts;
    insert into temp_bc_ts values(b_dvi||'%',b_ngaydn, b_ngayc);
    --boi thuong luy ke ==> OK
    PBC_THANG2D_TH_BT_PB_MD('T');
    insert into bc_bh_bt_temp (ma_dvi,phong,c30,n4,ngay_ht,so_id_hd,ma_dvi_hd,lh_nv)
                    select t.ma_dvi,t.phong,t.nv,sum(t.tien_qd),t.ngay_ht,t.so_id_hd,t.ma_dvi_hd,t.lh_nv from bc_bh_bt_hs_temp t, bh_hd_goc goc
                    where t.ngay_qd_n<30000101 and t.ngay_ht between b_ngaydn and b_ngayc
                    and (b_phong is null or t.phong=b_phong) and (b_lhnv is null or t.lh_nv like b_lhnv||'%')
                    and t.nv in (Select nv from temp_bc_nv)
                    and goc.ma_dvi=t.ma_dvi_hd and goc.so_id=t.so_id_hd
                    and (trim(b_nguon) is null or goc.ma_gt like b_nguon||'%')
                    and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                    group by t.ma_dvi,t.phong,t.nv,t.ngay_ht,t.so_id_hd,t.ma_dvi_hd,t.lh_nv;
    delete temp_bc_ts;
    insert into temp_bc_ts values(b_dvi||'%',b_ngaydn, b_ngayc);
    PBC_THANG2D_BT_CGQ_MD('T');
    insert into bc_bh_bt_temp (ma_dvi,phong,c30,n5,ngay_ht,so_id_hd,ma_dvi_hd,lh_nv)
                    select t.ma_dvi,t.c3,t.c2,sum(t.n5),t.n2,t.n3,t.c4,t.lh_nv from temp_bt_1 t, bh_hd_goc goc
                    where (b_phong is null or c3=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
                    --and c2 in (Select nv from temp_bc_nv)
                    and exists(Select nv from temp_bc_nv where nv=t.c2 and rownum=1)
                    and goc.ma_dvi=t.c4 and goc.so_id=t.n3
                    and (trim(b_nguon) is null or goc.ma_gt like b_nguon||'%')
                    and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                    group by t.ma_dvi,t.c2,t.c3,t.n2,t.n3,t.c4,t.lh_nv;
end if;

--Lay so lieu da tu xa xua den b_ngayc
delete temp_bc_ts;
 insert into temp_bc_ts values(b_dvi||'%',b_ngaydn, b_ngayc);
 --boi thuong luy ke ==> OK
 PBC_THANG2D_TH_BT_PB_MD('T');
 insert into bc_bh_bt_temp (ma_dvi,phong,c30, n7,ngay_ht,so_id_hd,ma_dvi_hd,lh_nv)
                 select t.ma_dvi,t.phong,t.nv, sum(t.tien_qd),t.ngay_ht,t.so_id_hd,t.ma_dvi_hd,t.lh_nv from bc_bh_bt_hs_temp t, bh_hd_goc goc
                 where t.ngay_qd_n<30000101 and t.ngay_ht between 20000101 and b_ngayc
                 and (b_phong is null or t.phong=b_phong) and (b_lhnv is null or lh_nv like b_lhnv||'%')
                 and t.nv in (Select nv from temp_bc_nv)
                 and goc.so_id=t.so_id_hd and goc.ma_dvi=t.ma_dvi_hd
                 and (trim(b_nguon) is null or goc.ma_gt like b_nguon||'%')
                 and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                 group by t.ma_dvi,t.phong,t.nv,t.ngay_ht,t.so_id_hd,t.ma_dvi_hd,t.lh_nv;
 delete temp_bc_ts;
 insert into temp_bc_ts values(b_dvi||'%',20000101, b_ngayc);
 PBC_THANG2D_BT_CGQ_MD('T');
 insert into bc_bh_bt_temp (ma_dvi,phong,c30, n8,ngay_ht,so_id_hd,ma_dvi_hd,lh_nv)
                 select t.ma_dvi,t.c3,t.c2, sum(t.n5),t.n2,t.n3,t.c4,t.lh_nv from temp_bt_1 t, bh_hd_goc goc
                 where (b_phong is null or t.c3=b_phong) and (b_lhnv is null or t.lh_nv like b_lhnv||'%')
                 --and c2 in (Select nv from temp_bc_nv)
                 and exists(Select nv from temp_bc_nv where nv=t.c2 and rownum=1)
                 and goc.so_id=t.n3 and goc.ma_dvi=t.c4
                 and (trim(b_nguon) is null or goc.ma_gt like b_nguon||'%')
                 and FBH_HD_LKH(goc.ma_dvi,goc.so_id)=b_lkh
                 group by t.ma_dvi,t.c3,t.c2,t.n2,t.n3,t.c4,t.lh_nv;

delete ket_qua;delete temp_6;

--Xu ly so don vi
delete temp_6; commit;
insert into temp_6(c1,c2, c30,n1, n2, n4, n5, n7, n8)
    select a.ma_dvi, '', b.ma_kh, sum(n1), sum(n2), sum(n4), sum(n5), sum(n7), sum(n8)
        from bc_bh_bt_temp a, bh_hd_goc b
        where (b_dvi is null or a.ma_dvi like b_dvi||'%') and a.ma_dvi<>'000'
        and (b_lhnv is null or a.lh_nv like b_lhnv||'%')
        and (b_phong is null or a.phong=b_phong)
        and b.so_id=a.so_id_hd and b.ma_dvi=a.ma_dvi_hd
        and FBH_HD_LKH(b.ma_dvi,b.so_id)=b_lkh
        group by a.ma_dvi, b.ma_kh;
--Chen doanh thu trong ky
    PBC_TS_BC_QTRI(b_dvi,b_ngayd,b_ngayc,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,ma_kh,dt_ps,dt_bh,dt_tt)
    select c20,c2,c4,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c20,c2,c4;
insert into temp_6 (c1,c2,c30,n10)
    select ma_dvi,'',ma_kh, sum(dt_bh)
    from BH_THANG2D_BC_DT_LUU 
    where ma_dvi like b_dvi||'%' 
--    and ngay between b_ngayd and b_ngayc
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_loai_kh is null or loai_kh like b_loai_kh||'%')
--    and (b_phong is null or phong=b_phong) and ma_dvi<>'000'
--    and (b_phong is null or phong=b_phong) and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    --and FBH_HD_LKH(ma_dvi,so_id)=b_lkh
--    and nv in (Select nv from temp_bc_nv)
    group by ma_dvi, ma_kh;

    PBC_TS_BC_QTRI(b_dvi,b_ngaydn,b_ngayc,'','','','',''); 
--    insert into temp_2 (c10,n20,c20,c1, c2, c3, c4, c5, c6, c7, c8, n1, n6, n7)
--    select nv,so_id, ma_dvig,ma_dvi,phong,so_hd,ma_kh,nguon,cb_ql,ma_kt,lh_nv,so_id,sum(phi),sum(thue)
    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,ma_kh,dt_ps,dt_bh,dt_tt)
    select c20,c2,c4,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c20,c2,c4;
insert into temp_6 (c1,c2, c30,n11)
    select ma_dvi,'',ma_kh, sum(dt_bh)
    from BH_THANG2D_BC_DT_LUU where ma_dvi like b_dvi||'%' 
--    and ngay between b_ngaydn and b_ngayc
--    and (b_lhnv is null or lh_nv like b_lhnv||'%') and (b_loai_kh is null or loai_kh like b_loai_kh||'%')
--    and (b_phong is null or phong=b_phong) and ma_dvi<>'000'
--    and (b_phong is null or phong=b_phong) and (trim(b_nguon) is null or nguon like b_nguon||'%')
--    --and FBH_HD_LKH(ma_dvi,so_id)=b_lkh
--    and nv in (Select nv from temp_bc_nv)
    group by ma_dvi, ma_kh;


delete temp_6 where nvl(n10,0)=0 and nvl(n11,0)=0 and nvl(n1,0)=0 and nvl(n2,0)=0 and nvl(n3,0)=0 and nvl(n4,0)=0 and nvl(n5,0)=0 and nvl(n6,0)=0 and nvl(n7,0)=0 and nvl(n8,0)=0;


-- update temp_6 set c29=(Select loai from bh_hd_ma_kh where ma_dvi=c1 and ma=c30);
update
       (select temp_6.c29 temp_6_c29, bh_hd_ma_kh.loai bh_hd_ma_kh_loai
              from temp_6, bh_hd_ma_kh
             where temp_6.c1 = bh_hd_ma_kh.ma_dvi and temp_6.c30 = bh_hd_ma_kh.ma)
       set temp_6_c29 = bh_hd_ma_kh_loai;


insert into ket_qua(c1, n1, n2, n4, n5, n7, n8,n10,n11)
  select c1, sum(n1), sum(n2), sum(n4), sum(n5), sum(n7), sum(n8),sum(n10),sum(n11) from temp_6
  where (b_loai_kh is null or c29 like b_loai_kh||'%')
  group by c1;

update ket_qua set (c11, c12)=(select ten_gon,'2. Cac cong ty thanh vien' from ht_ma_dvi where ma=c1) where c1<>'000';

commit;
open cs_kq for
    select c1, c2, c11 ten_dvi, c12 ten_dvi_goc, round(n10) DT_TK, round(n11) DT_LK,
        round(n1) DGQ_TK, round(n2) CON_U_TK, round(nvl(n1,0)+nvl(n2,0)) TONG_PS_TK, case round(n10) when 0 then 0 else round((nvl(n1,0)+nvl(n2,0))/n10,4)*100 end ty_le_tk,
        round(n4) DGQ_LK, round(n5) CON_U_LK, round(nvl(n4,0)+nvl(n5,0)) TONG_PS_LK, case round(n11) when 0 then 0 else round((nvl(n4,0)+nvl(n5,0))/n11,4)*100 end ty_le_lk,
        round(n7) DGQ_LK_BTXX, round(n8) TONG_TON
    from ket_qua;
exception when others then raise_application_error(-20105,b_loi);
end;
/

DROP PROCEDURE PBH_THANG2D_BT_QT_NV;
CREATE OR REPLACE PROCEDURE PBH_THANG2D_BT_QT_NV
    (b_madvi varchar2,b_nsd varchar2,b_pas varchar2, b_dvi varchar2, b_phong varchar2,b_nguon varchar2, b_loai_kh varchar2, b_lhnv varchar2,
    b_ngayd number,b_ngayc number,cs_kq out pht_type.cs_type)
AS
    b_loi varchar2(100);b_ngaydn number; b_n1 number; b_n2 number; b_ngaynt number;b_i1 number;
    b_ngay_c number; b_d1 number; b_d2 number;b_ngayd_nt number;b_ngayc_nt number;
    b_ngayd_lk_nt number;b_ngayc_lk_nt number;b_ma_vp varchar2(10); b_lkh varchar2(10);
    b_ten_proc varchar2(40);
Begin

-- Bao cao nhanh tinh hinh  boi thuong tong
b_loi:=FHT_MA_NSD_KTRA(b_madvi,b_nsd,b_pas,'BH','','');
if b_loi is not null then raise PROGRAM_ERROR; end if;
b_lkh:='';
if b_loai_kh is not null then
