    insert into BH_THANG2D_BC_DT_LUU(ma_dvi,phong,nv,lh_nv,dt_ps,dt_bh,dt_tt)
    select c20,c2,c10,c8,sum(nvl(n2,0)),sum(nvl(n4,0)),sum(nvl(n6,0)) from temp_2 group by c20,c2,c10,c8;
    insert into temp_1(c10, c3, n11)
        (Select lh_nv,loai_kh, sum(nvl(dt_bh,0)) from BH_THANG2D_BC_DT_LUU
        where (b_dvi is null or ma_dvi like b_dvi||'%') --ngay between b_ngaydn and b_ngayc and 
