  PROCEDURE MA_DVI(b_ma IN varchar2,cs out sys_refcursor);
  PROCEDURE PHONG(b_ma_dvi IN varchar2,b_ma IN varchar2,cs out sys_refcursor);
  PROCEDURE LHNV(b_ma_dvi IN varchar2,b_ma IN varchar2,cs out sys_refcursor);
  PROCEDURE LOAI(b_ma_dvi IN varchar2,b_ma IN varchar2,cs out sys_refcursor);
  PROCEDURE DTPS(b_ma_dvi IN varchar2,b_lhnv IN varchar2,b_ngayd in number,b_ngayc in number,cs out sys_refcursor);
  PROCEDURE DTBH(b_ma_dvi IN varchar2,b_lhnv IN varchar2,b_ngayd in number,b_ngayc in number,cs out sys_refcursor);
