CREATE OR REPLACE PACKAGE BODY PKG_CALL_DATA AS
/******************************************************************************
   NAME:       PKG_CALL_DATA
   PURPOSE: AAA CALL

   REVISIONS:
   Ver        Date        Author           Description
   ---------  ----------  ---------------  ------------------------------------
   1.0        11/8/2024      adminlocal       1. Created this package body.
******************************************************************************/

PROCEDURE MA_DVI(b_ma in VARCHAR2,cs out sys_refcursor) 
AS
BEGIN
open cs for 
select MA, CAP, TEN, TEN_GON, DCHI, MA_THUE,G_DOC, KTT, TEN_SV,TEN_DB, TEN_DBO, IP,MA_TK, NHANG, KVUC,MA_CT, PAS_DI, PAS_DEN,TT_HD, LOAI, VP,NGAY_BD, NGAY_KT, NSD,IDVUNG, MA_GOC, MA_CT_GOC,TDX, TDY 
from ht_ma_dvi 
where (b_ma is null or ma=b_ma);
END;

PROCEDURE PHONG(b_ma_dvi in varchar2,b_ma in VARCHAR2,cs out sys_refcursor) 
AS
BEGIN
open cs for 
select MA_DVI, MA, TEN, NHOM, PNHAN, MA_CT,NSD, IDVUNG 
from ht_ma_phong 
where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and (b_ma is null or ma=b_ma);
END;

PROCEDURE LHNV(b_ma_dvi in varchar2,b_ma in VARCHAR2,cs out sys_refcursor) 
AS
BEGIN
open cs for 
select MA, MA_DVI, TEN, TC, BB, LOAI,MA_CT, MA_CD, MA_TAI,NGAY_BD, NGAY_KT, NV,NSD, TXT
from bh_ma_lhnv
where (b_ma_dvi is null or ma_dvi=b_ma_dvi) and (b_ma is null or ma=b_ma);
END;

PROCEDURE LOAI(b_ma_dvi in varchar2,b_ma in VARCHAR2,cs out sys_refcursor) 
AS
BEGIN
open cs for 
select '1' from dual;
END;

PROCEDURE DTPS(b_ma_dvi IN varchar2,b_lhnv IN varchar2,b_ngayd in number,b_ngayc in number,cs out sys_refcursor) 
AS
BEGIN
delete TEMP_BC_BH_DTPS_MM;
delete temp_1;
BC_BH_LAY_BC_BH_DTPS_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
INSERT INTO temp_1(c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,d1,d2,c11,c12,n1,n2,n3,n4,n5,n6,n7,n8,c13)
SELECT MA_DVI, SO_HD, NV, KIEU_HD, MA_KH, NGUON, CB_QL, PHONG,
KIEU_KT, MA_KT, NGAY_HL, NGAY_KT, MA_NT, LH_NV, SO_ID,
NGAY_HT, NGAY_HTNV, PHI, THUE, PHI_NT, THUE_NT, 0, MA_DVIG
FROM TEMP_BC_BH_DTPS_MM where (b_lhnv is null or lh_nv like b_lhnv||'%');
merge into temp_1 using (select so_id,min(ngay_cap)ngay_cap from bh_hd_goc group by so_id)a on(n1=a.so_id) when matched then update set c14=PKH_SO_CNG(a.ngay_cap);
COMMIT;
open cs for 
SELECT C1 MA_DVI,C2 SO_HD,C3 NV,C4 KIEU_HD,C5 MA_KH,C6 NGUON,C7 CB_QL,C8 PHONG,
C9 KIEU_KT,C10 MA_KT,D1 NGAY_HL,D2 NGAY_KT,C11 MA_NT,C12 LH_NV,N1 SO_ID,C13 MA_DVIG,N2 NGAY_HT,N3 NGAY_HTNV,c14 ngay_cap,
N4 PHI,N5 THUE,N6 PHI_NT,N7 THUE_NT
FROM temp_1;
END;

PROCEDURE DTBH(b_ma_dvi IN varchar2,b_lhnv IN varchar2,b_ngayd in number,b_ngayc in number,cs out sys_refcursor) 
AS
BEGIN
delete temp_1;
delete TEMP_BC_BH_DTBH_MM;
BC_BH_LAY_BC_BH_DTBH_MM(B_MA_DVI,B_NGAYD,B_NGAYC);
INSERT INTO temp_1(c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,d1,d2,c11,c12,n1,n2,n3,n4,n5,n6,n7,n8,c13)
SELECT MA_DVI, SO_HD, A.NV, KIEU_HD, MA_KH, NGUON, CB_QL, PHONG,
KIEU_KT, MA_KT, NGAY_HL, NGAY_KT, MA_NT, LH_NV, SO_ID,
NGAY_HT, NGAY_HTNV, PHI, THUE, PHI_NT, THUE_NT, DBH, MA_DVIG
FROM TEMP_BC_BH_DTBH_MM A
WHERE (b_lhnv is null or lh_nv like b_lhnv||'%');
merge into temp_1 using (select so_id,min(ngay_cap)ngay_cap from bh_hd_goc group by so_id)a on(n1=a.so_id) when matched then update set c14=PKH_SO_CNG(a.ngay_cap);
COMMIT;
open cs for 
SELECT C1 MA_DVI,C2 SO_HD,C3 NV,C4 KIEU_HD,C5 MA_KH,C6 NGUON,C7 CB_QL,C8 PHONG,
C9 KIEU_KT,C10 MA_KT,D1 NGAY_HL,D2 NGAY_KT,C11 MA_NT,C12 LH_NV,N1 SO_ID,C13 MA_DVIG,N2 NGAY_HT,N3 NGAY_HTNV,c14 ngay_cap,
N4 PHI,N5 THUE,N6 PHI_NT,N7 THUE_NT
FROM temp_1;
END;

PROCEDURE DTTT(b_ma_dvi IN varchar2,b_lhnv IN varchar2,b_ngayd in number,b_ngayc in number,cs out sys_refcursor) 
AS
BEGIN
delete TEMP_BC_BH_DTTT_MA_DT;
delete temp_1;
BC_BH_LAY_BC_BH_DTTT_MA_DT(B_MA_DVI,B_NGAYD,B_NGAYC);
INSERT INTO temp_1(c1,c2,c3,c4,c5,c6,c7,c8,c9,c10,d1,d2,c11,c12,n1,n2,n3,n4,n5,n6,n7,n8,c13)
SELECT MA_DVI, SO_HD, NV, KIEU_HD, MA_KH, NGUON,CB_QL, PHONG, 
KIEU_KT,MA_KT, NGAY_HL, NGAY_KT,MA_NT, LH_NV, SO_ID, 
NGAY_HT, NGAY_HTNV,PHI, THUE,PHI, THUE,  DBH, MA_DVIG --SO_ID_TT, HHONG,HHONG_NT, HTRO, HTRO_NT,PT,
FROM TEMP_BC_BH_DTTT_MA_DT WHERE (b_lhnv is null or lh_nv like b_lhnv||'%');
merge into temp_1 using (select so_id,min(ngay_cap)ngay_cap from bh_hd_goc group by so_id)a on(n1=a.so_id) when matched then update set c14=PKH_SO_CNG(a.ngay_cap);
COMMIT;
open cs for 
SELECT C1 MA_DVI,C2 SO_HD,C3 NV,C4 KIEU_HD,C5 MA_KH,C6 NGUON,C7 CB_QL,C8 PHONG,
C9 KIEU_KT,C10 MA_KT,D1 NGAY_HL,D2 NGAY_KT,C11 MA_NT,C12 LH_NV,N1 SO_ID,C13 MA_DVIG,N2 NGAY_HT,N3 NGAY_HTNV,c14 ngay_cap,
N4 PHI,N5 THUE,N6 PHI_NT,N7 THUE_NT
FROM temp_1;
END;

PROCEDURE NO_PHI(b_ma_dvi varchar2,b_so_hd varchar2,b_ngayd number,b_ngayc number,cs out sys_refcursor)
AS
b_so_idD number:=0;
BEGIN
--Liet ke cac hop dong no phi
delete temp_1; delete temp_2; delete temp_3; commit;
if trim(b_so_hd) is not null then
    b_so_idD:=FBH_HD_GOC_SO_ID_DAU(b_ma_dvi,b_so_hd);
end if;
insert into temp_1(n1,c1)
    select so_id,so_hd from bh_hd_goc_sc_phi_ton where ma_dvi=b_ma_dvi and b_so_idD in(0,so_id) minus
    select so_id,so_hd from bh_hd_goc_sc_no_ton where ma_dvi=b_ma_dvi and b_so_idD in(0,so_id);
insert into temp_3(c5,n1,n2,c7,n3) select ma_dvi,so_id,ngay,'G',sum(ttoan) from bh_hd_goc_cl
    where ma_dvi=b_ma_dvi and so_id in (select n1 from temp_1) and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id,ngay;
insert into temp_3(c5,n1,n2,c7,n3) select  ma_dvi,so_id,ngay,'G',-sum(ttoan) from bh_hd_goc_ttpt
    where ma_dvi=b_ma_dvi and pt not in('N','H') and so_id in (select n1 from temp_1) and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id,ngay;
insert into temp_3(c5,n1,n2,c7,n3) select ma_dvi,so_id,ngay,'G',sum(ttoan) from bh_hd_goc_ttpt
    where ma_dvi=b_ma_dvi and pt='C' and so_id in (select n1 from temp_1) and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id,ngay;
insert into temp_3(c5,n1,n2,c7,n3) select ma_dvi,so_id,ngay,'G',-sum(ttoan) from bh_hd_goc_ttpt
    where ma_dvi=b_ma_dvi and pt='N' and so_id in (select n1 from temp_1) and ngay_ht between b_ngayd and b_ngayc group by ma_dvi,so_id,ngay;
insert into temp_2(c5,c7,n1,n2,n3) select c5,c7,n1,n2,sum(n3) from temp_3 group by c5,c7,n1,n2 having sum(n3)<>0;
update temp_2 set c1=(select distinct c1 from temp_1 where n1=temp_2.n1);
update temp_2 set (c2,c6,n6,n7,n8,n9)=(select ma_kh,nv,ngay_cap,ngay_hl,ngay_kt,ngay_ht from bh_hd_goc where ma_dvi=b_ma_dvi and so_id=temp_2.n1);
--update temp_2 set (c3,c4)=(select ten,mobi from bh_hd_ma_kh where ma=temp_2.c2);
COMMIT;
open cs for 
select c5 ma_dvi,c6 nv,c1 so_hd, pkh_so_cng(n2) ngay_nph,n3 phi,c2 MA_KH,n6 ngay_cap,n7 ngay_hl,n8 ngay_kt,n9 ngay_ht from temp_2 order by n2;
END;

