BEGIN
BC_BH_THDT_PSTRN_DULIEU (b_ma_dvi, b_ngayd,b_ngayc,cs);
COMMIT;
open cs for 
SELECT C1 MA_DVI,C10 TEN_DVI,C2 MA_KH,C3 TEN,C5 DCHI,C6 MOBI,c7 MA_KT,C4 SO_HD, N4 DTHU, N5 THUE,N20/10000 NAM, n3 ngay_ht
FROM KET_QUA;
END;

PROCEDURE BT(b_ma_dvi IN varchar2,b_loai in varchar2,b_ngayd in number,b_ngayc in number,cs out sys_refcursor) 
AS
ten1 varchar(100);ten2 varchar(100); ten3 varchar(100);ten4 varchar(100);ten5 varchar(100);
BEGIN
delete TEMP_16;
if b_loai ='DUYET' then
    insert into TEMP_16(C1, C2, C3, C4, C5, C6,C7, C8, C9,C10, C11, C12,C13, C14, N4, N5,N6, N7,N8,N9, N10,C15,N1, N2,N3)
    SELECT BT.MA_DVI_XL,NV,SO_HS,TTRANG,PHONG,PKH_SO_CNG(NGAY_GUI)NGAY_GUI,PKH_SO_CNG(NGAY_XR)NGAY_XR,PKH_SO_CNG(NGAY_QD)NGAY_QD,BT.NGAY_HT,N_TRINH,N_DUYET,
    MA_KH,TEN,LH_NV,TIEN_BH,PT_BT,T_THAT,TIEN,TIEN_QD,NV.THUE,NV.THUE_QD,NV.MA_NT,BT.SO_ID,SO_ID_HD,SO_ID_DT
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    AND BT.MA_DVI=BT.MA_DVI_XL
    AND (MA_DVI_XL= B_MA_DVI OR B_MA_DVI IS NULL)
    AND (BT.NGAY_QD BETWEEN b_ngayd AND b_ngayc);
else
    insert into TEMP_16(C1, C2, C3, C4, C5, C6,C7, C8, C9,C10, C11, C12,C13, C14, N4, N5,N6, N7,N8,N9, N10,C15,N1, N2,N3)
    SELECT BT.MA_DVI_XL,NV,SO_HS,TTRANG,PHONG,PKH_SO_CNG(NGAY_GUI)NGAY_GUI,PKH_SO_CNG(NGAY_XR)NGAY_XR,PKH_SO_CNG(NGAY_QD)NGAY_QD,BT.NGAY_HT,N_TRINH,N_DUYET,
    MA_KH,TEN,LH_NV,TIEN_BH,PT_BT,T_THAT,TIEN,TIEN_QD,NV.THUE,NV.THUE_QD,NV.MA_NT,BT.SO_ID,SO_ID_HD,SO_ID_DT
    FROM BH_BT_HS BT,BH_BT_HS_NV NV
    WHERE BT.MA_DVI=NV.MA_DVI AND BT.SO_ID=NV.SO_ID
    AND BT.MA_DVI=BT.MA_DVI_XL
    AND (MA_DVI_XL= B_MA_DVI OR B_MA_DVI IS NULL)
    AND (BT.NGAY_HT BETWEEN b_ngayd AND b_ngayc) and BT.NGAY_QD='30000101';
end if;
UPDATE TEMP_16 SET (C16,C17)=(SELECT BIEN_XE,NG_HUONG FROM  BH_BT_XE_CT WHERE MA_DVI=C1 AND SO_ID=N1);
UPDATE TEMP_16 SET (C18,C19,C20,C21)=(SELECT SO_KHUNG,SO_MAY,LOAI_XE,NHOM_XE FROM  BH_XE_DS WHERE MA_DVI=C1 AND SO_ID=N2 AND SO_ID_DT=N3);
UPDATE TEMP_16 SET (C22,C23)=(SELECT GCN,SO_HD FROM  BH_BT_XE WHERE MA_DVI=C1 AND SO_ID=N1);
update temp_16 set c24 = case when C4='S' then '�ang so?n' when C4='T' then '�ang tr�nh' when C4='D' then '�� duy?t' when C4='H' then 'H?y b?' when C4='C' then 'T? ch?i' end;
COMMIT;
open cs for 
SELECT C1 MA_DVI_XL,C2 NV,C3 SO_HS,c22 gcn,c23 so_hd,C4 TTRANG,c24 TINH_TRANG,C5 PHONG,C6 NGAY_GUI,C7 NGAY_XR,C8 NGAY_QD,C9 NGAY_HT,C10 N_TRINH,C11 N_DUYET,
C12 MA_KH,C13 TEN,C14 LH_NV,N4 TIEN_BH,N5 PT_BT,N6 T_THAT,N7 TIEN,N8 TIEN_QD,N9 THUE,N10 THUE_QD,C15 MA_NT,--,N1 SO_ID,N2 SO_ID_HD,N3 SO_ID_DT
C16 BIEN_XE,C17 NG_HUONG,C18 SO_KHUNG,C19 SO_MAY,C20 LOAI_XE,C21 NHOM_XE
FROM TEMP_16;
END;


END PKG_CALL_DATA;
/


DROP PROCEDURE PTBH_LKE_HDTA;

CREATE OR REPLACE PROCEDURE PTBH_LKE_HDTA
    (B_MA_DVI VARCHAR2,B_NSD VARCHAR2,B_PAS VARCHAR2,CS_TA OUT PHT_TYPE.CS_TYPE,B_LOAI VARCHAR2,B_NGAYD NUMBER,B_NV VARCHAR2)
AS
    B_LOI VARCHAR2(100);
BEGIN

B_LOI:=FHT_MA_NSD_KTRA(B_MA_DVI,B_NSD,B_PAS,'BH','TA','NX');
IF B_LOI IS NOT NULL THEN RAISE PROGRAM_ERROR; END IF;
FTBH_LKE_HDTA(B_MA_DVI,CS_TA,B_LOAI,B_NGAYD,B_NV);
EXCEPTION WHEN OTHERS THEN RAISE_APPLICATION_ERROR(-20105,B_LOI);
END;
/

DROP VIEW TAI_TM_HTRO;

CREATE OR REPLACE FORCE VIEW TAI_TM_HTRO
(
    SO_HD,
    NGAY_XU_LY,
    SO_CT,
    NGAY_HL,
    NGAY_KT,
    NT_TIEN,
    NT_PHI,
    MA_NHA_BH,
    TEN_NHA_BH,
    NGAY_HIEULUC,
    MA_TA,
    PT,
    TIEN,
    PHI,
    TL_THUE,
    THUE,
    PT_HH,
    HHONG,SO_ID_HD,SO_ID_DT
)
BEQUEATH DEFINER
AS
SELECT d.so_hd,           a.ngay_ht     ngay_xu_ly,           a.so_ct,           a.ngay_hl,           a.ngay_kt,           a.nt_tien,           a.nt_phi,
a.nha_bh      ma_nha_bh,           a.nha_bh      ten_nha_bh,           a.ngay_hl     ngay_hieuluc,           b.ma_ta,           b.PT,           b.tien,
b.phi,           b.tl_thue,           b.thue,           b.pt_hh,           b.hhong,c.so_id_hd,c.so_id_dt
FROM tbh_tm      a,
TBH_TM_PHI  b,
tbh_tm_hd   c,
bh_hd_goc   d
WHERE     a.so_id = b.so_id
AND a.so_id = c.so_id
AND c.so_id_hd = d.so_id
AND b.pt > 0
AND d.ttrang = 'D';

