DROP FUNCTION BCNAM_SO_NGAY_F;

CREATE OR REPLACE FUNCTION BCNAM_SO_NGAY_F
(
    B_SO NUMBER
)RETURN NVARCHAR2
AS
    B_NGAY NVARCHAR2(10);
BEGIN
    B_NGAY:=TO_CHAR(B_SO);
    RETURN SUBSTR(B_NGAY,7,2)||'/'||SUBSTR(B_NGAY,5,2)||'/'||SUBSTR(B_NGAY,1,4);
END;
/

DROP FUNCTION BC_HOI_LOAIXE;

CREATE OR REPLACE FUNCTION BC_HOI_LOAIXE (B_MA_DVI VARCHAR2,B_NV VARCHAR2,
	B_SO_ID NUMBER,B_SO_ID_DT NUMBER,B_LH_NV VARCHAR2) RETURN VARCHAR2
AS
	B_KQ VARCHAR2(20);B_I1 NUMBER;
BEGIN

B_KQ:='';
IF B_NV='XE' OR B_NV='XEL' THEN
	SELECT COUNT(*) INTO B_I1 FROM BH_XE_DS WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID AND SO_ID_DT=B_SO_ID_DT AND ROWNUM=1;
	IF B_I1 <>0 THEN
		SELECT nv_bh INTO B_KQ FROM BH_XE_DS WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID AND SO_ID_DT=B_SO_ID_DT  AND ROWNUM=1;
	END IF;
ELSIF B_NV='2B' OR B_NV='2BL' THEN
	SELECT COUNT(*) INTO B_I1 FROM BH_2B_Ds WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID AND SO_ID_DT=B_SO_ID_DT  AND ROWNUM=1;
	IF B_I1 <>0 THEN
		SELECT nv_bh  INTO B_KQ FROM BH_2B_Ds WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID AND SO_ID_DT=B_SO_ID_DT  AND ROWNUM=1;
	END IF;
END IF;
RETURN B_KQ;
END;
/
