DROP FUNCTION FBC_MA_BH;

CREATE OR REPLACE FUNCTION FBC_MA_BH(B_MADVI VARCHAR2,B_NV VARCHAR2,B_SO_ID NUMBER) RETURN NVARCHAR2
AS
    B_KQ NVARCHAR2(100); B_MA_DVI VARCHAR2(10);
BEGIN
--SELECT MA_DVI INTO B_MA_DVI FROM BH_HD_GOC WHERE MA_DVI=B_MADVI AND SO_ID=B_SO_ID;
b_ma_dvi:=b_madvi;
--IF B_NV='XE' OR B_NV='XEL'  THEN B_KQ:='XE';
--ELSIF B_NV='2B' OR B_NV='2BL'  THEN B_KQ:='2B';
--ELSIF B_NV='HANG' THEN SELECT MA_NHOM INTO B_KQ FROM BH_HANGGCN WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID;
--ELSIF B_NV IN('NG','NG_TT','NG_DL') THEN SELECT NHOM INTO B_KQ FROM BH_NGUOIHD WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID;
--ELSIF B_NV='TAU' THEN SELECT NHOM_TAU INTO B_KQ FROM BH_TAUGCN WHERE MA_DVI=B_MA_DVI AND SO_ID=B_SO_ID AND ROWNUM=1;
