DROP FUNCTION FBH_DONG_TL_DI;

CREATE OR REPLACE FUNCTION FBH_DONG_TL_DI(b_ma_dvi varchar2,b_so_id number,b_so_id_dt number,b_lh_nv varchar2,b_ma_dvi_do varchar2) return number DETERMINISTIC
AS
    b_kieu_do varchar2(1); b_kq number:=100; b_i1 number;
begin
-- Dong
select nvl(count(1),0) into b_i1 from bh_hd_do_tl where ma_dvi=b_ma_dvi and so_id=b_so_id and so_id_dt in (0,b_so_id_dt)
    and pthuc in('P','D') and lh_nv in ('*',b_lh_nv) and nha_bh=b_ma_dvi_do;
    if b_i1 > 0 then
    select max(sum(pt)) pt into b_kq from bh_hd_do_tl where ma_dvi=b_ma_dvi and so_id=b_so_id and so_id_dt in (0,b_so_id_dt)
    and pthuc in('P','D') and lh_nv in ('*',b_lh_nv) and nha_bh=b_ma_dvi_do; -- chuclh: bo group by
    else
    b_kq:=100;
    end if;
    
return b_kq;
end;
/

