DROP FUNCTION FBH_HD_SO_ID_BS_KK;

CREATE OR REPLACE FUNCTION FBH_HD_SO_ID_BS_KK(B_MA_DVI VARCHAR2,B_SO_ID NUMBER,B_NGAY_HT NUMBER) RETURN NUMBER
AS
    B_SO_ID_C NUMBER; B_I1 NUMBER; B_I2 NUMBER; B_TTRANG VARCHAR2(1);
BEGIN

B_SO_ID_C:=B_SO_ID;
WHILE TRUE LOOP
    SELECT NVL(MIN(SO_ID),0),NVL(MIN(NGAY_HT),0),MIN(TTRANG) INTO B_I1,B_I2,B_TTRANG
        FROM BH_HD_GOC WHERE MA_DVI=B_MA_DVI AND SO_ID_G=B_SO_ID_C AND KIEU_HD NOT IN ('K');
    IF B_I1=0 OR B_I2>=B_NGAY_HT OR B_TTRANG<>'D' THEN EXIT; END IF;
    B_SO_ID_C:=B_I1;
END LOOP;
RETURN B_SO_ID_C;
END;
/
