DROP FUNCTION fbh_hh_lay_nhomkh;

CREATE OR REPLACE FUNCTION fbh_hh_lay_nhomkh (B_MA_KH VARCHAR2, B_MA_DVI VARCHAR2)
    RETURN VARCHAR2
IS
    B_VALUE VARCHAR2(20); 
    RESULT VARCHAR2(20); 
BEGIN 
    SELECT MAX(loai) INTO B_VALUE FROM BH_HD_MA_KH WHERE MA = B_MA_KH;
    
    IF B_VALUE = 'C' THEN 
        RESULT := 'LC01'; 
    ELSIF B_VALUE = 'T' THEN 
        RESULT := 'LC02';
    ELSE
        RESULT := 'LC01';
    END IF;
         
    IF B_MA_KH IS NULL THEN
        RESULT := 'LC01';
    END IF;
       
    RETURN RESULT;  
END;

/

DROP FUNCTION FBH_MA_TEN;

CREATE OR REPLACE FUNCTION FBH_MA_TEN(B_NV VARCHAR2,B_MA_DVI VARCHAR2,B_MA VARCHAR2) RETURN NVARCHAR2
AS
    B_KQ NVARCHAR2(250):=''; 
BEGIN

IF B_NV='BH_MA_LHNV' THEN 
    SELECT MIN(TEN) INTO B_KQ FROM BH_MA_LHNV WHERE MA_DVI=B_MA_DVI AND MA=B_MA;
ELSIF B_NV='BH_HD_MA_KH' THEN
    SELECT MIN(TEN) INTO B_KQ FROM BH_HD_MA_KH WHERE MA_DVI=B_MA_DVI AND MA=B_MA;
ELSIF B_NV='HT_MA_PHONG' THEN
    SELECT MIN(TEN) INTO B_KQ FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_MA;
ELSIF B_NV='HT_MA_CB' THEN
    SELECT MIN(TEN) INTO B_KQ FROM HT_MA_CB WHERE MA_DVI=B_MA_DVI AND MA=B_MA;
ELSIF B_NV='BH_MA_LDT' THEN
    SELECT MIN(TEN) INTO B_KQ FROM HT_MA_PHONG WHERE MA_DVI=B_MA_DVI AND MA=B_MA;
ELSIF B_NV='HT_MA_DVI' THEN
    SELECT MIN(TEN) INTO B_KQ FROM HT_MA_DVI WHERE MA=B_MA;
END IF;
RETURN B_KQ;
END;
/

