DROP function FBH_MB_JOB_HOI_STAR;

CREATE OR REPLACE function FBH_MB_JOB_HOI_STAR(b_ma_dvi varchar2,b_so_id_hd number,b_ngay_ht number) return varchar2
as
    b_kieu_kt varchar2(1);b_ma_kt varchar2(20);b_i1 number;
    b_kq varchar2(5);
    --b_kq: DLCN - Dai ly ca nhan, TVV - Tu van vien, K - Khong phai
begin
select max(kieu_kt),max(ma_kt) into b_kieu_kt,b_ma_kt from bh_hd_goc where ma_dvi=b_ma_dvi and so_id=b_so_id_hd and kieu_kt='L';
if b_ma_kt is null then b_kq:='K';
else
    select count(*) into b_i1 from bh_dcn_ma_cc where ma=b_ma_kt and ngay<=b_ngay_ht;
    if b_i1>0 then b_kq:='DLCN'; else b_kq:='TVV'; end if;
end if;
return b_kq;
end;
/

