DROP FUNCTION INSTR1;

CREATE OR REPLACE FUNCTION INSTR1(V_COLUMNNAME VARCHAR2, V_VALUES VARCHAR2) RETURN NUMBER IS
  V_I NUMBER :=1;
  V_J NUMBER :=0;
  V_COUNT NUMBER :=1;
BEGIN
 IF V_VALUES IS NULL THEN
    RETURN 1;
 END IF;

  WHILE V_I <= LENGTH(V_VALUES) LOOP
     V_J :=INSTR(V_VALUES,';',V_COUNT);
     IF V_J = 0 THEN
        IF (V_COLUMNNAME = V_VALUES) OR V_COLUMNNAME = SUBSTR(V_VALUES,V_I) THEN
          RETURN 1;
        ELSE
          RETURN 0;
          END IF;
     END IF;

     IF V_COLUMNNAME = SUBSTR(V_VALUES,V_I,V_J-V_I) THEN
       RETURN 1;
     END IF;
       V_I := V_J + 1;
       V_COUNT := V_COUNT + 1;
  END LOOP;

  RETURN 0;

END INSTR1;
/

