DROP function PKH_SO_CNG_DATE;

CREATE OR REPLACE function PKH_SO_CNG_DATE(b_so number) return date
AS
    b_c8 varchar2(8);b_t number;b_n number;b_nam number;
begin
-- Duong - Chuyen so dang yyyymmdd sang date -- chi dung cho bao cao tu dong, chua xu ly chi tiet theo nam
b_c8:=to_char(b_so);
b_t := to_number(substr(b_c8,5,2));
b_n := to_number(substr(b_c8,7,2));
if b_t = 1 then
 if b_n > 31 then b_n:=31; end if;
end if;
if b_t = 2 then
 if b_n > 28 then b_n:=28; end if;
end if;
if b_t = 3 then
 if b_n > 31 then b_n:=31; end if;
end if;
if b_t = 4 then
 if b_n > 30 then b_n:=30; end if;
end if;
if b_t = 5 then
 if b_n > 31 then b_n:=31; end if;
end if;
if b_t = 6 then
 if b_n > 30 then b_n:=30; end if;
end if;
if b_t = 7 then
 if b_n > 31 then b_n:=31; end if;
end if;
if b_t = 8 then
 if b_n > 31 then b_n:=31; end if;
end if;
if b_t = 9 then
 if b_n > 30 then b_n:=30; end if;
end if;
if b_t = 10 then
 if b_n > 31 then b_n:=31; end if;
end if;
if b_t = 11 then
 if b_n > 30 then b_n:=30; end if;
end if;
if b_t >12 then
 b_t :=12 ;b_n:=31;
end if;
return to_date(b_n||'/'||b_t||'/'||substr(b_c8,1,4),'dd/MM/YYYY');
end;
/

