DROP VIEW V_BC_BH_DTBH_HUY;

CREATE OR REPLACE FORCE VIEW V_BC_BH_DTBH_HUY
(
    MA_DVI,
    SO_HD,
    NV,
    KIEU_HD,
    MA_KH,
    CB_QL,
    PHONG,
    KIEU_KT,
    MA_KT,
    NGAY_HL,
    NGAY_KT,
    MA_NT,
    LH_NV,
    SO_ID,
    SO_ID_TT,
    NGAY_HT,
    NGAY_HTNV,
    PHI,
    THUE,
    PHI_NT,
    THUE_NT,
    DBH,
    MA_DVIG
)
BEQUEATH DEFINER
AS
    SELECT goc.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay_tt,
           phi_qd,
           thue_qd,
           nv.phi,
           nv.thue,
           0,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND goc.ngay_ht BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND goc.kieu_hd <> 'V'
           AND (pt = 'G' OR pt = 'H')
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --giam doanh thu nhan truoc

    SELECT goc.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay_tt,
           -phi_qd,
           -thue_qd,
           -nv.phi,
           -nv.thue,
           4,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND nv.ngay_tt BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND goc.kieu_hd <> 'V'
           AND (pt = 'G' OR pt = 'H')
           AND (   (    PKH_SO_NAM (ngay_tt) < PKH_SO_NAM (ngay)
                    AND ADD_MONTHS (PKH_SO_DATE (ngay_hl), 12) <
                        PKH_SO_CDT (ngay))
                OR (    TO_NUMBER (TO_CHAR (PKH_SO_DATE (ngay_hl), 'yyyy')) <
                        3000
                    AND TO_NUMBER (TO_CHAR (PKH_SO_DATE (ngay_hl), 'yyyy')) >
                        PKH_SO_NAM (ngay_tt)))
           AND nv.ngay_tt >= 20091001
           AND lh_nv NOT LIKE 'KT%'
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --ket chuyen doanh thu nhan truoc
    SELECT goc.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay,
           phi_qd,
           thue_qd,
           nv.phi,
           nv.thue,
           5,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND (nv.ngay BETWEEN ts.ngayd AND ts.ngayc)
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND (pt = 'G' OR pt = 'H')
           AND ngay_hl < (nv.ngay)
           AND (   (    PKH_SO_NAM (ngay_tt) < PKH_SO_NAM (ngay)
                    AND ADD_MONTHS (PKH_SO_DATE (ngay_hl), 12) <
                        PKH_SO_CDT (ngay))
                OR (    TO_NUMBER (TO_CHAR (PKH_SO_DATE (ngay_hl), 'yyyy')) <
                        3000
                    AND TO_NUMBER (TO_CHAR (PKH_SO_DATE (ngay_hl), 'yyyy')) >
                        PKH_SO_NAM (ngay_tt)))
           AND nv.ngay_tt >= 20091001
           AND lh_nv NOT LIKE 'KT%'
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    SELECT goc.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay,
           phi_qd,
           thue_qd,
           nv.phi,
           nv.thue,
           5,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND (pt = 'G' OR pt = 'H')
           AND ngay_hl BETWEEN (ts.ngayd) AND (ts.ngayc)
           AND ngay_hl >= (nv.ngay)
           AND (   (    PKH_SO_NAM (ngay_tt) < PKH_SO_NAM (ngay)
                    AND ADD_MONTHS (PKH_SO_DATE (ngay_hl), 12) <
                        PKH_SO_CDT (ngay))
                OR (    TO_NUMBER (TO_CHAR (PKH_SO_DATE (ngay_hl), 'yyyy')) <
                        3000
                    AND TO_NUMBER (TO_CHAR (PKH_SO_DATE (ngay_hl), 'yyyy')) >
                        PKH_SO_NAM (ngay_tt)))
           AND nv.ngay_tt >= 20091001
           AND lh_nv NOT LIKE 'KT%'
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --ket chuyen doanh thu nhan truoc khi huy
    --giam dong bao hiem
    SELECT goc.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay_ht,
           DECODE (kieu, 'V', tien_qd, -tien_qd),
           0,
           DECODE (kieu, 'V', nv.tien, -nv.tien),
           0,
           3,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_do_pt nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND nv.ngay_ht BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND nv.loai IN ('CH_LE_PH', 'DT_LE_TL', 'DT_LE_HU')
           AND (goc.ma_dvi, goc.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --Dong bao hiem don vi
    --tang cho don vi dong folow c19=DT
    SELECT nv.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           nv.phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay_ht,
           phi_qd,
           0,
           nv.phi,
           0,
           1,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpb nv, temp_bc_ts ts
     WHERE     nv.ma_dvi LIKE ts.ma_dvi
           AND nv.ngay_ht BETWEEN ts.ngayd AND ts.ngayc
           AND nv.pthuc IN ('D', 'P')
           AND goc.ma_dvi = nv.dvi_xl
           AND goc.so_id = nv.so_id
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --giam cho don vi dong leader c19='DG'
    SELECT goc.ma_dvi,
           so_hd,
           goc.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           goc.phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_hl,
           ma_nt,
           lh_nv,
           goc.so_id,
           so_id_tt,
           goc.ngay_ht,
           nv.ngay_ht,
           -phi_qd,
           0,
           -nv.phi,
           0,
           2,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpb nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ngay_ht BETWEEN ts.ngayd AND ts.ngayc
           AND nv.pthuc IN ('D', 'P')
           AND goc.ma_dvi = nv.dvi_xl
           AND goc.so_id = nv.so_id
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)

-- Tang doanh thu nhan truoc sangdoanh thu ban hang khi huy hop dong
;


DROP VIEW V_BC_BH_DTBH_MNVM_HUY;

CREATE OR REPLACE FORCE VIEW V_BC_BH_DTBH_MNVM_HUY
(
    MA_DVI,
    SO_HD,
    NV,
    KIEU_HD,
    MA_KH,
    CB_QL,
    PHONG,
    KIEU_KT,
    MA_KT,
    NGAY_HL,
    NGAY_KT,
    MA_NT,
    LH_NV,
    SO_ID,
    NGAY_HT,
    NGAY_HTNV,
    PHI,
    THUE,
    PHI_NT,
    THUE_NT,
    DBH,
    MA_DVIG
)
BEQUEATH DEFINER
AS
    SELECT ma_dvi,
           so_hd,
           a.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           so_id,
           ngay_ht,
           ngay_htnv,
           phi,
           thue,
           phi_nt,
           thue_nt,
           dbh,
