      FROM V_BC_BH_DTBH_HUY  a,
           (SELECT DISTINCT nv
              FROM temp_bc_nv) b
     WHERE a.nv = b.nv;

DROP VIEW V_BC_BH_DTPS_HUY_MM;

CREATE OR REPLACE FORCE VIEW V_BC_BH_DTPS_HUY_MM
(
    MA_DVI,
    SO_HD,
    NV,
    KIEU_HD,
    MA_KH,
    CB_QL,
    PHONG,
    KIEU_KT,
    MA_KT,
    NGAY_HL,
    NGAY_KT,
    MA_NT,
    LH_NV,
    SO_ID,
    NGAY_HT,
    NGAY_HTNV,
    PHI,
    THUE,
    PHI_NT,
    THUE_NT,
    SO_ID_XL
)
BEQUEATH DEFINER
AS
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           goc.kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           goc.ngay_ht,
           nv.ngay_ht,
           CASE ma_nt
               WHEN 'VND'
               THEN
                   nv.phi
               ELSE
                   FTT_VND_QD (goc.ma_dvi,
                               nv.ngay_ht,
                               ma_nt,
                               nv.phi)
           END,
           CASE ma_nt
               WHEN 'VND'
               THEN
                   nv.thue
               ELSE
                   FTT_VND_QD (goc.ma_dvi,
                               nv.ngay_ht,
                               ma_nt,
                               nv.thue)
           END,
           nv.phi,
           nv.thue,
           so_id_xl
      FROM bh_hd_goc goc, bh_hd_goc_cl nv, temp_bc_ts ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND goc.ngay_ht BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
           AND FBH_HD_KIEU_HD (goc.ma_dvi, goc.so_id_d) <> 'V'
    UNION ALL
    --Huy toan bo don khi khong tra lai tien
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           goc.kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           goc.ngay_ht,
           c.n2,
           -(CASE ma_nt
                 WHEN 'VND'
                 THEN
                     nv.phi
                 ELSE
                     FTT_VND_QD (goc.ma_dvi,
                                 nv.ngay_ht,
                                 ma_nt,
                                 nv.phi)
             END),
           -(CASE ma_nt
                 WHEN 'VND'
                 THEN
                     nv.thue
                 ELSE
                     FTT_VND_QD (goc.ma_dvi,
                                 nv.ngay_ht,
                                 ma_nt,
                                 nv.thue)
             END),
           -nv.phi,
           -nv.thue,
           0
      FROM bh_hd_goc     goc,
           bh_hd_goc_cl  nv,
           (SELECT ma_dvi      c1,
                   so_id       n1,
                   ngay_ht     n2,
                   ton
              FROM bh_hd_goc_hups
             WHERE tra = 0) c,
           temp_bc_ts    ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND n2 BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.ma_dvi = c1
           AND goc.so_id = nv.so_id
           AND goc.so_id = c.n1
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
           AND FBH_HD_KIEU_HD (goc.ma_dvi, goc.so_id_d) <> 'V'
    UNION ALL
    --cong phan da thu duoc phi
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           goc.kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           goc.ngay_ht,
           c.n2,
           phi_qd,
           thue_qd,
           nv.phi,
           nv.thue,
           0
      FROM bh_hd_goc       goc,
           bh_hd_goc_ttpt  nv,
           (SELECT ma_dvi      c1,
                   so_id       n1,
                   ngay_ht     n2,
                   ton
              FROM bh_hd_goc_hups
             WHERE tra = 0) c,
           temp_bc_ts      ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND n2 BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.ma_dvi = c1
           AND goc.so_id = nv.so_id
           AND goc.so_id = c.n1
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
           AND FBH_HD_KIEU_HD (goc.ma_dvi, goc.so_id_d) <> 'V'
    UNION ALL
    --END Huy toan bo don khi khong  tra lai tien
    --Huy tra lai tien
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           goc.kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           goc.so_id,
           goc.ngay_ht,
           c.n2,
           CASE ma_nt
               WHEN 'VND'
               THEN
                   nv.phi
               ELSE
                   FTT_VND_QD (goc.ma_dvi,
                               nv.ngay_ht,
                               ma_nt,
                               nv.phi)
           END,
           CASE ma_nt
               WHEN 'VND'
               THEN
                   nv.thue
               ELSE
                   FTT_VND_QD (goc.ma_dvi,
                               nv.ngay_ht,
                               ma_nt,
                               nv.thue)
           END,
           nv.phi,
           nv.thue,
           0
      FROM bh_hd_goc       goc,
           bh_hd_goc_ttpt  nv,
           (SELECT ma_dvi c1, so_id n1, ngay_ht n2
              FROM bh_hd_goc_hups
             WHERE tra <> 0) c,
           temp_bc_ts      ts
     WHERE     goc.ma_dvi LIKE ts.ma_dvi
           AND nv.ma_dvi LIKE ts.ma_dvi
           AND n2 BETWEEN ts.ngayd AND ts.ngayc
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.ma_dvi = c1
           AND goc.so_id = nv.so_id
           AND goc.so_id = c.n1
           AND (pt = 'G' OR pt = 'H')
           AND nv.phi < 0
           AND so_id_tt = nv.so_id
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
           AND FBH_HD_KIEU_HD (goc.ma_dvi, goc.so_id_d) <> 'V';


DROP VIEW V_BC_BH_DTPS_HUY;

CREATE OR REPLACE FORCE VIEW V_BC_BH_DTPS_HUY
(
    MA_DVI,
