)
BEQUEATH DEFINER
AS
    SELECT ma_dvi,
           so_hd,
           a.nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
