DROP VIEW V_BC_BH_DTTT_HUY;

CREATE OR REPLACE FORCE VIEW V_BC_BH_DTTT_HUY
(
    MA_DVI,
    SO_HD,
    NV,
    KIEU_HD,
    MA_KH,
    CB_QL,
    PHONG,
    KIEU_KT,
    MA_KT,
    NGAY_HL,
    NGAY_KT,
    MA_NT,
    LH_NV,
    MA_DT,
    SO_ID_TT,
    SO_ID,
    NGAY,
    NGAY_HT,
    NGAY_HTNV,
    NGAY_HTBS,
    PHI,
    THUE,
    HHONG,
    HHONG_NT,
    HTRO,
    HTRO_NT,
    PT,
    DBH,
    MA_DVIG
)
BEQUEATH DEFINER
AS
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           lh_nv,
           ma_dt,
           nv.so_id_tt,
           goc.so_id,
           ngay,
           goc.ngay_ht,
           nv.ngay_tt,
           nv.ngay_ht,
           phi_qd,
           thue_qd,
           FTT_VND_QD (goc.ma_dvi,
                       nv.ngay_ht,
                       nv.ma_nt,
                       nv.hhong),
           nv.hhong,
           FTT_VND_QD (goc.ma_dvi,
                       nv.ngay_ht,
                       nv.ma_nt,
                       nv.htro),
           nv.htro,
           pt,
           0,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv
     WHERE     goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND kieu_hd <> 'V'
           AND (pt = 'G' OR pt = 'H')
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    --so tren bao gom ca so huy chua thu tien
    UNION ALL
    --loai tru cac mon huy chua thu tien
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_hl,
           nv.ma_nt,
           lh_nv,
           ma_dt,
           nv.so_id_tt,
           goc.so_id,
           ngay,
           goc.ngay_ht,
           nv.ngay_tt,
           nv.ngay_ht,
           -phi_qd,
           -thue_qd,
           -FTT_VND_QD (goc.ma_dvi,
                        nv.ngay_ht,
                        nv.ma_nt,
                        nv.hhong),
           -nv.hhong,
           -FTT_VND_QD (goc.ma_dvi,
                        nv.ngay_ht,
                        nv.ma_nt,
                        nv.htro),
           -nv.htro,
           pt,
           0,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, bh_hd_goc_hups c
     WHERE     goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND goc.ma_dvi = c.ma_dvi
           AND goc.so_id = c.so_id
           AND nv.ma_nt = c.ma_nt
           AND no <> 0
           AND tra = 0
           AND kieu_hd <> 'V'
           AND (pt = 'G' OR pt = 'H')
           AND nv.phi < 0
           AND nv.so_id = so_id_tt
    UNION ALL
    --giam dong bao hiem di
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           goc.phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           nv.lh_nv,
           ma_dt,
           nv.so_id_tt,
           goc.so_id,
           ngay,
           goc.ngay_ht,
           nv.ngay_tt,
           nv.ngay_ht,
           -phi_qd * c.pt / 100,
           -thue_qd * c.pt / 100,
           0,
           0,
           0,
           0,
           '',
           0,
           goc.ma_dvi
      FROM bh_hd_goc       goc,
           bh_hd_goc_ttpt  nv,
           (SELECT *
              FROM bh_hd_do_tl
             WHERE kieu = 'D' AND pthuc = 'C' AND ph = 'K') c
     WHERE     goc.ma_dvi = nv.ma_dvi
           AND goc.ma_dvi = c.ma_dvi
           AND goc.so_id = nv.so_id
           AND nv.so_id = c.so_id
           AND nv.lh_nv = c.lh_nv
           AND (nv.pt = 'G' OR nv.pt = 'H')
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --Dong bao hiem don vi
    --tang cho don vi dong folow
    SELECT DECODE (b.pthuc, 'D', b.nha_bh, goc.ma_dvi),
           so_hd,
           nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           b.phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           nv.lh_nv,
           ma_dt,
           nv.so_id_tt,
           goc.so_id,
           ngay,
           goc.ngay_ht,
           nv.ngay_ht,
           nv.ngay_ht,
           phi_qd * b.pt / 100,
           0,
           0,
           0,
           0,
           0,
           'G',
           1,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, bh_hd_do_tl b
     WHERE     b.kieu = 'D'
           AND b.pthuc IN ('D', 'P')
           AND nv.ma_dvi = b.ma_dvi
           AND nv.so_id = b.so_id
           AND nv.lh_nv = b.lh_nv
           AND goc.ma_dvi = nv.ma_dvi
           AND goc.so_id = nv.so_id
           AND goc.kieu_hd <> 'V'
           AND (nv.pt = 'G' OR nv.pt = 'H')
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu)
    UNION ALL
    --Giam cho don vi dong leader (don vi goc)
    SELECT goc.ma_dvi,
           so_hd,
           nv,
           kieu_hd,
           ma_kh,
           cb_ql,
           goc.phong,
           kieu_kt,
           ma_kt,
           ngay_hl,
           ngay_kt,
           ma_nt,
           nv.lh_nv,
           ma_dt,
           nv.so_id_tt,
           goc.so_id,
           ngay,
           goc.ngay_ht,
           nv.ngay_ht,
           nv.ngay_ht,
           -phi_qd * b.pt / 100,
           0,
           0,
           0,
           0,
           0,
           'G',
           0,
           goc.ma_dvi
      FROM bh_hd_goc goc, bh_hd_goc_ttpt nv, bh_hd_do_tl b
     WHERE     goc.ma_dvi = nv.ma_dvi
           AND goc.ma_dvi = b.ma_dvi
           AND nv.lh_nv = b.lh_nv
           AND goc.so_id = nv.so_id
           AND nv.so_id = b.so_id
           AND kieu_hd <> 'V'
           AND (nv.pt = 'G' OR nv.pt = 'H')
           AND b.kieu = 'D'
           AND b.pthuc IN ('D', 'P')
           AND (nv.ma_dvi, nv.so_id) IN
                   (SELECT ma_dvi, so_id FROM bh_hd_goc_hu);

DROP VIEW V_BC_BH_TH_BT;

CREATE OR REPLACE FORCE VIEW V_BC_BH_TH_BT
(
    MA_DVI,
    NV,
    SO_HS,
    PHONG,
    NGAY_GUI,
    NGAY_XR,
    N_TRINH,
    N_DUYET,
    NGAY_QD_S,
    MA_NN,
    MA_MD,
    QUY_LOI,
    MA_NT,
    LH_NV,
    SO_ID,
    NGAY_QD_N,
    SO_ID_HD,
    TIEN_BH,
    PT_BT,
    T_THAT,
    K_TRU,
    TIEN,
    TIEN_QD,
    SO_ID_DT,
    NGAY_HT,
    TC,
    SO_HD,
    MA_KH,
    NGAY_HT_HD,
    NGAY_CAP,
    NGAY_HL,
    NGAY_KT,
    TTRANG,
    KIEU_HD
)
BEQUEATH DEFINER
AS
    SELECT bt.ma_dvi,
           bt.nv,
           so_hs,
           goc.phong,
           PKH_SO_CNG (ngay_gui),
           PKH_SO_CNG (ngay_xr),
           n_trinh,
           n_duyet,
           PKH_SO_CNG (ngay_qd)     ngay_qd_s,
           ''                       ma_nn,
           ''                       ma_md,
           ''                       quy_loi,
           ma_nt,
           lh_nv,
           bt.so_id,
           (bt.ngay_qd)             ngay_qd_n,
           so_id_hd,
           tien_bh,
           pt_bt,
           t_that,
           ''                       k_tru,
           nv.tien,
           tien_qd,
           so_id_dt,
           bt.ngay_ht,
           'T'                      tc,
           goc.so_hd,
           goc.ma_kh,
           goc.ngay_ht,
           PKH_SO_CNG (GOC.NGAY_CAP),
           PKH_SO_CNG (GOC.NGAY_HL),
           PKH_SO_CNG (GOC.NGAY_KT),
           goc.ttrang,
           goc.kieu_hd
      FROM bh_bt_hs     bt,
           bh_bt_hs_nv  nv,
           bh_hd_goc    goc,
           temp_bc_ts   ts
     WHERE     bt.ma_dvi = nv.ma_dvi
           AND bt.so_id = nv.so_id
           AND bt.ma_dvi = ma_dvi_ql
           AND bt.ma_dvi = goc.ma_dvi
           AND bt.so_id_hd = goc.so_id
           AND bt.ma_dvi_ql LIKE ts.ma_dvi
           AND ((bt.ngay_qd) BETWEEN ts.ngayd AND ts.ngayc)
           AND bt.ngay_qd < 30000101
    UNION ALL
    SELECT bt.ma_dvi,
           bt.nv,
           so_hs,
           goc.phong,
           PKH_SO_CNG (ngay_gui),
           PKH_SO_CNG (ngay_xr),
           n_trinh,
           n_duyet,
           PKH_SO_CNG (ngay_qd)     ngay_qd_s,
           ''                       ma_nn,
           ''                       ma_md,
           ''                       quy_loi,
           ma_nt,
           lh_nv,
           bt.so_id,
           (bt.ngay_qd)             ngay_qd_n,
           so_id_hd,
           tien_bh,
           pt_bt,
           t_that,
           ''                       k_tru,
           nv.tien,
           tien_qd,
           so_id_dt,
           bt.ngay_ht,
           'K'                      tc,
           goc.so_hd,
           goc.ma_kh,
           goc.ngay_ht,
           PKH_SO_CNG (GOC.NGAY_CAP),
           PKH_SO_CNG (GOC.NGAY_HL),
           PKH_SO_CNG (GOC.NGAY_KT),
           goc.ttrang,
           goc.kieu_hd
      FROM bh_bt_hs     bt,
           bh_bt_hs_nv  nv,
           bh_hd_goc    goc,
           temp_bc_ts   ts
     WHERE     bt.ma_dvi = nv.ma_dvi
           AND bt.so_id = nv.so_id
           AND bt.ma_dvi = ma_dvi_xl
           AND (bt.ma_dvi_xl LIKE ts.ma_dvi)
           AND bt.ma_dvi <> bt.ma_dvi_ql
           AND bt.ma_dvi = goc.ma_dvi
           AND bt.so_id_hd = goc.so_id
           AND bt.ma_dvi IN (SELECT ma_dvi
                               FROM bh_bt_hs_pb
                              WHERE so_id = bt.so_id)
           AND ((bt.ngay_qd) BETWEEN ts.ngayd AND ts.ngayc)
           AND bt.ngay_qd < 30000101
    UNION ALL
    SELECT pb.ma_dvi,
           bt.nv,
           so_hs,
           bt.phong,
           PKH_SO_CNG (ngay_gui),
           PKH_SO_CNG (ngay_xr),
           n_trinh,
           n_duyet,
           PKH_SO_CNG (ngay_qd)     ngay_qd_s,
           ''                       ma_nn,
           ''                       ma_md,
           ''                       quy_loi,
           nv.ma_nt,
           nv.lh_nv,
           bt.so_id,
           (bt.ngay_qd)             ngay_qd_n,
           bt.so_id_hd,
           tien_bh,
           pt_bt,
           t_that,
           ''                       k_tru,
           pb.tien,
           pb.tien_qd,
           so_id_dt,
           bt.ngay_ht,
           'C'                      tc,
           goc.so_hd,
           goc.ma_kh,
           goc.ngay_ht,
           PKH_SO_CNG (GOC.NGAY_CAP),
           PKH_SO_CNG (GOC.NGAY_HL),
           PKH_SO_CNG (GOC.NGAY_KT),
           goc.ttrang,
           goc.kieu_hd
      FROM bh_bt_hs_pb  pb,
           bh_bt_hs     bt,
           bh_bt_hs_nv  nv,
           bh_hd_goc    goc,
           temp_bc_ts   ts
     WHERE     pb.ma_dvi <> pb.dvi_xl
           AND pb.dvi_xl = bt.ma_dvi_xl
           AND pb.so_id = bt.so_id
           AND pb.so_id = nv.so_id
           AND pb.dvi_xl = nv.ma_dvi
           AND bt.ma_dvi_xl = goc.ma_dvi
           AND bt.so_id_hd = goc.so_id
           AND (pb.ma_dvi LIKE ts.ma_dvi)
           AND ((bt.ngay_qd) BETWEEN ts.ngayd AND ts.ngayc)
           AND bt.ngay_qd < 30000101;
/
