/
create or replace procedure FBH_HH_HD_TG(b_ma_dvi varchar2,b_so_id number,b_nt_tien out varchar2,b_nt_phi out varchar2,b_tg out number)
AS
begin
-- Dan - Xac ty gia tren don
select nvl(min(nt_phi),'VND'),nvl(min(ty_gia),1) into b_nt_phi,b_tg from bh_hhgcn where ma_dvi=b_ma_dvi and so_id=b_so_id;
-- select nvl(min(nt_tien),'VND') into b_nt_tien from bh_hhgcn_dk where ma_dvi=b_ma_dvi and so_id=b_so_id;
end;
 
